CREATE TABLE `products` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(200) NOT NULL,
  `name_en` varchar(255) DEFAULT NULL,
  `name_ar` varchar(255) DEFAULT NULL,
  `name_ku` varchar(255) DEFAULT NULL,
  `category_id` int DEFAULT NULL,
  `base_price` int NOT NULL,
  `sell_price` int DEFAULT NULL,
  `commission_price` int DEFAULT NULL,
  `in_stock` tinyint(1) DEFAULT '1',
  `description` text,
  `description_en` text,
  `description_ar` text,
  `description_ku` text,
  `key_features` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `key_features_en` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `key_features_ar` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `key_features_ku` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `discount` decimal(10,2) DEFAULT '0.00',
  `discount_type` varchar(20) DEFAULT 'percentage',
  `discount_expires` datetime DEFAULT NULL,
  `brand_id` int DEFAULT NULL,
  `brand` varchar(100) DEFAULT NULL,
  `store_id` int unsigned DEFAULT NULL,
  `size` varchar(255) DEFAULT NULL,
  `colors` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `volume` varchar(255) DEFAULT NULL,
  `product_code` varchar(255) DEFAULT NULL,
  `is_trend` tinyint(1) DEFAULT '0',
  `is_important` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `category_id` (`category_id`),
  KEY `brand_id` (`brand_id`),
  KEY `store_id` (`store_id`),
  CONSTRAINT `fk_products_brand` FOREIGN KEY (`brand_id`) REFERENCES `brands` (`id`) ON DELETE SET NULL,
  CONSTRAINT `products_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE SET NULL,
  CONSTRAINT `products_store_id_foreign` FOREIGN KEY (`store_id`) REFERENCES `stores` (`id`) ON DELETE SET NULL,
  CONSTRAINT `products_chk_1` CHECK (json_valid(`key_features`)),
  CONSTRAINT `products_chk_2` CHECK (json_valid(`colors`))
) ENGINE=InnoDB AUTO_INCREMENT=265 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
