/*!40000 ALTER TABLE `products` DISABLE KEYS */;
INSERT INTO `products` VALUES (12,'کرێمی ئەمەلسیۆن تایبەت بە چارەسەکردنی کێشەکانی زیپکە لە جەستە وەک سنگ و پشت لە بڕاندی فڕۆیکای یۆنانی','کرێمی تایبەت بە چارەسەکردنی کێشەکانی زیپکە لە جەستە وەک سنگ و پشت لە بڕاندی فڕۆیکای یۆنانی','','',15,20000,29750,4750,1,'یارمەتی لادانی خانە مردووەکانی پێست دەدات و ڕەنگی پێست ڕووندەکاتەوە.\r\n• BHA (Salicylic Acid): دەچێتە ناو کونیلەکان و پاکیان دەکاتەوە لە چەوری زیادە و ڕێگری لە دروستبوونی زیپکە دەکات.\r\n• Azelaic Acid Complex: یارمەتی کەمکردنەوەی سووربوونەوە و پەڵەی دوای زیپکە دەدات.\r\n• Niacinamide (Vitamin B3): چەوری پێست ڕێکدەخات و کونیلەکان بچووک دەکاتەوە.\r\n• Hyaluronic Acid: پێستەکە بە شێداری دەهێڵێتەوە بۆ ئەوەی وشک نەبێتەوە بەهۆی ترشەکانەوە.\r\n٢. سوودەکانی:\r\n• نەهێشتنی زیپکە: یارمەتی نەمانی زیپکەی سەرڕەش و سەرسپی دەدات.\r\n• چارەسەری شوێنەوار: کاریگەرە بۆ کاڵکردنەوەی پەڵە و شوێنەواری زیپکە.\r\n• پاککردنەوەی کونیلەکان: ڕێگری دەکات لە گیرانی کونیلەکانی پێست.\r\n• ڕێکخستنی چەوری: پێستەکە بە مات (Matt) دەهێڵێتەوە و بریقە زیادەکەی ناهێڵێت.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• دەتوانرێت ڕۆژی ١ بۆ ٢ جار بەکاربێت لەسەر پێستێکی پاک و وشک.\r\n• بۆ ئەو شوێنانەی کێشەیان هەیە (دەموچاو، مل، پشت، یان سنگ) بەکاردێت.\r\n⚠️ تێبینی زۆر گرنگ:\r\n1. دژەخۆر: چونکە ئەم بەرهەمە ترشی (AHA) تێدایە، پێست هەستیار دەکات بە خۆر. پێویستە لە کاتی بەکارهێنانیدا لە ڕۆژدا دژەخۆر بەکاربهێنیت.\r\n','Special emulsion cream for treating body acne (chest & back). Helps remove dead skin cells and brighten skin tone. Key actives: Salicylic Acid (BHA) cleans pores and reduces excess oil; Azelaic Acid Complex helps calm redness and post-acne marks; Niacinamide (B3) balances oil and refines pores; Hyaluronic Acid keeps skin hydrated. Use 1–2 times daily on clean, dry skin on affected areas. Important: use sunscreen during the day because acids can increase sun sensitivity.','كريم إمولسيون خاص لعلاج حبّ الشباب في الجسم (الصدر والظهر). يساعد على إزالة الخلايا الميتة وتفتيح لون البشرة. المكوّنات الفعّالة: حمض الساليسيليك (BHA) ينظّف المسام ويقلّل الدهون الزائدة؛ مركّب حمض الأزيليك يخفّف الاحمرار وآثار الحبوب؛ النياسيناميد (B3) يوازن إفراز الدهون ويصغّر مظهر المسام؛ حمض الهيالورونيك يرطّب البشرة. يُستخدم 1–2 مرة يومياً على بشرة نظيفة وجافة في المناطق المتأثرة. ملاحظة مهمّة: استخدم واقي شمس نهاراً لأن الأحماض قد تزيد حساسية البشرة للشمس.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 08:05:48',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,0),(13,'کرێمی تەقشیری تایبەت بەو پێستانەی کە ئامادەیان تێدایە بۆ دروستبوونی زیپکە لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25000,2500,1,'تایبەتمەندییە سەرەکییەکانی:\r\n• پاککردنەوە و تەقشیر (Exfoliating): بەهۆی ماددەی X-Pressin (3%) تێیدا، یارمەتی لادانی خانە مردووەکانی پێست دەدات و ڕێگری دەکات لە گیرانی کونیلەکان و دروستبوونی خاڵە ڕەشەکان.\r\n• جێگرەوەی ڕێتینۆڵ (Bakuchiol): ماددەی باکوچیۆڵی تێدایە کە دژە ئۆکسانێکی بەهێزە و وەک ڕێتینۆڵ کار دەکات بۆ نوێکردنەوەی پێست، بەڵام بێ ئەوەی ببێتە هۆی سووربوونەوە یان هەستیاری زۆر.\r\n• پاراستنی مایکرۆبایۆمی پێست: ماددەی Inulin (Chicory Root) تێدایە کە هاوسەنگی بەکتریا سوودبەخشەکانی سەر پێست دەپارێزێت و ڕێگری لە گەشەی بەکتریای زیپکە دەگرێت.\r\n• کەمکردنەوەی چەوری: یارمەتی ڕێکخستنی دەردانی چەوری (Sebum) دەدات و ڕەنگێکی مات (Matte) بە پێست دەبەخشێت (نایەڵێت پێستەکە ببریسکێتەوە بەهۆی چەورییەوە).\r\nبۆ کێ گونجاوە؟\r\n• بۆ ئەو کەسانەی زیپکەی سەختیان هەیە.\r\n• بۆ چارەسەری خاڵە ڕەشەکان.\r\n• بۆ ئەو پێستانەی شوێنەواری زیپکە و ل پەڵەیان پێوە ماوە.\r\n• بۆ هەردوو تەمەنی هەرزەکاری و گەورە ساڵان گونجاوە.\r\nچۆنیەتی بەکارهێنان:\r\n1. پێش بەکارهێنان پێستت بە غەسولێکی گونجاو بشۆ و بە باشی وشکی بکەرەوە.\r\n2. ڕۆژی یەک یان دوو جار (بەیانیان و شەوان) بڕێکی گونجاو لە کرێمەکە بدە لەو شوێنانەی کە کێشەکەیان هەیە یان هەموو دەموچاو.\r\n3. دەتوانرێت وەک بنکەیەک (Base) بۆ ماکیاژیش بەکاربێت.\r\nتێبینی گرنگ:\r\n• چونکە ئەم کرێمە تایبەتمەندی تەقشیری تێدایە، ئەگەر بەیانیان بەکارت هێنا، پێویستە لەگەڵیدا دژەخۆر بەکاربهێنیت بۆ ئەوەی پێستت تووشی سووتان نەبێت.\r\n','Exfoliating cream for acne-prone skin. With X-Pressin 3% to gently exfoliate and prevent clogged pores and blackheads. Contains Bakuchiol (retinol alternative) to renew skin with less irritation. Includes Inulin (chicory root) to support the skin microbiome. Helps control oil and gives a matte look. Use once or twice daily on clean, dry skin (all face or problem areas). If used in the morning, apply sunscreen.','كريم تقشير للبشرة المعرّضة لظهور الحبوب. يحتوي على X-Pressin بنسبة 3% لتقشير لطيف ومنع انسداد المسام والرؤوس السوداء. يحتوي على باكوتشيول (بديل الريتينول) لتجديد البشرة مع تهيّج أقل. كما يحتوي على إنولين (جذر الهندباء) لدعم توازن الميكروبيوم. يساعد على ضبط الدهون ومنح البشرة مظهراً مطفياً. يُستخدم مرة أو مرتين يومياً على بشرة نظيفة وجافة (للوجه كاملًا أو مناطق المشكلة). عند استخدامه صباحاً يُفضّل وضع واقي شمس.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 16:49:05',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(14,'پاکەرەوەی تایبەت بە چارەسەرکردنی پێستی چەور و زیپکەی دەم و چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,26000,3000,1,'. پێکهاتەی سەرەکی\r\nئەم بەرهەمە ماددەی Salicylic Acid (سالیسیلیک ئەسید) ی تێدایە کە بە دوو شێوە کار دەکات:\r\n• پاککردنەوە (Keratolytic action): یارمەتی لادانی خانە مردووەکانی پێست دەدات کە دەبنە هۆی گیرانی کونیلەکان و دروستبوونی زیپکە.\r\n• دژە بەکتریا (Antimicrobial action): ڕێگری دەکات لە گەشەکردنی ئەو وردە زیندەوەر و بەکتریایانەی دەبنە هۆی هەوکردنی پێست.\r\n٢. تایبەتمەندییە گرنگەکان\r\n• Soap-Free (بێ سابوون): پێست وشک ناکاتەوە و هاوسەنگی سروشتی پێست تێک نادات.\r\n• Non-Alkaline: ماددەی ئەلکالی تێدا نییە کە زیان بە پێست بگەیەنێت.\r\n• چارەسەری چەوری: یارمەتی ڕێکخستنی دەردانی چەوری پێست دەدات و بریقەی ناخۆشی سەر پێست ناهێڵێت.\r\n• خاڵە ڕەشەکان: کاریگەرە بۆ کەمکردنەوە و نەهێشتنی خاڵە ڕەشەکان (Blackheads).\r\n٣. شێوازی بەکارهێنان\r\n• تەنها بۆ بەکارهێنانی دەرەکییە.\r\n• بڕێکی گونجاو لە پاککەرەوەکە بدە لە پێستت، بە هێواشی مەساجی پێ بکە و پاشان بە ئاو بیشۆ.\r\n','Cleanser for oily, acne-prone face and body. With Salicylic Acid to exfoliate dead cells, unclog pores, and reduce acne-causing bacteria. Soap-free and non-alkaline to help keep the skin balance without excessive dryness. Helps reduce shine and blackheads. Apply to wet skin, gently massage, then rinse with water. For external use only.','غسول للبشرة الدهنية والمُعرّضة للحبوب للوجه والجسم. يحتوي على حمض الساليسيليك لتقشير الخلايا الميتة وفتح المسام وتقليل البكتيريا المسببة للحبوب. خالٍ من الصابون وغير قلوي للحفاظ على توازن البشرة دون جفاف زائد. يساعد على تقليل اللمعان والرؤوس السوداء. يُستخدم على بشرة مبللة مع تدليك لطيف ثم يُشطف بالماء. للاستعمال الخارجي فقط.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 16:52:58',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(15,'کرێمی تایبەت بە پێستی چەور و زیپکە لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25500,2750,1,'. پێکهاتە سەرەکییەکان:\r\n• سalicylic Acid (BHA): یارمەتی پاککردنەوەی قووڵی کونیڵەکانی پێست دەدات و خانە مردووەکان لادەبات، کە ئەمەش ڕێگری لە دروستبوونی زیپکە دەکات.\r\n• Azelaic Acid & Glycine: ئەم دووانە پێکەوە کاردەکەن بۆ کەمکردنەوەی پەڵەی زیپکە، سپیکردنەوەی شوێنە تاریکەکان، و ڕێکخستنی دەردانی چەوری.\r\n• Niacinamide (Vitamin B3): سووربوونەوەی پێست کەمدەکاتەوە و بەربەستی پارێزەری پێست بەهێز دەکات.\r\n• Peptides: یارمەتی بەرگری پێست دەدەن دژی هەوکردن و خوروش.\r\n• Zinc Gluconate: وەک دژە بەکتریا کاردەکات و یارمەتی وشککردنەوەی زیپکە دەدات.\r\n٢. سوودە سەرەکییەکانی:\r\n• ڕێکخستنی چەوری (Seboregulating): بڕی ئەو چەورییەی پێست دەریدەدات هاوسەنگ دەکات.\r\n• دژە زیپکە: یارمەتی لابردنی سەرهەوێنکە (Blackheads) و کەمکردنەوەی زیپکە نوێیەکان دەدات.\r\n• دژە سووربوونەوە و هەوکردن: پێست ئارام دەکاتەوە و ناهێڵێت زۆر سوور ببێتەوە.\r\n• کەمکردنەوەی شوێنەواری زیپکە: بەهۆی هەبوونی ترشی ئازێلیک، یارمەتی کاڵکردنەوەی پەڵەکان دەدات.\r\n٣. چۆن بەکاردێت؟\r\n• پێش بەکارهێنانی، دەبێت پێستت بە غسولێکی گونجاو بەباشی بشۆیت.\r\n• بڕێکی گونجاو لە کرێمەکە بدە لە تەواوی دەموچاوت (یان تەنها ئەو شوێنانەی کێشەکەیان هەیە) ڕۆژی ١ بۆ ٢ جار (بەیانیان و شەوان).\r\n• تێبینی: بەهۆی هەبوونی ترشی سالیسیلیک، ئەگەر بەیانیان بەکاری دەهێنیت، زۆر گرنگە دژەخۆر لەسەر بەکاربهێنیت چونکە پێست هەستیار دەکات بە تیشکی خۆر.\r\n٤. تایبەتمەندی بەستەرەکەی (Packaging):\r\nئەم کرێمە بە شێوازی Airless System دروستکراوە، واتە هەوا ناچێتە ناو بوتڵەکە. ئەمەش وادەکات پێکهاتەکان تێکنەچن، بەکتریا بۆ ناوەوەی نەگوازرێتەوە، و تا کۆتا دڵۆپ بەکاربهێنرێت بەبێ ئەوەی ئۆکسید ببێت\r\n','Cream for oily and acne-prone skin. Key actives: Salicylic Acid (BHA) deeply cleans pores; Azelaic Acid + Glycine help reduce blemishes and dark marks and balance oil; Niacinamide strengthens the skin barrier and calms redness; Peptides support skin defense; Zinc Gluconate helps fight acne bacteria. Use 1–2 times daily after cleansing (full face or affected areas). Important: if used in daytime, apply sunscreen. Airless packaging helps keep the formula protected.','كريم للبشرة الدهنية والمُعرّضة للحبوب. المكوّنات الفعّالة: حمض الساليسيليك (BHA) لتنظيف المسام بعمق؛ حمض الأزيليك مع الجلايسين لتخفيف الحبوب والآثار الداكنة وتنظيم الدهون؛ النياسيناميد لتقوية حاجز البشرة وتهدئة الاحمرار؛ ببتيدات لدعم حماية البشرة؛ غلوكونات الزنك للمساعدة ضد بكتيريا الحبوب. يُستخدم 1–2 مرة يومياً بعد تنظيف البشرة (للوجه كاملًا أو مناطق المشكلة). ملاحظة: عند الاستخدام نهاراً يُفضّل وضع واقي شمس. عبوة Airless تحافظ على المكونات وتحميها.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 16:55:28',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(16,'پاکەرەوەی تایبەت بە پێستی چەور و زیپکەی دەم و چاو  لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25500,2750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• پاککردنەوەی قووڵ: یارمەتی پاککردنەوەی کونیڵەکانی پێست دەدات لە چەوری زیادە و پیسی.\r\n• دژە بەکتریا: کاردەکات بۆ کەمکردنەوەی ئەو بەکتریایانەی دەبنە هۆی دروستبوونی زیپکە.\r\n• هاوسەنگکردنی چەوری: یارمەتی ڕێکخستنی دەردانی چەوری (Sebum) دەدات بەبێ ئەوەی پێستەکە زۆر وشک بکاتەوە.\r\n• بێ سابوون و پارابین: پێست تووشی هەستیاری و سووربوونەوە ناکات چونکە ماددەی کیمیایی توندی تێدا نییە.\r\n٢. پێکهاتە گرنگەکانی (Active Ingredients):\r\nبەپێی ئەوەی لەسەر پاکەتەکە نووسراوە:\r\n• Zinc & Copper PCA: بۆ کۆنترۆڵکردنی چەوری و پاککردنەوەی پێست.\r\n• Hyaluronic Acid: بۆ ئەوەی پێستەکە بە شێداری بمێنێتەوە و وشک نەبێتەوە دوای شتن.\r\n• Glycolic Acid (AHA): بۆ لادانی خانە مردووەکان و ڕووناککردنەوەی پێست.\r\n• Nicotinamide (Vitamin B3): بۆ کەمکردنەوەی سووربوونەوە و نیشانەکانی زیپکە.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• بەیانیان و شەوان بەکاردێت.\r\n• کەمێکی لێ دەدەیت لە پێستی تەڕ (دەموچاو یان جەستە)، بە هێواشی مەساژی پێ دەکەیت تا کەف دەکات.\r\n• پاشان بە ئاوێکی شلەتێن بە باشی دەموچاوت دەشۆیت.\r\n٤. بۆ کێ گونجاوە؟\r\n• بۆ ئەو کەسانەی پێستیان چەوری زۆرە.\r\n• بۆ ئەو پێستانەی تووشی زیپکە دەبن.\r\n• دەتوانرێت بۆ دەموچاو و جەستەش (بۆ نموونە زیپکەی پشت) بەکاربهێنرێت\r\n','Deep-cleansing wash for oily, acne-prone face and body. Helps remove excess oil and impurities and reduce acne-related bacteria while keeping skin from over-drying. Free from harsh additives such as soap and parabens. Active ingredients (as listed): Zinc & Copper PCA for oil control, Hyaluronic Acid for hydration, Glycolic Acid (AHA) for gentle exfoliation, Nicotinamide (B3) for calming and improving blemish appearance. Use morning and night; lather on wet skin and rinse well.','غسول تنظيف عميق للبشرة الدهنية والمُعرّضة للحبوب للوجه والجسم. يساعد على إزالة الدهون الزائدة والشوائب وتقليل البكتيريا المرتبطة بالحبوب مع الحفاظ على البشرة دون جفاف شديد. خالٍ من الإضافات القاسية مثل الصابون والبارابين. مكوّنات فعّالة (حسب العبوة): Zinc & Copper PCA لضبط الدهون، حمض الهيالورونيك للترطيب، حمض الجليكوليك (AHA) لتقشير لطيف، نياسيناميد (B3) لتهدئة البشرة وتحسين مظهر آثار الحبوب. يُستخدم صباحاً ومساءً على بشرة مبللة ثم يُشطف جيداً.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 16:58:20',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(17,'پاکەرەوە و شێدارکەرەوەی پێستی دەم و چاو و جەستە لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25000,2500,1,'. پێکهاتە سەرەکییەکان\r\n• Hyaluronic Acid (ترشی هیالۆرۆنیک): یارمەتی شێدارکردنەوەی پێست دەدات و ناهێڵێت دوای شتن وشک ببێتەوە.\r\n• Bioactive Peptides: بۆ بەهێزکردنی خانەکانی پێست و پاراستنی لە پیربوون.\r\n• Soap & SLES Free: بێ سابوون و ماددە کیمیاییە توندەکانە، ئەمەش وای لێدەکات زۆر نەرم بێت لەسەر پێست و تووشی سووربوونەوە و خوران نەتکات.\r\n٢. سوودەکانی بۆ پێست\r\n• پاککردنەوەی قووڵ: چەوری زیادە و پیسی نیشتووی سەر پێست لادەبات بەبێ ئەوەی زیان بە چینی پارێزەری پێست بگەیەنێت.\r\n• شێدارکەرەوە: بە پێچەوانەی زۆربەی غەسولەکان، ئەمە کاردەکات بۆ هێشتنەوەی شێداری لەناو پێستدا.\r\n• بۆ پێستی هەستیار و وشک: زۆر گونجاوە بۆ ئەو کەسانەی پێستیان وشکە، یان بەهۆی بەکارهێنانی چارەسەری زیپکە (وەک ڕۆکوتان) پێستیان تووڕە و کزانەوەی هەیە.\r\n• دژە هەوکردن: ڤیتامین و ماددەی تێدایە کە پێست ئارام دەکاتەوە.\r\n٣. چۆن بەکاردێت؟\r\n• بڕێکی گونجاو بدە لە پێستی تەڕ (دەموچاو یان جەستە).\r\n• بە هێواشی مەساجی پێ بکە تا کەف دەکات.\r\n• پاشان بە ئاوێکی شلەتێن بە باشی دەموچاوت بشۆ.\r\n• دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.\r\n','Gentle cleanser + hydrator for face and body. With Hyaluronic Acid to maintain moisture and help prevent tightness after washing. Contains bioactive peptides to support skin renewal. Soap/SLES-free for a soft, non-irritating cleanse—especially suitable for dry or sensitive skin, including skin stressed by acne treatments. Use twice daily: massage onto wet skin, then rinse.','غسول لطيف مع ترطيب للوجه والجسم. يحتوي على حمض الهيالورونيك للحفاظ على الرطوبة ومنع شدّ البشرة بعد الغسل. مع ببتيدات حيوية لدعم تجدد البشرة. خالٍ من الصابون وSLES لتنظيف ناعم غير مهيّج—مناسب جداً للبشرة الجافة أو الحساسة، وحتى البشرة المتأثرة بعلاجات الحبوب. يُستخدم مرتين يومياً: يُدلّك على بشرة مبللة ثم يُشطف.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:01:13',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(18,'سپڕای تایبەت بە قژ لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,9000,15000,3000,1,'• پێکهاتە گرنگەکان: کێراتین (Keratin)، پانتینۆڵ (Panthenol)، پڕۆتینی گەنم، و ڕۆنی ئەرگان.\r\n• بۆ کێ دەبێت؟ بۆ هەموو جۆرە قژێک گونجاوە.\r\n١٠ سوودی سەرەکی لە یەک بەرهەمدا:\r\nبەپێی زانیارییەکانی پشتی بوتڵەکە، ئەم سپرایە ئەم کارانە دەکات:\r\n1. چاککردنەوە: قژی وشک و تێکچوو چاک دەکاتەوە.\r\n2. شێدارکردن: شێدارییەکی زۆر بە قژ دەدات و ڕێگری لە ماتبوون دەکات.\r\n3. داهێنان: گرێی قژ دەکاتەوە و داهێنانی ئاسان دەکات.\r\n4. نەرمی: پێکهاتەیەکی نەرم و ئاوریشمی بە قژ دەبەخشێت.\r\n5. دژە بژبوون: ڕێگری لە بژبوون و هەڵاوسانی قژ دەکات.\r\n6. بریقە: قژ بەهێز و بریقەدار دەکات.\r\n7. پاراستن لە گەرمی: قژ دەپارێزێت لە گەرمی ئامێرەکانی وەک (سشوار و فێر).\r\n8. پاراستنی ڕەنگ: یارمەتی پاراستنی ڕەنگی قژ دەدات.\r\n9. ستایلینگ: یارمەتی دەدات ستایلی قژەکە بۆ ماوەیەکی درێژتر بمێنێتەوە.\r\n10. قەبارە و پاراستن: قەبارە بە قژ دەدات و ناهێڵێت تاڵەکانی قژ لە کۆتایییەوە ببن بە دوو کەرت (Split ends).\r\nچۆن بەکاردێت؟\r\n• سپرایەکە بە یەکسانی بپڕژێنە سەر قژی تەڕ یان وشک.\r\n• بە شانە قژت دابهێنە و ئەو ستایلەی دەتەوێت دایبنێ.\r\n• تێبینی: پێویست بە شتن ناکات (Do not rinse).\r\n','Hair spray for all hair types with Keratin, Panthenol, Wheat Protein, and Argan Oil. 10-in-1 benefits: repairs damage, hydrates, detangles, softens, reduces frizz, adds shine, protects from heat tools, helps protect color, improves styling hold, and helps reduce split ends. Spray evenly on damp or dry hair, comb through, and style. No rinse needed.','سبراي للشعر مناسب لجميع الأنواع يحتوي على كيراتين وبانثينول وبروتين القمح وزيت الأرغان. فوائد 10 في 1: إصلاح التلف، ترطيب، فك التشابك، تنعيم، تقليل النفشة، لمعان، حماية من حرارة الأدوات، المساعدة في حماية اللون، تحسين ثبات التصفيف، والمساعدة على تقليل التقصف. يُرش بالتساوي على شعر رطب أو جاف ثم يُمشّط ويُصفّف. لا يحتاج إلى شطف.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:03:07',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(19,'سیڕۆمی شێدارکەرەوە و بەهێزکەری قژ لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,9000,16000,3500,1,'تایبەتمەندییە سەرەکییەکانی ئەم سێرمە:\r\n• بوژێنەرەوەی گشتی (Total Revival): یارمەتی قژی ماندوو و تێکچوو دەدات بۆ ئەوەی دووبارە بگەشێتەوە.\r\n• شێدارکەرەوە: بەهۆی پێکهاتەکانیەوە ڕێگری لە وشکبوونی قژ دەکات و نەرمی پێ دەبەخشێت.\r\n• بەهێزکەر: قژی لاواز بەهێز دەکات و لە هەڵوەرین و پچڕان دەیپارێزێت.\r\n• درەوشانەوە: بریقەیەکی سروشتی بە قژ دەدات.\r\nپێکهاتە گرنگەکانی ناوی:\r\nبەپێی ئەوەی لەسەر پشتەکەی نووسراوە، ئەم ماددانەی تێدایە:\r\n1. Wheat Protein (پرۆتینی گەنم): یارمەتی هێشتنەوەی شێ دەدات لەسەر ڕووی تاڵەکانی قژ.\r\n2. Keratin (کیراتین): بۆ چاککردنەوەی قژە سووتاوەکان و پاراستنی ڕەنگی قژ.\r\n3. Niacinamide (ڤیتامین B3): کە یارمەتی تەندروستی قژ و درێژبوونی دەدات.\r\n4. بەرگری گەرمی (Thermal Protection): قژ دەپارێزێت لە گەرمی ئامێرەکانی وەک (ستایتەر و موجەفیفە).\r\nچۆنیەتی بەکارهێنان:\r\n1. بڕێکی کەم لە سێرمەکە بدە لە لەپی دەستت (بەپێی درێژی قژت).\r\n2. دەستەکانت بەیەکدا بخشێنە بۆ ئەوەی سێرمەکە کەمێک گەرم بێتەوە.\r\n3. بیدە لە ناوەڕاست تا کۆتایی تاڵەکانی قژت (پێویست ناکات بیدەیت لە بێخی سەر).\r\n4. دەکرێت لەسەر قژی تەڕ یان وشک بەکاربهێنرێت.\r\n5. تێبینی: پێویست بە شۆردن ناکات دوای بەکارهێنانی.\r\n• لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە.\r\n','Hydrating and strengthening hair serum. Helps revive tired, damaged hair, improves softness, and supports stronger strands with a natural shine. Key ingredients: Wheat Protein for moisture support, Keratin for repair and color support, Niacinamide (B3) to support healthy hair, plus thermal protection to help guard against heat tools. Apply a small amount to mid-lengths and ends on damp or dry hair. No rinse needed.','سيروم ترطيب وتقوية للشعر. يساعد على إنعاش الشعر المتعب والمتضرر ويمنح نعومة ولمعاناً طبيعياً مع دعم قوة الخصلات. مكوّنات أساسية: بروتين القمح لدعم الترطيب، الكيراتين للإصلاح ودعم لون الشعر، النياسيناميد (B3) لدعم صحة الشعر، مع حماية حرارية للمساعدة ضد حرارة أدوات التصفيف. توضع كمية قليلة على منتصف الشعر والأطراف على شعر رطب أو جاف. لا يحتاج إلى شطف.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:07:37',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(20,'لۆشنی سپیکەرەوەی تایبەت بە ناوچەی هەستیار لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,21000,30000,4500,1,'. مەبەست لە بەکارهێنان\r\nئەم کرێمە (شیرە) بۆ چارەسەرکردنی ئەم کێشانە بەکاردێت:\r\n• سپیکردنەوەی ناوچە هەستیارەکان: وەک ژێر باڵ، ئەژنۆ، ئانیشک، و ناوچەکانی تری لێخشان.\r\n• لابردنی پەڵە: یارمەتیدەرە بۆ کەمکردنەوەی پەڵەی تۆخ (Dark Spots) کە بەهۆی تیشکی خۆر، سکپڕی، یان بەکارهێنانی دەرمانەوە دروست بوون.\r\n• یەکخستنی ڕەنگی پێست: کاردەکات بۆ ئەوەی پێستەکە ڕەنگێکی یەکسان و گەشاوەی هەبێت.\r\n٢. پێکهاتە سەرەکییەکان\r\nبەپێی ئەوەی لەسەر بوتڵەکە نووسراوە، سێ ماددەی گرنگی تێدایە:\r\n• Tranexamic Acid: بۆ ڕێگریگرتن لە دروستبوونی میلانین و کەمکردنەوەی پەڵە.\r\n• Licorice (سۆس): پێکهاتەیەکی سروشتییە بۆ سپیکردنەوە و هێورکردنەوەی پێست.\r\n• Resorcinol: یارمەتی سپیکردنەوەی خێراتری پێست دەدات.\r\n• هەروەها Niacinamide (ڤیتامین B3) و Alpha-Hydroxy Acids (AHA) تێدایە کە خانە مردووەکانی پێست لادەبەن و پێستەکە نوێ دەکەنەوە.\r\n٣. تایبەتمەندییە باشەکانی\r\n• بۆ پێستی هەستیار گونجاوە: بەهۆی ئەوەی ماددەی هێورکەرەوەی وەک ڕۆنی ئەڤۆکادۆ و کەرەی شیا (Shea Butter) تێدایە.\r\n• خێرا هەڵدەمژرێت: چەوری لەسەر پێست جێناهێڵێت و هەستێکی فێنک بە پێست دەبەخشێت.\r\n• پارێزەری پێست: دژە ئۆکسانی تێدایە (وەک ڤیتامین E) کە پێست لە تێکچوون دەپارێزێت.\r\n٤. چۆنیەتی بەکارهێنان\r\n• ڕۆژانە ١ بۆ ٢ جار لەسەر پێستی پاک و وشک بەکاردێت.\r\n• تەنها بۆ بەکارهێنانی دەرەکییە (بۆ سەر پێست).\r\n• باشترە لە کاتی بەکارهێنانی ئەم جۆرە بەرهەمانەدا بۆ ئەو ناوچانەی بەر خۆر دەکەون، دژەخۆر بەکاربهێنرێت\r\n','Brightening lotion for sensitive areas (underarms, knees, elbows, and other dark areas). Helps reduce dark spots and even skin tone. Key actives: Tranexamic Acid to help reduce discoloration, Licorice to brighten and soothe, Resorcinol for stronger brightening support, plus Niacinamide and AHAs for gentle renewal. Use 1–2 times daily on clean, dry skin. Sunscreen is recommended for sun-exposed areas.','لوشن تفتيح للمناطق الحساسة (تحت الإبط، الركب، الأكواع وغيرها من المناطق الداكنة). يساعد على تقليل البقع الداكنة وتوحيد لون البشرة. مكوّنات فعّالة: حمض الترانيكساميك للمساعدة في تقليل التصبغات، العرقسوس للتفتيح والتهدئة، ريزورسينول لدعم تفتيح أقوى، مع نياسيناميد وAHA لتجديد لطيف. يُستخدم 1–2 مرة يومياً على بشرة نظيفة وجافة. يُنصح باستخدام واقي شمس للمناطق المعرّضة للشمس.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:09:38',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(21,'موکەیفەی تایبەت بە تێرکردن و چاکردنەوەی قژ لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,4000,9000,2500,1,'. تایبەتمەندییە سەرەکییەکان\r\n• جۆری قژ: تایبەت دروستکراوە بۆ قژی وشک و تێکچوو (Damaged & Dry Hair).\r\n• پێکهاتە گرنگەکان:\r\n• ڤیتامین B3 و B6: یارمەتی بەهێزکردن و نوێکردنەوەی تاڵەکانی قژ دەدەن.\r\n• کیراتین (Keratin): بۆ نەرمکردنەوە و بریقەدارکردنی قژ.\r\n• پرۆتینی گەنم (Wheat Proteins): بۆ شێدارکردنەوەی قووڵی قژ و پاراستنی لە شکانەوە.\r\n٢. سوودەکانی بەرهەمەکە\r\n• چاککردنەوەی خێرا: یارمەتی چاککردنەوەی ئەو قژانە دەدات کە بەهۆی بۆیە یان گەرمی (ئوتوو و شەشوار) زەرەریان پێگەیشتووە.\r\n• نەرمکردن: قژەکە زۆر نەرم دەکات و داهێنانی ئاسان دەکات.\r\n• بریقەدان: ڕوکاری دەرەوەی قژەکە تەندروست و بریقەدار نیشان دەدات.\r\n٣. چۆنیەتی بەکارهێنان\r\n١. دوای ئەوەی قژت بە شامپۆ دەشۆیت، بڕێکی گونجاو لەم موکەیفە بدە لە نیوەی قژت بۆ خوارەوە (دوور بکەوەرەوە لەوەی بیدەیت لە بێخی سەر).\r\n٢. با بۆ ماوەی چەند خولەکێک بە قژتەوە بمێنێتەوە.\r\n٣. پاشان بە باشی بە ئاو بیشۆ.\r\nتێبینی: ئەم بەرهەمە لە وڵاتی یۆنان (Greece) بەرهەم دەهێنرێت و لەلایەن پزیشکانی پێستەوە تاقی کراوەتەوە.\r\n','Conditioner for dry and damaged hair. With Vitamins B3 & B6 to support stronger hair, Keratin for softness and shine, and Wheat Proteins for deep nourishment and protection against breakage. Helps repair damage from dyeing and heat tools, leaves hair smoother and easier to comb. Apply after shampoo from mid-lengths to ends, leave a few minutes, then rinse well.','بلسم للشعر الجاف والمتضرر. يحتوي على فيتاميني B3 وB6 لدعم قوة الشعر، كيراتين للنعومة واللمعان، وبروتينات القمح لتغذية عميقة وحماية من التكسر. يساعد على إصلاح التلف الناتج عن الصبغ وأدوات الحرارة ويجعل الشعر أسهل في التمشيط. يُستخدم بعد الشامبو على منتصف الشعر والأطراف، يُترك بضع دقائق ثم يُشطف جيداً.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:12:29',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(22,'موکەیەفی تایبەت بە قژی وشک وتێکچوو لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,16000,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بنیاتنانەوە و چاککردنەوە: یارمەتی چاککردنەوەی تاڵە قژە زیانپێکەوتووەکان دەدات.\r\n• تێرکردنی قژ (Nourishment): بەهۆی هەبوونی پێکهاتەی دەوڵەمەند، قژەکە بەتەواوی تەڕ (Hyderated) دەکاتەوە.\r\n• پێکهاتە گرنگەکان:\r\n• ڤیتامین B3 و B6: بۆ بەهێزکردن و تەندروستی قژ.\r\n• کیراتین (Keratin): بۆ نەرمکردنەوە و بریقەدارکردنی قژ.\r\n• پڕۆتینی گەنم (Wheat Proteins): بۆ پاراستنی قژ لە شکان و وشکبوونەوە.\r\nسوودەکانی:\r\n1. قژ زۆر نەرم دەکات و داهێنانی ئاسان دەکات.\r\n2. بریقەیەکی سروشتی بە قژەکە دەبەخشێت.\r\n3. بۆ بەکارهێنانی ڕۆژانە گونجاوە (Daily Care).\r\nشێوازی بەکارهێنان:\r\n1. دوای ئەوەی قژت بە شامپۆ دەشۆیت، بڕێکی گونجاو لەم کرێمە بدە لە تەنها تاڵەکانی قژت (دوور بکەوەرەوە لەوەی بیدەیت لە بێخی سەر).\r\n2. با بۆ ماوەی چەند خولەکێک بە قژتەوە بمێنێتەوە.\r\n3. پاشان بە جوانی بە ئاو بیشۆ.\r\nتێبینی: وەک لەسەر بوتڵەکە نووسراوە، ئەم بەرهەمە لەلایەن پزیشکی پێستەوە تاقیکراوەتەوە (Dermatologically Tested).\r\n','Conditioner for dry and damaged hair. Helps repair and nourish, leaving hair hydrated, soft, and shiny. With Vitamins B3 & B6 for hair vitality, Keratin for smoothness, and Wheat Proteins to help protect against breakage and dryness. Suitable for daily care. Apply after shampoo on lengths and ends, leave a few minutes, then rinse.','بلسم للشعر الجاف والمتضرر. يساعد على الإصلاح والتغذية ويمنح الشعر ترطيباً ونعومة ولمعاناً. يحتوي على فيتاميني B3 وB6 لدعم حيوية الشعر، كيراتين للملمس الناعم، وبروتينات القمح للمساعدة في الحماية من التكسر والجفاف. مناسب للعناية اليومية. يُستخدم بعد الشامبو على الأطوال والأطراف، يُترك دقائق ثم يُشطف.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:14:17',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(23,'کرێمی ئەزیلیەک ئەسید تایبەت بە شوێنی زیپکە لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,26000,3000,1,'. پێکهاتە سەرەکییەکانی:\r\n• Azelaic Acid (20%): ڕێژەیەکی بەهێزی تێدایە کە یارمەتی کەمکردنەوەی هەوکردن، نەمانی سووربوونەوە و سپیکردنەوەی شوێنەواری زیپکە دەدات. هەروەها دژی بەکتریا کاردەکات.\r\n• Niacinamide (ڤیتامین B3): چەوری پێست هاوسەنگ دەکات و کونییلەکانی پێست بچووک دەکاتەوە.\r\n• Licorice (ڕەگی بەیان): بۆ ڕوونکردنەوەی ڕەنگی پێست و کەمکردنەوەی پەڵە.\r\n• Prebiotics (Inulin): بۆ پاراستنی هاوسەنگی بەکتریا سوودبەخشەکانی سەر پێست و بەهێزکردنی بەرگری پێست.\r\n٢. سوودە سەرەکییەکانی:\r\n• چارەسەری زیپکە: یارمەتی نەمانی زیپکە و ڕێگری لە دروستبوونەوەی دەدات.\r\n• سپیکردنەوەی پەڵە: زۆر کاریگەرە بۆ نەمانی پەڵەی قاوەیی و شوێنەواری سووری زیپکە.\r\n• کەمکردنەوەی چەوری: گونجاوە بۆ ئەو کەسانەی پێستیان زۆر چەورە و دەدرەوشێتەوە.\r\n• سافکردنی پێست: یارمەتی سافکردن و ڕێکخستنی شانەکانی پێست دەدات.\r\n٣. چۆن بەکاردێت؟\r\n• پێویستە لەسەر پێستێکی پاک بەکاربێت (بەیانیان و شەوان).\r\n• لەبەر ئەوەی ڕێژەی ئەزەلاییک ئەسیدەکەی بەرزە (20%)، لەوانەیە لە سەرەتادا کەمێک هەستی خوران یان سووتانەوەت پێ بدات، ئەمە ئاساییە. ئەگەر پێستت زۆر هەستیارە، دەتوانیت سەرەتا ڕۆژی جارێک یان دوو ڕۆژ جارێک بەکاری بهێنیت تا پێستت ڕادێت.\r\n• تێبینی گرنگ: پێویستە لە کاتی بەکارهێنانی ئەم کرێمەدا لە ڕۆژدا دژەخۆر بەکاربهێنیت، چونکە پێست هەستیار دەکات بە تیشکی خۆر.\r\n٤. بۆ کێ گونجاوە؟\r\n• بۆ پێستی چەور، تێکەڵ (Mixed)، و ئەو پێستانەی زیپکەیان هەیە.\r\n• بۆ ئەو کەسانەی کێشەی (Rosacea) یان سووربوونەوەی دەموچاویان هەیە.\r\n','Azelaic Acid cream (20%) for acne marks and uneven tone. Helps calm redness, reduce post-acne discoloration, and support clearer-looking skin. With Niacinamide for oil balance and refined pores, Licorice for brightening, and Prebiotics (Inulin) to support the skin barrier. Use on clean skin morning and/or night. Beginners or sensitive skin: start slowly (once daily or every other day). Daytime sunscreen is recommended.','كريم حمض الأزيليك (20%) لآثار الحبوب وتفاوت اللون. يساعد على تهدئة الاحمرار وتقليل التصبغات بعد الحبوب ودعم صفاء البشرة. مع نياسيناميد لتوازن الدهون وتقليل مظهر المسام، عرقسوس للتفتيح، وبريبيوتك (إنولين) لدعم حاجز البشرة. يُستخدم على بشرة نظيفة صباحاً و/أو مساءً. للبشرة الحساسة: ابدأ تدريجياً (مرة يومياً أو يوم بعد يوم). يُنصح بواقي شمس نهاراً.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:16:34',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(24,'جێلی ئەزیلیەک ئەسید تایبەت بە شوێنی زیپکە لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25000,2500,1,'پێکهاتە سەرەکییەکانی:\r\n• Azelaic Acid (10%): ئەمە پێکهاتە سەرەکییەکەیە کە یارمەتی کەمکردنەوەی زیپکە، پەڵەی دوای زیپکە، و سووربوونەوەی پێست دەدات. هەروەها دژە بەکتریایە و ڕێگری لە دروستبوونی زیپکەی نوێ دەکات.\r\n• Niacinamide (ڤیتامین B3): یارمەتی کۆنترۆڵکردنی چەوری پێست دەدات و کونیلەکان بچووک دەکاتەوە.\r\n• Licorice (سۆس): بۆ ڕوونکردنەوەی ڕەنگی پێست و لابردنی پەڵە بەسوودە.\r\n• a-Bisabolol: ماددەیەکی هێورکەرەوەیە بۆ کەمکردنەوەی هەوکردن و خوران.\r\n• Prebiotics: بۆ پاراستنی هاوسەنگی بەکتریا سوودبەخشەکانی سەر پێست.\r\nسوودەکانی ئەم جێڵە:\r\n1. چارەسەری زیپکە: کاریگەرە بۆ جۆرە جیاوازەکانی زیپکە و ڕێگری لە گیرانی کونیلەکان دەکات.\r\n2. لابردنی پەڵە: یارمەتی سپیکردنەوەی ئەو پەڵە قاوەییانە دەدات کە دوای چاکبوونەوەی زیپکە بەجێ دەمێنن.\r\n3. کەمکردنەوەی سووربوونەوە: بۆ ئەو کەسانەی پێستیان سوور دەبێتەوە یان نەخۆشی (Rosacea)یان هەیە زۆر باشە.\r\n4. کۆنترۆڵکردنی چەوری: گونجاوە بۆ ئەو پێستانەی زۆر چەورن و دەدرەوشێنەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• پێویستە لەسەر پێستی پاک و وشک بەکاربهێنرێت.\r\n• ڕۆژی دوو جار (بەیانیان و شەوان) بڕێکی کەمی لێ دەدرێت لەو شوێنانەی کێشەکەیان هەیە یان بە هەموو دەموچاوەکەدا.\r\n• تێبینی گرنگ: لەبەر ئەوەی ترشی تێدایە، دەبێت لە کاتی ڕۆژدا دژەخۆر (Sunscreen) بەکاربهێنیت، چونکە پێست هەستیار دەکات بەرامبەر تیشکی خۆر.\r\n','Azelaic Acid gel (10%) for acne, redness, and post-acne marks. Helps reduce blemishes, calm irritation, and brighten uneven tone. With Niacinamide for oil control, Licorice for brightening, a-Bisabolol for soothing, and Prebiotics to support skin balance. Apply a small amount on clean, dry skin twice daily (face or affected areas). Use sunscreen during the day.','جل حمض الأزيليك (10%) للحبوب والاحمرار وآثار ما بعد الحبوب. يساعد على تقليل الشوائب وتهدئة التهيّج وتفتيح تفاوت اللون. يحتوي على نياسيناميد لضبط الدهون، عرقسوس للتفتيح، ألفا-بيسابولول للتهدئة، وبريبيوتك لدعم توازن البشرة. يُوضع مقدار قليل على بشرة نظيفة وجافة مرتين يومياً (للوجه أو مناطق المشكلة). استخدم واقي شمس نهاراً.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:18:37',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(25,'سیڕۆمی ئینۆ گالوڕۆن تایبەت بە چاودێریکردن و دژی پیری پێست لە بڕاندی هاندڵێس گاردنی رووسی',NULL,NULL,NULL,15,40000,50000,5000,1,'تایبەتمەندییە سەرەکییەکانی بەرهەمەکە:\r\n• دژە چرچولۆچی (Anti-wrinkle): یارمەتی کەمکردنەوەی هێڵە وردەکانی دەموچاو دەدات.\r\n• شێدارکردنێکی قووڵ (Deep moisturizing): بەهۆی هەبوونی ترشی هیالۆرۆنیک، شێدارییەکی زۆر بە پێست دەبەخشێت.\r\n• بەرگری دژی تیشکی خۆر (Resistance against UV): پارێزگارییەکی ڕێژەیی لە پێست دەکات بەرامبەر زیانەکانی تیشکی سەروو بنەوشەیی.\r\nپێکهاتە گرنگەکان:\r\n1. Hyaluronic Acid (ترشی هیالۆرۆنیک): بۆ شێدارکردنەوە و پڕکردنەوەی پێست.\r\n2. Folic Acid (ترشی فۆلیک): یارمەتی نوێکردنەوەی خانەکانی پێست دەدات.\r\n3. Seaweed Extracts (گیراوەی رووەکی دەریایی): دەوڵەمەندە بە پۆلیساکارایدە سروشتییەکان بۆ توندکردنەوەی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی کەم لە سێرمەکە بدە لە پێستی پاککراوە (دەموچاو، مل، دەوروبەری چاو، یان پشتی دەست).\r\n','Hyaluronic serum for hydration and anti-aging care. Helps reduce the look of fine lines and supports deep moisturizing. Includes Hyaluronic Acid for plumping hydration, Folic Acid to support skin renewal, and Seaweed Extracts rich in natural polysaccharides to help firm the skin. Apply a few drops to clean skin (face, neck, around eyes, or hands).','سيروم هيالورونيك للترطيب والعناية بمكافحة علامات التقدّم. يساعد على تقليل مظهر الخطوط الدقيقة ويوفّر ترطيباً عميقاً. يحتوي على حمض الهيالورونيك للترطيب والامتلاء، حمض الفوليك لدعم تجدد البشرة، ومستخلصات الأعشاب البحرية الغنية بالسكريات الطبيعية للمساعدة على شدّ البشرة. تُوضع بضع قطرات على بشرة نظيفة (الوجه، الرقبة، حول العين، أو اليدين).',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:20:49',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(26,'جێلی تایبەت بە چارەسەرکردنی شوێنەواری برین+ پاراستن لە خۆر لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,27000,3500,1,'. ئەرکە سەرەکییەکانی بەرهەمەکە:\r\n• چاککردنەوەی شوێنەواری برین: یارمەتی تەختکردنەوە و نەرمکردنەوەی برینە بەرزبووەوەکان (وەک کێلۆید و هیپەرتۆفیک) دەدات.\r\n• کەمکردنەوەی سووربوونەوە: یارمەتی کەمکردنەوەی ڕەنگی سوور و تۆخی شوێنی برین دەدات بۆ ئەوەی لەگەڵ ڕەنگی پێستدا یەکبگرێتەوە.\r\n• پاراستن لە خۆر (SPF 50+): ئەم خاڵەیان زۆر گرنگە؛ چونکە تیشکی خۆر دەبێتە هۆی تۆخکردنەوە و هەمیشەیی مانەوەی ڕەنگی برین (Hyperpigmentation). بوونی ئەم فلتەرە ڕێگری لە تۆخبوونی برینەکە دەکات.\r\n٢. پێکهاتە گرنگەکان:\r\n• Silicon Elastomer: چینێکی تەنک و نەرم دروست دەکات کە ڕێگری لە لەدەستدانی شێداری پێست دەکات و یارمەتی ڕێکنەخرانەوەی شانەکانی پێست دەدات.\r\n• Vitamin C & E: وەک دژە ئۆکسان کار دەکەن بۆ ڕوونکردنەوەی پێست و زوو چاکبوونەوە.\r\n• Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵی ناوچەی برینەکە.\r\n• Avocadine: یارمەتی کەمکردنەوەی هەوکردن و نەرمکردنەوەی پێست دەدات.\r\n٣. بۆ چ جۆرە برینێک دەبێت؟\r\n• بۆ هەموو جۆرە برینێکی کۆن و نوێ (دوای ئەوەی برینەکە بە تەواوی دادەخرێت).\r\n• برینی نەشتەرگەری، سووتاوی، برینداری، یان برینی جێگەی زیپکە.\r\nچۆنیەتی بەکارهێنان:\r\n١. دڵنیابەرەوە کە شوێنی برینەکە پاک و وشکە.\r\n٢. بڕێکی زۆر کەم لە جێڵەکە بدە لە شوێنەکە و بە هێواشی بڵاوی بکەرەوە (پێویست بە شێلان یان مەساجێکی زۆر ناکات).\r\n٣. دەتوانیت ڕۆژی ٢ جار بەکاری بهێنیت.\r\n٤. ئەگەر ماکیاژ بەکاردێنیت، دوای وشکبوونەوەی جێڵەکە دەتوانیت ماکیاژەکە بخەیتە سەری.\r\nتێبینی گرنگ: نابێت ئەم جێڵە بدرێت لە برینی کراوە (ئەو برینەی هێشتا خوێن یان ئاوی تێدایە). تەنها کاتێک بەکاری بهێنە کە برینەکە بە تەواوی وشک بووەتەوە و داخراوە.\r\n','Scar care gel with sun protection (SPF 50+). Helps improve the look of raised scars (hypertrophic/keloid), soften the area, and reduce redness while protecting the scar from darkening due to sunlight. Key ingredients: Silicone elastomer forms a protective layer, Vitamins C & E support antioxidant care, Hyaluronic Acid hydrates, and Avocadine soothes. Use only after the wound is fully closed and dry. Apply a thin layer 1–2 times daily. Do not use on open wounds.','جل للعناية بآثار الجروح مع حماية من الشمس (SPF 50+). يساعد على تحسين مظهر الندبات المرتفعة (مثل الكيلويد والندبات المتضخمة) وتنعيمها وتقليل الاحمرار مع حماية الندبة من الاسمرار بسبب الشمس. مكوّنات أساسية: سيليكون إيلاستومر لطبقة واقية، فيتامينا C وE كمضادات أكسدة، حمض الهيالورونيك للترطيب، وأفوكادين للتهدئة. يُستخدم فقط بعد إغلاق الجرح تماماً وجفافه. توضع طبقة رقيقة 1–2 مرة يومياً. لا يُستخدم على الجروح المفتوحة.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:23:40',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(27,'جێلی تایبەت بە چارەسەکردنی شێوەنەواری برین لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25000,2500,1,'پێکهاتە سەرەکییەکانی:\r\n• Silicone (Dimethicone): ماددەیەکی بنەڕەتییە بۆ پاراستنی شوێنی برینەکە و هێشتنەوەی بە شێداری، کە یارمەتی تەختکردنەوەی برینە بەرزەکان دەدات.\r\n• Allium Cepa (ئەلیۆم سێپا): دەرهێنراوی پیازە کە ناسراوە بەوەی هەوکردن و سووربوونەوەی برین کەمدەکاتەوە.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و یارمەتی نوێبوونەوەی پێست دەدات.\r\n• Omega 3 & 6: ترشە چەورییەکانن کە یارمەتی نەرمکردنەوەی پێست و چاکبوونەوەی خێراتر دەدەن.\r\nبەکاردێت بۆ چی؟\r\nئەم جێڵە بەکاردێت بۆ باشترکردنی شێوەی ئەم جۆرە برینانەی کە بەهۆی (نەشتەرگەری، سووتان، یان ڕووداوی جیاواز) دروست بوون:\r\n1. Hypertrophic Scars: ئەو برینانەی کە کەمێک بەرز دەبنەوە و سوور دەبن.\r\n2. Keloids: ئەو برینانەی گۆشتی زیادەیان تێدا دروست دەبێت و لە سنووری برینەکە زیاتر بڵاودەبنەوە.\r\nڕێنمایی گرنگ بۆ بەکارهێنان:\r\n• تەنها بۆ بەکارهێنانی دەرەکییە: نابێت بخرێتە ناو چاو یان دەم.\r\n• هەرگیز لەسەر برینی کراوە بەکاری مەهێنە: دەبێت چاوەڕێ بکەیت تاوەکو برینەکە بەتەواوی دادەخرێت و \"قەتماغە\" دەبەستێت یان تەقەڵەکانی لێ دەکرێتەوە، ئینجا دەست بە بەکارهێنانی بکەیت.\r\n• بەردەوامی: بۆ ئەوەی باشترین ئەنجامت دەستبکەوێت، دەبێت بۆ ماوەیەکی درێژخایەن (زۆربەی کات ۲ بۆ ٦ مانگ) ڕۆژانە بەکاری بهێنیت.\r\n','Scar gel for improving the look of raised scars. Contains Silicone (Dimethicone) to protect and hydrate the scar area and help smooth texture. Includes Onion Extract (Allium cepa) to help reduce redness, Vitamin E for antioxidant support, and Omega 3 & 6 to help soften the skin. For external use only. Do not apply on open wounds; start after the wound has fully closed. Best results require consistent daily use for weeks to months.','جل للندبات لتحسين مظهر الندبات المرتفعة. يحتوي على السيليكون (Dimethicone) لحماية وترطيب منطقة الندبة والمساعدة على تنعيم الملمس. مع مستخلص البصل (Allium cepa) للمساعدة في تقليل الاحمرار، فيتامين E لدعم مضادات الأكسدة، وأوميغا 3 و6 للمساعدة على تليين البشرة. للاستعمال الخارجي فقط. لا يُستخدم على الجروح المفتوحة؛ يبدأ بعد إغلاق الجرح تماماً. أفضل النتائج مع الاستمرار اليومي لأسابيع إلى أشهر.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:25:28',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(28,'ماسکی تایبەت بە تێرکردن و بوژانەوەی قژ لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,15000,2500,1,'پێکهاتە سەرەکییەکانی:\r\n• ڤیتامین B3 (Niacinamide): یارمەتی بەهێزکردنی ڕەگی قژ و باشترکردنی تەندروستی بێخی سەر دەدات.\r\n• Keratin Microproteins: ئەم پڕۆتینە بچووکانە دەچنە ناو تاڵەکانی قژەوە و ئەو بەشانەی زیانیان پێگەیشتووە چاک دەکەنەوە.\r\n• پڕۆتینی گەنمی شیکراوە و ڕۆنی ئەرگان: بۆ نەرمکردنەوە و بریقەدارکردنی قژەکە.\r\nسوودەکانی:\r\n• بۆ قژی زیانلێکەوتوو: گونجاوە بۆ ئەو قژانەی بەهۆی بۆیە (صبغ) و ئامێرە گەرمکەرەوەکان (وەک سشوار و ئوتوو) وشک بوون و سووتاون.\r\n• شێدارکردن: بە قووڵی قژەکە تەڕ و شێدار دەکاتەوە.\r\n• نەرمکردن: قژەکە زۆر نەرم دەکات (Silky smooth) و داهێنانی ئاسان دەکات.\r\nشێوازی بەکارهێنان:\r\n١. سەرەتا قژت بە شامپۆ بشۆ و بە باشی ئاوی لێ بکەرەوە.\r\n٢. بڕێکی گونجاو لەم ماسکە بدە لە قژت (زیاتر لە ناوەڕاستی تاڵەکان تا کۆتاییەکەی، دوور بکەوەرەوە لەوەی بیدەیت لە بێخی سەرت ئەگەر قژت چەورە).\r\n٣. بە هێواشی مەساجی پێ بکە.\r\n٤. با بۆ ماوەی ٣ بۆ ٥ خولەک بە قژتەوە بمێنێتەوە.\r\n٥. پاشان بە ئاوێکی زۆر بە باشی بیشۆ.\r\nدەتوانیت بەپێی پێویست (هەفتەی ١ بۆ ٢ جار) بەکاری بهێنیت.\r\nلە لایەن پزیشکانەوە تاقیکراوەتەوە\r\n','Hydration & repair hair mask for dry and damaged hair (from dyeing and heat tools). With Niacinamide (B3) to support scalp and hair vitality, Keratin microproteins to help repair damaged areas, plus hydrolyzed wheat protein and Argan oil for softness and shine. After shampoo, apply to lengths and ends, massage gently, leave 3–5 minutes, then rinse. Use 1–2 times per week as needed.','ماسك ترطيب وإصلاح للشعر الجاف والمتضرر (بسبب الصبغة وأدوات الحرارة). يحتوي على نياسيناميد (B3) لدعم حيوية فروة الرأس والشعر، بروتينات كيراتين دقيقة للمساعدة في إصلاح التلف، مع بروتين قمح محلّل وزيت الأرغان للنعومة واللمعان. بعد الشامبو يُوضع على الأطوال والأطراف ويُدلّك بلطف، يُترك 3–5 دقائق ثم يُشطف. يُستخدم 1–2 مرة أسبوعياً حسب الحاجة.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:27:15',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(29,'ماسکی تایبەت بە چاکردنەوە و شێدارکردنەوەی قژ لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,15000,2500,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• ناوی بەرهەم: Tango Hair Mask Professional (Hydration & Restoration).\r\n• پێکهاتە سەرەکییەکان: ڕۆنی ئەرگان (Argan Oil) و پرۆتینی گەنم (Wheat Proteins).\r\n• بۆ کێ گونجاوە؟: تایبەت دروستکراوە بۆ ئەو قژانەی کە وشکن یان بەهۆی بۆیە و ماددەی کیمیاییەوە تێکچوون.\r\n٢. سوودەکانی بەرهەمەکە:\r\n• شێدارکردنەوە: یارمەتی گەڕاندنەوەی شێ دەدات بۆ تاڵەکانی قژ.\r\n• نوێکردنەوە (Restoration): بەهۆی پرۆتینی گەنمەوە، یارمەتی پڕکردنەوە و بەهێزکردنی ئەو بەشانەی قژ دەدات کە زیانیان پێگەیشتووە.\r\n• نەرمی و درەوشانەوە: قژەکە زۆر نەرم دەکات و دیمەنێکی بریقەداری پێ دەبەخشێت.\r\n٣. چۆنیەتی بەکارهێنان :\r\n1. سەرەتا قژت بە شامپۆ بشۆ و پاشان ئاوەکەی لێ بکەرەوە تاوەکو تەنها بە تەڕی بمێنێتەوە.\r\n2. بڕێکی گونجاو لە ماسکەکە بدە لە قژت (زیاتر جەخت بکەرەوە سەر ناوەڕاست و کۆتایی قژەکە، نەک ڕەگەکەی).\r\n3. بە ئارامی مەساجی پێ بکە.\r\n4. بۆ ماوەی ٣ بۆ ٥ خولەک بە قژتەوە بیهێڵەرەوە.\r\n5. پاشان بە ئاوێکی زۆر و باش بیشۆ.\r\n6. دەتوانیت بەپێی پێویست و لە هەفتەیەکدا ١ بۆ ٢ جار بەکاری بهێنیت\r\n','Professional hydration & restoration hair mask. With Argan oil and Wheat proteins to nourish, strengthen, and improve softness and shine—ideal for dry or chemically treated hair. After shampoo, apply mainly to mid-lengths and ends, massage gently, leave 3–5 minutes, then rinse well. Use 1–2 times weekly.','ماسك شعر احترافي للترطيب وإعادة الحيوية. بزيت الأرغان وبروتينات القمح لتغذية الشعر وتقويته ومنحه نعومة ولمعاناً—مناسب للشعر الجاف أو المتضرر بسبب المواد الكيميائية. بعد الشامبو يوضع على منتصف الشعر والأطراف، يُدلّك بلطف، يُترك 3–5 دقائق ثم يُشطف جيداً. يُستخدم 1–2 مرة أسبوعياً.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:28:56',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(30,'لۆشنی پێستی جەستەی زەیتی زەیتونی پێنیلۆتی لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,16000,3000,1,'پێکهاتە سەرەکییەکان\r\n• شیری گوێدێژ (Donkey Milk): بەوە ناسراوە کە دەوڵەمەندە بە ڤیتامینەکانی (A, B, C, D, E) و زۆر بەسوودە بۆ نوێکردنەوەی خانەکانی پێست و کەمکردنەوەی چرچولۆچی.\r\n• ڕۆنی زەیتوونی ئۆرگانیک: بۆ شێدارکردنێکی قووڵ و پاراستنی نەرمی پێست.\r\n• ئالۆڤێرا (Aloe Vera): یارمەتیدەرە بۆ هێورکردنەوەی پێست، بەتایبەت ئەگەر پێستەکە سووتاوی یان هەستیاری هەبێت.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات بۆ پاراستنی پێست لە زیانە دەرەکییەکان.\r\nتایبەتمەندییە گرنگەکان\r\n• سروشتی بوون: زیاتر لە 97%ی پێکهاتەکانی سروشتین.\r\n• بێ زیان: بەبێ پارابین (Parabens)، ڕەنگە دەستکردەکان (Colorants) و سیلیکۆن دروستکراوە.\r\n• جۆری پێست: بۆ هەموو جۆرە پێستێک گونجاوە (All Skin Types).\r\n• تایبەتمەندی تێکەڵبوون: کۆمپانیاکە دەڵێت زۆر بە خێرایی بە پێستەوە دەبێت و هەستی چەوری بەجێناهێڵێت (Non-greasy).\r\nچۆنیەتی بەکارهێنان\r\nباشترە دوای خۆشتن یان هەر کاتێک هەستت بە وشکی پێست کرد، بڕێکی گونجاو لە لۆشنەکە بدەیت لە جەستەت و بە شێوەی بازنەیی مەساژی پێ بکەیت تا هەڵدەمژرێت.\r\n','Body lotion with olive oil and donkey milk. Rich in vitamins (A, B, C, D, E) to support skin renewal and softness, with organic olive oil for deep hydration, Aloe Vera for soothing, and Vitamin E for antioxidant care. Made with a high percentage of natural ingredients, free from parabens and added colorants, and designed to absorb quickly without a greasy feel. Apply after showering or whenever skin feels dry.','لوشن للجسم بزيت الزيتون وحليب الأتان. غني بالفيتامينات (A وB وC وD وE) لدعم تجدد البشرة ونعومتها، مع زيت زيتون عضوي للترطيب العميق، ألوفيرا للتهدئة، وفيتامين E للعناية المضادة للأكسدة. مصنوع بنسبة عالية من مكونات طبيعية، خالٍ من البارابين والألوان المضافة، ويمتص بسرعة دون ملمس دهني. يُستخدم بعد الاستحمام أو عند الشعور بجفاف البشرة.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:30:38',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(31,'لۆشنی شیری جەستەی پێنیلۆتی لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,16000,3000,1,'. پێکهاتە سەرەکییەکانی\r\n• شیری گوێدرێژ: دەوڵەمەندە بە ڤیتامینەکانی (A, B1, B2, B6, D, E) و تایبەتمەندی دژە پیربوونی هەیە و پێست بە قووڵی شێدار دەکاتەوە.\r\n• ڕۆنی زەیتوونی ئۆرگانیک: یارمەتی نەرمکردنەوەی پێست دەدات.\r\n• ئەلۆڤێرا (Aloe Vera): بۆ هێورکردنەوەی پێست و کەمکردنەوەی هەوکردن بەسوودە.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست لە کاریگەرییە دەرەکییەکان دەپارێزێت.\r\n٢. سوودەکانی بۆ پێست\r\n• شێدارکردنێکی قووڵ: بۆ ئەو کەسانە زۆر باشە کە پێستیان وشکە.\r\n• نەرمکردنی پێست: بەبێ ئەوەی هەست بە چەورییەکی ناخۆش بکەیت، پێستەکە وەک ئاوریشم لێ دەکات.\r\n• سروشتییە: زیاتر لە 97% پێکهاتەکانی سروشتیین و گیای یۆنانی تێدایە.\r\n• بێ ماددەی زیانبەخش: لەسەر بوتڵەکە نووسراوە کە بێ پارابین (Paraben Free) و بێ ڕەنگە (Colorant Free).\r\n٣. زانیارییە گرنگەکان\r\n• بۆ کێ دەبێت؟ بۆ هەموو جۆرە پێستێک گونجاوە (All Skin Types).\r\nچۆن بەکاردێت؟\r\nباشترین کات بۆ بەکارهێنانی دوای خۆشۆردنە کاتێک پێست کەمێک شێی پێوەیە، بڕێکی گونجاو لە جەستەت بدە و مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت\r\n','Donkey milk body lotion for deep hydration and soft, silky skin. Enriched with vitamins and organic olive oil, plus Aloe Vera to soothe and Vitamin E for antioxidant protection. Made with a high percentage of natural ingredients and free from parabens and colorants. Suitable for all skin types. Best used after showering on slightly damp skin.','لوشن للجسم بحليب الأتان لترطيب عميق وبشرة ناعمة كالحرير. مُعزّز بالفيتامينات وزيت زيتون عضوي، مع ألوفيرا للتهدئة وفيتامين E للحماية المضادة للأكسدة. مصنوع بنسبة عالية من مكونات طبيعية وخالٍ من البارابين والألوان. مناسب لجميع أنواع البشرة. يُفضّل استخدامه بعد الاستحمام على بشرة رطبة قليلاً.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:32:47',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(32,'لۆشنی نەرمکەرەوەی پێستی جەستە لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,16000,3000,1,'پێکهاتە سەرەکییەکانی:\r\n• شیری گوێدرێژ (Donkey Milk): کە بەوە ناسراوە دەوڵەمەندە بە ڤیتامین و ماددەی خۆراکی بۆ پێست، یارمەتی نوێکردنەوەی خانەکان و گەنج هێشتنەوەی پێست دەدات.\r\n• ڕۆنی بادەم (Almond Oil): بۆ نەرمکردنەوەی قووڵی پێست و پاراستنی لە وشکبوونەوە.\r\n• ئەلۆڤێرا (Aloe Vera): بۆ هێورکردنەوەی پێست و قووڵ تەڕکردنەوەی.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست لە کاریگەرییە خراپەکانی دەوروبەر دەپارێزێت.\r\nسوودەکانی بەپێی نووسراوی سەر بەرهەمەکە:\r\n• تەڕکەرێکی قووڵە: شێدارییەکی زۆر بە پێست دەبەخشێت و بۆ ماوەیەکی درێژ دەیمێنێتەوە.\r\n• بەبێ چەوری: هەستی چەوری بە پێست نابەخشێت و زوو هەڵدەمژرێت.\r\n• نەرمکەرەوە: پێست زۆر نەرم و لووس دەکات.\r\n• بۆنی خۆش: بۆنی گوڵی لۆتۆسی لێدێت کە هەستێکی ئارامبەخش دەبەخشێت.\r\n• تاقیکردنەوەی پزیشکی بۆ کراوە (Dermatologically Tested).\r\nچۆنیەتی بەکارهێنان:\r\nباشترە دوای خۆشتن کاتێک پێست کەمێک شێدارە بەکاری بهێنیت بۆ ئەوەی باشتر هەڵبمژرێت و شێدارییەکە لەناو پێستدا کۆبکاتەوە.\r\n','Softening body lotion with donkey milk, almond oil, Aloe Vera, and Vitamin E. Provides long-lasting hydration, absorbs quickly without a greasy feel, and leaves skin smooth and comfortable. Features a pleasant lotus fragrance and is dermatologically tested. Use after showering on slightly damp skin for best results.','لوشن للجسم للتنعيم يحتوي على حليب الأتان وزيت اللوز وألوفيرا وفيتامين E. يمنح ترطيباً يدوم ويمتص بسرعة دون إحساس دهني ويترك البشرة ناعمة ومريحة. برائحة لطيفة (اللوتس) ومختبر جلدياً. يُستخدم بعد الاستحمام على بشرة رطبة قليلاً للحصول على أفضل نتيجة.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:35:02',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(33,'لۆشنی شێدارکەرەوەی شیری جەستەی بۆن گوڵی سپی لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,16000,3000,1,'پێکهاتە سەرەکییەکانی:\r\nئەم بەرهەمە تێکەڵەیەکە لە چەند ماددەیەکی سوودبەخش بۆ پێست:\r\n• شیری گوێدرێژ (Donkey Milk): بەوە ناسراوە کە دەوڵەمەندە بە ڤیتامینەکان و یارمەتی نوێکردنەوەی خانەکانی پێست دەدات.\r\n• زەیتی بادەم (Almond Oil): بۆ شێدارکردنەوە و نەرمکردنی پێست زۆر کاریگەرە.\r\n• ئەلۆڤێرا (Aloe Vera): پێست ئارام دەکاتەوە و دژی هەوکردنە.\r\n• ڤیتامین E: پارێزگاری لە پێست دەکات و وەک دژە ئۆکسان کار دەکات.\r\nتایبەتمەندییە بەسوودەکانی:\r\n• شێدارکردن (Moisturization): پێست بە قووڵی شێدار دەکات و ڕێگری لە وشکبوونەوەی دەکات.\r\n• تەلمیکردنی پێست: دەبێتە هۆی ئەوەی پێستت وەک ئاوریشم نەرم و لووس بێت.\r\n• بێ چەوری:  هەستی چەوری بە پێست نابەخشێت (Without greasy feeling).\r\n• بێ پارابین (Parabens Free): پارابین ماددەیەکی پارێزەرە کە هەندێک کەس پێیان باشە لە بەرهەمەکاندا نەبێت، ئەم بەرهەمە بێ ئەو ماددەیەیە.\r\n• پشکنینی پزیشکی: لەڕووی پێستەوە پشکنینی بۆ کراوە (Dermatologically Tested).\r\nچۆن بەکاردێت؟\r\nباشترین کات بۆ بەکارهێنانی دوای گەرماوکردنە، کاتێک پێستت کەمێک شێی پێوەیە، بڕێکی گونجاو لە شیرەکە بدە لە تەواوی جەستەت و بە شێوەی بازنەیی مەساژی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\n','Moisturizing body lotion with donkey milk, almond oil, Aloe Vera, and Vitamin E. Deeply hydrates, helps soothe, and leaves skin silky smooth without greasiness. Free from parabens and dermatologically tested. Apply after bathing and massage until absorbed.','لوشن مرطّب للجسم يحتوي على حليب الأتان وزيت اللوز وألوفيرا وفيتامين E. يرطّب بعمق ويساعد على تهدئة البشرة ويتركها ناعمة دون ملمس دهني. خالٍ من البارابين ومختبر جلدياً. يُستخدم بعد الاستحمام مع تدليك حتى الامتصاص.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:36:34',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(34,'لۆشنی شێدارکەرەوەی شیری جەستە لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,16000,3000,1,'پێکهاتە سەرەکییەکانی:\r\n• شیری گوێدێژ (Donkey Milk): بەوە ناسراوە کە دەوڵەمەندە بە ڤیتامینەکان و یارمەتی نوێکردنەوەی خانەکانی پێست دەدات.\r\n• ڕۆنی زەیتوون (Olive Oil): بۆ شێدارکردنەوەیەکی قووڵ و پاراستنی پێست لە وشکبوونەوە.\r\n• ئەلۆڤێرا (Aloe Vera): بۆ هێورکردنەوەی پێست و کەمکردنەوەی سووربوونەوە و هەستیاری.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست لە پیربوون دەپارێزێت.\r\nسوودە گرنگەکانی:\r\n1. شێدارکردن: بەهۆی پێکهاتە دەوڵەمەندەکەیەوە، شێدارییەکی زۆر بە پێست دەبەخشێت کە بۆ ماوەیەکی درێژ دەمێنێتەوە.\r\n2. نەرمکردنی پێست: دەبێتە هۆی ئەوەی پێستەکە زۆر نەرم و لووس بێت بەبێ ئەوەی هەستی چەورییەکی ناخۆش (Greasy feeling) بەجێبهێڵێت.\r\n3. تەندروستی پێست: یارمەتی گەشانەوە و تازەمانەوەی پێست دەدات.\r\nتایبەتمەندییە تەنکنیکییەکان:\r\n• بێ پارابین (Parabens Free): ماددەی پارابینی تێدا نییە کە زۆرکەس لێی بەدوور دەگرن.\r\n• تاقیکراوەی پزیشکی (Dermatologically Tested): لە ڕووی پزیشکی پێستەوە تاقیکراوەتەوە.\r\n','Moisturizing donkey milk body lotion with olive oil, Aloe Vera, and Vitamin E. Gives long-lasting hydration, softens skin, and absorbs quickly without leaving a greasy layer. Paraben-free and dermatologically tested.','لوشن مرطّب للجسم بحليب الأتان مع زيت الزيتون وألوفيرا وفيتامين E. يمنح ترطيباً يدوم ويجعل البشرة أكثر نعومة ويمتص بسرعة دون طبقة دهنية. خالٍ من البارابين ومختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:38:22',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(35,'لۆشنی ڕوونکردنەوە و سپی کردنەوەیی پێستی دەم و چاو و جەستە لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,25000,35000,5000,1,'• ڕوونکردنەوەی پێست: کاردەکات بۆ کاڵکردنەوەی پەڵە قاوەییەکان و ئەو شوێنانەی ڕەنگیان گۆڕاوە.\r\n• پێکهاتە گرنگەکان: دەوڵەمەند کراوە بە ڤیتامین B3 (Niacinamide) کە زۆر بەناوبانگە بۆ سپیکردنەوە و پاراستنی پێست، لەگەڵ پێکهاتەی ڕووەکی وەک گۆیاڤا، پاپایا، و سەکسفراج (Saxifrage).\r\n• شێدارکردن: جگە لە سپیکردنەوە، وەک شێدارکەرەوەیەک کاردەکات بۆ ئەوەی پێستەکە بە نەرمی بهێڵێتەوە.\r\n• جۆری پێست: لەسەر تێپەڕەکە نووسراوە کە بۆ هەموو جۆرە پێستێک گونجاوە.\r\nلایەنە ئەرێنییەکان:\r\n• بێ پارابینە: لە ماددەی پارابین (Paraben Free) پاککراوەتەوە کە زۆرجار دەبێتە هۆی هەستیاری.\r\n• تێست کراوە: لە ڕووی تەندروستی پێستەوە (Dermatologically Tested) تاقی کراوەتەوە\r\n','Brightening and whitening body lotion for face and body. Helps reduce the look of dark spots and uneven tone. Enriched with Niacinamide (Vitamin B3) plus plant extracts such as guava, papaya, and saxifrage. Also moisturizes to keep skin soft. Suitable for all skin types. Paraben-free and dermatologically tested.','لوشن تفتيح وتبييض للوجه والجسم. يساعد على تقليل مظهر البقع الداكنة وتفاوت اللون. مُعزّز بالنياسيناميد (فيتامين B3) مع مستخلصات نباتية مثل الجوافة والبابايا والسكسفراج. كما يرطّب ليحافظ على نعومة البشرة. مناسب لجميع أنواع البشرة. خالٍ من البارابين ومختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:41:49',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(36,'لۆشنی پێستی جەستەی بۆن لاڤێندەر و گوڵی پرتەقاڵ لە بڕاندی پاپوتسانسی یۆنانی',NULL,NULL,NULL,15,4000,8000,2000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆنەکەی: تێکەڵەیەکە لە بۆنی گوڵی پرتەقاڵ (Orange Blossom) و لاڤیندەر (Lavender)، کە بۆنێکی خۆش و ئارامکەرەوەی هەیە.\r\n• پێکهاتە: ئەم بەرهەمە ڤیگانە (Vegan) و لە ١٠٠٪ پێکهاتەی ڕووەکی دروستکراوە.\r\n• بێ ماددەی زیانبەخش: فاکتەرێکی زۆر باشی ئەوەیە کە بەبێ پارابین (Parabens) و بەبێ ڕۆنی کانزایی (Mineral Oils) دروستکراوە، کە ئەمەش بۆ پێست تەندروستترە.\r\n• شێدارکردن: کۆمپانیاکە دەڵێت بۆ ماوەی ٢٤ کاتژمێر پێست بە شێداری دەهێڵێتەوە.\r\n• خێرا هەڵمژین: زوو بە پێستەوە وشک دەبێتەوە و هەستی چەورییەکی بێزارکەر جێناهێڵێت.\r\nپێکهاتە سوودبەخشەکانی ناو لۆشنەکە:\r\n١. Prebiotics (پریبایۆتیکس): یارمەتی پاراستنی هاوسەنگی سروشتی پێست دەدات و بەربەستی بەرگری پێست بەهێز دەکات.\r\n٢. ڤیتامین E: وەکو دژە ئۆکسان کار دەکات و پێست لە پیربوون و کاریگەرییە خراپەکانی دەوروبەر دەپارێزێت.\r\n٣. ئەلۆڤێرا (Aloe): بۆ نەرمکردنەوە و هێورکردنەوەی پێست زۆر بەسوودە.\r\nزانیاری زیاتر:\r\n• تێبینی: لەلایەن پزیشکانی پێستەوە تاقی کراوەتەوە (Dermatologically Tested).\r\nبە گشتی ئەم لۆشنە گونجاوە بۆ ئەو کەسانەی پێستیان وشکە یان دەیانەوێت دوای گەرماو پێستیان نەرم و بۆنخۆش بێت بەبێ بەکارهێنانی ماددەی کیمیایی قورس.\r\n','Vegan body lotion with Orange Blossom and Lavender scent. Made from plant-based ingredients, free from parabens and mineral oils, and designed to absorb quickly without greasiness. Enriched with prebiotics, Vitamin E, and Aloe Vera to help support skin comfort and hydration. Dermatologically tested. Suitable for dry skin or anyone who wants soft, nicely scented skin.','لوشن جسم نباتي (فيغان) برائحة زهر البرتقال واللافندر. مصنوع من مكونات نباتية وخالٍ من البارابين والزيوت المعدنية ويمتص بسرعة دون ملمس دهني. مُعزّز بالبريبيوتك وفيتامين E وألوفيرا لدعم راحة البشرة وترطيبها. مختبر جلدياً. مناسب للبشرة الجافة أو لمن يريد بشرة ناعمة برائحة جميلة.',NULL,NULL,NULL,NULL,NULL,'2025-12-30 17:43:45',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(37,'لۆشنی پێستی جەستەی بۆن ڤانێلا و دار سەندەل لە بڕاندی پاپوتسانیسی یۆنانی',NULL,NULL,NULL,15,4000,8000,2000,1,'لۆشنی پێستی جەستەی بۆن ڤانێلا و دار سەندەل لە بڕاندی پاپوتسانیسی یۆنانی','Vanilla & Sandalwood scented body lotion (Papoutsanis). Leaves skin soft and lightly fragranced.','لوشن جسم برائحة الفانيلا وخشب الصندل (Papoutsanis). يترك البشرة ناعمة وبرائحة لطيفة.',NULL,NULL,NULL,NULL,NULL,'2025-12-31 06:29:35',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(38,'کرێمی شێدارکەرەوەی دەستی پێنیلۆتی لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,2500,5500,1500,1,'. پێکهاتە سەرەکییەکان\r\n• شیری گوێدرێژ: دەوڵەمەندە بە ڤیتامین و ماددەی خۆراکی کە یارمەتی نوێکردنەوەی خانەکانی پێست دەدات.\r\n• ڕۆنی زەیتی کۆنی ئۆرگانیک: بۆ شێدارکردنەوەی قووڵی پێست.\r\n• ئەلۆڤێرا و ڤیتامین E: بۆ پاراستنی پێست و نەرمکردنەوەی.\r\n• ڕێژەی سروشتی: زیاتر لە 97% پێکهاتەکانی سروشتین.\r\n٢. سوودەکانی بەکارهێنان\r\n• شێدارکەرەوە: بە قووڵی پێستی دەست و جەستە شێدار دەکات و بەتەواوی نایهێڵێت وشک ببێتەوە.\r\n• نەرمی و بریقە: پێستەکە زۆر نەرم دەکات (Silky texture) و کاریگەرییەکەی بۆ ماوەیەکی درێژ دەمێنێتەوە.\r\n• خێرا هەڵدەمژرێت: یەکێک لە باشترین خەسڵەتەکانی ئەوەیە کە چەوری جێنەهێڵێت و پێستەکە بە خێرایی هەڵیدەمژێت','Donkey milk hand cream. Rich in vitamins and nourishing ingredients to help soften and moisturize hands. Contains organic olive oil for deep hydration, Aloe Vera and Vitamin E for comfort and protection. High natural content and fast-absorbing without greasy residue.','كريم يدين بحليب الأتان. غني بالفيتامينات ومكونات مغذية لتنعيم اليدين وترطيبهما. يحتوي على زيت زيتون عضوي لترطيب عميق، وألوفيرا وفيتامين E للراحة والحماية. نسبة عالية من المكونات الطبيعية ويمتص بسرعة دون ملمس دهني.',NULL,NULL,NULL,NULL,NULL,'2025-12-31 06:32:20',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(39,'کرێمی شێدارکەرەوەی پێستی دەست و جەستەی بۆن گوڵاو لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,2000,5000,1500,1,'• تایبەتمەندی سەرەکی: شێدارکەرەوەیە و زوو لەلایەن پێستەوە دەمژرێت بەبێ ئەوەی هەستێکی چەوری بەجێبهێڵێت.\r\nپێکهاتە گرنگەکان:\r\nبەپێی ئەوەی لەسەر پاکەتەکە نووسراوە، ئەم ماددانەی تێدایە کە یارمەتی نەرمکردنەوەی پێست دەدەن:\r\n1. ڕۆنی بادەم (Almond Oil): بۆ نەرمکردنەوە و قووڵ شێدارکردنەوەی پێست.\r\n2. ئالۆڤێرا (Aloe Vera): بۆ هێورکردنەوەی پێست و پاراستنی لە وشکبوونەوە.\r\n3. ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست دەپارێزێت.\r\n4. بەبێ پارابین (Parabens Free): ئەمە خاڵێکی ئەرێنییە کە ماددەی پارێزەری زیانبەخشی تێدا نییە.\r\n','Fast-absorbing moisturizing hand & body cream with a pleasant scent. Helps keep skin soft without greasy feeling. Key nourishing ingredients (as listed): Almond oil, Aloe Vera, and Vitamin E. Paraben-free.','كريم ترطيب سريع الامتصاص لليدين والجسم برائحة لطيفة. يساعد على إبقاء البشرة ناعمة دون إحساس دهني. مكوّنات مغذية (حسب العبوة): زيت اللوز، ألوفيرا، وفيتامين E. خالٍ من البارابين.',NULL,NULL,NULL,NULL,NULL,'2025-12-31 06:34:01',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(40,'کرێمی شێدارکەرەوەی دەستی پێنیلۆتی لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,2500,5500,1500,1,'پێکهاتە سەرەکییەکان\r\n• شیری گوێدرێژ (Donkey Milk): کە بەوە ناسراوە دەوڵەمەندە بە ڤیتامین و ماددەی خۆراکی بۆ پێست، یارمەتی نوێکردنەوە و نەرمکردنەوەی پێست دەدات.\r\n• زەیتی زەیتونی ئۆرگانیک: بۆ شێدارکردنەوەی قووڵ و پاراستنی پێست لە وشکبوونەوە.\r\n• ئەلۆڤێرا (Aloe Vera): بۆ هێورکردنەوەی پێست و کەمکردنەوەی سووربوونەوە.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست لە پیربوونی پێشوەختە دەپارێزێت.\r\nتایبەتمەندییەکانی بەرهەمەکە\r\n• ڕێژەی پێکهاتەی سروشتی: زیاتر لە 97% پێکهاتەکانی سروشتین.\r\n• جۆری پێست: بۆ هەموو جۆرە پێستێک گونجاوە.\r\n• تایبەتمەندی هەڵمژین: زۆر بە خێرایی لەلایەن پێستەوە هەڵدەمژرێت و شوێنەواری چەوری (Greasy) جێناهێڵێت.\r\n• بەکارهێنان: بۆ بەکارهێنانی ڕۆژانە گونجاوە، بەتایبەت بۆ ئەو کەسانەی دەستیان وشک دەبێتەوە.\r\n• تەندروستی: لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە (Dermatologically Tested) و ماددەی پارابین و ڕەنگی دەستکردی تێدا نییە.\r\n','Donkey milk hand cream with organic olive oil, Aloe Vera, and Vitamin E. High natural content, suitable for daily use, absorbs quickly without greasiness. Dermatologically tested and free from parabens and added colorants.','كريم يدين بحليب الأتان مع زيت زيتون عضوي وألوفيرا وفيتامين E. نسبة طبيعية عالية، مناسب للاستخدام اليومي، يمتص بسرعة دون ملمس دهني. مختبر جلدياً وخالٍ من البارابين والألوان المضافة.',NULL,NULL,NULL,NULL,NULL,'2025-12-31 06:58:45',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(41,'کرێمی شێدارکەرەوەی پێستی دەست و جەستە لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,2000,5000,1500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سەرەکی: ڕۆنی زەیتوون (Olive Oil) و ئالۆوێرا (Aloe Vera).\r\n• بۆ کێ دەبێت؟ تایبەتە بۆ پێستی ئاسایی (Normal Skin).\r\n• بەکارهێنان: هەم بۆ دەست و هەم بۆ هەموو جەستە بەکاردێت بۆ شێدارکردنەوە (Moisturising).\r\nسوودەکانی:\r\n• نەرمی و شێداری: پێست بە قووڵی دەبوژێنێتەوە و نەرمی و شێدارییەکی زۆری پێ دەبەخشێت.\r\n• خێرا هەڵمژین: زۆر بە خێرایی لەلایەن پێستەوە هەڵدەمژرێت و چینی چەوری بەسەر پێستەوە جێناهێڵێت.\r\n• تەندروستی پێست: بەبێ ماددەی پاراگۆن (Parabens Free) دروست کراوە کە ئەمەش بۆ تەندروستی پێست باشترە\r\n','Moisturizing hand & body cream for normal skin. With Olive oil and Aloe Vera to provide softness and hydration. Absorbs quickly without leaving an oily layer. Paraben-free.','كريم مرطّب لليدين والجسم للبشرة العادية. يحتوي على زيت الزيتون وألوفيرا لمنح نعومة وترطيب. يمتص بسرعة دون طبقة دهنية. خالٍ من البارابين.',NULL,NULL,NULL,NULL,NULL,'2025-12-31 07:00:50',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(42,'شامپۆی هێورکەرەوەی پێستی کاراڤاکی لە بڕاندی پاپوتیسانسی یۆنانی',NULL,NULL,NULL,15,0,0,0,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سەرەکی: لە ماندارینی شیرین (لالەنگی) و گوڵی کەلێندۆلا (Calendula) پێکهاتووە.\r\n• سروشتی بوون: %95ی پێکهاتەکانی لە سەرچاوەی سروشتی وەرگیراون.\r\n• تایبەتمەندی بەکارهێنان: وەک \"شامپۆیەکی نەرم\" (Gentle Shower Gel) وەسف کراوە، کە گونجاوە بۆ هەموو ئەندامانی خێزان چونکە پێست وشک ناکاتەوە و نایخورێنێت.\r\n• ڤیتامینەکان: دەوڵەمەندە بە ڤیتامین E کە یارمەتی پاراستن و شێدارکردنەوەی پێست دەدات.\r\nسوودەکانی:\r\n1. بۆنێکی خۆش و تازە: تێکەڵەی ماندارین هەستێکی گەشاوە و وزەبەخشت پێ دەبەخشێت لە کاتی خۆشتندا.\r\n2. هێورکەرەوەی پێست: بەهۆی هەبوونی گیراوەی بایۆ-کەلێندۆلا، یارمەتی هێورکردنەوەی پێستە هەستیارەکان\r\n4. تەندروستی: لە ڕووی پێستەوە تاقی کراوەتەوە (Dermatologically Tested).\r\nچۆنیەتی بەکارهێنان:\r\nبڕێکی گونجاو بدە لە ئیسفەنجی خۆشتن یان ڕاستەوخۆ لە پێستت بدە تا کەف دەکات، پاشان بە ئاو بێشۆ.\r\n','Gentle shower gel with sweet mandarin and calendula. Made with a high percentage of natural-origin ingredients and enriched with Vitamin E. Suitable for the whole family; cleanses without drying and helps soothe sensitive skin. Dermatologically tested. Apply to sponge or skin, lather, then rinse.','جل استحمام لطيف برائحة اليوسفي الحلو والآذريون (Calendula). مصنوع بنسبة عالية من مكونات ذات مصدر طبيعي ومُعزّز بفيتامين E. مناسب لجميع أفراد العائلة؛ ينظّف دون تجفيف ويساعد على تهدئة البشرة الحساسة. مختبر جلدياً. يوضع على الإسفنجة أو الجلد، يُرغى ثم يُشطف.',NULL,NULL,NULL,NULL,NULL,'2025-12-31 07:08:12',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(43,'شامپۆی شێدارکەرەوەی پێستی جەستەی کاراڤاکی لە بڕاندی پاپوتیسانسی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'١. پێکهاتە سەرەکییەکان\r\n• شیری بادەم (Almond Milk): یارمەتی نەرمکردنەوە و شێدارکردنەوەی پێست دەدات.\r\n• گوڵەبەڕۆژە (Sunflower): بۆ پاراستنی پێست و پێدانی درەوشانەوە بەسوودە.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست لە وشکبوونەوە دەپارێزێت.\r\n• ٩٥٪ پێکهاتەی سروشتی: کۆمپانیاکە ئاماژەی بەوە کردووە کە زۆربەی پێکهاتەکانی لە سەرچاوەی سروشتییەوە وەرگیراون.\r\n٢. تایبەتمەندییە گرنگەکان\r\n• شێدارکەرەوە (Moisturizing): تایبەت دروستکراوە بۆ ئەوەی پێست بە نەرمی بهێڵێتەوە و نەیەڵێت دوای گەرماو وشک ببێتەوە.\r\n• بۆنی خۆش: بۆنێکی ئارامکەرەوە و سووکی هەیە کە بۆ هەموو ئەندامانی خێزان گونجاوە.\r\n• پشکنینی پزیشکی: لە لایەن پزیشکانی پێستەوە تاقی کراوەتەوە (Dermatologically Tested).\r\n','Moisturizing shower gel with almond milk and sunflower, enriched with Vitamin E. High natural-origin formula designed to keep skin soft and comfortable after bathing. Pleasant, light scent suitable for the whole family. Dermatologically tested.','جل استحمام مرطّب بحليب اللوز ودوّار الشمس، مُعزّز بفيتامين E. تركيبة بنسبة عالية من مكونات ذات مصدر طبيعي للمحافظة على نعومة البشرة بعد الاستحمام. برائحة خفيفة ومناسبة للعائلة. مختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-01 18:17:08',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(44,'شامپۆی ئارامکەرەوەی پێستی جەستەی کاراڤاکی لە بڕاندی پاپوتیسانسی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سەرەکی: گوڵەبەیبوون (Chamomile)ی یۆنانی ئۆرگانیکی تێدایە کە بەوە ناسراوە پێست ئارام دەکاتەوە.\r\n• سروشتی بوون: %95ی پێکهاتەکانی لە سەرچاوەی سروشتی وەرگیراون.\r\n• ڤیتامین E: تێدایە کە یارمەتی تەندروستی و شێدارکردنەوەی پێست دەدات.\r\n• بەکارهێنان: بۆ هەموو ئەندامانی خێزان گونجاوە (بە منداڵانیشەوە) و بۆ پێستی هەستیاریش باشە چونکە لەلایەن پزیشکی پێستەوە تاقی کراوەتەوە (Dermatologically Tested).\r\nسوودەکانی بەرهەمەکە:\r\n1. ئارامکەرەوە: بەهۆی هەبوونی گوڵەبەیبوون، یارمەتی حەسانەوە و کەمکردنەوەی سترێس دەدات لەکاتی خۆشۆردندا.\r\n2. شێدارکەرەوە: پێست وشک ناکاتەوە و بە نەرمی دەیهێڵێتەوە.\r\nپێکهاتە کیمیاییەکان:\r\nئەم بەرهەمە ماددەی Sodium Laureth Sulfate (SLES) تێدایە کە بەرپرسە لە دروستکردنی کەف، هەروەها گلیسرین و پێکهاتەی دیکەی تێدایە بۆ پاراستنی شێداری پێست.\r\n','Soothing shower gel with organic Greek chamomile. High natural-origin ingredients and enriched with Vitamin E. Suitable for the whole family (including sensitive skin). Cleanses gently without excessive dryness. Dermatologically tested.','جل استحمام مهدّئ يحتوي على البابونج اليوناني العضوي. بمكونات ذات مصدر طبيعي وبإضافة فيتامين E. مناسب لجميع أفراد العائلة (ومناسب للبشرة الحساسة). ينظّف بلطف دون جفاف زائد. مختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-01 18:20:09',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(45,'شامپۆی بوژێنەرەوەی جەستەی کاراڤاکی لە بڕاندی پاپوتیسانسی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'. پێکهاتەی سروشتی: لە ٪٩٥ی پێکهاتەکانی لە سەرچاوەی سروشتی وەرگیراون.\r\n٢. پێکهاتەی سەرەکی: جەخت لەسەر بیۆ-قەوزەی دەریایی (Bio Seaweed Extract) و ڤیتامین E کراوەتەوە، کە یارمەتی نەرمکردن و پاراستنی پێست دەدەن لە وشکبوونەوە.\r\n٣. بۆن: بۆنێکی فرێش و \"نەسیمی دەریای ئیجە\"ی هەیە کە هەستی ئارامی و نوێبوونەوەت پێ دەبەخشێت.\r\n٤. بۆ هەمووان: ئەم بەرهەمە بۆ هەموو ئەندامانی خێزان گونجاوە و لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە (Dermatologically Tested).\r\nپێکهاتە کیمیاییەکان (Ingredients):\r\nلە لیستی پێکهاتەکانیدا ئەمانە دەبینرێن:\r\n• Aqua (Water): ئاو وەک بنچینە.\r\n• Sodium Laureth Sulfate: ماددەیەکە بۆ دروستکردنی کەف (رەغوە).\r\n• Glycerin: بۆ شێدارکردنەوەی پێست.\r\n• Coco Glucoside: پاککەرەوەیەکی نەرمە.\r\n• Citric Acid: بۆ ڕێکخستنی ترشێتی (pH) ی پێست.\r\n','Revitalizing shower gel with a fresh “Aegean sea breeze” scent. High natural-origin ingredients, enriched with Bio Seaweed Extract and Vitamin E to help soften and protect skin from dryness. Suitable for the whole family. Dermatologically tested.','جل استحمام مُنعش برائحة “نسيم بحر إيجه”. بمكونات ذات مصدر طبيعي ومُعزّز بمستخلص الطحالب البحرية الحيوي وفيتامين E للمساعدة على تنعيم البشرة وحمايتها من الجفاف. مناسب للعائلة. مختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-01 18:22:40',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(46,'شامپۆی تایبەت بە گەشاوەکردن وتازەکردنەوەی پێستی جەستەی کاراڤاکی لە بڕاندی پاپوتسانسی یۆنانی',NULL,NULL,NULL,15,100,0,0,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆن و پێکهاتە: ئەم بەرهەمە لە گوڵی یاسەمین (Jasmine) و بەرگامۆتی یۆنانی (Bergamot) پێکهاتووە. بۆنێکی زۆر خۆش و فرێشی هەیە.\r\n• سروشتی بوون: ۹٥٪ی پێکهاتەکانی لە سەرچاوەی سروشتی وەرگیراون.\r\n• ڤیتامینەکان: دەوڵەمەندە بە ڤیتامین E کە وەک دژە ئۆکسان کاردەکات و پێست دەپارێزێت.\r\n• بەکارهێنان: بۆ هەموو ئەندامانی خێزان گونجاوە (بۆ منداڵانی سەروو ۳ ساڵ).\r\n• تایبەتمەندی تەندروستی: لە ڕووی جەڵدییەوە تاقیکراوەتەوە (Dermatologically Tested)، پێست وشک ناکاتەوە و نابێتە هۆی خوران و سووربوونەوە.\r\nپێکهاتە گرنگەکان (Ingredients):\r\nبەپێی ئەوەی لەسەر پشتی قوتووەکە نووسراوە:\r\n1. Aqua (ئاو): بنچینەی سەرەکی بەرهەمەکە.\r\n2. Glycerin: بۆ شێدارکردنەوەی پێست.\r\n3. Citrus Aurantium Bergamia Fruit Extract: گیراوەی میوەی بەرگامۆت کە پێست گەشاوە دەکات.\r\n4. بەبێ پارابین: لە لیستەکەدا ماددە زیانبەخشە کلاسیکییەکان نابینرێن.\r\n','Refreshing shower gel with Jasmine and Greek bergamot. High natural-origin formula enriched with Vitamin E. Suitable for the whole family (3+ years). Dermatologically tested; cleanses gently without causing irritation.','جل استحمام مُنعش بالياسمين والبرغموت اليوناني. تركيبة بنسبة عالية من مكونات ذات مصدر طبيعي مع فيتامين E. مناسب للعائلة (أعمار 3 سنوات فما فوق). مختبر جلدياً؛ ينظّف بلطف دون تهيّج.',NULL,NULL,NULL,NULL,NULL,'2026-01-01 18:26:03',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(47,'شامپۆی تایبەت بە بەهێزکردن ە گەشکردنەوەی قژی کاراڤاکی لە بڕاندی پاپوتسانیسی یۆنانی',NULL,NULL,NULL,15,10000,9750,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سروشتی: ۹٥٪ی پێکهاتەکانی لە سەرچاوەی سروشتی وەرگیراون.\r\n• بەکارهێنان: گونجاوە بۆ بەکارهێنانی ڕۆژانە، بەتایبەت بۆ ئەو قژانەی کە تەنک بوون یان لاوازن.\r\n• پێکهاتە گرنگەکان:\r\n• بایۆتین (Biotin): یارمەتی بەهێزکردنی تاڵەکانی قژ و خێراکردنی گەشەی قژ دەدات.\r\n• گلایکۆجین (Glycogen): وزە بە تاڵەکانی قژ دەبەخشێت بۆ ئەوەی پڕتر و تەندروستتر دەربکەون.\r\n• عەلوج (Eucalyptus): جۆرە دارێکە (ئێکالیپتۆس) کە وەک پاککەرەوە و گەشەپێدەرێکی سروشتی کاردەکات.\r\nسوودەکانی:\r\n• یارمەتی چڕکردنەوە و زیادکردنی قەبارەی قژ دەدات.\r\n• تاڵەکانی قژ لە ڕەگەوە بەهێز دەکات بۆ ئەوەی کەمتر هەڵوەرێن.\r\n• هەستی تازەیی و خاوێنییەکی باش بە پێستی سەر دەبەخشێت.\r\n• پشکنینی پزیشکی: لەلایەن پزیشکانی پێستەوە تاقی کراوەتەوە (Dermatologically Tested).\r\nشێوازی بەکارهێنان:\r\nبڕێکی گونجاو بدە لە قژی تەڕ، بە هێواشی بیشێلە تا کەف دەکات، پاشان بە باشی بە ئاو بیشۆ. ئاگاداربە بەر چاو نەکەوێت.\r\n','Strengthening shampoo for thin or weak hair. High natural-origin formula designed for daily use. With Biotin to support stronger hair, Glycogen for energy and fuller look, and Eucalyptus for a fresh, clean scalp feel. Helps improve volume and reduce breakage. Dermatologically tested. Apply to wet hair, massage to lather, then rinse.','شامبو لتقوية الشعر الخفيف أو الضعيف. تركيبة بنسبة عالية من مكونات ذات مصدر طبيعي ومناسب للاستخدام اليومي. يحتوي على البيوتين لدعم قوة الشعر، والجليكوجين لمنح طاقة ومظهراً أكثر كثافة، والأوكالبتوس لإحساس منعش ونظيف لفروة الرأس. يساعد على زيادة الحجم وتقليل التكسر. مختبر جلدياً. يُستخدم على شعر مبلل مع تدليك حتى تتكون رغوة ثم يُشطف.',NULL,NULL,NULL,NULL,NULL,'2026-01-01 18:28:13',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(48,'شامپۆی تایبەت بە بریقە و گەشانەوەی قژی کاراڤاکی لە بڕاندی پاپوتسانیسی یۆنانی ',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• ناوی بەرهەم: Revitalizing Shampoo (شامپۆی بوژێنەرەوە).\r\n• بۆ چی بەکاردێت: بۆ بەخشینی بریقە و گەشاوەیی (Shine & Vitality) بە قژ.\r\n• پێکهاتە بنەڕەتییەکان:\r\n• زەعفەرانی یۆنانی (Greek Saffron): کە تایبەتمەندی دژە ئۆکسانی هەیە و قژ دەپارێزێت.\r\n• مەنداڵینا (Tangerine): بۆنێکی خۆش و گەشاوەیی بە قژ دەبەخشێت.\r\n• کیراتینی ڕووەکی (Plant-based Keratin): یارمەتی بەهێزکردنی تاڵەکانی قژ دەدات.\r\nزانیاری زیاتر (بەپێی پشتی بوتڵەکە):\r\n1. پێکهاتەی سروشتی: ۹٥٪ی پێکهاتەکانی لە سەرچاوەی سروشتین.\r\n2. بۆ کێ دەبێت؟: گونجاوە بۆ هەموو ئەندامانی خێزان (بە گەورە و بچووکەوە).\r\n3. سوودەکانی:\r\n• قژ نەرم دەکات و بریقەی پێ دەبەخشێت.\r\n• لاستیکییەت (Elasticity) بە قژ دەدات و ڕێگری لە بژبوونەوە (Frizz) دەکات.\r\n• پێستی سەر وشک ناکاتەوە چونکە پێکهاتەی سووکی هەیە','Revitalizing shampoo for shine and vitality. High natural-origin formula for the whole family. With Greek saffron for antioxidant care, tangerine for a fresh scent, and plant-based keratin to support stronger, smoother hair. Helps add shine, improve elasticity, and reduce frizz without drying the scalp.','شامبو مُجدّد لمنح لمعان وحيوية. تركيبة بنسبة عالية من مكونات ذات مصدر طبيعي ومناسبة للعائلة. يحتوي على الزعفران اليوناني للعناية المضادة للأكسدة، واليوسفي لرائحة منعشة، وكيراتين نباتي لدعم نعومة وقوة الشعر. يساعد على زيادة اللمعان وتحسين المرونة وتقليل النفشة دون تجفيف فروة الرأس.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 13:44:32',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(49,'شامپۆی تایبەت بە تێرکردن و شێدارکردنەوەی قژی کاراڤاکی لە بڕاندی پاپوتسانیس یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'\r\nپێکهاتە سەرەکییەکان:\r\n• هەناری بایۆلۆجی یۆنانی: یارمەتی بەهێزکردنی تاڵەکانی قژ دەدات و بریقەیەکی تەندروستی پێ دەبەخشێت.\r\n• هەنگوین: وەک شێدارکەرەوەیەکی سروشتی کاردەکات و قژەکە نەرم دەکات.\r\n• ترشی هیالۆرۆنیک (Hyaluronic Acid): ناسراوە بەوەی ئاو لەناو تاڵەکانی قژدا دەهێڵێتەوە و ناهێڵێت قژەکە وشک ببێتەوە.\r\nتایبەتمەندییە گرنگەکان:\r\n1. سروشتی بوون: %95ی پێکهاتەکانی لە سەرچاوەی سروشتی وەرگیراون.\r\n2. بۆ کێ گونجاوە؟ بۆ هەموو ئەندامانی خێزان گونجاوە و بۆ ئەو کەسانە زۆر باشە کە کێشەی وشکیی قژیان هەیە.\r\nچۆنیەتی بەکارهێنان:\r\nبڕێکی گونجاو بدە لە قژی تەڕ، بە باشی مەساجی پێ بکە تا کەف دەکات، پاشان بە ئاوی شلەتێن بیبەرەوە\r\n','Hydrating shampoo for softness and moisture. High natural-origin formula suitable for the whole family, especially for dry hair. With Greek organic pomegranate to support healthier-looking hair, honey as a natural moisturizing agent, and Hyaluronic Acid to help retain moisture in hair strands. Apply to wet hair, massage well, then rinse.','شامبو مرطّب لنعومة وترطيب الشعر. تركيبة بنسبة عالية من مكونات ذات مصدر طبيعي ومناسبة للعائلة، وخصوصاً للشعر الجاف. يحتوي على رمان يوناني عضوي لدعم مظهر صحي للشعر، وعسل كمرطّب طبيعي، وحمض الهيالورونيك للمساعدة على حبس الرطوبة داخل خصلات الشعر. يُستخدم على شعر مبلل مع تدليك جيد ثم يُشطف.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 13:47:43',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(51,'پاکەرەوەی پێستی جەستەی گوڵی پرتەقال و لاڤێندەر لە بڕاندی پاپوتسانیسی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆنەکەی: تێکەڵەیەکە لە بۆنی گوڵی پرتەقاڵ (Orange Blossom) و لاڤیندەر (Lavender). ئەم تێکەڵەیە هەستێکی ئارامی و تازەیی (Freshness) بە جەستە دەبەخشێت.\r\n• پێکهاتەی ڕووەکی (Vegan): ئەم بەرهەمە ۱۰۰٪ ڤیگانە، واتە هیچ کەرەستەیەکی ئاژەڵی تێدا بەکارنەهاتووە.\r\n• پارێزەری پێست: دەوڵەمەند کراوە بە ڤیتامین E (کە دژە ئۆکسانە) و پریبیۆتیک (Prebiotics) کە یارمەتی پاراستنی هاوسەنگی سروشتی پێست دەدات. هەروەها ئاڵۆڤێرا (Aloe Vera) تێدایە بۆ نەرمکردنەوەی پێست.\r\n• تەندروستی پێست: کۆمپانیاکە ئاماژەی بەوە کردووە کە بەرهەمەکە بەبێ پارابین (Parabens) و بەبێ ڕەنگە دەستکردەکان دروست کراوە و لە لایەن پزیشکانی پێستەوە تاقیکراوەتەوە.\r\nکاریگەری: جگە لە پاککردنەوە، یارمەتی شێدارکردنەوەی پێست دەدات و بۆنێکی خۆش لەسەر جەستە جێدەهێڵێت','Vegan body wash with Orange Blossom & Lavender scent. Creates rich foam for effective cleansing and leaves skin soft and nicely fragranced. Enriched with prebiotics, Vitamin E, and Aloe Vera. Free from parabens and added colorants. Dermatologically tested.','غسول جسم نباتي (فيغان) برائحة زهر البرتقال واللافندر. يعطي رغوة غنية لتنظيف فعّال ويترك البشرة ناعمة وبرائحة جميلة. مُعزّز بالبريبيوتك وفيتامين E وألوفيرا. خالٍ من البارابين والألوان المضافة. مختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 14:25:11',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(52,'شامپۆی چاکەرەوەی قژی زیانلێکەوتووی کاراڤاکی لە بڕاندی پاپوتسانیسی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'\r\n١. پێکهاتە سەرەکییەکان\r\n• ڕۆنی ماکادامیا (Macadamia Oil): یارمەتیدەرە بۆ شێدارکردنەوەی قژ و نەرمکردنی تاڵەکان.\r\n• کەرەتینی ڕووەکی (Natural Keratin): کاردەکات بۆ بەهێزکردنی بنیات و پێکهاتەی قژ و پڕکردنەوەی ئەو شوێنانەی کە زیانیان بەرکەوتووە.\r\n• شیلەی شاهانەی یۆنانی (Greek Royal Jelly): یارمەتی خۆراکپێدانی قژ و زیادکردنی گەشە و بریقەدارییەکەی دەدات.\r\n٢. تایبەتمەندییە گرنگەکان\r\n• ٩٥٪ پێکهاتەی سروشتی: بەشێکی زۆری پێکهاتەکانی لە سەرچاوەی سروشتی وەرگیراون.\r\n• بۆ قژی وشک و زیانلێکەوتوو: بە تایبەتی بۆ ئەو کەسانە گونجاوە کە قژیان بەهۆی بۆیە، ئامێرە گەرمکەرەوەکان، یان وشکییەوە بێهێز بووە.\r\n• تاقیکردنەوەی پێست: لە لایەن پزیشکانی پێستەوە تاقیکراوەتەوە (Dermatologically Tested).\r\n٣. چۆنیەتی بەکارهێنان\r\nبڕێکی گونجاو لە شامپۆکە بدە لە قژی تەڕ، بە باشی مەساجی پێست و تاڵەکانی قژت بکە تا کەف دەکات، پاشان بە ئاوێکی شلەتێن بە باشی بیبەرەوە.\r\nتێبینی: ئەگەر قژت زۆر وشکە، باشتر وایە دوای ئەم شامپۆیە \"موکەیف\" (Conditioner) یان ماسکی قژ بەکاربهێنیت بۆ ئەوەی باشترین ئەنجامت دەستبکەوێت','Repair shampoo for damaged hair. High natural-origin formula for dry, weakened hair from dyeing, heat tools, or dryness. With Macadamia oil for softness and moisture, natural keratin to support hair structure and fill damaged areas, and Greek royal jelly to nourish and boost shine. Dermatologically tested. Use on wet hair, massage to lather, then rinse. For very dry hair, follow with conditioner or mask.','شامبو لإصلاح الشعر المتضرر. تركيبة بنسبة عالية من مكونات ذات مصدر طبيعي للشعر الجاف والضعيف بسبب الصبغة أو أدوات الحرارة أو الجفاف. يحتوي على زيت الماكاديميا للنعومة والترطيب، كيراتين طبيعي لدعم بنية الشعر والمساعدة على ملء مناطق التلف، وغذاء ملكات النحل اليوناني لتغذية الشعر وزيادة اللمعان. مختبر جلدياً. يُستخدم على شعر مبلل مع تدليك حتى تتكون رغوة ثم يُشطف. للشعر شديد الجفاف يُفضّل اتباعه ببلسم أو ماسك.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 15:38:48',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(53,'پاکەرەوەی پێستی جەستەی بۆن میسک لە بڕاندی پاپوتسانیسی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'\r\nتایبەتمەندییە سەرەکییەکان\r\n• پێکهاتەی ڤیگن (100% Vegan): ئەم بەرهەمە هیچ ماددەیەکی سەرچاوە ئاژەڵی تێدا نییە.\r\n• بۆنی میسک (Musk): خاوەنی بۆنێکی میسکی سەرنجڕاکێش و درێژخایەنە.\r\n• پێکهاتەی سوودبەخش: تێکەڵەیەک لە پریبایۆتیکەکان (Prebiotics) بۆ خۆراکپێدانی پێست، لەگەڵ ڤیتامین E و ئەلووێرا کە وەک دژە ئۆکسان و نەرمکەرەوە کار دەکەن.\r\n• کەف و پاککردنەوە: کەفێکی زۆر و دەوڵەمەند دروست دەکات بۆ پاککردنەوەیەکی باشی جەستە.\r\n• پشکنینی پزیشکی: لە ڕووی پزیشکییەوە بۆ پێست تاقیکراوەتەوە (Dermatologically Tested).\r\n• کۆمپانیا: Papoutsanis، کە کۆنترین کۆمپانیای سابوونە لە یۆنان و مێژووەکەی دەگەڕێتەوە بۆ ساڵی 1870.\r\n','Vegan body wash with Musk scent (Papoutsanis). Long-lasting, attractive fragrance with prebiotics to support skin comfort, plus Vitamin E and Aloe Vera for softness and antioxidant care. Creates a rich foam for a clean feel. Dermatologically tested. Papoutsanis is one of the oldest soap companies in Greece (established in 1870).','غسول جسم نباتي (فيغان) برائحة المسك (Papoutsanis). رائحة جذابة وثابتة مع بريبيوتك لدعم راحة البشرة، بالإضافة إلى فيتامين E وألوفيرا للنعومة والعناية المضادة للأكسدة. يمنح رغوة غنية وإحساساً بالنظافة. مختبر جلدياً. Papoutsanis من أقدم شركات الصابون في اليونان (تأسست عام 1870).',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:14:35',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(54,'پاکەرەوەی پێستی جەستەی هەستی لۆکە لە بڕاندی پاپوتسانیسی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سەرەکی: دەوڵەمەندە بە Prebiotics (بۆ پاراستنی هاوسەنگی سروشتی پێست)، ڤیتامین E (وەک دژە ئۆکسان) و ئەلووێرا (بۆ نەرمکردنەوە و شێدارکردنەوەی پێست).\r\n• بۆن: خاوەن بۆنێکی سووک و ئارامکەرەوەیە کە ناونراوە بە \"Cotton Feel\" (هەستی لۆکە)، کە هەستی پاکوخاوێنی و نەرمیت پێ دەبەخشێت.\r\n• بێ بێبەش لە ماددە زیانبەخشەکان: ئەم بەرهەمە 0% پارابین (Parabens) و ماددەی پارێزەری تێدایە، کە ئەمەش بۆ پێستی هەستیار گونجاوترە.\r\n• پشکنینی پزیشکی: لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە (Dermatologically Tested).\r\nپێکهاتە گرنگەکان (بەپێی لیستی پشتەوە):\r\n1. Aqua (ئاو): بنچینەی بەرهەمەکە.\r\n2. Glycerin: بۆ پاراستنی شێداری پێست.\r\n3. Aloe Barbadensis Leaf Juice: گیراوەی گەڵای ئەلووێرا بۆ هێورکردنەوەی پێست.\r\n4. Inulin: جۆرێکە لە پریبایۆتیک کە یارمەتی تەندروستی پێست دەدات.\r\n• شێوازی بەکارهێنان: بڕێکی گونجاو دەخرێتە سەر ئیسفەنجی خۆشوشتن یان ڕاستەوخۆ لە جەستە دەدرێت و دواتر بە ئاو دەشۆرێت.\r\nئەم بەرهەمە زیاتر بۆ ئەو کەسانە گونجاوە کە حەزیان بە بۆنی ئارام و پێکهاتەیەک هەیە کە پێستیان وشک نەکاتەوە.\r\n','Gentle body cleanser designed for sensitive skin. Enriched with prebiotics to help support the skin’s natural balance, Vitamin E (antioxidant), and Aloe Vera to soothe and soften. Features a light, calming “Cotton Feel” fragrance for a clean, fresh sensation. Free from parabens (0%) and tested under dermatological control. How to use: apply to a sponge or directly on the body, lather, then rinse with water.','غسول جسم لطيف مُصمّم للبشرة الحساسة. مُعزّز بالبريبيوتيك لدعم توازن البشرة الطبيعي، وفيتامين E كمضاد للأكسدة، وألوفيرا لتهدئة البشرة وتنعيمها. برائحة خفيفة ومريحة باسم “Cotton Feel” تمنح إحساساً بالنظافة والانتعاش. خالٍ من البارابين (0%) ومختبر جلدياً. طريقة الاستخدام: يوضع على إسفنجة أو مباشرة على الجسم، يُرغى ثم يُشطف بالماء.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:29:35',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(55,'لۆشنی دژە هەڵوەرینی قژ و بەهێزکردنی قژ لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25000,2500,1,'کارەکانی ئەم بەرهەمە:\r\n• کەمکردنەوەی هەڵوەرین: یارمەتی ڕاگرتن و کەمکردنەوەی هەڵوەرینی قژ دەدات.\r\n• هاندانی گەشە: یارمەتی گەشەکردنی مووی نوێ دەدات و خانەکانی قژ چالاک دەکاتەوە.\r\n• پاراستنی دژە DHT: ماددەی وای تێدایە کە ڕێگری دەکات لەو هۆرمۆنەی (DHT) کە هۆکاری سەرەکی کچڵبوون و هەڵوەرینی قژە لە پیاوان و هەندێک لە خانماندا.\r\n• بەهێزکردنی تاڵەکانی قژ: بەهۆی هەبوونی ڤیتامین و ماددە خۆراکییەکان، تاڵەکان ئەستوورتر و بەهێزتر دەکات.\r\nپێکهاتە سەرەکییەکانی:\r\n1. Biotinyl Tripeptide: بۆ بەهێزکردنی ڕەگی موو و جێگیرکردنی لەناو پێستی سەردا.\r\n2. Apigenin: کە لە ڕووەکەوە وەردەگیرێت و سووڕی خوێن لە پێستی سەردا باشتر دەکات بۆ ئەوەی خۆراک بگاتە مووەکان.\r\n3. Oleanolic Acid: بۆ ڕێگریکردن لە هۆرمۆنی DHT.\r\n4. Diguanosine-GP4G: سەرچاوەیەکی وزەیە بۆ خانەکانی قژ بۆ ئەوەی زووتر گەشە بکەن.\r\nچۆن بەکاردێت؟ (بەپێی ڕێنمایی سەر کارتۆنەکە):\r\n• لۆشنەکە دەدرێت لەو شوێنانەی قژی لێ هەڵدەوەرێت یان کەم بووەتەوە.\r\n• پێویستە بۆ ماوەی ٥ خولەک بە پەنجەکانت مەساجی پێستی سەرت بکەیت تاوەکو بەباشی هەڵیمژێت.\r\n• ئاگاداری: پێویستە تەنها بۆ دەرەوەی جەستە بەکاربێت و نەکەوێتە چاو.\r\nتێبینی گرنگ:\r\nئەم لۆشنە پێکهاتەی کحولی (Alcohol Denat) تێدایە، بۆیە ئەگەر پێستی سەرت زۆر وشکە یان حەساسیەتت بە کحول هەیە، باشترە ئاگادار بیت.\r\n','Anti-hair loss lotion that helps reduce shedding, support new hair growth, and strengthen hair roots. Contains a complex designed to help protect against DHT (a key factor in androgen-related hair loss). Key actives: Biotinyl Tripeptide supports follicle anchoring, Apigenin supports scalp circulation, Oleanolic Acid helps inhibit DHT activity, and GP4G helps energize follicles. How to use: apply to thinning areas and massage the scalp for about 5 minutes until absorbed. For external use only; avoid contact with eyes. Note: contains Alcohol Denat—if your scalp is very dry or sensitive to alcohol, use with care.','لوسيون مضاد لتساقط الشعر يساعد على تقليل التساقط، دعم نمو شعر جديد، وتقوية جذور الشعر. يحتوي على مركّب يساعد على الحماية من تأثير هرمون DHT (أحد العوامل الأساسية لتساقط الشعر الهرموني). المكوّنات الفعّالة: Biotinyl Tripeptide لدعم تثبيت البصيلات، وApigenin لتحسين الدورة الدموية في فروة الرأس، وOleanolic Acid للمساعدة في تقليل نشاط DHT، وGP4G لتنشيط بصيلات الشعر. طريقة الاستخدام: يُوضع على مناطق التخفف/التساقط مع تدليك فروة الرأس حوالي 5 دقائق حتى الامتصاص. للاستعمال الخارجي فقط وتجنب ملامسة العينين. ملاحظة: يحتوي على كحول (Alcohol Denat) لذا يُستخدم بحذر إذا كانت فروة الرأس جافة جداً أو حساسة للكحول.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:34:34',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(56,'شامپۆی دژە هەڵوەرینی قژ لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,26000,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• دژی هەڵوەرین: یارمەتی کەمکردنەوەی هەڵوەرینی قژ دەدات و گەشەی تاڵەکان چالاک دەکاتەوە.\r\n• پاراستنی تاڵەکان: قژ لە کاریگەرییە خراپەکانی هۆرمۆنی (DHT) دەپارێزێت، کە هۆکاری سەرەکییە بۆ کچبوونی قژ و هەڵوەرینی بۆماوەیی.\r\n• زیادکردنی قەبارە: یارمەتی ئەستوورکردنی تاڵەکانی قژ دەدات و قەبارەیەکی زیاتری پێ دەبەخشێت.\r\n• پاککردنەوەی چەوری: یارمەتی ڕێکخستنی چەوری سەر دەدات بەبێ ئەوەی زیان بە پێستی سەر بگەیەنێت.\r\n• بێ ماددەی زیانبەخش: لەسەر پاکەتەکە ئاماژەی پێکراوە کە SLES Free (بێ سۆدیۆم لۆرێت سەلفات) و Paraben Free (بێ پارابین)ە.\r\nپێکهاتە گرنگەکان:\r\n1. Biotinyl Tripeptide: یارمەتی بەهێزکردنی ڕەگی قژ و هاندانی دروستبوونی تاڵی نوێ دەدات.\r\n2. Flavonoid Apigenin: سوڕی خوێن لە پێستی سەردا چالاک دەکات بۆ ئەوەی خۆراکێکی باشتر بگات بە تاڵەکان.\r\n3. بایۆتین و ڤیتامینەکان: پێویستن بۆ تەندروستی و درەوشانەوەی قژ.\r\nچۆنێتی بەکارهێنان:\r\n1. بڕێکی گونجاو بدە لە قژی تەڕ.\r\n2. بە هێواشی پێستی سەری پێ مەساژ بکە.\r\n3. بۆ ماوەی چەند خولەکێک بە قژتەوە بیهێڵەرەوە (بۆ ئەوەی پێکهاتەکان کار بکەن).\r\n4. پاشان بە باشی بە ئاو بیشۆ.\r\n5. دەتوانرێت ڕۆژانە یان دوو ڕۆژ جارێک بەکاربهێنرێت.\r\n','Anti-hair loss shampoo that helps reduce shedding and stimulate hair follicles while protecting hair from the negative effects of DHT. Supports thicker-looking hair and helps balance scalp oil without harshness. Labeled SLES-free and paraben-free. Key ingredients: Biotinyl Tripeptide to strengthen roots, Apigenin to support scalp circulation, plus biotin and vitamins for hair health. How to use: apply to wet hair, massage gently, leave for a few minutes, then rinse well. Can be used daily or every other day.','شامبو مضاد لتساقط الشعر يساعد على تقليل التساقط وتنشيط بصيلات الشعر مع حماية الشعر من التأثيرات السلبية لهرمون DHT. يدعم زيادة سماكة الشعر ويساعد على تنظيم دهون فروة الرأس دون تهييج. مذكور أنه خالٍ من SLES وخالٍ من البارابين. مكوّنات مهمة: Biotinyl Tripeptide لتقوية الجذور، وApigenin لتحسين الدورة الدموية في فروة الرأس، إضافةً إلى البيوتين والفيتامينات لدعم صحة الشعر. طريقة الاستخدام: يوضع على شعر مبلل مع تدليك لطيف، يُترك بضع دقائق ثم يُشطف جيداً. يمكن استخدامه يومياً أو يوماً بعد يوم.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:42:27',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(57,'شامپۆی پانتۆگرین تایبەت بە چارەسەرکردنی کێشەکانی هەڵوەرینی قژ لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,21000,29000,4000,1,'. سوودە سەرەکییەکانی:\r\n• بۆ قژی تەنک و بێهێز: ئەم شامپۆیە یارمەتی ئەو کەسانە دەدات کە قژیان تەنک بووەتەوە یان زوو دەشکێتەوە.\r\n• بەهێزکەری ڕەگی قژ: بەهۆی هەبوونی ڤیتامینەکان، یارمەتی گەشەی قژ و بەهێزکردنی تاڵەکان دەدات.\r\n• پاراستنی پێستی سەر: خاوەن پلەی ترشێتی (pH 5.5-7)یە، کە هاوسەنگی سروشتی پێستی سەر تێک نادات و ناهێڵێت پێستی سەر وشک بێتەوە یان تووشی هەستیاری ببێت.\r\n٢. پێکهاتە گرنگەکانی:\r\n• ڤیتامینەکانی PP و B5: بۆ هاندانی گەشە و بریقەدارکردنی قژ.\r\n• ترشە ئەمینییەکان (Amino Acids): کە بناغەی دروستبوونی پرۆتینی قژن.\r\n• خوێیە کانزاییەکان (Mineral Salts): بۆ تەندروستی و پتەوی تاڵەکان.\r\n• Extract ی سۆیا: بۆ نەرمکردن و خۆراکپێدانی قژ.\r\n٣. شێوازی بەکارهێنان:\r\nوەک شامپۆیەکی ئاسایی بەکاردێت، بەڵام باشترە لە کاتی شتنی قژدا بۆ ماوەی چەند خولەکێک بە پێستی سەرەوە بمێنێتەوە و بە هێواشی مەساجی پێ بکرێت، پاشان بە ئاو بشۆردرێت.\r\n• بە گشتی ئەم شامپۆیە بۆ ئەو کەسانە گونجاوە کە کێشەی وەرینی قژ یان سستی گەشەی قژیان هەیە.','Shampoo for thin and weak hair that supports hair growth and strengthens strands. Formulated with a balanced pH (about 5.5–7) to help respect the scalp’s natural balance and reduce dryness or sensitivity. Key components include vitamins PP and B5, amino acids (building blocks of hair proteins), mineral salts to support follicle strength, and soy extract for nourishment and softness. How to use: like a regular shampoo; for best results leave on the scalp for a few minutes with gentle massage, then rinse.','شامبو للشعر الخفيف والضعيف يساعد على دعم نمو الشعر وتقوية الخصلات. يتميز بدرجة حموضة متوازنة تقريباً (pH 5.5–7) للمحافظة على توازن فروة الرأس وتقليل الجفاف أو الحساسية. يحتوي على فيتامينات PP وB5، وأحماض أمينية (لبناء بروتينات الشعر)، وأملاح معدنية لدعم قوة البصيلات، ومستخلص الصويا للتغذية والنعومة. طريقة الاستخدام: يُستخدم مثل الشامبو العادي، ويفضّل تركه بضع دقائق مع تدليك لطيف لفروة الرأس ثم يُشطف.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:45:12',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(58,'لۆشنی پانتۆگرین تایبەت بە چارەسەرکردنی کێشەکانی هەڵوەرینی قژ لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,21000,28000,3500,1,'. پێکهاتە سەرەکییەکان:\r\nئەم لۆشنە چەند ماددەیەکی گرنگی تێدایە کە کار دەکەن بۆ بەهێزکردنی ڕەگی قژ:\r\n• Silanediol Salicylate: پێکهاتەیەکی سەرەکییە کە تێکەڵەیەکە لە \"سیلیکۆنی ئۆرگانیک\" و \"سالی سیلیک ئەسید\". یارمەتیدەرە بۆ چالاککردنی میتابۆلیزمی مووەکان و کەمکردنەوەی هەوکردنی پێستی سەر.\r\n• Ginger Extract (ئارەقی زەنجەفیل): دەبێتە هۆی فراوانکردنی دەمارە خوێنەکان و زیادکردنی هاتووچۆی خوێن بۆ پیازەی مووەکە، ئەمەش یارمەتی گەیشتنی خۆراک دەدات بە قژەکە.\r\n• Vitamin B Complex (B1, B2, B6, B12): ڤیتامینەکانی گرووپی B زۆر پێویستن بۆ گەشە و تەندروستی قژ.\r\n• Vitamin F (Linoleic acid): یارمەتی پاراستنی تەندروستی پێستی سەر دەدات.\r\n• Sulfur (کبریت): پێکهاتەیەکی گرنگە بۆ دروستبوونی پرۆتینی قژ.\r\n٢. سوودەکانی ئەم لۆشنە:\r\n• یارمەتی ڕاگرتنی وەرینی قژ دەدات.\r\n• ڕەگی قژ بەهێز دەکات و هانی گەشەکردنی مووی نوێ دەدات.\r\n• دژە هەوکردنە و پێستی سەر لە ماددە زیانبەخشەکان (Free radicals) دەپارێزێت.\r\n• ڕێنمایی بەکارهێنان:  (بەزۆری شەوانە بۆ سەر پێستی سەری وشک دەکرێت و مەساجی پێ دەکرێت).\r\n','Pantogrin hair lotion formulated to strengthen hair roots and help reduce hair loss. Key ingredients include Silanediol Salicylate (a combination of organic silicon and salicylic derivative) to support follicle metabolism and reduce scalp irritation, Ginger extract to boost microcirculation and nutrient delivery, Vitamin B complex (B1, B2, B6, B12) to support healthy hair growth, Vitamin F (linoleic acid) for scalp health, and Sulfur to support hair protein formation. How to use: typically applied to the scalp (often at night) on dry scalp and massaged in.','لوسيون بانتوغرِن لتقوية جذور الشعر والمساعدة في تقليل تساقطه. يحتوي على Silanediol Salicylate (مزيج من السيليكون العضوي ومشتق الساليسيليك) لدعم أيض بصيلات الشعر وتقليل تهيّج فروة الرأس، ومستخلص الزنجبيل لتحسين الدورة الدموية ووصول المغذيات للبصيلات، ومركب فيتامينات B (B1 وB2 وB6 وB12) لدعم نمو الشعر، وفيتامين F (حمض اللينوليك) لصحة الفروة، والكبريت لدعم تكوين بروتينات الشعر. طريقة الاستخدام: يُوضع على فروة الرأس (غالباً ليلاً) على فروة جافة مع تدليك لطيف حتى الامتصاص.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:47:34',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(59,'شێدارکەرەوەی شیری هایالۆرۆنیک تایبەت بە پێست لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,29000,4500,1,'پێکهاتە سەرەکییەکانی:\r\n•  ترشی گڵایکۆلیک (Glycolic Acid 10%): ئەمە جۆرێکی بەهێزی AHA (ئەلفا هایدرۆکسی ئەسید)ە کە خانە مردووەکانی پێست لادەبات، ڕەنگی پێست یەکدەخات و پێستەکە ساف و گەشاوە دەکات.\r\n• Hyaluronic Acid (ترشی هیالۆرۆنیک): بۆ شێدارکردنەوەی قووڵی پێست و پاراستنی لە وشکبوونەوە.\r\n• Niacinamide (ڤیتامین B3): یارمەتی کەمکردنەوەی سووربوونەوە و چاککردنەوەی بەربەستی پارێزەری پێست دەدات.\r\n• Vitamin E و Bisabolol: وەک دژە ئۆکسان و هێورکەرەوەی پێست کاردەکەن.\r\nبۆچی بەکاردێت؟\r\n1. لابردنی خانە مردووەکان: یارمەتی نوێکردنەوەی پێست دەدات (Resurfacing).\r\n2. چارەسەری وشکی: زۆر گونجاوە بۆ ئەو شوێنانەی جەستە کە زۆر وشکن یان توێکڵ دەدەن.\r\n3. دژە پیری: یارمەتی کەمکردنەوەی نیشانەکانی پیربوونی پێست و زیانەکانی خۆر دەدات.\r\n4. بۆ چەندین شوێن گونجاوە: دەتوانیت بۆ (دەموچاو، مل، سنگ، پشت، قۆڵ و دەستەکان) بەکاری بهێنیت.\r\nتێبینی و ڕێنمایی گرنگ:\r\n• پاراستن لە خۆر: بەهۆی هەبوونی AHA (ترشی گڵایکۆلیک)، پێستت هەستیار دەبێت بۆ تیشکی خۆر. زۆر گرنگە لە کاتی بەکارهێنانی ئەم بەرهەمەدا لە ڕۆژدا دژەخۆر بەکاربهێنیت.\r\n• بەکارهێنان: باشترە لە سەرەتادا بە بڕێکی کەم و تەنها شەوان بەکاری بهێنیت تا پێستت ڕادێت، چونکە ڕەنگە لە سەرەتادا کەمێک هەست بە کزانەوە بکەیت.\r\n• دوورکەوتنەوە: لە چاو و لێو و ئەو شوێنانەی برینیان پێوەیە دووری بخەرەوە.\r\n','Hydrating body/face serum with 10% Glycolic Acid (AHA) for effective exfoliation and skin resurfacing. Helps remove dead skin cells, even tone, and improve skin clarity. Includes Hyaluronic Acid for deep hydration, Niacinamide (B3) to calm redness and support the skin barrier, plus Vitamin E and Bisabolol for soothing antioxidant care. Suitable for multiple areas such as face, neck, chest, back, arms, and hands. Important: AHA increases sun sensitivity—use sunscreen during the day. Start slowly (preferably at night) and avoid eyes, lips, and broken skin.','سيروم/لوشن مرطّب وتقشيري يحتوي على حمض الجليكوليك 10% (AHA) لتقشير فعّال وتجديد سطح البشرة. يساعد على إزالة الخلايا الميتة، توحيد اللون، وتحسين صفاء البشرة. يحتوي على حمض الهيالورونيك للترطيب العميق، ونياسيناميد (B3) لتهدئة الاحمرار ودعم حاجز البشرة، إضافة إلى فيتامين E وبيسابولول للعناية المهدئة والمضادة للأكسدة. مناسب لعدة مناطق مثل الوجه والرقبة والصدر والظهر والذراعين واليدين. مهم: أحماض AHA تزيد حساسية الشمس—استخدم واقي شمس نهاراً. ابدأ تدريجياً (يفضّل ليلاً) وتجنب محيط العينين والشفاه والجلد المتشقق أو المجروح.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:50:29',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(60,'کرێمی ئۆمێگا پڵەس لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,19000,25000,3000,1,'. ئەم کرێمە بۆ کێ گونجاوە؟\r\n• ئەوانەی پێستیان زۆر وشکە (Extreme Dryness).\r\n• ئەوانەی کێشەی ئەتۆپیک (Atopic Skin) یان ئەکزیمایان هەیە.\r\n• بۆ ئەو پێستانەی تووشی سووربوونەوە و خوران دەبن.\r\n• گونجاوە بۆ دەموچاو و جەستەش.\r\n٢. پێکهاتە سەرەکییەکانی:\r\n• ئۆمێگا ٣ و ٦ (ω-3 & ω-6): یارمەتی نوێکردنەوەی خانەکانی پێست دەدەن و وەک دژە هەوکردن کار دەکەن.\r\n• ڤیتامین B3 (Niacinamide): بەرگری پێست بەهێز دەکات و یارمەتی دروستکردنی چەورییە سوودبەخشەکانی پێست دەدات.\r\n• تەواکەری ئۆت (Oat extract) و پانتینۆڵ: پێستەکە هێمن دەکەنەوە و خورانی ناهێڵن.\r\n• ڕۆنی ڕووەکی: شێدارییەکی زۆر بە پێست دەبەخشن و ڕێگری دەکەن لە وشکبوونەوە.\r\n٣. تایبەتمەندییەکانی:\r\n• بە خێرایی هەڵدەمژرێت و پێستەکە چەور ناکات.\r\n• هەستی پاراستن و فێنکی بە پێست دەبەخشێت.\r\n• بەربەستی سروشتی پێست (Skin Barrier) چاک دەکاتەوە بۆ ئەوەی ڕێگری بکات لە کاریگەرییە دەرەکییە زیانبەخشەکان.\r\n٤. تێبینی گرنگ:\r\n• بەکارهێنان: تەنها بۆ دەرەوەی جەستەیە (External Use\r\n','Omega Plus cream for very dry and irritated skin. Suitable for extreme dryness, atopic skin, eczema-prone skin, and redness/itchiness. Can be used on face and body. Key ingredients: Omega-3 & Omega-6 to support skin renewal and reduce irritation, Niacinamide (B3) to strengthen the skin barrier and support healthy lipids, Oat extract and Panthenol to soothe, plus plant oils for deep moisture and protection from dryness. Absorbs quickly without a greasy feel and helps restore the skin barrier. For external use only.','كريم أوميغا بلس للبشرة شديدة الجفاف والمتهيّجة. مناسب للجفاف الشديد، البشرة الأتوبية، البشرة المعرضة للأكزيما، والاحمرار والحكة. يمكن استخدامه للوجه والجسم. المكوّنات الأساسية: أوميغا 3 وأوميغا 6 لدعم تجدد البشرة وتقليل التهيّج، نياسيناميد (B3) لتقوية حاجز البشرة ودعم الدهون المفيدة، مستخلص الشوفان وبانثينول للتهدئة، وزيوت نباتية لترطيب عميق والحماية من الجفاف. يمتص بسرعة دون ملمس دهني ويساعد على إصلاح حاجز البشرة. للاستعمال الخارجي فقط.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:54:07',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(61,'کرێمی یوریا ١٠٪ تایبەت بە وشکبوونی پێست لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,19000,25000,3000,1,'پێکهاتەی سەرەکی\r\n• یوریا (Urea) بە ڕێژەی 10%: ئەمە پێکهاتەی سەرەکییە کە شێدارکەرەوەیەکی زۆر بەهێزە. یارمەتی هەڵمژینی ئاو دەدات بۆ ناو پێست و خانە مردووەکانی سەر پێست لادەبات (تەقشیرێکی سوک).\r\n• Lactic Acid و Salicylic Acid: یارمەتی سافکردنی پێست و نەهێشتنی زبرییەکەی دەدەن.\r\nبۆ کێ بەکاردێت؟\r\nئەم کرێمە بۆ ئەم حاڵەتانەی خوارەوە دروستکراوە:\r\n1. پێستی زۆر وشک و ڕەق (Hyperkeratosis).\r\n2. پێستی فلس‌هەڵداو (Dry-scaly skin).\r\n3. بۆ ئەو کەسانەی پێستیان سوور دەبێتەوە یان دەخورێت بەهۆی وشکییەوە.\r\n4. وەک تەواکەرێک بۆ چارەسەری نەخۆشییەکانی (سەدەفییە، ئەکزیما، و ئەتۆپیک دێرماتایتس).\r\nسوودەکانی\r\n• شێدارکردنێکی قووڵ: بەپێی زانیاری سەر کارتۆنەکە، ڕێژەی شێداری پێست تا +60.5% زیاد دەکات تەنها دوای ٢ کاتژمێر لە بەکارهێنانی.\r\n• نەرمکردنەوە: پێستەکە زۆر نەرم و ساف دەکات.\r\n• بێ بۆن و ڕەنگ: گونجاوە بۆ پێستە هەستیارەکان چونکە ماددەی بۆنخۆشکەری تێدا نییە.\r\nچۆن بەکاردێت؟\r\n• بڕێکی گونجاو بدە لەو شوێنەی کە پێویستی پێیەتی (دەبێت پێستەکە پاک و وشک بێت).\r\n• دەتوانیت ڕۆژانە چەند جارێک بەکاری بهێنیت بەپێی پێویستی پێستت.\r\nتێبینییەکی گرنگ:\r\n• نابێت بۆ منداڵی خوار تەمەن ٣ ساڵ بەکاربهێنرێت.\r\n• تەنها بۆ بەکارهێنانی دەرەکییە (نەدرێت لە دەم و چاو یان ناوچە هەستیارەکان مەگەر پزیشک بۆتی دیاری بکات).\r\n','Urea 10% cream for very dry, rough, and scaly skin. Provides strong hydration by attracting water into the skin and offers mild exfoliation to help remove dead cells. Contains 10% Urea plus Lactic Acid and Salicylic Acid to smooth and soften rough texture. Intended for hyperkeratosis, dry-scaly skin, redness/itching from dryness, and as supportive care for conditions such as psoriasis, eczema, and atopic dermatitis. Fragrance- and color-free, suitable for sensitive skin. How to use: apply to clean, dry areas as needed (can be used multiple times daily). Important: not for children under 3 years; external use only and avoid eyes/mouth and very sensitive areas unless advised by a doctor.','كريم يوريا 10% للجفاف الشديد والجلد الخشن والمتقشر. يمنح ترطيباً قوياً عبر جذب الماء إلى داخل الجلد مع تقشير لطيف للمساعدة على إزالة الخلايا الميتة. يحتوي على يوريا 10% مع حمض اللاكتيك وحمض الساليسيليك لتنعيم الملمس الخشن. مخصص لحالات فرط التقرّن، الجلد الجاف المتقشر، الاحمرار/الحكة بسبب الجفاف، وكعناية داعمة لبعض الحالات مثل الصدفية والأكزيما والتهاب الجلد الأتوبي. خالٍ من العطر واللون ومناسب للبشرة الحساسة. طريقة الاستخدام: يوضع على مناطق نظيفة وجافة حسب الحاجة (يمكن استخدامه عدة مرات يومياً). مهم: لا يُستخدم للأطفال دون 3 سنوات؛ للاستعمال الخارجي فقط وتجنب العينين/الفم والمناطق شديدة الحساسية إلا بتوجيه طبي.',NULL,NULL,NULL,NULL,NULL,'2026-01-04 16:56:58',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(62,'کرێمی یوریا ٤٠٪ تایبەت بە چارەسەرکردنی کێشەی قورسی وشکبوونی پێست لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,19000,26000,3500,1,'. پێکهاتە سەرەکییەکانی:\r\n• یوریا (Urea) بە خەستی 40%: ئەمە ڕێژەیەکی زۆر بەرزە. یوریا لەم خەستییەدا کاردەکات بۆ نەرمکردنەوە و لادانی چینە زۆر ئەستوور و ڕەقەکانی پێست.\r\n• سالیسیلیک ئەسید (Salicylic Acid): یارمەتی پاککردنەوەی پێست و لادانی خانە مردووەکان دەدات (وەک تەقشیرکردن).\r\n• لاکتیک ئەسید (Lactic Acid): بۆ شێدارکردنەوە و نەرمکردنی زیاتری پێست.\r\n٢. بەکاردێت بۆ چی؟\r\nئەم بەرهەمە بۆ وشکی ئاسایی نییە، بەڵکو بۆ ئەم حاڵەتانەیە:\r\n• پێستی زۆر ئەستوور و ڕەق: وەک پاژنەی پێ، ئەژنۆ، و ئانیشک کە زۆر زبر بوون.\r\n• کێشەی Keratosis: ئەو حاڵەتانەی پێست کە وەک \"پێستی مریشک\" وایە یان زبرییەکی زۆری هەیە.\r\n• بۆ نینۆک: ئەگەر نینۆک زۆر ئەستوور بووبێت یان کێشەی هەبێت.\r\n• بۆ پێستی سەر: ئەگەر کڕێشێکی زۆر ئەستوور و وەک قەتماغەی هەبێت.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• بۆ جەستە: ڕۆژی ١ بۆ ٢ جار لەو شوێنە بدە کە پێویستی پێیەتی (دەبێت پێستەکە پاک و وشک بێت).\r\n• بۆ پێستی سەر: دەدرێت لەو شوێنەی قەتماغەی هەیە، بۆ ماوەی یەک کاتژمێر جێدەهێڵرێت و پاشان بە شامپۆ دەشۆردرێت.\r\n٤. تێبینی و ئاگادارییە گرنگەکان:\r\n• تەمەن: نابێت بۆ منداڵی خوار تەمەن ٣ ساڵ بەکاربهێنرێت.\r\n• تەنها بۆ دەرەوەیە: نابێت بەر چاو و دەم و برینی کراوە بکەوێت.','Urea 40% intensive cream for very thick, hard, and extremely rough skin. High-strength urea helps soften and break down very thick layers of skin. With Salicylic Acid to help exfoliate and remove dead cells, and Lactic Acid for additional softening and hydration. Intended for tough areas such as heels, knees, and elbows, keratosis/“chicken skin”, thick nails, and very thick scalp buildup (used as a pre-shampoo treatment). How to use: for body, apply 1–2 times daily to clean, dry areas. For scalp buildup, apply to the thick area for about 1 hour then wash with shampoo. Important: not for children under 3 years; external use only; avoid eyes, mouth, and open wounds.','كريم يوريا 40% مكثّف للبشرة شديدة السماكة والخشونة. تركيز يوريا مرتفع يساعد على تليين وتفكيك الطبقات السميكة جداً من الجلد. يحتوي على حمض الساليسيليك للمساعدة في التقشير وإزالة الخلايا الميتة، وحمض اللاكتيك لمزيد من التنعيم والترطيب. مخصص للمناطق القاسية مثل كعب القدم والركب والأكواع، وحالات التقرّن/“جلد الدجاج”، والأظافر السميكة، وتراكمات فروة الرأس السميكة (يُستخدم قبل الشامبو). طريقة الاستخدام: للجسم يوضع 1–2 مرة يومياً على جلد نظيف وجاف. لفروة الرأس: يوضع على منطقة التراكم لمدة نحو ساعة ثم يُغسل بالشامبو. مهم: لا يُستخدم للأطفال دون 3 سنوات؛ للاستعمال الخارجي فقط؛ وتجنب العينين/الفم والجروح المفتوحة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 03:12:14',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(63,'لۆشنی پاکەرەوەی پێستی هەستیار و ناسک تایبەت بە دەم و چاو و لابەری مەیک ئەپ لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,18000,24000,3000,1,'• پاککەرەوەی دەموچاو و ماکیاژ: بە شێوەیەکی کاریگەر ماکیاژ، چەوری زیادە (Sebum) و پیسی سەر پێست لادەبات.\r\n• بۆ پێستی هەستیار: تایبەت دروست کراوە بۆ ئەوەی پێست تووشی سووربوونەوە و خوراو یان وشکبوونەوە نەکات.\r\n• پێویستی بە شتن نییە (No-rinse formula): دەتوانیت بە لۆکە (Cotton pad) بەکاری بهێنیت و پێویست ناکات دوای بەکارهێنانی دەموچاوت بە ئاو بشۆیت.\r\n• هێورکەرەوەیە: ماددەی (Calmosensine) تێدایە کە هەستی ناڕەحەتی و سووتانەوەی پێست کەمدەکاتەوە.\r\nپێکهاتە گرنگەکان\r\nلۆشنەکە چەند پێکهاتەیەکی باشی تێدایە بۆ شێدارکردنەوە و پاراستنی پێست:\r\n• Sodium Hyaluronate: یارمەتی شێدارکردنەوەی قووڵی پێست دەدات.\r\n• Calmosensine: وەک پیتایدێکی چالاک کاردەکات بۆ هێورکردنەوەی پێست لە بەرامبەر گۆڕانکارییەکانی پلەی گەرمی (سەرمای زۆر یان گەرمای زۆر).\r\n• بێ کحول: وەک لە لیستی پێکهاتەکاندا دیارە، ئەم جۆرە پاککەرەوەیە بە جۆرێک دروست کراوە کە پێست دانەخورێنێت.\r\nچۆنیەتی بەکارهێنان\r\nبڕێکی گونجاو لە لۆشنەکە بکە سەر لۆکەیەک، پاشان بە نەرمی دەموچاو و چاوتی پێ پاک بکەرەوە. پێویست بە ئاو لێدان ناکات مەگەر خۆت پێت خۆش بێت دواتر دەموچاوت بشۆیت.','Gentle cleansing lotion for face and eyes, suitable for sensitive skin and makeup removal. Effectively removes makeup, excess oil (sebum), and impurities without causing dryness or irritation. No-rinse formula: use with a cotton pad; rinsing is optional. Contains Sodium Hyaluronate for hydration and Calmosensine to help soothe discomfort and sensitivity (including sensitivity to temperature changes). Alcohol-free and designed to be skin-friendly. How to use: apply to a cotton pad and gently wipe face and eye area.','لوسيون تنظيف لطيف للوجه والعينين مناسب للبشرة الحساسة وإزالة المكياج. يزيل بفاعلية المكياج والدهون الزائدة (الزهم) والشوائب دون التسبب بجفاف أو تهيّج. تركيبة لا تتطلب الشطف (No-rinse): يُستخدم بقطنة ويمكن الشطف اختيارياً. يحتوي على Sodium Hyaluronate للترطيب وCalmosensine لتهدئة الانزعاج والحساسية (بما فيها الحساسية لتغيرات الحرارة). خالٍ من الكحول ومصمم ليكون لطيفاً على البشرة. طريقة الاستخدام: توضع كمية على قطنة ثم يُمسح الوجه ومنطقة العين برفق.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 03:15:07',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(64,'جێلی پاکەرەوەی پێستی هەستیار و ناسک بۆ دەم و چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,18000,25000,3500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• جۆری پێست: تایبەتە بە پێستی هەستیار (Sensitive) و ئەو پێستانەی بەرگەی بەرهەمی ئاسایی ناگرن (Intolerant skin).\r\n• بەکارهێنان: بۆ پاککردنەوەی دەموچاو و جەستە بەکاردێت.\r\n• پاککەرەوەیەکی نەرم: بە شێوەیەکی زۆر نەرم پێست پاک دەکاتەوە بەبێ ئەوەی ببێتە هۆی وشکبوونەوە یان خورانی پێست.\r\nپێکهاتە گرنگەکان و سوودەکانیان:\r\n1. Calmosensine: ئەمە پێکهاتەیەکی بایۆ-ئەکتیڤە (Peptide) کە یارمەتی کەمکردنەوەی هەستیاری پێست دەدات بەرامبەر گۆڕانی پلەی گەرمی (سەرمای زۆر یان گەرمای زۆر) و هەستکردن بە ناڕەحەتی پێست کەمدەکاتەوە.\r\n2. Panthenol (پانتینۆڵ): کاردەکات بۆ هێورکردنەوەی پێست و شێدارکردنەوەی.\r\n3. Oat extract (گیراوەی شۆفان): ناسراوە بەوەی دژی هەوکردنە و پێست نەرم و هێمن دەکاتەوە.\r\n4. بەبێ سابوون: ئەم بەرهەمە نابێتە هۆی تێکدانی چینی پارێزەری سروشتی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو لە جێڵەکە بدە لە پێستی تەڕ (دەموچاو یان جەستە).\r\n• بە نەرمی بیشێلە تا کەف دەکات.\r\n• پاشان بە ئاو ڕێخی بکە (بیشۆ).','Gentle cleansing gel for sensitive and intolerant skin, suitable for face and eyes. Cleanses softly without causing dryness or irritation. Key soothing ingredients: Calmosensine (bioactive peptide) to reduce sensitivity and discomfort, Panthenol for soothing and hydration, and Oat extract to calm and soften. Soap-free to help protect the skin’s natural barrier. How to use: apply to wet skin (face/eyes), massage gently until it foams, then rinse with water.','جل تنظيف لطيف للبشرة الحساسة والبشرة غير المتحملة للمنظفات العادية، مناسب للوجه والعينين. ينظف برفق دون التسبب بجفاف أو تهيّج. مكوّنات مهدئة مهمة: Calmosensine (ببتيد نشط) لتقليل الحساسية والانزعاج، بانثينول للتهدئة والترطيب، ومستخلص الشوفان لتهدئة البشرة وتنعيمها. خالٍ من الصابون للمساعدة في حماية حاجز البشرة الطبيعي. طريقة الاستخدام: يوضع على بشرة مبللة (الوجه/حول العين)، يُدلّك بلطف حتى تتكون رغوة ثم يُشطف بالماء.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 03:22:09',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(65,'جێلی پاکەرەوەی تایبەت بە پێستی هەستیار لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,21000,29500,4250,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ کێ دەبێت؟ تایبەت دروستکراوە بۆ پێستی هەستیار (Sensitive) و ئەو پێستانەی زوو سوور دەبنەوە یان بەرگەی پاککەرەوە ئاساییەکان ناگرن.\r\n• بۆ چ شوێنێک بەکاردێت؟ دەتوانیت هەم بۆ دەموچاو و هەم بۆ جەستە بەکاری بهێنیت.\r\n• چارەسەری نیشانەکانی ڕۆزاسیا (Rosacea): لەسەر پاکەتەکەی نووسراوە کە گونجاوە بۆ کەمکردنەوەی سووربوونەوە و نیشانەکانی نەخۆشی ڕۆزاسیا.\r\n• پارێزگاری لە پێست: بە شێوەیەک پاکی دەکاتەوە کە نابێتە هۆی وشکبوونەوەی پێست و چینی پارێزەری سروشتی پێست تێکنادات.\r\nپێکهاتە گرنگەکانی:\r\n• Calmosensine: ماددەیەکی تێدایە کە هەستی بێزارکەر و سووتانەوەی پێست کەمدەکاتەوە.\r\n• Panthenol و Oat Extract: هەردووکیان ناسراون بەوەی پێست ئارام دەکەنەوە و شێداری دەکەن.\r\n• بێ سابوون: ئەم بەرهەمە ماددەی کیمیایی توندی تێدا نییە کە پێست تووشی هەستیاری بکات.\r\nچۆنیەتی بەکارهێنان:\r\n1. کەمێک لە جێڵەکە بدە لە پێستی تەڕ.\r\n2. بە هێواشی بیشێلە تا کەف دەکات.\r\n3. پاشان بە ئاوێکی شلەتێن بە باشی ڕوخسار یان جەستەت بشۆ (Rinse off\r\n','Sensitive-skin cleansing gel suitable for face and body. Designed for easily irritated skin and may help reduce redness associated with rosacea. Cleanses while respecting the skin barrier to avoid dryness. Contains Calmosensine to calm discomfort, plus Panthenol and Oat extract for soothing hydration. Soap-free and gentle. How to use: apply a small amount on wet skin, massage gently to lather, then rinse off with water.','جل تنظيف للبشرة الحساسة مناسب للوجه والجسم. مُصمم للبشرة سريعة التهيّج وقد يساعد على تقليل الاحمرار المرتبط بالوردية (Rosacea). ينظف مع الحفاظ على حاجز البشرة لتجنب الجفاف. يحتوي على Calmosensine لتهدئة الانزعاج، مع بانثينول ومستخلص الشوفان لتهدئة وترطيب البشرة. خالٍ من الصابون ولطيف. طريقة الاستخدام: توضع كمية صغيرة على بشرة مبللة، تُدلّك بلطف حتى تتكون رغوة ثم يُشطف بالماء.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 03:24:48',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(66,'کرێمی تایبەت بە پێستی ناسک و هەستیار لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,18000,25000,3500,1,'کرێمێکی تایبەتە بۆ ئەو کەسانەی پێستیان ناسکە و کێشەی سووربوونەوەی دەموچاو (Redness) یان کێشەی تەقینی دەمارە وردەکانی ژێر پێستیان (Couperose) هەیە\r\nتایبەتمەندییە سەرەکییەکانی:\r\n• دژی سووربوونەوە: یارمەتی کەمکردنەوەی سووربوونەوەی بەردەوام و کاتی دەدات، هەروەها هەستی گەرمداهاتن و کزانەوەی پێست هێور دەکاتەوە.\r\n• پاراستنی دەمارەکان: یارمەتی بەهێزکردنی دیوارەکانی موولولە خوێنە وردەکان دەدات و سووڕی خوێن لەژێر پێستدا ئاسایی دەکاتەوە.\r\n• شێدارکەرەوە و هێورکەرەوە: بەهۆی هەبوونی پێکهاتەی شێدارکەرەوە، پێستەکە بە نەرمی و بە تازەیی دەهێڵێتەوە.\r\n• سیستەمی Airless: پاکەتەکەی بە جۆرێک دروستکراوە کە هەوا ناچێتە ناوی، ئەمەش وادەکات کرێمەکە تێک نەچێت، ئۆکسید نەبێت و دوور بێت لە پیسبوون.\r\nپێکهاتە گرنگەکانی:\r\n1. ڤیتامین C و Flavonoids: بۆ بەهێزکردنی موولولە خوێنەکان و پاراستنی پێست لە ئۆکسان.\r\n2. Calmosensine: پپتایدێکی چالاکە کە هەستیاری پێست و تێکچوونی کەم دەکاتەوە.\r\n3. Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵ و چاککردنەوەی خانە تێکچووەکان.\r\n4. Bisabolol و Ceramides: بۆ هێورکردنەوەی پێست و دووبارە دروستکردنەوەی چینی پارێزەری پێست.\r\n• بەکارهێنان: بۆ بەکارهێنانی دەرەکییە (تەنها بۆ سەر پێست).\r\nئەم کرێمە دەتوانیت ڕۆژی دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.','Special cream for thin and sensitive skin with persistent facial redness and visible small vessels (couperose). Helps reduce redness over time and calms the warm/burning sensation. Supports strengthening of capillary walls and helps normalize microcirculation under the skin. Provides hydration and soothing care, leaving skin soft and comfortable. Airless packaging helps protect the formula. Key ingredients include Vitamin C and flavonoids (antioxidant/capillary support), Calmosensine to calm sensitivity, Hyaluronic Acid for deep hydration, plus Bisabolol and Ceramides to soothe and help restore the skin barrier. Use twice daily (morning and night). For external use only.','كريم مخصص للبشرة الرقيقة والحساسة مع احمرار دائم وظهور الشعيرات الدموية الدقيقة (Couperose). يساعد على تقليل الاحمرار مع الوقت وتهدئة الإحساس بالحرارة/اللسع. يدعم تقوية جدران الأوعية الدقيقة ويساعد على تنظيم الدورة الدموية الدقيقة تحت الجلد. يمنح ترطيباً وتهدئة ويترك البشرة ناعمة ومريحة. عبوة Airless تساعد على حماية التركيبة. من المكوّنات المهمة: فيتامين C وفلافونويدات لدعم الأوعية ومضادات الأكسدة، وCalmosensine لتهدئة الحساسية، وحمض الهيالورونيك للترطيب العميق، مع بيسابولول وسيراميدات لتهدئة البشرة ودعم إصلاح الحاجز. يُستخدم مرتين يومياً (صباحاً ومساءً). للاستعمال الخارجي فقط.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 03:41:01',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(67,'کرێمی ڕێتیسۆم بۆ چارەسەرکردن و نوێکردنەوە و ڕوبەروبونەوەی نیشانەکانی پیری پێستی دەم و چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,21000,29000,4000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی ڕێتینۆڵ (0.1% Retinol): گرنگترین ماددەی تێدایە کە بە شێوەی \"لیپۆسۆم\" (Liposomes) دروستکراوە، ئەمەش وادەکات ماددەکە باشتر بچێتە ناو پێستەوە و کاریگەرییەکەی زیاتر بێت بەبێ ئەوەی ببێتە هۆی سووربوونەوەی زۆر.\r\n• دژە پیری: یارمەتی کەمکردنەوەی چرچولۆچی و هێڵە وردەکانی دەموچاو دەدات.\r\n• نوێکردنەوەی خانەکان: یارمەتی نوێکردنەوەی خانەکانی پێست دەدات و شێوەیەکی گەشاوە و نەرم بە پێست دەبەخشێت.\r\nپێکهاتە گرنگەکانی تر:\r\n1. Hyaluronic acid: بۆ شێدارکردنەوەی قووڵی پێست.\r\n2. Vitamin E: وەک دژە ئۆکسان کاردەکات و پێست لە تیشکی زیانبەخش و پیسی دەپارێزێت.\r\n3. D-Panthenol: کاردەکات بۆ هێورکردنەوەی پێست و ڕێگری لە وشکبوونەوە.\r\nبۆ چ جۆرە پێستێک گونجاوە؟\r\nبۆ ئەم حاڵەتانە گونجاوە:\r\n• ئەو پێستانەی بەهۆی تیشکی خۆرەوە زیانیان پێگەیشتووە.\r\n• پێستی ماندوو و بێڕەنگ.\r\n• پێستی چەور و ئەو پێستانەی زیپکەیان تێدایە (چونکە ڕێتینۆڵ کونیلەکان پاک دەکاتەوە).\r\nچۆنیەتی بەکارهێنان و تێبینی گرنگ:\r\n• کات: بەزۆری کرێمەکانی ڕێتینۆڵ تەنها شەوان بەکاردێن، چونکە ڕێتینۆڵ لەبەر تیشکی خۆر کارلێک دەکات و ڕەنگە پێست بسوتێنێت.\r\n• دژەخۆر: زۆر گرنگە ڕۆژانە دژەخۆر بەکاربهێنیت کاتێک ئەم کرێمە بەکاردێنیت، چونکە پێست ناسک دەبێتەوە بەرامبەر تیشکی خۆر.\r\n• پاراستن: پێویستە لە شوێنێکی سارد و وشکدا دایبنێیت (کەمتەر لە ٣٥ پلەی سیلیزی).\r\n• سیستەمی Airless: وەک لە وێنەکەدا دیارە، دەبەکەی جۆرێکە کە هەوا ناچێتە ناوی بۆ ئەوەی ماددەکانی ناوی تێک نەچن و بۆ ماوەیەکی درێژ بە باشی بمێننەوە.\r\nتێبینی: ئەگەر یەکەمجارتە ڕێتینۆڵ بەکاردێنیت، باشترە لە هەفتەیەکدا ٢ بۆ ٣ شەو دەست پێ بکەیت تا پێستت ڕادێت، پاشان بیکەیتە هەموو شەوێک.','Retinol treatment cream (0.1% retinol) in liposomes for better delivery and improved tolerance. Helps reduce fine lines and wrinkles around face and eyes and supports skin renewal for a smoother, brighter look. Includes Hyaluronic Acid for hydration, Vitamin E for antioxidant protection, and D-Panthenol to soothe and help prevent dryness. Suitable for sun-damaged, tired/dull skin and also for oily skin with clogged pores. Use mainly at night. Daily sunscreen is essential while using retinol. Store in a cool, dry place (below 35°C). Start slowly: 2–3 nights per week, then increase as tolerated.','كريم علاج بالريتينول (0.1% ريتينول) بتقنية الليبوسومات لتحسين التغلغل وتقليل التهيّج. يساعد على تقليل الخطوط الدقيقة والتجاعيد حول الوجه والعينين ويدعم تجدد خلايا البشرة لمظهر أنعم وأكثر إشراقاً. يحتوي على حمض الهيالورونيك للترطيب، وفيتامين E كمضاد للأكسدة، وD-بانثينول لتهدئة البشرة والحد من الجفاف. مناسب للبشرة المتضررة من الشمس والبشرة المتعبة/الباهتة، وكذلك للبشرة الدهنية مع انسداد المسام. يُستخدم غالباً ليلاً. واقي الشمس ضروري يومياً أثناء استخدام الريتينول. يُحفظ في مكان بارد وجاف (أقل من 35°م). ابدأ تدريجياً: 2–3 ليالٍ بالأسبوع ثم زد الاستخدام حسب تحمّل البشرة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 03:44:35',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(68,'کرێمی چارەسەرکردنی ڕەشی ژێر چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,21000,29000,4500,1,'سوودە سەرەکییەکانی ئەم کرێمە:\r\n• دژە پیربوون: یارمەتی کەمکردنەوەی نیشانەکانی پیربوون، هێڵە وردەکان و چرچولۆچی دەوری چاو دەدات.\r\n• بۆ ڕەشی دەوری چاو: تایبەت دروست کراوە بۆ کەمکردنەوەی ڕەشی (Dark Circles) و کەمکردنەوەی هەڵئاوسانی ژێر چاو (Puffiness).\r\n• نوێکردنەوەی خانەکان: بەهۆی هەبوونی ماددەی \"ڕێتینۆڵ\"، یارمەتی نوێکردنەوەی خانەکانی پێست دەدات.\r\n• شێدارکەرەوە: پێستەکە نەرم دەکات و شێدارییەکی پێویستی پێ دەبەخشێت بەهۆی بوونی \"هایالۆرۆنیک ئەسید\".\r\nپێکهاتە گرنگەکان:\r\n1. Retinol (0.1%): ماددەیەکی زۆر کارایە بۆ نوێکردنەوەی پێست و نەمانی چرچولۆچ (لەناو لیپۆسۆم دایە بۆ ئەوەی باشتر بچێتە ناو پێست و کەمتر هەستیاری دروست بکات).\r\n2. Biopeptides & Flavonoids: ئەم ماددانە موولوولەکانی خوێن بەهێز دەکەن و یارمەتی سووڕی خوێن دەدەن لە ژێر چاودا، کە دەبێتە هۆی نەمانی ڕەشی و هەڵئاوسان.\r\n3. Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵی پێست.\r\n4. Vitamin E & Panthenol: بۆ پاراستنی پێست و هێورکردنەوەی.\r\nچۆنیەتی بەکارهێنان و تێبینییە گرنگەکان:\r\n• بۆ کێ دەبێت؟ بۆ ئەو کەسانەی پێستی دەوری چاویان هەستیار و ناسکە.\r\n• شێوازی بەکارهێنان: بڕێکی کەم لە کرێمەکە بدە لە دەوری چاوت و بە پەنجە زۆر بە هێواشی (وەک لێدانێکی کەم) بڵاوی بکەرەوە تا هەڵدەمژرێت.\r\n• تێبینی: بەهۆی هەبوونی ڕێتینۆڵ، باشترە تەنها شەوان بەکاربێت. ئەگەر بە ڕۆژ بەکاری دەهێنیت، دەبێت دژەخۆر بەکاربهێنیت چونکە ڕێتینۆڵ پێست بەرامبەر خۆر هەستیار دەکات.','Eye cream for dark circles and puffiness with anti-aging support. Helps reduce the appearance of fine lines and wrinkles and supports skin renewal thanks to 0.1% retinol in liposomes (better tolerance). Includes biopeptides and flavonoids to support microcirculation and improve the look of dark circles and swelling, Hyaluronic Acid for hydration, plus Vitamin E and Panthenol for protection and soothing. How to use: apply a small amount around the eye area and gently tap with the fingertip. Best used at night; if used in daytime, sunscreen is recommended due to retinol.','كريم للعين للهالات السوداء والانتفاخ مع دعم مضاد لعلامات التقدم. يساعد على تقليل مظهر الخطوط الدقيقة والتجاعيد ويدعم تجدد البشرة بفضل ريتينول 0.1% بتقنية الليبوسومات (تحمّل أفضل). يحتوي على ببتيدات حيوية وفلافونويدات لدعم الدورة الدموية الدقيقة وتحسين مظهر الهالات والانتفاخ، وحمض الهيالورونيك للترطيب، مع فيتامين E وبانثينول للحماية والتهدئة. طريقة الاستخدام: توضع كمية قليلة حول العين مع التربيت الخفيف بطرف الإصبع. يُفضّل استخدامه ليلاً؛ وإذا استُخدم نهاراً فينصح بواقي شمس بسبب وجود الريتينول.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:00:38',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(69,'کرێمی دژە خۆری تایبەت بە پێستی چەور و زیپکە لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,26000,3000,1,'. پاراستنێکی زۆر بەهێز\r\n• SPF 50+: پاراستنێکی زۆر باش لە دژی تیشکی سەروو بنەوشەیی (UVA و UVB) دابین دەکات.\r\n• پاراستنی گشتگیر: جگە لە تیشکی خۆر، پێست دەپارێزێت لە تیشکی ژێرسوور (IR) و تیشکی شینی ئامێرە ئەلیکترۆنییەکان (Blue Light).\r\n• Antioxidant: ماددەی دژە ئۆکسانی تێدایە کە ڕێگری لە پیربوونی پێست و تێکچوونی خانەکان دەکات.\r\n٢. گونجاو بۆ پێستی چەور و زیپکەدار\r\n• Matte Effect: ڕەنگێکی مات (بێ بریقە) بە پێست دەبەخشێت و ناهێڵێت پێستەکە بە چەوری ببریسکێتەوە.\r\n• Non-Oily: پێکهاتەکەی چەور نییە و زوو هەڵدەمژرێت، هەستی \"پێستی ڕووت\" (Nude Skin Sensation) دەدات، واتە وەک ئەوە وایە هیچت لێ نەدابێت.\r\n• Seboregulating: یارمەتی ڕێکخستنی چەوری پێست دەدات و ڕێگری لە دروستبوونی زیپکە دەکات.\r\n٣. پێکهاتە سوودبەخشەکان\r\n• Hyaluronic Acid: بۆ شێدارکردنەوەی پێست بەبێ ئەوەی چەوری بکات.\r\n• Ectoin: یارمەتی بەهێزکردنی بەرگری سروشتی خانەکانی پێست دەدات.\r\n• Vitamin E: بۆ پاراستن و نەرمکردنەوەی پێست.\r\n• Water-Resistant: بەرگری بەرامبەر ئاو و ئارەق کردنەوە هەیە.\r\n٤. زانیارییەکانی بەکارهێنان\r\n• بڕ: 50 مل.\r\n• شێوازی بەکارهێنان: پێش چوونە بەر خۆر بە ٢٠ خولەک لێی بدە و هەر ٢ کاتژمێر جارێک نوێی بکەرەوە ئەگەر لەبەر خۆر بوویت.\r\n','High-protection sunscreen for oily and acne-prone skin (SPF 50+). Provides broad protection against UVA/UVB and also helps protect against IR and blue light. Matte finish (no shine) with a lightweight, non-greasy “nude skin” feel and sebum-regulating benefits to help reduce breakouts. Contains Hyaluronic Acid for hydration without heaviness, Ectoin to support skin cell protection, and Vitamin E for antioxidant care. Water-resistant. Size: 50 ml. How to use: apply evenly 20 minutes before sun exposure and reapply every 2 hours (especially after swimming or sweating).','واقي شمس عالي الحماية للبشرة الدهنية والمعرضة للحبوب (SPF 50+). يوفر حماية واسعة ضد UVA/UVB، ويساعد أيضاً على الحماية من الأشعة تحت الحمراء (IR) والضوء الأزرق. يمنح لمسة مطفية دون لمعان مع إحساس خفيف غير دهني (Nude Skin) ويساعد على تنظيم إفراز الدهون لتقليل ظهور الحبوب. يحتوي على حمض الهيالورونيك للترطيب دون ثقل، وEctoin لدعم حماية الخلايا، وفيتامين E كمضاد للأكسدة. مقاوم للماء. الحجم: 50 مل. طريقة الاستخدام: يُوضع بالتساوي قبل التعرض للشمس بـ20 دقيقة ويُعاد كل ساعتين (خصوصاً بعد السباحة أو التعرق).',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:03:08',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(70,'کرێمی دژە خۆر و دژە پەڵە و سپیکەرەوەی پێستی دەم و چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنێکی زۆر بەرز: خاوەنی فاکتەری پاراستنی $SPF 50+$ە، کە پێست دەپارێزێت لە تیشکە زیانبەخشەکانی خۆر (UVA و UVB).\r\n• دژە پەڵە و سپیکەرەوە: ئەم کرێمە تەنها دژەخۆر نییە، بەڵکو یارمەتی کەمکردنەوەی پەڵە قاوەییەکان، کڵۆف (پەڵەی دووگیانی) و نیشانەکانی پیری دەدات.\r\n• دژە پیری (Anti-aging): بەهۆی هەبوونی ڤیتامین C و ترشی هیالۆرۆنیک (Hyaluronic Acid)، یارمەتی شێدارکردنەوەی پێست و پاراستنی لە چرچولۆچی دەدات.\r\n• پاراستنی خانەکان: ماددەی Ectoinی تێدایە کە بەرگری سروشتی خانەکانی پێست بەهێز دەکات لە بەرامبەر سترێسی ژینگەیی.\r\nبۆ کێ گونجاوە؟\r\n• ئەو کەسانەی پەڵەی قاوەیی، کەکماک (نمەک)، یان شوێنەواری برین و زیپکەیان هەیە.\r\n• ئەو کەسانەی پێستیان زۆر سپی و هەستیارە.\r\n• گواراوە بۆ بەکارهێنان لە کاتی گەشت بۆ شاخ یان دەریا (کە تیشکی خۆر زۆر بەهێزە).\r\n• زۆر گونجاوە بۆ دوای چارەسەرەکانی لێزەر یان پیڵینگ (Peeling) چونکە پێست لەو کاتەدا زۆر هەستیارە.\r\nشێوازی بەکارهێنان:\r\n• پێش ئەوەی بچیتە بەر خۆر بە ٢٠ بۆ ٣٠ خولەک بە یەکسانی بیدە لە پێستت.\r\n• ئەگەر بۆ ماوەیەکی زۆر لەبەر خۆر بوویت، یان دوای مەلەکردن و ئارەقکردنەوە، پێویستە دووبارەی بکەیتەوە.\r\nتێبینییەکی گرنگ:\r\nئەم کرێمە بە سیستەمی Airless دروستکراوە (وەک لە وێنەی دووەمدا دیارە)، ئەمەش واتە هەوا ناچێتە ناو بوتڵەکە؛ ئەمە دەبێتە هۆی ئەوەی پێکهاتەکان تێکنەچن، میکرۆب بۆ ناوەوە نەچێت، و تا کۆتا دڵۆپ بتوانیت بەکاری بهێنیت بەبێ ئەوەی بە فیڕۆ بچێت','Sunscreen with very high protection (SPF 50+) plus anti-spot and brightening support. Helps protect against UVA/UVB while supporting reduction of brown spots, melasma, and signs of aging. With Vitamin C and Hyaluronic Acid for hydration and anti-aging support, and Ectoin to strengthen cellular defense against environmental stress. Especially suitable for pigmentation concerns, very fair/sensitive skin, travel to high-sun areas (sea/mountains), and post-laser or peeling when skin is extra sensitive. How to use: apply evenly 20–30 minutes before sun exposure; reapply during prolonged exposure or after swimming/sweating. Airless packaging protects the formula.','واقي شمس بحماية عالية جداً (SPF 50+) مع دعم مضاد للبقع وتفتيح. يحمي من UVA/UVB ويساعد على تقليل البقع البنية والكلف وعلامات التقدم. يحتوي على فيتامين C وحمض الهيالورونيك للترطيب ودعم مضاد للشيخوخة، وEctoin لتقوية دفاع الخلايا ضد الإجهاد البيئي. مناسب خصوصاً لمشاكل التصبغ والبشرة الفاتحة جداً/الحساسة، وللاستخدام أثناء السفر للمناطق ذات شمس قوية (البحر/الجبال)، وكذلك بعد الليزر أو التقشير عندما تكون البشرة أكثر حساسية. طريقة الاستخدام: يُوضع بالتساوي قبل التعرض للشمس بـ20–30 دقيقة ويُعاد أثناء التعرض الطويل أو بعد السباحة/التعرق. عبوة Airless تحمي التركيبة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:06:13',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(71,'کرێمی دژە خۆر و شێدارکەرەوەی پێست لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,19500,25500,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی زۆر بەهێز: خاوەنی $SPF 50+$ە کە پێست دەپارێزێت لە تیشکە زیانبەخشەکانی (UVA) و (UVB). هەروەها نیشانەی 5 ئەستێرەی لەسەرە بۆ پاراستنی \"Ultra\" لە تیشکی UVA کە بەرپرسە لە پیربوونی پێست.\r\n• پاراستنی خانەکان (Cellular Protection): تەکنەلۆژیای تێدایە کە خانەکانی پێست لە ئاستێکی قووڵدا دەپارێزێت لە تێکچوون و سووتان.\r\n• دژە ئۆکسان (Antioxidant): ڤیتامین E و پێکهاتەی تێدایە کە ڕێگری دەکەن لە دروستبوونی لۆچ و پیربوونی پێست بەهۆی خۆرەوە.\r\n• شێدارکەرەوە: ماددەی Hyaluronic Acid (هایلۆرۆنیک ئەسید)ی تێدایە کە یارمەتی مانەوەی شێداری پێست دەدات و نایەڵێت وشک ببێتەوە.\r\n• دژە ئاو: ئەم کرێمە بەرگەی ئاو و ئارەق کردنەوە دەگرێت (Water Resistant).\r\nبۆ کێ گونجاوە؟\r\n• بۆ هەموو جۆرە پێستێک گونجاوە، بەتایبەت ئەو پێستانەی زۆر هەستیارن یان زۆر سپین و زوو دەسووتێن.\r\n• بۆ ئەو کەسانەی لە شوێنی زۆر گەرم یان بەر تیشکی ڕاستەوخۆی خۆرن (وەک شاخەوانی یان کەنار دەریا).\r\nشێوازی بەکارهێنان:\r\n1. ١٥ بۆ ٣٠ خولەک پێش ئەوەی بچیتە بەر خۆر، بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاو و مل و ئەو شوێنانەی بەر خۆر دەکەون.\r\n2. ئەگەر بۆ ماوەیەکی درێژ لەبەر خۆر بوویت، یان دوای مەلەکردن و ئارەقکردنەوەی زۆر، پێویستە ٢ کاتژمێر جارێک نوێی بکەیتەوە.\r\nتێبینی گرنگ:\r\nئەم بەرهەمە لە سیستەمی Airless (بێ هەوا) بەکاردەهێنێت، ئەمەش وا دەکات ماددەکە تێک نەچێت و تا کۆتا دڵۆپ بە پاکی بمێنێتەوە.','Moisturizing sunscreen with very high protection (SPF 50+). Protects against UVA/UVB and provides enhanced UVA protection (Ultra UVA 5-star mark as stated). Supports deep cellular protection against sun damage and helps prevent premature aging. Contains Vitamin E for antioxidant defense and Hyaluronic Acid to maintain hydration. Water-resistant. Suitable for all skin types, especially very fair and sensitive skin that burns easily and for strong sun conditions (mountains/sea). How to use: apply 15–30 minutes before sun exposure on face, neck, and exposed areas; reapply every 2 hours or after swimming/sweating. Airless packaging helps keep the formula stable.','واقي شمس مرطب بحماية عالية جداً (SPF 50+). يحمي من UVA/UVB ويوفر حماية UVA محسّنة (وفق علامة Ultra UVA ذات 5 نجوم المذكورة). يدعم حماية خلوية عميقة من أضرار الشمس ويساعد على الوقاية من الشيخوخة المبكرة. يحتوي على فيتامين E كمضاد للأكسدة وحمض الهيالورونيك للحفاظ على الترطيب. مقاوم للماء. مناسب لجميع أنواع البشرة، خصوصاً البشرة الفاتحة جداً والحساسة التي تحترق بسرعة، ولظروف الشمس القوية (البحر/الجبال). طريقة الاستخدام: يوضع قبل التعرض للشمس بـ15–30 دقيقة على الوجه والرقبة والمناطق المكشوفة، ويُعاد كل ساعتين أو بعد السباحة/التعرق. عبوة Airless تساعد على ثبات التركيبة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:08:22',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(72,'کرێمی دژە خۆری پاراستنی پێست و چارەسەرکردنی پەڵە لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,21000,28000,3500,1,'. پاراستنێکی زۆر بەهێز\r\n• خاوەنی SPF 50+ یە، کە پاراستنێکی زۆر باش دژی تیشکە زیانبەخشەکانی (UVA و UVB) دابین دەکات.\r\n• Water Resistant: بەرگری بەرامبەر ئاو و ئارەقکردنەوە هەیە.\r\n٢. تایبەتمەندییە دەرمانییەکانی (Anti-Spot)\r\nئەم دژەخۆرە تەنها بۆ پاراستن نییە، بەڵکو وەک چارەسەریش کار دەکات:\r\n• دژی پەڵە (Anti-Spot): یارمەتی کەمکردنەوەی ئەو پەڵانە دەدات کە بەهۆی خۆرەوە دروست دەبن و ڕەنگی پێست یەکدەخاتەوە.\r\n• سپیکردنەوە (Brightening): بەهۆی هەبوونی ڤیتامین C تێیدا، درەوشانەوە بە پێست دەبەخشێت.\r\n• دژی چرچولۆچی: یارمەتی پاراستنی خانەکانی پێست و DNA دەدات لە پیربوونی پێشوەختە.\r\n٣. پێکهاتە سەرەکییەکان\r\n• Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵی پێست و ڕێگریکردن لە وشکبوونەوە.\r\n• Vitamin C: بۆ سپیکردنەوە و وەک دژە ئۆکسان (Antioxidant).\r\n• Indanone & Ethyl Ferulate: ئەمانە پێکهاتەی نوێن کە کار دەکەن بۆ پاراستنی خانە بنەڕەتییەکانی پێست (Stem Cell Protection).\r\n٤. شێواز و هەستی بەکارهێنان\r\n• Silk Touch: هەستێکی ئاوریشمی و نەرم بە پێست دەبەخشێت.\r\n• Non-Oily: چەوری جێناهێڵێت و پێست بریقەدار ناکات \r\n• Paraben Free: بەبێ ماددەی پارابین دروستکراوە کە ئەمەش بۆ پێستە هەستیارەکان باشە.\r\n• شێوازی بەکارهێنان: پێش چوونە بەر خۆر بە ٢٠ خولەک لێی دەدرێت و پێویستە ٢ کاتژمێر جارێک نوێ بکرێتەوە ئەگەر لەبەر خۆر بوویت.','High-protection sunscreen (SPF 50+) with water resistance and anti-spot care. Helps reduce sun-related spots and supports a brighter, more even tone thanks to Vitamin C. Also supports protection against premature aging and DNA damage. Key ingredients include Hyaluronic Acid for hydration and Indanone + Ethyl Ferulate for stem-cell level protection (as described). Provides a silky touch, non-oily feel, and is paraben-free—suitable for sensitive skin. How to use: apply 20 minutes before sun exposure and reapply every 2 hours during prolonged sun.','واقي شمس عالي الحماية (SPF 50+) مقاوم للماء مع عناية مضادة للبقع. يساعد على تقليل البقع الناتجة عن الشمس ويدعم توحيد اللون والتفتيح بفضل فيتامين C. كما يدعم الحماية من الشيخوخة المبكرة وأضرار الـDNA. من المكوّنات: حمض الهيالورونيك للترطيب وIndanone مع Ethyl Ferulate لدعم حماية متقدمة (كما هو مذكور). يمنح ملمساً حريرياً وإحساساً غير دهني، وخالٍ من البارابين ومناسب للبشرة الحساسة. طريقة الاستخدام: يُوضع قبل التعرض للشمس بـ20 دقيقة ويُعاد كل ساعتين عند التعرض الطويل.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:11:25',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(73,'سیڕۆمی دژە پیربوون و تازەکەرەوە و گەشکەرەوەی پێستی دەم و چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,26000,35000,4500,1,'پێکهاتە سەرەکییەکان:\r\n• ڤیتامین C بە خەستی %15 (Stabilized Vitamin C): دژە ئۆکسانێکی بەهێزە، کاردەکات بۆ سپیکردنەوەی پێست، کەمکردنەوەی پەڵە و هاندانی دروستبوونی کۆلاجین.\r\n• هایالۆرۆنیک ئەسید %0.5 (Hyaluronic Acid): شێدارییەکی زۆر بە پێست دەبەخشێت و وای لێدەکات پڕ و گەشاوە دەربکەوێت.\r\n• خەمیرەی گوڵی پۆرسەلین (Hoya Carnosa): یارمەتی هاوسەنگکردنەوەی بەکتریای سوودبەخشی پێست (Microbiome) دەدات.\r\n• ئەکتۆین و پێپتاید (Ectoin & Peptides): بەربەستی سروشتی پێست بەهێز دەکەن و دەیپارێزن لە کاریگەرییە خراپەکانی پیسبوونی ژینگە و تیشکی خۆر.\r\nسوودە گرنگەکانی:\r\n1. دژە پیربوون: نیشانەکانی پیربوون و چرچوڵۆچی کەم دەکاتەوە.\r\n2. گەشاوەیی دەمودەست: ڕەنگی پێست یەکدەخات و بریقەیەکی تەندروستی پێ دەبەخشێت.\r\n3. شێدارکردن: بە قووڵی پێست شێدار دەکاتەوە.\r\n4. کەمکردنەوەی پەڵە: کاردەکات بۆ کاڵکردنەوەی پەڵەی تەمەن و شوێنەواری زیپکە.\r\nچۆن بەکاردێت؟\r\n• بەیانیان و شەوان بڕێکی گونجاو بدە لە پێستی دەموچاو، مل و سنگ.\r\n• پێویستە پێش بەکارهێنانی، پێستت بەباشی پاک کردبێتەوە.\r\n• دەتوانیت بەتەنها بەکاریبهێنیت یان پێش بەکارهێنانی کرێمی شێدارکەرەوەی ڕۆژانەت.\r\n','Anti-aging and brightening serum for face and eyes. With 15% stabilized Vitamin C to brighten skin, reduce spots, and support collagen production; 0.5% Hyaluronic Acid for deep hydration and plump look; Hoya Carnosa flower yeast to support the skin microbiome balance; plus Ectoin and Peptides to strengthen the skin barrier and protect against pollution and sun stress. Benefits: reduces signs of aging, improves glow and tone uniformity, deeply hydrates, and helps fade age spots and post-acne marks. How to use: apply morning and night to clean skin on face, neck, and chest; can be used alone or before moisturizer.','سيروم مضاد لعلامات التقدم ومفتّح للوجه ومنطقة العين. يحتوي على فيتامين C مثبت بتركيز 15% لتفتيح البشرة وتقليل البقع وتحفيز إنتاج الكولاجين، وحمض الهيالورونيك 0.5% للترطيب العميق ومظهر أكثر امتلاءً، وخميرة زهرة Hoya Carnosa لدعم توازن الميكروبيوم، مع Ectoin وببتيدات لتقوية حاجز البشرة وحمايتها من التلوث وإجهاد الشمس. الفوائد: تقليل علامات التقدم، تحسين الإشراقة وتوحيد اللون، ترطيب عميق، والمساعدة على تخفيف بقع العمر وآثار الحبوب. طريقة الاستخدام: يُستخدم صباحاً ومساءً على بشرة نظيفة للوجه والرقبة والصدر، ويمكن استخدامه بمفرده أو قبل المرطب.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:31:02',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(74,'کرێمی پێشکەوتووی پاراستن و گەنجکردنەوەی پێست لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,26000,36000,5000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• دژە پیربوون (Anti-Ageing): ئەم کرێمە کار دەکات بۆ کەمکردنەوەی نیشانەکانی پیربوون و ڕێگری کردن لە دروستبوونی هێڵی ورد لەسەر دەموچاو.\r\n• پاراستن لە خۆر (SPF30): پارێزگارییەکی باش لە پێست دەکات دژی تیشکی زیانبەخشی خۆر و ڕێگری دەکات لە پەڵەی ناتەندروست.\r\n• تایبەتمەندی \"بۆتۆکس لایک\": ماددەی (Acetyl Hexapeptide-1) تێدایە کە یارمەتی خاوکردنەوەی گرژبوونی ماسولکەکانی دەموچاو دەدات، ئەمەش وەک جێگرەوەیەک بۆ دەرزی بۆتۆکس کار دەکات بۆ کەمکردنەوەی چرچولۆچی.\r\n• توندکردنەوەی پێست (V-shape effect): ماددەی (Bacillus ferment)ی تێدایە کە لە قوڵایی دەریاوە دەرهێنراوە، یارمەتی بەرزکردنەوە و توندکردنەوەی پێست دەدات بۆ ئەوەی دەموچاو شێوەیەکی رێک و گەنج وەربگرێت.\r\n• شێدارکەرەوە و پارێزەر: ترشی هیالۆرۆنیک (Hyaluronic Acid) و سیرامایدی تێدایە کە پێست بە شێداری دەهێڵنەوە و بەربەستە سروشتییەکەی بەهێز دەکەن.\r\nسوودەکانی:\r\n• گەشاوەیی و تازەیی دەبەخشێت بە پێست.\r\n• دژی کاریگەرییەکانی پیسبوونی ژینگە و تیشکی خۆرە کە زیان بە DNAی خانەکانی پێست دەگەیەنن.\r\n• گونجاوە بۆ پێستی پێگەیشتوو (Mature Skin).\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو بدە لە دەموچاو، مل، و سنگ.\r\n• دەتوانرێت دوای کارە جوانکارییەکانی وەک (لیزەر یان فیشەڵ) بەکاربهێنرێت بۆ باشترکردنی ئەنجامەکان.','Advanced protective and rejuvenating face cream with anti-aging and SPF 30 support. Helps reduce visible aging signs and prevent fine lines. Contains a “botox-like” peptide (Acetyl Hexapeptide-1) to help relax the look of expression lines, and Bacillus ferment (marine-derived) to support lifting and firmer-looking V-shape contour. Includes Hyaluronic Acid and Ceramides to hydrate and strengthen the skin barrier. Helps protect skin from environmental stress that can damage skin cells/DNA. Suitable for mature skin. How to use: apply an appropriate amount to face, neck, and upper chest; can be used after cosmetic procedures to support results.','كريم متقدم لحماية وتجديد البشرة مع خصائص مضادة لعلامات التقدم ودعم حماية SPF 30. يساعد على تقليل مظاهر التقدم ومنع الخطوط الدقيقة. يحتوي على ببتيد “شبيه بالبوتوكس” (Acetyl Hexapeptide-1) للمساعدة في تقليل مظهر خطوط التعبير، وBacillus ferment (مستخلص بحري) لدعم شدّ البشرة ومظهر V-Shape أكثر تماسكاً. يحتوي على حمض الهيالورونيك وسيراميدات لترطيب البشرة وتقوية حاجزها. يساعد على حماية البشرة من إجهادات البيئة التي قد تؤثر على خلايا البشرة/الـDNA. مناسب للبشرة الناضجة. طريقة الاستخدام: توضع كمية مناسبة على الوجه والرقبة وأعلى الصدر، ويمكن استخدامه بعد الإجراءات التجميلية لدعم النتائج.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:32:59',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(75,'کرێمی دژە خۆری هایالۆرۆنیک سیلک تەچی ڕەنگدار لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,21000,28000,3500,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی زۆر بەرز: خاوەنی SPF +50 کە پاراستنێکی تەواو دژی تیشکە زیانبەخشەکانی (UVA & UVB) دابین دەکات.\r\n• ڕەنگدار (Tinted Light): ئەم جۆرەیان ڕەنگی تێدایە (نەرم و کاڵ)، وەک ئەساسێکی سوک کاردەکات بۆ شاردنەوەی پەڵە، زیپکە و نایەکسانی ڕەنگی پێست.\r\n• تەکنەلۆژیای Silk Touch: هەستێکی زۆر نەرم وەک ئاوریشم بە پێست دەبەخشێت و پێست چەور ناکات (Non-oily).\r\n• دژە ئاو: بەرگری لە بەرامبەر ئاو و ئارەقەکردنەوە هەیە.\r\n٢. پێکهاتە گرنگەکان و سوودەکانیان:\r\n• Hyaluronic Acid: پێست بە قووڵی شێدار دەکاتەوە و ڕێگری دەکات لە دروستبوونی هێڵ و چرچی.\r\n• پاراستنی DNA و خانە بنەڕەتییەکان (Stem Cell): ماددەکانی وەک (Indanone, Ethyl Ferulate & Carnosine) تێدایە کە دژە ئۆکسانێکی بەهێزن و پێست لە پیربوونی پێشوەختە دەپارێزن.\r\n• بۆ کێ گونجاوە؟ بە تایبەت بۆ ئەو کەسانە دروستکراوە کە پێستیان چەورە یان زیپکەیان هەیە، چونکە کونیلەکان ناگرێت.\r\n٣. زانیارییە گرنگەکان\r\n• بەبێ پارابین (Paraben Free): واتە ماددەی کیمیایی زیانبەخشی پارابینی تێدا نییە.\r\n• سیستەمی Airless: پاکەتەکەی بە شێوەیەکە کە هەوا ناچێتە ناو عەسابەکە، ئەمەش وا دەکات بەرهەمەکە بۆ ماوەیەکی درێژتر بە تازەیی بمێنێتەوە و پیس نەبێت.\r\nچۆنیەتی بەکارهێنان:\r\nپێش ئەوەی بچیتە بەر هەتاو بە ٢٠ خولەک بیدە لە پێستت. ئەگەر بۆ ماوەیەکی زۆر لەبەر هەتاو بوویت، وا باشە هەموو ٢ بۆ ٣ کاتژمێر جارێک نوێی بکەیتەوە.','Tinted sunscreen (light tint) with Silk Touch technology for oily/acne-prone skin. Very high protection SPF 50+ against UVA/UVB with a soft, natural tint that helps cover spots, blemishes, and uneven tone like a lightweight base. Silky feel, non-greasy, and water-resistant. Contains Hyaluronic Acid for hydration and antioxidant protective agents (Indanone, Ethyl Ferulate, Carnosine) to support DNA/stem-cell protection as described. Paraben-free. Airless packaging helps preserve stability. How to use: apply 20 minutes before sun exposure; reapply every 2–3 hours during prolonged sun.','واقي شمس ملوّن (درجة خفيفة) بتقنية Silk Touch للبشرة الدهنية والمعرضة للحبوب. حماية عالية جداً SPF 50+ ضد UVA/UVB مع لون طبيعي ناعم يساعد على إخفاء البقع وآثار الحبوب وعدم تجانس اللون كقاعدة خفيفة. ملمس حريري غير دهني ومقاوم للماء. يحتوي على حمض الهيالورونيك للترطيب، وعوامل مضادة للأكسدة وحماية متقدمة (Indanone وEthyl Ferulate وCarnosine) لدعم حماية الـDNA/الخلايا كما هو مذكور. خالٍ من البارابين. عبوة Airless تساعد على ثبات المكوّنات. طريقة الاستخدام: يُوضع قبل التعرض للشمس بـ20 دقيقة ويُعاد كل 2–3 ساعات عند التعرض الطويل.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:35:43',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(76,'شامپۆی تایبەت بە چارەسەرکردنی قژی وشک و تێکچوو لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,15000,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• جۆری قژ: تایبەتە بە قژی وشک و تێکچوو (Dry & Damaged).\r\n• پێکهاتە گرنگەکان: * کیراتین (Keratin): بۆ بەهێزکردن و چاککردنەوەی تاڵە قژەکان.\r\n• پانتینۆڵ (Panthenol): بۆ شێدارکردنەوەی قووڵی قژەکە.\r\n• پڕۆتینی گەنم (Wheat Proteins): بۆ نەرمکردن و بریقەدارکردنی قژ.\r\n• کاریگەری: ئەم شامپۆیە یارمەتی پاککردنەوە، خۆراکپێدان و بەهێزکردنی قژ دەدات و وای لێدەکات نەرم و بریقەدار بێت.\r\n• بەکارهێنان: لەسەر قژی تەڕ بەکاردێت، بە هێواشی مەساجی پێدەکرێت و پاشان بە باشی بە ئاو دەشۆردرێت.\r\nتێبینییەکان دەربارەی پێکهاتەکەی:\r\n• ئەم بەرهەمە سولفاتی (Sodium Laureth Sulfate) تێدایە، کە بۆ پاککردنەوەی قژ زۆر باشە، بەڵام ئەگەر قژت زۆر هەستیار بێت یان ڕەنگی (بۆیەی) تێدا بێت، دەبێت بزانیت کە سولفات ڕەنگەکە زووتر لادەبات.\r\n• Dermatologically Tested: لە ڕووی پێستەوە تاقیکراوەتەوە و پەسەند کراوە.\r\n','Shampoo for dry and damaged hair. Key ingredients: Keratin to strengthen and repair hair fibers, Panthenol for deep hydration, and Wheat Proteins for softness and shine. Cleanses, nourishes, and helps hair look smoother and healthier. Dermatologically tested. Note: contains Sodium Laureth Sulfate (SLES)—great for cleansing, but it may fade color faster or be less suitable for highly sensitive/treated hair. How to use: apply to wet hair, massage gently, then rinse well.','شامبو مخصص للشعر الجاف والمتضرر. مكوّناته الأساسية: كيراتين لتقوية ألياف الشعر وإصلاحها، بانثينول لترطيب عميق، وبروتينات القمح للنعومة واللمعان. ينظف ويغذي ويساعد على مظهر أكثر نعومة وصحة. مختبر جلدياً. ملاحظة: يحتوي على Sodium Laureth Sulfate (SLES) وهو فعّال في التنظيف، لكنه قد يسرّع بهتان الصبغة أو لا يناسب الشعر شديد الحساسية/المعالَج. طريقة الاستخدام: يوضع على شعر مبلل مع تدليك لطيف ثم يُشطف جيداً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:38:48',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(77,'شامپۆی تایبەت بە پاراستن و بەهێزکردنی قژ لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,15000,2500,1,'زانیارییە سەرەکییەکان:\r\n• ناوی بەرهەم: Tango Hair Care - Multi-Force (Strength & Shine).\r\n• جۆری قژ: بۆ هەموو جۆرە قژێک گونجاوە (All Hair Types).\r\n• پێکهاتە سەرەکییەکان: پانتینۆڵ (Panthenol) و پرۆتینی گەنم (Wheat Proteins).\r\nسوودەکانی ئەم شامپۆیە:\r\n1. بەهێزکردن: بەهۆی هەبوونی پرۆتینی گەنم، یارمەتی بەهێزکردنی تاڵەکانی قژ دەدات و لە شکان دەیانپارێزێت.\r\n2. درەوشانەوە (Shine): وەک لەسەری نووسراوە \"Daily Radiance\"، یارمەتی قژ دەدات کە شێوەیەکی درەوشاوە و تەندروستی هەبێت.\r\n3. شێدارکردن: پانتینۆڵ بەوە ناسراوە کە شێدارییەکی قووڵ بە قژ دەبەخشێت و ناهێڵێت وشک ببێتەوە.\r\n4. پاککردنەوە: بە شێوەیەکی کاریگەر قژ لە چەوری و تەپوتۆز پاک دەکاتەوە بەبێ ئەوەی زیانی پێ بگەیەنێت.\r\nچۆنیەتی بەکارهێنان:\r\nبڕێکی گونجاو بدە لە قژی تەڕ، بە هێواشی مەساجی پێ بکە تا کەف دەکات، پاشان بە باشی بە ئاو بێشۆ.\r\nتێبینییەکی گرنگ:\r\nئەم شامپۆیە ماددەی Sodium Laureth Sulfate (SLES) تێدایە ئەگەر قژت زۆر وشکە یان کراتین و پرۆتینت بۆ کردووە، باشترە ئاگاداری بەکارهێنانی بیت چونکە ڕەنگە ببێتە هۆی زووتر نەمانی کاریگەری کراتینەکە.\r\n','Strength and shine shampoo suitable for all hair types. Formulated with Panthenol for deep hydration and Wheat Proteins to strengthen strands and reduce breakage. Promotes daily radiance and helps cleanse hair from oil and buildup without excessive harshness. Note: contains SLES (Sodium Laureth Sulfate); if your hair is very dry or has keratin/protein treatments, use with awareness as it may reduce treatment longevity. How to use: apply to wet hair, massage to lather, then rinse well.','شامبو لتقوية ولمعان الشعر مناسب لجميع أنواع الشعر. يحتوي على بانثينول للترطيب العميق وبروتينات القمح لتقوية الخصلات وتقليل التكسر. يمنح لمعاناً يومياً ويساعد على تنظيف الشعر من الدهون والترسبات دون قسوة زائدة. ملاحظة: يحتوي على SLES (Sodium Laureth Sulfate)؛ إذا كان شعرك شديد الجفاف أو خضع لعلاجات كيراتين/بروتين فقد يؤثر على مدة بقاء العلاج. طريقة الاستخدام: يوضع على شعر مبلل ويُدلّك حتى تتكون رغوة ثم يُشطف جيداً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:41:16',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(78,'سیڕۆمی تایبەت بە چارەسەرکردنی پەڵەی پێست و یەک ڕەنگ کردنەوەی پێستی دەم و چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,26000,35000,4500,1,'پێکهاتە سەرەکییەکانی:\r\n• Tranexamic Acid: یارمەتی کەمکردنەوەی بەرهەمهێنانی میلانین دەدات (کە بەرپرسە لە دروستبوونی پەڵە).\r\n• Alpha-Arbutin & Vitamin C: کاردەکەن بۆ سپیکردنەوە و ڕووناککردنەوەی پێست.\r\n• AHA (Alpha-Hydroxy Acids): ترشی میوەن کە یارمەتی پاککردنەوە و لێکردنەوەی خانە مردووەکانی پێست دەدەن بە شێوەیەکی نەرم.\r\n• Vitis Vinifera (Grape) Seed Extract: دژە ئۆکسانێکی بەهێزە و پێست لە کاریگەرییە خراپەکانی دەوروبەر دەپارێزێت.\r\nسوودەکانی:\r\n• چارەسەرکردنی پەڵەی قاوەیی و ئەو پەڵانەی بەهۆی تیشکی خۆرەوە دروستبوون.\r\n• کاریگەرە بۆ ئەو پەڵانەی دوای سکپڕی یان بەهۆی بەکارهێنانی دەرمانی ڕێگری لە سکپڕی دروست دەبن.\r\n• یەکخستنی ڕەنگی پێست و پێدانی درەوشانەوە بە دەموچاو.\r\nشێوازی بەکارهێنان:\r\n1. کەی بەکاردێت: باشتر وایە شەوان بەکاربێت دوای ئەوەی دەموچاوت بە باشی پاک دەکەیتەوە و پێش ئەوەی کرێمی شێدارکەرەوە (moisturizer) لێ بدەیت.\r\n2. لەکوێ لێی بدەیت: دەتوانیت تەنها لەو شوێنانەی لێ بدەیت کە پەڵەیان تێدایە، یان بە هەموو دەموچاو، مل و سنگدا بڵاوی بکەیتەوە.\r\n3. ئاگاداری: لە دەوروبەری چاوەکانی مەدە.\r\n4. خۆرەتاو: ئەگەر ڕۆژانە بەکاری دەهێنیت، زۆر گرنگە کە دژەخۆر بەکاربهێنیت، چونکە ئەم سیرومە پێست هەستیار دەکات بەرامبەر تیشکی خۆر.','Anti-spot serum for face and eyes to brighten and even skin tone. Key actives: Tranexamic Acid helps reduce melanin production (spot formation), Alpha-Arbutin and Vitamin C help brighten and fade discoloration, AHAs provide gentle exfoliation to remove dead cells, and Grape Seed extract provides strong antioxidant protection. Helps reduce brown spots (including sun spots and post-inflammatory marks) and improves radiance. Best used at night after cleansing and before moisturizer. Avoid the eye contour. Sunscreen is essential during the day while using brightening acids.','سيروم مضاد للبقع للوجه ومنطقة العين لتفتيح البشرة وتوحيد اللون. المكوّنات الفعّالة: حمض الترانيكساميك للمساعدة في تقليل إنتاج الميلانين (المسبب للبقع)، وألفا-أربوتين مع فيتامين C للتفتيح وتقليل التصبغات، وAHA لتقشير لطيف وإزالة الخلايا الميتة، ومستخلص بذور العنب كمضاد أكسدة قوي. يساعد على تقليل البقع البنية (بما فيها بقع الشمس وآثار الالتهاب) وتحسين الإشراقة. يُفضّل استخدامه ليلاً بعد التنظيف وقبل المرطب، مع تجنب محيط العين. واقي الشمس ضروري نهاراً أثناء استخدام أحماض التفتيح.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:44:12',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(79,'جێڵی تایبەت بە چارەسەرکردنی پەڵەی دەم و چاو و ڕونکردنەوەی لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'. بەکارهێنانی سەرەکی:\r\n• لابردنی پەڵە: کاردەکات بۆ کاڵکردنەوە و لابردنی پەڵە قاوەییەکان، پەڵەی دوای دووگیانی، پەڵەی تەمەن و ئەو پەڵانەی بەهۆی تیشکی خۆرەوە دروست دەبن.\r\n• یەکخستنی ڕەنگی پێست: یارمەتیدەرە بۆ ئەوەی پێستەکە یەک ڕەنگ و گەشاوە بێت (Brightness & Chromatic Homogeneity).\r\n• بۆ کوێ گونجاوە؟ دەکرێت بۆ دەموچاو، دەستەکان و جەستە بەکاربهێنرێت.\r\n٢. پێکهاتە گرنگەکانی:\r\nئەم جێڵە لە سێ ماددەی سەرەکی پێکهاتووە کە پێکەوە کاردەکەن:\r\n• ڤیتامین C (ستەبیڵایز کراو): بۆ ڕێگریکردن لە دروستبوونی میلانین (ئەو ماددەیەی ڕەنگی پێست تۆخ دەکات) و گەشانەوەی پێست.\r\n• Alpha-Arbutin: یەکێکە لە بەهێزترین ماددە سروشتییەکان بۆ سپیکردنەوە و لابردنی پەڵە بەبێ ئەوەی زیان بە پێست بگەیەنێت.\r\n• AHA (Alpha-Hydroxy Acids): ترشە جیاوازەکانی میوەن کە کاردەکەن وەک تەقشیر (Peeling). خانە مردووەکانی سەر پێست لادەبەن و یارمەتی پێکهاتەکانی تر دەدەن باشتر بچنە ناو پێستەوە.\r\n٣. زانیارییە گرنگەکان:\r\n• سیستەمی Airless: پاکەتەکەی بە شێوازێک دروستکراوە کە هەوا ناچێتە ناو جێڵەکە، ئەمەش وادەکات ڤیتامین C و پێکهاتەکانی تری تێک نەچن و بۆ ماوەیەکی زۆر بە چالاکی بمێننەوە.\r\n⚠️ تێبینی زۆر گرنگ بۆ بەکارهێنان:\r\n١. دژەخۆر: چونکە ئەم بەرهەمە ماددەی (AHA) یان ترشی تێدایە، پێستت هەستیار دەکات بەرامبەر تیشکی خۆر. زۆر گرنگە لە کاتی بەکارهێنانی ئەم جێڵەدا، لە ڕۆژدا دژەخۆر بەکاربهێنیت.\r\n٢. بەکارهێنان: بەزۆری شەوان تەنها لەسەر شوێنی پەڵەکان دادەنرێت\r\n','Brightening treatment gel for spots and uneven tone on face, hands, and body. Helps fade brown spots, melasma, age spots, and post-acne marks, and supports a more even, radiant complexion. Key ingredients: stabilized Vitamin C to help reduce melanin formation and brighten, Alpha-Arbutin for strong yet gentle spot-fading support, and AHAs for mild peeling to remove dead cells and enhance absorption. Airless packaging helps protect active ingredients. Important: because it contains AHAs, skin becomes more sun-sensitive—use sunscreen during the day. Best used at night and applied mainly on the spots.','جل علاجي للتفتيح وإزالة البقع وعدم تجانس اللون للوجه واليدين والجسم. يساعد على تخفيف البقع البنية والكلف وبقع العمر وآثار الحبوب، ويدعم توحيد اللون وزيادة الإشراقة. المكوّنات الأساسية: فيتامين C مُثبت لتقليل تكوّن الميلانين وتفتيح البشرة، وألفا-أربوتين لدعم قوي ولطيف لتخفيف البقع، وAHA لتقشير خفيف وإزالة الخلايا الميتة وتحسين امتصاص المكوّنات. عبوة Airless تحمي المواد الفعالة. مهم: لاحتوائه على AHA تصبح البشرة أكثر حساسية للشمس—استخدم واقي شمس نهاراً. يُفضّل استخدامه ليلاً ووضعه أساساً على أماكن البقع.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:48:36',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(80,'کرێمی تایبەت بە سپیکردنەوە و نەهێشتنی پەڵەی دەم و چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'. کار و سوودەکانی:\r\n• دژە پەڵە: کاردەکات بۆ کاڵکردنەوەی پەڵە قاوەییەکان، کلف (پەڵەی دووگیانی)، و فەرتەنە (کۆپانە).\r\n• سپیکردنەوە: یارمەتی یەکخستنی ڕەنگی پێست و گەشاوەکردنەوەی دەدات.\r\n• دژە پیربوون: بەهۆی هەبوونی ڤیتامین C وەک دژە ئۆکسان کاردەکات و پێست لە نیشانەکانی پیربوون (وەک چرچی) دەپارێزێت.\r\n• پاراستن لە خۆر: خاوەنی SPF 15 یە، واتە پێست دەپارێزێت لە تیشکی زیانبەخشی خۆر کە هۆکاری سەرەکی دروستبوونی پەڵەن.\r\n٢. پێکهاتە سەرەکییەکان:\r\n• ڤیتامین C: بۆ گەشاوەکردنەوە و پاراستنی پێست.\r\n• α-Arbutin (ئەلفا ئاربوتین): ماددەیەکی کاریگەرە بۆ ڕێگریکردن لە دروستبوونی میلانین و کاڵکردنەوەی پەڵەکان.\r\n• فلتەری UVA/UVB: بۆ پاراستن لە خۆر.\r\n٣. شێوازی بەکارهێنان:\r\nبڕێکی کەم لە کرێمەکە بدە لە دەموچاو یان مل لە کاتی بەیانیاندا.\r\n• ئاگاداربە بەر چاوەکانت نەکەوێت.\r\n٤. تێبینی گرنگ:\r\n• سیستەمی \"Airless\"ی هەیە کە ڕێگە نادات هەوا بچێتە ناو کرێمەکە، ئەمەش یارمەتی مانەوەی کوالێتییەکەی دەدات بۆ ماوەیەکی درێژتر.\r\n','Brightening and anti-spot cream for face and neck with SPF 15. Helps fade brown spots, melasma, and freckles and supports a more even tone. With Vitamin C for antioxidant and brightening benefits, Alpha-Arbutin to help inhibit melanin and reduce spots, plus UVA/UVB filters for daily sun protection. Apply a small amount in the morning to face/neck, avoiding the eye area. Airless packaging helps preserve formula stability.','كريم تفتيح ومضاد للبقع للوجه والرقبة مع حماية SPF 15. يساعد على تقليل البقع البنية والكلف والنمش ويدعم توحيد اللون. يحتوي على فيتامين C للتفتيح ومضادات الأكسدة، وألفا-أربوتين للمساعدة في تقليل الميلانين وتخفيف التصبغات، مع فلاتر UVA/UVB للحماية اليومية من الشمس. طريقة الاستخدام: توضع كمية قليلة صباحاً على الوجه/الرقبة مع تجنب محيط العين. عبوة Airless تساعد على ثبات التركيبة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:50:44',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(81,'کرێمی تایبەت بە چاودێری کردنی پێستی دەوروبەری چاو لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,24000,32000,4000,1,'. سوودە سەرەکییەکانی (بۆ چی بەکاردێت؟)\r\n• دژە چرچولۆچی: کاردەکات بۆ کەمکردنەوەی هێڵە وردەکان و چرچی دەوروبەری چاو.\r\n• توندکردنەوە (Lifting): وەک لە ناوەکەیدا دیارە، یارمەتی بەرزکردنەوە و توندکردنەوەی پێستی شۆڕبووەوەی چاو دەدات.\r\n• نەهێشتنی پف و ڕەشی: کاردەکات بۆ کەمکردنەوەی ئاوساوی ژێر چاو (Puffiness) و سپیکردنەوەی تیرە ڕەشەکانی دەوری چاو.\r\n٢. پێکهاتە گرنگەکانی\r\n• Edelweiss Cell culture: خانەی ڕووەکییە کە یارمەتی توندکردنەوەی بەستەرە شانەکانی پێست دەدات.\r\n• Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵ و پڕکردنەوەی هێڵەکان.\r\n• پێپتاید و فلاڤۆنۆیدەکان: بۆ باشترکردنی سووڕی خوێن لە دەوری چاو و نەهێشتنی ڕەشی.\r\n٣. چۆنیەتی بەکارهێنان:\r\n1. بڕێکی کەم لە کرێمەکە بدە لە پێستی دەوروبەری چاوت (پێویستە پێستەکە پاک بێت).\r\n2. خاڵی گرنگ: دوای لێدانی، بۆ ماوەی ٥ خولەک هەوڵبدە ماسولکەکانی دەموچاوت نەجووڵێنیت (پێمەکەنه یان دۆموچاوت گرژ مەکە) بۆ ئەوەی کرێمەکە کارلێکی خۆی بکات.\r\n3. بۆ باشترین ئەنجام، تا ٥ خولەکەکە تەواو نەبێت هیچ ماکیاژێک یان تۆزێک (پاودەر) بەکارمەهێنە.\r\n٤. زانیاری زیاتر\r\n• سیستەمی Airless: تیوبەکەی بە جۆرێک دروستکراوە کە هەوا ناچێتە ناوی، ئەمەش وادەکات کرێمەکە تێکنەچێت و تا کۆتا دڵۆپ بە پاکی بمێنێتەوە.','Eye-area care cream to reduce wrinkles, support lifting, and improve dark circles and puffiness. Key ingredients: Edelweiss cell culture to support firmness, Hyaluronic Acid to hydrate and plump, plus peptides and flavonoids to support microcirculation and brighten the under-eye area. How to use: apply a small amount to clean skin around the eyes. Important tip (as provided): after application, try not to move facial muscles around the eyes for about 5 minutes; avoid makeup/powder until it absorbs. Airless packaging helps protect the formula.','كريم عناية بمنطقة العين لتقليل التجاعيد ودعم الشد وتحسين الهالات والانتفاخ. من المكوّنات المهمة: خلايا نبات الإيدلويس (Edelweiss Cell Culture) لدعم التماسك، وحمض الهيالورونيك للترطيب والامتلاء، مع ببتيدات وفلافونويدات لدعم الدورة الدموية الدقيقة وتفتيح منطقة تحت العين. طريقة الاستخدام: توضع كمية قليلة على بشرة نظيفة حول العين. ملاحظة مهمة (حسب الإرشاد): بعد الاستخدام حاول عدم تحريك عضلات الوجه حول العين لمدة نحو 5 دقائق، وتجنب المكياج/البودرة حتى يتم الامتصاص. عبوة Airless تساعد على حماية التركيبة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:53:51',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(82,'کرێمی تایبەت بە توندکردنەوە و دژە پیربوونی پێست ئەڵتڕا لیفت ڕیچ لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,25000,35000,5000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• جۆری پێست: تایبەتە بەو پێستانەی کە وشکن (Dry) یان ماندوو و بێ هێزن (Fatigue Skins).\r\n• کاتی بەکارهێنان: بۆ هەردوو کاتی بەیانیان و شەوان دەبێت.\r\n• کاریگەرییەکان:\r\n• توندکردنەوە (Lifting): یارمەتی توندکردنەوەی پێستی دەموچاو و مل دەدات.\r\n• دژە چرچولۆچ: کار دەکات بۆ کەمکردنەوەی هێڵە وردەکان و چرچییە قووڵەکان.\r\n• شێدارکردن: بەهۆی ئەوەی جۆری \"Rich\"ـە، شێدارییەکی زۆر بە پێست دەبەخشێت.\r\nپێکهاتە گرنگەکان:\r\n1. Edelweiss Cell Culture: خانەی ڕووەکییە کە یارمەتی پاراستنی پێست و ڕێگری لە پیربوون دەدات.\r\n2. SUBERIN: پێکهاتەیەکی سروشتییە کە یارمەتی توندکردنەوەی خێرای پێست دەدات.\r\n3. X-PRESSIN: ئەنزیمێکە کە پێست ساف دەکات و دیمەنێکی گەنجانەی پێ دەبەخشێت.\r\n4. Hyaluronic Acid: ترشێکی ناسراوە بۆ شێدارکردنەوەی قووڵ و پڕکردنەوەی هێڵەکانی پێست.\r\nچۆنێتی بەکارهێنان:\r\n• پێستت بە باشی پاک بکەرەوە و وشکی بکەرەوە.\r\n• بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاو، مل و بەشی سەرەوەی سنگ (décolleté).\r\n• دوای لێدانی، پێویستە ١٠ خولەک بوەستیت پێش ئەوەی مکیاژ یان دژەخۆر بەکاربهێنیت بۆ ئەوەی پێستەکە بەتەواوی هەڵیبمژێت.\r\nزانیاری زیاتر:\r\n• سیستەمی Airless: پاکەتەکەی بە شێوازێک دروستکراوە کە هەوا ناچێتە ناو کرێمەکە، ئەمەش وادەکات کرێمەکە بۆ ماوەیەکی درێژتر بە باشی بمێنێتەوە و تووشی ئۆکسان نەبێت.\r\n','Ultra Lift Rich cream for dry or tired (fatigued) skin. Helps provide lifting/firming support, reduces the look of fine lines and deeper wrinkles, and delivers rich hydration. Key ingredients: Edelweiss cell culture for protective and anti-aging support, SUBERIN for firming effect, X-PRESSIN to smooth and brighten the skin surface, and Hyaluronic Acid for deep moisture. How to use: apply to clean, dry skin on face, neck, and upper chest; wait about 10 minutes before applying sunscreen or makeup so it absorbs fully. Airless packaging helps preserve stability.','كريم ألترا لِفت ريتش للبشرة الجافة أو المتعبة (فاقدة الحيوية). يساعد على دعم الشدّ والتماسك، تقليل مظهر الخطوط الدقيقة والتجاعيد العميقة، ويمنح ترطيباً غنياً. المكوّنات الأساسية: خلايا الإيدلويس لدعم الحماية ومكافحة علامات التقدم، وSUBERIN لتأثير شدّ، وX-PRESSIN لتنعيم سطح البشرة ومنح مظهر أكثر إشراقاً، وحمض الهيالورونيك للترطيب العميق. طريقة الاستخدام: يوضع على بشرة نظيفة وجافة للوجه والرقبة وأعلى الصدر، ويُفضّل الانتظار حوالي 10 دقائق قبل وضع واقي الشمس أو المكياج حتى يمتص بالكامل. عبوة Airless تساعد على ثبات المكوّنات.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:56:05',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(83,'کرێمی لابردنی پەڵە و سپیکردنەوەی پێستی دەست لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,19000,25000,3000,1,'زانیارییە سەرەکییەکان:\r\n• بەکارهێنانی سەرەکی: لابردنی پەڵە قاوەییەکان (Brown Spots) و یەکسانکردنەوەی ڕەنگی پێستی دەست.\r\n• پاراستن لە خۆر: خاوەنی SPF 15 یە، واتە دەستەکانت لە تیشکی زیانبەخشی خۆر دەپارێزێت کە هۆکاری سەرەکی دروستبوونی پەڵەن.\r\nپێکهاتە گرنگەکانی:\r\n1. Alpha-Arbutin: پێکهاتەیەکی زۆر کارایە بۆ سپیکردنەوەی پێست و ڕێگری لە دروستبوونی میلانین (پەڵە) دەکات.\r\n2. Rumex Extract: ڕووەکێکە یارمەتی کەمکردنەوەی ڕەنگی پەڵەکان دەدات.\r\n3. Shea Butter: بۆ نەرمکردنەوە و قووڵ شێدارکردنی پێست.\r\n4. Panthenol (Vitamin B5) و Vitamin E: بۆ نۆژەنکردنەوەی خانەکانی پێست و پاراستنیان وەک دژە ئۆکسان.\r\nسوودەکانی:\r\n• پەڵە قاوەییەکانی سەر دەست کە بەهۆی تەمەن یان خۆرەوە دروست بوون کەم دەکاتەوە.\r\n• پێستی دەست شێدار و نەرم دەکات.\r\n• بەهۆی دژە خۆرەکەیەوە، نایەڵێت پەڵەی نوێ دروست بێت.\r\nچۆنێتی بەکارهێنان:\r\n• بڕێکی گونجاو لە کرێمەکە بدە لە دەستەکانت و بە هێواشی مەساجی پێ بکە تا هەڵدەمژرێت.\r\n• باشتر وایە ڕۆژانە ٢ بۆ ٣ جار بەکاربێت (بەتایبەت پێش چوونە بەر خۆر).','Hand cream for spot reduction and tone evening, with SPF 15 to help protect hands from sun-related dark spots. Key ingredients: Alpha-Arbutin to help reduce melanin and fade spots, Rumex extract to support brightening, Shea Butter for deep softness and moisture, plus Panthenol (B5) and Vitamin E for repair and antioxidant care. Benefits: reduces brown spots from age/sun, hydrates and softens hands, and helps prevent new spots with sun protection. How to use: massage an appropriate amount into hands 2–3 times daily, especially before sun exposure.','كريم لليدين لتقليل البقع وتوحيد اللون مع حماية SPF 15 للمساعدة في حماية اليدين من البقع الناتجة عن الشمس. المكوّنات الأساسية: ألفا-أربوتين لتقليل الميلانين وتخفيف التصبغات، ومستخلص Rumex لدعم التفتيح، وزبدة الشيا للنعومة والترطيب العميق، مع بانثينول (B5) وفيتامين E للإصلاح ومضادات الأكسدة. الفوائد: تقليل البقع البنية الناتجة عن العمر/الشمس، ترطيب وتنعيم اليدين، والمساعدة على منع ظهور بقع جديدة بفضل الحماية الشمسية. طريقة الاستخدام: تُدلّك كمية مناسبة على اليدين 2–3 مرات يومياً خصوصاً قبل التعرض للشمس.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 04:59:31',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(84,'کرێمی شێدارکەرەوەی پێست مۆیست ریچ هایالۆرۆنیک لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'تایبەتمەندییە سەرەکییەکانی:\r\n• تەکنەلۆژیای خانەی قەدی (Stem Cell Technology): یارمەتی نوێکردنەوەی خانەکانی پێست دەدات و پارێزگاری لە گەنجێتی پێست دەکات.\r\n• شێدارکەرەوەی قووڵ:  \"Ultra Moisturizing\"، بۆیە بۆ ئەو کەسانە زۆر باشە کە پێستیان وشک بووەتەوە یان نیشانەکانی پیربوونی پێستیان لێ دەرکەوتووە.\r\n• پێکهاتەی دەوڵەمەند: تێکەڵەیەکی تێدایە لە (ترشی هایلۆرۆنیک، زەیتی ئەرگان، سیرامید، ڤیتامین E).\r\n• دژە پیربوون (Anti-ageing): کاردەکات بۆ کەمکردنەوەی چرچولۆچی و هێڵە وردەکانی دەموچاو.\r\nچۆنیەتی بەکارهێنان:\r\n• دەتوانیت بۆ دەموچاو، دەوروبەری چاو، و مل بەکاری بهێنیت.\r\n• تەنها بۆ بەکارهێنانی دەرەکییە.\r\nزانیاری زیاتر:\r\n• سیستەمی Airless: پاکەتەکەی بە جۆرێک دروستکراوە کە هەوا ناچێتە ناوی، ئەمەش وادەکات کرێمەکە بۆ ماوەیەکی درێژتر بە باشی بمێنێتەوە و تووشی ئۆکسان و پیسبوون نەبێت.','Moist Rich Hyaluronic moisturizer with stem-cell technology to support skin renewal and youthful look. Provides deep “ultra” hydration—ideal for dry skin or visible aging signs. Rich formula with Hyaluronic Acid, Argan oil, Ceramides, and Vitamin E to moisturize, strengthen the skin barrier, and help reduce the appearance of wrinkles and fine lines. Suitable for face, eye area, and neck. For external use only. Airless packaging helps protect the formula from oxidation and contamination.','مرطب مويست ريتش هايالرونيك مع تقنية الخلايا الجذعية لدعم تجدد البشرة والحفاظ على مظهر أكثر شباباً. يمنح ترطيباً عميقاً (Ultra Moisturizing) ومناسب جداً للبشرة الجافة أو عند ظهور علامات التقدم. تركيبة غنية تحتوي على حمض الهيالورونيك وزيت الأرغان وسيراميدات وفيتامين E لترطيب البشرة وتقوية الحاجز والمساعدة على تقليل مظهر التجاعيد والخطوط الدقيقة. مناسب للوجه ومنطقة العين والرقبة. للاستعمال الخارجي فقط. عبوة Airless تساعد على حماية التركيبة من الأكسدة والتلوث.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:04:13',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(85,'کرێمی چارەسەرکردنی نیشانەکانی پیربوون و شێدارکردنەوەی پێست هایالۆرۆنیک و ڤایتامین سی لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'• Hyaluronic Acid (بڕی مایکرۆ): یارمەتی شێدارکردنەوەی قووڵی پێست دەدات و بۆشایی نێوان خانەکان پڕ دەکاتەوە، کە ئەمەش چرچییەکان کەمدەکاتەوە.\r\n• Vitamin C (جێگیرکراو): وەک دژە ئۆکسانێکی بەهێز کاردەکات، ڕەنگی پێست ڕوون دەکاتەوە و هانی دروستبوونی کۆلاجین دەدات.\r\n• Bioactive Peptides: ئەم پێکهاتەیە کاریگەرییەکی هاوشێوەی (بۆتۆکس)ی هەیە بۆ خاوکردنەوەی گرژبوونی ماسولکەکانی دەموچاو و کەمکردنەوەی هێڵە وردەکان.\r\nسوودە گرنگەکانی بەرهەمەکە:\r\n• دژە پیری: بەرگری لە پیربوونی پێشوەختە دەکات و هێڵە قووڵەکانی دەموچاو کەمدەکاتەوە.\r\n• توندکردنەوە: یارمەتی توندکردنەوەی پێست و زیادکردنی نەرمییەکەی دەدات.\r\n• پاراستن: خاوەنی فلتەری پاراستنە لە تیشکی خۆر (SPF 10) کە پێست لە تیشکی UVA دەپارێزێت.\r\n• دواتر بەکارهێنان: زۆر گونجاوە بۆ بەکارهێنان دوای پڕۆسە جوانکارییەکانی وەک (لێزەر، بۆتۆکس، یان دەرزی هیالۆرۆنیک) بۆ پاراستنی ئەنجامەکان.\r\n• بۆنی خۆش و هەستی سوک: چەور نییە و زوو بە پێستدا دەچێت، دەکرێت وەک بنکەیەک (Base) بۆ ماکیاژیش بەکاربێت.\r\nتێبینییەکان:\r\n• سیستەمی Airless: پاکەتەکەی بە شێوەیەکە کە ڕێگە نادات هەوا بچێتە ناو کرێمەکە، ئەمەش کوالێتی ڤیتامین C و پێکهاتەکانی دیکە بۆ ماوەیەکی درێژ دەپارێزێت.\r\n\r\n','Hyaluronic + Vitamin C face cream for hydration and anti-aging care. Micro hyaluronic acid helps deeply hydrate, plump the skin, and reduce the look of lines. Stabilized Vitamin C provides antioxidant protection, brightens tone, and supports collagen production. Includes bioactive peptides with a “botox-like” smoothing effect on expression lines. Also provides sun filter protection (SPF 10) for UVA protection. Suitable after aesthetic procedures (laser, botox, hyaluronic fillers) to support results. Lightweight, non-greasy feel and can be used as a makeup base. Airless packaging helps preserve active ingredients.','كريم للوجه بحمض الهيالورونيك وفيتامين C للترطيب والعناية المضادة لعلامات التقدم. حمض الهيالورونيك (بحجم ميكرو) يساعد على ترطيب عميق وملء الفراغات بين الخلايا لتقليل مظهر الخطوط. فيتامين C مُثبت يمنح حماية مضادة للأكسدة ويفتح اللون ويدعم إنتاج الكولاجين. يحتوي على ببتيدات حيوية بتأثير “شبيه بالبوتوكس” للمساعدة على تنعيم خطوط التعبير. يوفر أيضاً حماية بفلتر شمسي (SPF 10) ضد أشعة UVA. مناسب بعد الإجراءات التجميلية مثل الليزر/البوتوكس/الفيلر لدعم النتائج. قوام خفيف غير دهني ويمكن استخدامه كقاعدة للمكياج. عبوة Airless تساعد على حفظ المكوّنات الفعالة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:06:10',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(86,'سیڕۆمی چڕی چاودێری کردنی پێستی هایالۆرانیک ڤایتامین سی بووستەر لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,27000,36000,4500,1,'. پێکهاتە سەرەکییەکانی:\r\n• ڤیتامین C (3-O-Ethyl Ascorbic Acid): جۆرێکی جێگیری ڤیتامین Cیە کە یارمەتی ڕوونکردنەوەی پێست دەدات، پەڵە کەم دەکاتەوە و هانی دروستبوونی کۆلاجین دەدات.\r\n• Hyaluronic Acid (ترشی هیالۆرۆنیک): بۆ شێدارکردنەوەی قووڵی پێست و پڕکردنەوەی هێڵە وردەکانی دەموچاو.\r\n• Cellynkage (پێکهاتەی دەریایی): ئەمە پێکهاتەیەکی تایبەتە کە پەیوەندی نێوان خانەکانی پێست باشتر دەکات، بە تایبەت بۆ ئەو پێستانەی بەهۆی تەمەنەوە (یان قۆناغی وەستانی سوڕی مانگانە) تووشی شلبوونەوە بوون.\r\n• Black Tea Ferment (تخوێبوی چای ڕەش): کاردەکات بۆ پێدانی قەبارە بەو شوێنانەی پێست کە چاڵ بوون یان چەورییان لەدەستداوە (Lipo-filling effect).\r\n٢. سوودەکانی ئەم سێرمە:\r\n• دژە پیربوون: چارەسەری چرچی و هێڵە قووڵەکان دەکات.\r\n• توندی پێست: ڕێگری لە شلبوونەوەی پێست دەکات و توندی پێ دەبەخشێت.\r\n• ڕەونەق و درەوشانەوە: پێست گەشاوە دەکات و ڕەنگی یەکدەخات (بۆ ئەو کەسانەی پێستیان ماندوو یان لێڵ دیارە).\r\n• پاراستن: بەهۆی هەبوونی دژە ئۆکسانەکان، پێست لە کاریگەرییە خراپەکانی ژینگە دەپارێزێت.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• پێویستە لەسەر پێستی پاک و وشک بەکاربهێنرێت.\r\n• چەند دڵۆپێکی لێ دەدەیت لە دەموچاو و ملت پێش ئەوەی کرێمی شێدارکەرەوە (Moisturizer) بەکاربهێنیت.\r\n• ڕۆژی دوو جار (بەیانیان و شەوان) دەتوانرێت بەکاربهێنرێت.\r\n٤. تێبینی گرنگ:\r\n• تەکنەلۆژیای Airless: قوتووەکەی بە جۆرێک دروستکراوە کە هەوا ناچێتە ناوی، ئەمەش وادەکات ڤیتامین C یەکەی تێک نەچێت و بۆ ماوەیەکی درێژ بە کارایی بمێنێتەوە.\r\n• بۆ کێ گونجاوە؟ زیاتر بۆ ئەو کەسانەی نیشانەکانی پیربوون، چرچی، یان پەڵەی تەمەنیان لێ دەرکەوتووە.','Concentrated hyaluronic + vitamin C booster serum. Key actives: 3-O-Ethyl Ascorbic Acid (a stable Vitamin C derivative) to brighten, reduce spots, and support collagen; Hyaluronic Acid for deep hydration and line-plumping; a marine complex (Cellynkage) to improve cell connections and support firmness, especially for skin affected by aging/hormonal changes; and Black Tea ferment for a “lipo-filling” effect to improve the look of hollow areas. Benefits: anti-aging support, improved firmness, brighter tone, and protection against environmental stress. How to use: apply a few drops to clean, dry face and neck before moisturizer, morning and night. Airless packaging helps protect Vitamin C stability.','سيروم بوستر مركز بحمض الهيالورونيك وفيتامين C. المكوّنات الفعّالة: 3-O-Ethyl Ascorbic Acid (مشتق ثابت لفيتامين C) لتفتيح البشرة وتقليل البقع ودعم الكولاجين، وحمض الهيالورونيك للترطيب العميق وملء الخطوط، ومركّب بحري (Cellynkage) لتحسين الترابط بين الخلايا ودعم التماسك خصوصاً للبشرة المتأثرة بالتقدم بالعمر/التغيرات الهرمونية، مع مخمّر الشاي الأسود لتأثير امتلاء (Lipo-filling) يحسن مظهر المناطق الغائرة. الفوائد: دعم مضاد لعلامات التقدم، تحسين التماسك، توحيد وإشراق اللون، وحماية من الإجهادات البيئية. طريقة الاستخدام: توضع بضع قطرات على بشرة نظيفة وجافة للوجه والرقبة قبل المرطب صباحاً ومساءً. عبوة Airless تساعد على ثبات فيتامين C.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:25:16',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(87,'سیڕۆمی چڕی دژە پیربوون و چارەسەرکردنی چرچ و لۆچیەکانی پێست و گەشاوەکردنی هایالۆرانیک و ڤایتامین سی لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,27000,35000,4000,1,'پێکهاتە سەرەکییەکانی:\r\n• Hyaluronic Acid (Cross-linked): جۆرێکی پێشکەوتووی ترشی هیالۆرۆنیکە کە وەک \"فیلەر\" کاردەکات؛ یارمەتی پڕکردنەوەی دەستبەجێی هێڵەکانی دەموچاو دەدات و شێدارییەکی زۆر بە پێست دەبەخشێت.\r\n• Vitamin C (Ethyl Ascorbic Acid): جۆرێکی جێگیری ڤیتامین C یە کە یارمەتی ڕوونکردنەوەی پێست، نەهێشتنی پەڵە و هاندانی دروستبوونی کۆلاجین دەدات.\r\n• Lipofilling Agents (Black Tea Ferment & Sarsasapogenin): ماددەی تایبەتن بۆ گەڕاندنەوەی قەبارە (Volume) بۆ ئەو شوێنانەی پێست کە شۆڕ بوونەتەوە یان چاڵ بوون.\r\nسوودەکانی:\r\n1. پڕکردنەوەی چرچولۆچی: کاردەکات بۆ کەمکردنەوەی هێڵە قووڵەکانی دەموچاو و هێڵەکانی دەربڕین (وەک هێڵەکانی ناوچەوان و دەوری دەم).\r\n2. گەشاوەکردن: ڕەنگی پێست یەکدەخات و پەڵە و تەڵخی پێست کەمدەکاتەوە.\r\n3. توندکردنەوە: یارمەتی توندکردنەوەی پێست و ڕێگریکردن لە شۆڕبوونەوە دەدات.\r\n4. تەکنەلۆژیای ئاوریشمی (Silk Technology): پێکهاتەکەی زۆر سووکە و هەستی نەرمییەکی زۆر بە پێست دەبەخشێت بەبێ ئەوەی چەور بێت.\r\nچۆنیەتی بەکارهێنان:\r\nبە شێوەی Topical (خۆجێیی) بەکاردێت، واتە تەنها لەو شوێنانەی کە چرچولۆچی یان هێڵی قووڵیان تێدایە دایبنێ و بڵاوی بکەرەوە.\r\n• باشترە لەسەر پێستێکی پاک بەکاربێت.\r\n• بەهۆی سیستمە تایبەتەکەی (Airless System)، بەرهەمەکە ناچێتە بەر هەوا و بە پاکی دەمێنێتەوە.\r\nتێبینی گرنگ:\r\n• ئەم بەرهەمە تەنها بۆ بەکارهێنانی دەرەکییە.','Intensive anti-aging and brightening serum with cross-linked Hyaluronic Acid for a filler-like plumping effect and immediate smoothing of expression lines. Contains Ethyl Ascorbic Acid (stable Vitamin C) to brighten and support collagen, plus lipofilling agents (Black Tea ferment and Sarsasapogenin) to restore volume in areas that appear hollow or sagging. Lightweight silky texture, non-greasy. How to use: apply topically on clean skin, focusing on areas with deep lines (e.g., nasolabial folds, around the mouth). For external use only. Airless system helps keep the formula fresh.','سيروم مكثف مضاد لعلامات التقدم ومفتّح يحتوي على حمض هيالورونيك مترابط (Cross-linked) يمنح تأثير امتلاء شبيه بالفيلر ويساعد على تنعيم خطوط التعبير بشكل سريع. يحتوي على Ethyl Ascorbic Acid (فيتامين C ثابت) لتفتيح البشرة ودعم الكولاجين، مع عوامل لزيادة الامتلاء (مخمّر الشاي الأسود وSarsasapogenin) لإعادة الحجم للمناطق التي تبدو غائرة أو مترهلة. قوام خفيف حريري غير دهني. طريقة الاستخدام: يُوضع موضعياً على بشرة نظيفة مع التركيز على مناطق الخطوط العميقة (مثل خطوط الأنف والفم وحول الفم). للاستعمال الخارجي فقط. نظام Airless يساعد على الحفاظ على التركيبة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:27:42',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(88,'سیڕۆمی ئەڵتڕا لیفت فیلێر تایبەت بە نیشانەکانی پیربونی پێست لە بڕاندی فڕۆیکای یۆنانی',NULL,NULL,NULL,15,27000,35750,4500,1,'. مەبەست لە بەکارهێنانی (Indications)\r\nئەم بەرهەمە بە پلەی یەکەم بۆ دوو شت دروستکراوە:\r\n• چرچییە قووڵەکان: پڕکردنەوە و کەمکردنەوەی ئەو چرچییانەی کە بەهۆی تەمەنەوە دروست دەبن.\r\n• هێڵەکانی دەربڕین (Expression lines): وەک ئەو هێڵانەی لە کاتی پێکەنین یان گرژکردنی ناوچەوان دروست دەبن.\r\n٢. پێکهاتە سەرەکییەکانی\r\nئەم کرێمە چەند ماددەیەکی زۆر گرنگی تێدایە:\r\n• Cross-linked Hyaluronic Acid: ئەمە جۆرێکی پێشکەوتووی هایلۆرۆنیک ئەسیدە کە وەک \"فیلەر\" کار دەکات؛ شێدارییەکی زۆر دەدات بە پێست و یەکسەر شوێنی چرچییەکان پڕ دەکاتەوە و پێستەکە توند دەکات.\r\n• Acetyl Hexapeptide: ئەم ماددەیە بە \"جێگرەوەی تاتۆقی بوتۆکس\" دادەنرێت. یارمەتی خاوکردنەوەی ماسولکەکانی دەموچاو دەدات بۆ ئەوەی هێڵەکان قووڵتر نەبن (لە ماوەی ١٥ ڕۆژدا کاریگەرییەکەی دەردەکەوێت).\r\n• Matrikines: پڕۆتینێکی بچووکن کە یارمەتی نوێبوونەوەی پێست و زیادکردنی ئەلاستیکی (نەرمی) پێست دەدەن.\r\n• Edelweiss Stem Cells: خانەی بنەڕەتی ڕووەکین کە پارێزگاری لە پێست دەکەن و ڕێگری لە پیربوونی پێست دەکەن لەسەر ئاستی دوورمەودا.\r\n٣. چۆنیەتی بەکارهێنان (Usage Directions)\r\nبەپێی ڕێنمایی سەر کارتۆنەکە:\r\n1. شوێنی مەبەست: تەنها لەو شوێنانەی کە چرچی قووڵ یان هێڵی تێدایە بەکاری بهێنە (وەک دەوری چاو، ناوچەوان، دەوری دەم).\r\n2. شێواز: بڕێکی گونجاو دابنێ و بە هێواشی مەساجی پێ بکە تا پێستەکە هەڵی دەمژێت.\r\n٤. تایبەتمەندییە دەگمەنەکانی\r\n• تەکنەلۆژیای Airless: وەک لە وێنەکەدا دیارە، دەبەی بەرهەمەکە هەوا ناچێتە ناوی. ئەمەش وادەکات کرێمەکە تێکنەچێت، ئۆکسید نەبێت و میکرۆبی بۆ نەچێت.\r\n• Silk Touch: هەستێکی ئاوریشمی نەرم بە پێست دەبەخشێت و پێستەکە چەور ناکات.\r\n• ماوەی بەکارهێنان: دوای کردنەوەی، بۆ ماوەی ١٢ مانگ دەتوانرێت بەکاربهێنرێت.\r\n','Ultra Lift Filler serum/cream designed to target signs of skin aging, focusing on deep wrinkles and expression lines (such as lines from smiling or frowning). Key actives include Cross-linked Hyaluronic Acid for a filler-like plumping effect and immediate smoothing, Acetyl Hexapeptide (botox-like peptide) to help reduce the appearance of expression lines with results typically visible with continued use, Matrikines to support skin renewal and elasticity, and Edelweiss stem cells for protective anti-aging support. Directions: apply only to targeted areas with deep wrinkles or expression lines (around eyes, between brows, around mouth) and massage gently until absorbed. Features airless packaging to protect the formula from oxidation and contamination and a silky touch texture. Use within 12 months after opening.','سيروم/كريم Ultra Lift Filler مخصص لاستهداف علامات شيخوخة البشرة، مع التركيز على التجاعيد العميقة وخطوط التعبير (مثل خطوط الابتسامة أو العبوس). يحتوي على حمض هيالورونيك مترابط (Cross-linked) يمنح تأثير امتلاء شبيه بالفيلر مع تنعيم فوري، وببتيد أسيتيل هيكساببتيد بتأثير “شبيه بالبوتوكس” للمساعدة على تقليل مظهر خطوط التعبير مع الاستمرار، وماتريكِينات لدعم تجدد البشرة وزيادة المرونة، وخلايا جذعية من نبات الإيدلويس لدعم الحماية ومقاومة علامات التقدم. طريقة الاستخدام: يوضع فقط على المناطق المستهدفة التي تحتوي على تجاعيد عميقة أو خطوط تعبير (حول العينين، بين الحاجبين، حول الفم) مع تدليك لطيف حتى الامتصاص. يتميز بعبوة Airless لحماية التركيبة من الأكسدة والتلوث وملمس حريري. يُستخدم خلال 12 شهراً بعد الفتح.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:30:40',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(89,'سیڕۆمی چڕی تایبەت بە چارەسەکردنی کێشەکانی دەورەبەری چاو لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,27000,36500,4750,1,'. کارە سەرەکییەکانی (بۆچی بەکاردێت؟)\r\n• بەرزکردنەوەی پێڵووی چاو (Instant Upper Lid Lift): یارمەتی توندکردنەوەی ئەو پێڵووانە دەدات کە کەمێک شۆڕ بوونەتەوە.\r\n• دژە چرچی: بۆ کەمکردنەوەی چرچی دەوری چاو (چرچییەکانی ناسراو بە Crow\'s feet).\r\n• نەهێشتنی پف و ڕەشی: یارمەتی کەمکردنەوەی پفکردنی ژێر چاو و ڕەشی دەوروبەری چاو دەدات.\r\n• شێدارکردنەوە: بەهۆی هەبوونی \"هیالۆرۆنیک ئەسید\" پێستەکە بە قووڵی تەڕ و شێدار دەکاتەوە.\r\n٢. پێکهاتە گرنگەکانی\r\n• Persian Silk Tree Extract: بۆ توندکردنەوەی پێست و لابردنی نیشانەکانی ماندوێتی.\r\n• Hyaluronic Acid: بۆ پڕکردنەوەی هێڵە وردەکان و شێدارکردن بە شێوەیەکی بەهێز.\r\n• Neuropeptides: یارمەتی خاوکردنەوەی ماسولکە وردەکانی دەوری چاو دەدات بۆ ئەوەی چرچی دروست نەبێت.\r\n• Hesperidin: بۆ باشترکردنی سوڕی خوێن لە ژێر چاو، کە دەبێتە هۆی کەمبوونەوەی ڕەشی ژێر چاو.\r\n٣. تایبەتمەندی بەرهەمەکە\r\n• Airless System: قوتووەکەی بە شێوازێک دروستکراوە کە هەوای تێناچێت، ئەمەش وا دەکات بەرهەمەکە تێکنەچێت، ئۆکسید نەبێت و میکرۆبی بۆ نەچێت.• ە.\r\n• بەکارهێنان: تەنها بۆ دەرەوەی پێستە (External Use) و نابێت بچێتە ناو چاوەوە.\r\nچۆنیەتی بەکارهێنان:\r\nبەزۆری بڕێکی کەم لە سیرومەکە دەدرێت لە دەوروبەری چاو (بە تایبەت شوێنی چرچییەکان و پێڵووی سەرەوە) بە پەنجەیەک و بە هێمنی مەساجی پێدەکرێت تا هەڵی دەمژێت. باشترە ڕۆژانە دوو جار (بەیانیان و شەوان) لەسەر پێستی پاک بەکاربهێنرێت. ','Concentrated eye-area serum for common concerns around the eyes: instant upper eyelid lifting effect, reducing crow’s feet wrinkles, helping lessen under-eye puffiness and dark circles, and deeply hydrating the area. Key ingredients include Persian Silk Tree extract to improve firmness and reduce signs of fatigue, Hyaluronic Acid to plump fine lines and provide strong hydration, Neuropeptides to help relax micro-muscles and reduce expression wrinkles, and Hesperidin to support microcirculation and improve the look of under-eye darkness. Airless packaging helps protect the formula from air and contamination. For external use only; avoid getting into the eyes. How to use: apply a small amount around the eye contour (especially wrinkles and upper lid) and massage gently until absorbed; use twice daily (morning and night) on clean skin.','سيروم مركز لمنطقة حول العين لمعالجة أكثر مشاكلها شيوعاً: شد فوري للجفن العلوي، تقليل تجاعيد “أقدام الغراب”، المساعدة في تقليل انتفاخ تحت العين والهالات الداكنة، مع ترطيب عميق. من المكونات الأساسية: مستخلص شجرة الحرير الفارسية لشد البشرة وتقليل علامات التعب، حمض الهيالورونيك لملء الخطوط الدقيقة وترطيب قوي، نيوروبيبتيدات للمساعدة على إرخاء العضلات الدقيقة وتقليل خطوط التعبير، وهسبيريدين لدعم الدورة الدموية الدقيقة وتحسين مظهر الهالات. عبوة Airless تساعد على حماية التركيبة من الهواء والتلوث. للاستعمال الخارجي فقط وتجنب دخوله للعين. طريقة الاستخدام: توضع كمية قليلة حول محيط العين (خصوصاً أماكن التجاعيد والجفن العلوي) مع تدليك لطيف حتى الامتصاص، ويُستخدم مرتين يومياً صباحاً ومساءً على بشرة نظيفة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:32:55',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(90,'فۆمی پاکەرەوەی پێستی هەستیار و شێدارکەرەوەی هایالۆرۆنیک لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25000,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سەرەکی: هایالۆرۆنیک ئەسیدی تێدایە (Hyaluronic Acid) کە یارمەتی شێدارکردنەوەی پێست دەدات و ناهێڵێت دوای شتن وشک ببێتەوە.\r\n• بەکارهێنان: هەم بۆ دەموچاو و هەم بۆ جەستە دەبێت.\r\n• جۆری پێست: گونجاوە بۆ هەموو جۆرە پێستەکان، بەتایبەت ئەو پێستانەی پێویستیان بە شێدارییە یان هەستیارن.\r\n• پاککردنەوە: وەک لەسەر بوتڵەکە نووسراوە، بۆ لادانی ماکیاژیش بەکاردێت و پیسی سەر پێست بە قووڵی پاک دەکاتەوە.\r\nسوودەکانی:\r\n1. نایخورێنێت: بەهۆی ئەوەی سابوونی تێدا نییە (Soap-free)، زیان بە چینی پارێزەری پێست ناگەیەنێت.\r\n2. هێورکەرەوەیە: پێکهاتەی وەک \"Betaine\" و ڤیتامینەکانی تێدایە کە پێست ئارام دەکەنەوە.\r\n3. بەرهەمی \"Extra Pure\": واتە پارێزەر (Paraben) و ماددە کیمیاییە توندەکانی تێدا نییە، کە ئەمەش بۆ ئەو کەسانە باشە کە زوو پێستیان سوور دەبێتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو لە کەفەکە بدە لە پێستی تەڕ.\r\n• بە هێواشی مەساجی پێ بکە.\r\n• پاشان بە ئاوێکی شلەتێن بیشۆ.\r\nتێبینی: ئەگەر پێستت زۆر چەورە و زیپکەی زۆری هەیە، ڕەنگە ئەم بەرهەمە تەنها وەک شێدارکەرەوە و پاککەرەوەیەکی نەرم کار بکات، بەڵام بۆ چارەسەری زیپکە پێویستت بە بەرهەمێک دەبێت کە ترشی (Salicylic Acid) تێدا بێت.','Gentle cleansing foam for sensitive skin with hyaluronic acid to help keep skin hydrated and comfortable after washing. Suitable for face and body and can help remove makeup and deeply cleanse impurities. Soap-free formula helps protect the skin barrier. Includes soothing ingredients like betaine and vitamins to calm the skin. Labeled “Extra Pure”, free from parabens and harsh chemicals, making it suitable for easily irritated skin. How to use: apply an appropriate amount onto wet skin, massage gently, then rinse with lukewarm water. Note: if your skin is very oily and you have a lot of acne, this may work mainly as a gentle cleanser/hydrator; for acne control you may need a product containing salicylic acid.','رغوة تنظيف لطيفة للبشرة الحساسة تحتوي على حمض الهيالورونيك للمساعدة على ترطيب البشرة والحفاظ على راحتها بعد الغسل. مناسبة للوجه والجسم ويمكن أن تساعد على إزالة المكياج والتنظيف العميق للشوائب. تركيبة خالية من الصابون للمحافظة على حاجز البشرة. تحتوي على مكونات مهدئة مثل البيتين وبعض الفيتامينات لتهدئة البشرة. مصنفة “Extra Pure” وخالية من البارابين والمواد القاسية، لذلك تناسب البشرة سريعة التهيج. طريقة الاستخدام: توضع كمية مناسبة على بشرة مبللة، تُدلّك بلطف ثم تُشطف بماء فاتر. ملاحظة: إذا كانت بشرتك دهنية جداً ومعها حب شباب كثير فقد يعمل هذا المنتج كمنظف لطيف/مرطب، وللسيطرة على الحبوب قد تحتاج منتجاً يحتوي على حمض الساليسيليك.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:35:47',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(91,'لۆشنی پاکەرەوەی پێستی هایالۆرۆنیک تۆنیک لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,19000,25000,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بەرهەمێکی بێ کحوولە (Alcohol-free): ئەمە وای لێدەکات زۆر گونجاو بێت بۆ ئەو کەسانەی پێستیان هەستیارە، چونکە پێست وشک ناکاتەوە و ناخورێنێت.\r\n• پێکهاتەی سەرەکی: هایالۆرۆنیک ئەسید (Hyaluronic Acid)، جینسینگ (Ginseng)، و بایۆفلاڤۆنۆیدز (Bioflavonoids).\r\n• بۆ هەموو جۆرە پێستێک گونجاوە: دەتوانرێت بۆ پێستی وشک، چەور و تێکەڵ بەکاربهێنرێت.\r\nسوودەکانی بۆ پێست:\r\n1. شێدارکردنەوە (Moisturizing): بەهۆی هەبوونی هایالۆرۆنیک ئەسید، یارمەتی ڕاگرتنی شێ و نەرمکردنەوەی پێست دەدات.\r\n2. بەهێزکەر و گەشاوەکەر: ڕووەکی جینسینگ یارمەتی چالاککردنەوەی پێست و پێدانی گەشاوەیی دەدات.\r\n3. دژە ئۆکسان (Antioxidant): بایۆفلاڤۆنۆیدەکان پێست لە ژەهرەکان (Detoxification) و کاریگەرییە خراپەکانی دەوروبەر دەپارێزن.\r\n4. پاککردنەوەی کۆتایی: پاشماوەی ماکیاژ و پیسی کە بە شووشتنی ئاسایی لێ نابێتەوە، پاکی دەکاتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• دوای ئەوەی دەموچاوت بە سابوون یان غەسول دەشۆیت و وشکی دەکەیتەوە، بڕێک لەم لۆشنە بکە سەر پارچە لۆکەیەک.\r\n• بە هێواشی بەسەر پێستی دەموچاو و ملتدا بیهێنە.\r\n• پێویست بە شووشتنەوە ناکات و دەتوانیت دوای ئەمە کرێمی شێدارکەرەوە بەکاربهێنیت.\r\n','Hyaluronic tonic cleansing lotion (alcohol-free) suitable for sensitive skin and all skin types (dry, oily, combination). Key ingredients include Hyaluronic Acid for hydration and softness, Ginseng to energize and revitalize the skin, and Bioflavonoids for antioxidant protection and detox support against environmental stress. Helps provide final cleansing by removing remaining makeup and impurities that regular washing may miss. How to use: after washing and drying the face, apply to a cotton pad and gently wipe over face and neck. No rinsing required; follow with your moisturizer.','تونر/لوسيون تنظيف بحمض الهيالورونيك خالٍ من الكحول، مناسب للبشرة الحساسة ولكل أنواع البشرة (الجافة والدهنية والمختلطة). يحتوي على حمض الهيالورونيك للترطيب والنعومة، والجينسنغ لتنشيط البشرة ومنحها حيوية، وبيوفلافونويدات كمضادات أكسدة لدعم التنقية والحماية من تأثيرات البيئة. يساعد على التنظيف النهائي بإزالة بقايا المكياج والشوائب التي قد لا تزول بالغسل العادي. طريقة الاستخدام: بعد غسل الوجه وتجفيفه، توضع كمية على قطعة قطن ويمسح بها الوجه والرقبة بلطف. لا يحتاج إلى شطف، ثم يُتبع بمرطب.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:37:33',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(92,'لۆشنی پاکەرەوەی دەم و چاوی هایالۆرۆنیک لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,26000,3000,1,'تایبەتمەندییە سەرەکییەکانی:\r\n• پێکهاتەی سەرەکی: هایالۆرۆنیک ئەسیدی تێدایە (Hyaluronic Acid)، کە یارمەتی قوڵبوونەوەی شێداری پێست دەدات و ڕێگری دەکات لە وشکبوونەوە.\r\n• پاککردنەوەی نەرم: بە شێوەیەکی زۆر نەرم دەموچاو لە ماکیاژ، چەوری زیادە و پیسی پاک دەکاتەوە بەبێ ئەوەی زیان بە چینی پارێزەری پێست بگەیەنێت.\r\n• هاوسەنگی pH: کار دەکات بۆ پاراستنی هاوسەنگی سروشتی ترشێتی و تفتێتی پێست (pH balance).\r\n• بۆ کێ گونجاوە؟: بۆ هەموو جۆرە پێستێک گونجاوە (For all skin types).\r\nسوودەکانی:\r\n1. پێست بە نەرمی و شێداری دەهێڵێتەوە دوای پاککردنەوە.\r\n2. هەستی کشان و وشکبوونەوەی پێست ناهێڵێت.\r\n3. بۆ لادانی ماکیاژی دەموچاو و مل زۆر باشە.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو لە لۆشنەکە بدە لە دەموچاو و ملت.\r\n• بە سەری پەنجەکانت بە بازنەیی مەساژی پێ بکە.\r\n• دواتر بە پارچەیەک لۆکە (Cotton ball) پاکی بکەرەوە.\r\n• پێویست بە ششتنەوە بە ئاو ناکات (مەگەر خۆت پێت خۆش بێت دوای لۆکەکە بە ئاوێکی شلەتێن ڕوخسارت بشۆیت).\r\n','Hyaluronic cleansing lotion for face and eyes. Formulated with Hyaluronic Acid to support deep hydration and help prevent dryness. Gently removes makeup, excess oil, and impurities without damaging the skin barrier and supports the skin’s natural pH balance. Suitable for all skin types. Benefits: leaves skin soft and hydrated, reduces tightness/dry feeling after cleansing, and is especially good for removing face and neck makeup. How to use: apply an appropriate amount to face and neck, massage gently in circular motions, then wipe off with a cotton pad. No rinsing required (rinsing is optional if desired).','لوسيون تنظيف بحمض الهيالورونيك للوجه والعينين. يحتوي على حمض الهيالورونيك لدعم الترطيب العميق والمساعدة على منع الجفاف. يزيل المكياج والدهون الزائدة والشوائب بلطف دون الإضرار بحاجز البشرة، ويساعد على الحفاظ على توازن الـpH الطبيعي. مناسب لجميع أنواع البشرة. الفوائد: يترك البشرة ناعمة ورطبة، يقلل إحساس الشد والجفاف بعد التنظيف، وممتاز لإزالة مكياج الوجه والرقبة. طريقة الاستخدام: توضع كمية مناسبة على الوجه والرقبة مع تدليك دائري لطيف، ثم يُزال بقطنة. لا يحتاج إلى شطف (والشطف اختياري لمن يرغب).',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:39:44',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(93,'شامپۆی بێ سەلفایت ئۆلیڤ ئۆیل لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,15000,2500,1,'تایبەتمەندییە سەرەکییەکانی:\r\n• بێ سۆلفات (Sulfate Free): ئەمە گرنگترین خاڵە، چونکە سۆلفات ماددەیەکی پاککەرەوەی بەهێزە کە چەوری سروشتی قژ لادەبات و دەبێتە هۆی وشکبوونەوە. ئەم شامپۆیە بەهۆی نەبوونی سۆلفاتەوە بۆ ئەوانەی قژیان وشکە، یان ڕەنگیان کردووە، یان (کێراتین و پڕۆتین)یان بۆ کردووە زۆر گونجاوە.\r\n• پارێزەری کێراتین (Keratin Protection): یارمەتی پاراستنی کێراتینی سروشتی قژ دەدات و ڕێگری دەکات لە تێکچوونی تاڵەکانی قژ.\r\n• پێکهاتە دەوڵەمەندەکان:\r\n• کێراتین: بۆ بەهێزکردنی تاڵەکانی قژ.\r\n• پڕۆتینی گەنم (Wheat Proteins): بۆ چاککردنەوەی قژی زیانلێکەوتوو.\r\n• کۆلاجین (Collagen): بۆ نەرمکردنەوە و زیادکردنی قەبارەی قژ.\r\n• ڕۆنی زەیتوون (Olive Oil): بۆ شێدارکردنەوە و درەوشانەوەی قژ.\r\nسوودەکانی:\r\n• بۆ هەموو جۆرە قژێک گونجاوە (All Hair Types).\r\n• بەهۆی ئەوەی سۆلفاتی تێدا نییە، ڕەنگی قژ زوو ناشۆرێتەوە و تەمەنی ڕەنگەکە درێژ دەکاتەوە.\r\n• قژ بە نەرمی دەهێڵێتەوە و لە کێشەی \"هەڵاوسان و بژبوون\" (Frizz) دەتبپارێزێت.\r\nتێبینی: ئەگەر قژت زۆر چەور بێت، ڕەنگە پێویستت بەوە بێت دووجار لە قژت بدەیت لە کاتی شتندا، چونکە شامپۆی بێ سۆلفات کەفێکی زۆر ناکات بەراورد بە شامپۆ ئاساییەکان، بەڵام تەندروستترە.\r\n','Sulfate-free Olive Oil shampoo designed to cleanse gently while helping protect hair’s natural oils. Ideal for dry hair, colored hair, and hair treated with keratin/protein, because it helps reduce dryness and preserves treatments longer. Enriched with keratin to strengthen strands, wheat proteins to repair damaged hair, collagen to add softness and volume, and olive oil to nourish and add shine. Suitable for all hair types and helps reduce frizz. Note: sulfate-free shampoos may foam less; if your hair is very oily you may need to shampoo twice for a deeper cleanse.','شامبو زيت الزيتون الخالي من السلفات لتنظيف لطيف مع الحفاظ على الزيوت الطبيعية للشعر. مناسب جداً للشعر الجاف أو المصبوغ أو المعالج بالكيراتين/البروتين، لأنه يساعد على تقليل الجفاف والحفاظ على نتائج العلاجات لفترة أطول. غني بالكيراتين لتقوية الخصلات، وبروتينات القمح لإصلاح الشعر المتضرر، والكولاجين لزيادة النعومة والحجم، وزيت الزيتون للتغذية واللمعان. مناسب لجميع أنواع الشعر ويساعد على تقليل الهيشان. ملاحظة: الشامبو الخالي من السلفات قد يعطي رغوة أقل؛ وإذا كان شعرك دهنياً جداً فقد تحتاج لغسله مرتين لتنظيف أعمق.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:41:19',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(94,'شامپۆی بێ سەلفایت ئەرگان ئۆیل لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,15000,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بێ سەلفەیت (Sulfate Free): ئەمە گرنگترین خاڵە، چونکە سەلفەیت دەبێتە هۆی وشکبوونەوەی قژ و نەمانی چەوری سروشتی سەر. ئەم شامپۆیە زۆر نەرمە و بۆ ئەو کەسانە گونجاوە کە پێستی سەریان هەستیارە.\r\n• پارێزەری کیراتین (Keratin Protection): بە تایبەت بۆ ئەو کەسانە دروستکراوە کە قژیان \"کیراتین\" یان \"پڕۆتین\" کردووە، چونکە یارمەتی مانەوەی ماددەی کیراتینەکە دەدات بۆ ماوەیەکی درێژتر.\r\n• پێکهاتەی دەوڵەمەند: تێکەڵەیەکە لە چەند ماددەیەکی بەسوود وەک:\r\n• ڕۆنی ئەرگان (Argan Oil): بۆ نەرمکردنەوە و بریقەدارکردنی قژ.\r\n• پڕۆتینی گەنم (Wheat Proteins): بۆ بەهێزکردنی تاڵەکانی قژ.\r\n• کۆلاجین (Collagen): بۆ زیادکردنی نەرمی و لاستیکیی قژ.\r\nسوودەکانی:\r\n1. بۆ قژی وشک و تێکچوو: چارەسەری وشکی دەکات و قژە سوتاو و تێکچووەکان چاک دەکاتەوە.\r\n2. بۆ هەموو جۆرە قژێک: (All Hair Types) گونجاوە، بەڵام زیاتر بۆ قژی وشک و کیراتین کراو باشە.\r\n3. تەندروستی پێستی سەر: بەهۆی ئەوەی ماددەی کیمیایی توندی تێدا نییە، زیان بە ڕەگی قژ ناگەیەنێت.\r\nشێوازی بەکارهێنان:\r\nبڕێکی گونجاو بدە لە قژی تەڕ، بە هێواشی مەساجی پێ بکە و پاشان بە باشی بە ئاو بێشۆ.\r\n','Sulfate-free Argan Oil shampoo with a very gentle cleansing action, suitable especially for sensitive scalps. Designed to help preserve keratin/protein treatments for longer. Enriched with Argan Oil to soften and add shine, wheat proteins to strengthen hair fibers, and collagen to improve softness and elasticity. Suitable for all hair types, but particularly beneficial for dry, damaged, and keratin-treated hair. How to use: apply to wet hair, massage gently, then rinse thoroughly.','شامبو زيت الأرغان الخالي من السلفات بتنظيف لطيف جداً، مناسب خصوصاً لفروة الرأس الحساسة. مصمم للمساعدة على الحفاظ على علاجات الكيراتين/البروتين لفترة أطول. غني بزيت الأرغان للنعومة واللمعان، وبروتينات القمح لتقوية ألياف الشعر، والكولاجين لزيادة النعومة والمرونة. مناسب لكل أنواع الشعر، لكنه مفيد أكثر للشعر الجاف والمتضرر والمعالج بالكيراتين. طريقة الاستخدام: يوضع على شعر مبلل مع تدليك لطيف ثم يُشطف جيداً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:43:22',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(95,'شامپۆی قژی تایبەت بە کڕێش لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,14000,20000,3000,1,' ئەم پێکهاتانەی تێدایە:\r\n١. Piroctone Olamine: ماددەیەکی کاریگەرە بۆ لەناوبردنی ئەو بەکتریایانەی دەبنە هۆی دروستبوونی کڕێش.\r\n٢. Salicylic Acid (سایلۆسلیک ئەسید): یارمەتی پاککردنەوەی پێستی سەر دەدات و ئەو کڕێشانەی پێوەی نووساون لێیان دەکاتەوە.\r\n٣. Keratin & Wheat Protein: بۆ پاراستنی مووەکە و بەهێزکردنی، کە وادەکات قژەکە نەرم و بریقەدار بێت.\r\n٤. Green Tea Extract: تێدایە بۆ هێورکردنەوەی پێستی سەر.\r\n٥. Menthol: هەستێکی فێنک و خۆش بە پێستی سەر دەبەخشێت دوای شۆردن.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو لە شامپۆکە بدە لە قژی تەڕ.\r\n• بە هێواشی مەساجی پێستی سەری پێ بکە.\r\n• پاشان بە باشی بە ئاو بیشۆ.\r\nتێبینی:\r\nئەم شامپۆیە لە ڕووی جەڵدییەوە تاقیكراوەتەوە (Dermatologically Tested)، واتە بۆ پێستی سەر سەلامەتە،\r\n','Anti-dandruff shampoo formulated to help eliminate the microorganisms linked to dandruff and reduce scalp flaking. Contains Piroctone Olamine for anti-dandruff action, Salicylic Acid to exfoliate the scalp and lift stuck flakes, Keratin and Wheat Protein to strengthen and smooth hair, Green Tea extract to soothe the scalp, and Menthol to provide a fresh cooling sensation after washing. How to use: apply to wet hair, massage the scalp gently, then rinse well. Dermatologically tested.','شامبو مضاد للقشرة يساعد على القضاء على الميكروبات المرتبطة بالقشرة وتقليل تقشر فروة الرأس. يحتوي على Piroctone Olamine كمكوّن مضاد للقشرة، وحمض الساليسيليك لتقشير فروة الرأس وإزالة القشور المتراكمة، وكيراتين مع بروتينات القمح لتقوية الشعر وتنعيمه، ومستخلص الشاي الأخضر لتهدئة الفروة، ومنثول لإحساس منعش وبارد بعد الغسل. طريقة الاستخدام: يوضع على شعر مبلل مع تدليك لطيف لفروة الرأس ثم يُشطف جيداً. مختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:44:56',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(96,'شامپۆی ئۆیل باڵانس تایبەت بە قژی چەور لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,10000,15000,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاککردنەوەی قووڵ (Deep Cleanse): یارمەتی پاککردنەوەی پێستی سەر و مووەکان دەدات لەو چەورییە زیادەی کە دەبێتە هۆی لکانی قژ و تێکچوونی شێوەکەی.\r\n• کۆنترۆڵکردنی چەوری: بۆ \"Oilness Control\" بەکاردێت، واتە ڕێگری دەکات لەوەی قژەکە زوو بە زوو چەور ببێتەوە.\r\n• پاراستنی قژ: هەرچەندە بۆ قژی چەورە، بەڵام هەوڵ دەدات قژەکە وشک نەکاتەوە، چونکە ماددەی سوودبەخشی تێدایە بۆ ئەوەی قژەکە بە نەرمی و بریقەداری بمێنێتەوە.\r\nپێکهاتە گرنگەکان:\r\nئەم شامپۆیە چوار پێکهاتەی سەرەکی تێدایە کە کاریگەری باشیان هەیە:\r\n1. Extract Nettle (گیای گەزنە): زۆر بەناوبانگە بۆ کۆنترۆڵکردنی چەوری پێستی سەر و بەهێزکردنی ڕەگی قژ.\r\n2. Keratin (کێراتین): بۆ پاراستن و چاککردنەوەی تاڵەکانی قژ و پێدانی نەرمی.\r\n3. Wheat Proteins (پڕۆتینی گەنم): یارمەتی بەهێزکردنی قژەکە دەدات و ڕێگری لە شکانەوەی دەکات.\r\n4. Collagen (کۆلاجین): بۆ بریقەدارکردن و پێدانی قەبارە (Volume) بە قژەکە بەبێ ئەوەی قورسی بکات.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو بدە لە قژی تەڕ.\r\n• بە هێمنی مەساجی پێستی سەری پێ بکە.\r\n• پاشان بە باشی بە ئاو بێشۆ.\r\n','Oil Balance shampoo for oily hair. Helps deep-cleanse the scalp and hair from excess oil that can cause heaviness and poor style hold, while aiming to keep hair from drying out. Supports oiliness control so hair stays fresh for longer. Key ingredients include nettle extract to help regulate scalp oil and support roots, keratin to protect and repair hair fibers, wheat proteins to strengthen and reduce breakage, and collagen to add shine and volume without weighing hair down. How to use: apply to wet hair, massage scalp gently, then rinse thoroughly.','شامبو Oil Balance للشعر الدهني. يساعد على تنظيف عميق لفروة الرأس والشعر من الزيوت الزائدة التي قد تسبب ثِقلاً للشعر وضعف ثبات التسريحة، مع الحرص على عدم تجفيف الشعر. يدعم التحكم بالدهون ليبقى الشعر منتعشاً لفترة أطول. من المكوّنات الأساسية: مستخلص القراص للمساعدة في تنظيم دهون الفروة وتقوية الجذور، كيراتين لحماية وإصلاح ألياف الشعر، بروتينات القمح لتقوية الشعر وتقليل التكسر، وكولاجين لإضافة لمعان وحجم دون إثقال. طريقة الاستخدام: يوضع على شعر مبلل مع تدليك لطيف لفروة الرأس ثم يُشطف جيداً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:46:42',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(97,'کرێمی چارەسەرکردنی نیشانەکەنی پیربوونی پێست لە ڕۆژدا لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ کێ گونجاوە؟ بە پلەی یەکەم بۆ پێستی پێگەیشتوو (Mature Skin) دروستکراوە، بەڵام بۆ هەموو جۆرە پێستەکان دەبێت.\r\n• کاریگەرییەکان: یارمەتی کەمکردنەوەی چرچ و لۆچی دەدات، پەڵە تۆخەکان کاڵ دەکاتەوە، و پێستەکە توند دەکاتەوە (Firming).\r\n• شێواز: پێکهاتەیەکی سووک و ناسکی هەیە کە بە خێرایی هەڵدەمژرێت و چەوری لەسەر پێست جێناهێڵێت.\r\nپێکهاتە گرنگەکان:\r\nئەم کرێمە کۆمەڵێک ماددەی چالاکی تێدایە کە زۆر بەسوودن بۆ پێست:\r\n1. پێپتایدەکان (Peptides): بۆ توندکردنەوەی پێست و بەرەنگاربوونەوەی چرچی.\r\n2. هەیالۆرۆنیک ئەسید (Hyaluronic Acid): بە چەند کێشێکی گەردیلەیی جیاواز بۆ ئەوەی قووڵترین چینەکانی پێست تەڕ بکات (Hydration).\r\n3. ڤیتامین B3 (Niacinamide): بۆ ڕێکخستنی ڕەنگی پێست و کەمکردنەوەی پەڵە.\r\n4. ڤیتامین C: وەک دژە ئۆکسان کاردەکات و بریقە و گەشانەوە بە پێست دەبەخشێت.\r\n5. ڕۆنی زەیتونی ئۆرگانیکی یۆنانی: دەوڵەمەندە بە ڤیتامین E بۆ نەرمکردنەوە و پاراستنی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n• بەیانیان و ئێواران دەتوانیت بەکاریبهێنیت.\r\n• بیدە لە پێستی پاکی دەموچاو، مل، و سنگ (décolleté).\r\n• ئاگاداربە: نابێت بەر ناوچەی دەوروبەری چاو بکەوێت.\r\nتێبینییە زیادەکان:\r\n• ئەم بەرهەمە بێ پارابینە (Parabens Free).\r\n• لە ڕووی پزیشکییەوە تاقیکراوەتەوە (Dermatologically Tested).\r\n','Day cream for treating visible signs of skin aging. Designed primarily for mature skin but suitable for all skin types. Helps reduce wrinkles and fine lines, fade dark spots, and improve firmness. Lightweight texture absorbs quickly and does not leave a greasy feel. Key actives include peptides to support firmness and anti-wrinkle care, Hyaluronic Acid (multiple molecular sizes) for deep hydration, Niacinamide (Vitamin B3) to help even skin tone and reduce spots, Vitamin C for antioxidant glow and collagen support, and organic Greek olive oil rich in Vitamin E for softness and protection. How to use: apply morning and/or evening to clean skin on face, neck, and décolleté; avoid the eye area. Paraben-free and dermatologically tested.','كريم نهاري لعلاج علامات تقدم البشرة. مُصمم بالدرجة الأولى للبشرة الناضجة لكنه مناسب لجميع أنواع البشرة. يساعد على تقليل التجاعيد والخطوط الدقيقة، تخفيف البقع الداكنة، وتحسين تماسك البشرة. قوامه خفيف يمتص بسرعة ولا يترك إحساساً دهنياً. من المكوّنات الفعّالة: ببتيدات لدعم الشد ومقاومة التجاعيد، حمض الهيالورونيك (بأوزان جزيئية متعددة) للترطيب العميق، نياسيناميد (فيتامين B3) لتوحيد اللون وتقليل البقع، فيتامين C لمضادات الأكسدة والإشراقة ودعم الكولاجين، وزيت زيتون يوناني عضوي غني بفيتامين E للنعومة والحماية. طريقة الاستخدام: يُوضع صباحاً و/أو مساءً على بشرة نظيفة للوجه والرقبة وأعلى الصدر مع تجنب محيط العين. خالٍ من البارابين ومختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:49:59',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(98,'سیڕۆمی تایبەت بە پێستی دەور و بەری چاو لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,29000,4500,1,'سوودە سەرەکییەکانی:\r\n• دژە چرچولۆچی: کاردەکات بۆ کەمکردنەوەی هێڵە وردەکان و چرچی دەوری چاو.\r\n• نەهێشتنی ڕەشی دەوری چاو: یارمەتی کەمکردنەوەی ئەو ڕەشی و تاریکییە دەدات کە لە ژێر چاودا دروست دەبێت.\r\n• کەمکردنەوەی هەڵئاوسان: یارمەتی کەمکردنەوەی تورەگەی ژێر چاو (پۆف) دەدات.\r\n• شێدارکردن و گەشانەوە: پێستی دەوروبەری چاو بە قووڵی شێدار دەکات و دیمەنێکی گەش و حەساوەی پێ دەبەخشێت.\r\nپێکهاتە گرنگەکانی:\r\nئەم پێکهاتە چالاکانەی تێدایە:\r\n1. پێپتایدەکان (Peptides): بۆ توندکردنەوەی پێست و هاندانی دروستبوونی کۆلاجین.\r\n2. هیالۆرۆنیک ئەسید (Hyaluronic Acid): بۆ شێدارکردنی قووڵ و پڕکردنەوەی پێست.\r\n3. ڤیتامین C: بۆ ڕوونکردنەوەی ڕەشی ژێر چاو و پاراستنی پێست وەک دژە ئۆکسان.\r\n4. نیاسینامید (ڤیتامین B3): بۆ باشترکردنی ڕەنگی پێست و پاراستنی بەربەستی پێست.\r\n5. ڕۆنی زەیتوونی ئۆرگانیکی یۆنانی: دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسانەکان بۆ نەرمکردنەوەی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n• پێویستە بەیانیان و شەوان بەکاربێت.\r\n• دوای شتنی دەموچاو، بڕێکی کەم لە سیرومەکە بدە لە دەوروبەری چاو.\r\n• بە جوڵەی لێدانی هێواش (Dabbing) بە پەنجەکانت بڵاوی بکەرەوە تا هەڵدەمژرێت.\r\nتێبینی زیادە:\r\n• ئەم بەرهەمە بۆ پێستی پێگەیشتوو (Mature Skin) زۆر گونجاوە.\r\n• خاڵییە لە پارابین و سیلیکۆن و لەلایەن پزیشکی پێستەوە تاقی کراوەتەوە.\r\n','Eye-contour serum designed for mature skin concerns. Helps reduce fine lines and wrinkles, lessen dark circles, reduce under-eye puffiness, and deeply hydrate for a brighter, fresher look. Key ingredients: peptides to support firmness and collagen, Hyaluronic Acid for deep hydration and plumping, Vitamin C to brighten and provide antioxidant protection, Niacinamide (Vitamin B3) to support tone and barrier, and organic Greek olive oil rich in Vitamin E to soften and protect. How to use: morning and night after cleansing, apply a small amount around the eyes and spread with gentle dabbing until absorbed. Paraben- and silicone-free; dermatologically tested.','سيروم لمنطقة حول العين مخصص لمشاكل البشرة الناضجة. يساعد على تقليل الخطوط الدقيقة والتجاعيد، تخفيف الهالات السوداء، تقليل الانتفاخ تحت العين، وترطيب عميق يمنح مظهراً أكثر إشراقاً وانتعاشاً. المكوّنات الأساسية: ببتيدات لدعم الشد وتحفيز الكولاجين، حمض الهيالورونيك للترطيب العميق وملء الخطوط، فيتامين C لتفتيح المنطقة وحماية مضادة للأكسدة، نياسيناميد (فيتامين B3) لدعم توحيد اللون وحاجز البشرة، وزيت زيتون يوناني عضوي غني بفيتامين E للتنعيم والحماية. طريقة الاستخدام: صباحاً ومساءً بعد التنظيف توضع كمية قليلة حول العين وتوزع بالتربيت اللطيف حتى الامتصاص. خالٍ من البارابين والسيليكون ومختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:53:45',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(99,'سیڕۆمی چاودێری کردنی پێستی دەم و چاو و مل لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,29000,4500,1,'ئەم سێرەمە بە پلەی یەکەم بۆ ئەو کەسانە دروستکراوە کە پێستیان بەرەو هەڵکشانی تەمەن دەچێت (Mature skin)\r\n١. پێکهاتە سەرەکییەکان\r\nئەم سێرەمە کۆمەڵێک ماددەی چالاک لەخۆدەگرێت کە پێکەوە کاردەکەن بۆ باشترکردنی تەندروستی پێست:\r\n• پەپتایدەکان (Peptides): یارمەتی کەمکردنەوەی چرچولۆچی دەدەن و پێست توند دەکەنەوە.\r\n• ترشی هیالۆرۆنیک (Hyaluronic Acid): بە چەند کێشێکی گەردیلەیی جیاواز تێدایە بۆ ئەوەی بە قووڵی پێست شێدار بکاتەوە.\r\n• ڤیتامین B3 (Niacinamide): یارمەتی گەشاوەکردنی پێست و نەهێشتنی پەڵەی ڕەش دەدات.\r\n• ڤیتامین C: دژە ئۆکسانێکی بەهێزە، یارمەتی بەرهەمهێنانی کۆلاجین دەدات و ڕەنگی پێست یەکدەخات.\r\n• ڕۆنی زەیتوونی ئۆرگانی یۆنانی: دەوڵەمەندە بە ڤیتامین E و پێست نەرم دەکات.\r\n٢. سوودە سەرەکییەکانی\r\n• دژە چرچولۆچی (Anti-wrinkle): نیشانەکانی پیربوون کەم دەکاتەوە.\r\n• توندکردنەوە (Firming & Lifting): پێستەکە توند دەکاتەوە و شێوەیەکی گەنجانەی پێ دەبەخشێت.\r\n• شێدارکردن (Moisturizing): بە قووڵی پێست شێدار دەکات و لە وشکبوونەوە دەیپارێزێت.\r\n• بێ پارابین و سیلیکۆنە: ئەمەش وای لێدەکات بۆ زۆربەی جۆرەکانی پێست گونجاو بێت.\r\n٣. چۆنیەتی بەکارهێنان\r\n• بەیانیان و ئێواران دەدرێت لە پێستی پاک (دەموچاو، مل و سنگ).\r\n• دەتوانیت بەتەنها بەکاریبهێنیت یان پێش بەکارهێنانی کرێمی ڕۆژ یان شەو لێی بدەیت.\r\n• تێبینی: پێویستە لە ناوچەی دەوروبەری چاو دووربخرێتەوە.\r\n','Face, eye, and neck care serum designed mainly for mature skin. Combines multiple actives to improve overall skin health: peptides to reduce wrinkles and improve firmness, Hyaluronic Acid in different molecular sizes for deep hydration, Niacinamide (Vitamin B3) to brighten and help reduce dark spots, Vitamin C as a strong antioxidant supporting collagen and tone uniformity, and organic Greek olive oil rich in Vitamin E to soften and protect. Benefits: anti-wrinkle, firming/lifting support, deep moisturizing, suitable for most skin types and free from parabens and silicones. How to use: apply morning and evening on clean skin (face, neck, décolleté). Can be used alone or before day/night cream. Note: keep away from the immediate eye contour.','سيروم عناية للوجه والرقبة (وأيضاً مذكور للعناية بالديمومة) مُصمم بالدرجة الأولى للبشرة الناضجة. يجمع عدة مكوّنات فعالة لتحسين صحة البشرة: ببتيدات لتقليل التجاعيد وتحسين التماسك، حمض الهيالورونيك بأحجام جزيئية مختلفة للترطيب العميق، نياسيناميد (فيتامين B3) لتفتيح البشرة وتقليل البقع الداكنة، فيتامين C كمضاد أكسدة قوي يدعم الكولاجين وتوحيد اللون، وزيت زيتون يوناني عضوي غني بفيتامين E للتنعيم والحماية. الفوائد: مقاومة التجاعيد، دعم الشد والرفع، ترطيب عميق، مناسب لمعظم أنواع البشرة وخالٍ من البارابين والسيليكون. طريقة الاستخدام: يوضع صباحاً ومساءً على بشرة نظيفة (الوجه والرقبة وأعلى الصدر). يمكن استخدامه بمفرده أو قبل كريم النهار/الليل. ملاحظة: يُفضّل إبعاده عن محيط العين المباشر.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 05:57:07',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(100,'کرێمی چارەسەرکردنی نیشانەکانی پیربوون و نوێکردنەوەی خانەکانی پێست لە شەودا لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,30000,5000,1,'کارەکانی ئەم کرێمە:\r\n• توندکردنەوە و بەرزکردنەوە (Firming & Lifting): یارمەتی توندکردنەوەی پێست دەدات و ڕێگری لە شۆڕبوونەوەی دەکات.\r\n• دژە چرچولۆچی: بەهۆی هەبوونی ڕێتینۆڵ و پێپتاید، هێڵە وردەکان و چرچییەکان کەمدەکاتەوە.\r\n• ڕوونکردنەوە و گەشاوەیی: پەڵە تۆخەکان کەمدەکاتەوە و ڕەنگی پێست یەکدەخات.\r\n• شێدارکردنێکی قووڵ: بەدرێژایی شەو پێستەکە بە شێداری دەهێڵێتەوە بەبێ ئەوەی هەستی چەوری دروست بکات.\r\nپێکهاتە سەرەکییەکانی:\r\nئەم کرێمە کۆمەڵێک ماددەی زۆر کارای تێدایە کە بریتین لە:\r\n1. ڕێتینۆڵ (Retinol): ناسراوە بەوەی خانەکانی پێست نوێ دەکاتەوە و بەرهەمهێنانی کۆلاجین زیاد دەکات.\r\n2. پێپتاید (Peptides): بۆ توندکردنەوەی پێست و پاراستنی جیڕی (Elasticity) پێست.\r\n3. ترشی هیالۆرۆنیک (Hyaluronic Acid): بۆ شێدارکردنەوەی قووڵی پێست و پڕکردنەوەی هێڵەکان.\r\n4. ڤیتامین B3 (Niacinamide): بۆ چارەسەری پەڵە و کەمکردنەوەی سووربوونەوە.\r\n5. ڤیتامین C: وەک دژە ئۆکسان کار دەکات و پێست گەشاوە دەکات.\r\n6. ڕۆنی زەیتوونی ئۆرگانیکی یۆنانی: دەوڵەمەندە بە ڤیتامین E بۆ نەرمکردنەوەی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n• کەی؟: تەنها لە شەواندا بەکاردێت (چونکە ڕێتینۆڵی تێدایە و نابێت لەبەر خۆر بێت).\r\n• بۆ کوێ؟: بیدە لە پێستی پاکی دەموچاو، مل، و بەشی سەرەوەی سنگ (décolleté).\r\n• ئاگاداری: ئاگاداربە بەر چاوەکانت نەکەوێت.\r\nتێبینی گرنگ:\r\n• ئەم کرێمە بۆ پێستی پێگەیشتوو (Mature Skin) گونجاوە.\r\n• بەهۆی هەبوونی ڕێتینۆڵ، ئەگەر یەکەمجارتە بەکاری بهێنیت، باشترە سەرەتا هەفتەی ٢ بۆ ٣ جار بەکاری بهێنیت تا پێستت ڕادێت، و بەیانیان حەتمەن دژەخۆر بەکاربهێنیت.\r\n','Night cream for anti-aging and skin cell renewal, designed for mature skin. Helps firm and lift to reduce sagging, reduces fine lines and wrinkles thanks to retinol and peptides, brightens and evens skin tone by helping fade dark spots, and provides deep overnight hydration without a greasy feel. Key ingredients: Retinol to support cell turnover and boost collagen, Peptides for firmness and elasticity, Hyaluronic Acid for deep hydration and line-plumping, Niacinamide (Vitamin B3) to help reduce spots and redness, Vitamin C for antioxidant radiance, and organic Greek olive oil rich in Vitamin E for softness and protection. How to use: apply only at night on clean skin of face, neck, and décolleté; avoid eye area. If new to retinol, start 2–3 times per week then increase as tolerated; always use sunscreen in the morning.','كريم ليلي لمقاومة علامات التقدم وتجديد خلايا البشرة، مخصص للبشرة الناضجة. يساعد على الشد والرفع وتقليل الترهل، ويقلل الخطوط الدقيقة والتجاعيد بفضل الريتينول والببتيدات، ويُسهم في تفتيح وتوحيد اللون عبر تقليل البقع الداكنة، مع ترطيب عميق طوال الليل دون إحساس دهني. المكوّنات الأساسية: ريتينول لتجديد الخلايا وزيادة إنتاج الكولاجين، ببتيدات لدعم التماسك والمرونة، حمض الهيالورونيك للترطيب العميق وملء الخطوط، نياسيناميد (فيتامين B3) لتقليل البقع والاحمرار، فيتامين C لمضادات الأكسدة والإشراقة، وزيت زيتون يوناني عضوي غني بفيتامين E للنعومة والحماية. طريقة الاستخدام: يُستخدم ليلاً فقط على بشرة نظيفة للوجه والرقبة وأعلى الصدر مع تجنب محيط العين. إذا كانت هذه أول تجربة لك مع الريتينول فابدأ 2–3 مرات أسبوعياً ثم زد تدريجياً حسب التحمل، ومعه يُنصح بواقي شمس صباحاً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 06:01:36',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(101,'سیڕۆمی دژە چرچی و لۆچی و ڕونونکەرەوەی پێست لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28500,4250,1,'. پێکهاتە سەرەکییەکان:\r\n• ڕۆنی زەیتوونی ئۆرگانیکی یۆنانی: دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسانەکان بۆ پاراستنی پێست.\r\n• هیالۆرۆنیک ئەسید (Hyaluronic Acid): بە کێشی گەردیلەیی جیاواز بۆ شێدارکردنەوەی قووڵی پێست.\r\n• ڤیتامین B3 (Niacinamide): بۆ چارەسەری پەڵەی تۆخ و بەرەنگاربوونەوەی چرچی.\r\n• پێپتایدەکان (Peptides): یارمەتیدەرن لە چالاککردنی کۆلاجینی سروشتی و توندکردنەوەی پێست.\r\n٢. سوودەکانی ئەم سێرمە:\r\n• پێست بە قووڵی شێدار دەکاتەوە.\r\n• چرچی و هێڵە وردەکانی دەموچاو کەم دەکاتەوە.\r\n• پەڵە تۆخەکان کاڵ دەکاتەوە و ڕەنگی پێست یەکدەخات.\r\n• پێست گەشاوە و گەنجتر پیشان دەدات.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• کەی؟ بەیانیان و ئێواران یان تەنها یەکێکیان.\r\n• چۆن؟ دوای شۆردنی دەموچاو، بڕێکی گونجاو بدە لە دەموچاو و مل.\r\n• دەتوانیت بەتەنها بەکاریبهێنیت یان پێش کرێمی ڕۆژ و شەو.\r\n• تێبینی: نابێت لە دەوروبەری چاو بدرێت.\r\n٤. تایبەتمەندی تری بەرهەمەکە:\r\n• بۆ هەموو جۆرە پێستێک گونجاوە.\r\n• بەبێ پارابین (Parabens) و سیلیکۆن (Silicones) دروستکراوە.','Anti-wrinkle, firming, and brightening serum. Key ingredients include organic Greek olive oil rich in Vitamin E and antioxidants to protect the skin, Hyaluronic Acid with different molecular sizes for deep hydration, Niacinamide (Vitamin B3) to help reduce dark spots and support anti-aging, and peptides to stimulate natural collagen and improve firmness. Benefits: deeply hydrates, reduces fine lines and wrinkles, fades dark patches and evens tone, and leaves skin looking fresher and younger. How to use: apply morning and evening (or once daily) after cleansing to face and neck. Can be used alone or before day/night cream. Note: avoid the immediate eye contour.','سيروم مضاد للتجاعيد مع دعم للشد والتفتيح. يحتوي على زيت زيتون يوناني عضوي غني بفيتامين E ومضادات الأكسدة لحماية البشرة، وحمض الهيالورونيك بأحجام جزيئية مختلفة للترطيب العميق، ونياسيناميد (فيتامين B3) للمساعدة على تقليل البقع الداكنة ودعم مقاومة علامات التقدم، وببتيدات لتحفيز الكولاجين الطبيعي وتحسين التماسك. الفوائد: ترطيب عميق، تقليل الخطوط الدقيقة والتجاعيد، تخفيف التصبغات وتوحيد اللون، ومنح البشرة مظهراً أكثر نضارة وشباباً. طريقة الاستخدام: يوضع صباحاً ومساءً (أو مرة واحدة يومياً) بعد التنظيف على الوجه والرقبة. يمكن استخدامه بمفرده أو قبل كريم النهار/الليل. ملاحظة: تجنب محيط العين المباشر.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 06:03:34',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(102,'ڕۆنی بریقەدارکردنی پێست لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,2,20000,29750,4750,1,'پێکهاتە سەرەکییەکانی:\r\n• ڕۆنی زەیتوونی ئۆرگانیک: بۆ نەرمکردن و تەڕکردنی پێست.\r\n• ڕۆنی ئەرگان (Argan Oil): یارمەتی نوێکردنەوە و پاراستنی پێست دەدات.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست لە پیربوون دەپارێزێت.\r\nسوودەکانی:\r\n• بریقەیەکی زێڕینی (Glow): سەرنجڕاکێش بە پێست دەبەخشێت کە بۆ بۆنە و ئاهەنگەکان یان کاتی چوونە کەنار دەریا زۆر گونجاوە.\r\n• تەڕکردن (Hydration): پێست بە قووڵی شێدار دەکاتەوە و دەیپارێزێت.\r\n• هەڵمژینی خێرا: زوو بە پێستەوە وشک دەبێتەوە و هەستێکی چەوری بێزارکەر بەجێناهێڵێت.\r\nخاسیەتە گرنگەکان:\r\n• بێ پارابینە (Parabens Free).\r\n• لە ڕووی پێستناسییەوە تاقیکراوەتەوە (Dermatologically Tested).\r\n• بێ ماددەی هەستیارکەرە (Allergen Free).\r\n• بۆ هەموو جۆرە پێستێک گونجاوە.\r\nچۆنیەتی بەکارهێنان:\r\n1. پێش بەکارهێنان بە باشی ڕایوەشێنە (چونکە بریقەکان لە بنی دەمێننەوە).\r\n2. بیدە لەو شوێنەی جەستەت کە دەتەوێت کاتێک پێستت وشکە.\r\n3. تەنها بۆ بەکارهێنانی دەرەکییە.\r\n','Radiant body oil for a golden glow. Formulated with organic olive oil to soften and hydrate skin, organic argan oil to help renew and protect, and Vitamin E for antioxidant anti-aging support. Benefits: gives the skin a shiny golden glow suitable for occasions, parties, or beach time; provides deep hydration; absorbs quickly without leaving an uncomfortable greasy feel. Key notes: paraben-free, allergen-free, dermatologically tested, suitable for all skin types. How to use: shake well before use (shimmer particles settle), then apply to desired areas of the body when skin is dry. External use only.','زيت للجسم يمنح لمعاناً ذهبياً وإشراقة جذابة. تركيبة تحتوي على زيت زيتون عضوي لتنعيم وترطيب البشرة، وزيت أرغان للمساعدة على التجدد والحماية، وفيتامين E كمضاد أكسدة لدعم مقاومة علامات التقدم. الفوائد: يمنح البشرة توهجاً ذهبياً مناسباً للمناسبات والحفلات أو وقت الشاطئ، مع ترطيب عميق وامتصاص سريع دون إحساس دهني مزعج. خصائص مهمة: خالٍ من البارابين وخالٍ من مسببات الحساسية، مختبر جلدياً ومناسب لكل أنواع البشرة. طريقة الاستخدام: يُرج جيداً قبل الاستعمال (لأن جزيئات اللمعان تترسب)، ثم يوضع على مناطق الجسم المراد إبرازها عندما تكون البشرة جافة. للاستعمال الخارجي فقط.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 06:05:42',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(103,'کرێم و سیڕۆمی دژە چرچی دەوری چاو لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'تایبەتمەندییە سەرەکییەکانی:\r\n• دژە چرچ (Anti-Wrinkle): یارمەتی کەمکردنەوەی هێڵە وردەکان و چرچی دەوری چاو دەدات.\r\n• بۆ هەموو جۆرە پێستێک گونجاوە: وەک لەسەر کارتۆنەکە نووسراوە (All skin types).\r\n• چارەسەری پف و ڕەشی: یارمەتی کەمکردنەوەی پفی ژێر چاو و بازنە ڕەشەکانی دەوری چاو دەدات.\r\n• تەندروست و سەلامەت: بێ پارابین (Parabens Free) و بێ سیلیکۆنە (Silicones Free)، هەروەها لەلایەن پزیشکی پێستەوە پشکنینی بۆ کراوە.\r\nپێکهاتە گرنگەکانی:\r\n1. ڕۆنی زەیتوونی ئۆرگانیکی یۆنانی: دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسان بۆ شێدارکردنەوەی پێست.\r\n2. هیالۆرۆنیک ئەسید (Hyaluronic Acid): بە چەند کێشێکی گەردیلەیی جیاواز، کە بە قووڵی پێستەکە شێدار دەکاتەوە.\r\n3. ڤیتامین B3 (Niacinamide): کاریگەرە بۆ سپیکردنەوەی ڕەشی ژێر چاو و توندکردنەوەی پێست.\r\n4. پێپتایدەکان (Peptides): تێکەڵەیەکی بەهێز بۆ هاندانی کۆلاجین و کەمکردنەوەی نیشانەکانی پیری.\r\nچۆنیەتی بەکارهێنان:\r\n• ڕۆژانە دوای پاککردنەوەی دەموچاو، بڕێکی گونجاو لە دەوری چاو (بەشی دەرەوە و ژێر چاو) بدە.\r\n• دەتوانیت بەیانیان، ئێواران، یان هەردووکی بەکاری بهێنیت.','Eye anti-wrinkle cream/serum suitable for all skin types. Helps reduce fine lines and wrinkles around the eyes, and supports reducing under-eye puffiness and dark circles. Formulated without parabens and without silicones, and dermatologically tested. Key ingredients include organic Greek olive oil rich in Vitamin E and antioxidants for hydration and protection, Hyaluronic Acid (multiple molecular sizes) for deep moisture and plumping, Niacinamide (Vitamin B3) to help brighten under-eye darkness and support firmness, and peptides to support collagen and reduce signs of aging. How to use: apply daily after cleansing to the outer and under-eye area; can be used morning and/or evening.','كريم/سيروم مضاد لتجاعيد محيط العين مناسب لجميع أنواع البشرة. يساعد على تقليل الخطوط الدقيقة والتجاعيد حول العين، ويدعم تقليل انتفاخ تحت العين والهالات. تركيبة خالية من البارابين والسيليكون ومختبرة جلدياً. من المكوّنات الأساسية: زيت زيتون يوناني عضوي غني بفيتامين E ومضادات الأكسدة للترطيب والحماية، حمض الهيالورونيك بأحجام جزيئية متعددة للترطيب العميق وملء الخطوط، نياسيناميد (فيتامين B3) للمساعدة في تفتيح سواد تحت العين وتحسين التماسك، وببتيدات لتحفيز الكولاجين وتقليل علامات التقدم. طريقة الاستخدام: يُستخدم يومياً بعد التنظيف على محيط العين الخارجي وتحت العين، ويمكن استخدامه صباحاً و/أو مساءً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 06:08:29',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(104,'کرێمی دژە خۆر و دژە پیربوونی پێست لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'• ناوی بەرهەم: Herbellis Anti-Wrinkle Radiant Cream.\r\n• دژە خۆر: خاوەنی SPF 50یە و پارێزگاری لە پێست دەکات بەرامبەر تیشکەکانی (UVA و UVB).\r\n• دژە چرچولۆچ: کاردەکات بۆ کەمکردنەوە و ڕێگریکردن لە دروستبوونی چرچی پێست.\r\n• دژە پەڵە: یارمەتی کەمکردنەوەی پەڵە ڕەشەکان دەدات و ڕەنگی پێست یەکدەخاتەوە.\r\n• شێدارکەرەوە: بە قووڵی پێست شێدار دەکاتەوە بەبێ ئەوەی هەست بە چەوری بکەیت (Greasy feel).\r\nپێکهاتە گرنگەکان:\r\nئەم پێکهاتانەی تێدایە:\r\n1. ڕۆنی زەیتوونی ئۆرگانی یۆنانی: دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسانەکان.\r\n2. ترشی هایالۆرۆنیک (Hyaluronic Acid): بۆ شێدارکردنەوەی بەهێز.\r\n3. ڤیتامین B3 (Niacinamide): بۆ شەڕکردن دژی چرچی و پەڵە.\r\n4. پێپتایدەکان (Peptides): بۆ توندکردنەوەی پێست و دژە پیربوون.\r\n5. تێکەڵەی ڕووەکی: بۆ درەوشانەوە و چارەسەری تێکچوونی ڕەنگی پێست.\r\nچۆنیەتی بەکارهێنان و ڕێنمایییەکان:\r\n• کات: بەیانیان لەسەر پێستی پاك (دەموچاو و مل) بەکاریدەهێنرێت.\r\n• پاراستن: پێویستە پێش چوونە بەر خۆر لێبدرێت و ئەگەر زۆر لەبەر خۆر بوویت، چەند جارێک دووبارە لێی بدەرەوە.\r\n• تێبینی: نابێت لە دەوروبەری چاو بدرێت.\r\n• بۆ کێ دەبێت؟ بۆ هەموو جۆرە پێستێک گونجاوە (All skin types).\r\n• بێ پارابینە و لە لایەن پزیشکانی پێستەوە تاقیکراوەتەوە.\r\n','Anti-wrinkle radiant sunscreen cream with very high protection SPF 50. Protects the skin from UVA and UVB rays while helping reduce and prevent wrinkles, fade dark spots, and even skin tone. Provides deep hydration without a greasy feel. Key ingredients include organic Greek olive oil rich in Vitamin E and antioxidants, Hyaluronic Acid for strong hydration, Niacinamide (Vitamin B3) for anti-spot and anti-aging support, peptides for firming and anti-aging, and botanical complexes to boost radiance and treat uneven tone. How to use: apply in the morning to clean face and neck before sun exposure; reapply during prolonged sun exposure. Avoid the eye area. Paraben-free and dermatologically tested.','كريم واقٍ من الشمس ومضاد للتجاعيد مع إشراقة وحماية عالية جداً SPF 50. يحمي البشرة من أشعة UVA وUVB، ويساعد على تقليل ومنع التجاعيد، وتخفيف البقع الداكنة وتوحيد لون البشرة. يمنح ترطيباً عميقاً دون إحساس دهني. من المكوّنات المهمة: زيت زيتون يوناني عضوي غني بفيتامين E ومضادات الأكسدة، حمض الهيالورونيك للترطيب القوي، نياسيناميد (فيتامين B3) لدعم مقاومة البقع وعلامات التقدم، ببتيدات للشد ومقاومة الشيخوخة، ومركبات نباتية لتعزيز الإشراقة وعلاج عدم تجانس اللون. طريقة الاستخدام: يُوضع صباحاً على بشرة نظيفة للوجه والرقبة قبل التعرض للشمس، ويُعاد عند التعرض الطويل. تجنب محيط العين. خالٍ من البارابين ومختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 06:11:28',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(105,'کرێمی شێدارکەرەوەی تایبەت بە پێستی چەور لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• ناوی بەرهەم: Moisturising Cream Oil-Free Sense.\r\n• جۆری پێست: گونجاوە بۆ پێستی چەور (For oily skin).\r\n• مەبەست لە بەکارهێنان: کۆنتڕۆڵکردنی چەوری پێست (Sebum Control) و شێدارکردنەوەی بەبێ ئەوەی پێستەکە چەور یان بریقەدار بکات.\r\n• ئەنجام: شێوەیەکی مات (Matte Finish) بە پێست دەبەخشێت کە بۆ ماوەی ٢٤ کاتژمێر دەمێنێتەوە.\r\nپێکهاتە گرنگەکان:\r\n١. Hyaluronic Acid (هایالۆرۆنیک ئەسید): بە چەند کێشێکی گەردیلەیی جیاواز تێدایە بۆ ئەوەی بە قووڵی پێستەکە شێدار بکاتەوە.\r\n٢. Vitamin B3 (Niacinamide): یارمەتی کەمکردنەوەی دەردانی چەوری، بچوکردنەوەی کونیلەکانی پێست، کەمکردنەوەی سووربوونەوە و بەرەنگاربوونەوەی زیپکە دەدات.\r\n٣. بێ پارابین: ئەم بەرهەمە ماددەی پارابینی تێدا نییە و لە ڕووی پزیشکییەوە تاقیکراوەتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• بەیانیان و ئێواران دەدرێت لە دەموچاو و مل دوای ئەوەی بە باشی پاککراوەتەوە.\r\n• تێبینی: پێویستە لە ناوچەی چاوەکان دووربخرێتەوە.\r\n','Oil-free moisturizing cream designed for oily skin. Helps control sebum and moisturize without making the skin look greasy or shiny. Leaves a matte finish that can last up to 24 hours. Key ingredients include Hyaluronic Acid (multiple molecular sizes) for deep hydration, Niacinamide (Vitamin B3) to reduce excess oil, help minimize the look of pores, calm redness, and support acne-prone skin. Paraben-free and dermatologically tested. How to use: apply morning and evening to face and neck after cleansing; avoid the eye area.','كريم ترطيب خالٍ من الزيوت مخصص للبشرة الدهنية. يساعد على التحكم في إفراز الدهون وترطيب البشرة دون أن يجعلها لامعة أو دهنية. يمنح لمسة مطفية قد تدوم حتى 24 ساعة. من المكوّنات الأساسية: حمض الهيالورونيك بأحجام جزيئية متعددة للترطيب العميق، ونياسيناميد (فيتامين B3) لتقليل الدهون الزائدة والمساعدة على تصغير مظهر المسام وتهدئة الاحمرار ودعم البشرة المعرضة للحبوب. خالٍ من البارابين ومختبر جلدياً. طريقة الاستخدام: يُوضع صباحاً ومساءً على الوجه والرقبة بعد التنظيف مع تجنب محيط العين.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 06:13:07',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(106,'کرێمی دژە خۆر و شێدارکەرەوەی ڕەنگدار لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستن لە خۆر: خاوەنی SPF 50یە و دەموچاو لە تیشکە زیانبەخشەکانی (UVA و UVB) دەپارێزێت.\r\n• ڕەنگدار (Tinted): وەک ئەساسێکی سووک کاردەکات، ڕەنگێکی سروشتی و یەکگرتوو بە پێست دەبەخشێت و پەڵەکان دادەپۆشێت.\r\n• دژە پەڵە: کاردەکات بۆ ڕێگریکردن لە دروستبوونی پەڵەی نوێ و کەمکردنەوەی پەڵە کۆنەکانی سەر پێست.\r\n• مات فینیش (Matte Finish): دوای لێدان پێست بە گەشاوەیی و وشکی دەهێڵێتەوە (Dry Touch)، واتە پێست زۆر چەور و بریقەدار نیشان نادات.\r\nپێکهاتە سەرەکییەکانی:\r\n1. ڕۆنی زەیتوونی ئۆرگانیکی یۆنانی: دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسانەکان بۆ نەرمکردنەوەی پێست.\r\n2. هایالۆرۆنیک ئەسید (Hyaluronic acid): پێست بە قووڵی شێدار دەکاتەوە و ناهێڵێت وشک ببێتەوە.\r\n3. ڤیتامین B3 (Niacinamide): یارمەتی کەمکردنەوەی چرچوڵۆچی و پەڵە ڕەشەکان دەدات.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو بدە لە تەواوی دەموچاوت پێش ئەوەی بچیتە بەر خۆر.\r\n• ئاگاداربە بەر چاوەکانت نەکەوێت.\r\n• ئەگەر دەتەوێت داپۆشینی زیاتر بێت (وەک ئەساس)، دەتوانیت زیاتر لە چینێکی لێ بدەیت.\r\n• پێویستە چەند کاتژمێر جارێک نوێ بکرێتەوە ئەگەر لەبەر خۆر بویت.\r\nتێبینییەکان:\r\n• بۆ هەموو جۆرە پێستێک گونجاوە.\r\n• لە لایەن پزیشکی پێستەوە تاقی کراوەتەوە.','Tinted moisturizing sunscreen with SPF 50. Protects face from UVA/UVB rays and provides a natural, even tint like a lightweight foundation to help cover blemishes and spots. Also supports anti-spot care to help prevent new pigmentation and reduce existing dark patches. Leaves a matte, dry-touch finish without excessive shine. Key ingredients include organic Greek olive oil rich in Vitamin E and antioxidants for softness and protection, Hyaluronic Acid for deep hydration, and Niacinamide (Vitamin B3) to help reduce wrinkles and dark spots. How to use: apply an appropriate amount over the entire face before sun exposure; avoid the eyes. For more coverage, apply an additional layer. Reapply during prolonged sun exposure. Dermatologically tested and suitable for all skin types.','واقي شمس مرطب ملوّن مع SPF 50. يحمي الوجه من أشعة UVA/UVB ويمنح لوناً طبيعياً موحداً يشبه أساساً خفيفاً يساعد على تغطية العيوب والبقع. كما يدعم العناية المضادة للتصبغ للمساعدة في منع ظهور بقع جديدة وتخفيف البقع القديمة. يمنح لمسة مطفية “Dry Touch” دون لمعان زائد. من المكوّنات الأساسية: زيت زيتون يوناني عضوي غني بفيتامين E ومضادات الأكسدة للنعومة والحماية، حمض الهيالورونيك للترطيب العميق، ونياسيناميد (فيتامين B3) للمساعدة على تقليل التجاعيد والبقع الداكنة. طريقة الاستخدام: توضع كمية مناسبة على كامل الوجه قبل التعرض للشمس مع تجنب العينين. لزيادة التغطية يمكن وضع طبقة إضافية. يُعاد عند التعرض الطويل. مختبر جلدياً ومناسب لجميع أنواع البشرة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 06:14:38',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(107,'کرێمی شێدارکەرەوەی چڕی پێست لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'. پێکهاتە سەرەکییەکان:\r\n• ڕۆنی زەیتوونی ئۆرگانی یۆنانی: کە دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسانەکان، یارمەتی پاراستنی پێست و نوێکردنەوەی دەدات.\r\n• ترشی هیالۆرۆنیک (Hyaluronic Acid): بە چەند کێشێکی گەردیلەیی جیاواز تێدایە، کە کاردەکات بۆ شێدارکردنەوەی قووڵی پێست و هێشتنەوەی نەرمییەکەی بۆ ماوەیەکی درێژ.\r\n٢. سوودە سەرەکییەکانی:\r\n• شێدارکردنەوەی ٢٤ کاتژمێری:کاردەکات بۆ هێشتنەوەی شێی پێست بۆ ماوەی شەو و ڕۆژێک.\r\n• بۆ هەموو جۆرە پێستێک: گونجاوە بۆ هەموو جۆرەکانی پێست (All skin types).\r\n• تەنی سووک: پێکهاتەکەی سووکە و زوو هەڵدەمژرێت، بەبێ ئەوەی هەستی چەوری (greasy feel) لەسەر پێست جێبهێڵێت.\r\n• تەندروستی: بەرهەمەکە بێ \"پارابین\"ە (Parabens Free) و لەلایەن پزیشکانی پێستەوە پشکنینی بۆ کراوە.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• بەیانیان و ئێواران (یان هەردووکیان) دەدرێت لە دەموچاو و مل دوای ئەوەی بە جوانی پاککراونەتەوە.\r\n• ئاگاداری: پێویستە لە ناوچەی دەوروبەری چاو دووربخرێتەوە.\r\n','Rich moisturizing cream for all skin types. Formulated with organic Greek olive oil rich in Vitamin E and antioxidants to protect and support skin renewal, and Hyaluronic Acid (multiple molecular sizes) to provide deep hydration and long-lasting softness. Offers 24-hour moisturizing support. Lightweight texture absorbs quickly without leaving a greasy feel. Paraben-free and dermatologically tested. How to use: apply morning and/or evening to face and neck after cleansing; avoid the eye area.','كريم ترطيب غني مناسب لجميع أنواع البشرة. يحتوي على زيت زيتون يوناني عضوي غني بفيتامين E ومضادات الأكسدة لحماية البشرة ودعم تجددها، وحمض الهيالورونيك بأحجام جزيئية متعددة للترطيب العميق والحفاظ على نعومة تدوم طويلاً. يوفر ترطيباً يدوم حتى 24 ساعة. قوامه خفيف يمتص بسرعة دون إحساس دهني. خالٍ من البارابين ومختبر جلدياً. طريقة الاستخدام: يُوضع صباحاً و/أو مساءً على الوجه والرقبة بعد التنظيف مع تجنب محيط العين.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:00:35',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(108,'کرێمی چارەسەرکردنی چرچولۆچی و توندکردنەوەی پێست لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• دژە چرچولۆچی (Anti-wrinkle): یارمەتی کەمکردنەوەی هێڵە وردەکانی دەموچاو دەدات.\r\n• توندکردنەوە (Firming): کار دەکات بۆ ڕێگریکردن لە شلبوونەوەی پێست و توندکردنەوەی.\r\n• ڕوونکردنەوە و درەوشانەوە (Radiant): پەڵە تۆخەکان کەم دەکاتەوە و ڕەنگی پێست یەکسان دەکاتەوە.\r\n• بۆ هەموو جۆرە پێستێک گونجاوە: بەهۆی پێکهاتە سوکەکەیەوە، چەوری لەسەر پێست جێناهێڵێت و خێرا هەڵدەمژرێت.\r\nپێکهاتە گرنگەکانی:\r\n١. ڕۆنی زەیتونی ئۆرگانیکی یۆنانی: دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسانەکان بۆ پاراستن و شێدارکردنی پێست.\r\n٢. ترشی هیالۆرۆنیک (Hyaluronic Acid): بە چەند کێشێکی گەردیلەیی جیاواز، کە بە قووڵی پێستەکە شێدار دەکاتەوە.\r\n٣. ڤیتامین B3 (Niacinamide): زۆر کاریگەرە بۆ نەهێشتنی پەڵە و کەمکردنەوەی چرچی.\r\n٤. پێپتایدەکان (Peptides): یارمەتی دروستکردنی کۆلاجین دەدەن و پێست بە گەنجی دەهێڵنەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• بەیانیان و ئێواران دوای پاککردنەوەی دەموچاو، بڕێکی گونجاو بدە لە دەموچاو و مل.\r\n• تێبینی: ئاگاداربە بەر ناوچەی دەوروبەری چاوەکانت نەکەوێت.\r\nزانیاری زیاتر:\r\n• بێ پارابین (Parabens Free): واتە ماددەی کیمیایی زیانبەخشی تێدا نییە.\r\n• لە لایەن پزیشکانی پێستەوە تاقی کراوەتەوە (Dermatologically Tested).\r\n','Anti-wrinkle and firming cream with brightening/radiant effect. Helps reduce fine lines, support firmness, and improve uneven tone and dark spots, while remaining lightweight and fast-absorbing without leaving oily residue. Key ingredients include organic Greek olive oil rich in Vitamin E and antioxidants for protection and hydration, Hyaluronic Acid (multiple molecular sizes) for deep moisture, Niacinamide (Vitamin B3) to help reduce spots and improve tone, and peptides to support collagen production and keep skin looking youthful. How to use: apply morning and evening after cleansing to face and neck. Note: avoid the eye area. Paraben-free and dermatologically tested.','كريم مضاد للتجاعيد مع دعم للشد وتأثير إشراقة. يساعد على تقليل الخطوط الدقيقة، دعم تماسك البشرة، وتحسين عدم تجانس اللون والبقع الداكنة، مع قوام خفيف سريع الامتصاص دون بقايا دهنية. من المكوّنات الأساسية: زيت زيتون يوناني عضوي غني بفيتامين E ومضادات الأكسدة للحماية والترطيب، حمض الهيالورونيك بأحجام جزيئية متعددة للترطيب العميق، نياسيناميد (فيتامين B3) للمساعدة على تقليل البقع وتحسين اللون، وببتيدات لدعم إنتاج الكولاجين والحفاظ على مظهر أكثر شباباً. طريقة الاستخدام: يوضع صباحاً ومساءً بعد التنظيف على الوجه والرقبة. ملاحظة: تجنب محيط العين. خالٍ من البارابين ومختبر جلدياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:02:04',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(109,'کرێمی شێدارکەرەوەی پێست و نەهێشتنی پەڵەی دەم و چاو لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'پێکهاتە سەرەکییەکانی:\r\n• ڕۆنی زەیتونی ئۆرگانیک: دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسانەکان کە پێست دەپارێزن.\r\n• هایالۆرۆنیک ئەسید (Hyaluronic acid): یارمەتیدەرێکی بەهێزە بۆ شێدارکردنەوەی قووڵی پێست.\r\n• ڤیتامین B3 (Niacinamide): کاردەکات بۆ کەمکردنەوەی چرچوڵۆچی و نەهێشتنی پەڵە تۆخەکان.\r\n• پێکهاتە ڕووەکییەکان (وەک گواڤا، پاپایا و ساکسیفراگا): ئەم ڕووەکانە یارمەتی ڕاگرتنی بەرهەمهێنانی میلانین دەدەن (ئەو ماددەیەی دەبێتە هۆی پەڵە).\r\nسوودەکانی:\r\n• نەهێشتنی پەڵە: پەڵە تۆخەکان و نیشانەکانی پیربوونی پێست کەمدەکاتەوە.\r\n• شەوقدان بە پێست: ڕەنگی پێست یەکدەخات و گەشاوەیی پێ دەبەخشێت.\r\n• مژینی خێرا: پێستەکە زوو هەڵی دەمژێت و هەستی چەوری جێنەهێڵێت.\r\n• بێ پارابین: هیچ ماددەیەکی پارابینی تێدا نییە و لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• بەیانیان و شەوان بڕێکی گونجاو بدە لە پێستی دەموچاو و مل (پێشتر پێستەکە پاک کرابێتەوە).\r\n• ئاگاداربە بەر ناوچەی چاو نەکەوێت.\r\n• ئەنجامەکانی دوای ٣ بۆ ٥ هەفتە بەکارهێنانی بەردەوام دەردەکەون.\r\n','Moisturizing and anti-spot face/neck cream designed to help reduce dark patches and signs of aging. Key ingredients include organic olive oil rich in Vitamin E and antioxidants to protect skin, Hyaluronic Acid for deep hydration, Niacinamide (Vitamin B3) to reduce wrinkles and dark spots, and botanical extracts (such as guava, papaya, and saxifraga) that help limit melanin production (the pigment linked to spots). Benefits: fades dark spots and aging signs, evens tone and boosts radiance, absorbs quickly without greasy feel. Paraben-free and dermatologically tested. How to use: apply a suitable amount morning and night on clean face and neck; avoid the eye area. Results may be noticed after 3–5 weeks of consistent use.','كريم ترطيب ومضاد للبقع للوجه والرقبة يساعد على تقليل التصبغات وعلامات التقدم. يحتوي على زيت زيتون عضوي غني بفيتامين E ومضادات الأكسدة لحماية البشرة، حمض الهيالورونيك للترطيب العميق، نياسيناميد (فيتامين B3) لتقليل التجاعيد والبقع الداكنة، ومستخلصات نباتية (مثل الجوافة والبابايا والسكسيفراجا) تساعد على تقليل إنتاج الميلانين (الصبغة المرتبطة بالبقع). الفوائد: تخفيف البقع وعلامات الشيخوخة، توحيد اللون وزيادة الإشراقة، امتصاص سريع دون إحساس دهني. خالٍ من البارابين ومختبر جلدياً. طريقة الاستخدام: توضع كمية مناسبة صباحاً ومساءً على بشرة نظيفة للوجه والرقبة مع تجنب محيط العين. قد تظهر النتائج بعد 3–5 أسابيع من الاستخدام المنتظم.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:04:40',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(110,'کرێمی دژە چرچ و لۆچی رەونەقدەری دەم و چاو لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,20000,28000,4000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• ناوی بەرهەم: کرێمی دژە چرچ و لۆچی و ڕەونەقدەر (Radiant Cream).\r\n• بۆ کێ دەبێت؟ بۆ هەموو جۆرە پێستێک گونجاوە (All Skin Types).\r\n• بەکارهێنان: کرێمێکی ٢٤ کاتژمێرییە (دەتوانیت بەیانیان و شەوان بەکاری بهێنیت).\r\nپێکهاتە سەرەکییەکان:\r\nئەم کرێمە لە چوار ماددەی گرنگ پێکهاتووە کە بۆ پێست زۆر بەسوودن:\r\n1. ڕۆنی زەیتونی ئۆرگانیکی یۆنانی: دەوڵەمەندە بە ڤیتامین E و دژە ئۆکسان، پێست نەرم دەکات و دەیپارێزێت.\r\n2. هایالۆرۆنیک ئەسید (Hyaluronic acid): بە چەند کێشێکی گەردیلەیی جیاواز، کە بە قووڵی پێست شێدار دەکاتەوە و وشکبوونەوە ناهێڵێت.\r\n3. ڤیتامین B3 (Niacinamide): کاردەکات بۆ کەمکردنەوەی پەڵە تاریکەکان و ڕێگری لە چرچبوونی پێست.\r\n4. پێپتایدەکان (Peptides): یارمەتی توندکردنەوەی پێست و کەمکردنەوەی هێڵە وردەکانی دەموچاو دەدەن.\r\nسوودەکانی:\r\n• بە قووڵی پێست شێدار دەکاتەوە.\r\n• چرچ و لۆچی و هێڵە وردەکان کەمدەکاتەوە.\r\n• پەڵەی ڕەشی سەر پێست کاڵ دەکاتەوە.\r\n• ڕەونەق و درەوشانەوەیەکی سروشتی بە پێست دەبەخشێت.\r\n• تەقەلایەکی سووکی هەیە و زوو هەڵدەمژرێت، بەبێ ئەوەی هەستی چەوری بە پێست بدات.\r\nچۆنیەتی بەکارهێنان:\r\n• بەیانیان و شەوان بڕێکی گونجاو بدە لە پێستی دەموچاو و مل (پێویستە پێستەکە پاک بێت پێشتر).\r\n• تێبینی: ئاگاداربە بەر چاوەکانت نەکەوێت.\r\nزانیاری زۆرتر: ئەم بەرهەمە لەژێر چاودێری پزیشکی پێستدا تاقیکراوەتەوە (Dermatologically Tested) و بەبێ \"پارابین\" دروستکراوە\r\n','Radiant anti-wrinkle cream suitable for all skin types for 24-hour care (morning and night). Formulated with organic Greek olive oil rich in Vitamin E and antioxidants to soften and protect, Hyaluronic Acid (multiple molecular sizes) for deep hydration and to prevent dryness, Niacinamide (Vitamin B3) to help reduce dark spots and support anti-aging, and peptides to firm skin and reduce fine lines. Benefits: deep hydration, reduced wrinkles and fine lines, lighter appearance of dark patches, and a natural radiant glow. Lightweight texture absorbs quickly without oily feel. Dermatologically tested and paraben-free. How to use: apply morning and night on clean face and neck; avoid the eye area.','كريم Radiant مضاد للتجاعيد مناسب لجميع أنواع البشرة لعناية 24 ساعة (صباحاً ومساءً). يحتوي على زيت زيتون يوناني عضوي غني بفيتامين E ومضادات الأكسدة لتنعيم البشرة وحمايتها، وحمض الهيالورونيك بأحجام جزيئية متعددة للترطيب العميق ومنع الجفاف، ونياسيناميد (فيتامين B3) للمساعدة على تقليل البقع ودعم مقاومة علامات التقدم، وببتيدات لشد البشرة وتقليل الخطوط الدقيقة. الفوائد: ترطيب عميق، تقليل التجاعيد والخطوط، تخفيف مظهر التصبغات، ومنح إشراقة طبيعية. قوام خفيف سريع الامتصاص دون إحساس دهني. مختبر جلدياً وخالٍ من البارابين. طريقة الاستخدام: يوضع صباحاً ومساءً على وجه ورقبة نظيفين مع تجنب محيط العين.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:06:25',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(111,'سیڕۆمی قژ و پێست لە بڕاندی سانتۆ ڤۆلکانۆ سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,' ئەم سێرمە بەرهەمێکی فرەکارەیە و هەم بۆ قژ و هەم بۆ پێست بەکاردێت.\r\nپێکهاتە سەرەکییەکانی:\r\n• زەیتی گێزەر (Carrot Oil): دەوڵەمەندە بە ڤیتامینەکان و یارمەتی نوێکردنەوەی خانەکانی پێست و قژ دەدات.\r\n• زەیتی ئەرگانی ئۆرگانیک (Organic Argan Oil): ناسراوە بە \"زێڕی شل\"، شێدارییەکی قووڵ دەبەخشێت و ڕێگری لە وشکبوونەوە دەکات.\r\n• زەیتی ناوکە ترێ (Grapeseed Oil): دژە ئۆکسانێکی بەهێزە و پێست و قژ لە زیانە دەرەکییەکان دەپارێزێت.\r\nسوودەکانی بۆ قژ و پێست:\r\n1. بۆ قژ:\r\n• درەوشاوەیی و نەرمی بە قژ دەبەخشێت.\r\n• یارمەتی چاککردنەوەی سەرتاڵە سووتاوەکان و بژبوونی قژ دەدات.\r\n• بۆ هەموو جۆرە قژێک گونجاوە.\r\n2. بۆ پێست و جەستە:\r\n• پێست بە شێداری دەهێڵێتەوە بەبێ ئەوەی هەستێکی زۆر چەور و ناخۆش جێبهێڵێت.\r\n• پێست نەرم دەکات و یارمەتی گەشانەوەی دەدات.\r\n• بەهۆی زەیتی گێزەرەوە، دەتوانرێت دوای بەرکەوتنی خۆر بەکاربێت بۆ پاراستنی ڕەنگی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n• بۆ قژ: بڕێکی کەم بدە لە قژی تەڕ یان وشک (زیاتر لە ناوەڕاستی قژەکەوە تاوەکو سەرتاڵەکان).\r\n• بۆ جەستە: بڕێکی گونجاو مەساج بکە بە پێستی پاک تاوەکو هەڵیدەمژێت.','Multi-use serum for both hair and skin. Key oils include Carrot Oil rich in vitamins to support renewal, Organic Argan Oil for deep hydration and protection against dryness, and Grapeseed Oil with strong antioxidant properties to help protect hair and skin from external damage. Benefits for hair: adds softness and shine, helps improve the look of damaged ends and reduces breakage, suitable for all hair types. Benefits for body/skin: hydrates without heavy greasy feel, softens skin and supports a healthy glow; can be used after sun exposure to help maintain skin tone. How to use: for hair, apply a small amount to wet or dry hair mainly from mid-lengths to ends; for body, massage onto clean skin until absorbed.','سيروم متعدد الاستخدامات للشعر والبشرة. يحتوي على زيوت أساسية مثل زيت الجزر الغني بالفيتامينات لدعم التجدد، وزيت الأرغان العضوي لترطيب عميق والحماية من الجفاف، وزيت بذور العنب كمضاد أكسدة قوي لحماية الشعر والبشرة من العوامل الخارجية. فوائده للشعر: يمنح نعومة ولمعاناً، يساعد على تحسين مظهر الأطراف المتقصفة وتقليل التكسر، مناسب لجميع أنواع الشعر. فوائده للبشرة/الجسم: يرطب دون إحساس دهني ثقيل، ينعّم البشرة ويدعم إشراقة صحية، ويمكن استخدامه بعد التعرض للشمس للمساعدة في الحفاظ على لون البشرة. طريقة الاستخدام: للشعر تُوضع كمية قليلة على الشعر الرطب أو الجاف من منتصف الشعر حتى الأطراف، وللجسم يُدلّك على بشرة نظيفة حتى الامتصاص.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:09:09',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(112,'سیڕومی درەوشاوەی تایبەت بە پێستی جەستە لە بڕاندی سانتۆ ڤۆلکانۆ سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'ئەم براندە بەوە ناسراوە کە سوود لە پێکهاتەی گڕکانی (Volcanic) و ڕۆنی سروشتی وەردەگرێت.\r\nتایبەتمەندییە سەرەکییەکان:\r\n• درەوشانەوە (Shimmer): ئەم سێرمە بڕێکی زۆر وردیلەی بریسکەداری تێدایە کە ڕەنگێکی زێڕین و سەرنجڕاکێش بە پێست دەبەخشێت، بەتایبەت لەژێر تیشکی خۆر یان ڕووناکیدا.\r\n• شێدارکردن: بەهۆی پێکهاتە ڕۆنییەکانییەوە، پێست بە نەرمی دەهێڵێتەوە و ڕێگری لە وشکبوونەوە دەکات.\r\n• پێکهاتەی سووک: زۆربەی سێرمەکانی ئەم جۆرە بە خێرایی بە پێستدا دەچن و هەستێکی زۆر چەور و ناخۆش جێناهێڵن.\r\nکەی و بۆچی بەکاردێت؟\r\n1. بۆ بۆنە و ئاهەنگەکان: زۆر گونجاوە بۆ کاتێک کە جلی کراوە دەپۆشیت و دەتەوێت قۆڵ، شان یان قاچەکانت درەوشانەوەیەکی تەندروست و جوانیان هەبێت.\r\n2. بۆ هاوین و کەنار دەریا: ڕەنگی ئەسمەری (Tan) پێست تۆختر و جوانتر نیشان دەدات.\r\n3. بۆنێکی خۆش: بەزۆری ئەم جۆرە سێرمانە بۆنێکی سووک و خۆشیان هەیە کە وەک بۆنی جەستە دەمێنێتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• پێش بەکارهێنان بوتڵەکە باش ڕاوەشێنە بۆ ئەوەی ماددە بریسکەدارەکان تێکەڵ ببن.\r\n• بڕێکی گونجاو بدە لەو شوێنانەی جەستەت کە دەتەوێت ببریسکێتەوە.\r\n• چاوەڕێ بکە کەمێک وشک ببێتەوە پێش ئەوەی جل لەبەر بکەیت بۆ ئەوەی پەڵە نەنێت بە جلەکانتەوە.\r\n','Body shimmer serum that combines skin moisturization with a sparkling golden glow. Contains fine shimmer particles that reflect light beautifully, especially under sunlight or bright lighting. The oil-based formula helps keep skin soft and protected from dryness with a lightweight feel that absorbs quickly without an unpleasant greasy sensation. Ideal for occasions and parties, and for summer/beach use to enhance and highlight a tan. Often has a light pleasant scent that lingers like a body fragrance. How to use: shake the bottle well before use so shimmer particles mix evenly, apply to the areas you want to highlight, and allow it to dry before dressing to avoid transferring onto clothing.','سيروم لامع للجسم يجمع بين الترطيب وإشراقة ذهبية متلألئة. يحتوي على جزيئات لامعة دقيقة تعكس الضوء بشكل جميل، خاصة تحت أشعة الشمس أو الإضاءة القوية. تركيبة زيتية تحافظ على نعومة البشرة وتحميها من الجفاف مع قوام خفيف سريع الامتصاص دون إحساس دهني مزعج. مثالي للمناسبات والحفلات، ومناسب للصيف والشاطئ لإبراز لون السُمرة وجعلها أجمل. غالباً برائحة خفيفة لطيفة تدوم مثل عطر للجسم. طريقة الاستخدام: يُرج جيداً قبل الاستعمال لخلط الجزيئات اللامعة، ثم يُوضع على المناطق المراد إبرازها، ويُترك ليجف قليلاً قبل ارتداء الملابس لتجنب انتقال اللمعان إلى القماش.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:10:29',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(113,'سپڕای پاراستن و چاودێری کردنی قژ لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'کە سپرایەکی تایبەتە بۆ پاراستن و چاودێریکردنی قژ، بەتایبەت لە کاتی بەرکەوتنی تیشکی خۆر.\r\n١. پاراستن لە تیشکی خۆر (UV Protection)\r\nئەم سپرایە فلتەری تیشکی سەروو بنەوشەیی (UV) تێدایە. وەک چۆن پێست پێویستی بە دژەخۆر هەیە، قژیش لە کاتی بەرکەوتنی زۆری خۆر تووشی وشکبوونەوە، بێهێزی و گۆڕانی ڕەنگ دەبێت. ئەم بەرهەمە وەک قەڵغانێک قژ دەپارێزێت.\r\n٢. پێکهاتە سەرەکییەکانی\r\nسێ پێکهاتەی گرنگی تێدایە بۆ تەندروستی قژ:\r\n• Hyaluronic Acid (هایالۆرۆنیک ئەسید): یارمەتی شێدارکردنەوەی قژ دەدات لە قووڵاییەوە و ڕێگری لە وشکبوونەوە دەکات.\r\n• Hydrolysed Keratin (کیراتینی شیکراوە): یارمەتی چاککردنەوەی تاڵە قژە زیانلێکەوتووەکان دەدات و قژەکە بەهێز دەکات.\r\n• Wheat Proteins (پڕۆتینی گەنم): بریقە و نەرمی بە قژ دەبەخشێت و وای لێدەکات تەندروست دەربکەوێت.\r\n٣. شێوازی بەکارهێنان\r\n• دەتوانیت لەسەر قژی تەڕ یان وشک بەکاری بهێنیت.\r\n• پێویستە بەسەر قژتدا بیپڕژێنیت و پاشان بە شانە دایبهێنیت.\r\n• تێبینی: پێویست ناکات دوای لێدانی، قژت بشۆیت (Leave-in).\r\n٤. کەی بەکاردێت؟\r\n• بۆ بەکارهێنانی ڕۆژانە گونجاوە.\r\n• زۆر گونجاوە بۆ کاتی چوونە دەریای یان مەلەوانگە، چونکە قژ لە زیانەکانی خۆر و خوێ دەپارێزێت.\r\n','Hair protection and care spray, especially useful during sun exposure. Contains UV filters to help shield hair from sun damage that can cause dryness, weakness, and color fading. Key ingredients: Hyaluronic Acid for deep hydration and to prevent dryness, Hydrolyzed Keratin to repair and strengthen damaged hair fibers, and Wheat Proteins to add softness and shine. Can be used on wet or dry hair. Leave-in formula: no need to rinse after application. How to use: spray over hair and comb through for even distribution. Suitable for daily use and especially recommended for the beach or swimming pool to help protect hair from sun and sea/salt.','بخاخ لحماية الشعر والعناية به، مفيد خصوصاً أثناء التعرض لأشعة الشمس. يحتوي على فلاتر UV للمساعدة في حماية الشعر من أضرار الشمس التي قد تسبب الجفاف والضعف وبهتان اللون. المكوّنات الأساسية: حمض الهيالورونيك لترطيب عميق ومنع الجفاف، كيراتين متحلل (Hydrolyzed Keratin) لإصلاح وتقوية ألياف الشعر المتضررة، وبروتينات القمح لمنح نعومة ولمعاناً. يمكن استخدامه على شعر رطب أو جاف. تركيبة تُترك على الشعر (Leave-in) ولا تحتاج إلى شطف. طريقة الاستخدام: يُرش على الشعر ثم يُمشط لتوزيعه بالتساوي. مناسب للاستخدام اليومي ومُوصى به خاصة للشاطئ أو المسبح لحماية الشعر من الشمس ومياه البحر/الملح.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:13:17',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(114,'پاککەرەوەی نەرمی دەموچاو لە بڕاندی هێربالیسی یۆنانی',NULL,NULL,NULL,15,13500,19000,2750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتە سروشتییەکان: تێکەڵەیەکی تێدایە لە ئۆلیڤ (زەیتوون)، ئەلۆڤێرا، و پانتینۆڵ.\r\n• بەکارهێنان: بۆ پاککردنەوەی دەموچاو و دەوروبەری چاویش گونجاوە.\r\n• جۆری پێست: بۆ هەموو جۆرە پێستەکان گونجاوە و بۆ بەکارهێنانی ڕۆژانە دروستکراوە.\r\n• کاریگەری: کەفێکی زۆر دروست دەکات کە یارمەتی لادانی ماکیاژ و پیسی دەموچاو دەدات، لە هەمان کاتدا پێست بە نەرمی و شێداری دەهێڵێتەوە.\r\nخاڵە ئەرێنییەکانی تر:\r\n• بێ ماددەی زیانبەخش: لەسەری نووسراوە کە بێ پارابین (Parabens Free) و بێ ماددەی هەستیاری (Allergens Free) یە.\r\n• پشکنینی پزیشکی: لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە (Dermatologically Tested).\r\nچەند تێبینییەکی گرنگ\r\n. لەبەر ئەوەی سابوونێکی نەرمە، نابێت پێست وشک بکاتەوە، بەڵام ئەگەر پێستت زۆر هەستیارە هەمیشە باشترە سەرەتا لە بەشێکی بچووکی پێست تاقی بکرێتەوە.\r\nهەنگاوەکانی بەکارهێنان:\r\n1. تەڕکردنی دەموچاو: سەرەتا دەموچاوت بە ئاوێکی شلەتێن (نەک زۆر گەرم) تەڕ بکە. ئاوی شلەتێن یارمەتی کردنەوەی کونیلەکان دەدات.\r\n2. بەکارهێنانی سابوونەکە: بڕێکی گونجاو لە پاککەرەوەکە بدە لە دەستت و کەمێک ئاوی پێوە بکە تاوەکو کەف دروست دەکات.\r\n3. شۆردن و مەساج: کەفەکە بدە لە دەموچاوت. بە شێوەی بازنەیی و بە نەرمی مەساجی پێ بکە، بە تایبەت ئەو شوێنانەی ماکیاژی پێوەیە یان چەوری لێ کۆدەبێتەوە (وەک ناوچەوان و لووت).\r\n4. پاککردنەوەی چاو: بەو پێیەی لەسەر بەرهەمەکە نووسراوە \"بۆ چاو دەبێت\"، دەتوانیت بە وریایی بۆ لادانی ماکیاژی چاویش بەکاری بهێنیت، بەڵام ئاگاداربە نەچێتە ناو چاوتەوە.\r\n5. شووشتن: بە ئاوی سارد یان شلەتێن دەموچاوت بە باشی بشۆ تاوەکو هیچ پاشماوەیەکی سابوونەکەی پێوە نەمێنێت.\r\n6. وشککردنەوە: بە خاولییەکی نەرم و بە شێوەی \"کێشان و دانان\" (نەک سڕین و فشار خستنە سەر) دەموچاوت وشک بکەرەوە.\r\n','Gentle facial cleanser with natural ingredients such as olive oil, aloe vera, and panthenol. Suitable for cleansing the face and also the eye area. Designed for all skin types and daily use. Creates a rich foam that helps remove makeup and impurities while leaving skin soft and hydrated. Labeled paraben-free and allergen-free, and dermatologically tested. Tips for use: wet the face with lukewarm water, lather a small amount in the hands, massage gently in circular motions (especially oily/makeup areas like the T-zone), then rinse with cool or lukewarm water. Pat dry with a soft towel. Can be used to remove eye makeup with care—avoid getting it into the eyes.','منظف وجه لطيف بمكوّنات طبيعية مثل زيت الزيتون والألوفيرا والبانثينول. مناسب لتنظيف الوجه وكذلك منطقة حول العين. مُصمم لجميع أنواع البشرة وللاستخدام اليومي. يُكوّن رغوة جيدة تساعد على إزالة المكياج والشوائب مع ترك البشرة ناعمة ورطبة. مذكور أنه خالٍ من البارابين وخالٍ من مسببات الحساسية ومختبر جلدياً. نصائح الاستخدام: يُبلل الوجه بماء فاتر، تُرغى كمية صغيرة بين اليدين ثم يُدلّك الوجه بحركات دائرية لطيفة (خصوصاً مناطق الدهون/المكياج مثل منطقة الـT)، ثم يُشطف بماء فاتر أو بارد. يُجفف بالتربيت بمنشفة ناعمة. يمكن استخدامه لإزالة مكياج العين بحذر مع تجنب دخوله للعين.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:15:08',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(115,'هێورکەرەوە و شێدارکەرەوەی کاڵامین لۆشن لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'بە تایبەتی بۆ منداڵان و پێستی هەستیار دروستکراوە.\r\nپێکهاتە سەرەکییەکانی:\r\n• کالامین (5% Calamine): ماددەیەکی زۆر کارایە بۆ کەمکردنەوەی خوروو و سووربوونەوەی پێست.\r\n• پانتینۆڵ (Panthenol): یارمەتی چاکبوونەوە و نوێبوونەوەی پێست دەدات.\r\n• شی باتەر (Shea Butter): پێستەکە بە قووڵی شێدار دەکات و دەیپارێزێت.\r\n• پۆلیدۆکانۆڵ (Polidocanol): کاریگەرییەکی خێرای هەیە لە هێورکردنەوەی خوروو.\r\nسوودەکانی و کەی بەکاردێت؟\r\nئەم بەرهەمە بۆ ئەم بارودۆخانەی خوارەوە بەسوودە:\r\n1. خورووی پێست: بە هەموو جۆرەکانییەوە.\r\n2. نەخۆشییە گواستراوەکانی منداڵان: وەک ئاوکوتە (Varicella/Chickenpox) بۆ کەمکردنەوەی خورووەکەی.\r\n3. پێوەدانی مێروو: هێورکردنەوەی شوێنی پێوەدانی مێرووەکان.\r\n4. حەساسییەت و ئەکزیما: کەمکردنەوەی نیشانەکانی حەساسییەت و وشکبوونی زۆری پێست.\r\n5. سووتانەوەی سووک: وەک سووتانەوەی بەهۆی خۆرەوە.\r\nخاڵە ئەرێنییەکان:\r\n• بێ کۆرتیزۆنە (Cortisone Free): بۆیە بەکارهێنانی بۆ ماوەیەکی درێژ سەلامەتە.\r\n• بێ پارابینە (Paraben Free): مەترسی حەساسییەت کەم دەکاتەوە.\r\n• بۆ بەکارهێنانی دەرەکییە: تەنها لەسەر پێست بەکاردێت.\r\nتێبینی: پێش بەکارهێنانی، شوێنەکە باش پاک بکەرەوە و پاشان بڕێکی گونجاو لە گیراوەکە بدە لەو شوێنەی کە خوروو یان سووربوونەوەی هەیە.\r\n','Soothing and moisturizing calamine lotion designed especially for children and sensitive skin. Contains 5% Calamine to help reduce itching and redness, Panthenol to support skin repair and renewal, Shea Butter for deep moisturization and protection, and Polidocanol for fast itch-relief comfort. Useful for: general skin itching, chickenpox-related itching, insect bites, allergies and eczema flare-ups, and mild burns including sunburn. Key features: cortisone-free, paraben-free, and for external use only. How to use: clean the area well, then apply an appropriate amount to the itchy/red area as needed.','لوسيون كالامين مهدئ ومرطب مُصمم خصوصاً للأطفال وللبشرة الحساسة. يحتوي على كالامين 5% للمساعدة على تقليل الحكة والاحمرار، وبانثينول لدعم إصلاح وتجدد البشرة، وزبدة الشيا لترطيب عميق وحماية من الجفاف، وبوليدوكانول لتخفيف سريع للحكة. مناسب لـ: الحكة الجلدية بمختلف أنواعها، حكة الجدري المائي (الحماق)، لدغات الحشرات، الحساسية ونوبات الأكزيما، والحروق الخفيفة بما فيها حروق الشمس. ميزات مهمة: خالٍ من الكورتيزون وخالٍ من البارابين وللاستعمال الخارجي فقط. طريقة الاستخدام: تُنظف المنطقة جيداً ثم توضع كمية مناسبة على موضع الحكة/الاحمرار حسب الحاجة.',NULL,NULL,NULL,NULL,NULL,'2026-01-05 13:17:45',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(116,'لۆشنی دژە مێشوولە مێش و مەگەز لە بڕاندی تانگۆی یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,' کە لۆشنی دژە مێشوولە و مێش و مەگەزە. بەرهەمێکی یۆنانییە و بە شێوەیەکی سەرەکی پشت بە پێکهاتەی سروشتی دەبەستێت.\r\nتایبەتمەندییە سەرەکییەکان\r\n• پێکهاتەی سروشتی: لە ڕۆنی ڕووەکی Eucalyptus citriodora (ئەکالیپتۆسی لیمۆیی) دروستکراوە. هەروەها ڕۆنی بنەڕەتی گەرانیۆم، دارچین، مێخەک و ڕیحانەی تێدایە.\r\n• بەکارهێنان: بۆ پاراستن لە مێشوولە و مێشە وردەکان (midges) بەکاردێت.\r\n• ماوەی کارپێکردن: تاوەکو ٥ کاتژمێر پارێزگاریت لێ دەکات.\r\n• تەمەن: گونجاوە بۆ منداڵانی سەروو ٢ ساڵ.\r\nڕێنمایی بەکارهێنان\r\n١. بڕێکی کەم بدە لەو شوێنانەی جەستە کە دەرکەوتوون (وەک دەست و قاچ).\r\n٢. بۆ دەموچاو: ڕاستەوخۆ مەرشێنە بە دەموچاوتدا؛ سەرەتا بیڕێژە ناو لەپی دەستت و پاشان بە وریایی بیدە لە دەموچاو (دوور بکەوە لە چاو و دەم).\r\n٣. تەنها ڕۆژی یەکجار بەکاری بهێنە.\r\nتێبینییە گرنگەکان\r\n• ئاگاداری: ئەگەر پێستت هەستیاری بە یەکێک لەو ڕۆنە سروشتیانە هەیە، پێش بەکارهێنان لە شوێنێکی بچووکی پێستت تاقی بکەرەوە.\r\n• هەڵگرتن: لە شوێنێکی وشک و فێنک و دوور لە دەستی منداڵان دایبنێ.','Natural-based insect repellent lotion designed to help protect against midges, mosquitoes, and flies. Formulated with plant-derived oil from Eucalyptus citriodora, plus essential oils such as geranium, cinnamon, clove, and basil. Provides protection for up to about 5 hours. Suitable for children over 2 years old. Directions: apply a small amount to exposed skin areas (hands, legs). For face, do not apply directly—first apply to the palm then spread carefully over the face, avoiding eyes and mouth. Use only once per day. Important notes: if you have sensitive skin or sensitivity to essential oils, test on a small area first. Store in a cool, dry place away from children.','لوسيون طارد للحشرات بتركيبة تعتمد بشكل أساسي على مكوّنات طبيعية، للمساعدة في الحماية من الهاموش/الذباب الصغير، والبعوض، والذباب. مُصنّع من زيت نباتي مشتق من Eucalyptus citriodora (الأوكالبتوس الليموني) مع زيوت عطرية مثل إبرة الراعي (جيرانيوم) والقرفة والقرنفل والريحان. يوفر حماية حتى نحو 5 ساعات. مناسب للأطفال فوق عمر سنتين. طريقة الاستخدام: توضع كمية قليلة على مناطق الجلد المكشوفة (مثل اليدين والساقين). للوجه: لا يوضع مباشرة؛ تُوضع أولاً كمية على راحة اليد ثم تُوزع بحذر على الوجه مع تجنب العينين والفم. يُستخدم مرة واحدة يومياً فقط. ملاحظات مهمة: إذا كانت بشرتك حساسة أو لديك تحسس من الزيوت العطرية فاختبره على منطقة صغيرة أولاً. يُحفظ في مكان بارد وجاف وبعيداً عن متناول الأطفال.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 03:51:57',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(117,'کرێمی زێتاسین لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'ئەم کرێمە بە پلەی یەکەم بۆ چارەسەرکردن و ڕێگریکردن لە درزبوونی پێست (Stretch Marks) بەکاردێت\r\n١. بەکارهێنانی سەرەکی\r\n• ڕێگریکردن لە درزبوونی پێست: تایبەت دروستکراوە بۆ ئەو درزانەی بەهۆی دووگیانی، گۆڕانی کێش (قەڵەوبوون و لاوازبوون)، یان گەشەی خێرای کاتی هەرزەکاری دروست دەبن.\r\n• نەرمکردنەوەی پێست: یارمەتی پێست دەدات کە کێش کێش (Elasticity) زۆر بێت بۆ ئەوەی لە کاتی کشاندا نەدڕێت.\r\n٢. تایبەتمەندییەکانی ئەم کرێمە\r\n• pH 5 - 6.5: ئەمەش هاوسەنگە لەگەڵ سروشتی پێست و نابێتە هۆی تێکدانی ترشەڵۆکی پێست.\r\n• Hypo-allergenic: ئەگەری دروستکردنی هەستیاری زۆر کەمە.\r\n• Non-comedogenic: کونیلەکانی پێست ناگرێت و نابێتە هۆی دروستبوونی زیپکە یان چەوری زیادە.\r\n• پێکهاتەی سەرەکی: تێیدا ئاماژە بە (AQUADRM) و (AVOGADINE) کراوە کە بۆ شێدارکردنەوە و پاراستنی پێست بەکاردێن.\r\n٤. چۆنیەتی بەکارهێنان (بە گشتی)\r\nزۆربەی ئەم جۆرە کرێمانە ڕۆژی ٢ جار دەدرێن لەو شوێنانەی کە ئەگەری درزبوونیان هەیە (وەک سک، ڕان، و سنگ) و بە شێوەی بازنەیی مەساجی پێ دەکرێت تا پێستەکە هەڵیدەمژێت.\r\n','Zetasine cream designed mainly to help prevent and improve the appearance of stretch marks. Suitable for stretch marks linked to pregnancy, weight changes (gain or loss), or rapid growth during puberty. Helps soften and improve skin elasticity to reduce the chance of tearing during stretching. Formulated with a skin-friendly pH of about 5–6.5 and labeled hypoallergenic (lower risk of irritation) and non-comedogenic (does not clog pores). Key complexes mentioned include AQUADRM and AVOGADINE for hydration and protection. General directions: apply twice daily to areas prone to stretch marks (such as abdomen, thighs, and chest) and massage in circular motions until absorbed.','كريم Zetasine مُصمم بالدرجة الأولى للمساعدة على الوقاية من علامات تمدد الجلد (Stretch Marks) وتحسين مظهرها. مناسب للتمددات المرتبطة بالحمل، تغيّر الوزن (زيادة أو نقصان)، أو النمو السريع في سن المراهقة. يساعد على تليين البشرة وتحسين مرونتها لتقليل احتمال تشققها أثناء الشد. يتميز بدرجة حموضة مناسبة للبشرة pH حوالي 5–6.5، ومصنف Hypo-allergenic لتقليل احتمال التحسس، وNon-comedogenic بحيث لا يسد المسام ولا يسبب الحبوب. مذكور وجود مركّبي AQUADRM وAVOGADINE لدعم الترطيب والحماية. طريقة الاستخدام العامة: يُوضع مرتين يومياً على المناطق المعرضة للتمدد (مثل البطن والفخذين والصدر) مع تدليك دائري حتى الامتصاص.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 03:54:29',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(118,'پاکەرەوەی سەر و جەستەی منداڵان لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بەکارهێنان: بۆ شتنی سەر و جەستە (Head & Body) بەکاردێت، واتە هەم شامپۆیە و هەم سابوونی شلەیە بۆ پێستی منداڵ.\r\n• جۆری پێست: تایبەت دروست کراوە بۆ پێستی ناسکی منداڵ (Extra Pure for baby\'s fragile skin).\r\n• پێکهاتە گرنگەکان:\r\n• Polysaccharides: یارمەتی پاراستنی شێداری پێست دەدەن.\r\n• Vitamins F & B5: بۆ نەرمکردنەوە و تەندروستی پێست و قژ.\r\n• Oat & Chamomile: گیراوەی ڕووەکی (ئۆت و بەیبوون) کە کاردەکەن بۆ هێورکردنەوەی پێست و ڕێگری لە سووربوونەوە و خوران.\r\nسوودەکانی ئەم بەرهەمە:\r\n1. ناسووتێنێت: بە شێوەیەک دروست کراوە کە چاوی منداڵ نەکزێنێت (ئەمە تایبەتمەندی زۆربەی بەرهەمە دەرمانسازییەکانە).\r\n2. دژە هەستیاری: بەهۆی ئەوەی وشەی Dermopediatric لەسەرە، واتە لەژێر چاودێری پزیشکی پێست تاقیکراوەتەوە و بۆ پێستی زۆر ناسکیش گونجاوە.\r\n3. پاراستنی شێداری: پێستی منداڵ وشک ناکاتەوە دوای حەمامکردن.\r\nچۆنیەتی بەکارهێنان:\r\nبڕێکی گونجاو بدە لە جەستە و سەری تەڕی منداڵەکە، بە هێواشی مەساجی پێ بکە تا کەف دەکات، پاشان بە ئاوێکی شلەتێن لێی بکەرەوە.\r\nتێبینی: ئەگەر منداڵەکەت کێشەیەکی تایبەتی پێستی هەیە (وەک ئەکزیما)، هەمیشە باشترە پێشتر ڕاوێژ بە پزیشکی منداڵان بکەیت.\r\n','Baby head & body cleanser designed for washing both hair and body. Specially made for babies’ delicate skin (“Extra Pure for baby’s fragile skin”). Key ingredients include polysaccharides to help protect skin hydration, Vitamins F & B5 for softness and healthy skin/hair, and botanical extracts of oat and chamomile to soothe and help reduce redness and irritation. Gentle formula that does not sting the eyes and is dermopediatric-tested for very sensitive baby skin. Helps prevent dryness after bathing. How to use: apply an appropriate amount to baby’s wet body and hair, massage gently to form a light lather, then rinse with lukewarm water. Note: if your child has a specific skin condition such as eczema, consult a pediatrician/doctor before use.','منظف للأطفال للرأس والجسم، يُستخدم لغسل الشعر والجسم معاً. مُصمم خصيصاً لبشرة الأطفال الحساسة (“Extra Pure for baby’s fragile skin”). يحتوي على عديدات السكاريد للمساعدة على حماية ترطيب البشرة، وفيتامينات F وB5 للنعومة ودعم صحة البشرة والشعر، ومستخلصات نباتية من الشوفان والبابونج لتهدئة البشرة وتقليل الاحمرار والتهيج. تركيبة لطيفة لا تلسع العينين ومختبرة تحت إشراف طب الجلد للأطفال (Dermopediatric) ومناسبة حتى للبشرة شديدة الحساسية. تساعد على منع جفاف البشرة بعد الاستحمام. طريقة الاستخدام: توضع كمية مناسبة على جسم وشعر الطفل المبللين، تُدلّك بلطف لتكوين رغوة خفيفة ثم تُشطف بماء فاتر. ملاحظة: إذا كان لدى الطفل مشكلة جلدية خاصة مثل الأكزيما، يُفضّل استشارة طبيب الأطفال قبل الاستخدام.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 03:57:01',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(119,'سپڕای دژە ئارەقکردنەوەی تایبەت بە پیاوان لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,6000,10000,2000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• ڕێکخەری ئارەقەکردنەوە: یارمەتیدەرە بۆ کۆنتڕۆڵکردنی ئارەقەکردنەوەی نائاسایی و زۆر (Excessive Perspiration).\r\n• پاراستنی ٢٤ کاتژمێری: کاردەکات بۆ ڕێگریکردن لە دروستبوونی بۆنی ناخۆش و ئارەقە بۆ ماوەی شەو و ڕۆژێک.\r\n• بۆ پێستی هەستیار: بە شێوەیەک دروستکراوە کە نابێتە هۆی سووربوونەوە یان خوران (Dermo-Sensitive).\r\n• کرداری بایۆلۆژی سروشتی: وەک لەسەری نووسراوە \"Natural Bioaction\"، واتە هەوڵ دەدات بە شێوەیەکی هاوسەنگ لەگەڵ سروشتی پێست کار بکات.\r\nچۆنیەتی بەکارهێنان:\r\n١. پێش بەکارهێنان، پێویستە شوێنەکە (بۆ نموونە بنباڵ) بە باشی پاک بێت و وشک بێتەوە.\r\n٢. بڕێکی گونجاو لە دووری ١٥ سم بپڕژێنە سەر پێستت.\r\n٣. دەتوانیت ڕۆژانە یان بەپێی پێویست بەکاریبهێنیت.\r\nتێبینی گرنگ:\r\n• ئەم بەرهەمە زیاتر بۆ ئەو کەسانە باشە کە کێشەی ئارەقەکردنەوەی زۆریان هەیە نەک تەنها بۆ بۆنی خۆش.\r\n','Men’s antiperspirant spray designed to help regulate excessive sweating and reduce unpleasant odor for up to 24 hours. Formulated for sensitive skin to minimize redness or irritation (dermo-sensitive). Labeled “Natural Bioaction” to indicate a balanced action that works in harmony with the skin. How to use: ensure the target area (e.g., underarms) is clean and dry, spray from about 15 cm distance, and use daily or as needed. Note: best suited for those with heavy sweating rather than only for fragrance.','بخاخ مضاد للتعرق مخصص للرجال للمساعدة على تنظيم التعرق الزائد وتقليل الرائحة غير المرغوبة حتى 24 ساعة. تركيبة مناسبة للبشرة الحساسة لتقليل الاحمرار أو التهيج (Dermo-Sensitive). مذكور “Natural Bioaction” للدلالة على عمل متوازن ينسجم مع طبيعة البشرة. طريقة الاستخدام: تُنظف المنطقة المستهدفة (مثل الإبط) وتُجفف جيداً، ثم يُرش من مسافة حوالي 15 سم. يُستخدم يومياً أو حسب الحاجة. ملاحظة: مناسب أكثر لمن لديهم تعرق غزير وليس فقط للحصول على رائحة عطرية.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 03:58:48',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(120,'سپڕای دژە ئارەقکردنەوەی تایبەت بە ئافرەتان لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,6000,10000,2000,1,'. ئەرکی سەرەکی\r\nئەم سپرایە دیزاین کراوە بۆ ئەو کەسانەی کە کێشەی ئارەقەکردنەوەی زۆریان (Hyperhidrosis) هەیە. وەک ڕێکخەرێک کاردەکات بۆ کەمکردنەوەی ڕێژەی ئارەقە و ڕێگریگرتن لە دروستبوونی بۆنی ناخۆش.\r\n٢. تایبەتمەندییەکان\r\n• پاراستنی ٢٤ کاتژمێری: بۆ ماوەی شەو و ڕۆژێک کاریگەری دەمێنێت.\r\n• Natural Bioaction: ئاماژەیە بۆ ئەوەی کە پێکهاتەکانی بە جۆرێک ڕێکم خراون کە کاریگەری سروشتییان هەبێت لەسەر پێست بەبێ تێکدانی هاوسەنگی بایۆلۆژی پێست.\r\n• Dermo-Sensitive: گونجاوە بۆ پێستە هەستیارەکان و نابێتە هۆی سووربوونەوە یان خوران.\r\n٣. چۆنیەتی بەکارهێنان\r\n• پێش بەکارهێنان پێویستە جێگای مەبەست (بۆ نموونە بنباڵ) بە باشی بشۆردرێت و وشک بکرێتەوە.\r\n• سپرایەکەی لێ بدە و کەمێک بوەستە تا وشک دەبێتەوە پێش ئەوەی جلی لەبەر بکەیت.\r\n• بەزۆری لە کاتی پێویستدا یان ڕۆژی یەکجار بەکاردێت.\r\n','Women’s antiperspirant spray designed for people with excessive sweating (hyperhidrosis). Helps reduce sweat and prevent unpleasant odor with up to 24-hour protection. Labeled “Natural Bioaction” to indicate a skin-friendly balanced action without disturbing the skin’s biological balance, and “Dermo-Sensitive” to suit sensitive skin and reduce irritation. How to use: wash the target area (e.g., underarms), dry well, spray and allow to dry before dressing. Typically used once daily or as needed.','بخاخ مضاد للتعرق مخصص للنساء ومصمم لمن يعانون من فرط التعرق (Hyperhidrosis). يساعد على تقليل التعرق ومنع الرائحة غير المرغوبة مع حماية قد تمتد حتى 24 ساعة. مذكور “Natural Bioaction” للدلالة على تأثير متوازن لطيف على البشرة دون إرباك توازنها البيولوجي، ومذكور “Dermo-Sensitive” ليكون مناسباً للبشرة الحساسة ويقلل التهيج. طريقة الاستخدام: تُغسل المنطقة المستهدفة (مثل الإبط) وتُجفف جيداً، ثم يُرش المنتج ويُترك ليجف قبل ارتداء الملابس. غالباً يُستخدم مرة يومياً أو حسب الحاجة.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 04:00:07',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(121,'شامپۆی ڕێنێکس پڵەس لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,26000,3000,1,'پێکهاتە سەرەکییەکانی:\r\n• قەترانی بی (Willow Tar) بە ڕێژەی 10%: ئەمە پێکهاتەیەکی سروشتییە و یارمەتی کەمکردنەوەی خوران و هەوکردنی پێست دەدات.\r\n• گۆگرد (Sulfur): ناسراوە بەوەی دژی بەکتریا کار دەکات.\r\nبۆچی بەکاردێت؟\r\nئەم شامپۆیە بە پلەی یەکەم بۆ ئەم مەبەستانە بەکاردێت:\r\n1. چارەسەری کڕێشی سەر: بەتایبەت ئەو کڕێشانەی زۆرن و بە شامپۆی ئاسایی ناڕۆن.\r\n2. سەدەف (Psoriasis): یارمەتی کەمکردنەوەی ئەو توێژاڵە ئەستوورانە دەدات کە بەهۆی سەدەفەوە لەسەر پێستی سەر دروست دەبن.\r\n3. هەوکردنی پێستی چەوری (Seborrheic Dermatitis): بۆ ئەو کەسانەی پێستی سەریان زۆر چەورە و سوور دەبێتەوە و دەخورێت.\r\n4. کەمکردنەوەی خوران و سووربوونەوە: بەهۆی تایبەتمەندییە هێورکەرەوەکانی قەترانەکە.\r\nخاڵە گرنگەکان:\r\n• pH 5.5-7: هاوسەنگە و نابێتە هۆی وشکبوونەوەی زۆری پێست یان تێکدانی ترشێتی سروشتی پێست.\r\n• بێ ئەلکەهول (Non-Alkaline): ئەمە وای لێدەکات بۆ پێستی هەستیار گونجاوتر بێت.\r\nچۆن بەکاردێت؟\r\nزۆربەی شامپۆ چارەسەرییەکان بەم شێوەیە بەکاردێن (مەگەر پزیشک یان دەرمانساز شێوازێکی تری پێ وتبێتی):\r\n1. قژت تەڕ بکە و بڕێکی گونجاو لە شامپۆکە بدە لە پێستی سەرت.\r\n2. بە نوکی پەنجەکانت (نەک بە نینۆک) مەساجی پێ بکە.\r\n3. بۆ ماوەی 3 بۆ 5 خولەک بە قژتەوە بیهێڵەرەوە تا ماددەکان کار بکەن.\r\n4. پاشان بە باشی بە ئاو بیشۆ.\r\nتێبینی: بەهۆی هەبوونی قەتران و گۆگرد، لەوانەیە بۆنێکی تایبەتی هەبێت کە کەمێک تیژ بێت، بەڵام بۆ چارەسەر زۆر کاریگەرە.\r\n','Rinex Plus therapeutic shampoo formulated with 10% Willow Tar and Sulfur. Designed primarily for stubborn dandruff, scalp psoriasis, and seborrheic dermatitis (oily, red, itchy scalp). Helps reduce itching, redness, and flaking thanks to the soothing properties of tar and the antibacterial benefits of sulfur. Balanced pH (about 5.5–7) and described as non-alkaline to be more suitable for sensitive scalp. How to use: wet hair, apply an appropriate amount to the scalp, massage gently with fingertips (not nails), leave on for 3–5 minutes, then rinse thoroughly. Note: due to tar and sulfur it may have a distinctive strong smell, but it is described as effective for treatment.','شامبو علاجي Rinex Plus يحتوي على قطران الصفصاف (Willow Tar) بنسبة 10% مع الكبريت. مُخصص بالدرجة الأولى للقشرة الشديدة والعنيدة، وصدفية فروة الرأس، والتهاب الجلد الدهني (فروة دهنية مع احمرار وحكة). يساعد على تقليل الحكة والاحمرار والتقشر بفضل خصائص القطران المهدئة وفوائد الكبريت المضادة للبكتيريا. يتميز بدرجة حموضة متوازنة تقريباً (pH 5.5–7) ومذكور أنه غير قلوي ليكون أنسب لفروة الرأس الحساسة. طريقة الاستخدام: يُبلل الشعر، توضع كمية مناسبة على فروة الرأس، تُدلّك بلطف بأطراف الأصابع (دون الأظافر)، يُترك 3–5 دقائق ثم يُشطف جيداً. ملاحظة: بسبب القطران والكبريت قد تكون له رائحة قوية مميزة، لكنه يوصف بأنه فعّال علاجياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 04:02:46',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(122,'شامپۆی کلیمبازۆڵ لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,25000,2500,1,'کە شامپۆیەکی پزیشکی تایبەتە بۆ چارەسەرکردنی کێشەکانی پێستی سەر، بەتایبەت ئەو جۆرانەی پەیوەندییان بە کەڕووەوە هەیە.\r\nپێکهاتەی سەرەکی و تایبەتمەندییەکان\r\n• Climbazole (کلیمبازۆڵ): ماددەیەکی دژە کەڕووی بەهێزە. کاردەکات بۆ لەناوبردنی ئەو میکرۆبانەی دەبنە هۆی دروستبوونی کڕێش و خوران.\r\n• Tar-Free: وەک لەسەر کارتۆنەکە نوسراوە \"بێ قەترانە\"، ئەمەش باشە چونکە هەندێک شامپۆی کڕێش قەترانیان تێدایە کە بۆنی ناخۆشە و ڕەنگی قژ دەگۆڕێت، بەڵام ئەمەیان ئەو کێشەیەی نییە\r\nسوودەکانی ئەم شامپۆیە\r\n1. چارەسەری کڕێش: بۆ ئەو کەسانە زۆر باشە کە کڕێشی زۆر و بەردەوامیان هەیە (چ کڕێشی وشک یان چەور).\r\n2. کەمکردنەوەی خوران: یارمەتی هێورکردنەوەی پێستی سەر دەدات و ئەو خورانە توندە ناهێڵێت کە بەهۆی کڕێشەوە دروست دەبێت.\r\n3. کۆنتڕۆڵکردنی چەوری: یارمەتی ڕێکخستنەوەی دەردانی چەوری پێستی سەر دەدات.\r\n4. چارەسەری سەدەف و ئەکزیما: زۆرجار پزیشکان بۆ حاڵەتەکانی (Seborrheic Dermatitis) یان سەدەفی سوکی پێستی سەر پێشنیاری دەکەن.\r\nچۆنیەتی بەکارهێنان (بە شێوەیەکی گشتی)\r\n• بڕێکی گونجاو لە شامپۆکە بدە لە قژی تەڕ.\r\n• بە سەری پەنجەکانت مەساجی پێستی سەری پێ بکە (نەک بە نینۆک).\r\n• گرنگە: وازی لێ بهێنە بۆ ماوەی ٢ بۆ ٣ خولەک بە پێستی سەرەوە بمێنێتەوە تا ماددە کاریگەرەکان کار بکەن، پاشان بە باشی بە ئاو بیشۆ.\r\n• بە گشتی هەفتەی ٢ بۆ ٣ جار بەکاردێت\r\n','Climbazole medicated shampoo designed to treat scalp problems related to dandruff and fungal overgrowth. Climbazole is a strong anti-dandruff/antifungal active that helps eliminate microorganisms that cause dandruff, itching, and irritation. Labeled tar-free to avoid the unpleasant smell and hair discoloration some tar shampoos may cause. Benefits: reduces dandruff, calms itching, helps regulate scalp oil, and may be recommended for seborrheic dermatitis or mild scalp eczema. How to use: apply to wet hair, massage gently with fingertips, leave on for 2–3 minutes so actives can work, then rinse well. Typically used 2–3 times per week.','شامبو علاجي يحتوي على كليمبازول (Climbazole) لعلاج مشاكل فروة الرأس المرتبطة بالقشرة وزيادة الفطريات. كليمبازول مادة فعالة قوية مضادة للقشرة ومضادة للفطريات تساعد على القضاء على الكائنات الدقيقة المسببة للقشرة والحكة والتهيج. مُصنف Tar-Free (خالٍ من القطران) لتجنب الرائحة القوية وتغير لون الشعر التي قد تحدث مع بعض شامبوهات القطران. الفوائد: تقليل القشرة، تهدئة الحكة، المساعدة في تنظيم دهون فروة الرأس، وقد يُنصح به لالتهاب الجلد الدهني أو الإكزيما الخفيفة في الفروة. طريقة الاستخدام: يوضع على شعر مبلل مع تدليك لطيف بأطراف الأصابع، يُترك 2–3 دقائق ليعمل المكوّن الفعال ثم يُشطف جيداً. عادة يُستخدم 2–3 مرات أسبوعياً.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:22:59',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(123,'شامپۆی نینۆلینی تایبەت بە منداڵان لە بڕاندی فرۆیکای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'بەکارهێنانی سەرەکی\r\nئەم شامپۆیە بە پلەی یەکەم بۆ چارەسەرکردن و پاککردنەوەی کڕێشی سەری کۆرپەلە (Cradle Cap) بەکاردێت. کڕێشی کۆرپەلە ئەو توێژاڵە چەور و زەردانەیە کە زۆرجار لەسەر پێستی سەری منداڵی تازە لەدایکبوو دروست دەبێت.\r\nپێکهاتە گرنگەکانی\r\n• Capryloyl Glycine: وەک ماددەیەکی دژە بەکتریا و دژە کەڕوو کاردەکات، یارمەتی ڕێکخستنی چەوری سەر دەدات.\r\n• Vitamins F & B5: بۆ نەرمکردنەوەی پێست و بەهێزکردنی خانەکانی پێستی سەر.\r\n• Botanical Extracts (Oat & Chamomile): گیراوەی ڕووەکی وەک شۆفان و بەیبوون کە تایبەتمەندی هێورکەرەوەیان هەیە و ڕێگری لە سووربوونەوە و خورانی پێست دەکەن.\r\nتایبەتمەندییەکان\r\n1. نەرم و بێزارکەر نییە: بە شێوەیەک دروست کراوە کە چاو نانوتێنێتەوە و گونجاوە بۆ پێستی هەستیاری منداڵ.\r\n2. پاککەرەوەی چەوری: یارمەتی لادانی توێژاڵە مردووەکان و چەورییە زیادەکانی سەر دەدات بەبێ ئەوەی پێستەکە وشک بکاتەوە.\r\n3. پارێزگاری: ڕێگری دەکات لە دووبارە دروستبوونەوەی کڕێشەکە.\r\nچۆن بەکاردێت؟\r\n• بڕێکی کەم لە شامپۆکە بدە لە سەری تەڕی منداڵەکە.\r\n• بە هێواشی مەساجی پێ بکە و با بۆ ماوەی ٢ بۆ ٣ خولەک بە سەریا بمێنێتەوە.\r\n• پاشان بە ئاوێکی شلەتێن بە باشی دەیشۆیت.\r\nتێبینی: ئەگەر منداڵەکەت کێشەی پێستی زۆر تووندی هەیە یان برینی لەسەر سەری دروست بووە، باشترە پێش بەکارهێنان ڕاوێژ بە پزیشکی منداڵان بکەیت.\r\n','Ninolini baby shampoo designed mainly to treat and cleanse cradle cap (the yellowish greasy scales on a newborn’s scalp). Key ingredients include Capryloyl Glycine for antibacterial/antifungal action and to help regulate scalp oil, Vitamins F & B5 to soften and strengthen the scalp skin barrier, and botanical extracts (oat and chamomile) to soothe and reduce redness and itching. Gentle tear-free formula suitable for sensitive baby scalp. Helps remove built-up scales and reduce recurrence. How to use: apply a small amount to the baby’s wet scalp, massage gently and leave for 2–3 minutes, then rinse well with lukewarm water. Note: if there is severe irritation or wounds, consult a pediatrician before use.','شامبو Ninolini للأطفال مخصص بالدرجة الأولى لعلاج وتنظيف قشرة المهد (Cradle Cap) وهي القشور الدهنية الصفراء التي تظهر غالباً على فروة رأس حديثي الولادة. من المكوّنات المهمة: Capryloyl Glycine بخصائص مضادة للبكتيريا والفطريات وللمساعدة في تنظيم دهون الفروة، فيتامينات F وB5 لتنعيم وتقوية حاجز الجلد في الفروة، ومستخلصات نباتية (الشوفان والبابونج) لتهدئة البشرة وتقليل الاحمرار والحكة. تركيبة لطيفة لا تلسع العين ومناسبة لفروة رأس الطفل الحساسة. تساعد على إزالة التراكمات وتقليل عودة القشرة. طريقة الاستخدام: توضع كمية صغيرة على فروة رأس الطفل المبللة، تُدلّك بلطف وتُترك 2–3 دقائق ثم تُشطف جيداً بماء فاتر. ملاحظة: إذا كانت هناك تهيجات شديدة أو جروح على الفروة يُفضّل استشارة طبيب الأطفال قبل الاستخدام.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:24:35',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(124,'فۆمی پاکەرەوەی دەم و چاوی سانتۆ ڤۆلکانۆ سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'پێکهاتەیەکی یۆنانییە و بەوە ناسراوە کە سوود لە کەرەستە سروشتییەکانی ناوچەی ڤۆڵکانی (ئاگرپژێن) دەبینێت.\r\nپێکهاتە گرنگەکان:\r\n• ڕۆنی زەیتونی ئۆرگانیک: بۆ شێدارکردنەوە و نەرمکردنی پێست.\r\n• تێکهەڵکێشی چای سەوز: وەک دژە ئۆکسان کاردەکات و پێست لە پیسی دەپارێزێت.\r\n• ئاوی ڤۆڵکانی: دەوڵەمەندە بە کانزاکان کە یارمەتی نوێکردنەوەی پێست دەدەن.\r\n• جۆری پێست: گونجاوە بۆ هەموو جۆرە پێستەکان.\r\nسوودەکانی ئەم فۆمە:\r\n1. پاککردنەوەی قووڵ: یارمەتی لادانی چەوری زیادە، تۆز و غوبار، و پاشماوەی مکیاژ دەدات بەبێ ئەوەی پێست وشک بکاتەوە.\r\n2. هێورکردنەوەی پێست: بەهۆی هەبوونی چای سەوز، سووربوونەوە و هەستیاری پێست کەمدەکاتەوە.\r\n3. پاراستنی شێداری: بە پێچەوانەی سابوونە ئاساییەکان، ئەم فۆمە هاوسەنگی شێداری سروشتی پێست دەپارێزێت.\r\n4. دژە پیربوون: کانزاکانی ناو ئاوی ڤۆڵکانی یارمەتی توندکردنەوە و گەشانەوەی پێست دەدەن.\r\nچۆن بەکاردێت؟\r\n• بڕێکی گونجاو لە فۆمەکە بخەرە سەر لەپی دەستت.\r\n• لەسەر پێستی تەڕ (دەموچاو و مل) بە شێوەی بازنەیی مەساژی پێ بکە.\r\n• پاشان بە ئاوێکی شلەتێن بە باشی دەموچاوت بشۆ.\r\nتێبینی: باشترە ڕۆژی دوو جار (بەیانیان و شەوان پێش خەوتن) بەکاربهێنرێت بۆ ئەوەی باشترین ئەنجامت دەستبکەوێت.\r\n','Greek cleansing foam inspired by natural volcanic ingredients. Key ingredients include organic olive oil to moisturize and soften, green tea extract as an antioxidant to protect the skin from impurities, and volcanic water rich in minerals that support skin renewal. Suitable for all skin types. Benefits: deep cleansing that removes excess oil, dust, and makeup residue without drying; helps soothe redness and sensitivity; supports the skin’s natural moisture balance; and helps promote a firmer, more revitalized look. How to use: pump an appropriate amount into your palm, massage gently in circular motions on wet face (including eye area) and neck, then rinse well with lukewarm water. Note: best used twice daily (morning and night).','رغوة تنظيف يونانية مستوحاة من مكوّنات بركانية طبيعية. من المكوّنات الأساسية: زيت الزيتون العضوي لترطيب وتنعيم البشرة، خلاصة الشاي الأخضر كمضاد أكسدة للمساعدة في حماية البشرة من الشوائب، وماء بركاني غني بالمعادن يدعم تجدد البشرة. مناسبة لجميع أنواع البشرة. الفوائد: تنظيف عميق يزيل الدهون الزائدة والغبار وبقايا المكياج دون التسبب بجفاف؛ يساعد على تهدئة الاحمرار والحساسية؛ يدعم توازن الترطيب الطبيعي للبشرة؛ ويساعد على منح البشرة مظهراً أكثر تماسكاً وحيوية. طريقة الاستخدام: توضع كمية مناسبة على راحة اليد، تُدلّك بلطف بحركات دائرية على الوجه (بما في ذلك محيط العين) والرقبة وهي مبللة، ثم تُشطف جيداً بماء فاتر. ملاحظة: يُفضّل استخدامها مرتين يومياً صباحاً ومساءً.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:26:30',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(125,'فۆمی پاکەرەوەی دەم و چاو لە بڕاندی ئۆلیڤا سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'پێکهاتە سەرەکییەکانی:\r\n• ئەلۆڤێرا (Aloe Vera): یارمەتیدەرە بۆ هێورکردنەوەی پێست و شێدارکردنەوەی.\r\n• ڕۆنی زەیتونی بایۆ (Bio Olive Oil): پێست بە نەرمی دەهێڵێتەوە و ناهێڵێت وشک ببێتەوە دوای ششتن.\r\n• گیراوەی چای سەوز (Green Tea Extract): وەک دژە ئۆکسان کار دەکات و پێست لە پیسی دەپارێزێت.\r\nتایبەتمەندییە گرنگەکان:\r\n1. کەف (Foam): ئەم بەرهەمە بە شێوەی کەف دێتە دەرەوە، کە زۆر سوکە لەسەر پێست و بە ئاسانی پاکی دەکاتەوە.\r\n2. بایۆ (Bio): ئاماژە بەوە دەکات کە پێکهاتە سەرەکییەکانی سروشتین و کوالێتییان بەرزە.\r\n3. بۆ هەموو جۆرە پێستێک: بەهۆی هەبوونی ئەلۆڤێرا و زەیتون، بە گشتی بۆ پێستی هەستیاریش گونجاوە.\r\nسوودەکانی:\r\n• پاشماوەی ماکیاژ و تۆز و غوباری ڕۆژانە لادەبات.\r\n• پێست بە گەشی دەهێڵێتەوە.\r\n• هەستی وشکبوونەوەی زۆر بە پێست نابەخشێت (بە پێچەوانەی سابوونی ئاسایی).\r\nتێبینی: ئەگەر پێستت زۆر چەورە یان زیپکەی زۆری هەیە، ڕەنگە پێویستت بە پاککەرەوەیەک بێت کە ماددەی بەهێزتری تێدا بێت، بەڵام بۆ بەکارهێنانی ڕۆژانە و پاراستنی نەرمی پێست، ئەم براندە زۆر باشە.\r\nهەنگاوەکانی بەکارهێنان:\r\n1. تەڕکردنی دەموچاو: سەرەتا دەموچاوت بە ئاوی شلەتێن کەمێک تەڕ بکە. (ئاوی زۆر گەرم بەکارمەهێنە چونکە پێست وشک دەکاتەوە).\r\n2. بەکارهێنانی کەفەکە: بڕی یەک بۆ دوو فشار (Pump) لە کەفەکە بدە لە لەپی دەستت.\r\n3. شێلانی پێست: بە شێوەی بازنەیی و بە نەرمی کەفەکە لە دەموچاوت بدە. گرنگی بدە بەو شوێنانەی کە چەورییان زیاترە وەک (تەوێڵ، لووت، و چەناگە).\r\n4. شتن: بۆ ماوەی 30 بۆ 60 چرکە بەردەوام بە لە شێلانی، پاشان بە ئاوی سارد یان شلەتێن دەموچاوت بشۆ تا هەموو کەفەکە لادەچێت.\r\n5. وشککردنەوە: بە خاولییەکی نەرم یان کلێنس بە شێوەی \"لێدان\" (نەک سڕینی توند) دەموچاوت وشک بکەرەوە.\r\n','Greek face and eye cleansing foam with soothing aloe vera, bio olive oil, and green tea extract. Aloe vera helps calm and hydrate, olive oil helps soften and prevents dryness after cleansing, and green tea provides antioxidant protection against daily impurities. Suitable for all skin types, including sensitive skin. Benefits: removes makeup residue, dust, and everyday impurities while leaving the skin fresh and comfortable without tightness. How to use: wet the face with lukewarm water, pump 1–2 pumps into your palm, massage gently in circular motions (focus on oily areas like forehead, nose, and chin), then rinse well and pat dry. Note: ideal for daily use; if your skin is very oily or has heavy acne, you may need a stronger acne-focused cleanser alongside it.','رغوة تنظيف للوجه والعين من اليونان تحتوي على الألوفيرا وزيت الزيتون العضوي وخلاصة الشاي الأخضر. تساعد الألوفيرا على تهدئة البشرة وترطيبها، ويساعد زيت الزيتون على تنعيم البشرة ومنع الجفاف بعد الغسل، بينما يوفر الشاي الأخضر حماية مضادة للأكسدة ضد الشوائب اليومية. مناسبة لجميع أنواع البشرة بما فيها الحساسة. الفوائد: تزيل بقايا المكياج والغبار والشوائب اليومية وتترك البشرة منتعشة ومريحة دون شدّ أو جفاف. طريقة الاستخدام: يُبلّل الوجه بماء فاتر، تُؤخذ 1–2 ضغطة على راحة اليد، تُدلّك بلطف بحركات دائرية (خصوصاً مناطق الدهون مثل الجبهة والأنف والذقن)، ثم تُشطف جيداً وتُجفف بالتربيت. ملاحظة: مناسبة للاستخدام اليومي؛ وإذا كانت البشرة شديدة الدهنية أو حب الشباب قويّاً فقد تحتاجين إلى غسول أقوى مخصص للحبوب إلى جانبها.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:27:45',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(126,'ڕۆنی دارچا(تیە تری ئۆیل) لە بڕاندی ئۆلیڤا سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتە: ١٠٠٪ سروشتییە و ڤیتامین E (Extra Vitamin E) بۆ زیاد کراوە، کە یارمەتی تەندروستی پێست و پاراستنی ڕۆنەکە دەدات.\r\nسوودەکانی ڕۆنی دار چا:\r\nئەم ڕۆنە بەوە ناسراوە کە دژە بەکتریا، دژە کەڕوو و دژە هەوکردنێکی بەهێزە، و بۆ ئەم مەبەستانە بەکاردێت:\r\n1. بۆ پێست (چارەسەری زیپکە): یەکێکە لە باشترین چارەسەرە سروشتییەکان بۆ وشککردنەوە و نەهێشتنی زیپکە، چونکە بەکتریاکانی ناو کونیلەکانی پێست دەکوژێت.\r\n2. بۆ قژ (کڕێش): دەکرێت چەند دڵۆپێکی لێ تێکەڵ بە شامپۆ بکرێت بۆ چارەسەری کڕێشی سەر و خوورانی پێستی سەر.\r\n3. دژە کەڕوو: بۆ چارەسەری کەڕووی نێوان پەنجەکانی قاچ یان نینۆک بەکاردێت.\r\n4. پاککەرەوە: بەهۆی سیفەتە دژە بەکتریایەکەیەوە، هەندێک جار بۆ پاککردنەوەی برینە بچووکەکان یان وەک تەعقیمکەر بەکاردێت.\r\nچۆنیەتی بەکارهێنان و ئاگاداری:\r\n• تێست بکە: پێش ئەوەی بەکاری بهێنیت، دڵۆپێکی لە بەشێکی بچووکی پێستت بدە (وەک مەچەک) بۆ ئەوەی دڵنیا بیتەوە کە حەساسیەتت پێی نییە.\r\n• تێکەڵکردن: چونکە ئەمە ڕۆنێکی خەستە، باشترە ڕاستەوخۆ بە بڕی زۆر لە پێستی نەدەیت؛ دەتوانیت لەگەڵ \"ڕۆنی گواستنەوە\" وەک ڕۆنی زەیتون یان باوی تێکەڵ بکەیت ئەگەر پێستت هەستیارە.\r\n• تەنها بۆ دەرەوە: ئەم ڕۆنە بە هیچ شێوەیەک ناخورێت و نابێت بەر چاو بکەوێت.\r\n','100% natural tea tree oil enriched with extra vitamin E to support skin health and help preserve the oil. Tea tree oil is known for strong antibacterial, antifungal, and anti-inflammatory properties. Common uses: for acne-prone skin (helps reduce pimples by targeting bacteria), for scalp issues like dandruff (add a few drops to shampoo), and for fungal concerns such as athlete’s foot or nail area (external use only). How to use & caution: patch test first on a small area; because it is concentrated, dilute with a carrier oil (such as olive oil) if your skin is sensitive. For external use only and avoid contact with eyes.','زيت شجرة الشاي طبيعي 100% ومُعزّز بفيتامين E إضافي لدعم صحة البشرة والمساعدة في الحفاظ على جودة الزيت. يُعرف زيت شجرة الشاي بخصائص قوية مضادة للبكتيريا والفطريات ومضادة للالتهاب. الاستخدامات الشائعة: للبشرة المعرضة لحب الشباب (يساعد على تقليل الحبوب باستهداف البكتيريا)، ولمشاكل فروة الرأس مثل القشرة (تضاف بضع قطرات إلى الشامبو)، وللمشاكل الفطرية مثل فطريات القدم أو منطقة الأظافر (للاستخدام الخارجي فقط). طريقة الاستخدام والتحذيرات: يُنصح باختبار الحساسية أولاً على مساحة صغيرة؛ ولأنه مركز يُفضّل تخفيفه بزيت ناقل مثل زيت الزيتون عند البشرة الحساسة. للاستعمال الخارجي فقط وتجنب ملامسة العينين.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:29:22',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(127,'ڕۆنی جۆجۆبابا لە بڕاندی ئۆلیڤا سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکانی ئەم بەرهەمە:\r\n• پێکهاتەی سروشتی:  100% سروشتییە.\r\n• دەوڵەمەندکراوە: ڤیتامین E زیادەی (Extra Vitamin E) تێدایە کە وەک دژە ئۆکسانێکی بەهێز کاردەکات بۆ پاراستنی پێست.\r\nسوودەکانی ڕۆنی جۆجۆبا بۆ پێست و قژ:\r\nڕۆنی جۆجۆبا لە ڕاستیدا مۆمێکی شلەیە کە زۆر لە چەوری سروشتی پێستی مرۆڤ (Sebum) دەچێت، بۆیە زۆر بە ئاسانی هەڵدەمژرێت:\r\n1. بۆ پێست:\r\n• شێدارکەرەوەیەکی قووڵە: بەبێ ئەوەی کونییلەکانی پێست بگرێت یان پێستەکە زۆر چەور بکات، شێداری پێ دەبەخشێت.\r\n• دژە هەوکردنە: یارمەتی کەمکردنەوەی سووربوونەوە و خورانی پێست دەدات.\r\n• بۆ زیپکە: چونکە هاوسەنگی چەوری پێست ڕادەگرێت، بۆ ئەو کەسانەش باشە کە پێستیان چەورە و زیپکەیان هەیە.\r\n2. بۆ قژ:\r\n• بریقەدارکردن: قژەکە نەرم و بریقەدار دەکات.\r\n• چارەسەری وشکی سەر: یارمەتی نەهێشتنی کڕێش و وشکی پێستی سەر دەدات.\r\nچۆنیەتی بەکارهێنان:\r\n• بۆ پێست: چەند دڵۆپێکی کەم بخەرە سەر پێستی پاک و بە هێواشی مەساجی پێ بکە (باشترە دوای خۆشتن بێت).\r\n• بۆ قژ: دەتوانیت وەک ماسکی پێش خۆشتن بەکاری بهێنیت (بۆ ماوەی ٣٠ خولەک) یان تەنها چەند دڵۆپێکی کەم بدەیت لە کۆتایی تاڵەکانی قژت دوای وشککردنەوە.\r\n','100% natural jojoba oil enriched with extra vitamin E. Jojoba is a lightweight wax-like oil similar to the skin’s natural sebum, so it absorbs easily without leaving a heavy feel. For skin: provides deep hydration without clogging pores, helps calm irritation and redness, and can help balance oil for oily/acne-prone skin. For hair: softens and adds shine, and helps reduce scalp dryness and flaking. How to use: apply a few drops to clean skin and massage gently (especially after shower). For hair, use as a pre-wash mask for about 30 minutes or apply a tiny amount to the ends after drying.','زيت الجوجوبا طبيعي 100% ومُعزّز بفيتامين E إضافي. زيت الجوجوبا يشبه الدهون الطبيعية للبشرة (الزهم) لذلك يُمتص بسهولة ولا يترك إحساساً ثقيلاً. للبشرة: يرطب بعمق دون انسداد المسام، يساعد على تهدئة التهيج والاحمرار، وقد يساهم في توازن إفراز الدهون للبشرة الدهنية والمعرّضة للحبوب. للشعر: يمنح نعومة ولمعاناً ويساعد على تقليل جفاف فروة الرأس والتقشر. طريقة الاستخدام: توضع بضع قطرات على بشرة نظيفة مع تدليك لطيف (يفضل بعد الاستحمام). للشعر يمكن استخدامه كقناع قبل الغسل لمدة حوالي 30 دقيقة أو وضع كمية قليلة جداً على الأطراف بعد التجفيف.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:30:43',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(128,'ڕۆنی گوێزی هیندی لە بڕاندی ئۆلیڤا سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییەکانی بەرهەمەکە:\r\n• سروشتییە: وەک لەسەری نووسراوە ۱۰۰٪ سروشتییە.\r\n• دەوڵەمەند کراوە: ڤیتامین E (Vitamin E) بۆ زیاد کراوە کە وەک دژە ئۆکسان کار دەکات و بۆ پاراستنی پێست و قژ زۆر باشە.\r\nسوودەکانی بۆ قژ و پێست:\r\n۱. بۆ قژ:\r\n• شێدارکەرەوە: یارمەتی نەرمکردنەوەی قژی وشک و تێکچوو دەدات.\r\n• درەوشانەوە: بریقەیەکی سروشتی بە قژ دەبەخشێت.\r\n• دژی کڕێش: دەتوانرێت بۆ مەساجکردنی پێستی سەر بەکاربێت بۆ کەمکردنەوەی وشکی و کڕێش.\r\n۲. بۆ پێست:\r\n• شێدارکەرەوەی جەستە: زۆر گونجاوە بۆ ئەو شوێنانەی جەستە کە زۆر وشک دەبنەوە (وەک ئەژنۆ و ئانیشک).\r\n• لابەری ماکیاژ: بە شێوەیەکی زۆر نەرم ماکیاژ لادەبات بەبێ ئەوەی پێستەکە زبر بکات.\r\n• پاراستنی پێست: بەهۆی هەبوونی ڤیتامین E، یارمەتی نوێبوونەوەی خانەکانی پێست دەدات.\r\nچۆنیەتی بەکارهێنان:\r\n• بۆ قژ: پێش چوونە گەرماو بڕێکی گونجاو لە ڕۆنەکە بدە لە قژت و بۆ ماوەی ۳۰ خولەک بیهێڵەرەوە، پاشان بە شامپۆ بیقۆ رەوە.\r\n• بۆ پێست: چەند دڵۆپێکی کەم بدە لەو شوێنەی کە دەتەوێت و بە هێواشی مەساجی پێ بکە تا هەڵدەمژرێت.\r\nتێبینی: ئەگەر پێستت چەورە یان زیپکەی زۆرە، باشترە بۆ دەموچاو بەکاری نەهێنیت چونکە ڕۆنی گوێزی هیندی ڕەنگە کونییلەکانی پێست بگرێت','100% natural coconut oil enriched with vitamin E for extra antioxidant support. For hair: helps soften dry, damaged hair, adds natural shine, and can help reduce scalp dryness and dandruff when used as a scalp massage oil. For skin: moisturizes very dry areas (such as elbows and knees) and can remove makeup gently without irritation. How to use: for hair, apply a suitable amount before shower, leave for about 30 minutes, then wash with shampoo. For skin, apply a small amount and massage until absorbed. Note: if your facial skin is very oily or acne-prone, avoid using coconut oil on the face as it may clog pores for some people.','زيت جوز الهند طبيعي 100% ومُعزّز بفيتامين E لدعم مضاد للأكسدة. للشعر: يساعد على تنعيم الشعر الجاف والمتضرر ويمنحه لمعاناً طبيعياً، ويمكن أن يساهم في تقليل جفاف فروة الرأس والقشرة عند استخدامه مع تدليك الفروة. للبشرة: يرطب المناطق شديدة الجفاف مثل المرفقين والركبتين، ويمكن استخدامه لإزالة المكياج بلطف دون تهيج. طريقة الاستخدام: للشعر توضع كمية مناسبة قبل الاستحمام وتُترك حوالي 30 دقيقة ثم يُغسل بالشامبو. للبشرة توضع كمية قليلة وتُدلّك حتى الامتصاص. ملاحظة: إذا كانت بشرة الوجه دهنية جداً أو معرضة للحبوب، يُفضّل عدم استخدامه على الوجه لأن زيت جوز الهند قد يسبب انسداد المسام لبعض الأشخاص.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:32:00',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(129,'ڕۆنی گێزەر لە بڕاندی ئۆلیڤا سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,' ئەم ڕۆنە بەوە ناسراوە کە دەوڵەمەندە بە ڤیتامینەکان و پێکهاتەی سوودبەخش بۆ پێست و قژ.\r\nزانیارییە سەرەکییەکانی بەرهەمەکە:\r\n• پێکهاتە: ١٠٠٪ سروشتییە و ڤیتامین E (Extra Vitamin E) بۆ زیادکراوە بۆ بەهێزکردنی کاریگەرییەکەی.\r\nسوودەکانی ڕۆنی گێزەر:\r\n١. بۆ پێست:\r\n• پاراستنی پێست: بەهۆی هەبوونی بێتا-کارۆتین و ڤیتامین A، یارمەتی نوێکردنەوەی خانەکانی پێست دەدات.\r\n• دژە پیربوون: یارمەتی کەمکردنەوەی نیشانەکانی چرچولۆچی دەدات و پێست گەنج دەهێڵێتەوە.\r\n• بۆنی (Tanning): زۆرجار بەکاردێت بۆ دەستکەوتنی ڕەنگێکی ئەسمەری (Bronze) جوان و پاراستنی پێست لە کاتی بەرکەوتنی خۆر (بەڵام جێگرەوەی دژەخۆر نییە).\r\n٢. بۆ قژ:\r\n• بەهێزکەر: قژ لە شکان و هەڵوەرین دەپارێزێت.\r\n• نەرمکەرەوە: قژ نەرم و بریقەدار دەکات و ڕێگری لە وشکبوونەوەی دەکات.\r\nچۆنێتی بەکارهێنان:\r\n• بۆ پێست: چەند دڵۆپێکی کەم بدە لەو شوێنەی کە دەتەوێت و بە هێواشی مەساژی پێ بکە تا پێستەکە هەڵی دەمژێت. باشترە شەوان پێش خەوتن بەکاربێت.\r\n• بۆ قژ: دەتوانیت وەک ماسکێکی سروشتی پێش حەمام بەکاریبهێنیت (بۆ ماوەی ٣٠ خولەک) یان چەند دڵۆپێکی زۆر کەم بدەیت لە کۆتایی قژت دوای حەمام بۆ ڕێگری لە بژبوونەوە\r\n','100% natural carrot oil enriched with extra vitamin E. Rich in beta-carotene and vitamin A, it supports skin renewal and helps protect the skin from signs of aging. Often used to help achieve a healthy bronze glow when exposed to sunlight (but it is not a sunscreen and does not replace SPF). For hair: helps strengthen hair, reduce breakage, and improve softness and shine. How to use: apply a few drops to the desired area and massage gently; best used at night for facial skin. For hair, use as a pre-wash mask for about 30 minutes or apply a tiny amount to the ends after shower.','زيت الجزر طبيعي 100% ومُعزّز بفيتامين E إضافي. غني بالبيتا كاروتين وفيتامين A مما يدعم تجدد البشرة ويساعد على حماية البشرة من علامات التقدم بالسن. يُستخدم أحياناً للمساعدة في الحصول على لون برونزي جميل مع التعرض للشمس (لكنّه ليس واقياً شمسياً ولا يغني عن استخدام SPF). للشعر: يساعد على تقوية الشعر وتقليل التقصف وتحسين النعومة واللمعان. طريقة الاستخدام: توضع بضع قطرات على المنطقة المطلوبة مع تدليك لطيف؛ ويفضل استخدامه ليلاً على بشرة الوجه. للشعر يمكن استخدامه كقناع قبل الغسل لمدة حوالي 30 دقيقة أو وضع كمية قليلة جداً على الأطراف بعد الاستحمام.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:35:02',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(130,'ڕۆنی لاورێل (گەڵای غار) لە بڕاندی ئۆلیڤا سپای یۆنانی',NULL,NULL,NULL,15,20000,29750,4750,1,'ئەم جۆرە ڕۆنە لە یۆنان دروست دەکرێت و بە یەکێک لە باشترین کەرەستە سروشتییەکان بۆ چارەسەری کێشەکانی قژ دادەنرێت.\r\nسوودە سەرەکییەکانی:\r\n• بەهێزکردنی قژ: یارمەتی بەهێزکردنی پیازەی قژ دەدات و ڕێگری دەکات لە هەڵوەرین.\r\n• تێرکردنی قژ بە ڤیتامین: ئەم بەرهەمە ڤیتامین E تێدایە کە وەک دژە ئۆکسان کاردەکات و قژ بە بریقەداری دەهێڵێتەوە.\r\n• بۆ تەندروستی پێستی سەر: یارمەتیدەرە بۆ کەمکردنەوەی کڕێش و باشکردنی سووڕی خوێن لە پێستی سەردا.\r\n• تۆخکردنی ڕەنگی قژ:  بەکاردێت بۆ هێشتنەوەی ڕەنگی تۆخی قژ و درەنگ سپی بوونی.\r\nتایبەتمەندییەکانی ئەم جۆرە:\r\n1. 100% سروشتییە: هیچ کەرەستەیەکی کیمیایی زیانبەخشی تێدا نییە.\r\n2. دەوڵەمەند کراوە: جگە لە ڕۆنی لاورێلەکە، ڤیتامین E زیاتری بۆ زیاد کراوە بۆ پاراستنی خانەکان.\r\nچۆنێتی بەکارهێنان:\r\n• بۆ قژ: بڕێکی گونجاو لە ڕۆنەکە بدە لە پێستی سەرت و بە شێوەی بازنەیی مەساجی پێ بکە. دواتر بیدە لە هەموو قژت و بۆ ماوەی ٣٠ بۆ ٦٠ خولەک پێوەی بهێڵەرەوە، پاشان بە شامپۆیەکی گونجاو بیشۆ.\r\n• بۆ برۆ و برژانگ: بۆ بەهێزکردنی برۆ و برژانگ بەکار دێت (بە وریاییەوە بیبەکارهێنە بۆ ئەوەی نەچێتە ناو چاوت).\r\n','Greek laurel oil (bay leaf oil) enriched with extra vitamin E, known as a natural option for supporting hair health. Benefits: helps strengthen hair roots, reduce shedding, improve scalp circulation, and may help reduce dandruff and scalp dryness. Also commonly used to help maintain darker hair tone and delay premature greying. How to use: massage a suitable amount into the scalp in circular motions, distribute through hair, leave for 30–60 minutes, then wash with a suitable shampoo. Can also be used carefully on eyebrows and eyelashes to support thickness (avoid getting into the eyes).','زيت الغار (اللوريل) من اليونان ومُعزّز بفيتامين E إضافي، ويُعد من الخيارات الطبيعية لدعم صحة الشعر. الفوائد: يساعد على تقوية جذور الشعر وتقليل التساقط وتحسين الدورة الدموية في فروة الرأس، وقد يساهم في تقليل القشرة وجفاف الفروة. كما يُستخدم أحياناً للمساعدة في الحفاظ على لون الشعر الداكن وتأخير الشيب المبكر. طريقة الاستخدام: تُدلّك كمية مناسبة على فروة الرأس بحركات دائرية، ثم تُوزّع على الشعر وتُترك 30–60 دقيقة، وبعدها يُغسل بالشامبو المناسب. يمكن استخدامه بحذر على الحواجب والرموش لدعم الكثافة مع تجنب دخول الزيت إلى العين.',NULL,NULL,NULL,NULL,NULL,'2026-01-06 06:36:40',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(131,'کەفی پاکەرەوەی تایبەت بە پێستی هەستیار و ناسک لە بڕاندی سێبامێدی ئەڵمانی','Cleansing foam for sensitive and delicate skin from German brand Sebamed','غسول رغوي للبشرة الحساسة والرقيقة من العلامة التجارية الألمانية سيباميد','کەفی پاکەرەوەی تایبەت بە پێستی هەستیار و ناسک لە بڕاندی سێبامێدی ئەڵمانی',15,16000,24000,4000,1,'. تایبەتمەندییە سەرەکییەکان\r\n• بۆ کێ گونجاوە؟: تایبەت دروستکراوە بۆ پێستی زۆر هەستیار و ئەو پێستانەی زوو سوور دەبنەوە (وەک حاڵەتی ڕۆزاشیا یان زیپکەی سوور).\r\n• هاوسەنگی pH 5.5: ئەمە نیشانەی بازرگانی سێبامێدەکەیە؛ یارمەتی پاراستنی چینی سروشتی بەرگری پێست دەدات و ڕێگری دەکات لە وشکبوونەوە و تێکچوونی خانەکان.\r\n• پاککردنەوەیەکی نەرم: بەبێ ئەوەی پێستەکە ڕووشێنێت یان زبر بێت، چەوری زیادە و پیسی و تەنانەت ماکیاژیش لادەبات.\r\n٢. سوودەکانی بەپێی زانیارییەکانی سەر پاکەتەکە\r\n• هێورکەرەوە: هەستێکی فێنککەرەوە و ئارام بە پێست دەبەخشێت و ئەو سووتانەوە و گرژییەی لە پێستدا هەیە کەمی دەکاتەوە.\r\n• بێ سابوون (Soap-free): ماددەی کیمیایی زبری تێدا نییە کە پێست هەست پێ بکات یان بیورووژێنێت.\r\n• کاریگەری: کۆمپانیاکە دەڵێت دوای ٤ هەفتە بەکارهێنان، باشتربوونی بەرچاو لە سووربوونەوەی پێستدا دەبینرێت.\r\n٣. چۆن بەکاردێت؟\r\n• بەیانیان و شەوان: بڕێکی گونجاو لە کەفەکە بدە لە پێستت (دەتوانیت بۆ دەوری چاویش بەکاری بهێنیت چونکە زۆر نەرمە).\r\n• مەساج: بە هێواشی مەساجی پێ بکە بەبێ ئەوەی بە توندی پێستت بخشێنیت (چونکە لێکخشاندن سووربوونەوە زیاد دەکات).\r\n• شوشتن: دواتر بە ئاوێکی شلەتێن (نەک زۆر گەرم) بیشۆ و بە خاولییەکی نەرم وشکی بکەرەوە.\r\nتێبینییەکی گرنگ:\r\nئەم بەرهەمە بۆ پاککردنەوەیە و چارەسەری یارمەتیدەرە. ئەگەر سووربوونەوەی پێستت زۆرە و بەردەوامە، باشترە لەگەڵ ئەم پاککەرەوەیەدا کرێمێکی تایبەت بە دژە-سووربوونەوە (Anti-Redness Cream) بەکاربهێنیت بۆ ئەوەی باشترین ئەنجامت دەستبکەوێت.\r\n','. . . . Key Features\n• Who is it suitable for?: Specially formulated for very sensitive skin and skin that is prone to redness (such as rosacea or red acne).\n• pH 5.5 balance: this is the trademark of the sebamed; It helps maintain the skin’s natural barrier layer and prevents dryness and cell damage.\n• Gentle cleansing: Removes excess oil, dirt and even makeup without stripping or roughening the skin.\n2. Benefits According to the information on the package\n• Soothing: Gives the skin a cooling and relaxing feeling and reduces burning and tension.\n• Soap-free: Contains no harsh chemicals that can irritate the skin.\n• Effectiveness: The company says that after 4 weeks of use, there is a noticeable improvement in skin redness.\n3. how is it used\n• Morning and night: Apply an appropriate amount of the foam to your skin (you can also use it around the eyes because it is very gentle).\n• Massage: Massage gently without rubbing your skin hard (as rubbing increases redness).\n• Rinse: Then rinse with running water (not too hot) and dry with a soft towel.\nImportant note:\nThis product is for cleansing and helpful treatment. If you have severe and persistent redness, it is best to use an anti-redness cream with this cleanser for best results.','الميزات الرئيسية\n• لمن يناسب؟: تركيبة خاصة للبشرة الحساسة جدًا والمعرضة للاحمرار (مثل الوردية أو حب الشباب الأحمر).\n• درجة حموضة متوازنة 5.5: هذه هي السمة المميزة لسيباميد؛ فهي تساعد على الحفاظ على طبقة الحاجز الطبيعية للبشرة وتمنع الجفاف وتلف الخلايا.\n• تنظيف لطيف: يزيل الزيوت الزائدة والأوساخ وحتى المكياج دون تجريد البشرة من زيوتها الطبيعية أو التسبب في خشونة ملمسها.\n\nالفوائد (وفقًا للمعلومات الموجودة على العبوة)\n• مهدئ: يمنح البشرة شعورًا بالانتعاش والاسترخاء، ويخفف من الحرقان والتوتر.\n• خالٍ من الصابون: لا يحتوي على مواد كيميائية قاسية قد تهيج البشرة.\n• الفعالية: تشير الشركة إلى أنه بعد 4 أسابيع من الاستخدام، يُلاحظ تحسن ملحوظ في احمرار البشرة.\n\nطريقة الاستخدام\n• صباحًا ومساءً: ضعي كمية مناسبة من الرغوة على بشرتك (يمكنكِ أيضًا استخدامها حول العينين لأنها لطيفة جدًا).\n• التدليك: دلّكي بشرتكِ بلطف دون فركها بقوة (لأن الفرك يزيد الاحمرار).\nالشطف: اشطفي بشرتكِ بالماء الجاري (ليس ساخنًا جدًا) وجففيها بمنشفة ناعمة.\nملاحظة هامة: هذا المنتج مُخصّص للتنظيف والعلاج. في حال وجود احمرار شديد ومستمر، يُنصح باستخدام كريم مُضاد للاحمرار مع هذا المُنظّف للحصول على أفضل النتائج.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-06 17:11:40',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-59',0,0),(132,'کەفی پاکەرەوەی دژە بەکتریا و تایبەت بە خاڵی رەش و زیوان لە بڕاندی سێبامێدی ئەڵمانی','Antibacterial cleansing foam for blackheads from German brand Sebamed','رغوة تنظيف مضادة للبكتيريا للرؤوس السوداء من العلامة التجارية الألمانية سيباميد','کەفی پاکەرەوەی دژە بەکتریا و تایبەت بە خاڵی رەش و زیوان لە بڕاندی سێبامێدی ئەڵمانی',15,12500,19500,3500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی چەور و زیپکەدار: ئەم بەرهەمە بە شێوەیەکی تایبەت بۆ ئەو جۆرە پێستانە دروستکراوە کە زوو زیپکە دەردەکەن یان خاڵی ڕەشیان تێدایە.\r\n• دژە بەکتریایە: ماددەی Montaline C40 ی تێدایە کە یارمەتیدەرە لە لەناوبردنی ئەو بەکتریایانەی دەبنە هۆی دروستبوونی زیپکە.\r\n• هاوسەنگی pH 5.5: پارێزگاری لە بەرگی سروشتی و ترشەڵۆکی پێست دەکات، کە ئەمە وادەکات پێستەکە وشک نەبێتەوە و لە هەمان کاتدا لە بەکتریا بیپارێزێت.\r\n• پاککردنەوەی قووڵ: کونیلەکانی پێست بە قووڵی لە چەوری زیادە و پیسی پاک دەکاتەوە.\r\n• هێورکەرەوەیە: ماددەی Panthenol (پانتینۆڵ) ی تێدایە کە یارمەتی چاکبوونەوەی پێستە سووتاو یان هەوکردووەکان دەدات و پێست نەرم دەکات.\r\nچۆنیەتی بەکارهێنان:\r\n1. بڕێکی گونجاو لە کەفەکە بدە لە دەستت.\r\n2. بە هێواشی مەساجی پێستی دەموچاوتی پێ بکە (ئاگاداربە نەیەت بە چاوتدا).\r\n3. بۆ ماوەی ٣ خولەک بە پێستتەوە بیهێڵەرەوە بۆ ئەوەی ماددە دژە بەکتریایەکان کاری خۆیان بکەن.\r\n4. پاشان بە ئاوێکی شلەتێن بە باشی دەموچاوت بشۆ.\r\n5. ڕۆژی دوو جار (بەیانیان و شەوان) بەکاری بهێنە.\r\nتێبینی گرنگ:\r\n• ئەم بەرهەمە بەبێ سابوون (Soap-free) و بەبێ کحول دروستکراوە، بۆیە زۆر زیانی نییە بۆ پێستە هەستیارەکان.\r\n','Key Features:\n• For oily and acne-prone skin: This product is specially formulated for skin types that are prone to acne or blackheads.\n• Antibacterial: Contains Montaline C40, which helps kill the bacteria that cause acne.\n• Balance pH 5.5: Maintains the natural texture and acidity of the skin, which prevents the skin from drying out while protecting it from bacteria.\n• Deep Cleansing: Deeply cleans pores of excess oil and dirt.\n• Soothing: Contains Panthenol (panthenol) which helps heal burnt or inflamed skin and softens the skin.\nHow to use:\n1. Apply the appropriate amount of foam to your hand.\n2. Gently massage into your facial skin (be careful not to get in your eyes).\n3. Leave it on your skin for 3 minutes for the antibacterial agents to do their job.\n4. Then wash your face thoroughly with lukewarm water.\n5. Use twice a day (morning and night).\nImportant Note:\n• This product is soap-free and alcohol-free, so it is not too harmful to sensitive skin.','الميزات الرئيسية:\n• للبشرة الدهنية والمعرضة لحب الشباب: صُمم هذا المنتج خصيصًا لأنواع البشرة المعرضة لحب الشباب أو الرؤوس السوداء.\n• مضاد للبكتيريا: يحتوي على مونتالين C40، الذي يساعد على قتل البكتيريا المسببة لحب الشباب.\n• درجة حموضة متوازنة 5.5: يحافظ على ملمس البشرة الطبيعي وحموضتها، مما يمنع جفافها ويحميها من البكتيريا.\n• تنظيف عميق: ينظف المسام بعمق من الزيوت الزائدة والأوساخ.\n• مهدئ: يحتوي على البانثينول الذي يساعد على شفاء البشرة المحروقة أو الملتهبة وينعمها.\n\nطريقة الاستخدام:\n1. ضعي كمية مناسبة من الرغوة على يدك.\n2. دلكي الرغوة بلطف على بشرة وجهك (مع الحرص على عدم ملامستها للعينين).\n3. اتركيها على بشرتك لمدة 3 دقائق حتى تؤدي المواد المضادة للبكتيريا مفعولها.\n4. اغسلي وجهك جيدًا بالماء الفاتر.\n5. استخدميه مرتين يوميًا (صباحًا ومساءً). ملاحظة هامة:\n• هذا المنتج خالٍ من الصابون والكحول، لذا فهو ليس ضارًا جدًا للبشرة الحساسة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-07 16:39:38',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-58',0,0),(133,'لۆشنی شێدارکەرەوەی تایبەت بە جەستەی منداڵان لە بڕاندی سێبامێدی ئەڵمانی','Children\'s moisturizing body lotion from German brand Sebamed','لوشن مرطب للجسم للأطفال من ماركة سيباميدي الألمانية','لۆشنی شێدارکەرەوەی تایبەت بە جەستەی منداڵان لە بڕاندی سێبامێدی ئەڵمانی',15,12500,17500,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی هەستیار: تایبەت دروست کراوە بۆ پێستی ناسک و هەستیاری منداڵ، بەتایبەت بۆ ئەوانەی پێستیان زوو وشک دەبێتەوە یان سوور دەبێتەوە.\r\n• هاوسەنگی pH 5.5: ئەم خاڵە زۆر گرنگە؛ چونکە ڕێگری دەکات لە تێکچوونی چینی پارێزەری سروشتی پێست و ناهێڵێت بەکتریا و میکرۆب زیان بە پێست بگەیەنن.\r\n• پێکهاتەی ئارامکەرەوە: بڕێکی باش بەیبوون (Camomile) و ئەلانتاوین (Allantoin) تێدایە کە یارمەتی ئارامکردنەوەی پێست و نەرمکردنی دەدەن.\r\n• شێدارکەرەوەی سروشتی: یارمەتی هاوسەنگکردنی شێی ناو پێست دەدات و ناهێڵێت پێستەکە وشک بێتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n1. سەرەتا پێستی منداڵەکە بە باشی پاک بکەرەوە.\r\n2. بڕێکی گونجاو لە لۆشنەکە بدە لە دەستت.\r\n3. بە هێواشی و بە شێوەی مەساج بیدە لە جەستەی منداڵەکە تا پێستەکە هەڵیدەمژێت.\r\nتێبینییە گرنگەکان:\r\n• ئەم بەرهەمە لە یەکەم ڕۆژی لەدایکبوونەوە دەکرێت بەکاربهێنرێت.\r\n• تەنها بۆ بەکارهێنانی دەرەکییە.\r\n• لە شوێنێکی فێنک و وشکدا هەڵیبگرە.\r\nئەم لۆشنە یارمەتییەکی زۆری منداڵ دەدات بۆ ئەوەی هەمیشە پێستی بە نەرمی بمێنێتەوە و پارێزراو بێت لە سووربوونەوە.\r\n','Key Features:\n• For sensitive skin: Specially formulated for children\'s delicate and sensitive skin, especially those with dry or red skin.\n• pH 5.5 balance: This point is very important; Because it prevents the deterioration of the skin\'s natural protective layer and prevents bacteria and germs from damaging the skin.\n• Soothing ingredients: Contains good amounts of chamomile and allantoin to help soothe and soften the skin.\n• Natural moisturizer: Helps balance moisture in the skin and prevents it from drying out.\nHow to use:\n1. First clean the baby’s skin thoroughly.\n2. Apply the appropriate amount of lotion to your hands.\n3. Gently massage until absorbed by the skin.\nImportant Notes:\n• This product can be used from the first day of birth.\n• For external use only.\n• Store in a cool, dry place.\nThis lotion helps a child to keep his skin soft and protected from redness.','الميزات الرئيسية:\n• للبشرة الحساسة: تركيبة خاصة لبشرة الأطفال الرقيقة والحساسة، وخاصةً البشرة الجافة أو الحمراء.\n• درجة حموضة متوازنة 5.5: هذه النقطة مهمة للغاية؛ لأنها تمنع تدهور الطبقة الواقية الطبيعية للبشرة وتحميها من البكتيريا والجراثيم.\n• مكونات مهدئة: يحتوي على كميات مناسبة من البابونج والألانتوين لتهدئة البشرة وتنعيمها.\n• مرطب طبيعي: يساعد على موازنة رطوبة البشرة ويمنع جفافها.\n\nطريقة الاستخدام:\n1. نظفي بشرة الطفل جيدًا.\n2. ضعي كمية مناسبة من اللوشن على يديكِ.\n3. دلكي بلطف حتى تمتصه البشرة.\n\nملاحظات هامة:\n• يمكن استخدام هذا المنتج من اليوم الأول للولادة.\nللاستخدام الخارجي فقط.\nيحفظ في مكان بارد وجاف.\nيساعد هذا اللوشن الطفل على الحفاظ على نعومة بشرته وحمايتها من الاحمرار.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-07 16:41:52',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-57',0,0),(134,'کرێمی دژە خۆر لە بڕاندی سێبامێدی ئەڵمانی','Sunscreen from the German brand Sebamed','واقي الشمس من العلامة التجارية الألمانية سيباميد','کرێمی دژە خۆر لە بڕاندی سێبامێدی ئەڵمانی',15,15750,24750,4500,1,'. تایبەتمەندییە سەرەکییەکان\r\n• پلەی پاراستن (SPF 50+): پاراستنێکی زۆر بەرز دابین دەکات دژی تیشکی خۆر، کە گونجاوە بۆ ئەو کەسانەی پێستیان سپییە یان زۆر هەستیارە.\r\n• سیستەمی فلتەری سیانی: دژی هەردوو جۆری تیشکی زیانبەخشە (UVA کە دەبێتە هۆی پیربوونی پێست و چرچبوون، و UVB کە دەبێتە هۆی سووتانی پێست).\r\n• هاوسەنگی pH 5.5: ئەمە تایبەتمەندی ناوازەی سیبامیدە، کە یارمەتی پاراستنی چینی سروشتی پارێزەری پێست دەدات و ناهێڵێت پێست وشک ببێتەوە یان تێکبچێت.\r\n• بۆ پێستی هەستیار: تایبەت دروستکراوە بۆ ئەو کەسانەی پێستیان بە خۆر سوور دەبێتەوە یان هەستیارییان هەیە.\r\n٢. پێکهاتە سوودبەخشەکان\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات بۆ پاراستنی پێست لە پیربوون و تێکچوونی خانەکان.\r\n• ئینولین و لیسیتین: یارمەتی شێدارکردنەوەی (Hydration) پێست دەدەن بە شێوەیەکی قووڵ.\r\n• دژە ئاو (Water Resistant): بۆ ماوەیەکی باش بەرگەی ئاو و ئارەق دەگرێت (بەڵام دوای مەلەکردن یان وشککردنەوەی دەموچاو بە خاولی، پێویستە نوێ بکرێتەوە).\r\n٣. چۆنیەتی بەکارهێنان\r\n• کاتی بەکارهێنان: پێویستە ٢٠ خولەک پێش ئەوەی بچیتە بەر خۆر لێی بدەیت.\r\n• بڕی گونجاو: بڕێکی باشی لێ بدە و بە باشی بڵاوی بکەرەوە؛ ئەگەر بڕێکی کەمی لێ بدەیت، ئاستی پاراستنەکەی کەمدەبێتەوە.\r\n• نوێکردنەوە: پێویستە هەموو ٢ کاتژمێر جارێک نوێ بکرێتەوە، بەتایبەت ئەگەر زۆر لەبەر خۆر بویت یان ئارەقت کردەوە.\r\n٤. تێبینی گرنگ\r\n• ئەم بەرهەمە تاقیگەیی و پزیشکییە (Dermatologically tested','. . . . Key Features\n• Protection Grade (SPF 50+): Provides ultra-high protection against sunlight, suitable for people with fair or very sensitive skin.\n• Cyanide Filter System: Against both types of harmful rays (UVA, which causes skin aging and wrinkles, and UVB, which causes skin burns).\n• pH 5.5 balance: This is Cibamide’s unique property, which helps maintain the skin’s natural protective layer and prevents skin from becoming dry or damaged.\n• For sensitive skin: Specially formulated for people with sun tanned or sensitive skin.\n2. beneficial ingredients\n• Vitamin E: Acts as an antioxidant to protect skin from aging and cell damage.\n• Inulin and lecithin: Help hydrate the skin deeply.\n• Water Resistant: Water and sweat resistant for a long time (but needs to be renewed after swimming or towel drying).\n3. How to use\n• Time to use: Apply 20 minutes before going out in the sun.\n• Adequate amount: apply a good amount and spread well; If you apply a small amount, the level of protection will decrease.\n• Renewal: Renew every 2 hours, especially if you are exposed to the sun or sweat a lot.\n4. Important notes\n• This product is laboratory and medical (Dermatologically tested','الميزات الرئيسية\n• درجة الحماية (SPF 50+): يوفر حماية فائقة من أشعة الشمس، مناسب للبشرة الفاتحة أو الحساسة جدًا.\n• نظام فلترة السيانيد: يحمي من نوعي الأشعة الضارة (UVA، المسببة لشيخوخة الجلد والتجاعيد، وUVB، المسببة لحروق الشمس).\n• درجة حموضة متوازنة 5.5: هذه خاصية فريدة للسباميد، تساعد في الحفاظ على طبقة الحماية الطبيعية للبشرة وتمنع جفافها أو تلفها.\n• للبشرة الحساسة: تركيبة خاصة لأصحاب البشرة السمراء أو الحساسة.\n\nالمكونات المفيدة\n• فيتامين هـ: يعمل كمضاد للأكسدة لحماية البشرة من الشيخوخة وتلف الخلايا.\n• الإينولين والليسيثين: يساعدان على ترطيب البشرة بعمق.\n• مقاوم للماء: مقاوم للماء والعرق لفترة طويلة (لكن يجب إعادة وضعه بعد السباحة أو التجفيف بالمنشفة).\n\nطريقة الاستخدام\n• وقت الاستخدام: يوضع قبل 20 دقيقة من التعرض لأشعة الشمس.\n• الكمية المناسبة: ضعي كمية كافية ووزعيها جيداً؛ فاستخدام كمية قليلة يقلل من مستوى الحماية.\n• التجديد: جدديه كل ساعتين، خاصةً عند التعرض للشمس أو التعرق الشديد.\n\n٤. ملاحظات هامة\n• هذا المنتج مُختَبَر مخبرياً وطبياً (مُختَبَر من قِبَل أطباء الجلدية).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-07 16:44:36',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'75ml','03-56',0,0),(135,'پاکەرەوەی نەرمی تاینەت بە جەستەی منداڵان لە بڕاندی سێبامێدی ئەڵمانی','Gentle children\'s body cleanser from German brand Sebamed','غسول لطيف للجسم للأطفال من ماركة سيباميدي الألمانية','پاکەرەوەی نەرمی تایبەت بە جەستەی منداڵان لە بڕاندی سێبامێدی ئەڵمانی',15,7250,11500,2000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی ناسک: بەتایبەت بۆ پێستی زۆر ناسکی منداڵ دروستکراوە کە پێویستی بە پاراستنی تایبەت هەیە.\r\n• هاوسەنگی pH 5.5: ئەمە خاڵە هەرە گرنگەکەیەتی؛ یارمەتی دروستکردنی چینی پارێزەری سروشتی پێست دەدات (Acid Mantle) کە ڕێگری دەکات لە وشکبوونەوە و هەوکردن.\r\n• ماددەی Allantoin: ئەم ماددەیەی تێدایە کە یارمەتی نەرمکردنەوەی پێست دەدات و لە وشکبوونەوە دەیپارێزێت.\r\n• بێ فرمێسک (No Tears Formula): چاوی منداڵ ناسووتێنێتەوە.\r\n• بێ سابوون: پاککەرەوەیەکە کە سابوونی تێدا نییە (Soap-free)، بۆیە نابێتە هۆی تێکدانی چەورییە سروشتییەکانی پێست.\r\nسوودەکانی:\r\n1. پێست بە نەرمی پاک دەکاتەوە بەبێ ئەوەی بیخورێنێت یان وشکی بکاتەوە.\r\n2. یارمەتی هاوسەنگکردنی شێی پێست دەدات.\r\n3. لە لایەن پزیشکانی پێستەوە تاقیکراوەتەوە و پەسەند کراوە.\r\nشێوازی بەکارهێنان:\r\n• چەند دڵۆپێکی کەم لە غەسولەکە بکەرە ناو دەستت.\r\n• کەمێک ئاوی گەرمی تێبکە تا کەفێکی کەم دروست دەکات.\r\n• بە جوڵەی هێواش و نەرم جەستەی منداڵەکەی پێ بشۆ.\r\n• لە کۆتاییدا بە ئاوی شلەتێن بە باشی ڕایبشۆ.\r\nتێبینی گرنگ:\r\n• تەنها بۆ بەکارهێنانی دەرەکییە.\r\n• پێویستە لە شوێنێکی فێنک و وشک هەڵبگیرێت','Key Features:\n• For delicate skin: Especially formulated for very delicate baby skin that needs special protection.\n• pH 5.5 balance: This is the most important point; It helps create the skin’s natural protective layer (Acid Mantle) which prevents dryness and inflammation.\n• Allantoin: Contains this substance that helps soften the skin and prevent it from drying out.\n• No Tears Formula: Does not burn the child\'s eyes.\n• Soap-free: A soap-free cleanser, so it does not damage the skin\'s natural oils.\nBenefits:\n1. Gently cleanses skin without irritating or drying it.\n2. Helps balance skin moisture.\n3. Tested and approved by dermatologists.\nHow to use:\n• Put a few drops of the lotion into your hand.\n• Add a little hot water until it forms a slight foam.\n• Wash the child\'s body with slow, gentle movements.\n• Finally, rinse thoroughly with lukewarm water.\nImportant Note:\n• For external use only.\n• It should be stored in a cool, dry place','الميزات الرئيسية:\n• للبشرة الحساسة: تركيبة خاصة مصممة خصيصًا لبشرة الأطفال الرقيقة جدًا التي تحتاج إلى حماية خاصة.\n• درجة حموضة متوازنة 5.5: هذه هي النقطة الأهم؛ فهي تساعد على تكوين الطبقة الواقية الطبيعية للبشرة (الغطاء الحمضي) التي تمنع الجفاف والالتهاب.\n• آلانتوين: يحتوي على هذه المادة التي تساعد على ترطيب البشرة ومنع جفافها.\n• تركيبة لا تسبب الدموع: لا تسبب حرقانًا في عيون الطفل.\n• خالٍ من الصابون: منظف خالٍ من الصابون، لذا فهو لا يضر بالزيوت الطبيعية للبشرة.\n\nالفوائد:\n1. ينظف البشرة بلطف دون تهيجها أو تجفيفها.\n2. يساعد على موازنة رطوبة البشرة.\nتم اختباره واعتماده من قبل أطباء الجلدية.\n\nطريقة الاستخدام:\n• ضعي بضع قطرات من المستحضر على راحة يدك.\nأضيفي القليل من الماء الدافئ حتى تتكون رغوة خفيفة.\nدلكي جسم الطفل بحركات بطيئة ولطيفة.\nأخيرًا، اشطفي جيدًا بالماء الفاتر.\nأخيرًا، اشطفي جيدًا بالماء الفاتر. ملاحظة هامة:\n• للاستخدام الخارجي فقط.\n• يُحفظ في مكان بارد وجاف.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-07 16:47:16',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-55',0,0),(136,'کرێمی تایبەت بە دژە پیربوونی دەورەبەری چاو لە بڕاندی سێبامێدی ئەڵمانی','Anti-aging cream around the eyes from the German brand Sebamed','كريم مضاد للشيخوخة لمنطقة حول العينين من ماركة سيباميدي الألمانية','کرێمی تایبەت بە دژە پیربوونی دەورەبەری چاو لە بڕاندی سێبامێدی ئەڵمانی',15,11250,16500,2500,1,'کۆمەڵەی سێیانەی ترشی هیالۆرۆنیک): بە قووڵی پێست شێدار دەکاتەوە و یارمەتی پڕکردنەوەی هێڵە وردەکانی دەوری چاو دەدات.\r\n• Coenzyme Q10: ماددەیەکی دژە ئۆکسانە، یارمەتی نوێکردنەوەی خانەکان و کەمکردنەوەی چرچی دەدات.\r\n• Phyto-peptides: یارمەتی جیڕکردنەوە و توندکردنەوەی پێست دەدەن.\r\n• ڕۆنی سروشتی: وەک ڕۆنی بادەمی شیرین، ئەڤۆکادۆ و کەرەی شیا (Shea Butter) کە پێستەکە نەرم دەکەن و دەیپارێزن.\r\n• Bisabolol: بۆ هێورکردنەوەی ئەو شوێنانەی دەوری چاو کە هەستیارن.\r\nسوودە گرنگەکانی:\r\n1. دژە پیری: یارمەتی کەمکردنەوە و ڕێگریکردن لە دروستبوونی چرچی و هێڵە وردەکان دەدات.\r\n2. توندکردنەوە (Lifting): کاریگەری هەیە لەسەر توندکردنەوەی پێستی دەوری چاو.\r\n3. پاراستنی ترشێتی پێست (pH 5.5): هاوسەنگی سروشتی پێست دەپارێزێت و بەربەستی بەرگری پێست بەهێز دەکات.\r\n4. تێستکراوە: لە لایەن پزیشکانی پێست و چاوەوە تاقی کراوەتەوە و گونجاوە تەنانەت بۆ ئەو کەسانەش کە عەدەسەی چاو بەکاردێنن.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی کەم لە کرێمەکە بدە لە پێستی دەوروبەری چاو (ئەو شوێنەی ئێسکەکەی لێیە).\r\n• بە پەنجەی ئەڵقە (چونکە هێزی کەمترە) بە شێوەی تەپتەپە (Dabbing) بڵاوی بکەرەوە.\r\n• ئاگاداربە بە هێز مەیشێلە و با نەچێتە ناو خودی چاوەکەتەوە.\r\n• دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) دوای پاککردنەوەی دەموچاو بەکاری بهێنیت.','Hyaluronic Acid Triad Set): Deeply hydrates skin and helps fill in fine lines around the eyes.\n• Coenzyme Q10: An antioxidant, helps renew cells and reduce wrinkles.\n• Phyto-peptides: Help firm and tighten the skin.\n• Natural oils: such as sweet almond oil, avocado and shea butter that soften and protect the skin.\n• Bisabolol: To soothe sensitive areas around the eyes.\nImportant benefits:\n1. Anti-aging: Helps reduce and prevent the formation of wrinkles and fine lines.\n2. Lifting: It works to tighten the skin around the eyes.\n3. Maintain skin acidity (pH 5.5): Maintains the skin\'s natural balance and strengthens the skin\'s immune barrier.\n4. Tested: Tested by dermatologists and ophthalmologists and suitable even for people who wear contact lenses.\nHow to use:\n• Apply a small amount of the cream to the skin around the eye (where the bone is).\n• Spread by dabbing with a ring finger (because it is less powerful).\n• Be careful not to rub forcefully and let it not get into your eye itself.\n• You can use it twice daily (morning and night) after cleansing your face.','مجموعة حمض الهيالورونيك الثلاثية: ترطب البشرة بعمق وتساعد على ملء الخطوط الدقيقة حول العينين.\n• الإنزيم المساعد Q10: مضاد للأكسدة، يساعد على تجديد الخلايا وتقليل التجاعيد.\n• الببتيدات النباتية: تساعد على شد البشرة.\n• زيوت طبيعية: مثل زيت اللوز الحلو، وزيت الأفوكادو، وزبدة الشيا، التي تُنعم البشرة وتحميها.\n• البيسابولول: لتهدئة المناطق الحساسة حول العينين.\n\nالفوائد الرئيسية:\n1. مكافحة الشيخوخة: يساعد على تقليل ومنع ظهور التجاعيد والخطوط الدقيقة.\n2. شد البشرة: يعمل على شد البشرة حول العينين.\n3. الحفاظ على حموضة البشرة (درجة حموضة 5.5): يحافظ على التوازن الطبيعي للبشرة ويقوي حاجزها المناعي.\n4. مُختبر: تم اختباره من قبل أطباء الجلدية والعيون، وهو مناسب حتى لمن يرتدون العدسات اللاصقة.\n\nطريقة الاستخدام:\n• ضعي كمية صغيرة من الكريم على البشرة حول العين (عند عظمة الخد). • يُوزّع بالتربيت الخفيف باستخدام إصبع البنصر (لأنه أقل تركيزًا).\n• احرصي على عدم فركه بقوة وتجنبي دخوله في العين.\n• يمكنكِ استخدامه مرتين يوميًا (صباحًا ومساءً) بعد تنظيف الوجه.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:07:53',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'15ml','03-54',0,0),(137,'سیڕۆمی تایبەت بە نوێکردنەوە و کەمکردنەوەی نیشانەکانی پیری  پێست لە بڕاندی سێبامێدی ئەڵمانی','Special serum to renew and reduce the signs of aging of the skin from the German brand Sebamed','سيروم خاص لتجديد البشرة وتقليل علامات الشيخوخة من العلامة التجارية الألمانية سيباميد','سیڕۆمی تایبەت بە نوێکردنەوە و کەمکردنەوەی نیشانەکانی پیری پێست لە بڕاندی سێبامێدی ئەڵمانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی چالاک (Paracress): ئەم ڕووەکە وەک \"بۆتۆکسی سروشتی\" کاردەکات؛ یارمەتی خاوکردنەوەی گرژییە وردەکانی دەموچاو دەدات و هێڵەکان (وەک هێڵی پێکەنین و ناوچەوان) بە شێوەیەکی خێرا کەم دەکاتەوە.\r\n• سێ جۆر لە Hyaluronic Acid: ئەم سێرەمە سێ جۆر هایالۆرۆنیک ئەسیدی تێدایە کە بە قووڵی پێست شێدار دەکەنەوە و وادەکەن پێستەکە پڕتر و گەنجتر دەربکەوێت.\r\n• هاوسەنگی pH 5.5: وەک هەموو بەرهەمەکانی سێبامێد، ئەمەش پارێزگاری لە ترشەڵۆکی سروشتی پێست دەکات کە وەک قەڵغانێکە دژی وشکبوونەوە و هەوکردن.\r\n• ئەنجام: بەپێی زانیاری سەر کارتۆنەکە، لە دوای ٤ هەفتە بەکارهێنان، %٧٦ی بەکارهێنەران هەستیان بە باشتربوونی پێستیان کردووە.\r\nسوودەکانی:\r\n1. توندکردنەوەی پێست و ڕێگریکردن لە شۆڕبوونەوە.\r\n2. کەمکردنەوەی هێڵە وردەکانی دەموچاو.\r\n3. شێدارکردنێکی زۆر و درێژخایەن (تا %٣١ شێداری زیاتر لە دوای ٢٨ ڕۆژ).\r\n4. گونجاوە بۆ هەموو جۆرە پێستێک، بەتایبەت ئەو پێستانەی بەرەو پیربوون دەچن.\r\nشێوازی بەکارهێنان:\r\n• پێشتر پێستت بە پاککەرەوەیەکی گونجاو پاک بکەرەوە.\r\n• بەیانیان و شەوان بڕێکی گونجاو بدە لە دەموچاو، مل، و بەشی سەرەوەی سنگ (décolleté).\r\n• بە پەنجەکانت بە هێواشی مەساجی پێ بکە تا هەڵدەمژرێت.\r\n• تێبینی: ئاگاداربە با ١ سانتیمەتر لە چاوەکانتەوە دوور بێت.\r\n• دەتوانیت وەک بنکەیەک (Base) بۆ ماکیاژیش بەکاری بهێنیت.\r\n','Key Features:\n• Active ingredient (Paracress): This plant acts as “natural Botox”; It helps slow down subtle facial tension and reduce lines (such as laugh lines and armpits) instantly.\n• Three types of Hyaluronic Acid: This serum contains three types of hyaluronic acid that deeply moisturize the skin and make it look fuller and younger.\n• Balance pH 5.5: As with all Sebamed products, this maintains the skin’s natural acidity which acts as a shield against dryness and inflammation.\n• Results: According to the information on the carton, after 4 weeks of use, 76% of users felt improved skin.\nBenefits:\n1. Tightens the skin and prevents sagging.\n2. Reduce fine facial lines.\n3. Excessive and prolonged humidification (up to 31% more humidity after 28 days).\n4. Suitable for all skin types, especially aging skin.\nHow to use:\n• Cleanse your skin with an appropriate cleanser beforehand.\n• Apply appropriate amounts to face, neck, and upper chest (décolleté) morning and night.\n• Massage gently with your fingers until absorbed.\n• Note: Be careful to keep 1 cm away from your eyes.\n• You can also use it as a base for makeup.','الميزات الرئيسية:\n• المكون الفعال (باراكريس): يعمل هذا النبات كبديل طبيعي للبوتوكس؛ فهو يساعد على إبطاء توتر عضلات الوجه وتقليل الخطوط الدقيقة (مثل خطوط الضحك وخطوط الإبط) بشكل فوري.\n• ثلاثة أنواع من حمض الهيالورونيك: يحتوي هذا السيروم على ثلاثة أنواع من حمض الهيالورونيك التي ترطب البشرة بعمق وتجعلها تبدو أكثر امتلاءً وشبابًا.\n• درجة حموضة متوازنة 5.5: كما هو الحال مع جميع منتجات سيباميد، يحافظ هذا السيروم على حموضة البشرة الطبيعية التي تعمل كحاجز واقٍ ضد الجفاف والالتهابات.\n• النتائج: وفقًا للمعلومات الموجودة على العبوة، شعر 76% من المستخدمين بتحسن في بشرتهم بعد 4 أسابيع من الاستخدام.\n\nالفوائد:\n1. يشد البشرة ويمنع ترهلها.\n2. يقلل من الخطوط الدقيقة في الوجه.\n3. ترطيب مكثف ومستمر (يزيد الرطوبة بنسبة تصل إلى 31% بعد 28 يومًا).\n4. مناسب لجميع أنواع البشرة، وخاصة البشرة المتقدمة في السن.\n\nطريقة الاستخدام:\n• نظفي بشرتكِ بمنظف مناسب قبل الاستخدام.\n• ضعي كمية مناسبة على الوجه والرقبة وأعلى الصدر (منطقة الصدر) صباحًا ومساءً.\n• دلكي بلطف بأطراف أصابعك حتى يتم امتصاصه.\n• ملاحظة: احرصي على إبقاء مسافة 1 سم بين المنتج وعينيكِ.\n• يمكنكِ أيضًا استخدامه كأساس للمكياج.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:19:59',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'30ml','03-53',0,0),(138,'کرێمی دژە تیشکی خۆر لە بڕاندی سێبامێدی ئەڵمانی','Sunscreen from the German brand Sebamed','واقي الشمس من العلامة التجارية الألمانية سيباميد','کرێمی دژە تیشکی خۆر لە بڕاندی سێبامێدی ئەڵمانی',15,14750,20750,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پلەی پاراستن (SPF 30): پاراستنێکی باش (High Protection) دابین دەکات دژی تیشکە زیانبەخشەکانی خۆر.\r\n• پاراستنی دوولایەنە: دژی هەردوو تیشکی UVA (کە دەبێتە هۆی پیربوونی پێست) و UVB (کە دەبێتە هۆی سووتانی پێست) کاردەکات.\r\n• بۆ پێستی هەستیار: تایبەت دروست کراوە بۆ ئەو کەسانەی پێستیان ناسکە یان زوو سوور دەبێتەوە.\r\n• هاوسەنگی pH 5.5: یارمەتی پاراستنی چینی سروشتی پێست دەدات و ناهێڵێت پێست وشک ببێتەوە.\r\n• دژە ئاو (Water Resistant): لە کاتی ئارەقکردنەوە یان مەلەکردن بۆ ماوەیەک بەرگری دەگرێت.\r\n• پێکهاتەی دەوڵەمەند: ڤیتامین E و ئینولینی تێدایە کە وەک دژە ئۆکسان کاردەکەن و پێست بە شێداری دەهێڵنەوە.\r\nڕێنمایییەکانی بەکارهێنان:\r\n1. پێش چوونە بەر خۆر: پێویستە ٢٠ خولەک پێش ئەوەی بچیتە بەر خۆر، بڕێکی گونجاو لە کرێمەکە لە پێستت بدەیت.\r\n2. بڕی پێویست: بە بڕێکی باش بەکاری بهێنە؛ چونکە بەکارهێنانی بڕێکی کەم، ئاستی پاراستنەکە کەمدەکاتەوە.\r\n3. دووبارەکردنەوە: ئەگەر بۆ ماوەیەکی زۆر لەبەر خۆر بوویت، یان دوای مەلەکردن و ئارەقکردنەوەی زۆر، پێویستە کرێمەکە دووبارە بکەیتەوە.\r\n','Key Features:\n• Protection degree (SPF 30): Provides good protection (High Protection) against harmful sun rays.\n• Dual protection: Works against both UVA (which causes skin aging) and UVB (which causes skin burns) rays.\n• For sensitive skin: Specially formulated for people with sensitive or prone to redness.\n• Balance pH 5.5: Helps maintain the skin’s natural layer and prevents skin from drying out.\n• Water Resistant: Resists sweating or swimming for a while.\n• Rich Ingredients: Contains vitamin E and inulin which act as antioxidants and keep skin hydrated.\nInstructions for use:\n1. Before going out in the sun: Apply an appropriate amount of cream 20 minutes before going out in the sun.\n2. Amount: Use in good amounts; Because using small amounts reduces the level of protection.\n3. Repeat: If you have been in the sun for a long time, or after swimming and sweating a lot, you should repeat the cream.','الميزات الرئيسية:\n• درجة الحماية (SPF 30): يوفر حماية عالية من أشعة الشمس الضارة.\n• حماية مزدوجة: يحمي من أشعة UVA (المسببة لشيخوخة الجلد) وأشعة UVB (المسببة لحروق الشمس).\n• للبشرة الحساسة: تركيبة خاصة للأشخاص ذوي البشرة الحساسة أو المعرضة للاحمرار.\n• درجة حموضة متوازنة 5.5: تساعد في الحفاظ على الطبقة الطبيعية للبشرة وتمنع جفافها.\n• مقاوم للماء: يقاوم التعرق أو السباحة لفترة.\n• مكونات غنية: يحتوي على فيتامين E والإينولين اللذين يعملان كمضادات للأكسدة ويحافظان على ترطيب البشرة.\n\nطريقة الاستخدام:\n1. قبل التعرض للشمس: ضعي كمية مناسبة من الكريم قبل 20 دقيقة من التعرض للشمس.\n2. الكمية: استخدمي كمية مناسبة؛ لأن استخدام كميات قليلة يقلل من مستوى الحماية.\n3. التكرار: إذا كنتِ قد تعرضتِ للشمس لفترة طويلة، أو بعد السباحة والتعرق الشديد، يُنصح بتكرار وضع الكريم.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:22:45',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'75ml','03-52',0,0),(139,'شامپۆی دژە کڕێش لە بڕاندی سێبامێدی ئەڵمانی','Anti- dandruff shampoo from German brand Sebamed','شامبو مضاد للتجاعيد من ماركة سيباميدي الألمانية','شامپۆی دژە کڕێش لە بڕاندی سێبامێدی ئەڵمانی',15,13000,18000,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ قژی چەور گونجاوە: ئەم شامپۆیە تایبەت دروستکراوە بۆ ئەو کەسانەی قژیان چەورە یان پێستی سەریان زوو چەوری دەردەدات.\r\n• دژە کڕێش: ماددەی کارای (Piroctone Olamine) تێدایە کە بە شێوەیەکی کاریگەر ڕووبەڕووی ئەو قارچکانە دەبێتەوە کە دەبنە هۆی دروستبوونی کڕێش.\r\n• هاوسەنگی pH 5.5: ئەمە خاڵە بەهێزەکەی سێبامێدە؛ یارمەتی پاراستنی چینی سروشتی پارێزەری پێستی سەر دەدات و نایەڵێت پێستەکە زۆر وشک ببێتەوە یان تێکبچێت.\r\n• کەمکردنەوەی خورۆ و سووربوونەوە: یارمەتی هێورکردنەوەی پێستی سەر دەدات و ئەو خورۆ و سووتانەوەیەی بەهۆی کڕێشەوە دروست دەبێت کەمی دەکاتەوە.\r\nسوودەکانی:\r\n1. ئەنجامی خێرا: ئاماژە بەوە دراوە کە دوای ١٤ ڕۆژ بەکارهێنان، کڕێشی سەر بە ڕێژەی %٥٠ کەمی کردووە (بەپێی تاقیکردنەوە کلینیکییەکان).\r\n2. پاککردنەوەی قووڵ: چەوری زیادەی پێستی سەر لادەبات بەبێ ئەوەی زیان بە تاڵەکانی قژ بگەیەنێت.\r\n3. بێ ماددەی زیانبەخش: زۆربەی بەرهەمەکانی سێبامێد بەوە ناسراون کە سابوون و ماددە توندەکانیان تێدا نییە.\r\nشێوازی بەکارهێنان:\r\n• سەرەتا قژت بە ئاو تەڕ بکە.\r\n• بڕێکی گونجاو لە شامپۆکە بدە لە لەپی دەستت و پاشان بیدە لە قژت.\r\n• بە هێواشی پێستی سەرت مەساج بکە تا کەف دەکات.\r\n• باشترە خولەکێک یان دوو خولەک بە قژتەوە بێت تا ماددەکان کار بکەن، پاشان بە ئاوێکی شلەتێن باش بێشۆ.\r\n• ئەگەر پێویست بوو دەتوانیت دووبارەی بکەیتەوە.\r\nتێبینی:\r\nئەم شامپۆیە زیاتر بۆ چارەسەرە، بۆیە ئەگەر کڕێشت نەما دەتوانیت جاروبار بەکاری بهێنیت بۆ ئەوەی پێستی سەرت وشک نەبێتەوە، یان لەگەڵ شامپۆیەکی ڕۆژانەی ئاسایی سێبامێد (Everyday Shampoo) بیگۆڕیتەوە.\r\n','Key Features:\n• Suitable for oily hair: This shampoo is specially formulated for people with oily hair or scalp that secretes oil quickly.\n• Anti-wrinkle: Contains the active ingredient Piroctone Olamine, which effectively fights the fungi that cause wrinkles.\n• pH 5.5 balance: This is Sebamed’s strength; It helps maintain the natural protective layer of the scalp and prevents the skin from becoming too dry or damaged.\n• Reduce itching and redness: Helps soothe the scalp and reduces itching and burning caused by wrinkles.\nBenefits:\n1. Quick results: It has been reported that after 14 days of use, scalp wrinkles decreased by 50% (according to clinical trials).\n2. Deep Cleansing: Removes excess scalp oil without damaging hair follicles.\n3. Free of harmful substances: Most Sebamed products are known to be free of soap and harsh substances.\nHow to use:\n• Wet your hair with water first.\n• Apply an appropriate amount of shampoo to your palms and then to your hair.\n• Gently massage your scalp until it foams up.\n• It is best to leave on your hair for a minute or two for the substances to work, then rinse thoroughly with lukewarm water.\n• You can repeat if necessary.\nnotice:\nThis shampoo is more for treatment, so if you don\'t have dandruff, you can use it from time to time to keep your scalp from drying out, or swap it with a regular Sebamed Everyday Shampoo.','الميزات الرئيسية:\n• مناسب للشعر الدهني: صُمم هذا الشامبو خصيصًا لأصحاب الشعر الدهني أو فروة الرأس التي تفرز الزيوت بكثرة.\n• مضاد للتجاعيد: يحتوي على المكون النشط بيروكتون أولامين، الذي يُحارب الفطريات المُسببة للتجاعيد بفعالية.\n• درجة حموضة متوازنة 5.5: هذه هي ميزة سيباميد؛ فهي تُساعد في الحفاظ على الطبقة الواقية الطبيعية لفروة الرأس وتمنع جفافها أو تلفها.\n• يُخفف الحكة والاحمرار: يُساعد على تهدئة فروة الرأس ويُخفف الحكة والحرقان الناتجين عن التجاعيد.\n\nالفوائد:\n1. نتائج سريعة: أُفيد أنه بعد 14 يومًا من الاستخدام، انخفضت تجاعيد فروة الرأس بنسبة 50% (وفقًا للتجارب السريرية).\n2. تنظيف عميق: يُزيل الزيوت الزائدة من فروة الرأس دون إتلاف بصيلات الشعر.\n3. خالٍ من المواد الضارة: تُعرف معظم منتجات سيباميد بخلوها من الصابون والمواد الكيميائية القاسية.\n\nطريقة الاستخدام:\n• بللي شعركِ بالماء أولًا.\n• ضعي كمية مناسبة من الشامبو على راحة يديكِ ثم وزعيها على شعركِ.\n• دلكي فروة رأسكِ بلطف حتى تتكون رغوة.\n• يُفضل ترك الشامبو على شعركِ لمدة دقيقة أو دقيقتين حتى تعمل مكوناته، ثم اشطفيه جيدًا بالماء الفاتر.\n• يمكنكِ تكرار العملية إذا لزم الأمر.\n\nملاحظة: هذا الشامبو مُخصص لعلاج القشرة، لذا إذا لم تكن لديكِ قشرة، يمكنكِ استخدامه من حين لآخر لترطيب فروة رأسكِ ومنع جفافها، أو استبداله بشامبو سيباميد اليومي العادي.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:25:22',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-51',0,0),(140,'لۆشنی شێدارکەرەوەی  تایبەت بە پێستی وشک هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Moisturizing lotion for dry sensitive skin from German brand Sebamed','لوشن مرطب للبشرة الجافة والحساسة من ماركة سيباميدي الألمانية','لۆشنی شێدارکەرەوەی تایبەت بە پێستی وشک هەستیار لە بڕاندی سێبامێدی ئەڵمانی',NULL,19000,26500,3750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• pH 5.5: ئەمە گرنگترین خاڵە، چونکە نیشانەی ئەوەیە کە لۆشنەکە هاوسەنگە لەگەڵ چینی پارێزەری سروشتی پێست و ناهێڵێت پێستەکە تووشی هەوکردن یان وشکبوونەوەی زیاتر ببێت.\r\n• Phytosterols: پێکهاتەیەکی ڕووەکی تێدایە (لە ڕووەکی ڕەپس وەرگیراوە) کە یارمەتی هێورکردنەوەی پێست دەدات و ناهێڵێت پێست بخورێت یان سوور ببێتەوە.\r\n• Shea Butter: کەرەی شیا (Shea Butter)ی تێدایە کە بە یەکێک لە باشترین شێدارکەرەوە سروشتییەکان دادەنرێت بۆ نەرمکردنەوەی پێست.\r\n٢. سوودەکانی:\r\n• نەهێشتنی توندی پێست: ئەو هەستە ناخۆشەی دوای گەرماو کە پێست توند دەبێت و دەخورێت، ئەم لۆشنە کەمی دەکاتەوە.\r\n• زیادکردنی شێداری: بەپێی نوسراوی سەر کارتۆنەکە، ڕێژەی شێداری پێست بە ڕێژەی 26% زیاد دەکات ئەگەر بۆ ماوەی ٣ هەفتە بەردەوام بەکاربێت.\r\n• پاراستنی پێست: یارمەتی دروستکردنەوەی چەورییە سروشتییەکانی پێست دەدات بۆ ئەوەی پێستەکە بە نەرمی بمێنێتەوە.\r\n٣. شێوازی بەکارهێنان:\r\n• دوای ئەوەی پێستت بە جوانی پاک دەکەیتەوە (باشترە دوای گەرماو بێت چونکە کونکەلەکانی پێست کراوەن)، بڕێکی گونجاو لە لۆشنەکە بدە لە جەستەت و بە هێواشی مەساژی بکە تاوەکو هەمووی هەڵدەمژرێت.','Key Features:\n• pH 5.5: This is the most important point, as it indicates that the lotion is balanced with the skin\'s natural protective layer and prevents the skin from becoming more inflamed or dry.\n• Phytosterols: Contains a plant compound (derived from the rapeseed plant) that helps soothe the skin and prevents itchiness or redness.\n• Shea Butter: Contains shea butter, which is considered one of the best natural moisturizers for softening the skin.\n2. Benefits:\n• Eliminate skin tightness: This lotion reduces the unpleasant feeling of tightness and itching after a bath.\n• Increased moisture: According to the label, the skin\'s moisture content increases by 26% if used continuously for 3 weeks.\n• Skin protection: Helps regenerate the skin’s natural oils to keep the skin supple.\n3. How to use:\n• After thoroughly cleansing your skin (preferably after a bath as skin pores are open), apply an appropriate amount of the lotion and massage gently until it is all absorbed.','الميزات الرئيسية:\n• درجة حموضة 5.5: هذه هي النقطة الأهم، إذ تدل على أن المستحضر متوازن مع طبقة الحماية الطبيعية للبشرة، ويمنع تهيجها أو جفافها.\n• فيتوستيرولات: يحتوي على مركب نباتي (مستخلص من بذور اللفت) يساعد على تهدئة البشرة ومنع الحكة والاحمرار.\n• زبدة الشيا: يحتوي على زبدة الشيا، التي تُعتبر من أفضل المرطبات الطبيعية لتنعيم البشرة.\n\n2. الفوائد:\n• التخلص من شد البشرة: يُخفف هذا المستحضر الشعور المزعج بالشد والحكة بعد الاستحمام.\n• زيادة الترطيب: وفقًا للملصق، تزداد نسبة ترطيب البشرة بنسبة 26% عند استخدامه باستمرار لمدة 3 أسابيع.\n• حماية البشرة: يساعد على تجديد الزيوت الطبيعية للبشرة للحفاظ على نعومتها.\n\n3. طريقة الاستخدام:\n• بعد تنظيف بشرتك جيداً (يفضل بعد الاستحمام لأن مسام البشرة تكون مفتوحة)، ضعي كمية مناسبة من اللوشن ودلكيها بلطف حتى يتم امتصاصها بالكامل.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:28:25',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-50',0,0),(141,'شامپۆی شێدارکەرەوەی تایبەت بە قژی وشک و تێکچوو لە بڕاندی سێبامێدی ئەڵمانی','Moisturizing shampoo for dry and damaged hair from German brand Sebamed','شامبو مرطب للشعر الجاف والتالف من ماركة سيباميدي الألمانية','شامپۆی شێدارکەرەوەی تایبەت بە قژی وشک و تێکچوو لە بڕاندی سێبامێدی ئەڵمانی',15,16000,23000,3500,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• پێوەری pH 5.5: ئەمە گرنگترین خاڵی بەرهەمەکانی سێبامێدە، چونکە هاوسەنگی ترشێتی سروشتی پێست دەپارێزێت و ڕێگری دەکات لە تێکچوونی چینی پارێزەری سەر.\r\n• بەکارهێنانی ڕووەکی: پێکهاتەکەی لە پرۆتینی ڕووەکی (Active Plant Protein) پێکهاتووە کە یارمەتی گەڕانەوەی شێ بۆ پێستی سەر دەدات.\r\n• دژە وشکی: بە پێی نوسراوی سەر کارتۆنەکە، ئەم شامپۆیە دەبێتە هۆی کەمکردنەوەی وشکی پێستی سەر بە ڕێژەی %٤٩ لە ماوەی سێ هەفتەدا.\r\n٢. سوودەکانی بۆ قژ و پێستی سەر:\r\n• بۆ پێستی هەستیار: زۆر گونجاوە بۆ ئەو کەسانەی پێستی سەریان بەهۆی وشکییەوە تووشی خوران یان سووربوونەوە دەبێت.\r\n• نۆژەنکەرەوە: یارمەتی چاککردنەوەی قژی بێهێز و بێ بریقە دەدات و جارێکی تر بریقە و نەرمی بۆ دەگەڕێنێتەوە.\r\n• پاراستن: ڕێگری دەکات لە لەدەستدانی شێ و وشکبوونەوەی قژ بەهۆی هۆکارە ژینگەییەکانەوە.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• قژت بە باشی تەڕ بکە.\r\n• بڕێکی گونجاو لە شامپۆکە بدە لە دەستت و پاشان مەساجی پێستی سەری پێ بکە بە هێواشی.\r\n• بە ئاوێکی شلەتێن بە باشی قژت بشۆ.\r\n• ئەگەر پێویست بوو دەتوانیت دووبارەی بکەیتەوە.\r\n٤. تێبینی گرنگ:\r\nئەم شامپۆیە بێ سابوون و بێ پێکهاتە توندەکانە (Soap and Alkali-free)، بۆیە زۆر نەرمە لەسەر پێست. ئەگەر کێشەی وەک ئەگزیما یان سەدەفییەت (Psoriasis) هەیە، ئەم جۆرە شامپۆیانە زۆرجار لەلایەن پزیشکانی پێستەوە پێشنیار دەکرێن.\r\n','. . . . Key Features:\n• pH 5.5: This is the most important point of Sebamed products, as it maintains the natural acidity balance of the skin and prevents the protective layer of the scalp from breaking down.\n• Botanical Use: Contains Active Plant Protein that helps restore moisture to the scalp.\n• Anti-dryness: According to the label, this shampoo reduces scalp dryness by 49% within three weeks.\n2. Benefits for hair and scalp:\n• For sensitive skin: Ideal for people whose scalp is prone to irritation or redness due to dryness.\n• Restorer: Helps repair dull, shine-free hair and restore shine and softness.\n• Protection: Prevents moisture loss and hair dryness due to environmental factors.\n3. How to use:\n• Wet your hair thoroughly.\n• Apply an appropriate amount of shampoo to your hands and then massage gently into the scalp.\n• Rinse your hair thoroughly with lukewarm water.\n• You can repeat if necessary.\n4. Important Note:\nThis shampoo is soap and alkali-free, so it is very gentle on the skin. If there are problems like eczema or psoriasis, these shampoos are often recommended by dermatologists.','الميزات الرئيسية:\n• درجة حموضة 5.5: هذه أهم ميزة في منتجات سيباميد، حيث تحافظ على توازن الحموضة الطبيعي للبشرة وتمنع تلف الطبقة الواقية لفروة الرأس.\n• مستخلصات نباتية: يحتوي على بروتين نباتي نشط يساعد على استعادة رطوبة فروة الرأس.\n• مضاد للجفاف: وفقًا للملصق، يقلل هذا الشامبو جفاف فروة الرأس بنسبة 49% خلال ثلاثة أسابيع.\n\n2. فوائد للشعر وفروة الرأس:\n• للبشرة الحساسة: مثالي للأشخاص الذين يعانون من تهيج أو احمرار في فروة الرأس بسبب الجفاف.\n• مُرمِّم: يساعد على إصلاح الشعر الباهت والمتقصف واستعادة لمعانه ونعومته.\n• حماية: يمنع فقدان الرطوبة وجفاف الشعر الناتج عن العوامل البيئية.\n\n3. طريقة الاستخدام:\n• بللي شعركِ جيدًا.\n• ضعي كمية مناسبة من الشامبو على يديكِ ثم دلكي فروة رأسكِ بلطف.\n• اشطفي شعركِ جيدًا بالماء الفاتر.\n• يمكنكِ تكرار العملية إذا لزم الأمر.\n\n٤. ملاحظة هامة:\nهذا الشامبو خالٍ من الصابون والقلويات، لذا فهو لطيف جدًا على البشرة. في حال وجود مشاكل جلدية مثل الإكزيما أو الصدفية، غالبًا ما ينصح أطباء الجلدية باستخدام هذا الشامبو.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:30:21',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-49',0,0),(142,'لۆشنی شێدارکەرەوەی جەستە تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Moisturizing body lotion for sensitive skin from German brand Sebamed','لوشن مرطب للجسم للبشرة الحساسة من ماركة سيباميدي الألمانية','لۆشنی شێدارکەرەوەی جەستە تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,9250,14500,2500,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی ئاسایی و هەستیار: دیزاین کراوە بۆ ئەوەی بە نەرمی مامەڵە لەگەڵ پێستدا بکات و نەبێتە هۆی سووربوونەوە یان خوران.\r\n• pH 5.5: ئەمە گرنگترین خاڵی بەرهەمەکانی سێبامێدە؛ یارمەتی پاراستنی چینی بەرگری سروشتی پێست دەدات و ناهێڵێت پێست وشک ببێتەوە یان میکرۆبی تێبچێت.\r\n• بێ پارابین (No Parabens): ئەم لۆشنە ماددەی پارابینی تێدا نییە، کە ئەمەش وای لێدەکات تەندروستتر بێت بۆ بەکارهێنانی رۆژانە.\r\n• پێکهاتەی سروشتی: ماددەی کامامۆیل (بەیبوون) و ئەلانتاینی (Allantoin) تێدایە، کە کاردەکەن بۆ هێورکردنەوەی پێست و نەرمکردنی.\r\n٢. سوودەکانی:\r\n• پێست بە قووڵی شێدار دەکاتەوە و ناهێڵێت وشک ببێتەوە.\r\n• زۆر خێرا هەڵدەمژرێت و هەستی \"چەوری\" لەسەر پێست بەجێ ناهێڵێت.\r\n• پێست هێور دەکاتەوە لە ئەنجامی ماندوێتی یان گۆڕانی کەشوهەوا.\r\n• بەهۆی ئەوەی لە لایەن پزیشکانی پێستەوە تاقیکراوەتەوە، بۆ ئەو کەسانەی پێستیان ناسکە زۆر گونجاوە.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• دوای ئەوەی پێستت بە جوانی پاک دەکەیتەوە (باشترە دوای خۆشۆردن بێت چونکە پێست ئامادەیە بۆ هەڵمژین).\r\n• بڕێکی گونجاو بدە لە جەستەت و بە شێوەی مەساج بڵاوی بکەرەوە تا بە تەواوی هەڵدەمژرێت.\r\n','. . . . Key Features:\n• For normal and sensitive skin: Designed to treat skin gently and not cause redness or irritation.\n• pH 5.5: This is the most important point of Sebamed products; Helps protect the skin\'s natural defense layer and prevents skin from becoming dry or contaminated.\n• No Parabens: This lotion does not contain parabens, which makes it healthier for daily use.\n• Natural ingredients: Contains chamomile (violet) and allantoin, which work to soothe and soften the skin.\n2. Benefits:\n• Deeply moisturizes skin and prevents dryness.\n• Absorbs very quickly and does not leave a “greasy” feeling on the skin.\n• Soothes the skin from fatigue or weather changes.\n• Being tested by dermatologists, it is very suitable for people with sensitive skin.\n3. How to use:\n• After cleansing your skin thoroughly (preferably after bathing as the skin is ready to absorb).\n• Apply an appropriate amount and spread by massaging until completely absorbed.','الميزات الرئيسية:\n• مناسب للبشرة العادية والحساسة: مصمم خصيصًا للعناية بالبشرة بلطف دون التسبب في احمرار أو تهيج.\n• درجة حموضة 5.5: هذه هي أهم ميزة في منتجات سيباميد؛ فهي تساعد على حماية طبقة الدفاع الطبيعية للبشرة وتمنع جفافها أو تلوثها.\n• خالٍ من البارابين: هذا المستحضر خالٍ من البارابين، مما يجعله أكثر صحة للاستخدام اليومي.\n• مكونات طبيعية: يحتوي على البابونج (البنفسج) والألانتوين، اللذان يعملان على تهدئة البشرة وتنعيمها.\n\n2. الفوائد:\n• يرطب البشرة بعمق ويمنع جفافها.\n• يمتص بسرعة فائقة ولا يترك ملمسًا دهنيًا على البشرة.\n• يهدئ البشرة من الإرهاق أو تغيرات الطقس.\n• تم اختباره من قبل أطباء الجلدية، وهو مناسب جدًا لأصحاب البشرة الحساسة.\n\n3. طريقة الاستخدام:\n• بعد تنظيف البشرة جيدًا (يفضل بعد الاستحمام لأن البشرة تكون مستعدة للامتصاص).\n• ضعي كمية مناسبة ودلكيها حتى يتم امتصاصها بالكامل.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:33:03',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-48',0,0),(143,'شامپۆی تایبەت بە قژی ڕەنگکراو لە بڕاندی  سێبامێدی ئەڵمانی','Shampoo for colored hair from German brand Sebamed','شامبو للشعر المصبوغ من ماركة سيباميدي الألمانية','شامپۆی تایبەت بە قژی ڕەنگکراو لە بڕاندی  سێبامێدی ئەڵمانی',15,13000,18500,2750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• بۆ کێ گونجاوە؟ تایبەت دروست کراوە بۆ ئەو کەسانەی قژیان ڕەنگ (بۆیە) کردووە یان بەهۆی بەکارهێنانی ماددەی کیمیایی و ئامێرەکانی گەرمی، قژیان ماندوو و بێهێز بووە.\r\n• هاوسەنگی pH 5.5: ئەمە گرنگترین خاڵی سیبامیدە. ئەم پلەیەی ترشێتییە هاوسەنگە لەگەڵ چینی پارێزەری سەردا، کە دەبێتە هۆی پاراستنی پێستی سەر لە وشکبوونەوە و هەوکردن.\r\n٢. سوودەکانی ئەم شامپۆیە:\r\n• پاراستنی ڕەنگی قژ: یارمەتی دەدات ڕەنگی قژەکە بۆ ماوەیەکی درێژتر بە گەشی و بریقەداری بمێنێتەوە و زوو کاڵ نەبێتەوە.\r\n• تایبەتمەندی Hydro-Balancing: ئەم پێکهاتەیە کار دەکات بۆ شێدارکردنەوەی قژ و ڕێگری لە وشکبوونەوەی تاڵەکانی قژ و پێستی سەر دەکات.\r\n• هێورکەرەوەی پێستی سەر: یارمەتی هێورکردنەوەی ئەو پێستانە دەدات کە بەهۆی بۆیەی قژەوە تووشی خوران یان هەستیاری بوون.\r\n• فلتەری UV: پارێزگاری لە قژ دەکات لە بەرامبەر تیشکی زیانبەخشی خۆر کە دەبێتە هۆی تێکچوونی ڕەنگ و وشکبوونی قژ.\r\n٣. چۆنیەتی بەکارهێنان:\r\n1. قژت بە ئاو تەڕ بکە.\r\n2. بڕێکی گونجاو لە شامپۆکە بدە لە ناو دەستت و پاشان مەساجی پێستی سەرت پێ بکە تا کەف دەکات.\r\n3. بە باشی بە ئاو بیشۆ. (ئەگەر پێویستی کرد دەتوانی دووبارەی بکەیتەوە).\r\n','. . . . Key Features:\n• Who is it suitable for? It is specially designed for people who have dyed their hair or whose hair is tired and weak due to the use of chemicals and heat devices.\n• pH 5.5 balance: This is the most important point of cibamide. This degree of acidity is balanced by the protective layer of the scalp, which protects the scalp from dryness and inflammation.\n2. Benefits of this shampoo:\n• Hair color protection: Helps hair color stay bright and shiny for longer and prevent premature fading.\n• Hydro-Balancing Properties: This ingredient works to moisturize hair and prevent hair follicles and scalp from drying out.\n• Scalp Soother: Helps soothe skin that has been irritated or allergic to hair dye.\n• UV filter: Protects hair against harmful sun rays that cause discoloration and dry hair.\n3. How to use:\n1. Wet your hair with water.\n2. Apply an appropriate amount of shampoo to your hands and then massage into your scalp until it foams.\n3. Rinse thoroughly with water. (You can repeat if necessary).','الميزات الرئيسية:\n• لمن يناسب؟ صُمم هذا الشامبو خصيصًا للأشخاص الذين صبغوا شعرهم أو الذين يعانون من شعر متعب وضعيف نتيجة استخدام المواد الكيميائية وأدوات التصفيف الحرارية.\n• درجة حموضة متوازنة 5.5: هذه هي أهم ميزة للسباميد. تعمل هذه الدرجة من الحموضة على موازنة الطبقة الواقية لفروة الرأس، مما يحميها من الجفاف والالتهاب.\n\nفوائد هذا الشامبو:\n• حماية لون الشعر: يساعد على الحفاظ على لون الشعر زاهيًا ولامعًا لفترة أطول ويمنع بهتانه المبكر.\n• خصائص ترطيب متوازنة: يعمل هذا المكون على ترطيب الشعر ومنع جفاف بصيلات الشعر وفروة الرأس.\n• تهدئة فروة الرأس: يساعد على تهدئة فروة الرأس المتهيجة أو التي تعاني من حساسية تجاه صبغة الشعر.\n• فلتر للأشعة فوق البنفسجية: يحمي الشعر من أشعة الشمس الضارة التي تسبب تغير اللون وجفاف الشعر.\n\nطريقة الاستخدام:\n1. بللي شعرك بالماء.\n٢. ضعي كمية مناسبة من الشامبو على يديكِ، ثم دلكي فروة رأسكِ حتى تتكون رغوة.\n٣. اشطفي شعركِ جيداً بالماء. (يمكنكِ تكرار العملية إذا لزم الأمر).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:34:52',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-47',0,0),(144,'پاکەرەوەی تایبەت بە پیستی وشک و هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Cleanser for dry and sensitive skin from German brand Sebamed','غسول للبشرة الجافة والحساسة من ماركة سيباميدي الألمانية','پاکەرەوەی تایبەت بە پیستی وشک و هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,15000,22000,3500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• هاوسەنگی pH 5.5: ئەم بەرهەمە هاوسەنگی ترشێتی سروشتی پێست دەپارێزێت، کە ئەمەش ڕێگری دەکات لە تێکچوونی بەربەستی پارێزەری پێست.\r\n• ماددەی پانتینۆڵ (Panthenol): پێکهاتەیەکی تێدایە کە یارمەتی هێورکردنەوەی پێست دەدات و ئەو سووتانەوە و خورانەی بەهۆی وشکییەوە دروست دەبێت کەم دەکاتەوە.\r\n• پاککەرەوەی بێ سابوون: وەک سابوونی ئاسایی نییە کە پێست وشک بکاتەوە، بەڵکو بە نەرمی چەوری و پیسی لادەبات بەبێ ئەوەی شێداری سروشتی پێست تێک بدات.\r\nسوودەکانی:\r\n• هێورکردنەوەی پێست: یارمەتی کەمکردنەوەی نیشانەکانی وشکی دەدات وەک (گرژی پێست، سووربوونەوە، و خوران).\r\n• شێدارکردنەوە: پێست نەرم دەکات و ڕێگری دەکات لەوەی دوای شتن زۆر وشک ببێتەوە.\r\n• پاراستن: یارمەتی زیندەوەرە بەسوودەکانی سەر پێست دەدات و ڕێگری دەکات لە وشکبوونەوەی زیاتری پێست.\r\nچۆنیەتی بەکارهێنان:\r\n1. بڕێکی کەم بدە لە پێستی تەڕ (دەم و چاو یان جەستە).\r\n2. بە هێواشی مەساجی پێ بکە تا کف دەکات.\r\n3. بە ئاوێکی شلەتێن (نەک زۆر گەرم) بیشۆ.\r\n4. بە خاولییەکی نەرم و بە هێواشی پێستەکە وشک بکەرەوە.\r\n5. بۆ ئەنجامی باشتر، دوای شتنەکە کرێمی شێدارکەرەوە بەکاربهێنە.','Key Features:\n• Balance pH 5.5: This product maintains the skin’s natural acidity balance, which prevents the skin’s protective barrier from breaking down.\n• Panthenol: Contains an ingredient that helps soothe the skin and reduces burning and itching caused by dryness.\n• Soap-free cleanser: Unlike regular soaps that dry out the skin, it gently removes oil and dirt without disturbing the skin’s natural moisture.\nBenefits:\n• Soothes the skin: Helps reduce dryness symptoms such as skin tension, redness, and itching.\n• Moisturizing: Softens the skin and prevents it from becoming too dry after washing.\n• Protection: Helps beneficial organisms on the skin and prevents further drying of the skin.\nHow to use:\n1. Apply a small amount to wet skin (face or body).\n2. Gently massage until lathered.\n3. Rinse with lukewarm (not too hot) water.\n4. Dry the skin gently with a soft towel.\n5. For best results, apply a moisturizer after washing.','الميزات الرئيسية:\n• درجة حموضة متوازنة 5.5: يحافظ هذا المنتج على توازن حموضة البشرة الطبيعية، مما يمنع تكسر حاجزها الواقي.\n• بانثينول: يحتوي على مكون يساعد على تهدئة البشرة وتخفيف الحرقة والحكة الناتجة عن الجفاف.\n• منظف خالٍ من الصابون: على عكس أنواع الصابون العادية التي تُجفف البشرة، يُزيل هذا المنظف الزيوت والأوساخ بلطف دون التأثير على رطوبة البشرة الطبيعية.\n\nالفوائد:\n• يُهدئ البشرة: يُساعد على تخفيف أعراض الجفاف مثل شد البشرة والاحمرار والحكة.\n• يُرطب: يُنعم البشرة ويمنع جفافها الزائد بعد الغسل.\n• يُحافظ على الكائنات الحية المفيدة على البشرة ويمنع جفافها.\n\nطريقة الاستخدام:\n1. ضعي كمية صغيرة على بشرة رطبة (الوجه أو الجسم).\n2. دلكي بلطف حتى تتكون رغوة.\n3. اشطفي بالماء الفاتر (ليس ساخنًا جدًا).\n4. جففي البشرة بلطف بمنشفة ناعمة.\n5. للحصول على أفضل النتائج، ضعي مرطباً بعد الغسل.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 03:37:26',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-46',0,0),(145,'شامپۆی تایبەت بە منداڵان لە بڕاندی سێبامێدی ئەڵمانی','Children\'s shampoo from the German brand Sebamed','شامبو للأطفال من العلامة التجارية الألمانية سيباميد','شامپۆی تایبەت بە منداڵان لە بڕاندی سێبامێدی ئەڵمانی',15,6750,10750,2000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• هاوسەنگی pH 5.5: ئەمە گرنگترین خاڵە؛ چونکە ڕێگری دەکات لە وشکبوونەوەی پێستی سەر و یارمەتی دروستبوونی چینی پارێزەری سروشتی پێست دەدات.\r\n• بۆ پێستی هەستیار: تایبەت دروستکراوە بۆ ئەو منداڵانەی پێستی سەریان ناسک و هەستیارە.\r\n• پێکهاتەی گوڵە بەیبوون (Camomile): یارمەتی هێورکردنەوەی پێستی سەر دەدات و ڕێگری لە سووربوونەوە دەکات.\r\n• بێ فرمێسک (No Tears Formula): چاوەکانی منداڵ ناسوتێنێتەوە.\r\n• بێ سابوون و مەوادە زیانبەخشەکان: خاڵییە لە پێکهاتە کیمیاییە توندەکان کە زیان بە قژ و پێستی سەر دەگەیەنن.\r\nسوودەکانی:\r\n1. پاککردنەوەیەکی زۆر نەرم و ناسکی قژ و پێستی سەر.\r\n2. پاراستنی شێداری سروشتی پێست و ڕێگریکردن لە وشکبوونەوە.\r\n3. قژەکە نەرم دەکات و داهێنانی ئاسان دەکات.\r\nشێوازی بەکارهێنان:\r\n• چەند دڵۆپێکی کەم بخەرە ناو دەستت.\r\n• بە هێواشی و بە مەساج کردن بیخە سەر قژی تەڕی منداڵەکە.\r\n• پاشان بە ئاوێکی شلەتێن بە باشی قژەکەی بشۆ.\r\n','Key Features:\n• pH 5.5 balance: This is the most important point; Because it prevents the scalp from drying out and promotes the formation of the skin’s natural protective layer.\n• For sensitive skin: Specially formulated for children with delicate and sensitive scalp.\n• Chamomile: Helps soothe the scalp and prevent redness.\n• No Tears Formula: Does not burn the child\'s eyes.\n• Free of soap and harmful substances: Free of harsh chemicals that damage the hair and scalp.\nBenefits:\n1. Very gentle cleansing of hair and scalp.\n2. Maintain skin\'s natural moisture and prevent dryness.\n3. Softens the hair and makes it easier to create.\nHow to use:\n• Put a few drops in your hand.\n• Gently massage into wet hair.\n• Then rinse the hair thoroughly with lukewarm water.','الميزات الرئيسية:\n• درجة حموضة متوازنة 5.5: هذه هي النقطة الأهم؛ لأنها تمنع جفاف فروة الرأس وتعزز تكوين طبقة الحماية الطبيعية للبشرة.\n• للبشرة الحساسة: تركيبة خاصة للأطفال ذوي فروة الرأس الحساسة.\n• البابونج: يساعد على تهدئة فروة الرأس ومنع الاحمرار.\n• تركيبة لا تسبب الدموع: لا تسبب حرقانًا في عيون الطفل.\n• خالٍ من الصابون والمواد الضارة: خالٍ من المواد الكيميائية القاسية التي تضر بالشعر وفروة الرأس.\n\nالفوائد:\n1. تنظيف لطيف للغاية للشعر وفروة الرأس.\n2. يحافظ على رطوبة البشرة الطبيعية ويمنع جفافها.\n3. ينعم الشعر ويسهل تصفيفه.\n\nطريقة الاستخدام:\n• ضعي بضع قطرات في راحة يدك.\n• دلكي الشعر المبلل برفق.\n• ثم اشطفي الشعر جيدًا بالماء الفاتر.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 04:02:02',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-45',0,0),(146,'کرێمی شێدارکەرەوەی تایبەت بە پێستی منداڵان لە بڕاندی سێبامێدی ئەڵمانی','Moisturizing cream for children\'s skin from the German brand Sebamed','كريم مرطب لبشرة الأطفال من العلامة التجارية الألمانية سيباميدي','کرێمی شێدارکەرەوەی تایبەت بە پێستی منداڵان لە بڕاندی سێبامێدی ئەڵمانی',15,5000,8000,1500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی زۆر ناسک: ئەم کرێمە بە جۆرێک دروستکراوە کە زۆر نەرم بێت و گونجاو بێت بۆ پێستی منداڵی تازە لەدایکبوو.\r\n• هاوسەنگی ترشێتی (pH 5.5): گرنگترین خاڵی ئەم بەرهەمە ئەوەیە کە پلەی ترشێتییەکەی pH 5.5، ئەمەش یارمەتی دروستکردنی چینی پارێزەری سروشتی پێست دەدات.\r\n• بوونی پانتینۆڵ (Panthenol): ئەم ماددەیە یارمەتی چاکبوونەوەی پێست و قەدەغەکردنی سووربوونەوە و هەوکردن دەدات.\r\nسوودەکانی:\r\n• دژی وشکبوونەوە: پێست بە شێداری دەهێڵێتەوە و ناهێڵێت وشک ببێتەوە.\r\n• پاراستنی پێست: وەک بەربەستێک کار دەکات دژی کاریگەرییە دەرەکییە زیانبەخشەکان.\r\n• کەمکردنەوەی هەستیاری: بەهۆی ئەوەی لەلایەن پزیشکانی پێستەوە تاقی کراوەتەوە، ئەگەری دروستکردنی هەستیاری زۆر کەمە.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو لە کرێمەکە بدە لە دەستەکانت.\r\n• بە هێواشی مەساجی پێ بکە بۆ سەر پێستی منداڵەکە (بە تایبەت ئەو شوێنانەی کە تووشی وشکبوونەوە یان سووربوونەوە بوون).\r\n• تەنها بۆ بەکارهێنانی دەرەکییە.\r\nتێبینی: هەرچەندە ئەم بەرهەمە زۆر سەلامەتە، بەڵام ئەگەر منداڵەکەت هەر نیشانەیەکی نائاسایی وەک سووربوونەوەی زۆر یان خوران و زیپکەی نیشاندا، وا باشترە بەکارهێنانی ڕابگریت و پرسی پزیشک بکەیت.','Key Features:\n• For very delicate skin: This cream is designed to be very gentle and suitable for newborn skin.\n• Acidity balance (pH 5.5): The most important point of this product is that the acidity degree of pH 5.5, which helps to create the natural protective layer of the skin.\n• Panthenol: This substance helps skin healing and prevents redness and inflammation.\nBenefits:\n• Anti-drying: Keeps skin moisturized and prevents dryness.\n• Skin protection: Acts as a barrier against harmful external influences.\n• Allergy reduction: Being tested by dermatologists, the chances of causing allergies are very low.\nHow to use:\n• Apply an appropriate amount of cream to your hands.\n• Massage gently onto baby’s skin (especially areas prone to dryness or redness).\n• For external use only.\nNote: Although this product is very safe, if your child shows any unusual symptoms such as excessive redness or itching and acne, it is best to stop using it and consult a doctor.','الميزات الرئيسية:\n• للبشرة الحساسة جدًا: صُمم هذا الكريم ليكون لطيفًا للغاية ومناسبًا لبشرة الأطفال حديثي الولادة.\n• توازن الحموضة (درجة حموضة 5.5): أهم ما يميز هذا المنتج هو درجة الحموضة 5.5، التي تساعد على تكوين طبقة الحماية الطبيعية للبشرة.\n• البانثينول: تساعد هذه المادة على التئام البشرة وتمنع الاحمرار والالتهاب.\n\n• فوائد:\n• مضاد للجفاف: يحافظ على ترطيب البشرة ويمنع جفافها.\n• حماية البشرة: يعمل كحاجز ضد المؤثرات الخارجية الضارة.\n• تقليل الحساسية: بعد اختباره من قبل أطباء الجلدية، فإن احتمالية التسبب بالحساسية منخفضة جدًا.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة من الكريم على يديكِ.\nدلكي بلطف على بشرة الطفل (خاصة المناطق المعرضة للجفاف أو الاحمرار).\nللاستخدام الخارجي فقط.\n\nملاحظة: على الرغم من أن هذا المنتج آمن للغاية، إلا أنه إذا ظهرت على طفلك أي أعراض غير عادية مثل الاحمرار المفرط أو الحكة وحب الشباب، فمن الأفضل التوقف عن استخدامه واستشارة الطبيب.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 04:13:37',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,NULL,'03-44',0,0),(147,'سپڕای دژە خۆر تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Sunscreen spray for sensitive skin from German brand Sebamed','بخاخ واقي من الشمس للبشرة الحساسة من العلامة التجارية الألمانية سيباميد','سپڕای دژە خۆر تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,25000,35000,5000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پلەی پارێزگاری (SPF 30): پارێزگارییەکی باش و \"بەرز\" لە پێست دەکات دژی تیشکی خۆر.\r\n• سیستەمی فلتەری سیانی: پارێزگاری لە پێست دەکات دژی هەردوو تیشکی زیانبەخشی (UVA و UVB)، هەروەها ڤیتامین E تێدایە کە ڕێگری لە پیربوونی پێست و تێکچوونی خانەکان دەکات بەهۆی خۆرەوە.\r\n• بۆ پێستی هەستیار: ئەم بەرهەمە تایبەت بۆ ئەو کەسانە دروستکراوە کە پێستیان ناسکە یان زوو بە خۆر سوور دەبێتەوە.\r\n• هاوسەنگی pH 5.5: وەک هەموو بەرهەمەکانی سێبامێد، ئەمەش هاوسەنگی ترشێتی پێست دەپارێزێت و بەربەستە سروشتییەکەی بەهێز دەکات.\r\n• شێدارکەرەوە: ماددەی (Inulin) و (Lecithin)ی تێدایە کە یارمەتی نەرمکردنەوە و هێشتنەوەی شێی پێست دەدەن.\r\n• بەرگری دژە ئاو: تا ڕادەیەک بەرگەی ئاو دەگرێت (Water Resistant).\r\nچۆنیەتی بەکارهێنان:\r\n1. پێش چوونە بەر خۆر: پێویستە ٢٠ خولەک پێش ئەوەی بچیتە بەر خۆر لێی بدەیت.\r\n2. ڕاوەشاندن: پێش بەکارهێنان دەبێت بە باشی بیهەژێنیت.\r\n3. بڵاوکردنەوە: بە یەکسانی بەسەر پێستدا بڵاوی بکەرەوە و بە دەست کەمێک مەساژی بکە بۆ ئەوەی بمژرێت.\r\n4. دووبارە کردنەوە: پێویستە چەند جارێک لە ڕۆژدا دووبارەی بکەیتەوە، بەتایبەت دوای مەلەکردن یان ئارەقکردنەوەی زۆر یان وشککردنەوەی پێست بە خاولی.\r\n','Key Features:\n• Protective Grade (SPF 30): Provides good, “high” skin protection against sunlight.\n• Cyanide Filter System: Protects skin against both harmful rays (UVA and UVB), and contains vitamin E that prevents skin aging and cell damage caused by the sun.\n• For sensitive skin: This product is especially designed for people with sensitive or easily sunburned skin.\n• Balance pH 5.5: As with all Sebamed products, this balances the skin’s acidity and strengthens its natural barrier.\n• Moisturizing: Contains inulin and lecithin, which help soften and retain skin moisture.\n• Water resistance: Somewhat water resistant.\nHow to use:\n1. Before going out in the sun: You should apply it 20 minutes before going out in the sun.\n2. Shake: Shake well before use.\n3. Spread: Spread evenly over the skin and massage slightly with your hands for absorption.\n4. Repeat: Repeat several times a day, especially after swimming or excessive sweating or towel drying.','الميزات الرئيسية:\n• عامل حماية من الشمس (SPF 30): يوفر حماية عالية وفعالة للبشرة من أشعة الشمس.\n• نظام فلترة السيانيد: يحمي البشرة من الأشعة الضارة (UVA وUVB)، ويحتوي على فيتامين E الذي يمنع شيخوخة البشرة وتلف الخلايا الناتج عن الشمس.\n• للبشرة الحساسة: صُمم هذا المنتج خصيصًا للأشخاص ذوي البشرة الحساسة أو المعرضة لحروق الشمس.\n• درجة حموضة متوازنة 5.5: كما هو الحال مع جميع منتجات سيباميد، يعمل هذا المنتج على موازنة حموضة البشرة وتقوية حاجزها الطبيعي.\n• مرطب: يحتوي على الإينولين والليسيثين، اللذين يساعدان على تنعيم البشرة والحفاظ على رطوبتها.\n• مقاومة للماء: مقاوم للماء إلى حد ما.\n\nطريقة الاستخدام:\n1. قبل التعرض للشمس: يُنصح بوضعه قبل 20 دقيقة من التعرض للشمس.\n2. رج العبوة جيدًا: رج العبوة جيدًا قبل الاستخدام.\n3. وزّعه: وزّعه بالتساوي على البشرة ودلّكه برفق بيديك حتى يتم امتصاصه.\n\nطريقة الاستخدام:\n 4. التكرار: كرر ذلك عدة مرات في اليوم، خاصة بعد السباحة أو التعرق المفرط أو التجفيف بالمنشفة.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 04:21:50',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-43',0,0),(148,'لۆشنی دژە خۆر بۆ پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Sunscreen lotion for sensitive skin from German brand Sebamed','لوشن واقي من الشمس للبشرة الحساسة من العلامة التجارية الألمانية سيباميد','لۆشنی دژە خۆر بۆ پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,16750,22750,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پلەی پاراستن (SPF 30): پاراستنێکی باش (High Protection) دابین دەکات دژی تیشکی خۆر.\r\n• سیستەمی پاراستنی سێییانی: پارێزگاری لە پێست دەکات دژی هەردوو جۆری تیشکی UVA و UVB، هەروەها ڤیتامین E تێدایە کە وەک دژە ئۆکسان کاردەکات بۆ ڕێگری لە پیربوونی پێشوەختەی پێست.\r\n• نەرمی و شێداری: ماددەی \"ئینۆلین\" و \"لیستین\"ی تێدایە کە یارمەتی شێدارکردنەوەی پێست دەدەن بە قووڵی.\r\n• بۆ پێستی هەستیار: تایبەت دروستکراوە بۆ ئەو کەسانەی پێستیان بەرگەی خۆر ناگرێت یان هەستیارە.\r\n• هاوسەنگی pH 5.5: ئەمەش هاوکاری پاراستنی بەرگی سروشتی پێست دەکات و ڕێگری لە وشکبوونەوە دەکات.\r\n• بەرگری لە بەرامبەر ئاو (Water Resistant): بۆ ماوەیەکی باش لە کاتی ئارەقکردنەوە یان مەلەکردن دەمێنێتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n1. پێش چوونە بەر خۆر: پێویستە ٢٠ خولەک پێش ئەوەی بچیتە بەر تیشکی خۆر لۆشنەکە لە پێستت بدەیت.\r\n2. بڕی پێویست: بڕێکی گونجاو بەکاربهێنە؛ کەم بەکارهێنانی دەبێتە هۆی کەمبوونەوەی ئاستی پاراستنەکە.\r\n3. دووبارەکردنەوە: بۆ ئەوەی پاراستنەکە بەردەوام بێت، پێویستە چەند جارێک دووبارەی بکەیتەوە، بەتایبەت دوای مەلەکردن، ئارەقکردنەوە، یان وشککردنەوەی پێست بە خاولی.\r\n','Key Features:\n• Protection degree (SPF 30): Provides good protection (High Protection) against sunlight.\n• Triple Protection System: Protects skin against both UVA and UVB rays, and contains vitamin E, which acts as an antioxidant to prevent premature skin aging.\n• Softness and moisture: Contains enolin and listen, which help deeply moisturize the skin.\n• For sensitive skin: Specially formulated for people with sun intolerant or sensitive skin.\n• Balance pH 5.5: This helps maintain the skin’s natural texture and prevents dryness.\n• Water Resistant: Stays for a long time when sweating or swimming.\nHow to use:\n1. Before going out in the sun: Apply the lotion 20 minutes before going out in the sun.\n2. Quantity: Use the right amount; Underuse will reduce the level of protection.\n3. Repeat: To maintain protection, you should repeat several times, especially after swimming, sweating, or towel drying.','الميزات الرئيسية:\n• درجة الحماية (SPF 30): يوفر حماية عالية من أشعة الشمس.\n• نظام حماية ثلاثي: يحمي البشرة من أشعة UVA وUVB، ويحتوي على فيتامين E الذي يعمل كمضاد للأكسدة لمنع شيخوخة البشرة المبكرة.\n• نعومة وترطيب: يحتوي على الإينولين والليسين، مما يساعد على ترطيب البشرة بعمق.\n• للبشرة الحساسة: تركيبة خاصة للأشخاص ذوي البشرة الحساسة أو التي لا تتحمل الشمس.\n• درجة حموضة متوازنة 5.5: تساعد على الحفاظ على ملمس البشرة الطبيعي وتمنع جفافها.\n• مقاوم للماء: يدوم لفترة طويلة حتى مع التعرق أو السباحة.\n\nطريقة الاستخدام:\n1. قبل التعرض للشمس: ضعي اللوشن قبل 20 دقيقة من التعرض للشمس.\n2. الكمية: استخدمي الكمية المناسبة؛ فالاستخدام غير الكافي يقلل من مستوى الحماية.\n3. التكرار: للحفاظ على الحماية، كرري الاستخدام عدة مرات، خاصة بعد السباحة أو التعرق أو التجفيف بالمنشفة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 04:24:13',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-42',0,0),(149,'کرێمی شێدارکەرەوەی تایبەت بە پێستی دەست لە بڕاندی سێبامێدی ئەڵمانی','Moisturizing hand cream from German brand Sebamed','كريم مرطب لليدين من ماركة سيباميدي الألمانية','کرێمی شێدارکەرەوەی تایبەت بە پێستی دەست لە بڕاندی سێبامێدی ئەڵمانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• ڕێژەی 5% یۆریا (Urea): یۆریا ماددەیەکی سروشتی پێستە، کاردەکات بۆ شێدارکردنەوەی قووڵی پێست و یارمەتی لابردنی خانە مردووەکان و قڵیشاوی دەست دەدات.\r\n• چارەسەری خێرا: یارمەتیدەرێکی زۆر باشە بۆ کەمکردنەوەی خورووی دەست و ئەو سووربوونەوەیەی بەهۆی وشکییەوە دروست دەبێت.\r\n• پێکهاتەی دەوڵەمەند: جگە لە یۆریا، پێکهاتەی وەک Glycerin و Panthenol و Allantoinی تێدایە کە یارمەتی نوێبوونەوەی خانەکانی پێست دەدەن.\r\n• ڕۆنی سروشتی: ڕۆنی ئاڤۆکادۆ و **کاکاو (Cocoa Butter)**ی تێدایە کە پێستەکە نەرم دەکەن و دەیپارێزن لە دووبارە وشکبوونەوە.\r\nبۆ کێ گونجاوە؟\r\nئەم کرێمە تەنها بۆ وشکی ئاسایی نییە، بەڵکو کلینیکیانە سەلمێنراوە کە گونجاوە بۆ ئەم حاڵەتانەش:\r\n1. ئەوانەی بەدەست ئەکزیما (Atopic Eczema) دەناڵێنن.\r\n2. کەسانی تووشبوو بە نەخۆشی شەکرە (کە زۆرجار پێستیان وشک دەبێتەوە).\r\n3. ئەوانەی نەخۆشی **سەدەفی (Psoriasis)**یان هەیە.\r\nچۆنیەتی بەکارهێنان:\r\n• بەپێی پێویست بڕێکی گونجاو بدە لە دەستەکانت، بەتایبەت لەنێوان پەنجەکان و دەوروبەری نینۆکەکان.\r\n• بە هێواشی مەساجی پێ بکە تا پێستەکە بە تەواوی هەڵی دەمژێت.\r\nتێبینی: ئەم بەرهەمە لە ئەڵمانیا دروستکراوە و پشکنینی پزیشکی بۆ کراوە.\r\n','Key Features:\n• 5% Urea: Urea is a natural skin substance that works to deeply moisturize the skin and help remove dead cells and exfoliation.\n• Quick treatment: Very good helper to reduce hand itching and redness caused by dryness.\n• Rich Ingredients: In addition to urea, it contains ingredients such as Glycerin, Panthenol and Allantoin that promote skin cell renewal.\n• Natural oil: Contains avocado oil and cocoa butter to soften the skin and protect it from re-drying.\nWho is it suitable for?\nThis cream is not only for normal dryness, but is also clinically proven to be suitable for the following conditions:\n1. Those suffering from atopic eczema.\n2. People with diabetes (who often have dry skin).\n3. Those with psoriasis.\nHow to use:\n• Apply the right amount to your hands, especially between the fingers and around the nails.\n• Gently massage until completely absorbed by the skin.\nNote: This product is made in Germany and has been medically tested.','الميزات الرئيسية:\n• ٥٪ يوريا: اليوريا مادة طبيعية للبشرة تعمل على ترطيبها بعمق وتساعد على إزالة الخلايا الميتة وتقشيرها.\n• علاج سريع: يُعدّ هذا الكريم مساعدًا ممتازًا في تخفيف حكة اليدين واحمرارهما الناتج عن الجفاف.\n• مكونات غنية: بالإضافة إلى اليوريا، يحتوي على مكونات مثل الجلسرين والبانثينول والألانتوين التي تُعزز تجديد خلايا البشرة.\n• زيوت طبيعية: يحتوي على زيت الأفوكادو وزبدة الكاكاو لتنعيم البشرة وحمايتها من الجفاف مجددًا.\n\nلمن يُناسب؟\nهذا الكريم ليس فقط للجفاف العادي، بل ثبت سريريًا أيضًا أنه مناسب للحالات التالية:\n١. المصابون بالإكزيما التأتبية.\n٢. مرضى السكري (الذين يعانون غالبًا من جفاف البشرة).\n٣. المصابون بالصدفية.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة على يديكِ، خاصةً بين الأصابع وحول الأظافر.\n• دلكي بلطف حتى تمتصه البشرة تمامًا.\nاستخدمي الكريم. ملاحظة: هذا المنتج مصنوع في ألمانيا وقد تم اختباره طبياً.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 04:59:26',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'75ml','03-41',0,0),(150,'فۆمی پاکەرەوەی تایبەت بە ناوچەی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Cleansing foam for sensitive areas from the German brand Sebamed','رغوة تنظيف للمناطق الحساسة من العلامة التجارية الألمانية سيباميد','فۆمی پاکەرەوەی تایبەت بە ناوچەی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,11750,16750,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• هاوسەنگی ترشێتی (pH 3.8): ئەمە گرنگترین خاڵە، چونکە ئەم ئاستە لە pH هاوسەنگە لەگەڵ ژینگەی سروشتی ناوچە هەستیارەکان لە تەمەنی منداڵداندا، ئەمەش یارمەتی مانەوەی بەکتریا سوودبەخشەکان دەدات.\r\n• پێکهاتەی هێورکەرەوە: ماددەی Panthenol و Aloe barbadensis (ئالۆڤێرا)ی تێدایە کە پێست نەرم دەکەنەوە و ڕێگری لە سووربوونەوە و خورۆش دەکەن.\r\n• بەکارهێنانی ترشی لاکتیک (Lactic Acid): یارمەتی پاراستنی ناوچەکە دەدات لە هەوکردن و بەکتریا زیانبەخشەکان.\r\n• بێ سابوون: ئەم بەرهەمە سابوونی تێدا نییە (Soap-free)، بۆیە نابێتە هۆی وشکبوونەوەی پێست.\r\nسوودەکانی:\r\n• یارمەتی ڕێگریکردن لە دروستبوونی بۆنی ناخۆش دەدات.\r\n• بۆ بەکارهێنانی ڕۆژانە گونجاوە.\r\n• لە لایەن پزیشکانی پێست و ئافرەتانەوە تاقی کراوەتەوە.\r\nشێوازی بەکارهێنان:\r\n1. کەمێک لە شوێنەکە بە ئاو تەڕ بکە.\r\n2. بڕێکی کەم لە کەفەکە بخەرە سەر دەستت.\r\n3. بە هێواشی ناوچە هەستیارەکەی پێ بشۆ (تەنها بۆ بەکارهێنانی دەرەکییە).\r\n4. پاشان بە ئاوێکی زۆر بە جوانی لێی بکەرەوە.\r\nتێبینییەکی گرنگ: ئەم بەرهەمە تەنها بۆ بەکارهێنانی دەرەکییە.\r\n','Key Features:\n• Acidity balance (pH 3.8): This is the most important point, as this level of pH is in balance with the natural environment of sensitive areas during uterine life, which helps the survival of beneficial bacteria.\n• Soothing ingredients: Contains Panthenol and Aloe barbadensis (Aloe Vera) to soften the skin and prevent redness and itching.\n• Use Lactic Acid: Helps protect the area from infection and harmful bacteria.\n• Soap-free: This product is soap-free, so it does not dry the skin.\nBenefits:\n• Helps prevent bad breath.\n• Suitable for everyday use.\n• Tested by dermatologists and gynecologists.\nHow to use:\n1. Wet the area slightly with water.\n2. Put a small amount of the foam on your hand.\n3. Gently rub the sensitive area with it (for external use only).\n4. Then rinse thoroughly with plenty of water.\nIMPORTANT NOTE: This product is for external use only.','الميزات الرئيسية:\n• توازن الحموضة (درجة حموضة 3.8): هذه هي النقطة الأهم، حيث أن مستوى الحموضة هذا متوازن مع البيئة الطبيعية للمناطق الحساسة خلال فترة الحمل، مما يساعد على بقاء البكتيريا النافعة.\n• مكونات مُلطفة: يحتوي على البانثينول والصبار (الألوفيرا) لتنعيم البشرة ومنع الاحمرار والحكة.\n• يحتوي على حمض اللاكتيك: يساعد على حماية المنطقة من العدوى والبكتيريا الضارة.\n• خالٍ من الصابون: هذا المنتج خالٍ من الصابون، لذا فهو لا يُسبب جفاف البشرة.\n\n• فوائد:\n• يساعد على منع رائحة الفم الكريهة.\n• مناسب للاستخدام اليومي.\n• مُختبر من قبل أطباء الجلدية وأطباء النساء.\n\nطريقة الاستخدام:\n1. بللي المنطقة قليلاً بالماء.\n2. ضعي كمية صغيرة من الرغوة على يدك.\n3. دلكي المنطقة الحساسة بلطف (للاستخدام الخارجي فقط).\n4. اشطفي جيداً بكمية وفيرة من الماء.\nاشطفي جيداً بكمية وفيرة من الماء. ملاحظة هامة: هذا المنتج للاستخدام الخارجي فقط.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:02:08',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-40',0,0),(151,'ئاوی تایبەت بە لابردنی مکیاج بۆ پێستی چەور و تێکەڵ لە بڕاندی سێبامێدی ئەڵمانی','Makeup remover for oily and combination skin from German brand Sebamed','مزيل مكياج للبشرة الدهنية والمختلطة من ماركة سيباميدي الألمانية','ئاوی تایبەت بە لابردنی مکیاج بۆ پێستی چەور و تێکەڵ لە بڕاندی سێبامێدی ئەڵمانی',15,9250,13500,2000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ چ جۆرە پێستێکە؟ ئەم جۆرەیان بە تایبەت بۆ پێستی چەور و تێکەڵ (Oily and Combination Skin) دروستکراوە.\r\n• پلەی ترشێتی (pH 5.5): هاوسەنگی ترشێتی پێست دەپارێزێت، کە ئەمەش یارمەتی بەهێزکردنی بەرگری سروشتی پێست دەدات دژی بەکتریا و وشکبوونەوە.\r\n• پێکهاتەی Hamamelis: وەک لەسەر پاکەتەکە نووسراوە، ماددەی (Hamamelis)ی تێدایە کە یارمەتی کەمکردنەوەی چەوری زیادەی پێست دەدات و پێستەکە (Mattifies) دەکات، واتە بریقە زیادەکەی ناهێڵێت.\r\n• پاککردنەوەی قوڵ: یارمەتیدەرە بۆ لێکردنەوەی ماکیاژ و پیسی سەر پێست بەبێ ئەوەی پێستەکە زۆر وشک بکاتەوە.\r\nسوودەکانی بەکارهێنانی:\r\n1. لێکردنەوەی ماکیاژ: بە ئاسانی ماکیاژی دەموچاو و دەوروبەری چاو و لێو لادەبات.\r\n2. بێ پێویستی بە شتن: بەپێی ڕێنماییەکە، پێویست ناکات دوای بەکارهێنانی دەموچاو بە ئاو بشۆردرێت (بەڵام زۆرێک لە پسپۆڕانی پێست پێیان باشە دوای میسلار وۆتەر، دەموچاو بە غەسولێکی سوک بشۆردرێت).\r\n3. دژە هەستیاری: لەلایەن پزیشکانی پێست و چاوەوە تاقیکراوەتەوە و بۆ پێستی هەستیاریش گونجاوە.\r\nچۆنییەتی بەکارهێنان:\r\n• بڕێکی گونجاو لە گیراوەکە بکەرە سەر پارچەیەک لۆکە (Cotton pad).\r\n• بە نەرمی بەسەر دەموچاو، چاو، و لێوەکانتدا بیهێنە تا پیسی و ماکیاژەکە لادەچێت.\r\n• پێویست بە پەنەژان (خوراندنی توند) ناکات.\r\n• دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.\r\n','Key Features:\n• What skin type is it for? This one is specially designed for Oily and Combination Skin.\n• Acidity (pH 5.5): Maintains the skin’s acidity balance, which helps strengthen the skin’s natural defenses against bacteria and dryness.\n• Hamamelis Ingredients: As stated on the package, it contains Hamamelis, which helps reduce excess oil and mattifies the skin.\n• Deep cleansing: Helps remove makeup and dirt without drying the skin too much.\nBenefits of using:\n1. Makeup Remover: Easily removes makeup from the face, around the eyes and lips.\n2. No need to wash: According to the instructions, it is not necessary to wash the face with water after use (but many dermatologists prefer to wash the face with a mild lotion after Mislar Water).\n3. Anti-allergy: Tested by dermatologists and ophthalmologists and suitable for sensitive skin.\nHow to use:\n• Apply an appropriate amount of the solution to a cotton pad.\n• Gently apply to face, eyes, and lips until dirt and makeup are removed.\n• No panacea (severe itching) is required.\n• You can use it twice a day (morning and night).','الميزات الرئيسية:\n• ما نوع البشرة المناسب له؟ صُمم هذا المنتج خصيصًا للبشرة الدهنية والمختلطة.\n• حموضة متوازنة (درجة حموضة 5.5): يحافظ على توازن حموضة البشرة، مما يُعزز دفاعاتها الطبيعية ضد البكتيريا والجفاف.\n• مكونات الهاماميليس: كما هو موضح على العبوة، يحتوي على الهاماميليس، الذي يُساعد على تقليل الزيوت الزائدة ويُضفي على البشرة مظهرًا مطفيًا.\n• تنظيف عميق: يُساعد على إزالة المكياج والأوساخ دون تجفيف البشرة بشكل مفرط.\n\nفوائد الاستخدام:\n1. مزيل مكياج: يُزيل المكياج بسهولة من الوجه، وحول العينين، والشفاه.\n2. لا حاجة للغسل: وفقًا للتعليمات، ليس من الضروري غسل الوجه بالماء بعد الاستخدام (لكن يُفضل العديد من أطباء الجلدية غسل الوجه بلوشن لطيف بعد استخدام ماء الميسلار).\n3. مضاد للحساسية: تم اختباره من قبل أطباء الجلدية والعيون، وهو مناسب للبشرة الحساسة.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة من المحلول على قطعة قطن. • ضعيه برفق على الوجه والعينين والشفتين حتى إزالة الأوساخ والمكياج.\n• لا حاجة لعلاج الحكة الشديدة.\n• يمكنكِ استخدامه مرتين يوميًا (صباحًا ومساءً).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:15:21',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-39',0,0),(152,'ئاوی تایبەت بە لابردنی مکیاج بۆ پێستی ئاسای و وشک لە بڕاندی سێبامێدی ئەڵمانی','Makeup remover for normal and dry skin from German brand Sebamed','مزيل مكياج للبشرة العادية والجافة من ماركة سيباميدي الألمانية','ئاوی تایبەت بە لابردنی مکیاج بۆ پێستی ئاسای و وشک لە بڕاندی سێبامێدی ئەڵمانی',15,9250,13500,2000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• جۆری پێست: تایبەت دروستکراوە بۆ پێستی هەستیار (Sensitive Skin) و بەتایبەت بۆ پێستی ئاسایی تا وشک.\r\n• کاری سەرەکی: بۆ لابردنی مکیاج و پاککردنەوەی پێستی دەموچاو، چاو، و لێو بەکاردێت بەبێ ئەوەی پێویستت بە ئاو بێت.\r\n• هاوسەنگی (pH 5.5): ئەمە خاڵە بەهێزەکەی سێبامێدە؛ یارمەتی پاراستنی چینی سروشتی پێست دەدات و ڕێگری دەکات لە هەوکردن و وشکبوونەوەی پێست.\r\n• پێکهاتە: ماددەی Hyaluronی تێدایە کە شێداری بە پێست دەبەخشێت و ناهێڵێت دوای پاککردنەوە پێستەکە توند و وشک بێتەوە.\r\n• تەندروستی: لە لایەن پزیشکانی پێست و چاوەوە تاقی کراوەتەوە، بۆیە سەلامەتە بۆ ئەو کەسانەی هاوێنە (Lens) بەکاردەهێنن یان چاویان هەستیارە.\r\nسوودەکانی:\r\n1. پێویستی بە شتن نییە: دەتوانیت بەکاریبهێنیت بەبێ ئەوەی دوای بەکارهێنانی دەموچاوت بە ئاو بشۆیت (مەگەر خۆت پێت خۆشبێت).\r\n2. بێ کحولە: پێست ناکۆڵێتەوە و نایسوتێنێت.\r\n3. لابەری مکیاج: بە ئاسانی مکیاجی ئاسایی و تەنانەت هەندێک جۆری مکیاجی دژە ئاویش لادەبات.\r\nشێوازی بەکارهێنان:\r\n• بڕێکی گونجاو بکە سەر پارچەیەک لۆکە (Cotton pad).\r\n• بە هێمنی بەسەر دەموچاو، چاو و لێودا بیهێنە تا هەموو پیسی و مکیاجەکە لادەچێت.\r\n• پێویست بەوە ناکات پێستەکە زۆر بخشێنیت یان پەستانی لێ بکەیت.\r\n• دەتوانیت ڕۆژی دوو جار بەکاریبهێنیت (بەیانیان بۆ تازەکردنەوەی پێست و شەوان بۆ پاککردنەوە).\r\n','Key Features:\n• Skin type: Formulated for sensitive skin and especially for normal to dry skin.\n• Main function: Used to remove makeup and cleanse the skin of the face, eyes, and lips without the need for water.\n• Balance (pH 5.5): This is Sebamed’s strength; Helps protect the skin’s natural layer and prevents inflammation and dryness.\n• Ingredients: Contains hyaluron, which moisturizes the skin and prevents it from becoming tight and dry after cleansing.\n• Health: Tested by dermatologists and ophthalmologists, so it is safe for people who wear contact lenses or have sensitive eyes.\nBenefits:\n1. No rinsing required: You can use it without washing your face with water after use (unless you prefer).\n2. Alcohol-free: Does not scratch or burn the skin.\n3. Makeup Remover: Easily removes regular makeup and even some waterproof makeup.\nHow to use:\n• Apply an appropriate amount on a cotton pad.\n• Gently apply to face, eyes and lips until all dirt and makeup is removed.\n• There is no need to scratch or press the skin too much.\n• You can use it twice a day (morning to refresh the skin and at night to cleanse).','الميزات الرئيسية:\n• نوع البشرة: مُصمم خصيصًا للبشرة الحساسة، وخاصةً للبشرة العادية إلى الجافة.\n• الوظيفة الرئيسية: يُستخدم لإزالة المكياج وتنظيف بشرة الوجه والعينين والشفاه دون الحاجة إلى الماء.\n• متوازن (درجة حموضة 5.5): هذه هي ميزة سيباميد؛ فهو يساعد على الحفاظ على الطبقة الطبيعية للبشرة ويمنع الالتهابات وجفافها.\n• المكونات: يحتوي على حمض الهيالورونيك، الذي يرطب البشرة ويمنعها من أن تصبح مشدودة وجافة بعد التنظيف.\n• صحي: تم اختباره من قبل أطباء الجلدية والعيون، لذا فهو آمن للأشخاص الذين يرتدون العدسات اللاصقة أو لديهم عيون حساسة.\n\nالفوائد:\n1. لا حاجة للشطف: يمكنك استخدامه دون غسل وجهك بالماء بعد الاستخدام (إلا إذا كنتِ تفضلين ذلك).\n2. خالٍ من الكحول: لا يسبب خدوشًا أو حروقًا للبشرة.\n3. مزيل مكياج: يزيل المكياج العادي بسهولة، وحتى بعض أنواع المكياج المقاوم للماء.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة على قطعة قطن.\n• ضعيه بلطف على الوجه والعينين والشفتين حتى تتم إزالة جميع الأوساخ والمكياج.\n• لا داعي للفرك أو الضغط على البشرة بقوة.\n• يمكنكِ استخدامه مرتين يوميًا (صباحًا لإنعاش البشرة ومساءً لتنظيفها).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:16:55',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-38',0,0),(153,'پاودەری تایبەت بە منداڵان لە بڕاندی سێبامێدی ئەڵمانی','Baby powder from the German brand Sebamed','بودرة أطفال من ماركة سيباميدي الألمانية','پاودەری تایبەت بە منداڵان لە بڕاندی سێبامێدی ئەڵمانی',15,6500,9500,1500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی زەیتی زەیتون (Olive Oil): یارمەتی نەرمکردنەوەی پێست دەدات و لە وشکبوونەوە دەیپارێزێت.\r\n• ماددەی ئالانتۆین (Allantoin): ئەم ماددەیە کاردەکات بۆ کەمکردنەوەی هەستیاری و سووربوونەوەی پێست.\r\n• کەمکردنەوەی لێخشاندن: یارمەتی کەمکردنەوەی ئەو لێخشاندنە دەدات کە بەهۆی دایبی (پایپەرز) یان جلوبەرگەوە لەسەر پێستی منداڵەکە دروست دەبێت.\r\n• بێ زیانە: لە ڕووی پزیشکییەوە تاقیکراوەتەوە و گونجاوە بۆ ئەو منداڵانەی پێستیان زۆر ناسکە.\r\nچۆنێتی بەکارهێنان:\r\n١. بڕێکی کەم بکەرە سەر دەستی خۆت (دوور لە دەموچاوی منداڵەکە).\r\n٢. پاشان بە هێواشی بیدە لەو شوێنانەی پێستی منداڵەکە کە پێویستییەتی.\r\n٣. دوای بەکارهێنان سەری قوتووەکە بە باشی دابخە.\r\nئاگادارییە گرنگەکان (زۆر گرنگە):\r\n• دوورخستنەوە لە هەناسە: زۆر ئاگاداربە باودەرەکە لە لووت و دەمی منداڵەکە نزیک نەبێتەوە؛ چونکە هەڵمژینی تۆزی باودەر دەبێتە هۆی کێشەی کۆئەندامی هەناسە.\r\n• برینی کراوە: نابێت بەکاربهێنرێت ئەگەر پێستەکە بریندار بووبێت یان خوێنی لێ بێت.\r\n• دوور لە منداڵ: لە شوێنێکی وشک و فێنک و دوور لە دەستی منداڵ دایبنێ.\r\n','Key Features:\n• Olive Oil: Helps soften the skin and prevent it from drying out.\n• Allantoin: This substance works to reduce skin sensitivity and redness.\n• Reduce friction: Helps reduce friction caused by diapers (pipers) or clothing on baby’s skin.\n• Harmless: Clinically tested and suitable for children with very sensitive skin.\nHow to use:\n1. Apply a small amount to your hand (away from the child’s face).\n2. Then apply slowly to the areas of the child\'s skin that need it.\n3. Cap the bottle securely after use.\nIMPORTANT NOTICES (VERY IMPORTANT):\n• Remove from breath: Be very careful not to get the powder near the child’s nose and mouth; Because inhalation of powder dust can cause respiratory problems.\n• Open wounds: should not be used if the skin is injured or bleeding.\n• Out of reach of children: Keep in a dry, cool place out of reach of children.','الميزات الرئيسية:\n• زيت الزيتون: يساعد على ترطيب البشرة ومنع جفافها.\n• آلانتوين: تعمل هذه المادة على تقليل حساسية البشرة واحمرارها.\n• تقليل الاحتكاك: يساعد على تقليل الاحتكاك الناتج عن الحفاضات أو الملابس على بشرة الطفل.\n• آمن: تم اختباره سريريًا ومناسب للأطفال ذوي البشرة الحساسة جدًا.\n\nطريقة الاستخدام:\n1. ضعي كمية صغيرة على يدك (بعيدًا عن وجه الطفل).\n2. ثم دلكي بلطف المناطق التي تحتاج إلى ذلك من بشرة الطفل.\n3. أغلقي الزجاجة بإحكام بعد الاستخدام.\n\nملاحظات هامة (هام جدًا):\n• تجنبي وصول المسحوق إلى أنف وفم الطفل؛ لأن استنشاق غبار المسحوق قد يسبب مشاكل في الجهاز التنفسي.\n• الجروح المفتوحة: لا يُستخدم في حال وجود جروح أو نزيف في الجلد.\n• يُحفظ بعيدًا عن متناول الأطفال: يُحفظ في مكان جاف وبارد بعيدًا عن متناول الأطفال.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:18:55',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'100ml','03-37',0,0),(154,'سکڕەب و پاکەرەوەی تایبەت بە پێستی چەور و زیپکە لە بڕاندی سێبامێدی ئەڵمانی','Scrub and cleanser for oily skin and acne from the German brand Sebamed','مقشر ومنظف للبشرة الدهنية وحب الشباب من العلامة التجارية الألمانية سيباميد','سکڕەب و پاکەرەوەی تایبەت بە پێستی چەور و زیپکە لە بڕاندی سێبامێدی ئەڵمانی',15,14250,20750,3250,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاککردنەوەی قووڵ: یارمەتی پاککردنەوەی کونیلەکانی پێست دەدات و چەوری زیادە و پیسی لادەبات.\r\n• دژە زیپکە و خاڵی ڕەش: بەهۆی هەبوونی دەنکۆڵەی زۆر ورد (Micro-peeling particles)، خانە مردووەکانی پێست لادەبات و ڕێگری دەکات لە دروستبوونی خاڵی ڕەش و سپی.\r\n• پاراستنی هاوسەنگی پێست: خاوەنی pH 5.5 کێشراوە، کە هاوسەنگی سروشتی پێست دەپارێزێت و ناهێڵێت پێست وشک ببێتەوە یان تێکبچێت.\r\n• بۆ پێستی هەستیار گونجاوە: بە شێوەیەکی کلینیکی تاقیکراوەتەوە و زۆر نەرمە لەسەر پێست، وەک سکڕابە زبرەکان زیان بە پێست ناگەیەنێت.\r\nسوودەکانی:\r\n1. پێست ساف و گەشاوە دەکات.\r\n2. بەرگری سروشتی پێست بەهێز دەکات.\r\n3. پێست مات دەکاتەوە (کەمکردنەوەی بریقەی چەوری).\r\nشێوازی بەکارهێنان:\r\n1. پێستت بە ئاو تەڕ بکە.\r\n2. بڕێکی کەم لە سکڕابەکە بخەرە سەر دەستت و بە شێوەی بازنەیی و زۆر بە نەرمی مەساجی پێستی پێ بکە.\r\n3. دواتر بە ئاوێکی شلەتێن بە باشی بیشۆ.\r\n4. ئاگاداری: لە چواردەوری چاو بەکاری مەهێنە.\r\n5. دەتوانرێت ڕۆژی یەک جار بەکاربێت (بەپێی پێویستی و جۆری پێستت).\r\n','Key Features:\n• Deep Cleansing: Helps clear pores and removes excess oil and dirt.\n• Anti-acne and blackheads: Due to its micro-peeling particles, it removes dead skin cells and prevents the formation of blackheads and whiteheads.\n• Maintain skin balance: It has a pH of 5.5, which maintains the skin\'s natural balance and prevents skin dryness or damage.\n• Suitable for sensitive skin: Clinically tested and very gentle on the skin, not as damaging as rough scrubs.\nBenefits:\n1. Cleans and brightens the skin.\n2. Strengthens the skin\'s natural defenses.\n3. Dulls the skin (reduces the shine of oil).\nHow to use:\n1. Moisten your skin with water.\n2. Put a small amount of the scrub on your hand and massage in circular motions very gently.\n3. Then rinse thoroughly with lukewarm water.\n4. Caution: Do not use around the eyes.\n5. Can be used once a day (depending on your needs and skin type).','الميزات الرئيسية:\n• تنظيف عميق: يساعد على تنظيف المسام وإزالة الزيوت الزائدة والأوساخ.\n• مضاد لحب الشباب والرؤوس السوداء: بفضل جزيئاته الدقيقة المقشرة، يزيل خلايا الجلد الميتة ويمنع ظهور الرؤوس السوداء والبيضاء.\n• يحافظ على توازن البشرة: يتميز بدرجة حموضة 5.5، مما يحافظ على توازن البشرة الطبيعي ويمنع جفافها أو تلفها.\n• مناسب للبشرة الحساسة: تم اختباره سريريًا وهو لطيف جدًا على البشرة، وليس ضارًا مثل المقشرات الخشنة.\n\nالفوائد:\n1. ينظف البشرة ويمنحها إشراقة.\n2. يقوي دفاعات البشرة الطبيعية.\n3. يقلل من لمعان البشرة (يقلل من إفراز الزيوت).\n\nطريقة الاستخدام:\n1. بللي بشرتك بالماء.\n2. ضعي كمية صغيرة من المقشر على يدك ودلكيها بحركات دائرية لطيفة جدًا.\n3. اشطفي جيدًا بالماء الفاتر.\n4. تحذير: تجنبي استخدامه حول العينين. 5. يمكن استخدامه مرة واحدة يومياً (حسب احتياجاتك ونوع بشرتك).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:22:03',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-36',0,0),(155,'کرێمی شێدارکەرەوەی تایبەت بە منداڵان لە بڕاندی سێبامێدی ئەڵمانی','Moisturizing cream for children from the German brand Sebamed','كريم مرطب للأطفال من ماركة سيباميدي الألمانية','کرێمی شێدارکەرەوەی تایبەت بە منداڵان لە بڕاندی سێبامێدی ئەڵمانی',15,13000,18000,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پلەی ترشێتی (pH 5.5): ئەمە گرنگترین خاڵی بەرهەمەکەیە، چونکە هاوسەنگی ترشێتی سروشتی پێست دەپارێزێت و یارمەتی دروستبوونی چینی پارێزەری پێست دەدات.\r\n• بۆ پێستی زۆر ناسک: وەک لەسەری نووسراوە \"Extra Soft\"ـە، واتە زۆر نەرمە و بۆ ئەو منداڵانەی پێستیان هەستیارە گونجاوە.\r\n• پێکهاتەی دەوڵەمەند: پانتینۆڵ (Panthenol) و ڕۆنی جۆجۆبا (Jojoba Oil) و ئاڵانتۆینی تێدایە کە بۆ هێورکردنەوەی پێست و نەمانی سووربوونەوە زۆر باشن.\r\nسوودەکانی ئەم کرێمە:\r\n1. دژی وشکبوونەوە: ڕێگری دەکات لە وشکبوونی پێست و شێدارییەکی زۆری پێ دەبەخشێت.\r\n2. پاراستن: پێست دەپارێزێت لە کاریگەرییە دەرەکییە زیانبەخشەکان (وەک سەرما یان بای وشک).\r\n3. چاککردنەوەی پێست: یارمەتی زوو چاکبوونەوەی شوێنی سووربوونەوە یان خوران دەدات.\r\n4. بەکارهێنانی ڕۆژانە: دەتوانرێت بۆ دەموچاو و هەموو جەستەی منداڵەکە بەکاربهێنرێت.\r\nچۆنیەتی بەکارهێنان:\r\nبڕێکی گونجاو لە کرێمەکە بدە لە دەستت و بە نەرمی مەساجی پێ بکە بۆ سەر پێستی پاک و وشکی منداڵەکە. باشترە دوای گەرماوکردن بەکاربهێنرێت بۆ ئەوەی شێدارییەکە لە ناو پێستدا بهێڵێتەوە.\r\n','Key Features:\n• Acidity (pH 5.5): This is the most important point of the product, as it maintains the skin\'s natural acidity balance and helps form a protective layer.\n• For very delicate skin: As it says \"Extra Soft\", it is very soft and suitable for children with sensitive skin.\n• Rich ingredients: Contains panthenol, jojoba oil and allantoin, which are good for soothing the skin and relieving redness.\nBenefits of this cream:\n1. Anti-drying: Prevents dry skin and gives it plenty of moisture.\n2. Protection: Protects skin from harmful external influences (such as cold or dry wind).\n3. Skin repair: Helps early healing of redness or irritation.\n4. Daily Use: Can be used on the face and all over the body.\nHow to use:\nApply an appropriate amount of cream to your hands and massage gently onto baby’s clean, dry skin. It is best used after a bath to keep the moisture inside the skin.','الميزات الرئيسية:\n• حموضة متوازنة (درجة حموضة 5.5): هذه أهم ميزة في المنتج، حيث تحافظ على توازن حموضة البشرة الطبيعية وتساعد على تكوين طبقة واقية.\n• للبشرة الحساسة جدًا: كما هو موضح بعبارة \"ناعم جدًا\"، فهو ناعم للغاية ومناسب للأطفال ذوي البشرة الحساسة.\n• مكونات غنية: يحتوي على البانثينول وزيت الجوجوبا والألانتوين، وهي مكونات فعالة في تهدئة البشرة وتخفيف الاحمرار.\n\nفوائد هذا الكريم:\n1. مضاد للجفاف: يمنع جفاف البشرة ويمنحها ترطيبًا عميقًا.\n2. حماية: يحمي البشرة من العوامل الخارجية الضارة (مثل البرد أو الرياح الجافة).\n3. ترميم البشرة: يساعد على التئام الاحمرار أو التهيج بسرعة.\n4. للاستخدام اليومي: يمكن استخدامه على الوجه وكامل الجسم.\n\nطريقة الاستخدام: ضعي كمية مناسبة من الكريم على يديكِ ودلكيها بلطف على بشرة الطفل النظيفة والجافة. يُفضل استخدامه بعد الاستحمام للحفاظ على ترطيب البشرة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:24:32',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-35',0,0),(156,'سابوونی تایبەت  پێستی چەوری دەم و چاو لە بڕاندی سێبامێدی ئەڵمانی','Special soap for oily skin of the face from the German brand Sebamed','صابون خاص للبشرة الدهنية للوجه والعينين من العلامة التجارية الألمانية سيباميد','سابوونی تایبەت  پێستی چەوری دەم و چاو لە بڕاندی سێبامێدی ئەڵمانی',15,7750,10750,1500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ کێ گونجاوە؟ تایبەتە بۆ ئەو کەسانەی پێستیان چەورە یان زوو زیپکە و خاڵی ڕەش (Blackheads) لەسەر دەموچاویان دروست دەبێت.\r\n• هاوسەنگی pH 5.5: گرنگترین خاڵی ئەم سابوونە ئەوەیە کە پلەی ترشەڵۆکی پێست (pH) لە ئاستی ئاسایی خۆیدا دەهێڵێتەوە، ئەمەش یارمەتی پاراستنی چینی سروشتی پێست دەدات و ڕێگری دەکات لە گەشەکردنی بەکتریا.\r\n• پاقژکردنەوەی قووڵ: یارمەتی پاککردنەوەی کونیلەکانی پێست دەدات لە چەوری زیادە و پیسی، بەبێ ئەوەی پێستەکە وشک بکاتەوە.\r\n• پێکهاتەی دەوڵەمەند: ڤیتامین E و ترشە ئەمینییەکانی تێدایە کە پێست بە نەرمی دەهێڵنەوە.\r\nسوودەکانی:\r\n1. دژی زیپکە: یارمەتی کەمکردنەوە و نەهێشتنی زیپکە و خاڵە سپی و ڕەشەکان دەدات.\r\n2. کۆنترۆڵکردنی چەوری: ڕێژەی دەردانی چەوری پێست ڕێکدەخات.\r\n3. پاراستنی پێست: بەهۆی ئەوەی ماددەی سابوونی (Soap-free) تێدا نییە، پێست تێک نادات و بە ئارامی پاکی دەکاتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• ڕۆژی دوو جار (بەیانیان و شەوان) بەکاریدێت.\r\n• کەمێک ئاو بدە لە سابوونەکە و لەناو دەستت بیکە بە کەف، پاشان بە هێواشی بیدە لە دەموچاوت و مەساجی پێ بکە.\r\n• دواتر بە ئاوێکی شلەتێن بە باشی دەموچاوت بشۆ.\r\n• تێبینی: دوای بەکارهێنان، سابوونەکە لە شوێنێکی وشک دابنێ بۆ ئەوەی زوو نەتێتەوە و بۆ ماوەیەکی درێژتر بمێنێتەوە.\r\n','Key Features:\n• Who is it suitable for? It is especially for people with oily skin or frequent acne and blackheads on the face.\n• Balance pH 5.5: The most important point of this soap is that it keeps the acidity of the skin (pH) at its normal level, which helps to maintain the skin’s natural layer and prevents the growth of bacteria.\n• Deep Cleansing: Helps cleanse pores of excess oil and dirt, without drying the skin.\n• Rich Ingredients: Contains vitamin E and amino acids that keep skin supple.\nBenefits:\n1. Anti-acne: Helps reduce and eliminate acne, whiteheads and blackheads.\n2. Sebum control: Regulates the amount of sebum secreted by the skin.\n3. Skin protection: Because it does not contain soap (Soap-free), does not damage the skin and gently cleanses.\nHow to use:\n• Use twice a day (morning and night).\n• Add a little water to the soap and foam in your hands, then gently apply to your face and massage.\n• Then wash your face thoroughly with lukewarm water.\n• Note: After use, keep the soap in a dry place to prevent it from melting quickly and to keep it longer.','الميزات الرئيسية:\n• لمن يناسب؟ يناسب بشكل خاص أصحاب البشرة الدهنية أو الذين يعانون من حب الشباب والرؤوس السوداء بشكل متكرر.\n• درجة حموضة متوازنة 5.5: أهم ما يميز هذا الصابون هو قدرته على الحفاظ على حموضة البشرة (درجة الحموضة) عند مستواها الطبيعي، مما يساعد على الحفاظ على طبقة البشرة الطبيعية ويمنع نمو البكتيريا.\n• تنظيف عميق: يساعد على تنظيف المسام من الزيوت الزائدة والأوساخ، دون تجفيف البشرة.\n• مكونات غنية: يحتوي على فيتامين هـ والأحماض الأمينية التي تحافظ على نضارة البشرة.\n\nالفوائد:\n1. مضاد لحب الشباب: يساعد على تقليل حب الشباب والرؤوس البيضاء والسوداء والتخلص منها.\n2. تنظيم إفراز الدهون: ينظم كمية الدهون التي تفرزها البشرة.\n3. حماية البشرة: لأنه خالٍ من الصابون، فهو لا يضر البشرة وينظفها بلطف.\n\nطريقة الاستخدام:\n• يُستخدم مرتين يوميًا (صباحًا ومساءً).\n• أضيفي القليل من الماء إلى الصابون وافركيه بين يديكِ حتى تتكون رغوة، ثم ضعيه برفق على وجهكِ ودلكيه.\n• اغسلي وجهكِ جيداً بالماء الفاتر.\n\n• ملاحظة: بعد الاستخدام، احفظي الصابون في مكان جاف لمنع ذوبانه بسرعة وللحفاظ عليه لفترة أطول.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:27:42',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150g','03-34',0,0),(157,'پاکەرەوەی تایبەت بە پێستی چەور و تێکەڵی دەم و چاو لە بڕاندی سێبامێدی ئەڵمانی','Face cleanser for oily skin from German brand Sebamed','غسول للوجه للبشرة الدهنية من ماركة سيباميدي الألمانية','پاکەرەوەی تایبەت بە پێستی چەور و تێکەڵی دەم و چاو لە بڕاندی سێبامێدی ئەڵمانی',15,20000,29750,4750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• پاککردنەوەی قووڵ: یارمەتیدەرە بۆ پاککردنەوەی کونیلەکانی پێست لە چەوری زیادە و پیسی.\r\n• هاوسەنگی pH 5.5: ئەمە تایبەتمەندی بەناوبانگی سێبامیدە، کە دەبێتە هۆی پاراستنی چینی سروشتی بەرگری پێست و ڕێگری دەکات لە وشکبوونەوە و هەوکردن.\r\n• پێکهاتەی هێورکەرەوە: ماددەی (Hamamelis virginiana) و (Provitamin B5)ی تێدایە کە یارمەتی شێدارکردنەوە و هێورکردنەوەی پێست دەدەن.\r\n• ڕێگری لە زیپکە: بەهۆی ئەوەی ڕێگری دەکات لە گیرانی کونیلەکان، یارمەتیدەرە بۆ کەمکردنەوەی دروستبوونی زیپکە.\r\n٢. بۆ کێ گونجاوە؟\r\n• بۆ ئەو کەسانەی پێستیان چەورە.\r\n• بۆ ئەو کەسانەی پێستیان تێکەڵەیە (هەندێک شوێنی چەورە و هەندێک شوێنی وشکە).\r\n• بۆ پێستی هەستیار گونجاوە چونکە ماددەی سابوونی تێدا نییە.\r\n٣. چۆنیەتی بەکارهێنان:\r\n1. پێستت بە ئاو تەڕ بکە.\r\n2. بڕێکی کەم لە غسولەکە بخەرە سەر دەستت و کەمێک ئاوی تێکەڵ بکە تا کەف دەکات.\r\n3. بە هێواشی مەساجی پێستی دەموچاوت پێ بکە.\r\n4. پاشان بە ئاوێکی شلەتێن باش بیشۆ و وشکی بکەرەوە.\r\n','. . . . Key Features:\n• Deep Cleansing: Helps clear pores of excess oil and dirt.\n• Balance pH 5.5: This is the famous property of sebamide, which maintains the skin’s natural barrier layer and prevents dryness and inflammation.\n• Soothing ingredients: Contains Hamamelis virginiana and Provitamin B5 to help moisturize and soothe the skin.\n• Prevents acne: Because it prevents clogging of pores, it helps to reduce the formation of acne.\n2. Who is it suitable for?\n• For people with oily skin.\n• For people with combination skin (some oily areas and some dry areas).\n• Suitable for sensitive skin because it does not contain soap.\n3. How to use:\n1. Moisten your skin with water.\n2. Put a small amount of the lotion on your hand and mix a little water until it foams up.\n3. Gently massage your facial skin.\n4. Then rinse thoroughly with running water and dry.','الميزات الرئيسية:\n• تنظيف عميق: يساعد على تنظيف المسام من الزيوت الزائدة والأوساخ.\n• درجة حموضة متوازنة 5.5: هذه خاصية معروفة للسباميد، الذي يحافظ على طبقة الحاجز الطبيعية للبشرة ويمنع الجفاف والالتهاب.\n• مكونات ملطفة: يحتوي على خلاصة هاماميليس فيرجينيانا وبروفيتامين B5 لترطيب البشرة وتهدئتها.\n• يمنع ظهور حب الشباب: لأنه يمنع انسداد المسام، مما يساعد على تقليل ظهور حب الشباب.\n\n2. لمن يناسب؟\n• لأصحاب البشرة الدهنية.\n• لأصحاب البشرة المختلطة (بعض المناطق دهنية وبعضها جافة).\n• مناسب للبشرة الحساسة لأنه خالٍ من الصابون.\n\n3. طريقة الاستخدام:\n1. بللي بشرتك بالماء.\n2. ضعي كمية صغيرة من اللوشن على يدك وامزجيها بقليل من الماء حتى تتكون رغوة.\n3. دلكي بشرة وجهك بلطف.\n4. ثم اشطف جيداً بالماء الجاري وجفف.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:32:17',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-33',0,0),(158,'پاکەرەوەی تایبەت بە پێستی وشک و ئاسایی دەم و چاو لە بڕاندی سێبامێدی ئەڵمانی','Cleanser for dry and normal skin of the face from the German brand Sebamed','غسول للوجه للبشرة الجافة والعادية من ماركة سيباميدي الألمانية','پاکەرەوەی تایبەت بە پێستی وشک و ئاسایی دەم و چاو لە بڕاندی سێبامێدی ئەڵمانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکانی:\r\n• بۆ پێستی هەستیار: بە تایبەتی بۆ ئەو کەسانە دروستکراوە کە پێستیان هەستیارە و بە پاککەرەوە ئاساییەکان تێکدەچێت.\r\n• پێستی ئاسایی بۆ وشک: زۆر گونجاوە بۆ ئەو کەسانەی پێستیان وشکە یان ئاساییە، چونکە بە نەرمی پێستەکە پاک دەکاتەوە بەبێ ئەوەی وشکی بکاتەوە.\r\n• هاوسەنگی pH 5.5: ئەم خاڵە زۆر گرنگە؛ چونکە ژینگەی سروشتی پێست دەپارێزێت و ڕێگری دەکات لە تێکچوونی بەربەستی پارێزەری پێست.\r\n• پڕۆتینی ئاوریشمی هایدرۆلیزکراو (Hydrolyzed Silk): یارمەتی شێدارکردنەوەی پێست دەدات و وای لێدەکات نەرم و لووس بێت.\r\nسوودەکانی بەکارهێنانی:\r\n1. پاککردنەوەی قوڵ و نەرم: بەبێ ئەوەی ببێتە هۆی سووربوونەوە یان خوران، چەوری زیادە و پیسی سەر پێست لادەبات.\r\n2. پاراستنی شێی پێست: بەهۆی پێکهاتەی سۆدیۆم لاکتات، هاوسەنگی شێ لە ناو خانەکانی پێستدا دەپارێزێت.\r\n3. پشکنینی پزیشکی: لە لایەن پزیشکانی پێستەوە تاقیکراوەتەوە و پەسەند کراوە.\r\nچۆن بەکاردێت؟\r\n• سەرەتا دەموچاوت بە ئاوی شلەتێن تەڕ بکە.\r\n• بڕێکی کەم لە غسولەکە بخەرە سەر دەستت و مەساجی پێستی پێ بکە تا کەمێک کەف دروست دەکات.\r\n• پاشان بە جوانی بە ئاو بیشۆ و بە خاولییەکی نەرم دەموچاوت وشک بکەرەوە.\r\nتێبینی: ئەگەر پێستت زۆر چەورە یان زیپکەی زۆری هەیە، ڕەنگە جۆرەکانی تری سێبامێد (وەک Clear Face) زیاتر بۆت گونجاو بن.\r\n','Key Features:\n• For sensitive skin: Especially formulated for people with sensitive skin that is aggravated by conventional cleansers.\n• Normal to Dry Skin: Perfect for people with dry or normal skin, as it gently cleanses the skin without drying it out.\n• pH 5.5 balance: This point is very important; Because it protects the skin\'s natural environment and prevents the skin\'s protective barrier from breaking down.\n• Hydrolyzed Silk Protein: Helps moisturize the skin and make it soft and loose.\nBenefits of using:\n1. Deep and gentle cleansing: Removes excess oil and dirt from the skin without causing redness or irritation.\n2. Maintain skin moisture: Due to its sodium lactate content, it maintains the moisture balance in the skin cells.\n3. Medical examination: Tested and approved by dermatologists.\nhow is it used\n• Wet your face with lukewarm water first.\n• Put a small amount of the lotion on your hand and massage into the skin until it lathers slightly.\n• Then rinse thoroughly with water and dry your face with a soft towel.\nNote: If you have very oily or acne-prone skin, other types of Sebamed (such as Clear Face) may be more suitable for you.','الميزات الرئيسية:\n• للبشرة الحساسة: تركيبة خاصة لأصحاب البشرة الحساسة التي تتهيج بفعل المنظفات التقليدية.\n• للبشرة العادية إلى الجافة: مثالي لأصحاب البشرة الجافة أو العادية، حيث ينظف البشرة بلطف دون تجفيفها.\n• درجة حموضة متوازنة 5.5: هذه النقطة مهمة للغاية؛ لأنها تحمي البيئة الطبيعية للبشرة وتمنع تكسر حاجزها الواقي.\n• بروتين الحرير المتحلل: يساعد على ترطيب البشرة وجعلها ناعمة ومرنة.\n\nفوائد الاستخدام:\n1. تنظيف عميق ولطيف: يزيل الزيوت الزائدة والأوساخ من البشرة دون التسبب في احمرار أو تهيج.\n2. الحفاظ على رطوبة البشرة: بفضل احتوائه على لاكتات الصوديوم، يحافظ على توازن الرطوبة في خلايا البشرة.\n3. تم فحصه واعتماده من قبل أطباء الجلدية.\n\nطريقة الاستخدام:\n• بللي وجهك بالماء الفاتر أولاً.\nضعي كمية صغيرة من المستحضر على يدك ودلكيها على البشرة حتى تتكون رغوة خفيفة.\nتم اختباره واعتماده من قبل أطباء الجلدية. • ثم اشطفي وجهك جيداً بالماء وجففيه بمنشفة ناعمة.\n\nملاحظة: إذا كانت بشرتك دهنية جداً أو معرضة لحب الشباب، فقد تكون أنواع أخرى من سيباميد (مثل كلير فيس) أنسب لكِ.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:33:38',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150ml','03-32',0,0),(159,'پاکەرەوەی تایبەت بە ناوچەی هەستیاری خانمان لە بڕاندی سێبامێدی ئەڵمانی','Women\'s sensitive area cleanser from the German brand Sebamed','غسول للمناطق الحساسة للنساء من ماركة سيباميدي الألمانية','پاکەرەوەی تایبەت بە ناوچەی هەستیاری خانمان لە بڕاندی سێبامێدی ئەڵمانی',15,10750,15750,2500,1,'. تایبەتمەندییە سەرەکییەکانی:\r\n• بۆ تەمەنی ١٥ بۆ ٥٠ ساڵ: ئەم جۆرەیان بە تایبەت بۆ ئەو خانمانە دروستکراوە کە لە تەمەنی منداڵبوون و سووڕی مانگانەدان.\r\n• هاوسەنگی ترشێتی (pH 3.8): گرنگترین تایبەتمەندی ئەم بەرهەمە ئەوەیە کە پلەی ترشێتییەکەی pH 3.8، کە ڕێک گونجاوە لەگەڵ ژینگەی سروشتی ئەو ناوچەیە و ڕێگری دەکات لە گەشەی بەکتریا و کەڕووی زیانبەخش.\r\n• پێکهاتەی سروشتی: ماددەی Bisabolol (کە لە بەیبوون وەردەگیرێت) و Aloe barbadensis (ئالۆڤێرا)ی تێدایە کە یارمەتی هێورکردنەوەی پێست و ڕێگری لە سووربوونەوە و خوروان دەدەن.\r\n• بێ سابوون: ئەم بەرهەمە بەبێ بەکارهێنانی ماددە سابوونییە توندەکان دروستکراوە کە دەبنە هۆی وشکبوونەوە.\r\n٢. سوودەکانی بەکارهێنانی:\r\n• پارێزگاری لە بەکتریا سوودبەخشەکانی (Micro-flora) ناوچە هەستیارەکە دەکات.\r\n• بۆ کاتی سووڕی مانگانە زۆر گونجاوە بۆ پاککردنەوە و نەهێشتنی بۆنی ناخۆش.\r\n• دژی هەوکردن و سووربوونەوەیە.\r\n٣. شێوازی بەکارهێنان:\r\n• بڕێکی کەم بدە لە دەستەکانت و بیدە لە ناوچەی دەرەوەی کۆئەندامی زاوزێ (تەنها بۆ بەکارهێنانی دەرەکییە).\r\n• بە ئاوێکی شلەتێن بە باشی دەموچاو یان ناوچەکە بشۆ.\r\n• دەتوانرێت ڕۆژانە بەکاربهێنرێت.\r\nتێبینی گرنگ: ئەم جۆرەیان (pH 3.8) تەنها بۆ تەمەنی پێش تەمەنی بێئومێدی (Menopause) گونجاوە. دوای تەمەنی ٥٠ ساڵی، سێبامێد جۆرێکی تری هەیە کە pH 6.8 چونکە لەو تەمەنەدا پێویستی جەستە دەگۆڕێت.\r\n','. . . . Key Features:\n• For ages 15 to 50: This one is especially designed for women of childbearing and menstrual age.\n• Acidity balance (pH 3.8): The most important feature of this product is that the acidity degree of pH 3.8, which is suitable for the natural environment of the area and prevents the growth of harmful bacteria and worms.\n• Natural ingredients: Contains Bisabolol (derived from violet) and Aloe barbadensis (aloe vera) to help soothe the skin and prevent redness and itching.\n• Soap-free: This product is formulated without the use of harsh soapy ingredients that can cause dryness.\n2. Benefits of using:\n• Protects the beneficial bacteria (micro-flora) of the sensitive area.\n• Ideal for cleaning and eliminating bad breath during menstruation.\n• Anti-inflammatory and redness.\n3. How to use:\n• Apply a small amount to your hands and apply to the outer genital area (for external use only).\n• Rinse the face or area thoroughly with lukewarm water.\n• Can be used daily.\nImportant note: This one (pH 3.8) is only suitable for pre-menopausal age. After the age of 50, Sebamed has a pH of 6.8 because at that age the body’s needs change.','الميزات الرئيسية:\n• مناسب للأعمار من 15 إلى 50 عامًا: صُمم هذا المنتج خصيصًا للنساء في سن الإنجاب وسن الحيض.\n• توازن الحموضة (درجة حموضة 3.8): أهم ما يُميز هذا المنتج هو درجة حموضته المُناسبة للبيئة الطبيعية للمنطقة، والتي تبلغ 3.8، مما يمنع نمو البكتيريا الضارة والديدان.\n• مكونات طبيعية: يحتوي على البيسابولول (المستخلص من البنفسج) والصبار (الألوفيرا) لتهدئة البشرة ومنع الاحمرار والحكة.\n• خالٍ من الصابون: صُمم هذا المنتج بدون استخدام مكونات صابونية قاسية قد تُسبب الجفاف.\n\n2. فوائد الاستخدام:\n• يحمي البكتيريا النافعة (الميكروبات الطبيعية) في المنطقة الحساسة.\n• مثالي للتنظيف والتخلص من رائحة الفم الكريهة أثناء الدورة الشهرية.\n• مضاد للالتهابات والاحمرار.\n\n٣. طريقة الاستخدام:\n• ضعي كمية صغيرة على يديكِ ثم وزعيها على المنطقة التناسلية الخارجية (للاستخدام الخارجي فقط).\n• اشطفي الوجه أو المنطقة جيدًا بالماء الفاتر.\n• يمكن استخدامه يوميًا.\n\nملاحظة هامة: هذا المنتج (درجة حموضة ٣.٨) مناسب فقط لمن هنّ في سن ما قبل انقطاع الطمث. بعد سن الخمسين، يصبح سيباميد بدرجة حموضة ٦.٨ لأن احتياجات الجسم تتغير في هذه المرحلة العمرية.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:36:01',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-31',0,0),(160,'پاکەرەوەی تایبەت بە پێستی جەستە و دەم و چاوی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Cleanser for sensitive body, face skin from German brand Sebamed','غسول للبشرة الحساسة للجسم والوجه والعينين من العلامة التجارية الألمانية سيباميد','پاکەرەوەی تایبەت بە پێستی جەستە و دەم و چاوی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,9500,15500,3000,1,'. پاراستنی سروشتی پێست\r\nگرنگترین تایبەتمەندی بەرهەمەکانی سێبامید ئەوەیە کە پلەی ترشەڵۆکی پێست (pH 5.5) دەپارێزن. ئەمەش وادەکات چینی پارێزەری سروشتی پێست تێکنەچێت و لە وشکبوونەوە و بەکتریا بیپارێزێت.\r\n٢. پێکهاتە سەرەکییەکان\r\n• زەیتی زەیتون (Olive Oil): یارمەتی نەرمکردنەوەی پێست دەدات و ڕێگری دەکات لە لەدەستدانی شێداری لە کاتی شتندا.\r\n• پانتینۆڵ (Panthenol): یارمەتی نوێبوونەوەی خانەکانی پێست و هێورکردنەوەی هەستیاری (حەساسییە) دەدات.\r\n• نیشاستەی ڕووەکی: یارمەتیدەرە بۆ پاککردنەوەی پێست بە شێوەیەکی زۆر نەرم بەبێ ئەوەی پێستەکە زبر بکات.\r\n٣. سوودە سەرەکییەکان\r\n• بێ سابوون (Soap-free): ئەمە سابوون نییە، بۆیە وەک سابوونی ئاسایی پێست وشک ناکاتەوە و نایسوتێنێت.\r\n• بۆ دەموچاو و جەستە: دەتوانیت بۆ هەردوکیان بەکاریبهێنیت، کە ئەمەش کار ئاسانییە بۆ کاتی گەرماو.\r\n• دژە تێژبوونی پێست: زۆر گونجاوە بۆ ئەو کەسانەی دوای خۆشتن پێستیان دەخورێت یان سوور دەبێتەوە.\r\n٤. چۆنییەتی بەکارهێنان\r\n١. پێستت بە ئاو تەڕ بکە.\r\n٢. بڕێکی کەم لە غەسولەکە بخەرە سەر دەستت یان لۆفەیەکی نەرم و کەفێکی لێ دروست بکە.\r\n٣. بە هێواشی بە مەساج بیدە لە دەموچاو و جەستەت.\r\n٤. پاشان بە ئاوێکی شلەتێن باش بیشۆ.\r\nتێبینی: ئەگەر پێستت زۆر چەورە یان زیپکەی زۆرت هەیە، ڕەنگە ئەم جۆرەیان (کە بە زەیتونە) بۆ تۆ کەمێک قورس بێت و باشتر بێت جۆرە شینەکەی (Liquid Face & Body Wash) بەکاربهێنیت.\r\n','Protect the skin\'s nature\nThe most important feature of Sebamid products is that they maintain the acidity degree of the skin (pH 5.5). This prevents the skin\'s natural protective layer from being damaged and protects it from dryness and bacteria.\n2. The main ingredients\n• Olive Oil: Helps soften the skin and prevent moisture loss during washing.\n• Panthenol: Helps renew skin cells and soothe allergies.\n• Vegetable Starch: Helps to cleanse the skin ultra-gently without roughening it.\n3. The main advantages\n• Soap-free: This is not soap, so it does not dry or burn the skin like regular soap.\n• For face and body: You can use it for both, which makes it easy to take a bath.\n• Anti-skin rash: Very suitable for people whose skin is itchy or red after washing.\n4. How to use\n1. Moisten your skin with water.\n2. Put a small amount of the lotion on your hand or make a soft, foaming loaf.\n3. Gently massage into your face and body.\n4. Then rinse thoroughly with lukewarm water.\nNote: If you have very oily skin or a lot of acne, this one (which is in olive) may be a little heavy for you and it is better to use the blue one (Liquid Face & Body Wash).',' حماية صحة البشرة\nأهم ما يميز منتجات سيباميد هو قدرتها على الحفاظ على درجة حموضة البشرة (الرقم الهيدروجيني 5.5). هذا يمنع تلف الطبقة الواقية الطبيعية للبشرة ويحميها من الجفاف والبكتيريا.\n2. المكونات الرئيسية\n• زيت الزيتون: يساعد على ترطيب البشرة ومنع فقدان الرطوبة أثناء الغسل.\n• البانثينول: يساعد على تجديد خلايا البشرة وتهدئة الحساسية.\n• النشا النباتي: يساعد على تنظيف البشرة بلطف شديد دون التسبب في خشونة.\n\n3. المزايا الرئيسية\n• خالٍ من الصابون: هذا المنتج ليس صابونًا، لذا فهو لا يُسبب جفافًا أو حرقًا للبشرة مثل الصابون العادي.\nللوجه والجسم: يُمكن استخدامه لكليهما، مما يُسهل الاستحمام.\nمضاد للطفح الجلدي: مناسب جدًا للأشخاص الذين يعانون من حكة أو احمرار في البشرة بعد الغسل.\n\n4. طريقة الاستخدام\n1. بللي بشرتك بالماء.\n٢. ضعي كمية صغيرة من اللوشن على يدك أو اصنعي رغوة ناعمة.\n٣. دلكي وجهكِ وجسمكِ بلطف.\n٤. ثم اشطفي جيدًا بالماء الفاتر.\n\nملاحظة: إذا كانت بشرتكِ دهنية جدًا أو تعانين من حب الشباب بكثرة، فقد يكون هذا المنتج (بزيت الزيتون) ثقيلًا بعض الشيء، ويُفضل استخدام المنتج الأزرق (غسول سائل للوجه والجسم).',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:38:17',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-30',0,0),(161,'شامپۆی قژی تایبەت بە بەکارهێنانی ڕۆژانە لە بڕاندی سێبامێدی ئەڵمانی','Hair shampoo for daily use from German brand Sebamed','شامبو للشعر للاستخدام اليومي من ماركة سيباميدي الألمانية','شامپۆی قژی تایبەت بە بەکارهێنانی ڕۆژانە لە بڕاندی سێبامێدی ئەڵمانی',15,10750,16750,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ کێ دەبێت؟ تایبەت دروستکراوە بۆ قژی ئاسایی بۆ قژی وشک. هەروەها زۆر گونجاوە بۆ ئەو کەسانەی پێستی سەریان هەستیارە.\r\n• پلەی ترشێتی (pH 5.5): ئەمە گرنگترین خاڵی ئەم بەرهەمەیە؛ چونکە پلەی ترشێتییەکەی ڕێک لەگەڵ پلەی سروشتی پێستدایە، ئەمەش یارمەتی پاراستنی چینی بەرگری پێستی سەر دەدات و لە وشکبوونەوە دەیپارێزێت.\r\n• پاککردنەوەیەکی نەرم: ماددەی کیمیایی توندی تێدا نییە، بۆیە دەتوانیت ڕۆژانە بەکاری بهێنیت بەبێ ئەوەی زیان بە قژت بگەیەنێت یان پێستی سەرت بتووشێنێت.\r\nسوودەکانی:\r\n• پاراستنی شێداری: یارمەتی پاراستنی هاوسەنگی شێداری دەدات لەناو تاڵەکانی قژدا، کە وای لێدەکات قژەکە بریقەدار و نەرم بێت.\r\n• زیادکردنی قەبارە (Volume): بە شێوەیەک کار دەکات کە قژەکە بە پڕی و تەندروستی پیشان بدات.\r\n• بێ سابوون و ئەلکەلی: بە پێچەوانەی شامپۆ ئاساییەکان، سابوونی تێدا نییە کە ببێتە هۆی زبری قژ.\r\nچۆنیەتی بەکارهێنان:\r\n1. قژت بە ئاو تەڕ بکە.\r\n2. بڕێکی گونجاو لە شامپۆکە بدە لە لەپی دەستت و کەفێکی لێ دروست بکە.\r\n3. بە نەرمی مەساجی پێستی سەرت و قژتی پێ بکە.\r\n4. پاشان بە باشی بە ئاو بیشۆ.\r\n5. ئەگەر پێویستی کرد، دەتوانیت جارێکی تریش دووبارەی بکەیتەوە.','Key Features:\n• Who will it be for? Specially formulated for normal hair to dry hair. It is also very suitable for people with sensitive scalp.\n• Acidity (pH 5.5): This is the most important point of this product; Because its acidity is in line with the skin\'s natural temperature, it helps protect the scalp\'s protective layer from drying out.\n• Gentle cleanser: No harsh chemicals, so you can use it daily without damaging your hair or irritating your scalp.\nBenefits:\n• Moisture maintenance: Helps maintain moisture balance within the hair strands, making hair shiny and soft.\n• Volume: Works to make hair look fuller and healthier.\n• Soap and alkaline-free: Unlike regular shampoos, it does not contain soap that can cause hair roughness.\nHow to use:\n1. Wet your hair with water.\n2. Apply an appropriate amount of shampoo to your palms and foam.\n3. Gently massage into your scalp and hair.\n4. Then rinse thoroughly with water.\n5. If necessary, you can repeat again.','الميزات الرئيسية:\n• لمن هذا المنتج؟ تركيبة خاصة للشعر العادي إلى الجاف. كما أنه مناسب جدًا لأصحاب فروة الرأس الحساسة.\n• حموضة متوازنة (درجة حموضة 5.5): هذه هي أهم ميزة لهذا المنتج؛ فبفضل حموضته المتوازنة مع درجة حرارة فروة الرأس الطبيعية، يساعد على حماية الطبقة الواقية لفروة الرأس من الجفاف.\n• منظف لطيف: خالٍ من المواد الكيميائية القاسية، لذا يمكنك استخدامه يوميًا دون إتلاف شعرك أو تهيج فروة رأسك.\n\nالفوائد:\n• الحفاظ على ترطيب الشعر: يساعد على الحفاظ على توازن الرطوبة داخل خصلات الشعر، مما يجعله لامعًا وناعمًا.\n• كثافة الشعر: يعمل على جعل الشعر يبدو أكثر كثافة وصحة.\n• خالٍ من الصابون والمواد القلوية: على عكس أنواع الشامبو العادية، لا يحتوي على الصابون الذي قد يسبب خشونة الشعر.\n\nطريقة الاستخدام:\n1. بللي شعرك بالماء.\n2. ضعي كمية مناسبة من الشامبو على راحة يديكِ ودلكيها حتى تتكون رغوة.\n3. دلكي فروة رأسكِ وشعركِ بلطف.\n4. اشطفي شعركِ جيدًا بالماء. 5. إذا لزم الأمر، يمكنك التكرار مرة أخرى.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:40:21',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-29',0,0),(162,'شامپۆی دژە هەڵوەرینی قژ لە بڕاندی سێبامێدی ئەڵمانی','Anti-Hair Loss Shampoo from German brand Sebamed','شامبو مضاد لتساقط الشعر من العلامة التجارية الألمانية سيباميد','شامپۆی دژە هەڵوەرینی قژ لە بڕاندی سێبامێدی ئەڵمانی',15,11750,18750,3500,1,'تایبەتمەندییەکانی شامپۆکە:\r\n• بەهێزکردنی سوڕی خوێن: پێکهاتەی (NHE) و کافاین و گینکو بیلۆبای تێدایە، کە یارمەتی چالاککردنی سوڕی خوێن دەدەن لە بێخی سەردا، ئەمەش وادەکات قژەکە خۆراکی زیاتری پێ بگات.\r\n• پاراستنی ترشێتی (pH 5.5): هاوسەنگی ترشێتی پێستی سەر دەپارێزێت و چینە پارێزەرەکەی تێکنادات.\r\n• بۆ هەموو جۆرە قژێک: دەتوانرێت بۆ هەموو جۆرە قژێک بەکاربێت.\r\nشێوازی بەکارهێنان:\r\n١. قژت بە ئاو تەڕ بکە.\r\n٢. بڕێکی گونجاو لە شامپۆکە بدە لە لەپی دەستت و پاشان مەساجی پێستی سەری پێ بکە.\r\n٣. بۆ ماوەی ٢ خولەک بە بێخی سەرەوە بیهێڵەرەوە بۆ ئەوەی پێکهاتەکان کار بکەن و هەڵبمژرێن.\r\n٤. دواتر بە ئاوێکی زۆر قژت بشۆ.\r\nتێبینی گرنگ:\r\n• بڕی بەکارهێنان: بۆ پێستی سەری ئاسایی، بڕی یەک کەوچکی بچووک بەسە.\r\n• بۆ پێستی هەستیار: ئەگەر پێستی سەرت زۆر هەستیارە، بڕێکی کەمتر بەکاربهێنە و ڕۆژ نا ڕۆژێک قژتی پێ بشۆ.\r\n• ئاگاداری: زیادەڕۆیی مەکە لە بەکارهێنانی، چونکە ڕەنگە ببێتە هۆی سووربوونەوە و خوران. ئەگەر سووربوونەوەی کەم دروست بوو، ئاساییە و زۆربەی کات لە دوای ٣٠ خولەک نامێنێت.\r\n','Features of the shampoo:\n• Strengthen blood circulation: Contains NHE, caffeine and ginkgo biloba, which help activate blood circulation in the scalp, which makes the hair more nourished.\n• Acidity maintenance (pH 5.5): Maintains the scalp’s acidity balance and does not disrupt its protective layer.\n• For all hair types: Can be used for all hair types.\nHow to use:\n1. Wet your hair with water.\n2. Apply an appropriate amount of shampoo to your palms and then massage into the scalp.\n3. Leave for 2 minutes to let the ingredients work and absorb.\n4. Then rinse your hair with plenty of water.\nImportant Note:\n• Dosage: For normal scalp, 1 teaspoon is enough.\n• For sensitive skin: If your scalp is very sensitive, use a smaller amount and wash your hair every day.\n• Caution: Do not overuse, as it may cause redness and irritation. If a slight redness develops, it is normal and usually disappears after 30 minutes.','مميزات الشامبو:\n• يُحسّن الدورة الدموية: يحتوي على NHE والكافيين وخلاصة الجنكة بيلوبا، التي تُساعد على تنشيط الدورة الدموية في فروة الرأس، مما يُغذي الشعر.\n• يُحافظ على حموضة فروة الرأس (درجة حموضة 5.5): يُحافظ على توازن حموضة فروة الرأس ولا يُؤثر على طبقتها الواقية.\n• مُناسب لجميع أنواع الشعر: يُمكن استخدامه لجميع أنواع الشعر.\n\nطريقة الاستخدام:\n1. بللي شعركِ بالماء.\n2. ضعي كمية مُناسبة من الشامبو على راحة يديكِ، ثم دلكي فروة رأسكِ به.\n3. اتركيه لمدة دقيقتين حتى تتغلغل المكونات في الشعر.\n4. اشطفي شعركِ جيدًا بالماء.\n\nملاحظة هامة:\n• الجرعة: لفروة الرأس العادية، ملعقة صغيرة واحدة كافية.\n• للبشرة الحساسة: إذا كانت فروة رأسكِ حساسة جدًا، استخدمي كمية أقل واغسلي شعركِ يوميًا.\n• تحذير: لا تُفرطي في الاستخدام، فقد يُسبب احمرارًا وتهيجًا. إذا ظهر احمرار طفيف، فهذا أمر طبيعي وعادة ما يختفي بعد 30 دقيقة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:43:12',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-28',0,0),(163,'شامپۆی تایبەت بە وشکی پێستی سەر و قژ لە بڕاندی سێبامێدی ئەڵمانی','Dry scalp and hair shampoo from German brand Sebamed','شامبو للشعر وفروة الرأس الجافة من ماركة سيباميدي الألمانية','شامپۆی تایبەت بە وشکی پێستی سەر و قژ لە بڕاندی سێبامێدی ئەڵمانی',15,13500,19500,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی یۆریا (5% Urea): یۆریا یارمەتی شێدارکردنەوەی قووڵی پێستی سەر دەدات و ئەو خوراندنە توندە کەم دەکاتەوە کە بەهۆی وشکییەوە دروست دەبێت.\r\n• بۆ کێ گونجاوە؟ گونجاوە بۆ ئەو کەسانەی پێستی سەریان زۆر وشکە، یان ئەو بارودۆخانەی وەک (ئەکزیما، سەدەف، و وشکی پێست بەهۆی شەکرەوە).\r\n• پاککەرەوەی نەرم: پێکهاتەیەکی شەکرەیی تێدایە کە بە نەرمی قژ و پێستی سەر پاک دەکاتەوە بەبێ ئەوەی زیاتر وشکی بکاتەوە.\r\n• درەوشانەوەی قژ: نیشاستەی سروشتی تێدایە کە یارمەتی تەندروستی تاڵەکانی قژ و بریقەدارکردنیان دەدات.\r\nسوودەکانی:\r\n1. کەمکردنەوەی خورانی توندی سەر.\r\n2. نەهێشتنی کڕێش و سووربوونەوەی پێستی سەر کە بەهۆی وشکییەوە دروست بووە.\r\n3. پاراستنی هاوسەنگی شێی پێستی سەر و قژ.\r\nشێوازی بەکارهێنان:\r\n1. قژت بە ئاو تەڕ بکە.\r\n2. بڕێکی کەم لە شامبۆکە بخە ناو لەپی دەستت و مەساجی پێ بکە تا کەف دەکات.\r\n3. بە هێواشی بیدە لە پێستی سەرت و مەساجی پێ بکە.\r\n4. پاشان بە باشی بە ئاو بیشۆ.\r\n5. ئەگەر پێویست بوو دەتوانیت دووبارەی بکەیتەوە.\r\nتێبینی گرنگ:\r\n• ئەم شامبۆیە وەک هەنگاوی یەکەم بەکاردێت بۆ چارەسەری وشکی توند.\r\n• کاتێک پێستی سەرت باشتر بوو، کۆمپانیاکە پێشنیار دەکات بیگۆڕیت بۆ جۆری Anti-Dry Revitalizing Shampoo بۆ پاراستنی درێژخایەن.\r\n• تەنها بۆ بەکارهێنانی دەرەکییە.','Key Features:\n• Urea Ingredient (5% Urea): Urea helps deeply moisturize the scalp and reduces the severe itching caused by dryness.\n• Who is it suitable for? Suitable for people with very dry scalp, or conditions such as eczema, psoriasis, and dry skin due to diabetes.\n• Gentle Cleanser: Contains a sugary ingredient that gently cleanses the hair and scalp without further drying it.\n• Hair shine: Contains natural starches that help hair follicles stay healthy and shiny.\nBenefits:\n1. Reduce severe headache.\n2. Eliminate wrinkles and redness of the scalp caused by dryness.\n3. Maintain the moisture balance of the scalp and hair.\nHow to use:\n1. Wet your hair with water.\n2. Apply a small amount of the shampoo to your palm and massage until it foams.\n3. Gently apply to your scalp and massage.\n4. Then rinse thoroughly with water.\n5. You can repeat if necessary.\nImportant Note:\n• This shampoo is used as a first step to treat severe dryness.\n• Once your scalp has improved, the company recommends switching to Anti-Dry Revitalizing Shampoo for long-term protection.\n• For external use only.','الميزات الرئيسية:\n• مكون اليوريا (5% يوريا): تساعد اليوريا على ترطيب فروة الرأس بعمق وتخفيف الحكة الشديدة الناتجة عن الجفاف.\n• لمن يناسب؟ مناسب للأشخاص الذين يعانون من جفاف شديد في فروة الرأس، أو حالات مثل الإكزيما، والصدفية، وجفاف الجلد الناتج عن مرض السكري.\n• منظف لطيف: يحتوي على مكونات سكرية تنظف الشعر وفروة الرأس بلطف دون زيادة جفافهما.\n• لمعان الشعر: يحتوي على نشويات طبيعية تساعد بصيلات الشعر على البقاء صحية ولامعة.\n\nالفوائد:\n1. تخفيف الصداع الشديد.\n2. إزالة التجاعيد والاحمرار الناتج عن جفاف فروة الرأس.\n3. الحفاظ على توازن رطوبة فروة الرأس والشعر.\n\nطريقة الاستخدام:\n1. بللي شعرك بالماء.\n2. ضعي كمية صغيرة من الشامبو على راحة يدك ودلكيها حتى تتكون رغوة.\n3. وزعي الشامبو بلطف على فروة رأسك ودلكيها.\n4. اشطفي شعرك جيدًا بالماء.\nيمكنك تكرار العملية إذا لزم الأمر. ملاحظة هامة:\n• يُستخدم هذا الشامبو كخطوة أولى لعلاج الجفاف الشديد.\n• بعد تحسن حالة فروة رأسك، تنصح الشركة بالانتقال إلى شامبو مُنعش مضاد للجفاف لحماية طويلة الأمد.\n• للاستخدام الخارجي فقط.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:46:02',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml',NULL,0,0),(164,'لۆشنی چاکەرەوەی پێستی زۆر وشک لە بڕاندی سێبامێدی ئەڵمانی','Very dry skin repair lotion from German brand Sebamed','لوشن مرطب للبشرة شديدة الجفاف من ماركة سيباميدي الألمانية','لۆشنی چاکەرەوەی پێستی زۆر وشک لە بڕاندی سێبامێدی ئەڵمانی',15,13500,19500,3000,1,'پێکهاتە سەرەکییەکان:\r\n• ١٠٪ یووریا (Urea): ئەمە پێکهاتەیەکی سروشتییە کە یارمەتی شێدارکردنەوەی قووڵی پێست دەدات و خانە مردووەکان لادەبات، بەمەش زبری و قڵیشاوی پێست کەم دەکاتەوە.\r\n• ڕۆنی بادەمی شیرین و لێسیتین (Lecithin): یارمەتی هاوسەنگکردنەوەی چەورییە سروشتییەکانی پێست دەدەن و نایەڵن شێدارییەکەی لەدەست بدات.\r\nسوودەکانی ئەم لۆشنە:\r\n• نەهێشتنی خوران: بە شێوەیەکی خێرا خورانی توند کە بەهۆی وشکییەوە دروست دەبێت، کەمدەکاتەوە.\r\n• نەرمکردنەوەی پێست: پێستە زبر و توێکڵدارەکە زۆر بە باشی نەرم دەکات.\r\n• گونجاوە بۆ حاڵەتە تایبەتەکان: ئەم بەرهەمە زۆر گونجاوە بۆ ئەو کەسانەی نەخۆشی شەکرە، سەدەف (Psoriasis)، یان **ئێکزیما (Atopic Eczema)**یان هەیە، چونکە پێستی ئەم کەسانە زیاتر تووشی وشکبوونەوەی توند دەبێت.\r\nچۆن بەکاردێت؟\r\n• ڕۆژانە بەپێی پێویست دەدرێت لەو شوێنانەی جەستە کە زۆر وشکن یان دەخورێن.\r\n• پێویستە کەمێک مەساجی پێ بکرێت تا بە تەواوی لەلایەن پێستەوە دەمژرێت.\r\n• تێبینی ئەوە کراوە کە باشترە دوای ئەوەی پێستەکە باش بووەوە، بگۆڕدرێت بۆ بەرهەمەکانی \"Anti-Dry\"ی سێبامێد بۆ پاراستنی درێژخایەن.\r\nتێبینییەکی گرنگ:\r\nئەم لۆشنە تەنها بۆ بەکارهێنانی دەرەکییە (نابێت لە دەم و چاو و ناوەوەی جەستە بدرێت تەنها ئەگەر پزیشک بۆی دیاری کردبیت).','Key Ingredients:\n• 10% Urea: This is a natural ingredient that helps deeply moisturize the skin and remove dead cells, thus reducing roughness and exfoliation.\n• Sweet almond oil and lecithin: Help balance the skin\'s natural oils and prevent moisture loss.\nBenefits of this lotion:\n• Eliminate itching: Instantly relieves severe itching caused by dryness.\n• Skin Softening: Softens rough and scaly skin very well.\n• Suitable for special conditions: This product is ideal for people with diabetes, psoriasis, or atopic eczema, as their skin is more prone to severe dryness.\nhow is it used\n• Applied daily as needed to areas of the body that are very dry or itchy.\n• It should be massaged slightly until it is completely absorbed by the skin.\n• It has been noted that it is best to switch to Sebamed\'s \"Anti-Dry\" products for long-term protection after the skin has healed.\nImportant note:\nThis lotion is for external use only (it should not be applied to the face, eyes or internal body unless prescribed by a doctor).','المكونات الرئيسية:\n• ١٠٪ يوريا: مكون طبيعي يساعد على ترطيب البشرة بعمق وإزالة الخلايا الميتة، مما يقلل من الخشونة والتقشر.\n• زيت اللوز الحلو والليسيثين: يساعدان على موازنة الزيوت الطبيعية للبشرة ومنع فقدان الرطوبة.\n\nفوائد هذا المستحضر:\n• يزيل الحكة: يخفف الحكة الشديدة الناتجة عن الجفاف فورًا.\n• ينعم البشرة: ينعم البشرة الخشنة والمتقشرة بشكل ممتاز.\n• مناسب لحالات خاصة: هذا المنتج مثالي للأشخاص المصابين بداء السكري، أو الصدفية، أو الإكزيما التأتبية، لأن بشرتهم أكثر عرضة للجفاف الشديد.\n\nطريقة الاستخدام:\n• يوضع يوميًا حسب الحاجة على مناطق الجسم شديدة الجفاف أو التي تسبب الحكة.\n• يُدلك بلطف حتى تمتصه البشرة تمامًا.\n• يُنصح بالتحول إلى منتجات \"مضادة للجفاف\" من سيباميد للحصول على حماية طويلة الأمد بعد شفاء البشرة.\n\nملاحظة هامة:\nهذا المستحضر للاستخدام الخارجي فقط (لا ينبغي وضعه على الوجه أو العينين أو داخل الجسم إلا بوصفة طبية).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:48:17',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-27',0,0),(165,'شامپۆی چاکەرەوەی قژ لە بڕاندی سێبامێدی ئەڵمانی','Hair repair shampoo from German brand Sebamed','شامبو لإصلاح الشعر من ماركة سيباميدي الألمانية','شامپۆی چاکەرەوەی قژ لە بڕاندی سێبامێدی ئەڵمانی',15,13250,18500,2500,1,'. ئامانج و بەکارهێنان\r\n• بۆ قژی وشک و تێکچوو: ئەم شامپۆیە کار دەکات بۆ گەڕاندنەوەی شێ و نەرمی بۆ ئەو قژانەی کە بێهێز بوون.\r\n• پاراستنی پێستی سەر: بەهۆی ئەوەی هاوسەنگی ترشێتییەکەی pH 5.5 ـە، هاوشێوەی پێستی مرۆڤە و یارمەتی پاراستنی چینی سروشتی پێستی سەر دەدات.\r\n٢. پێکهاتە و سوودەکانی\r\n• پڕۆتینی ڕووەکی: پێکهاتەیەکی تێدایە کە لە پڕۆتینی سروشتی ڕووەک دروست کراوە، یارمەتی شێدارکردنەوەی تاڵەکانی قژ و پێستی سەر دەدات.\r\n• چاککردنەوەی تاڵەکان: کار دەکات بۆ پڕکردنەوەی ئەو درزانەی لەسەر تاڵە قژەکان دروست بوون، ئەمەش وادەکات قژەکە بریقەدارتر و نەرمتر دەربکەوێت.\r\n• کەمکردنەوەی وشکی: بەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە، بە ڕێژەی ٤٧٪ وشکی قژ کەمدەکاتەوە.\r\n٣. چۆنیەتی بەکارهێنان\r\n• قژت بە ئاو تەڕ بکە.\r\n• بڕێکی گونجاو لە شامپۆکە بدە لە دەستت و پاشان بیدە لە قژت و بە هێمنی مەساجی پێستی سەرت بکە.\r\n• بە باشی بە ئاو پاشماوەی شامپۆکە لێ بکەرەوە.\r\n• ئەگەر پێویست بوو دەتوانیت دووبارەی بکەیتەوە.\r\n','. . . . purpose and application\n• For dry and damaged hair: This shampoo works to restore moisture and softness to weakened hair.\n• Scalp Protection: With an acidity balance of pH 5.5, it is similar to human skin and helps protect the natural layer of the scalp.\n2. Ingredients and benefits\n• Plant Protein: Contains an ingredient made from natural plant proteins, helping to moisturize hair follicles and scalp.\n• Strand Repair: Works to fill cracks on the hair strands, making hair look shinier and softer.\n• Reduces dryness: According to the packaging, it reduces hair dryness by 47%.\n3. How to use\n• Wet your hair with water.\n• Apply an appropriate amount of shampoo to your hands, then apply to your hair and gently massage into your scalp.\n• Remove shampoo residue thoroughly with water.\n• You can repeat if necessary.','الغرض والاستخدام\n• للشعر الجاف والتالف: يعمل هذا الشامبو على استعادة رطوبة ونعومة الشعر الضعيف.\n• حماية فروة الرأس: بفضل درجة حموضته المتوازنة (pH 5.5)، فهو مشابه لبشرة الإنسان ويساعد على حماية الطبقة الطبيعية لفروة الرأس.\n\n٢. المكونات والفوائد\n• بروتين نباتي: يحتوي على مكونات مصنوعة من بروتينات نباتية طبيعية، تساعد على ترطيب بصيلات الشعر وفروة الرأس.\n• إصلاح الشعر: يعمل على ملء التشققات في خصلات الشعر، مما يجعل الشعر أكثر لمعانًا ونعومة.\n• يقلل الجفاف: وفقًا للعبوة، يقلل جفاف الشعر بنسبة 47%.\n\n٣. طريقة الاستخدام\n• بللي شعرك بالماء.\n• ضعي كمية مناسبة من الشامبو على يديك، ثم وزعيها على شعرك ودلكي فروة رأسك بلطف.\n• اشطفي بقايا الشامبو جيدًا بالماء.\n• يمكنكِ تكرار العملية إذا لزم الأمر.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:50:54',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-26',0,0),(166,'کۆندێشنەری چاکەرەوەی قژ لە بڕاندی سێبامێدی ئەڵمانی','Hair repair conditioner from German brand Sebamed','بلسم لإصلاح الشعر من ماركة سيباميدي الألمانية','کۆندێشنەری چاکەرەوەی قژ لە بڕاندی سێبامێدی ئەڵمانی',15,12000,17000,2500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ کێ گونجاوە؟ بە تایبەت بۆ ئەو قژانە دروستکراوە کە ئاسایی یان وشکن، یان بەهۆی ڕەنگکردن و ئامێرە گەرمکەرەوەکانەوە زیانیان پێگەیشتووە.\r\n• هاوسەنگی pH 5.5: گرنگترین خاڵی ئەم بەرهەمە ئەوەیە کە پلەی ترشێتییەکەی (pH) ڕێک 5.5ـە، ئەمەش یارمەتی پاراستنی چینی سروشتی پارێزەری سەر دەدات و ڕێگری دەکات لە هەوکردن و کڕێشی سەر.\r\n• پڕۆتینی ئاوریشم (Silk Protein): ئەم ماددەیە قژەکە نەرم دەکات و ڕێگری لە وشکبوونەوەی دەگرێت، هەروەها بریقەیەکی جوان دەدات بە قژ.\r\n• پانتینۆڵ (Panthenol): کاردەکات بۆ چاککردنەوەی تاڵە قژە زیانلێکەوتووەکان و بەهێزکردنیان لە ناوەوە.\r\nسوودەکانی بەکارهێنان:\r\n1. قژ نەرم دەکات و داهێنانی ئاسان دەکات.\r\n2. قەبارە (Volume) و بریقە بە قژ دەبەخشێت بەبێ ئەوەی قژەکە چەور بکات.\r\n3. پێستی سەر ناخورێنێت چونکە لە ڕووی کلینیکییەوە تاقیکراوەتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• دوای ئەوەی قژت بە شامپۆ دەشۆیت، بڕێکی گونجاو لە بەڵسەمەکە بدە لە تاڵەکانی قژت (دوور بکەوەرەوە لەوەی بیدەیت لە بێخی سەرت).\r\n• بە هێواشی مەساجی پێ بکە و با بۆ ماوەی ٢ بۆ ٣ خولەک پێوەی بێت.\r\n• دواتر بە ئاوی شلەتێن بە باشی بیشۆ.\r\nتێبینی: باشترە لەگەڵ شامپۆیەکی گونجاوی هەمان براند بەکاری بهێنیت بۆ ئەوەی باشترین ئەنجامت دەستبکەوێت.','Key Features:\n• Who is it suitable for? It is especially designed for hair that is normal or dry, or damaged by coloring and heating devices.\n• pH 5.5 balance: The most important point of this product is that its pH is exactly 5.5, which helps preserve the natural protective layer of the scalp and prevents inflammation and wrinkles.\n• Silk Protein: This substance softens the hair and prevents it from drying out, and gives it a beautiful shine.\n• Panthenol: Works to repair damaged hair follicles and strengthen them from within.\nBenefits of use:\n1. Softens hair and makes it easier to create.\n2. Gives volume and shine to hair without greasing it.\n3. Does not irritate the scalp because it is clinically tested.\nHow to use:\n• After shampooing your hair, apply an appropriate amount of the balm to your strands (avoid applying it to the scalp).\n• Gently massage and let it stick for 2 to 3 minutes.\n• Then rinse thoroughly with lukewarm water.\nNote: It is best to use with a suitable shampoo from the same brand for best results.','الميزات الرئيسية:\n• لمن يناسب؟ صُمم خصيصًا للشعر العادي أو الجاف، أو التالف نتيجة الصبغات أو أدوات التصفيف الحرارية.\n• درجة حموضة متوازنة 5.5: أهم ما يميز هذا المنتج هو درجة حموضته المتوازنة 5.5، مما يساعد على الحفاظ على الطبقة الواقية الطبيعية لفروة الرأس ويمنع الالتهابات والتجاعيد.\n• بروتين الحرير: تعمل هذه المادة على تنعيم الشعر ومنع جفافه، وتمنحه لمعانًا رائعًا.\n• البانثينول: يعمل على إصلاح بصيلات الشعر التالفة وتقويتها من الداخل.\n\nفوائد الاستخدام:\n1. يُنعم الشعر ويسهل تصفيفه.\n2. يمنح الشعر كثافة ولمعانًا دون أن يجعله دهنيًا.\n3. لا يُسبب تهيجًا لفروة الرأس لأنه مُختبر سريريًا.\n\nطريقة الاستخدام:\n• بعد غسل الشعر بالشامبو، ضعي كمية مناسبة من البلسم على خصلات شعرك (تجنبي وضعه على فروة الرأس).\nدلكي بلطف واتركيه لمدة 2 إلى 3 دقائق.\n• ثم اشطف جيداً بالماء الفاتر.\n\nملاحظة: يُفضل استخدامه مع شامبو مناسب من نفس العلامة التجارية للحصول على أفضل النتائج.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:53:11',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'200ml','03-25',0,0),(167,'کرێمی پارێزەر و دژە پیربوونی پێست لە بڕاندی سێبامێدی ئەڵمانی','Skin protection and anti-aging cream from the German brand Sebamed','كريم لحماية البشرة ومكافحة الشيخوخة من العلامة التجارية الألمانية سيباميد','کرێمی پارێزەر و دژە پیربوونی پێست لە بڕاندی سێبامێدی ئەڵمانی',15,22500,32500,5000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی Q10: ئەم ماددەیە یارمەتی خانەکانی پێست دەدات بۆ نوێبوونەوە و وزە وەرگرتن، کە دەبێتە هۆی کەمکردنەوەی چرچ و لۆچی دەموچاو.\r\n• پانتینۆڵ (Panthenol) و ڤیتامین E: یارمەتی نەرمکردنەوە و شێدارکردنەوەی پێست دەدەن و وەک دژە ئۆکسان کار دەکەن بۆ پاراستنی پێست لە کاریگەرییە خراپەکانی دەوروبەر.\r\n• ترشێتی pH 5.5: ئەمە تایبەتمەندی بەناوبانگی سێبامێدە، کە هاوسەنگی ترشێتی سروشتی پێست دەپارێزێت و ڕێگری دەکات لە وشکبوونەوە و هەستیاری.\r\n• ڕۆنی بادەم و کەرەی شیا (Shea Butter): پێست بە قووڵی شێدار دەکەن و ڕێگری دەکەن لە لەدەستدانی شێداری سروشتی.\r\nسوودەکانی:\r\n1. دژە پیربوون: لە ماوەی ٢٨ ڕۆژدا بە ڕێژەی ٧٩٪ نیشانەکانی پیربوون کەم دەکاتەوە.\r\n2. بۆ پێستی هەستیار: زۆر گونجاوە بۆ ئەو کەسانەی پێستیان هەستیارە یان زوو سوور دەبێتەوە، چونکە ماددەی کیمیایی توندی تێدا نییە.\r\n3. شێدارکردن: پێستەکە بە توندی و نەرمی دەهێڵێتەوە.\r\nچۆنیەتی بەکارهێنان:\r\n• دوای ئەوەی پێستت بەباشی پاک دەکەیتەوە (بە غسولێکی گونجاو)، بڕێکی کەم لە کرێمەکە بدە لە دەموچاو، مل، و بەشی سەرەوەی سنگ.\r\n• ڕۆژانە دوو جار (بەیانیان و شەوان) بە شێوەی مەساجی هێواش بەکاری بهێنە.\r\nتێبینی: ئەگەر پێستت زۆر چەورە، لەوانەیە ئەم کرێمەت کەمێک بەلاوە قورس بێت چونکە پێکهاتەی شێدارکەرەوەی زۆری تێدایە، بەڵام بۆ پێستی وشک و مامناوەند نایابە.','Key Features:\n• Q10 ingredient: This substance helps skin cells to renew and energize, which reduces facial wrinkles.\n• Panthenol and vitamin E: Help soften and moisturize the skin and act as antioxidants to protect the skin from harmful environmental influences.\n• Acidity pH 5.5: This is Sebamed’s famous property, which balances the skin’s natural acidity and prevents dryness and sensitivity.\n• Almond Oil and Shea Butter: Deeply moisturize skin and prevent loss of natural moisture.\nBenefits:\n1. Anti-aging: Reduces signs of aging by 79% in 28 days.\n2. For sensitive skin: Very suitable for people with sensitive or red skin, because it does not contain harsh chemicals.\n3. Moisturizing: Keeps skin firm and soft.\nHow to use:\n• After cleansing your skin thoroughly (with an appropriate lotion), apply a small amount of cream to your face, neck, and upper chest.\n• Apply twice daily (morning and night) as a gentle massage.\nNote: If you have very oily skin, you may find this cream a little heavy because it contains a lot of moisturizing ingredients, but it is great for dry and medium skin.','الميزات الرئيسية:\n• مكون Q10: يساعد هذا المكون خلايا البشرة على التجدد والتنشيط، مما يقلل من تجاعيد الوجه.\n• البانثينول وفيتامين E: يساعدان على تنعيم وترطيب البشرة، ويعملان كمضادات للأكسدة لحمايتها من العوامل البيئية الضارة.\n• درجة حموضة 5.5: هذه خاصية مميزة لمنتجات سيباميد، حيث توازن حموضة البشرة الطبيعية وتمنع جفافها وحساسيتها.\n• زيت اللوز وزبدة الشيا: يرطبان البشرة بعمق ويمنعان فقدان رطوبتها الطبيعية.\n\nالفوائد:\n1. مكافحة الشيخوخة: يقلل من علامات الشيخوخة بنسبة 79% خلال 28 يومًا.\n2. للبشرة الحساسة: مناسب جدًا لأصحاب البشرة الحساسة أو الحمراء، لأنه خالٍ من المواد الكيميائية القاسية.\n3. ترطيب: يحافظ على نعومة البشرة ومرونتها.\n\nطريقة الاستخدام:\n• بعد تنظيف البشرة جيدًا (باستخدام غسول مناسب)، ضعي كمية صغيرة من الكريم على الوجه والرقبة وأعلى الصدر.\n• استخدميه مرتين يوميًا (صباحًا ومساءً) مع التدليك بلطف.\nاستخدميه مرتين يوميًا (صباحًا ومساءً) مع التدليك. ملاحظة: إذا كانت بشرتك دهنية للغاية، فقد تجدين هذا الكريم ثقيلاً بعض الشيء لأنه يحتوي على الكثير من المكونات المرطبة، ولكنه رائع للبشرة الجافة والمتوسطة.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:55:42',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-24',0,0),(168,'کرێمی شێدارکەرەوەی تایبەت بە پێستی هەستیار و وشک لە بڕاندی سێبامێدی ئەڵمانی','Moisturizing cream for sensitive and dry skin from German brand Sebamed','كريم مرطب للبشرة الحساسة والجافة من ماركة سيباميدي الألمانية','کرێمی شێدارکەرەوەی تایبەت بە پێستی هەستیار و وشک لە بڕاندی سێبامێدی ئەڵمانی',15,2000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• دەوڵەمەندە بە ڤیتامین E: ڕێژەی 2% ڤیتامین E تێدایە کە وەک دژە ئۆکسان کاردەکات و پێست لە پیربوونی پێشوەختە و کاریگەرییە خراپەکانی ژینگە دەپارێزێت.\r\n• هاوسەنگی pH 5.5: ئەمە گرنگترین خاڵی بەرهەمەکانی سێبامێدە، چونکە پارێزگاری لە ترشەڵۆکی سروشتی پێست دەکات و ڕێگری دەکات لە وشکبوونەوە و هەوکردنی پێست.\r\n• شێدارکردنێکی قووڵ: یارمەتی هاوسەنگکردنەوەی شێی پێست دەدات و پێستەکە نەرم دەکات.\r\n• خێرا هەڵدەمژرێت: چەورییەکی بێزارکەر لەسەر پێست جێناهێڵێت و زوو بە پێستەکەوە دیار نامێنێت.\r\nبۆ کێ گونجاوە؟\r\n• بۆ ئەو کەسانەی پێستیان ئاسایی یان وشکە.\r\n• زۆر گونجاوە بۆ پێستی هەستیار چونکە لەلایەن پزیشکانی پێستەوە تاقی کراوەتەوە و ماددەی زیانبەخشی تێدا نییە.\r\nچۆنیەتی بەکارهێنان:\r\n١. سەرەتا پێستت بە پاککەرەوەیەکی گونجاو (وەک سابوونی سێبامێد) بشۆ و وشکی بکەرەوە.\r\n٢. بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاو و مل.\r\n٣. بە هێواشی بە شێوەی بازنەیی مەساژی بۆ بکە تا پێستەکە بە تەواوی هەڵیدەمژێت.\r\n','Key Features:\n• Rich in vitamin E: Contains 2% vitamin E, which acts as an antioxidant and protects the skin from premature aging and adverse environmental effects.\n• pH 5.5 balance: This is the most important point of Sebamed products, as it maintains the natural acidity of the skin and prevents dryness and inflammation.\n• Deep moisturizing: Helps rebalance skin moisture and softens skin.\n• Quickly absorbed: Does not leave an annoying oil on the skin and disappears quickly.\nWho is it suitable for?\n• For people with normal or dry skin.\n• Very suitable for sensitive skin because it has been tested by dermatologists and does not contain harmful substances.\nHow to use:\n1. First, wash and dry your skin with an appropriate cleanser (such as Sebamed soap).\n2. Apply an appropriate amount of the cream to the face and neck.\n3. Gently massage in circular motions until the skin absorbs it completely.','الميزات الرئيسية:\n• غني بفيتامين هـ: يحتوي على 2% من فيتامين هـ، الذي يعمل كمضاد للأكسدة ويحمي البشرة من الشيخوخة المبكرة والآثار البيئية الضارة.\n• درجة حموضة متوازنة 5.5: هذه هي أهم ميزة في منتجات سيباميد، حيث تحافظ على حموضة البشرة الطبيعية وتمنع الجفاف والالتهاب.\n• ترطيب عميق: يساعد على إعادة توازن رطوبة البشرة وينعمها.\n• سريع الامتصاص: لا يترك أي أثر دهني مزعج على البشرة ويختفي بسرعة.\n\nلمن يناسب؟\n• مناسب لأصحاب البشرة العادية أو الجافة.\n• مناسب جدًا للبشرة الحساسة لأنه تم اختباره من قبل أطباء الجلدية ولا يحتوي على مواد ضارة.\n\nطريقة الاستخدام:\n1. اغسلي بشرتك وجففيها جيدًا باستخدام غسول مناسب (مثل صابون سيباميد).\n2. ضعي كمية مناسبة من الكريم على الوجه والرقبة.\n3. دلكي بلطف بحركات دائرية حتى تمتصه البشرة تمامًا.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 05:58:32',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'75ml','03-22',0,0),(169,'کرێمی تایبەت بەکەمکردنەوەی نیشانەکانی پیری وپڕکردنەوەی چرچ و لۆچی دەم و چاو لە بڕاندی سێبامێدی ئەڵمانی','Cream to reduce the signs of aging and fill the wrinkles of the face from the German brand Sebamed','كريم من ماركة سيباميدي الألمانية لتقليل علامات الشيخوخة وملء تجاعيد الوجه ','کرێمی تایبەت بەکەمکردنەوەی نیشانەکانی پیری وپڕکردنەوەی چرچ و لۆچی دەم و چاو لە بڕاندی سێبامێدی ئەڵمانی',15,27250,37750,5500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سێ لایەنەی هیالۆرۆنیک ئەسید (Triple Hyaluronic Complex): ئەم کرێمە سێ جۆر کێشی گەردیلەیی جیاوازی هیالۆرۆنیکی تێدایە کە یارمەتیدەرە بۆ:\r\n1. کێشی زۆر: شێدارییەکی دەستبەجێ بە ڕووی دەرەوەی پێست دەبەخشێت.\r\n2. کێشی مامناوەند: بە شێوەیەکی کاتی دەچێتە ناو چینەکانی سەرەوەی پێست بۆ پڕکردنەوەی هێڵەکان.\r\n3. کێشی کەم: دەچێتە ناو چینە قووڵترەکانی پێست بۆ باشترکردنی شێداری و نەرمکردنی پێست لە بنەڕەتەوە.\r\n• ماددەی ئالانتۆین (Allantoin): یارمەتی نەرمکردنەوە و هێورکردنەوەی پێست دەدات و ڕێگری لە وشکبوونەوە دەکات.\r\n• نەبوونی چەوری: وەک لەسەر کارتۆنەکە نووسراوە، زوو هەڵدەمژرێت و هەستی چەوری جێناهێڵێت، بۆیە بۆ ژێر مکیاژیش گونجاوە.\r\n• pH 5.5: ئەمەش هاوسەنگییەکی تەندروست بۆ پێست دروست دەکات و پارێزگاری لە چینی سروشتی بەرگری پێست دەکات.\r\nسوودەکانی:\r\n• یارمەتی پڕکردنەوە و کەمکردنەوەی چرچی و هێڵە وردەکانی دەموچاو دەدات.\r\n• پێست بە شێداری و توندی دەهێڵێتەوە.\r\n• دوای ٢٨ ڕۆژ بەکارهێنان، ئەنجامێکی دیاری دەبێت لە کەمکردنەوەی چرچییەکان.\r\nچۆنیەتی بەکارهێنان:\r\n1. بەیانیان و شەوان دوای ششتنی دەموچاو بەکاری بهێنە.\r\n2. بڕێکی گونجاو بدە لە دەموچاو، مل، و بەشی سەرەوەی سنگ.\r\n3. بە هێواشی مەساجی پێ بکە تا هەڵدەمژرێت.\r\n4. ئاگاداری: پێویستە بە لایەنی کەمەوە ١ سانتیمەتر لە چاوەکانتەوە دوور بێت.','Key Features:\n• Triple Hyaluronic Complex: This cream contains three different molecular weights of hyaluronic acid that helps to:\n1. Overweight: Provides immediate moisture to the outer surface of the skin.\n2. Medium Weight: Temporarily penetrates the upper layers of the skin to fill in lines.\n3. Low weight: penetrates deeper layers of skin to improve moisture and smooth skin from the ground up.\n• Allantoin: Helps soften and soothe the skin and prevents dryness.\n• No grease: As written on the carton, it absorbs quickly and does not leave a greasy feeling, so it is also suitable for under makeup.\n• pH 5.5: This creates a healthy balance for the skin and maintains the skin’s natural barrier layer.\nBenefits:\n• Helps fill in and reduce facial wrinkles and fine lines.\n• Keeps skin moisturized and firm.\n• After 28 days of use, there will be a definite result in reducing wrinkles.\nHow to use:\n1. Use in the morning and at night after washing your face.\n2. Apply appropriate amounts to face, neck, and upper chest.\n3. Gently massage until absorbed.\n4. Caution: It should be at least 1 cm away from your eyes.','الميزات الرئيسية:\n• مركب الهيالورونيك الثلاثي: يحتوي هذا الكريم على ثلاثة أنواع مختلفة من حمض الهيالورونيك بأوزان جزيئية مختلفة، مما يساعد على:\n1. ترطيب عميق: يوفر ترطيبًا فوريًا للسطح الخارجي للبشرة.\nترطيب متوسط: يتغلغل مؤقتًا في الطبقات العليا من الجلد لملء الخطوط الدقيقة.\nترطيب خفيف: يتغلغل في طبقات الجلد العميقة لتحسين الترطيب وتنعيم البشرة من الجذور إلى الأطراف.\nآلانتوين: يساعد على تنعيم البشرة وتهدئتها ويمنع جفافها.\nغير دهني: كما هو موضح على العبوة، يمتص بسرعة ولا يترك ملمسًا دهنيًا، لذا فهو مناسب أيضًا كأساس للمكياج.\nدرجة حموضة 5.5: تحافظ على توازن البشرة وتحافظ على طبقة الحاجز الطبيعية لها.\n\nالفوائد:\n• يساعد على ملء وتقليل تجاعيد الوجه والخطوط الدقيقة.\nيحافظ على ترطيب البشرة وشدّها.\nبعد 28 يومًا من الاستخدام، ستلاحظين نتائج واضحة في تقليل التجاعيد.\n\nطريقة الاستخدام:\n١. يُستخدم صباحًا ومساءً بعد غسل الوجه.\n٢. ضعي كمية مناسبة على الوجه والرقبة وأعلى الصدر.\n٣. دلكي بلطف حتى يتم امتصاصه.\n٤. تنبيه: يجب إبقاء المنتج على بُعد ١ سم على الأقل من العينين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:01:07',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-21',0,0),(170,'کرێمی تایبەت بە پستی دەم و چاوی زۆر وشک لە بڕاندی سێبامێدی ئەڵمانی','Cream for very dry face from the German brand Sebamed','كريم للبشرة شديدة الجفاف من ماركة سيباميدي الألمانية','کرێمی تایبەت بە پستی دەم و چاوی زۆر وشک لە بڕاندی سێبامێدی ئەڵمانی',15,18500,26500,4000,1,'پێکهاتە سەرەکییەکان و سوودەکانیان:\r\n• 5% یۆریا (Urea): ئەمە گرنگترین پێکهاتەیەتی. یۆریا یارمەتی شێدارکردنەوەی قووڵی پێست دەدات، کزانەوە و خوران ناهێڵێت و ئەو توێژاڵە (قڵیشانە) لادەبات کە بەهۆی وشکییەوە دروست دەبێت.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست لە کاریگەرییە خراپەکانی دەوروبەر دەپارێزێت.\r\n• پانتینۆڵ (Panthenol): یارمەتی نوێبوونەوەی خانەکانی پێست دەدات و خێرای دەکات لە چاکبوونەوە.\r\n• بیسابۆلۆڵ (Bisabolol): کە لە ڕووەکی بەیبوون وەردەگیرێت، بۆ هێورکردنەوەی پێست و نەهێشتنی سووربوونەوە زۆر باشە.\r\n• گیای پڵنگ (Tiger Grass): یارمەتی زیادکردنی کێش r پێست (Elasticity) دەدات و نیشانەکانی چرچبوونی ناهێڵێت.\r\nکەی و بۆ کێ بەکاردێت؟\r\n• بۆ ئەو کەسانەی پێستیان زۆر وشکە و هەمیشە هەست بە توندی و خوران دەکەن.\r\n• بۆ ئەو کەسانەی تووشی حاڵەتەکانی (ئەکزیما، سەدەف، یان وشکی پێست بەهۆی شەکرە) بوون، چونکە زۆر گونجاوە بۆیان.\r\n• لەبەر ئەوەی پەرەی پێدراوە لەلایەن پزیشکانی پێستەوە، زۆر سەلامەتە و هەستیاری دروست ناکات.\r\nچۆنیەتی بەکارهێنان:\r\n١. سەرەتا دەموچاوت بە پاککەرەوەیەکی گونجاو بشۆ و بەجوانی وشکی بکەرەوە.\r\n٢. بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاو، مل و بەشی سەرەوەی سنگ.\r\n٣. بە هێواشی مەساجی بۆ بکە تا پێستەکە بە تەواوی هەڵیدەمژێت.\r\n٤. دەتوانیت ڕۆژانە چەند جارێک بەکاری بهێنیت (بەپێی پێویستی وشکی پێستت).\r\nتێبینی: تەنها بۆ بەکارهێنانی دەرەکییە و ئاگاداربە نەکەوێتە ناو چاوەکانت.\r\n','Key ingredients and benefits:\n• 5% Urea: This is the most important ingredient. Urea helps deeply moisturize the skin, prevents sagging and itching and removes scales caused by dryness.\n• Vitamin E: Acts as an antioxidant and protects the skin from harmful environmental effects.\n• Panthenol: Helps skin cell renewal and accelerates healing.\n• Bisabolol: Derived from the violet plant, it is good for soothing the skin and relieving redness.\n• Tiger Grass: Helps increase weight r skin elasticity and prevents wrinkles.\nWhen and for whom is it used?\n• For people with very dry skin that always feels tight and itchy.\n• For people with conditions (eczema, psoriasis, or dry skin due to diabetes), because it is very suitable for them.\n• Because it was developed by dermatologists, it is very safe and non-allergenic.\nHow to use:\n1. First, wash your face with an appropriate cleanser and dry it thoroughly.\n2. Apply an appropriate amount of the cream to the face, neck and upper chest.\n3. Gently massage until completely absorbed by the skin.\n4. You can use it several times a day (depending on the dryness needs of your skin).\nNote: For external use only and be careful not to get into your eyes.','المكونات الرئيسية وفوائدها:\n• ٥٪ يوريا: هذا هو المكون الأهم. تساعد اليوريا على ترطيب البشرة بعمق، وتمنع الترهل والحكة، وتزيل القشور الناتجة عن الجفاف.\n• فيتامين هـ: يعمل كمضاد للأكسدة ويحمي البشرة من التأثيرات البيئية الضارة.\n• بانثينول: يساعد على تجديد خلايا البشرة ويسرع عملية الشفاء.\n• بيسابولول: مستخلص من نبات البنفسج، وهو مفيد لتهدئة البشرة وتخفيف الاحمرار.\n• عشبة النمر: تساعد على زيادة وزن البشرة ومرونتها وتمنع ظهور التجاعيد.\n\nمتى ولمن يُستخدم؟\n• للأشخاص ذوي البشرة الجافة جدًا التي تشعر دائمًا بالشد والحكة.\n• للأشخاص الذين يعانون من حالات جلدية معينة (مثل الإكزيما، والصدفية، أو جفاف البشرة الناتج عن مرض السكري)، لأنه مناسب جدًا لهم.\n• لأنه طُوّر من قبل أطباء الجلدية، فهو آمن تمامًا ولا يسبب الحساسية.\n\nطريقة الاستخدام:\n١. اغسلي وجهك أولًا بمنظف مناسب وجففيه جيدًا.\nلأنه طُوّر من قبل أطباء الجلدية، فهو آمن جدًا ولا يسبب الحساسية. ٢. ضعي كمية مناسبة من الكريم على الوجه والرقبة وأعلى الصدر.\n٣. دلكي بلطف حتى تمتصه البشرة تمامًا.\n٤. يمكنكِ استخدامه عدة مرات في اليوم (حسب حاجة بشرتكِ للترطيب).\n\nملاحظة: للاستخدام الخارجي فقط، يُرجى الحرص على عدم ملامسته للعينين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:04:21',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-20',0,0),(171,'کرێمی تایبەت بە پێست و پاژنەی پێ لە بڕاندی سێبامێدی ئەڵمانی','Ankle and foot skin cream from German brand Sebamed','كريم للكاحل من ماركة سيباميدي الألمانية','کرێمی تایبەت بە پێستی پاژنەی پێ لە بڕاندی سێبامێدی ئەڵمانی',15,10750,15750,2500,1,'پێکهاتە سەرەکییەکەی:\nئەم کرێمە ڕێژەی 10% یووریا (Urea) تێدایە. یووریا ماددەیەکی زۆر کاریگەرە بۆ:\n• شێدارکردنەوە: ئاو بۆ ناو پێست ڕادەکێشێت و ڕێگری دەکات لە وشکبوونەوە.\n• قەشرە لادان: یارمەتی لێکردنەوەی پێستە مردووەکان و زبرەکان دەدات (کە دەبێتە هۆی نەرمکردنی پاژنەی پێ).\nسوودەکانی بەرهەمەکە:\n• نەهێشتنی خورۆن: یارمەتیدەرە بۆ کەمکردنەوەی ئەو خورۆنە زۆرەی بەهۆی وشکییەوە دروست دەبێت.\n• چاککردنەوەی شەقبوونی پێ: زبری و قڵیشاوی و شەقبوونی پاژنەی پێ چارەسەر دەکات.\n• پێکهاتەی تەندروست: پانتینۆڵ و ڤیتامین E تێدایە کە یارمەتی نوێبوونەوەی پێست دەدەن.\n• تایبەت بە نەخۆشییەکان: گونجاوە بۆ ئەو کەسانەی پێستیان زۆر وشکە یان تووشبووی شەکرە، سەدەف (Psoriasis)، و ئەکزیمان.\nچۆن بەکاری بهێنیت؟\n1. پێیەکانت بە باشی بشۆ و وشکی بکەرەوە.\n2. بڕێکی گونجاو لە کرێمەکە بدە لەو شوێنانەی وشک یان قڵیشاون.\n3. بە باشی مەساجی بۆ بکە تا پێستەکە هەڵیدەمژێت.\n4. دەتوانیت ڕۆژانە بەکاری بهێنیت تا ئەو کاتەی پێستت چاک دەبێتەوە.\nتێبینی گرنگ:\n• ئەم کرێمە بۆ پێ دروستکراوە، بۆیە باشترە بۆ دەموچاو بەکارنەیەت چونکە ڕێژەی یووریاکەی زۆرە بۆ پێستی دەموچاو.','The main squad:\nThis cream contains 10% urea. Urea is a very effective agent for:\n• Moisturizing: Attracts water into the skin and prevents dryness.\n• Exfoliation: Helps remove dead and rough skin (which softens the ankle).\nBenefits of the product:\n• Eliminate itching: Helps reduce excessive itching caused by dryness.\n• Repair sprains: Treats roughness, exfoliation and sprains of the ankles.\n• Healthy ingredients: Contains panthenol and vitamin E that promote skin rejuvenation.\n• Disease-specific: Suitable for people with very dry skin or diabetes, psoriasis, and eczema.\nhow do you use it\n1. Wash and dry your feet thoroughly.\n2. Apply an appropriate amount of cream to dry or peeling areas.\n3. Massage well until skin absorbs.\n4. You can use it daily until your skin heals.\nImportant Notes:\n• This cream is designed for the feet, so it is better not to use it for the face because it contains too much urea for the skin.','المكونات الرئيسية:\nيحتوي هذا الكريم على 10% من اليوريا. اليوريا عامل فعال للغاية في:\n• الترطيب: يجذب الماء إلى الجلد ويمنع جفافه.\n• التقشير: يساعد على إزالة الجلد الميت والخشن (مما يُنعم الكاحل).\n\nفوائد المنتج:\n• التخلص من الحكة: يساعد على تقليل الحكة المفرطة الناتجة عن الجفاف.\n• علاج التواءات الكاحل: يعالج خشونة الجلد، وتقشيره، والتواءات الكاحل.\n• مكونات صحية: يحتوي على البانثينول وفيتامين هـ اللذين يعززان تجديد البشرة.\n• مناسب لحالات محددة: مناسب للأشخاص ذوي البشرة شديدة الجفاف، أو المصابين بداء السكري، أو الصدفية، أو الإكزيما.\n\nطريقة الاستخدام:\n1. اغسل قدميك وجففهما جيدًا.\n2. ضع كمية مناسبة من الكريم على المناطق الجافة أو المتقشرة.\n3. دلك جيدًا حتى يمتص الجلد الكريم.\n4. يمكنك استخدامه يوميًا حتى يشفى جلدك.\nيمكنك استخدامه يوميًا حتى يشفى جلدك. ملاحظات هامة:\n• هذا الكريم مصمم للقدمين، لذا يُفضل عدم استخدامه على الوجه لاحتوائه على نسبة عالية من اليوريا التي قد لا تناسب البشرة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:10:41',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'100ml','03-19',0,0),(174,'کرێمی تایبەت بە پێستی چەور و زیپکە و خاڵە رەشەکان لە بڕاندی سێبامێدی ئەڵمانی','Cream for oily skin, acne and blackheads from the German brand Sebamed','كريم للبشرة الدهنية، وحب الشباب، والرؤوس السوداء من العلامة التجارية الألمانية سيباميد','کرێمی تایبەت بە پێستی چەور و زیپکە و خاڵە رەشەکان لە بڕاندی سێبامێدی ئەڵمانی',15,13500,19500,3000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی چەور و زیپکەدار: بە تایبەت دروستکراوە بۆ چارەسەرکردنی کێشەکانی پێستی تێکەڵ و چەور کە زیپکەی زۆر دروست دەکات.\r\n• کەمکردنەوەی چەوری (Mattifying): کار دەکات بۆ ڕێکخستنی دەردانی چەوری (Sebum) لە پێستدا، ئەمەش دەبێتە هۆی ئەوەی پێستەکە بریقەی نەمێنێت و شێوەیەکی سروشتی و وشکی (مات) هەبێت.\r\n• pH 5.5: ئەم بەرهەمە پارێزگاری لە ترشەڵۆکی سروشتی پێست دەکات، کە یارمەتیدەرە بۆ ڕێگریکردن لە گەشەی بەکتریا و دروستبوونی زیپکە.\r\nپێکهاتە و سوودەکانی:\r\n• ئەسپێی کێوی (Horse Chestnut): یارمەتی هێورکردنەوەی پێست و کەمکردنەوەی سووربوونەوە و هەوکردن دەدات.\r\n• Hyaluron: پێستەکە بە شێداری دەهێڵێتەوە بەبێ ئەوەی چەوری بکات.\r\n• بێ چەوری: کرێمەکە زۆر خێرا هەڵدەمژرێت و هەستی چەوری بەجێناهێڵێت.\r\nچۆنیەتی بەکارهێنان:\r\n١. سەرەتا دەموچاوت بە باشی بە پاککەرەوەیەکی گونجاو بشۆ (وەک سابوون یان فۆمی Sebamed Clear Face).\r\n٢. بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاو، مل و بەشی سەرەوەی سنگ.\r\n٣. بە شێوەی مەساجێکی نەرم بڵاوی بکەرەوە تا هەڵدەمژرێت.\r\n٤. دەتوانیت بەیانیان و شەوان بەکاری بهێنیت.\r\nئامۆژگاری:\r\nئەم کرێمە بەشێکە لە گرووپی \"Clear Face\"ی کۆمپانیای سیبامید. بۆ ئەوەی باشترین ئەنجامت دەستبکەوێت، باشترە لەگەڵ سابوون یان فۆمی پاککەرەوەی هەمان مارکە بەکاری بهێنیت.\r\n','Key Features:\n• For oily and acne-prone skin: Specially formulated to treat combination and oily skin problems that cause a lot of acne.\n• Mattifying: Works to regulate the secretion of sebum in the skin, which causes the skin to lose shine and have a natural, dry (matte) appearance.\n• pH 5.5: This product maintains the skin’s natural acidity, which helps to prevent bacterial growth and acne formation.\nIngredients and Benefits:\n• Horse Chestnut: Helps soothe the skin and reduce redness and inflammation.\n• Hyaluron: Keeps skin hydrated without oily.\n• Grease-free: The cream absorbs very quickly and does not leave a greasy feeling.\nHow to use:\n1. First, wash your face thoroughly with an appropriate cleanser (such as soap or Sebamed Clear Face foam).\n2. Apply an appropriate amount of the cream to the face, neck and upper chest.\n3. Spread in a gentle massage until absorbed.\n4. You can use it in the morning and at night.\nadvice:\nThis cream is part of Cibamid\'s \"Clear Face\" group. For best results, it’s best to use it with soap or cleansing foam from the same brand.','الميزات الرئيسية:\n• للبشرة الدهنية والمعرضة لحب الشباب: تركيبة خاصة لعلاج مشاكل البشرة المختلطة والدهنية التي تسبب ظهور حب الشباب بكثرة.\n• مُطَفِّف: يعمل على تنظيم إفراز الدهون في البشرة، مما يُفقدها لمعانها ويمنحها مظهرًا طبيعيًا جافًا (مطفأ).\n• درجة حموضة 5.5: يحافظ هذا المنتج على حموضة البشرة الطبيعية، مما يساعد على منع نمو البكتيريا وتكوّن حب الشباب.\n\nالمكونات والفوائد:\n• كستناء الحصان: يساعد على تهدئة البشرة وتقليل الاحمرار والالتهاب.\nحمض الهيالورونيك: يحافظ على ترطيب البشرة دون أن يجعلها دهنية.\nخالٍ من الدهون: يمتص الكريم بسرعة كبيرة ولا يترك أي شعور دهني.\n\nطريقة الاستخدام:\n1. اغسلي وجهكِ جيدًا باستخدام غسول مناسب (مثل الصابون أو غسول سيباميد كلير فيس الرغوي).\n2. ضعي كمية مناسبة من الكريم على الوجه والرقبة وأعلى الصدر.\n3. دلكي بلطف حتى يتم امتصاصه.\n\nاستخدمي الكريم\n ٤. يُمكن استخدامه صباحًا ومساءً.\nنصيحة: هذا الكريم جزء من مجموعة \"Clear Face\" من سيباميد. للحصول على أفضل النتائج، يُنصح باستخدامه مع صابون أو غسول رغوي من نفس العلامة التجارية.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:12:56',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-18',0,0),(175,'کرێمی چڕی تایبەت بە پێستی هەستیار و دژە سووربوونەوە لە بڕاندی سێبامێدی ئەڵمانی','Intensive cream for sensitive skin and anti-redness from German brand Sebamedi','كريم مكثف للبشرة الحساسة ومضاد للاحمرار من العلامة التجارية الألمانية سيباميد','کرێمی چڕی تایبەت بە پێستی هەستیار و دژە سووربوونەوە لە بڕاندی سێبامێدی ئەڵمانی',15,21000,30000,4500,1,'تایبەتمەندییە سەرەکییەکانی:\r\n• بۆ پێستی زۆر هەستیار: تایبەت دروست کراوە بۆ ئەو پێستانەی زوو سوور دەبنەوە و تووشی خوران یان کزان دەبن.\r\n• کەمکردنەوەی سووربوونەوە: کاردەکات بۆ هێورکردنەوەی پێست و کەمکردنەوەی ئەو سووربوونەوەیەی بەهۆی کێشەکانی دەمارە خوێنەکان یان تێکچوونی بەربەستی پێستەوە دروست دەبێت.\r\n• پاراستنی هاوسەنگی (pH 5.5): وەک هەموو بەرهەمەکانی سێبامێد، ئەمەش هاوسەنگی ترشێتی پێست دەپارێزێت کە یارمەتی بەهێزکردنی بەرگری سروشتی پێست دەدات.\r\n• پێکهاتەی ڕووەکی: ماددەی (Physalis pubescens) تێدایە کە کاریگەرییەکەی وەک چارەسەرێکی ڕووەکییە بۆ بەهێزکردنی دەمارە خوێنەکان و کەمکردنەوەی هەوکردن.\r\n• شێدارکەرەوەی چڕ: شێدارییەکی زۆر بە پێست دەبەخشێت و هەستی گەرمی و توندی (Tension) سەر پێست ناهێڵێت.\r\nسوودەکانی:\r\n1. هێورکەرەوەیە: بە خێرایی پێست ئارام دەکاتەوە.\r\n2. بەهێزکردنی پێست: بەرگری پێست لە بەرامبەر کاریگەرییە دەرەکییەکان زیاد دەکات.\r\n3. بۆ ماکیاژ گونجاوە: دەتوانرێت وەک بنکەیەک (Base) بۆ ماکیاژ بەکاربێت.\r\n4. کاردەکات لەسەر کەمکردنەوەی نیشانەکانی ڕۆزاشیا.\r\nشێوازی بەکارهێنان:\r\n• ڕۆژانە دوو جار (بەیانیان و شەوان) دوای ئەوەی دەموچاوت بە پاککەرەوەیەکی نەرم دەشۆیت، بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاوت.\r\n• بە نەرمی مەساجی بۆ بکە تا هەڵدەمژرێت.\r\n• ئەگەر پێستت زۆر هەستیار بوو یان تووشی هەوکردنی کتوپڕ بوویت، دەتوانیت چەند جارێک لە ڕۆژێکدا بەکاری بهێنیت.\r\nتێبینی:\r\nئەم کرێمە بێ بۆنە و ماددەی پارێزەری زیانبەخشی تێدا نییە، بۆیە بۆ ئەو کەسانەی بە تیشکی خۆر یان گەرمی پێستیان سوور دەبێتەوە زۆر گونجاوە.','Key Features:\n• For very sensitive skin: Specially formulated for skin that is prone to redness and irritation or irritation.\n• Redness Reduction: Works to soothe the skin and reduce redness caused by blood vessel problems or damage to the skin barrier.\n• Maintain balance (pH 5.5): Like all Sebamed products, this maintains the skin’s acidity balance helping to strengthen the skin’s natural defenses.\n• Botanical ingredients: Contains Physalis pubescens, which acts as a herbal remedy to strengthen blood vessels and reduce inflammation.\n• Intensive moisturizer: Gives the skin a lot of moisture and relieves the feeling of heat and tension on the skin.\nBenefits:\n1. Soothing: Quickly soothes the skin.\n2. Skin strengthening: Increases skin resistance against external influences.\n3. Suitable for makeup: Can be used as a base for makeup.\n4. Works to reduce the symptoms of rosacea.\nHow to use:\n• Apply an appropriate amount of cream twice a day (morning and night) after washing your face with a gentle cleanser.\n• Gently massage until absorbed.\n• If your skin is very sensitive or you have a sudden infection, you can use it several times a day.\nnotice:\nThis cream is odorless and does not contain harmful preservatives, so it is perfect for people whose skin is red from the sun or heat.','الميزات الرئيسية:\n• للبشرة شديدة الحساسية: تركيبة خاصة للبشرة المعرضة للاحمرار والتهيج.\n• تقليل الاحمرار: يعمل على تهدئة البشرة وتقليل الاحمرار الناتج عن مشاكل الأوعية الدموية أو تلف حاجز البشرة.\n• الحفاظ على التوازن (درجة حموضة 5.5): كجميع منتجات سيباميد، يحافظ هذا المنتج على توازن حموضة البشرة، مما يساعد على تقوية دفاعاتها الطبيعية.\n• مكونات نباتية: يحتوي على نبات فيساليس بوبيسينس، الذي يعمل كعلاج عشبي لتقوية الأوعية الدموية وتقليل الالتهاب.\n• مرطب مكثف: يمنح البشرة ترطيبًا عميقًا ويخفف الشعور بالحرارة والشد.\n\n• الفوائد:\n1. تهدئة البشرة: يهدئ البشرة بسرعة.\n2. تقوية البشرة: يزيد من مقاومة البشرة للعوامل الخارجية.\n3. مناسب للمكياج: يمكن استخدامه كأساس للمكياج.\n4. يعمل على تخفيف أعراض الوردية.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة من الكريم مرتين يوميًا (صباحًا ومساءً) بعد غسل وجهك بغسول لطيف.\n• دلكي بلطف حتى يمتصه الجلد.\n• إذا كانت بشرتك حساسة جدًا أو كنتِ تعانين من التهاب مفاجئ، يمكنكِ استخدامه عدة مرات في اليوم.\n\nملاحظة:\nهذا الكريم عديم الرائحة ولا يحتوي على مواد حافظة ضارة، لذا فهو مثالي لمن يعانون من احمرار البشرة بسبب الشمس أو الحرارة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:17:09',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-17',0,0),(176,'کرێمی تایبەت بە پێستی هەستیار و دژە سووربوونەوە لە بڕاندی سێبامێدی ئەڵمانی','Special cream for sensitive skin and anti-redness from the German brand Sebamed','كريم خاص للبشرة الحساسة ومضاد للاحمرار من العلامة التجارية الألمانية سيباميد','کرێمی تایبەت بە پێستی هەستیار و دژە سووربوونەوە لە بڕاندی سێبامێدی ئەڵمانی',15,21000,29000,4000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• دژە سووربوونەوە: یارمەتی کەمکردنەوەی سووربوونەوەی ئێستا دەدات و ڕێگری دەکات لە دروستبوونی سووربوونەوەی نوێ.\r\n• پاراستن لە خۆر (SPF 20): خاوەنی فلتەری پارێزەرە لە تیشکی خۆر کە ڕێگری دەکات لە تێکچوونی پێست بەهۆی تیشکی سەروو بنەوشەیی، چونکە خۆر یەکێکە لە هۆکارە سەرەکییەکانی سووربوونەوە.\r\n• ساردکردنەوە و ئارامکردنەوە: بەهۆی پێکهاتە سووکەکەیەوە، یەکسەر هەستی سووتان و گەرمداهاتنی دەموچاو هێمن دەکاتەوە.\r\n• پێکهاتەی Physalis pubescens: ئەم ڕووەکە یارمەتی بەهێزکردنی موولولەکانی خوێن دەدات بۆ ئەوەی پێستەکە کەمتر سوور هەڵبگێڕێت.\r\n• هاوسەنگی pH 5.5: ئەمە تایبەتمەندی سەرەکی براندی سێبامێدە کە دەبێتە هۆی پاراستنی چینی سروشتی بەرگری پێست.\r\nچۆنیەتی بەکارهێنان:\r\n1. بەیانیان دوای ئەوەی دەموچاوت بە باشی پاک دەکەیتەوە (بە غەسولێکی گونجاو بۆ پێستی هەستیار).\r\n2. بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاوت و بە نەرمی مەساجی بۆ بکە تا هەڵدەمژرێت.\r\n3. دەتوانرێت وەک ئەساس (Makeup base) پێش مکیاجیش بەکاربهێنرێت.\r\nتێبینییەکان:\r\n• ئەم کرێمە ڕەنگی سەوزێکی کاڵی تێدایە (Green care formula) کە بە شێوەیەکی بینراو ڕەنگی سووری پێستەکە دادەپۆشێت و دەیشارێتەوە.\r\n• بۆ دەستکەوتنی باشترین ئەنجام، پێویستە بە بەردەوامی بەکاربهێنرێت ( دوای ٤ هەفتە گۆڕانکارییەکان دیار دەبن).\r\n','Key Features:\n• Anti-redness: Helps reduce existing redness and prevents new ones from forming.\n• Sun Protection (SPF 20): It has a protective sun filter that prevents UV damage to the skin, as the sun is one of the main causes of redness.\n• Cooling and soothing: Due to its lightweight composition, it immediately soothes burning and hot flashes.\n• Physalis pubescens ingredients: This plant helps strengthen blood capillaries to make the skin less red.\n• Balance pH 5.5: This is the main feature of the Sebamed brand that will maintain the skin’s natural barrier layer.\nHow to use:\n1. In the morning after thoroughly cleansing your face (with a suitable lotion for sensitive skin).\n2. Apply an appropriate amount of the cream on your face and massage gently until absorbed.\n3. Can also be used as a makeup base before makeup.\nNotes:\n• This cream contains a pale green pigment (Green care formula) that visually covers and hides the red pigmentation of the skin.\n• For best results, it should be used regularly (changes will be visible after 4 weeks).','الميزات الرئيسية:\n• مضاد للاحمرار: يساعد على تقليل الاحمرار الموجود ويمنع ظهور احمرار جديد.\n• حماية من الشمس (SPF 20): يحتوي على فلتر واقٍ من أشعة الشمس يحمي البشرة من أضرار الأشعة فوق البنفسجية، حيث تُعدّ الشمس أحد الأسباب الرئيسية للاحمرار.\n• مُرطّب ومهدئ: بفضل تركيبته الخفيفة، يُهدئ فورًا الحروق والهبات الساخنة.\n• مكونات نبات فيساليس بوبيسينس: يُساعد هذا النبات على تقوية الشعيرات الدموية، مما يُقلل من احمرار البشرة.\n• درجة حموضة متوازنة 5.5: هذه هي الميزة الرئيسية لمنتجات سيباميد، حيث تُحافظ على طبقة الحاجز الطبيعية للبشرة.\n\nطريقة الاستخدام:\n1. في الصباح بعد تنظيف الوجه جيدًا (باستخدام غسول مناسب للبشرة الحساسة).\n2. ضعي كمية مناسبة من الكريم على الوجه ودلكيه بلطف حتى يتم امتصاصه.\n3. يُمكن استخدامه أيضًا كأساس للمكياج قبل وضع المكياج.\n\nملاحظات:\n• يحتوي هذا الكريم على صبغة خضراء فاتحة (تركيبة العناية الخضراء) تُغطي وتُخفي احمرار البشرة.\n• للحصول على أفضل النتائج، يُنصح باستخدامه بانتظام (ستظهر التغييرات بعد 4 أسابيع).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:18:58',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-16',0,0),(177,'سیڕۆمی چڕی تایبەت نوێکردن و پاراستنی پێست لە بڕاندی سێبامێدی ئەڵمانی','Special intensity serum to renew and protect the skin from the German brand Sebamed','سيروم مكثف خاص لتجديد وحماية البشرة من العلامة التجارية الألمانية سيباميد','سیڕۆمی چڕی تایبەت نوێکردن و پاراستنی پێست لە بڕاندی سێبامێدی ئەڵمانی',15,24500,34500,5000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پڕۆبایۆتیک (Probiotic): کار دەکات بۆ بەهێزکردنی پێکهاتەی خانەکانی پێست و پاراستنی هاوسەنگیی سروشتیی پێست.\r\n• نەهێشتنی چرچی: ئەم سیرومە ماددەی (Alpinia Galanga)ی تێدایە کە یارمەتی پڕکردنەوەی پێست و کەمکردنەوەی چرچییە دیارەکان دەدات لە ناوەوە.\r\n• هاوسەنگیی ترشێتی (pH 5.5): وەک هەموو بەرهەمەکانی سێبامێد، ئەمەش پلەی ترشێتییەکەی 5.5ـە کە پەردەی پارێزەری پێست جێگیر دەکات و دەیپارێزێت لە وشکبوونەوە و هۆکارە دەرەکییە زیانبەخشەکان.\r\n• شێدارکردن: بە شێوەیەکی چڕ شێداری بە پێست دەبەخشێت و وای لێ دەکات نەرم و تەڕ بێت.\r\nسوودەکانی:\r\n1. پێست لە پیربوونی پێشوەختە دەپارێزێت.\r\n2. ڕووی پێست سافتر و گەنجتر پیشان دەدات.\r\n3. بەرگری پێست دژی کاریگەرییە خراپەکانی ژینگە (وەک تۆز و پیسی) زیاد دەکات.\r\nشێوازی بەکارهێنان:\r\n• کەی؟: بەیانیان و شەوان دوای ئەوەی دەموچاوت بە باشی دەشۆیت.\r\n• بۆ کوێ؟: بڕێکی گونجاو بدە لە دەموچاو، مل و بەشی سەرەوەی سنگ.\r\n• تێبینی: دەتوانیت وەک بنچینەیەک (Base) بۆ ماکیاژیش بەکاری بهێنیت. هەروەها دەتوانیت کرێمی (Regenerating Cream)ی هەمان جۆر لە دوای سیرومەکە بەکاربهێنیت بۆ ئەنجامێکی باشتر.\r\nپێکهاتە گرنگەکان:\r\n• ئاوی پاککراوە (Aqua).\r\n• ڕۆنی ناوکی ترێ (Vitis vinifera seed oil).\r\n• گیراوەی پڕۆبایۆتیک (Lactococcus Ferment Lysate).\r\n• جینجەری تایلەندی (Alpinia galanga).','Key Features:\n• Probiotic: Works to strengthen skin cell structure and maintain the skin\'s natural balance.\n• Eliminate wrinkles: This serum contains Alpinia Galanga, which helps replenish the skin and reduce visible wrinkles from within.\n• Acidity balance (pH 5.5): Like all Sebamed products, this has an acidity of 5.5 that stabilizes the skin\'s protective membrane and protects it from drying and harmful external factors.\n• Moisturizing: Intensively moisturizes the skin and makes it soft and moist.\nBenefits:\n1. Protects skin from premature aging.\n2. Makes the skin look softer and younger.\n3. Increases skin resistance against adverse environmental influences (such as dust and dirt).\nHow to use:\n• When?: Morning and night after washing your face thoroughly.\n• Where?: Apply appropriate amounts to face, neck and upper chest.\n• Note: You can also use it as a base for makeup. You can also use Regenerating Cream of the same type after the serum for better results.\nImportant Ingredients:\n• Purified water (Aqua).\n• Vitis vinifera seed oil.\n• Probiotic solution (Lactococcus Ferment Lysate).\n• Thai Ginger (Alpinia galanga).','الميزات الرئيسية:\n• بروبيوتيك: يعمل على تقوية بنية خلايا البشرة والحفاظ على توازنها الطبيعي.\n• إزالة التجاعيد: يحتوي هذا السيروم على مستخلص ألبينا غالانغا، الذي يساعد على تجديد البشرة وتقليل التجاعيد الظاهرة من الداخل.\n• توازن الحموضة (درجة حموضة 5.5): كجميع منتجات سيباميد، يتميز هذا السيروم بدرجة حموضة 5.5، مما يُثبّت الغشاء الواقي للبشرة ويحميها من الجفاف والعوامل الخارجية الضارة.\n• ترطيب: يرطب البشرة بعمق ويجعلها ناعمة ونضرة.\n\nالفوائد:\n1. يحمي البشرة من الشيخوخة المبكرة.\n2. يجعل البشرة تبدو أكثر نعومة وشبابًا.\n3. يزيد من مقاومة البشرة للتأثيرات البيئية الضارة (مثل الغبار والأوساخ).\n\nطريقة الاستخدام:\n• متى؟: صباحًا ومساءً بعد غسل الوجه جيدًا.\n• أين؟: ضعي كمية مناسبة على الوجه والرقبة وأعلى الصدر.\n• ملاحظة: يمكنكِ استخدامه أيضًا كأساس للمكياج. يمكنكِ أيضاً استخدام كريم التجديد من نفس النوع بعد السيروم للحصول على نتائج أفضل.\n\nالمكونات الرئيسية:\n• ماء نقي (أكوا).\n• زيت بذور العنب (فيتيس فينيفيرا).\n• محلول بروبيوتيك (مستخلص تخمير لاكتوكوكوس).\n• زنجبيل تايلاندي (ألبينيا غالانغا).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:21:35',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'30ml','03-15',0,0),(178,'کرێمی تایبەت بە چارەسەرکردنی سووتانەوەی جێگەی دایبی کۆرپەلە لە بڕاندی سێبامێدی ئەڵمانی','Cream for treating diaper burns from the German brand Sebamed','كريم لعلاج حروق الحفاضات من ماركة سيباميدي الألمانية','کرێمی تایبەت بە چارەسەرکردنی سووتانەوەی شوێنی دایبی کۆرپەلە لە بڕاندی سێبامێدی ئەڵمانی',15,6000,9000,1500,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• پانتینۆڵ (Panthenol):  ماددەی پانتینۆڵی تێدایە کە یارمەتی زوو چاکبوونەوەی برین و پێستە سووتاوەکە دەدات.\r\n• پلەی ترشێتی گونجاو (pH 5.5): ئەم پلەیە هاوسەنگی پێست دەپارێزێت و ناهێڵێت بەکتریا و میکرۆبە زیانبەخشەکان گەشە بکەن.\r\n• پارێزگاری: چینێکی پارێزەر لەسەر پێست دروست دەکات بۆ ئەوەی ڕێگری بکات لەوەی پیسی دایبی بەر پێستی منداڵەکە بکەوێت و زیاتری بکات.\r\n٢. سوودەکانی:\r\n• چارەسەری سووتانەوە و سووربوونەوەی توندی جێگەی دایبی دەکات.\r\n• پێستی منداڵەکە نەرم دەکاتەوە و ئارامی دەکاتەوە (دژە هەوکردنە).\r\n• لە ڕۆژی یەکەمی لەدایکبوونەوە دەتوانرێت بەکاربهێنرێت.\r\n٣. چۆنیەتی بەکارهێنان:\r\n1. پێویستە جێگەی دایبییەکە بە باشی بشۆردرێت و بە تەواوی وشک بکرێتەوە.\r\n2. بڕێکی گونجاو لە کرێمەکە بدە لەو شوێنانەی کە سووربوونەوەیان هەیە.\r\n3. پێویستە لەگەڵ هەموو گۆڕینێکی دایبی بەکاربهێنرێت تاوەکو سووربوونەوەکە نامێنێت.\r\nتێبینییەکی گرنگ: ئەگەر سووتانەوەکە زۆر توند بوو، یان دوای چەند ڕۆژێک لە بەکارهێنان باش نەبوو، یان برینی تێدا دروست بوو، باشترە سەردانی پزیشکی منداڵان بکەیت چونکە ڕەنگە پێویستی بە چارەسەری بەهێزتر هەبێت.\r\n','Key Features:\n• Panthenol: Contains panthenol, which helps wounds and burned skin heal faster.\n• Optimal acidity (pH 5.5): This temperature maintains the skin\'s balance and prevents the growth of harmful bacteria and germs.\n• Protection: Creates a protective layer on the skin to prevent diaper dirt from coming into contact with the baby’s skin and aggravating it.\n2. Benefits:\n• Treats severe diaper bed burns and redness.\n• Softens and soothes the baby\'s skin (anti-inflammatory).\n• Can be used from the first day of birth.\n3. How to use:\n1. The diaper bed should be washed thoroughly and dried thoroughly.\n2. Apply an appropriate amount of cream to areas of redness.\n3. It should be used with every diaper change until the redness disappears.\nIMPORTANT NOTE: If the burn is very severe, does not improve after a few days of use, or ulceration develops, it is best to see a pediatrician as more vigorous treatment may be needed.','الميزات الرئيسية:\n• بانثينول: يحتوي على البانثينول، الذي يساعد على التئام الجروح وحروق الجلد بشكل أسرع.\n• حموضة مثالية (درجة حموضة 5.5): تحافظ هذه الدرجة على توازن البشرة وتمنع نمو البكتيريا والجراثيم الضارة.\n• الحماية: يُشكّل طبقة واقية على بشرة الطفل لمنع وصول الأوساخ من الحفاضات إلى بشرته وتهييجها.\n\nالفوائد:\n• يعالج الحروق الشديدة الناتجة عن فراش الحفاضات والاحمرار.\n• يُنعّم ويُهدئ بشرة الطفل (مضاد للالتهابات).\n• يُمكن استخدامه من اليوم الأول للولادة.\n\nطريقة الاستخدام:\n1. يجب غسل فراش الحفاضات جيدًا وتجفيفه تمامًا.\n2. ضعي كمية مناسبة من الكريم على المناطق المُحمرة.\n3. يُستخدم مع كل تغيير للحفاض حتى يختفي الاحمرار\n\nيُستخدم مع كل تغيير للحفاضات. ملاحظة هامة: إذا كان الحرق شديدًا للغاية، أو لم يتحسن بعد بضعة أيام من الاستخدام، أو ظهرت تقرحات، فمن الأفضل مراجعة طبيب أطفال حيث قد يكون من الضروري إجراء علاج أكثر قوة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:24:13',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-14',0,0),(179,'سابوونی پاکەرەوەی تایبەت بە منداڵان لە بڕاندی سێبامێدی ئەڵمانی','Children\'s cleaning soap from the German brand Sebamed','صابون تنظيف للأطفال من العلامة التجارية الألمانية سيباميد',' سابوونی پاکەرەوەی تایبەت بە منداڵان لە بڕاندی سێبامێدی ئەڵمانی',15,4750,7750,1500,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی هەستیار: بە تایبەت بۆ پێستی ناسکی منداڵان دروست کراوە کە زۆر هەستیارە.\r\n• هاوسەنگی ترشێتی (pH 5.5): گرنگترین خاڵی ئەم سابوونە ئەوەیە کە پلەی ترشێتییەکەی pH 5.5ـە، ئەمەش یارمەتی دروستکردنی چینی پارێزەری سروشتی پێست دەدات (Acid Mantle) کە ڕێگری لە وشکبوونەوە و هەوکردن دەکات.\r\n• ماددەی پانثینۆڵ (Panthenol): پێکهاتەی پانثینۆڵی تێدایە کە یارمەتی شێدارکردنەوە و چاکبوونەوەی پێست دەدات و ڕێگری لە سووربوونەوە دەکات.\r\n• بێ سابوونی زیانبەخش: ئەمە بە \"Soap-free\" دادەنرێت، واتە ئەو ماددە توندانەی تێدا نییە کە پێست وشک دەکەنەوە.\r\nسوودەکانی:\r\n• پێستی منداڵ بە نەرمی پاک دەکاتەوە بەبێ ئەوەی بیخورێنێت.\r\n• بۆ پاراستنی پێست لە سووتانەوەی دایبی و وشکی زستان زۆر باشە.\r\n• بۆ ئەو گەورانەش کە پێستیان زۆر هەستیارە یان کێشەی ئەکزیما و وشکی زۆریان هەیە، زۆرجار لەلایەن پزیشکانی پێستەوە پێشنیار دەکرێت.\r\nچۆن بەکاردێت؟\r\n١. کەمێک ئاو بدە لە سابوونەکە و لەناو دەستتدا بیکە بە کەف.\r\n٢. بە نەرمی بیدە لە پێستی منداڵەکە.\r\n٣. بە ئاوێکی شلەتێن (نە زۆر گەرم نە سارد) لێی بکەرەوە.\r\n٤. تێبینی: دوای بەکارهێنان سابوونەکە لە شوێنێکی وشک دابنێ بۆ ئەوەی زوو نەتێتەوە و بۆ ماوەیەکی درێژتر بمێنێتەوە.\r\n','Key Features:\n• For sensitive skin: Especially formulated for the delicate skin of children who are very sensitive.\n• Acidity balance (pH 5.5): The most important point of this soap is that its acidity is pH 5.5, which helps to create the skin\'s natural protective layer (Acid Mantle) that prevents dryness and inflammation.\n• Panthenol: Contains panthenol compounds that help moisturize and heal the skin and prevent redness.\n• No harmful soap: This is considered \"Soap-free\", meaning it does not contain harsh substances that dry out the skin.\nBenefits:\n• Gently cleanses baby’s skin without irritation.\n• Great for protecting skin from diaper burn and winter dryness.\n• It is also often recommended by dermatologists for adults with very sensitive skin or problems with extreme eczema and dryness.\nhow is it used\n1. Add a little water to the soap and lather it in your hand.\n2. Gently apply to the skin.\n3. Rinse with running water (not too hot or cold).\n4. Note: Keep the soap in a dry place after use to prevent it from melting quickly and to keep it longer.','الميزات الرئيسية:\n• للبشرة الحساسة: تركيبة خاصة مصممة خصيصًا لبشرة الأطفال الرقيقة والحساسة جدًا.\n• توازن الحموضة (درجة حموضة 5.5): أهم ما يميز هذا الصابون هو درجة حموضته المتوازنة (درجة حموضة 5.5)، مما يساعد على تكوين طبقة الحماية الطبيعية للبشرة (الغطاء الحمضي) التي تمنع الجفاف والالتهاب.\n• البانثينول: يحتوي على مركبات البانثينول التي تساعد على ترطيب البشرة وعلاجها ومنع الاحمرار.\n• خالٍ من المواد الكيميائية الضارة: يُعتبر هذا الصابون \"خاليًا من الصابون\"، أي أنه لا يحتوي على مواد قاسية تُسبب جفاف البشرة.\n\n• فوائده:\n• ينظف بشرة الطفل بلطف دون تهيج.\n• مثالي لحماية البشرة من حروق الحفاضات وجفاف الشتاء.\n• غالبًا ما يوصي به أطباء الجلدية للبالغين ذوي البشرة الحساسة جدًا أو الذين يعانون من مشاكل الأكزيما الشديدة والجفاف.\n\nطريقة الاستخدام:\n1. أضيفي القليل من الماء إلى الصابون ودلكيه بين يديكِ حتى تتكون رغوة.\n2. ضعيه بلطف على البشرة.\n٣. اشطف بالماء الجاري (ليس ساخنًا جدًا ولا باردًا جدًا).\n٤. ملاحظة: احفظ الصابون في مكان جاف بعد الاستخدام لمنعه من الذوبان بسرعة وللحفاظ عليه لفترة أطول.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:28:30',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'100g','03-13',0,0),(180,'سابوونی تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Soap for sensitive skin from German brand Sebamed','صابون للبشرة الحساسة من ماركة سيباميد الألمانية','سابوونی تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,4750,8750,2000,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی هەستیار: تایبەت دروستکراوە بۆ ئەو کەسانەی پێستیان هەستیارە یان کێشەی وەک (زیپکە، سەدەف، یان ئەکزیما)یان هەیە.\r\n• هاوسەنگی pH 5.5: ئەمە گرنگترین خاڵە، چونکە پلەی ترشێتییەکەی ڕێک وەک پێستی مرۆڤە، ئەمەش یارمەتی پاراستنی چینی بەرگری پێست دەدات و ناهێڵێت بەکتریا و میکرۆب گەشە بکەن.\r\n• بێ سابوون (Soap-free): ماددەی کیمیایی زیانبەخشی تێدا نییە کە ببێتە هۆی وشکبوونەوەی پێست.\r\n٢. پێکهاتە و سوودەکانی:\r\n• پاککەرەوەیەکی قووڵ: کونیلەکانی پێست بە باشی پاک دەکاتەوە بەبێ ئەوەی بیخورێنێت.\r\n• ڤیتامین و ترشە ئەمینییەکان: تێدایە کە یارمەتی شێدارکردنەوە و نەرمکردنی پێست دەدەن.\r\n• بۆ دەموچاو و جەستە: دەتوانیت هەم بۆ دەموچاو و هەم بۆ هەموو جەستەت بەکاری بهێنیت.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• دەستت یان پێستت کەمێک تەڕ بکە.\r\n• سابوونەکە لە ناو دەستتدا بکە بە کەف.\r\n• بە هێواشی مەساجی پێستت پێ بکە و پاشان بە ئاوێکی شلەتێن لێی بکەرەوە.\r\n• تێبینی: دوای بەکارهێنان، سابوونەکە لە شوێنێکی وشک دابنێ بۆ ئەوەی زوو نەتێتەوە و بۆ ماوەیەکی درێژ بمێنێتەوە.\r\n','. . . . Key Features:\n• For sensitive skin: Specially formulated for people with sensitive skin or problems such as acne, psoriasis, or eczema.\n• pH 5.5 balance: This is the most important point, because its acidity is the same as human skin, which helps protect the skin\'s immune layer and prevents the growth of bacteria and germs.\n• Soap-free: Contains no harmful chemicals that can cause dry skin.\n2. Ingredients and Benefits:\n• Deep Cleanser: Cleans pores thoroughly without irritation.\n• Vitamins and amino acids: Contains that help moisturize and soften the skin.\n• For face and body: You can use it both on your face and all over your body.\n3. How to use:\n• Wet your hands or skin slightly.\n• Foam the soap in your hands.\n• Gently massage into your skin and then rinse with lukewarm water.\n• Note: After use, keep the soap in a dry place to prevent it from melting quickly and to keep it for a long time.','الميزات الرئيسية:\n• للبشرة الحساسة: تركيبة خاصة للأشخاص ذوي البشرة الحساسة أو الذين يعانون من مشاكل مثل حب الشباب، الصدفية، أو الإكزيما.\n• درجة حموضة متوازنة 5.5: هذه هي النقطة الأهم، لأن حموضته مماثلة لحموضة بشرة الإنسان، مما يساعد على حماية الطبقة المناعية للبشرة ويمنع نمو البكتيريا والجراثيم.\n• خالٍ من الصابون: لا يحتوي على أي مواد كيميائية ضارة قد تسبب جفاف البشرة.\n\n2. المكونات والفوائد:\n• منظف عميق: ينظف المسام بعمق دون تهيج.\n• فيتامينات وأحماض أمينية: يحتوي على مكونات تساعد على ترطيب وتنعيم البشرة.\n• للوجه والجسم: يمكن استخدامه على الوجه وكامل الجسم.\n\n3. طريقة الاستخدام:\n• بللي يديكِ أو بشرتكِ قليلاً.\n• افركي الصابون بين يديكِ حتى تتكون رغوة.\n• دلكي الرغوة بلطف على بشرتكِ ثم اشطفيها بالماء الفاتر.\n\n• ملاحظة: بعد الاستخدام، احتفظ بالصابون في مكان جاف لمنعه من الذوبان بسرعة وللحفاظ عليه لفترة طويلة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:31:57',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'100g','03-12',0,0),(181,'سابوونی زەیتی زەیتون لە بڕاندی سێبامێدی ئەڵمانی','Olive oil soap from German brand Sebamed','صابون زيت الزيتون من ماركة سيباميد الألمانية','سابوونی زەیتی زەیتون لە بڕاندی سێبامێدی ئەڵمانی',15,6250,10000,1750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی هەستیار و وشک: ئەم جۆرەیان بە تایبەت بۆ ئەو کەسانە دروستکراوە کە پێستیان وشکە یان زوو بە سابوونی ئاسایی تێکدەچێت.\r\n• بەبێ سابوون (Soap-free): ئەمە زۆر گرنگە چونکە سابوونی ئاسایی پێست وشک دەکاتەوە و ئاستی ترشێتی (pH) تێکدەدات، بەڵام ئەم بەرهەمە ماددەی پاککەرەوەی تێدایە کە هاوسەنگی پێست دەپارێزێت.\r\n• هاوسەنگی pH 5.5: هاوسەنگییەکی تەواوی هەیە لەگەڵ چینی پارێزەری پێست، ئەمەش وادەکات پێستەکە بە تەندروستی بمێنێتەوە و دژی بەکتریا و وشکبوونەوە بێت.\r\n• پێکهاتە دەوڵەمەندەکان: زەیتی زەیتوون، پانتینۆڵ (Panthenol)، و پڕۆتینی ئاوریشمی تێدایە کە یارمەتی نەرمکردنەوە و شێدارکردنەوەی پێست دەدەن.\r\nسوودەکانی:\r\n1. پاککردنەوەیەکی زۆر نەرم و کاریگەر بۆ دەموچاو و جەستە.\r\n2. ڕێگری دەکات لە تێکچوونی ڕێژەی شێی ناو پێست.\r\n3. پێستەکە بە نەرمی دەهێڵێتەوە تەنانەت دوای شتنیش.\r\nشێوازی بەکارهێنان:\r\nکەمێک ئاو بدە لە دەستت و سابوونەکە، پاشان بیدە لەو شوێنەی دەتەوێت و بە باشی بە ئاو بیشۆ.\r\n• تێبینی: دوای بەکارهێنان، سابوونەکە لە شوێنێکی وشک دابنێ بۆ ئەوەی بۆ ماوەیەکی درێژتر بمێنێتەوە و نەتوێتەوە.\r\n','Key Features:\n• For sensitive and dry skin: This one is especially formulated for people whose skin is dry or easily damaged by regular soap.\n• Soap-free: This is very important because ordinary soap dries the skin and disrupts the pH level, but this product contains cleansing agents that maintain the skin\'s balance.\n• Balance pH 5.5: Perfectly balanced with the skin’s protective layer, keeping the skin healthy and resistant to bacteria and dryness.\n• Rich ingredients: Contains olive oil, panthenol, and silk protein that help soften and moisturize the skin.\nBenefits:\n1. Very gentle and effective cleansing for face and body.\n2. Prevents deterioration of skin moisture.\n3. Keeps skin soft even after washing.\nHow to use:\nApply a little water to your hands and the soap, then apply to the desired area and rinse thoroughly.\n• Note: After use, store the soap in a dry place to keep it longer and not dissolve.','الميزات الرئيسية:\n• للبشرة الحساسة والجافة: صُمم هذا المنتج خصيصًا للأشخاص ذوي البشرة الجافة أو التي تتضرر بسهولة من الصابون العادي.\n• خالٍ من الصابون: هذه ميزة مهمة للغاية لأن الصابون العادي يُجفف البشرة ويُخل بتوازن درجة الحموضة، بينما يحتوي هذا المنتج على عوامل تنظيف تحافظ على توازن البشرة.\n• درجة حموضة متوازنة 5.5: متوازن تمامًا مع الطبقة الواقية للبشرة، مما يحافظ على صحتها ومقاومتها للبكتيريا والجفاف.\n• مكونات غنية: يحتوي على زيت الزيتون، والبانثينول، وبروتين الحرير التي تُساعد على تنعيم وترطيب البشرة.\n\n• الفوائد:\n1. تنظيف لطيف وفعال للغاية للوجه والجسم.\n2. يمنع فقدان رطوبة البشرة.\n3. يُحافظ على نعومة البشرة حتى بعد الغسل.\n\nطريقة الاستخدام: ضعي القليل من الماء على يديكِ وعلى الصابون، ثم ضعيه على المنطقة المطلوبة واشطفيه جيدًا.\n• ملاحظة: بعد الاستخدام، يُحفظ الصابون في مكان جاف للحفاظ عليه لفترة أطول ومنع ذوبانه.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 06:34:57',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'150g','03-11',0,0),(182,'دیۆدۆرانتی تایبەت بە چاودێریکردنی پێست لە بڕاندی سێبامێدی ئەڵمانی','Skin care deodorant from German brand Sebamed','مزيل عرق للعناية بالبشرة من العلامة التجارية الألمانية سيباميد','دیۆدۆرانتی تایبەت بە چاودێریکردنی پێست لە بڕاندی سێبامێدی ئەڵمانی',15,6250,9750,1750,1,'. تایبەتمەندییە گرنگەکان:\r\n• بێ خوێی ئەلەمنیۆم (No Aluminium Salts): ئەمە خاڵە هەرە گرنگەکەیە. بە پێچەوانەی زۆرێک لە دژە ئارەقەکان (Antiperspirants)، ئەمە کونیلەکانی پێست داناناخات و رێگری لە پرۆسەی سروشتی ئارەقکردنەوە ناکات، بەڵکو تەنها رێگری لە دروستبوونی بۆنی ناخۆش دەکات.\r\n• پلەی ترشێتی (pH 5.5): هاوسەنگە لەگەڵ پلەی ترشێتی سروشتی پێست، ئەمەش یارمەتی پاراستنی چینی بەرگری پێست دەدات و لە وشکبوونەوە یان هەستیاری دەیپارێزێت.\r\n• بۆ پێستی هەستیار (Sensitive Skin): بە تایبەت بۆ ئەو کەسانە دروستکراوە کە پێستیان ناسکە و زوو تووشی سووربوونەوە یان خوران دەبن.\r\n• مانەوەی بۆ ماوەیەکی درێژ: 48h، واتا کاریگەرییەکەی بۆ ماوەی ٤٨ کاتژمێر دەمێنێتەوە لە رێگری کردن لە بۆنی ناخۆش.\r\n٢. پێکهاتەکانی:\r\n پێکهاتە سەرەکییەکانی بریتین لە:\r\n• Alcohol (ئەلکحول): بۆ لەناوبردنی ئەو بەکتریانەی دەبنە هۆی دروستبوونی بۆنی ناخۆش.\r\n• Triethyl Citrate: وەک ماددەیەکی دژە بۆن کاردەکات.\r\n• Bisabolol: ماددەیەکی هێورکەرەوەیە کە لە گوڵە بەیبوون وەردەگیرێت، بۆ رێگریکردن لە هەوکردنی پێست.\r\n• بێ پارابین و بێ رەنگە.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• لەسەر پێستی خاوێن و وشک بەکاری بهێنە (باشتر وایە دوای خۆشۆردن بێت).\r\n• تەنها بۆ بەکارهێنانی دەرەکییە.\r\n٤. تێبینی گرنگ:\r\nئەم بەرهەمە \"دژە بۆنە\" (Deodorant) نەک \"دژە ئارەقە\" (Antiperspirant). واتا ئەگەر تۆ زۆر ئارەق دەکەیتەوە و دەتەوێت جێگای بنباڵت هەر بە وشکی بمێنێتەوە، رەنگە ئەمە ئەو ئەنجامە تەواوەت پێنەدا، چونکە ئەمە تەنها بۆنە ناخۆشەکە ناهێڵێت و پێستەکە بە تەندروستی دەهێڵێتەوە.\r\n','Important Features:\n• No Aluminum Salts: This is the most important point. Unlike many antiperspirants, this does not clog the pores of the skin and prevent the natural sweating process, but only prevents the formation of bad breath.\n• Acidity (pH 5.5): Balanced with the skin’s natural acidity, this helps maintain the skin’s barrier layer and protects it from dryness or sensitivity.\n• For Sensitive Skin: Especially designed for people with sensitive skin that is prone to redness or irritation.\n• Long lasting: 48h, meaning the effect lasts for 48 hours in preventing bad breath.\n2. Ingredients:\n Its main components are:\n• Alcohol: To kill the bacteria that cause bad breath.\n• Triethyl Citrate: Acts as an anti-odor agent.\n• Bisabolol: A sedative derived from violet flowers, to prevent skin inflammation.\n• Paraben-free and colorless.\n3. How to use:\n• Apply to clean, dry skin (preferably after washing).\n• For external use only.\n4. Important Note:\nThis product is an \"Antiperspirant\" (Deodorant) not an \"Antiperspirant\" That is, if you sweat a lot and want to keep your underarms dry, this may not give you the perfect result, because it only eliminates the bad smell and keeps the skin healthy.','.أهم الميزات:\n• خالٍ من أملاح الألومنيوم: هذه هي الميزة الأهم. على عكس العديد من مضادات التعرق، لا يسد هذا المنتج مسام الجلد ولا يمنع عملية التعرق الطبيعية، بل يمنع فقط تكوّن رائحة الفم الكريهة.\n• حموضة متوازنة (درجة حموضة 5.5): متوازنة مع حموضة الجلد الطبيعية، مما يساعد على الحفاظ على طبقة الحماية الطبيعية للبشرة وحمايتها من الجفاف أو الحساسية.\n• للبشرة الحساسة: مصمم خصيصًا للأشخاص ذوي البشرة الحساسة المعرضة للاحمرار أو التهيج.\n• يدوم طويلًا: 48 ساعة، أي أن مفعوله يستمر لمدة 48 ساعة في منع رائحة الفم الكريهة.\n\n2. المكونات:\nمكوناته الرئيسية هي:\n• الكحول: لقتل البكتيريا المسببة لرائحة الفم الكريهة.\n• سترات ثلاثي الإيثيل: يعمل كمضاد للروائح.\n• بيسابولول: مهدئ مستخلص من زهور البنفسج، لمنع التهاب الجلد.\n• خالٍ من البارابين وعديم اللون.\n\n٣. طريقة الاستخدام:\n• يُوضع على بشرة نظيفة وجافة (يُفضل بعد غسلها).\n• للاستخدام الخارجي فقط.\n\n٤. ملاحظة هامة:\nهذا المنتج مُضاد للتعرق (مضاد للعرق) وليس مُضادًا للتعرق بحد ذاته. بمعنى آخر، إذا كنتِ تتعرقين بكثرة وترغبين في الحفاظ على جفاف منطقة الإبط، فقد لا يُعطيكِ هذا المنتج النتيجة المرجوة، لأنه يُزيل الرائحة الكريهة فقط ويُحافظ على صحة البشرة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:11:02',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-10',0,0),(183,'دیۆدۆرانتی تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Deodorant for sensitive skin from German brand Sebamed','مزيل عرق للبشرة الحساسة من ماركة سيباميد الألمانية','دیۆدۆرانتی تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,6250,9750,1750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بێ خوێی ئەلەمنیۆم (No Aluminium salts): ئەمە گرنگترین تایبەتمەندییەتی، چونکە ڕێگری لە ئارەقەکردنەوە ناکات بە شێوەیەکی دەستکرد (کونیلەکان ناگرێت)، بەڵکو ڕێگری لە دروستبوونی بۆنی ناخۆش دەکات.\r\n• بۆ پێستی هەستیار: زۆر گونجاوە بۆ ئەو کەسانەی پێستیان زوو سوور دەبێتەوە یان دەخورێت، بەتایبەت دوای تاشینی مووی بن باڵ.\r\n• هاوسەنگی ترشێتی (pH 5.5): هاوسەنگی سروشتی پێست دەپارێزێت و ناهێڵێت بەکتریاکان گەشە بکەن کە دەبنە هۆی بۆنی ناخۆش.\r\n• مانەوە بۆ ٤٨ کاتژمێر:  (48h)، پارێزگارییەکی درێژخایەن دابین دەکات.\r\nپێکهاتەکانی (Ingredients):\r\n• Aqua (ئاو): وەک بنکەی سەرەکی بەرهەمەکە.\r\n• Zinc Ricinoleate: پێکهاتەیەکی کاریگەرە بۆ هەڵمژینی بۆنی ناخۆش بێ ئەوەی زیان بە پێست بگەیەنێت.\r\n• بەبێ کحول: بە گشتی ئەم جۆرە بەرهەمانەی سێبامێد کحولیان تێدا نییە تاوەکو نەبێتە هۆی وشکبوونەوەی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n١. دڵنیابەرەوە کە بن باڵت پاک و وشکە.\r\n٢. بڕێکی گونجاو لە دیۆدرانتەکە لێ بدە.\r\n٣. کەمێک بوەستە تاوەکو وشک دەبێتەوە پێش ئەوەی جل لەبەر بکەیت بۆ ئەوەی پەڵە لەسەر جلەکانت دروست نەکات.\r\nسەرنج:\r\nئەم بەرهەمە Deodorantـە نەک Antiperspirant. واتە بۆنی ناخۆش لادەبات بەڵام ڕێگری تەواو لە تەڕبوونی بن باڵ (ئارەقەکردنەوە) ناکات، کە ئەمەش لە ڕووی تەندروستییەوە بە باشتر دادەنرێت بۆ ئەوەی جەستە بە سروشتی ئارەق بکاتەوە.\r\n','Key Features:\n• No Aluminum salts: This is the most important feature, because it does not prevent sweating artificially (does not clog pores), but also prevents the formation of bad breath.\n• For sensitive skin: Very suitable for people whose skin is easily red or itchy, especially after shaving underarm hair.\n• Acidity balance (pH 5.5): Maintains the natural balance of the skin and prevents the growth of bacteria that cause bad breath.\n• Stay for 48 hours: (48h), provides long-lasting protection.\nIngredients:\n• Aqua (water): as the main base of the product.\n• Zinc Ricinoleate: An effective ingredient to absorb unpleasant odors without harming the skin.\n• Alcohol-free: These Sebamed products usually do not contain alcohol to avoid drying the skin.\nHow to use:\n1. Make sure your underarms are clean and dry.\n2. Apply the appropriate amount of deodorant.\n3. Wait a bit for it to dry before getting dressed to avoid stains.\nattention:\nThis product is a deodorant, not an antiperspirant. That is, it removes unpleasant odors but does not completely prevent underarm wetness (sweating), which is considered healthier for the body to sweat naturally.','الميزات الرئيسية:\n• خالٍ من أملاح الألومنيوم: هذه أهم ميزة، لأنه لا يمنع التعرق بشكل مصطنع (لا يسد المسام)، بل يمنع أيضًا رائحة الفم الكريهة.\n• مناسب للبشرة الحساسة: مناسب جدًا لمن يعانون من احمرار أو حكة في البشرة، خاصة بعد حلاقة شعر الإبط.\n• متوازن الحموضة (درجة حموضة 5.5): يحافظ على التوازن الطبيعي للبشرة ويمنع نمو البكتيريا المسببة لرائحة الفم الكريهة.\n• يدوم 48 ساعة: يوفر حماية طويلة الأمد.\n• الماء: المكون الأساسي للمنتج.\n• ريسينوليت الزنك: مكون فعال لامتصاص الروائح الكريهة دون الإضرار بالبشرة.\n• خالٍ من الكحول: منتجات سيباميد عادةً لا تحتوي على الكحول لتجنب جفاف البشرة.\n\nطريقة الاستخدام:\n1. تأكد من نظافة وجفاف منطقة الإبط.\n2. ضع كمية مناسبة من مزيل العرق.\n3. انتظر قليلًا حتى يجف قبل ارتداء الملابس لتجنب البقع. تنبيه:\nهذا المنتج مزيل للعرق، وليس مضادًا للتعرق. أي أنه يزيل الروائح الكريهة، لكنه لا يمنع تمامًا تعرق الإبط، والذي يُعتبر طبيعيًا وصحيًا للجسم.',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:12:18',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-9',0,0),(184,'دیۆدۆرانتی تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Deodorant for sensitive skin from German brand Sebamed','مزيل عرق للبشرة الحساسة من ماركة سيباميد الألمانية','دیۆدۆرانتی تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,6250,9750,1750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆنی لیمۆ (Lime): بۆنێکی فرێش و خۆشی هەیە کە هەستی پاکوخاوێنیت پێ دەبەخشێت.\r\n• بێ کحول (0% Alcohol): زۆر گونجاوە بۆ ئەو کەسانەی پێستیان هەستیارە، چونکە کحول دەبێتە هۆی سووتانەوە یان وشککردنەوەی پێست.\r\n• بێ خوێی ئەلەمنیۆم (No Aluminium salts): ئەم خاڵە زۆر گرنگە؛ زۆربەی دژە ئارەقەکان ئەلەمنیۆمیان تێدایە کە کونیلەکانی پێست دەگرێت، بەڵام ئەمەیان ڕێگری لە ئارەقەکردن ناکات بەڵکو تەنها ڕێگری لە دروستبوونی بۆنی ناخۆش دەکات.\r\n• هاوسەنگی pH 5.5: ئەم بەرهەمە پارێزگاری لە ترشێتی سروشتی پێست دەکات، کە یارمەتیدەرە بۆ ڕێگریکردن لە گەشەی ئەو بەکتریایانەی دەبنە هۆی بۆنی ناخۆش.\r\n• مانەوە بۆ ٤٨ کاتژمێر:کاریگەرییەکەی بۆ ماوەیەکی درێژ دەمێنێتەوە.\r\nکەی بەکار دێت؟\r\nئەم بەرهەمە زیاتر بۆ ئەو کەسانە گونجاوە کە:\r\n١. پێستیان هەستیارە یان دوای تاشینی مووی بن باڵ تووشی سووربوونەوە دەبن.\r\n٢. نایانەوێت ئەو بەرهەمانە بەکاربهێنن کە کونیلەکانی پێست دەگرن (Antiperspirants).\r\n٣. حەز بە بۆنی سووک و سروشتی وەک لیمۆ دەکەن.\r\nتێبینی: ئەگەر مەبەستت ئەوەیە کە بە تەواوی ئارەق نەکەیت، ئەم بەرهەمە ڕەنگە جێگەی ڕەزامەندیت نەبێت، چونکە ئەمە تەنها بۆن لایەبەرە نەک دژە ئارەقە (چونکە ئەلەمنیۆمی تێدا نییە).\r\n','Key Features:\n• Lime Scent: It has a fresh and pleasant scent that gives you a sense of cleanliness.\n• Alcohol-free (0% Alcohol): Ideal for people with sensitive skin, as alcohol can burn or dry the skin.\n• No Aluminum salts: This is very important; Most antiperspirants contain aluminum which clogs pores, but this one doesn’t prevent sweating but only prevents the formation of bad breath.\n• Balance pH 5.5: This product maintains the skin’s natural acidity, which helps to prevent the growth of bacteria that cause bad breath.\n• Stay for 48 hours: The effect lasts for a long time.\nWhen is it used?\nThis product is more suitable for people who:\n1. Their skin is sensitive or they get red after shaving the underarm hair.\n2. They don’t want to use products that block pores (Antiperspirants).\n3. They like light, natural scents like citrus.\nNote: If your intention is to avoid sweating altogether, this product may not be to your satisfaction, as this is only a deodorant, not an antiperspirant (as it does not contain aluminum).','الميزات الرئيسية:\n• رائحة الليمون: يتميز برائحة منعشة ولطيفة تمنحك شعورًا بالنظافة.\n• خالٍ من الكحول (0%): مثالي لأصحاب البشرة الحساسة، حيث أن الكحول قد يسبب تهيجًا أو جفافًا للبشرة.\n• خالٍ من أملاح الألومنيوم: هذه ميزة مهمة للغاية؛ فمعظم مضادات التعرق تحتوي على الألومنيوم الذي يسد المسام، بينما هذا المنتج لا يمنع التعرق، بل يمنع فقط رائحة الفم الكريهة.\n• درجة حموضة متوازنة 5.5: يحافظ هذا المنتج على حموضة البشرة الطبيعية، مما يساعد على منع نمو البكتيريا المسببة لرائحة الفم الكريهة.\n• يدوم مفعوله 48 ساعة: يدوم مفعوله لفترة طويلة.\n\nمتى يُستخدم؟\nهذا المنتج مناسب أكثر للأشخاص الذين:\n1. بشرتهم حساسة أو يحمرّون بعد حلاقة شعر الإبط.\n2. لا يرغبون في استخدام منتجات تسد المسام (مضادات التعرق).\n3. يفضلون الروائح الخفيفة والطبيعية مثل الحمضيات.\n\nملاحظة: إذا كانت نيتك هي تجنب التعرق تمامًا، فقد لا يكون هذا المنتج مناسبًا لك، لأنه مزيل للعرق فقط، وليس مضادًا للتعرق (لأنه لا يحتوي على الألومنيوم).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:15:13',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-8',0,0),(185,'دیۆدرانتی تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی','Deodorant for sensitive skin from German brand Sebamed','مزيل عرق للبشرة الحساسة من ماركة سيباميدي الألمانية','دیۆدرانتی تایبەت بە پێستی هەستیار لە بڕاندی سێبامێدی ئەڵمانی',15,6250,9750,1750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بێ خوێی ئەلەمنیۆم (No Aluminium salts): ئەمە خاڵە هەرە گرنگەکەیەتی، چونکە ڕێگری لە ئارەقەکردنەوە ناکات بە داخستنی کونکەژێکان، بەڵکو تەنها بۆنە ناخۆشەکە ناهێڵێت.\r\n• هاوسەنگی pH 5.5: ئەم نمرەیە هەمان نمرەی ترشەڵۆکی پێستی سروشتی مرۆڤە، کە یارمەتی پاراستنی چینی بەرگری پێست دەدات و ڕێگری لە گەشەی بەکتریا دەگرێت.\r\n• بۆ پێستی هەستیار: دیزاین کراوە بۆ ئەوەی ببێتە هۆی خوران یان سووربوونەوەی بن باڵ.\r\n• مانەوەی ٤٨ کاتژمێر: کە کاریگەرییەکەی تا ٤٨ کاتژمێر دەمێنێتەوە.\r\nپێکهاتەکان:\r\n• Aqua (ئاو): وەک بنکەی بەرهەمەکە.\r\n• Alcohol (کحول): بۆ وشکبوونەوەی خێرا و کوشتنی ئەو بەکتریانەی بۆنی ناخۆش دروست دەکەن (تێبینی: ئەگەر تازە بن باڵت تاشیبێت، ڕەنگە کەمێک بسوتێتەوە بەهۆی کحولەکەوە).\r\n• Triethyl Citrate: پێکهاتەیەکی کاریگەرە بۆ ڕێگریکردن لە دروستبوونی بۆنی ئارەقە.\r\nتێبینییەکی گرنگ:\r\nئەم بەرهەمە Deodorantـە نەک Anti-perspirant. واتە:\r\n• تەنها بۆنی ناخۆش لادەبات.\r\n• نابیێتە هۆی کەمکردنەوەی تەڕی یان بڕی ئارەقەکردنەکە.\r\n','Key Features:\n• No Aluminum salts: This is the most important point, because it does not prevent sweating by closing the pores, but only eliminates the bad smell.\n• Balance pH 5.5: This score is the same as the acidity score of natural human skin, which helps maintain the skin’s barrier layer and inhibits bacterial growth.\n• For sensitive skin: Designed to cause irritation or redness under the wings.\n• 48-hour duration: The effect lasts up to 48 hours.\nIngredients:\n• Aqua (water): as the base of the product.\n• Alcohol: To dry quickly and kill odor-causing bacteria (Note: If you have just shaved your wings, the alcohol may burn slightly).\n• Triethyl Citrate: An effective ingredient to prevent sweat odor.\nImportant note:\nThis product is a deodorant, not an anti-perspirant. mean:\n• Only removes unpleasant smells.\n• Does not reduce moisture or the amount of sweating.','الميزات الرئيسية:\n• خالٍ من أملاح الألومنيوم: هذه هي النقطة الأهم، لأنه لا يمنع التعرق عن طريق سد المسام، بل يزيل الرائحة الكريهة فقط.\n• درجة حموضة متوازنة 5.5: هذه الدرجة مماثلة لدرجة حموضة البشرة الطبيعية، مما يساعد على الحفاظ على حاجز البشرة ويمنع نمو البكتيريا.\n• مناسب للبشرة الحساسة: مصمم لتجنب تهيج أو احمرار منطقة أسفل الأجنحة.\n• يدوم مفعوله حتى 48 ساعة.\n• ماء: أساس المنتج.\n• كحول: يجف بسرعة ويقتل البكتيريا المسببة للرائحة (ملاحظة: قد يسبب الكحول شعورًا طفيفًا بالحرقة إذا كنت قد حلقت منطقة أسفل الأجنحة مؤخرًا).\n• سترات ثلاثي الإيثيل: مكون فعال لمنع رائحة العرق.\n\nملاحظة هامة:\nهذا المنتج مزيل للعرق، وليس مضادًا للتعرق. يعني:\n• يزيل الروائح الكريهة فقط.\n• لا يقلل من رطوبة البشرة أو كمية التعرق.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:16:31',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-7',0,0),(186,'دێۆدرانتی تایبەت بە پیاوان لە بڕاندی سێبامێدی ئەڵمانی','Men\'s deodorant from German brand Sebamed','مزيل عرق رجالي من ماركة سيباميد الألمانية','دێۆدرانتی تایبەت بە پیاوان لە بڕاندی سێبامێدی ئەڵمانی',15,6250,9750,1750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی هەستیار (Sensitive Skin): بە شێوەیەک دروستکراوە کە تەنانەت بۆ ئەو کەسانەش دەبێت کە پێستیان زوو تووشی سووربوونەوە یان خوران دەبێت.\r\n• بێ ئەلەمنیۆم (No Aluminium Salts): ئەمە خاڵێکی زۆر گرنگە بۆ زۆر کەس، چونکە ڕێگری لە ئارەقکردنەوەی سروشتی ناکات و کونیلەکانی پێست داناناخات، بەڵکو تەنها ڕێگری لە دروستبوونی بۆنی ناخۆش دەکات.\r\n• بێ کحول (0% Alcohol): نابێتە هۆی کزانەوەی پێست، بەتایبەت ئەگەر دوای تاشینی مووی بن باڵ بەکاربهێنرێت.\r\n• سیستەمی pH 5.5: ئەمە تایبەتمەندی ناوازەی سێبامێدە کە یارمەتی پاراستنی چینی بەرگری سروشتی پێست دەدات و ڕێگری لە گەشەی ئەو بەکتریایانە دەکات کە بۆنی ناخۆش دروست دەکەن.\r\n• مانەوەی بۆ ماوەی ٤٨ کاتژمێر: بۆ ماوەیەکی درێژ دەتبپارێزێت.\r\nپێکهاتەکانی (Ingredients):\r\n ئەم پێکهاتانەی تێدایە:\r\n• Aqua (ئاو): وەک بنکەیەکی شلەمەنی.\r\n• Zinc Ricinoleate: پێکهاتەیەکی سەرەکییە بۆ مژینی بۆنی ناخۆش بەبێ تێکدانی سیستەمی ئارەقکردنەوە.\r\n• Glycerin: بۆ نەرمکردنەوەی پێست.\r\nتێبینی و ئامۆژگاری:\r\n• چۆنیەتی بەکارهێنان: پێویستە لەسەر پێستێکی پاک و وشک بەکاربهێنرێت بۆ ئەوەی باشترین ئەنجامی هەبێت.\r\n• جیاوازی لەگەڵ دژە ئارەق (Antiperspirant): ئەم بەرهەمە تەنها \"دیۆدرانتە\"، واتە بۆنی ناخۆش لادەبات بەڵام ڕێگری تەواو لە تەڕبوونی بن باڵ ناکات (چونکە ئەلەمنیۆمی تێدا نییە)\r\n','Key Features:\n• For Sensitive Skin: Designed to be even for people whose skin is prone to redness or irritation.\n• No Aluminum Salts: This is a very important point for many people, because it does not prevent natural sweating and does not clog pores, but only prevents the formation of bad breath.\n• Alcohol-free (0% Alcohol): Does not cause skin irritation, especially if used after shaving underarm hair.\n• pH 5.5 System: This is Sebamed’s unique property that helps protect the skin’s natural defense layer and prevents the growth of bacteria that cause bad breath.\n• Lasts for 48 hours: Protects for a long time.\nIngredients:\n Contains the following ingredients:\n• Aqua (water): as a liquid base.\n• Zinc Ricinoleate: A key ingredient for absorbing odors without disrupting the sweat system.\n• Glycerin: To soften the skin.\nNotes and advice:\n• How to use: It should be used on clean, dry skin for best results.\n• Difference with antiperspirant: This product is only a \"deodorant\", ie it removes unpleasant smells but does not completely prevent wetness under the wings (because it does not contain aluminum).','الميزات الرئيسية:\n• للبشرة الحساسة: مصمم ليناسب حتى أصحاب البشرة المعرضة للاحمرار أو التهيج.\n• خالٍ من أملاح الألومنيوم: هذه ميزة مهمة للكثيرين، لأنه لا يمنع التعرق الطبيعي ولا يسد المسام، بل يمنع فقط رائحة الفم الكريهة.\n• خالٍ من الكحول (0%): لا يسبب تهيجًا للبشرة، خاصةً عند استخدامه بعد حلاقة شعر الإبط.\n• نظام درجة حموضة 5.5: هذه خاصية فريدة من نوعها في سيباميد، تساعد على حماية طبقة الدفاع الطبيعية للبشرة وتمنع نمو البكتيريا المسببة لرائحة الفم الكريهة.\n• يدوم مفعوله 48 ساعة: يوفر حماية طويلة الأمد.\n\nالمكونات:\nيحتوي على المكونات التالية:\n• ماء: كقاعدة سائلة.\n• ريسينوليت الزنك: مكون رئيسي لامتصاص الروائح دون التأثير على نظام التعرق.\n• جلسرين: لتنعيم البشرة.\n\nملاحظات ونصائح:\n• طريقة الاستخدام: يُفضل استخدامه على بشرة نظيفة وجافة للحصول على أفضل النتائج.\n• الفرق مع مضادات التعرق: هذا المنتج هو مجرد \"مزيل للعرق\"، أي أنه يزيل الروائح الكريهة ولكنه لا يمنع البلل تمامًا تحت الأجنحة (لأنه لا يحتوي على الألومنيوم).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:17:42',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'50ml','03-6',0,0),(187,'پارێزەری لێو لە بڕاندی سێبامێدی ئەڵمانی','Lip protector from German brand Sebamed','واقي شفاه من العلامة التجارية الألمانية سيباميد','پارێزەری لێو لە بڕاندی سێبامێدی ئەڵمانی',15,3250,5500,1000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستن لە خۆر (SPF 30): یارمەتیدەرە بۆ پاراستنی لێوەکان لە تیشکی زیانبەخشی خۆر، کە ڕێگری دەکات لە ڕەشبوونی لێو و دروستبوونی چرچولۆچی بەهۆی خۆرەوە.\r\n• تام و بۆنی گێلاس (Cherry): ئەم جۆرەیان تامی گێلاسی هەیە و ڕەنگێکی زۆر کاڵ و سروشتی بە لێوەکان دەبەخشێت.\r\n• دەوڵەمەند بە ڤیتامین E: دژە ئۆکسانە و یارمەتی پاراستنی لێو دەدات لە وشکبوونەوە و تێکچوون بەهۆی کاریگەرییە دەرەکییەکان (وەک با و سەرما).\r\n• شێدارکەرەوەیەکی بەهێز: بەپێی ئەوەی لەسەر کارتۆنەکەی نووسراوە، دەبێتە هۆی زیادکردنی شێداری لێو بە ڕێژەی 85%.\r\nکەی و بۆچی بەکاردێت؟\r\n1. بۆ لێوی وشک و قڵیشاو: یارمەتی چاکبوونەوەی لێوەکان دەدات و زۆر بە نەرمی دەیهێڵێتەوە.\r\n2. بۆ وەرزی زستان و هاوین: لە زستاندا دژی قڵیشان و لە هاویندا دژی سووتانی لێو بە خۆر دەپارێزێت.\r\n3. بۆ پێستی هەستیار: چونکە بەرهەمەکانی Sebamed زۆربەیان بۆ پێستی هەستیار (Sensitive Skin) دروستکراون و هاوسەنگی ترشێتی پێست دەپارێزن.\r\nچۆنیەتی بەکارهێنان:\r\nدەتوانیت ڕۆژانە چەند جارێک بەکاری بهێنیت، بەتایبەت پێش ئەوەی بچیتە بەر تیشکی خۆر یان لەو کاتانەی هەست دەکەیت لێوەکانت وشک بوونەتەوە.\r\n','Key Features:\n• Sun Protection (SPF 30): Helps protect lips from harmful sun rays, preventing darkening of the lips and wrinkles caused by the sun.\n• Cherry Flavor: This one has a cherry flavor and gives a very pale and natural color to the lips.\n• Rich in Vitamin E: Antioxidant and helps protect lips from dryness and damage due to external influences (such as wind and cold).\n• Powerful moisturizer: According to the packaging, it increases lip moisture by 85%.\nWhen and why is it used?\n1. For dry and flaky lips: Helps heal lips and keeps them very soft.\n2. For winter and summer: Protects lips against exfoliation in winter and sunburn in summer.\n3. For sensitive skin: Because Sebamed products are mostly designed for sensitive skin and maintain the acidity balance of the skin.\nHow to use:\nYou can use it several times a day, especially before going out in the sun or when you feel your lips are dry.','الميزات الرئيسية:\n• حماية من الشمس (SPF 30): يساعد على حماية الشفاه من أشعة الشمس الضارة، ويمنع اسمرارها وظهور التجاعيد الناتجة عن التعرض للشمس.\n• نكهة الكرز: يتميز هذا المنتج بنكهة الكرز، ويمنح الشفاه لونًا فاتحًا وطبيعيًا.\n• غني بفيتامين E: مضاد للأكسدة، ويساعد على حماية الشفاه من الجفاف والتلف الناتج عن العوامل الخارجية (مثل الرياح والبرد).\n• مرطب قوي: وفقًا للعبوة، يزيد من ترطيب الشفاه بنسبة 85%.\n\nمتى ولماذا يُستخدم؟\n1. للشفاه الجافة والمتقشرة: يساعد على ترطيب الشفاه والحفاظ على نعومتها.\n2. للشتاء والصيف: يحمي الشفاه من التقشر في الشتاء وحروق الشمس في الصيف.\n3. للبشرة الحساسة: لأن منتجات سيباميد مصممة خصيصًا للبشرة الحساسة، وتحافظ على توازن حموضة البشرة.\n\nطريقة الاستخدام:\nيمكنكِ استخدامه عدة مرات في اليوم، خاصةً قبل التعرض للشمس أو عند الشعور بجفاف الشفاه.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:20:21',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'Stick','03-5',0,0),(188,'پارێزەری لێو لە بڕاندی سێبامێدی ئەڵمانی','Lip protector from German brand Sebamed','واقي شفاه من العلامة التجارية الألمانية سيباميد','پارێزەری لێو لە بڕاندی سێبامێدی ئەڵمانی',15,2750,4750,1000,1,'تایبەتمەندییە گرنگەکان:\r\n• پاراستن لە خۆر (SPF 30): ئەمە خاڵێکی زۆر گرنگە، چونکە لێوەکان لە تیشکی زیانبەخشی خۆر دەپارێزێت و ناهێڵێت ڕەنگی لێو تاریک ببێت یان زوو چرچ بێت.\r\n• بۆ لێوی وشک و قڵیشاو: تایبەت دروستکراوە بۆ چارەسەرکردنی وشکی و قڵیشانی لێو و نەرمکردنەوەی.\r\n• ڤیتامین E: ماددەی دژە ئۆکسانی تێدایە کە لێو لە کاریگەرییە خراپەکانی ژینگە دەپارێزێت.\r\n• شێدارکەرەوەی بەهێز: دەبێتە هۆی زیادکردنی شێداری پێست (لێو) بە ڕێژەی 85%.\r\n• بێ ماددەی زیانبەخش: بە جۆرێک دروستکراوە کە بۆ پێستی هەستیار گونجاو بێت و زیانی لێ نەکەوێتەوە.\r\nکەی بەکاردێت؟\r\n• لە وەرزی زستاندا بۆ ڕێگری لە قڵیشانی لێو بەهۆی سەرماوە.\r\n• لە وەرزی هاویندا بۆ پاراستن لە تیشکی خۆر.\r\n• دەتوانیت ڕۆژانە چەند جارێک بەکاری بهێنیت، بەتایبەت پێش چوونە دەرەوە.\r\nتێبینی:\r\nئەم بەرهەمە زیاتر لایەنی چارەسەری و پاراستنی هەیە نەک تەنها جوانکاری. ئەگەر لێوت زۆر وشک دەبێت، ئەمە بژاردەیەکی زۆر گونجاوە.','Important Features:\n• Sun protection (SPF 30): This is very important because it protects the lips from harmful sun rays and prevents darkening or premature wrinkles.\n• For dry and flaky lips: Specially formulated to treat dry and flaky lips and soften them.\n• Vitamin E: Contains antioxidants that protect the lips from the harmful effects of the environment.\n• Powerful moisturizer: Increases skin (lips) moisture by 85%.\n• Harmless: Formulated to be suitable for sensitive skin and not harmful.\nWhen is it used?\n• In winter to prevent cold lip itching.\n• In summer for sun protection.\n• You can use it several times a day, especially before going out.\nnotice:\nThis product is more therapeutic and protective than just cosmetic. If your lips get very dry, this is a great option.','الميزات الرئيسية:\n• حماية من الشمس (SPF 30): هذه الميزة مهمة للغاية لأنها تحمي الشفاه من أشعة الشمس الضارة وتمنع اسمرارها أو ظهور التجاعيد المبكرة.\n• للشفاه الجافة والمتقشرة: تركيبة خاصة لعلاج جفاف وتقشر الشفاه وتنعيمها.\n• فيتامين هـ: يحتوي على مضادات أكسدة تحمي الشفاه من الآثار الضارة للبيئة.\n• مرطب قوي: يزيد ترطيب الشفاه بنسبة 85%.\n• آمن: تركيبة مناسبة للبشرة الحساسة وغير ضارة.\n\nمتى يُستخدم؟\n• في الشتاء للوقاية من حكة الشفاه الناتجة عن البرد.\n• في الصيف للحماية من الشمس.\n• يمكن استخدامه عدة مرات في اليوم، خاصة قبل الخروج.\n\nملاحظة:\nهذا المنتج علاجي ووقائي أكثر من كونه مجرد مستحضر تجميلي. إذا كانت شفتاكِ تعانيان من جفاف شديد، فهذا المنتج خيار ممتاز.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:22:41',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'Stick','03-4',0,0),(189,'پارێزەری لێو لە بڕاندی سێبامێدی ئەڵمانی','Lip protector from German brand Sebamed','واقي شفاه من العلامة التجارية الألمانية سيباميد','پارێزەری لێو لە بڕاندی سێبامێدی ئەڵمانی',15,3250,5500,1000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستن لە خۆر (SPF 30): یەکێک لە باشترین تایبەتمەندییەکانی ئەوەیە کە لێوەکانت لە تیشکی زیانبەخشی خۆر دەپارێزێت، کە دەبێتە هۆی ڕەشبوون یان وشکبوونەوەی لێو.\r\n• شێدارکردنەوەی بەهێز: بەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە، ڕادەی شێداری پێست (لێو) بە ڕێژەی 85% زیاد دەکات.\r\n• ڤیتامین E: تێدایە کە وەک دژە ئۆکسان کار دەکات و لێو لە کاریگەرییە خراپەکانی ژینگە و چرچبوون دەپارێزێت.\r\n• چارەسەری وشکی: زۆر گونجاوە بۆ ئەو کەسانەی لێویان زۆر وشک دەبێت یان قڵیشاوە، چونکە یارمەتی چاکبوونەوەی خێرای لێو دەدات.\r\nبۆ کێ گونجاوە؟\r\n• بۆ هەموو تەمەن و ڕەگەزێک گونجاوە.\r\n• تایبەت بۆ ئەو کەسانە دروستکراوە کە پێستیان هەستیارە (Sensitive Skin).\r\nچۆن بەکاردێت؟\r\nدەتوانیت ڕۆژانە چەند جارێک بەکاری بهێنیت، بەتایبەت پێش چوونە بەر خۆر یان کاتێک هەست بە وشکی لێوت دەکەیت.\r\nتێبینی: ئەم جۆرەیان تامی فرەولەی هەیە، بۆیە ڕەنگێکی زۆر کاڵ و سروشتی دەدات بە لێو (کەمێک سووری زۆر کاڵ).\r\n','Key Features:\n• Sun Protection (SPF 30): One of its best features is that it protects your lips from the sun’s harmful rays, which can cause dark or dry lips.\n• Strong moisturizing: Increases the moisture content of the skin (lips) by 85% according to the packaging.\n• Contains Vitamin E: which acts as an antioxidant and protects the lips from the adverse effects of the environment and wrinkles.\n• Dryness treatment: Ideal for people with very dry or flaky lips, as it helps the lips heal faster.\nWho is it suitable for?\n• Suitable for all ages and genders.\n• Specially designed for people with sensitive skin.\nhow is it used\nYou can use it several times a day, especially before going out in the sun or when your lips are feeling dry.\nNote: This one has a plum flavor, so it gives a very pale and natural color to the lips (slightly very pale red).','الميزات الرئيسية:\n• حماية من الشمس (SPF 30): من أهم مميزاته حماية الشفاه من أشعة الشمس الضارة، التي قد تسبب اسمرارها أو جفافها.\n• ترطيب قوي: يزيد من ترطيب الشفاه بنسبة 85% وفقًا لما هو مذكور على العبوة.\n• يحتوي على فيتامين E: الذي يعمل كمضاد للأكسدة ويحمي الشفاه من الآثار الضارة للبيئة والتجاعيد.\n• علاج الجفاف: مثالي لمن يعانون من جفاف أو تقشر الشفاه الشديد، حيث يساعد على التئامها بشكل أسرع.\n\nلمن يناسب؟\n• مناسب لجميع الأعمار والجنسين.\n• مصمم خصيصًا لأصحاب البشرة الحساسة.\n\nطريقة الاستخدام\nيمكنك استخدامه عدة مرات في اليوم، خاصة قبل التعرض للشمس أو عند الشعور بجفاف الشفاه.\nملاحظة: يتميز هذا المنتج بنكهة البرقوق، مما يمنح الشفاه لونًا فاتحًا وطبيعيًا (أحمر فاتح جدًا).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:23:58',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'Stick','03-3',0,0),(190,'پارێزەری لێوی منداڵان لە بڕاندی سێبامێدی ئەڵمانی','Children\'s lip protector from German brand Sebamed','واقي شفاه للأطفال من ماركة سيباميد الألمانية','پارێزەری لێوی منداڵان لە بڕاندی سێبامێدی ئەڵمانی',15,3500,5500,1000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سروشتی: دەوڵەمەندە بە زەیتی جۆجۆبا (Jojoba Oil) و کەرەی شیا (Shea Butter) کە یارمەتی شێدارکردنەوەی قووڵی لێو دەدەن و نایەڵن وشک ببێتەوە.\r\n• ڤیتامین E: ئەم ڤیتامینەی تێدایە بۆ پاراستنی لێو لە کاریگەرییە خراپەکانی ژینگە و هەوکردن.\r\n• پاراستن: وەک چینێکی پارێزەر کاردەکات دژی وشکبوونەوەی لێو کە بەهۆی سەرما، با، یان ئاڵوگۆڕی کەشوهەوا دروست دەبێت.\r\n• بێ ماددەی زیانبەخش: زۆربەی بەرهەمەکانی سێبامێد خاڵین لە ماددەی پارێزەر (Parabens) و ڕەنگە دەستکردەکان، کە ئەمەش بۆ پێستی ناسکی منداڵ زۆر گونجاوە.\r\nکەی بەکاردێت؟\r\n• بۆ ئەو منداڵانەی لێویان وشک دەبێتەوە یان قڵیشاوە.\r\n• بۆ پاراستنی لێوی منداڵ لە وەرزی سەرمادا.\r\n• گونجاوە بۆ بەکارهێنان لە یەکەم ڕۆژی لەدایکبوونەوە (بەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە).\r\nچۆنیەتی بەکارهێنان:\r\nڕۆژانە دوو بۆ سێ جار، یان هەر کاتێک هەستت کرد لێوی منداڵەکە پێویستی بە شێدارییە، بڕێکی کەمی لێ بدە.\r\n','Key Features:\n• Natural Ingredients: Rich in Jojoba Oil and Shea Butter that help deeply moisturize the lips and prevent them from drying out.\n• Vitamin E: Contains this vitamin to protect the lips from adverse environmental effects and infection.\n• Protection: Acts as a protective layer against dry lips caused by cold, wind, or weather changes.\n• Harmless: Most Sebamed products are free of parabens and artificial colors, which is ideal for children\'s delicate skin.\nWhen is it used?\n• For children with dry or flaky lips.\n• To protect children\'s lips in winter.\n• Suitable for use from the first day of birth (as stated on the carton).\nHow to use:\nApply a small amount two to three times a day, or whenever you feel baby’s lips need moisture.','الميزات الرئيسية:\n• مكونات طبيعية: غني بزيت الجوجوبا وزبدة الشيا لترطيب الشفاه بعمق ومنع جفافها.\n• فيتامين هـ: يحتوي على هذا الفيتامين لحماية الشفاه من العوامل البيئية الضارة والعدوى.\n• حماية: يشكل طبقة واقية ضد جفاف الشفاه الناتج عن البرد أو الرياح أو تغيرات الطقس.\n• آمن: معظم منتجات سيباميد خالية من البارابين والألوان الصناعية، مما يجعلها مثالية لبشرة الأطفال الحساسة.\n\nمتى يُستخدم؟\nللأطفال ذوي الشفاه الجافة أو المتقشرة.\nلحماية شفاه الأطفال في فصل الشتاء.\nمناسب للاستخدام من اليوم الأول للولادة (كما هو موضح على العبوة).\n\nطريقة الاستخدام: ضعي كمية صغيرة مرتين إلى ثلاث مرات يوميًا، أو كلما شعرتِ أن شفاه طفلكِ بحاجة إلى ترطيب.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:26:22',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'Stick','03-2',0,0),(191,'پارەێزەری لێو لە نڕاندی سێبامێدی ئەڵمانی','Lip protection from German brand Sebamed','واقي للشفاه من العلامة التجارية الألمانية سيباميد','پارەێزەری لێو لە بڕاندی سێبامێدی ئەڵمانی',15,3250,5500,1000,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستن لە خۆر (SPF 30): یارمەتیدەرە بۆ پاراستنی پێستی ناسکی لێو لە تیشکی زیانبەخشی خۆر (UVA و UVB)، کە ڕێگری دەکات لە قڵیشان و تۆخبوونەوەی ڕەنگی لێو بەهۆی خۆرەوە.\r\n• شێدارکردنەوەی بەهێز:  شێداریی پێست بە ڕێژەی 85% زیاد دەکات، ئەمەش بۆ ئەو کەسانە زۆر باشە کە لێویان زۆر وشک دەبێتەوە یان دەقڵیشێت.\r\n• ڤیتامین E: پێکهاتەی ئەم بەرهەمە ڤیتامین E تێدایە کە وەک دژە ئۆکسان کار دەکات و لێو لە کاریگەرییە خراپەکانی ژینگە دەپارێزێت.\r\n• گونجاوە بۆ پێستی ناسک: بەرهەمەکانی سێبامید بەوە ناسراون کە بۆ ئەو کەسانە باشن کە پێستیان حەساسە.\r\n• بۆن و تام: ئەم جۆرەیان تامی شووتی (Watermelon) یە، کە بۆنێکی خۆش و جیاوازی هەیە.\r\nکەی بەکاردێت؟\r\n• لە کاتی چوونە بەر خۆر بۆ پاراستنی لێو.\r\n• لە وەرزی زستان و سەرما کە لێو تووشی وشکبوونەوەی زۆر دەبێت.\r\n• پێش بەکارهێنانی سووراو (حەمرا) بۆ ئەوەی لێو بە نەرمی بمێنێتەوە.\r\nتێبینی: سێبامید براندێکی ئەڵمانییە و بەوە ناسراوە کە هاوسەنگی ترشێتی (pH 5.5) دەپارێزێت، کە ئەمەش بۆ تەندروستی پێست زۆر گرنگە.\r\n','Key Features:\n• Sun Protection (SPF 30): Helps protect delicate lip skin from harmful sun rays (UVA and UVB), preventing sun-induced exfoliation and darkening of lip color.\n• Powerful Moisturizing: Increases skin moisture by 85%, which is great for people with extremely dry or chapped lips.\n• Vitamin E: This product contains vitamin E, which acts as an antioxidant and protects the lips from the harmful effects of the environment.\n• Suitable for delicate skin: Sebamid products are known to be good for people with sensitive skin.\n• Smell and taste: This is a watermelon flavor, which has a pleasant and distinctive smell.\nWhen is it used?\n• When going out in the sun to protect the lips.\n• In winter and cold when the lips become very dry.\n• Before applying lipstick (hamra) to keep lips soft.\nNote: Sebamid is a German brand and is known to maintain an acidity balance (pH 5.5), which is very important for skin health.','الميزات الرئيسية:\n• حماية من الشمس (SPF 30): يساعد على حماية بشرة الشفاه الحساسة من أشعة الشمس الضارة (UVA وUVB)، ويمنع تقشر الشفاه واسمرار لونها الناتج عن الشمس.\n• ترطيب قوي: يزيد من ترطيب البشرة بنسبة 85%، وهو مثالي لمن يعانون من جفاف أو تشقق الشفاه الشديد.\n• فيتامين E: يحتوي هذا المنتج على فيتامين E، الذي يعمل كمضاد للأكسدة ويحمي الشفاه من الآثار الضارة للبيئة.\n• مناسب للبشرة الحساسة: منتجات سيباميد معروفة بفعاليتها مع البشرة الحساسة.\n• رائحة وطعم: يتميز بنكهة البطيخ، برائحة لطيفة ومميزة.\n\n• متى يُستخدم؟\n• عند الخروج في الشمس لحماية الشفاه.\n• في فصل الشتاء والبرد عندما تصبح الشفاه جافة جدًا.\n• قبل وضع أحمر الشفاه (الحمراء) للحفاظ على نعومة الشفاه.\n\n• ملاحظة: سيباميد علامة تجارية ألمانية معروفة بقدرتها على الحفاظ على توازن الحموضة (pH 5.5)، وهو أمر بالغ الأهمية لصحة البشرة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-08 08:28:45',0.00,'percentage',NULL,13,NULL,3,NULL,NULL,'Stick','03-1',0,0),(192,'لۆشنی تایبەت بە چارەسەرکردنی وشکی زۆری پێست لە بڕاندی بابێی ئیسپانی','Lotion for treating extreme dryness of the skin from the Spanish brand Babe','لوشن لعلاج الجفاف الشديد للبشرة من ماركة Babe الإسبانية','لۆشنی تایبەت بە چارەسەرکردنی وشکی زۆری پێست لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'پێکهاتە سەرەکییەکانی:\r\n• یوریا (Urea 10%): ئەمە پێکهاتە سەرەکییەکەیە کە کاردەکات بۆ شێدارکردنەوەی قووڵی پێست و لادانی خانە مردووەکان (تەقشیرێکی سووک).\r\n• ڕۆنی سۆیا (Soy Oil 3.5%): یارمەتی نەرمکردنەوەی پێست دەدات.\r\n• گلیسرین (Glycerin 3%): بۆ پاراستنی شێداری ناو پێست.\r\n• کەرەی شیا (Shea Butter 2%): بۆ قووڵ شێدارکردنەوە و پاراستنی پێست لە وشکبوونەوە.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات.\r\nسودەکانی ئەم لۆشنە:\r\n1. بۆ پێستی زۆر وشک: تایبەت دروستکراوە بۆ ئەو کەسانەی پێستیان زۆر وشکە، زبرە، یان قڵیشاوە.\r\n2. کەمکردنەوەی خوران: یارمەتی هێورکردنەوەی ئەو خوران و کزانە دەدات کە بەهۆی وشکی زۆرەوە دروست دەبێت.\r\n3. چاککردنەوەی پێست: یارمەتی گەڕاندنەوەی نەرمی و تەندروستی بۆ پێست دەدات.\r\n4. هەستکردن بە ئارامی: یەکسەر دوای بەکارهێنان هەست بە نەرمی و ئارامی پێست دەکەیت.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو بدە لەو شوێنانەی جەستەت کە وشکە.\r\n• بە شێوەی بازنەیی مەساژی بۆ بکە تا پێستەکە هەڵیدەمژێت.\r\n• دەتوانیت ڕۆژانە یان بەپێی پێویست بەکاریبهێنیت.\r\nتێبینی گرنگ:\r\n• ئەم بەرهەمە زیاتر بۆ جەستە بەکاردێت.\r\n• باشترە لەو شوێنانە بەکارنەیەت کە برینی کراوەیان پێوەیە یان زۆر هەستیارن (وەک دەموچاو ئەگەر پێستت زۆر هەستیار بێت)، چونکە ڕێژەی ١٠٪ یوریا ڕەنگە کەمێک کزانەوە دروست بکات ئەگەر پێستەکە زۆر تەنک بێت.','Key ingredients:\n• Urea (Urea 10%): This is the key ingredient that works to deeply moisturize the skin and remove dead cells (mild exfoliation).\n• Soy Oil (3.5%): Helps soften the skin.\n• Glycerin (3%): To maintain moisture in the skin.\n• Shea Butter (2%): To deeply moisturize and protect skin from drying out.\n• Vitamin E: Acts as an antioxidant.\nBenefits of this lotion:\n1. For Very Dry Skin: Specially formulated for people with very dry, rough, or exfoliated skin.\n2. Reduce itching: Helps relieve itching and cramps caused by excessive dryness.\n3. Skin repair: Helps restore softness and health to the skin.\n4. Feeling comfortable: Immediately after use, you will feel soft and comfortable skin.\nHow to use:\n• Apply appropriate amounts to areas of your body that are dry.\n• Massage in circular motions until skin absorbs.\n• You can use it daily or as needed.\nImportant Note:\n• This product is mostly used for the body.\n• It is best not to use on areas with open wounds or very sensitive areas (such as the face if your skin is very sensitive), as 10% urea may cause slight shrinkage if the skin is very thin.','المكونات الرئيسية:\n• اليوريا (10%): هذا هو المكون الرئيسي الذي يعمل على ترطيب البشرة بعمق وإزالة الخلايا الميتة (تقشير لطيف).\n• زيت الصويا (3.5%): يساعد على تنعيم البشرة.\n• الجلسرين (3%): للحفاظ على رطوبة البشرة.\n• زبدة الشيا (2%): لترطيب البشرة بعمق وحمايتها من الجفاف.\n• فيتامين هـ: يعمل كمضاد للأكسدة.\n\nفوائد هذا المستحضر:\n1. للبشرة شديدة الجفاف: تركيبة خاصة للأشخاص ذوي البشرة شديدة الجفاف أو الخشنة أو المتقشرة.\n2. تخفيف الحكة: يساعد على تخفيف الحكة والتقلصات الناتجة عن الجفاف الشديد.\n3. ترميم البشرة: يساعد على استعادة نعومة البشرة وصحتها.\n4. شعور بالراحة: ستشعرين بنعومة بشرتكِ وراحتها فورًا بعد الاستخدام.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة على المناطق الجافة من جسمكِ.\n• دلكي بحركات دائرية حتى تمتصه البشرة.\n• يمكنك استخدامه يوميًا أو حسب الحاجة.\n\nملاحظة هامة:\n• يُستخدم هذا المنتج في الغالب للجسم.\n• يُفضّل عدم استخدامه على المناطق التي بها جروح مفتوحة أو المناطق شديدة الحساسية (مثل الوجه إذا كانت بشرتك حساسة للغاية)، حيث قد يُسبب تركيز اليوريا بنسبة 10% انكماشًا طفيفًا إذا كانت البشرة رقيقة جدًا.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:27:24',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'100ml','01-69',0,0),(193,'سپڕای دژە خۆر لە بڕاندی بابێی ئیسپانی','Sunscreen spray from Spanish brand Babe','بخاخ واقي من الشمس من ماركة Babe الإسبانية','سپڕای دژە خۆر لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەرز (SPF 50): پێست دەپارێزێت لە هەردوو تیشکی زیانبەخشی UVA و UVB.\r\n• تایبەتمەندی Wet Skin: ئەمە گرنگترین خاڵیەتی؛ دەتوانیت ڕاستەوخۆ لەسەر پێستی تەڕ بەکاریبهێنیت (بۆ نموونە دوای مەلەکردن یان عارەقکردنەوە) بەبێ ئەوەی کاریگەرییەکەی کەم بێتەوە یان شوێنەواری سپی جێبهێڵێت.\r\n• ڕوون و شەفاف (Transparent): دوای لێدان بە خێرایی هەڵدەمژرێت و هیچ ڕەنگێکی سپی بەسەر پێستەوە جێناهێڵێت.\r\n• بەرگری لە ئاو: بۆ ماوەیەکی باش بەرگەی ئاو دەگرێت، بۆیە بۆ کەنار دەریا و مەلەوانگە زۆر گونجاوە.\r\nچۆنێتی بەکارهێنان:\r\n1. پێش بەکارهێنان: قوتووەکە بە باشی ڕابوەشێنە.\r\n2. کاتی لێدان: نزیکەی ٢٠ خولەک پێش ئەوەی بچیتە بەر خۆر لێی بدە.\r\n3. دووبارەکردنەوە: پێویستە هەموو ٢ کاتژمێر جارێک دووبارەی بکەیتەوە، یان دوای هەر مەلەکردنێک یان وشککردنەوەی جەستە بە خاولی.\r\n4. ئاگاداری: ڕاستەوخۆ لە دەموچاوی مەدە؛ سەرەتا بیڕێژە سەر دەستت و پاشان بیدە لە دەموچاوت (بۆ ئەوەی نەچێتە ناو چاوت یان هەناسەتەوە).\r\nتێبینییە گرنگەکان:\r\n• ئەم سپڕایە لە هەر ئاڕاستەیەک بێت کار دەکات (تەنانەت ئەگەر سەرەوخواریش بێت)، ئەمەش بەکارهێنانی بۆ پشت و شوێنە دوورەکان ئاسان دەکات.\r\n','Key Features:\n• High Protection (SPF 50): Protects skin from both harmful UVA and UVB rays.\n• Wet Skin Feature: This is the most important point; You can use it directly on wet skin (e.g. after swimming or sweating) without diminishing effectiveness or leaving a white trail.\n• Transparent: Absorbs quickly after application and does not leave any white color on the skin.\n• Water resistance: Water resistant for a good amount of time, so it’s perfect for the beach and swimming pool.\nHow to use:\n1. Before use: Shake the bottle well.\n2. Application time: Apply about 20 minutes before going out in the sun.\n3. Repeat: You should repeat every 2 hours, or after each swim or towel drying.\n4. Caution: Do not hit him directly in the face; Pour it onto your hands first and then apply to your face (so it doesn’t get in your eyes or breath).\nImportant Notes:\n• This spray works in any direction (even upside down), making it easy to use on the back and remote areas.','الميزات الرئيسية:\n• حماية عالية (SPF 50): يحمي البشرة من أشعة UVA وUVB الضارة.\n• مناسب للبشرة الرطبة: هذه الميزة الأهم؛ يمكنكِ استخدامه مباشرةً على البشرة الرطبة (مثلاً بعد السباحة أو التعرق) دون أن يتأثر مفعوله أو يترك أي أثر أبيض.\n• شفاف: يمتص بسرعة بعد الاستخدام ولا يترك أي لون أبيض على البشرة.\n• مقاوم للماء: مقاوم للماء لفترة طويلة، مما يجعله مثالياً للشاطئ وحمام السباحة.\n\nطريقة الاستخدام:\n1. قبل الاستخدام: رجي الزجاجة جيداً.\n2. وقت الاستخدام: ضعيه قبل الخروج من الشمس بحوالي 20 دقيقة.\n3. التكرار: كرري الاستخدام كل ساعتين، أو بعد كل سباحة أو تجفيف بالمنشفة.\n\nتحذير: تجنبي ملامسته للوجه مباشرةً؛ ضعيه على يديكِ أولاً ثم ضعيه على وجهكِ (مع الحرص على عدم دخوله في عينيكِ أو تنفسكِ).\n\nتحذير: تجنبي ملامسته للوجه مباشرةً؛ ضعيه على يديكِ أولاً ثم ضعيه على وجهكِ (مع الحرص على عدم دخوله في عينيكِ أو تنفسكِ). ملاحظات هامة:\n• يعمل هذا البخاخ في أي اتجاه (حتى رأساً على عقب)، مما يجعله سهل الاستخدام على الظهر والمناطق البعيدة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:28:40',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-68',0,0),(194,'پاکەرەوەی دەم و چاو تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی','Facial cleanser for oily and acne prone skin from Spanish brand Babe','غسول للوجه للبشرة الدهنية والمعرضة لحب الشباب من ماركة Babe الإسبانية','پاکەرەوەی دەم و چاو تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پێکهاتە سەرەکییەکانی:\r\n• Salicylic Acid: یارمەتیدەرە بۆ پاککردنەوەی کونیلەکانی پێست و نەهێشتنی چەوری زیادە و ڕێگری لە دروستبوونی زیپکە دەکات.\r\n• Succinic Acid: تایبەتمەندی دژە بەکتریای هەیە و یارمەتی کەمکردنەوەی سووربوونەوەی پێست دەدات.\r\n• Azeloglycin: یارمەتی هاوسەنگکردنی چەوری پێست دەدات و ڕەنگی پێست ڕێکدەخاتەوە.\r\n• Prebiotic: یارمەتی پاراستنی بەربەستی سروشتی پێست دەدات (Microbiome) بۆ ئەوەی پێستەکە تەندروست بمێنێتەوە.\r\n٢. سوودەکانی ئەم غەسولە:\r\n• کۆنترۆڵکردنی چەوری: بە قووڵی پێست پاک دەکاتەوە و بریقەی ناخۆشی سەر دەموچاو (کە بەهۆی چەورییەوە دروست دەبێت) کەم دەکاتەوە.\r\n• ڕێگری لە زیپکە: کونیلەکان دەکاتەوە و ناهێڵێت بەکتریا تێیاندا کۆببێتەوە.\r\n• ماتکردنی پێست (Mattifies): پێستەکە شێوەیەکی سروشتی و بێ بریقەی چەوری پێ دەبەخشێت.\r\n• نایەکزێنێت: ئەم غەسولە لە جۆری (Syndet)ە، واتە سابوونی تێدا نییە، بۆیە پێست زۆر وشک ناکاتەوە و هاوسەنگییەکەی دەپارێزێت.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• ڕۆژی دوو جار (بەیانیان و شەوان) بەکاری بهێنە.\r\n• کەمێکی لێ بدە لە دەموچاوێکی تەڕ، بە هێواشی مەساجی پێ بکە، پاشان بە ئاوێکی شلەتێن بیشۆ.\r\n','. . . . Key ingredients:\n• Salicylic Acid: Helps cleanse pores, remove excess oil and prevent acne.\n• Succinic Acid: It has antibacterial properties and helps reduce skin redness.\n• Azeloglycin: Helps balance skin oil and restore skin tone.\n• Prebiotic: Helps maintain the skin’s natural barrier (Microbiome) to keep the skin healthy.\n2. Benefits of this lotion:\n• Oil Control: Deeply cleanses the skin and reduces unsightly shine on the face (caused by oil).\n• Prevents acne: Opens pores and prevents bacteria from building up.\n• Mattifies: Gives the skin a natural, oily shine-free appearance.\n• Does not dry out: This lotion is syndet, which means it does not contain soap, so it does not dry the skin too much and maintains its balance.\n3. How to use:\n• Use twice a day (morning and night).\n• Apply a small amount to a wet face, massage gently, then rinse with lukewarm water.','المكونات الرئيسية:\n• حمض الساليسيليك: يساعد على تنظيف المسام، وإزالة الزيوت الزائدة، والوقاية من حب الشباب.\n• حمض السكسينيك: يتميز بخصائص مضادة للبكتيريا، ويساعد على تقليل احمرار البشرة.\n• أزيلوجليسين: يساعد على موازنة إفراز الزيوت في البشرة، واستعادة لونها الطبيعي.\n• البريبايوتيك: يساعد على الحفاظ على حاجز البشرة الطبيعي (الميكروبيوم) للحفاظ على صحة البشرة.\n\n٢. فوائد هذا المستحضر:\n• التحكم في الزيوت: ينظف البشرة بعمق، ويقلل من اللمعان غير المرغوب فيه على الوجه (الناتج عن الزيوت).\n• الوقاية من حب الشباب: يفتح المسام، ويمنع تراكم البكتيريا.\n• يمنح البشرة مظهرًا مطفيًا: يمنح البشرة مظهرًا طبيعيًا غير لامع.\n• لا يسبب الجفاف: هذا المستحضر خالٍ من الصابون، لذا فهو لا يسبب جفافًا مفرطًا للبشرة، ويحافظ على توازنها.\n\n٣. طريقة الاستخدام:\n• يُستخدم مرتين يوميًا (صباحًا ومساءً).\n• ضعي كمية صغيرة على وجه مبلل، ودلكي بلطف، ثم اشطفي بالماء الفاتر.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:30:02',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'400ml','01-67',0,0),(196,'جێلی پاکەرەوەی تایبەت بە پێستی هەستیار و ئاسای لە بڕاندی بابێی ئیسپانی','Cleansing gel for sensitive and normal skin from Spanish brand Babe','جل منظف للبشرة الحساسة والعادية من ماركة Babe الإسبانية','جێلی پاکەرەوەی تایبەت بە پێستی هەستیار و ئاسای لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاککەرەوەیەکی نەرم (Syndet): ئەم جێڵە لە جۆری \"Syndet\"ە، واتە سابوونی تێدا نییە. ئەمەش یارمەتیدەرە بۆ ئەوەی پێستەکە وشک نەکاتەوە و هاوسەنگی سروشتی پێست تێکنەدات.\r\n• تەکنەلۆژیای میسێلار (Micellar): یارمەتی لێکردنەوەی ماکیاژ و پیسی دەموچاو دەدات بەبێ ئەوەی پێویست بکات بە توندی پێستەکە بخشێنیت.\r\n• پلەی ترشێتی (pH 5.5): هاوشێوەی پلەی ترشێتی سروشتی پێستە، کە ئەمەش پارێزگاری لە بەربەستی پارێزەری پێست دەکات.\r\n• پێکهاتەی هێورکەرەوە: ماددەی وەک Glycerin و Licorice (سۆس)ی تێدایە کە یارمەتی شێدارکردنەوە و کەمکردنەوەی سووربوونەوە و خورانی پێست دەدەن.\r\nسوودەکانی:\r\n1. پێست بە قووڵی پاک دەکاتەوە بەبێ ئەوەی بێزاری بکات.\r\n2. بۆ ئەو کەسانە زۆر گونجاوە کە پێستیان زۆر هەستیارە یان بەهۆی وشکییەوە دەخورێت.\r\n3. هەستی نەرمی و تازەیی بە پێست دەبەخشێت.\r\n4. لە تاقیکارییە پزیشکییەکاندا دەرکەوتووە کە نابێتە هۆی هەستیاری (Hypoallergenic).\r\nچۆن بەکاردێت؟\r\n• بڕێکی گونجاو بدە لە دەموچاوی تەڕ.\r\n• بە هێواشی مەساجی پێ بکە تا کەفێکی کەم دروست دەکات.\r\n• پاشان بە ئاوێکی شلەتێن بە باشی دەموچاوت بشۆ.\r\n• دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.','Key Features:\n• Gentle cleanser (Syndet): This gel is of the \"Syndet\" type, meaning it does not contain soap. This helps to avoid drying out the skin and upsetting the skin’s natural balance.\n• Micellar technology: Helps remove makeup and dirt without having to scrub the skin harshly.\n• Acidity (pH 5.5): Similar to the skin\'s natural acidity, which maintains the skin\'s protective barrier.\n• Soothing ingredients: Contains ingredients such as glycerin and licorice (sauce) that help moisturize and reduce redness and irritation.\nBenefits:\n1. Deeply cleanses the skin without irritating it.\n2. Perfect for people with very sensitive or dry skin.\n3. Gives the skin a soft and fresh feeling.\n4. Clinical tests have shown that it is hypoallergenic.\nhow is it used\n• Apply appropriate amount to wet face.\n• Massage gently until it forms a slight lather.\n• Then wash your face thoroughly with lukewarm water.\n• You can use it twice a day (morning and night).','الميزات الرئيسية:\n• منظف لطيف (ساينديت): هذا الجل من نوع \"ساينديت\"، أي أنه خالٍ من الصابون. يساعد ذلك على تجنب جفاف البشرة والحفاظ على توازنها الطبيعي.\n• تقنية الميسيلار: تساعد على إزالة المكياج والأوساخ دون الحاجة إلى فرك البشرة بقوة.\n• حموضة (درجة حموضة 5.5): مشابهة لحموضة البشرة الطبيعية، مما يحافظ على حاجزها الواقي.\n• مكونات مهدئة: يحتوي على مكونات مثل الجلسرين وعرق السوس (الصلصة) التي تساعد على ترطيب البشرة وتقليل الاحمرار والتهيج.\n\nالفوائد:\n1. ينظف البشرة بعمق دون تهييجها.\n2. مثالي لأصحاب البشرة الحساسة جدًا أو الجافة.\n3. يمنح البشرة ملمسًا ناعمًا ومنتعشًا.\n4. أثبتت الاختبارات السريرية أنه لا يسبب الحساسية.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة على وجه مبلل.\nدلكي بلطف حتى تتكون رغوة خفيفة.\n\nاستخدمي\n • ثم اغسلي وجهك جيداً بالماء الفاتر.\n• يمكنكِ استخدامه مرتين يومياً (صباحاً ومساءً).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:31:25',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'90ml','01-66',0,0),(197,'لۆشنی تایبەت بە چارەسەرکردنی وشکی زۆری پێست کە بڕاندی بابێی ئیسپانی','Lotion for treating extreme dryness of the skin from the Spanish brand Babe','لوشن لعلاج الجفاف الشديد للبشرة من ماركة Babe الإسبانية','لۆشنی تایبەت بە چارەسەرکردنی وشکی زۆری پێست کە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'پێکهاتە سەرەکییەکان:\r\n• یوریا (Urea 10%): ماددەیەکی زۆر کارایە بۆ شێدارکردنەوەی قووڵی پێست و نەهێشتنی زبری و خانە مردووەکان.\r\n• ڕۆنی سۆیا (Soy Oil): یارمەتی نەرمکردنەوەی پێست دەدات.\r\n• گلیسرین (Glycerin): پارێزگاری لە شێی پێست دەکات بۆ ماوەیەکی درێژ.\r\n• کەرەی شیا (Shea Butter): پێستەکە لە وشکبوونەوە دەپارێزێت و بەهێزی دەکات.\r\nسوودەکانی:\r\n• شێدارکردنەوەی قووڵ: تایبەتە بۆ ئەو پێستانەی زۆر وشکن، زبرن، یان قڵیشاون.\r\n• ئارامکەرەوە: خوران و توندبوونی پێست کە بەهۆی وشکییەوە دروست دەبێت، کەمدەکاتەوە.\r\n• چاککەرەوە: یارمەتی گەڕانەوەی نەرمی و سروشتیی پێست دەدات.\r\nشێوازی بەکارهێنان:\r\n• بڕێکی گونجاو لە لۆشنەکە بدە لەو شوێنانەی پێستت کە وشکن.\r\n• بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\n• دەتوانیت ڕۆژانە یان بەپێی پێویست بەکاریبهێنیت.\r\nتێبینییە گرنگەکان:\r\n• ئەم بەرهەمە لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە (Dermatologically Tested).\r\n','Key Ingredients:\n• Urea (Urea 10%): A very effective agent to deeply moisturize the skin and eliminate roughness and dead cells.\n• Soy Oil: Helps soften the skin.\n• Glycerin: Protects skin moisture for a long time.\n• Shea Butter: Protects and strengthens the skin.\nBenefits:\n• Deep moisturizing: Ideal for very dry, rough, or exfoliated skin.\n• Soothing: Relieves dry skin irritation and tightness.\n• Restorative: Helps restore the natural softness of the skin.\nHow to use:\n• Apply the appropriate amount of lotion to dry areas of your skin.\n• Gently massage until fully absorbed.\n• You can use it daily or as needed.\nImportant Notes:\n• This product is Dermatologically Tested.','المكونات الرئيسية:\n• اليوريا (10%): عامل فعال للغاية لترطيب البشرة بعمق وإزالة الخشونة والخلايا الميتة.\n• زيت الصويا: يساعد على تنعيم البشرة.\n• الجلسرين: يحافظ على رطوبة البشرة لفترة طويلة.\n• زبدة الشيا: تحمي البشرة وتقويها.\n\nالفوائد:\n• ترطيب عميق: مثالي للبشرة شديدة الجفاف أو الخشنة أو المتقشرة.\n• مهدئ: يخفف من تهيج البشرة الجافة والشعور بالشد.\n• مُرمم: يساعد على استعادة نعومة البشرة الطبيعية.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة من اللوشن على المناطق الجافة من بشرتك.\n• دلكي بلطف حتى يتم امتصاصه بالكامل.\n• يمكنك استخدامه يوميًا أو حسب الحاجة.\n\nملاحظات هامة:\n• هذا المنتج مُختبر من قبل أطباء الجلدية.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:32:51',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'500ml','01-65',0,0),(198,'شامپۆی تایبەت بە پێستی هەستیار و ناسک لە بڕاندی بابێی ئیسپانی','Shampoo for sensitive and delicate skin from Spanish brand Babe','شامبو للبشرة الحساسة والرقيقة من ماركة Babe الإسبانية','شامپۆی تایبەت بە پێستی هەستیار و ناسک لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پێکهاتە و سوودەکانی:\r\n• جۆجۆبا (Jojoba Active): ئەم پێکهاتەیە یارمەتی نەرمکردنەوەی پێست دەدات و پارێزگاری لە تەڕییەکەی دەکات.\r\n• هێورکەرەوە (Soothing Complex): پێکهاتەی وەک ئالۆڤێرا و بەیبوون (Chamomile) ی تێدایە کە سووربوونەوە و خورانی پێست کەمدەکاتەوە.\r\n• بێ سابوون (Syndet): ئەمە جۆرە پاککەرەوەیەکە کە سابوونی تێدا نییە، ئەمەش وادەکات هاوسەنگی سروشتی پێست تێکنەچێت.\r\n٢. بۆ کێ گونجاوە؟\r\n• بۆ ئەو کەسانەی پێستیان ناسکە (Sensitive Skin) یان زوو تووشی خوران و سووربوونەوە دەبن.\r\n• بۆ بەکارهێنانی ڕۆژانە گونجاوە چونکە زۆر نەرمە و پێست وشک ناکاتەوە.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• بڕێکی گونجاو بدە لە پێستی تەڕ لەکاتی خۆشۆردندا.\r\n• بە هێواشی مەساجی پێ بکە و پاشان بە ئاوێکی زۆر بیشۆ.\r\n','Ingredients and Benefits:\n• Jojoba Active: This ingredient helps soften the skin and maintain moisture.\n• Soothing Complex: Contains ingredients such as aloe vera and chamomile that reduce redness and irritation.\n• Soap-free (Syndet): This is a soap-free cleanser, which prevents the skin\'s natural balance.\n2. Who is it suitable for?\n• For people with sensitive skin or prone to itching and redness.\n• Suitable for daily use because it is very soft and does not dry the skin.\n3. How to use:\n• Apply an appropriate amount to wet skin while bathing.\n• Massage gently and then rinse with plenty of water.',' المكونات والفوائد:\n• مستخلص الجوجوبا: يساعد هذا المكون على تنعيم البشرة والحفاظ على رطوبتها.\n• مركب مهدئ: يحتوي على مكونات مثل الصبار والبابونج التي تقلل الاحمرار والتهيج.\n• خالٍ من الصابون (سينديت): هذا غسول خالٍ من الصابون، مما يحافظ على التوازن الطبيعي للبشرة.\n\nلمن يناسب؟\n• مناسب لأصحاب البشرة الحساسة أو المعرضة للحكة والاحمرار.\n• مناسب للاستخدام اليومي لأنه لطيف جدًا ولا يسبب جفاف البشرة.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة على بشرة مبللة أثناء الاستحمام.\n• دلكي بلطف ثم اشطفي جيدًا بالماء.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:34:24',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'500ml','01-64',0,0),(199,'سپڕای تایبەت بە پێستی منداڵان لە بڕاندی بابێی ئیسپانی','Children\'s sunscreen spray from the Spanish brand Babe','بخاخ واقي من الشمس للأطفال من ماركة Babe الإسبانية','سپڕای دژە خۆر تایبەت بە پێستی منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان\r\n• پاراستنی بەهێز (SPF 50): ڕێگرییەکی زۆر باش دەکات لە تیشکی زیانبەخشی خۆر (UVA و UVB).\r\n• تایبەتمەندی Wet Skin: ئەمە گرنگترین خاڵیەتی؛ دەتوانیت ڕاستەوخۆ لەسەر پێستی تەڕ بەکاری بهێنیت (بۆ نموونە دوای مەلەکردن) بێ ئەوەی پێویست بکات پێستەکە وشک بکەیتەوە، و هیچ شوێنەوارێکی سپی جێناهێڵێت.\r\n• شەفاف و سووک: وەک ئاو وایە و زوو هەڵدەمژرێت، پێست چەور ناکات و نانووسێت بە جەستەوە.\r\n• بەکارهێنانی ئاسان: بە شێوەی سپرایە (Spray) و تەنانەت ئەگەر سەرەوخواریش بگریت، هەر کار دەکات، ئەمەش بۆ منداڵ کە زۆر دەجووڵێت زۆر گونجاوە.\r\nپێکهاتە و سوودە تەندروستییەکانی\r\n• بۆ پێستی هەستیار: لەژێر چاودێری پزیشکی منداڵان و پزیشکی پێست تاقیکراوەتەوە.\r\n• هێورکەرەوە: ماددەی وەک (Vitamin E) و پێکهاتەی تێدایە کە پێستی منداڵەکە لە سووتان و سووربوونەوە دەپارێزێت و ئارامی دەکاتەوە.\r\n• بێ کحول: زۆربەی بەرهەمە \"پیدیاتریکەکان\"ی ئەم براندە هەوڵ دەدەن کەمترین ماددەی کیمیایی زیانبەخشیان تێدابێت.\r\nچۆنیەتی بەکارهێنان\r\n1. پێش چوونە بەر خۆر: نزیکەی ٢٠ خولەک پێشتر بیدە لە جەستەی منداڵەکە.\r\n2. دووبارەکردنەوە: هەموو ٢ کاتژمێر جارێک یان دوای هەر مەلەکردن و ئارەقکردنەوەیەکی زۆر، دووبارە بەکاری بهێنەرەوە.\r\n3. دوورکەوتنەوە لە دەموچاو: ڕاستەوخۆ مەیڕژێنە بە دەموچاویدا؛ سەرەتا بیدە لە دەستت و پاشان بە هێواشی بیدە لە دەموچاوی (دوور لە چاوەکانی).\r\nتێبینی: باشترە بۆ منداڵی سروشت سەروو ٣ ساڵ بەکاربێت (چونکە سپرایە)، بەڵام براندەکە بە گشتی بۆ پێستی منداڵان دروستی کردووە.\r\n','Key Features\n• Strong protection (SPF 50): Excellent protection against harmful sun rays (UVA and UVB).\n• Wet Skin Feature: This is the most important point; You can use it directly on wet skin (e.g. after swimming) without having to dry the skin, and it doesn’t leave any white traces.\n• Transparent and lightweight: Water-like and quickly absorbed, does not grease the skin and does not write to the body.\n• Easy to use: Sprayable and works even if you hold it upside down, which is ideal for children who move a lot.\nIngredients and health benefits\n• For sensitive skin: Tested under the supervision of a pediatrician and dermatologist.\n• Soothing: Contains substances such as vitamin E and ingredients that protect and soothe the child\'s skin from burns and redness.\n• Alcohol free: Most of the brand’s “pediatric” products try to contain as few harmful chemicals as possible.\nHow to use\n1. Before going out in the sun: Apply about 20 minutes before.\n2. Repeat: Reapply every 2 hours or after any swimming and excessive sweating.\n3. Avoid the face: Do not spray directly into the face; Apply it to your hand first and then gently to his face (away from his eyes).\nNote: It is best used for natural children over 3 years old (because it is a spray), but the brand is generally formulated for children\'s skin.','الميزات الرئيسية\n• حماية قوية (SPF 50): حماية ممتازة من أشعة الشمس الضارة (UVA وUVB).\n• مناسب للبشرة الرطبة: هذه هي الميزة الأهم؛ يمكنكِ استخدامه مباشرةً على البشرة الرطبة (مثلاً بعد السباحة) دون الحاجة إلى تجفيفها، ولا يترك أي أثر أبيض.\n• شفاف وخفيف الوزن: قوامه كالماء وسريع الامتصاص، لا يترك أثراً دهنياً على البشرة ولا يلتصق بالجسم.\n• سهل الاستخدام: بخاخ يعمل حتى عند قلبه رأساً على عقب، مما يجعله مثالياً للأطفال كثيري الحركة.\n• مناسب للبشرة الحساسة: تم اختباره تحت إشراف طبيب أطفال وطبيب جلدية.\n• مُلطف: يحتوي على مواد مثل فيتامين E ومكونات تحمي بشرة الطفل وتلطفها من الحروق والاحمرار.\n• خالٍ من الكحول: تحرص معظم منتجات العلامة التجارية المخصصة للأطفال على تقليل المواد الكيميائية الضارة قدر الإمكان.\n\nطريقة الاستخدام\n1. قبل الخروج في الشمس: يُوضع قبل حوالي 20 دقيقة.\n٢. التكرار: يُعاد استخدامه كل ساعتين أو بعد السباحة أو التعرق الشديد.\n٣. تجنب ملامسة الوجه: لا ترش المنتج مباشرة على الوجه؛ ضعه على يدك أولاً ثم وزعه برفق على وجه الطفل (بعيدًا عن عينيه).\n\nملاحظة: يُفضل استخدامه للأطفال الذين تزيد أعمارهم عن ٣ سنوات (لأنه بخاخ)، ولكن تركيبة هذا المنتج مصممة خصيصًا لبشرة الأطفال.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:36:06',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-63',0,0),(200,'فلود(شلە)ی شێدارکەرەوەی تایبەت بە پێستی هەستیار و ناسک لە بڕاندی بابێی ئیسپانی','Moisturizing fluid for sensitive and delicate skin from Spanish brand Babe','سائل مرطب للبشرة الحساسة والرقيقة من ماركة Babe الإسبانية','فلود(شلە)ی شێدارکەرەوەی تایبەت بە پێستی هەستیار و ناسک لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• شێدارکردنەوەی قووڵ: یارمەتی شێدارکردنەوەی پێست دەدات و بۆ ماوەیەکی درێژ بە نەرمی دەیهێڵێتەوە.\r\n• هێورکەرەوە (Calming): بەهۆی پێکهاتەکانی وەک ڕۆنی جۆجۆبا (Jojoba Oil)، یارمەتی کەمکردنەوەی سووتانەوە و خوران و هەستیاری پێست دەدات.\r\n• پاراستنی پێست: بەرگری سروشتی پێست بەهێز دەکات دژی کاریگەرییە دەرەکییەکان.\r\n• مژینی خێرا: پێکهاتەکەی سووکە و زوو بە پێستەوە دەمژرێت بێ ئەوەی هەست بە چەوری بکەیت.\r\nپێکهاتە گرنگەکان:\r\n• ڕۆنی جۆجۆبا: پێست نەرم دەکات و هێزی پێ دەبەخشێت.\r\n• کۆمپلێکسی هێورکەرەوەی بابێ: تێکەڵەیەکی تایبەتە بۆ ئارامکردنەوەی پێستە زۆر هەستیارەکان.\r\n• کەرەی شیا (Shea Butter): بۆ نوێکردنەوە و پاراستنی شێی ناو پێست.\r\n• شێوازی بەکارهێنان: ڕۆژانە دوای خۆشۆردن یان هەر کاتێک هەستت بە وشکی پێست کرد، بڕێکی گونجاو بدە لە جەستەت و بە نەرمی مەساجی پێ بکە تا دەمژرێت.\r\n','Key Features:\n• Deep Moisturizing: Helps hydrate skin and keeps it soft for long periods of time.\n• Calming: Due to ingredients such as jojoba oil, it helps reduce burning, itching and skin sensitivity.\n• Skin Protection: Strengthens the skin’s natural defenses against external influences.\n• Fast absorption: The texture is lightweight and absorbs quickly into the skin without feeling greasy.\nImportant Ingredients:\n• Jojoba oil: Softens and strengthens the skin.\n• Babe Soothing Complex: A special blend to soothe hypersensitive skins.\n• Shea Butter: To renew and maintain moisture in the skin.\n• How to use: Apply an appropriate amount daily after bathing or whenever you feel dry skin and massage gently until absorbed.','الميزات الرئيسية:\n• ترطيب عميق: يساعد على ترطيب البشرة والحفاظ على نعومتها لفترات طويلة.\n• تهدئة: بفضل مكونات مثل زيت الجوجوبا، يساعد على تخفيف الحرقان والحكة وحساسية البشرة.\n• حماية البشرة: يقوي دفاعات البشرة الطبيعية ضد المؤثرات الخارجية.\n• امتصاص سريع: قوامه خفيف ويمتصه الجلد بسرعة دون ترك أي ملمس دهني.\n\n• المكونات الهامة:\n• زيت الجوجوبا: ينعم البشرة ويقويها.\n• مركب بيبي المهدئ: مزيج خاص لتهدئة البشرة شديدة الحساسية.\n• زبدة الشيا: لتجديد ترطيب البشرة والحفاظ عليه.\n\n• طريقة الاستخدام: ضعي كمية مناسبة يوميًا بعد الاستحمام أو عند الشعور بجفاف البشرة، ودلكي بلطف حتى يتم امتصاصه.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:37:29',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'500ml','01-62',0,0),(201,'پاکەرەوەی زەیتی تایبەت بە پێستی وشک و هەستیار لە بڕاندی بابێی ئیسپانی','Oil Cleanser for Dry and Sensitive Skin from Spanish brand Babe','منظف ​​زيتي للبشرة الجافة والحساسة من ماركة Babe الإسبانية','پاکەرەوەی زەیتی تایبەت بە پێستی وشک و هەستیار لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• جۆری پێست: تایبەت دروستکراوە بۆ پێستی زۆر وشک یان ئەو پێستانەی تووشی ئەتۆپیک (Atopic) دەبن (وەک ئەکزیما و خوران).\r\n• پێکهاتەی Syndet: ئەمە بەرهەمێکی بێ سابوونە (Soap-free)، واتە بە شێوەیەکی زۆر نەرم پێست پاک دەکاتەوە بەبێ ئەوەی چەورییە سروشتییەکانی پێست لەناو ببات یان بیووشکێنێت.\r\n• پێکهاتە دەوڵەمەندەکان: ڕێژەی زیاتر لە ٤٠٪ لە زەیتی ڕوەکی تێدایە، لەگەڵ ئۆمیگا ٣، ٦ و ٩ کە یارمەتی دووبارە دروستکردنەوەی چینی پارێزەری پێست دەدەن.\r\n٢. سوودەکانی ئەم سابوونە زەیتییە:\r\n• شێدارکەرەوەی بەهێز: بەهۆی ڕێژە زۆرەکەی زەیتەوە، ڕێگری دەکات لە وشکبوونەوەی پێست دوای خۆشتن.\r\n• هێورکەرەوە: یارمەتی کەمکردنەوەی خوران و سووربوونەوەی پێست دەدات.\r\n• پاراستن: بەربەستێکی سروشتی بۆ پێست دروست دەکات دژی کاریگەرییە دەرەکییەکان.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• لەکاتی خۆشتندا بڕێکی گونجاو بدە لە پێستی تەڕ.\r\n• بە هێواشی مەساجی پێ بکە و پاشان بە ئاوێکی زۆر بیشۆ.\r\n• تێبینی: بەهۆی زەیتەکەیەوە، ڕەنگە زەوی حەمامەکە کەمێک خلیسک بکات، بۆیە وریابە.\r\n','. . . . Key Features:\n• Skin type: Specially formulated for very dry or atopic skin (such as eczema and itching).\n• Syndet Ingredients: This is a soap-free product, which means it cleanses the skin very gently without destroying or breaking down the skin\'s natural oils.\n• Rich Ingredients: Contains more than 40% vegetable oil, with Omega 3, 6 and 9 that help rebuild the skin’s protective layer.\n2. Benefits of this oil soap:\n• Powerful moisturizer: Due to its high oil content, it prevents skin from drying out after washing.\n• Soothing: Helps reduce itching and redness of the skin.\n• Protection: Creates a natural barrier for the skin against external influences.\n3. How to use:\n• Apply an appropriate amount to wet skin during bathing.\n• Massage gently and then rinse with plenty of water.\n• Note: Because of the oil, the bathroom floor may be a little slippery, so be careful.','الميزات الرئيسية:\n• نوع البشرة: تركيبة خاصة للبشرة شديدة الجفاف أو المصابة بالتهاب الجلد التأتبي (مثل الأكزيما والحكة).\n• مكونات نباتية: منتج خالٍ من الصابون، مما يعني أنه ينظف البشرة بلطف شديد دون إزالة الزيوت الطبيعية منها.\n• مكونات غنية: يحتوي على أكثر من 40% من الزيوت النباتية، مع أحماض أوميغا 3 و6 و9 التي تساعد على إعادة بناء الطبقة الواقية للبشرة.\n\n2. فوائد هذا الصابون الزيتي:\n• مرطب قوي: بفضل محتواه العالي من الزيوت، يمنع جفاف البشرة بعد الغسل.\n• مهدئ: يساعد على تخفيف الحكة والاحمرار.\n• حماية: يشكل حاجزًا طبيعيًا للبشرة ضد المؤثرات الخارجية.\n\n3. طريقة الاستخدام:\n• ضعي كمية مناسبة على بشرة مبللة أثناء الاستحمام.\n• دلكي بلطف ثم اشطفي جيدًا بالماء.\n• ملاحظة: قد يكون أرضية الحمام زلقة بعض الشيء بسبب الزيت، لذا كوني حذرة.',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:38:45',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'500ml','01-61',0,0),(202,'شێدارکەرەوەی شیری تایبەت بە پێستی منداڵان لە بڕاندی بابێی ئیسپانی','Milk moisturizer for children\'s skin from the Spanish brand Babe','مرطب حليبي لبشرة الأطفال من ماركة Babe الإسبانية','شێدارکەرەوەی شیری تایبەت بە پێستی منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• بەکارهێنان: بۆ شێدارکردنەوە، نەرمکردن و پاراستنی پێستی ناسکی منداڵان و ساوایان بەکاردێت.\r\n• پشکنینی پزیشکی: لەلایەن پزیشکانی منداڵان و پزیشکانی پێستەوە پشکنینی بۆ کراوە (Pediatrically Tested).\r\n٢. پێکهاتە گرنگەکان:\r\nبەپێی ئەوەی لەسەر پشتی بوتڵەکە نووسراوە، ئەم ماددانەی تێدایە:\r\n• کۆمپلێکسی چاودێری ساوا (Baby-care Complex): پێکهاتوە لە (کالێندۆلا، میمۆزا، ئالۆڤێرا) کە یارمەتی هێورکردنەوەی پێست دەدەن.\r\n• کۆکۆم باتەر (Kokum Butter): بۆ شێدارکردنەوەیەکی قووڵ و پاراستنی بەربەستی پێست.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست دەپارێزێت.\r\n٣. سوودەکانی:\r\n• بە خێرایی هەڵدەمژرێت و هەستی چەوری بەجێناهێڵێت.\r\n• پێست زۆر نەرم دەکات و ڕێگری دەکات لە وشکبوونەوە.\r\n• بۆ ئەو منداڵانەی پێستیان هەستیارە زۆر گونجاوە.\r\n٤. چۆنیەتی بەکارهێنان:\r\nڕۆژانە بڕێکی گونجاو بدە لە پێستی پاک و وشکی منداڵەکە و بە هێواشی مەساژی بۆ بکە تا پێستەکە هەڵی دەمژێت.\r\n','. . . . Key Features:\n• Usage: Used to moisturize, soften and protect the delicate skin of children and infants.\n• Medical Examination: Pediatrically Tested by Pediatricians and Dermatologists.\n2. Important Ingredients:\nAccording to the label on the back of the bottle, it contains:\n• Baby-care Complex: Contains calendula, mimosa, aloe vera that help soothe the skin.\n• Kokum Butter: For deep moisturizing and skin barrier protection.\n• Vitamin E: Acts as an antioxidant and protects the skin.\n3. Benefits:\n• Absorbs quickly and does not leave a greasy feeling.\n• Very soft skin and prevents dryness.\n• Ideal for children with sensitive skin.\n4. How to use:\nApply an appropriate amount daily to clean, dry skin and gently massage until skin absorbs.','الميزات الرئيسية:\n• الاستخدام: يُستخدم لترطيب وتنعيم وحماية بشرة الأطفال والرضع الحساسة.\n• الفحص الطبي: تم اختباره من قبل أطباء الأطفال وأطباء الجلدية.\n\n٢. المكونات الهامة:\nوفقًا للملصق الموجود على ظهر العبوة، يحتوي على:\n• مركب العناية بالأطفال: يحتوي على الكاليندولا والميموزا والصبار، التي تساعد على تهدئة البشرة.\n• زبدة الكوكوم: لترطيب عميق وحماية حاجز البشرة.\n• فيتامين هـ: يعمل كمضاد للأكسدة ويحمي البشرة.\n\n٣. الفوائد:\n• يمتص بسرعة ولا يترك ملمسًا دهنيًا.\n• بشرة ناعمة جدًا ويمنع الجفاف.\n• مثالي للأطفال ذوي البشرة الحساسة.\n\n٤. طريقة الاستخدام:\nضعي كمية مناسبة يوميًا على بشرة نظيفة وجافة، ودلكيها بلطف حتى تمتصها البشرة.',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:40:38',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'500ml','01-60',0,0),(203,'پاکەرەوەی تایبەت بە پێستی جەستەی منداڵان لە بڕاندی بابێی ئیسپانی','Children\'s body skin cleanser from Spanish brand Babe','منظف ​​بشرة الجسم للأطفال من ماركة Babe الإسبانية','پاکەرەوەی تایبەت بە پێستی جەستەی منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاککەرەوەیەکی نەرم: پێستی منداڵ بە هێمنی پاک دەکاتەوە بەبێ ئەوەی ببێتە هۆی وشکبوونەوە یان خوران.\r\n• ناسووتێنێت: بە جۆرێک دروستکراوە کە چاوەکان ناهورژێنێت و نایانستوێنێت.\r\n• پارێزگاری لە شێداری دەکات: پارێزگاری لە نەرمی و هاوسەنگی سروشتی پێست دەکات.\r\n• بەکارهێنانی ڕۆژانە: گونجاوە بۆ شۆردنی ڕۆژانەی منداڵ لە کاتی گەرماوکردن.\r\nپێکهاتە گرنگەکان (بەپێی پشتی بوتڵەکە):\r\nئەم جێڵە \"کۆمپلێکسی چاودێری منداڵ\" (Baby-care Complex) تێدایە کە ڕێژەی 0.50% لەمانەی خوارەوە پێکدێت:\r\n1. گوڵە بەیبوون (Calendula): بۆ هێورکردنەوەی پێست.\r\n2. میمۆزا (Mimosa): یارمەتی چاکبوونەوە و پاراستنی پێست دەدات.\r\n3. ئەلۆڤێرا (Aloe Vera): بۆ شێدارکردنەوەی پێست.\r\n• باری تەندروستی: لەلایەن پزیشکانی منداڵ و پزیشکانی پێستەوە تاقیکراوەتەوە.\r\nتێبینی:  \"Syndet\"ـە، واتە بەکارهێنانی سابوونی تێدا نییە و زیاتر پشت بە پاککەرەوەی دەستکردی نەرم دەبەستێت کە بۆ پێستی هەستیار گونجاوترە\r\n','Key Features:\n• Gentle cleanser: Gently cleanses baby’s skin without causing dryness or irritation.\n• Does not burn: It is designed not to irritate or burn the eyes.\n• Maintains moisture: Maintains skin\'s natural softness and balance.\n• Daily use: Suitable for daily bath washing.\nImportant ingredients (depending on the back of the bottle):\nThis gel contains 0.50% Baby-care Complex:\n1. Calendula: To soothe the skin.\n2. Mimosa: Helps heal and protect the skin.\n3. Aloe Vera: To moisturize the skin.\n• Health status: Tested by pediatricians and dermatologists.\nNote: It is Syndet, which means it does not use soap and relies more on gentle synthetic cleansers that are more suitable for sensitive skin','الميزات الرئيسية:\n• منظف لطيف: ينظف بشرة الطفل بلطف دون التسبب في جفاف أو تهيج.\n• لا يسبب حرقان: مصمم خصيصًا لعدم تهيج أو حرق العينين.\n• يحافظ على ترطيب البشرة: يحافظ على نعومة البشرة الطبيعية وتوازنها.\n• للاستخدام اليومي: مناسب للاستحمام اليومي.\nالمكونات الهامة (حسب ما هو مدون على ظهر العبوة):\nيحتوي هذا الجل على 0.50% من مركب العناية بالطفل:\n1. آذريون: لتهدئة البشرة.\n2. ميموزا: تساعد على شفاء البشرة وحمايتها.\n3. صبار: لترطيب البشرة.\n• مناسب للاستخدام الصحي: تم اختباره من قبل أطباء الأطفال وأطباء الجلدية.\n\nملاحظة: هذا المنتج من نوع Syndet، أي أنه لا يحتوي على الصابون ويعتمد بشكل أكبر على منظفات صناعية لطيفة مناسبة للبشرة الحساسة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:41:58',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'500ml','01-59',0,0),(204,'ئاوی میسێلار تایبەت بە پاکردنەوەی دەم چاو و لابردنی مکیاژ لە بڕاندی بابێی ئیسپانی','Micellar water for cleansing the face and eyes and removing makeup from the Spanish brand Babe','ماء ميسيلار لتنظيف الوجه والعينين وإزالة المكياج من ماركة Babe الإسبانية','ئاوی میسێلار تایبەت بە پاکردنەوەی دەم چاو و لابردنی مکیاژ لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. تایبەتمەندییە گرنگەکان\r\n• پاککردنەوەی قووڵ: یارمەتی لێکردنەوەی مکیاژ و پیسی سەر پێست دەدات بەبێ ئەوەی پێستەکە زۆر وشک بکاتەوە.\r\n• بۆ هەموو جۆرە پێستێک: گونجاوە بۆ هەموو جۆرەکانی پێست، تەنانەت پێستی هەستیاریش (Sensitive Skin).\r\n• پێکهاتەی سروشتی: لەسەر بوتڵەکە نووسراوە کە %٩٧ی پێکهاتەکانی لە سەرچاوەی سروشتییەوە وەرگیراون.\r\n• Prebiotic Active: ماددەی \"پریبایۆتیک\"ی تێدایە کە یارمەتی پاراستنی هاوسەنگی بەکتریا سوودبەخشەکانی سەر پێست دەدات و بەرگری پێست بەهێز دەکات.\r\n٢. سوودەکانی بەکارهێنانی\r\n• بێ پێویستی بە شتن: دەتوانیت بۆ پاککردنەوەی دەموچاو بەکاری بهێنیت بەبێ ئەوەی دواتر پێویستت بە ئاو شتن بێت (هەرچەندە زۆرێک لە پزیشکانی پێست پێیان باشە دوای ئەوە بە ئاوێکی شلەتێن دەموچاو بشۆردرێت).\r\n• نەرمکەرەوە: ماددەی وەکو Betaine و Aloe Veraی تێدایە کە پێست نەرم دەکەن و سووتانەوەی کەمدەکەنەوە.\r\n• بۆ چاو و لێو: چونکە ماددەی عەتری تێدا نییە و تاقیکردنەوەی پزیشکی بۆ کراوە، دەتوانرێت بۆ لێکردنەوەی مکیاژی چاو و لێویش بەکاربێت.\r\n٣. چۆنیەتی بەکارهێنان\r\n١. بڕێکی گونجاو لە ئاوەکە بکەرە سەر لۆکەیەکی پاک.\r\n٢. بە هێواشی بەسەر دەموچاو، چاو و لێوتدا بیهێنە تا پیسی و مکیاژەکە لێدەبێتەوە.\r\n٣. پێویست بەوە ناکات زۆر بە توندی لۆکەکە بخشێنیت بە پێستتدا.\r\n','Important Features\n• Deep cleansing: Helps remove makeup and dirt without drying the skin too much.\n• For all skin types: Suitable for all skin types, even sensitive skin.\n• Natural ingredients: The bottle says that 97% of the ingredients are derived from natural sources.\n• Prebiotic Active: Contains prebiotics that help maintain the balance of beneficial bacteria on the skin and strengthen the skin\'s immune system.\n2. Benefits of its use\n• No need for rinsing: You can use it to cleanse your face without having to rinse with water afterwards (although many dermatologists prefer to wash your face with lukewarm water afterwards).\n• Softener: Contains ingredients such as Betaine and Aloe Vera that soften the skin and reduce burns.\n• For eyes and lips: Because it does not contain perfume and has been clinically tested, it can also be used to remove eye and lip makeup.\n3. How to use\n1. Apply the appropriate amount of water to a clean cloth.\n2. Gently apply to face, eyes and lips to remove dirt and makeup.\n3. You don\'t have to apply the cloth too tightly to your skin.',' أهم الميزات\n• تنظيف عميق: يساعد على إزالة المكياج والأوساخ دون تجفيف البشرة بشكل مفرط.\n• مناسب لجميع أنواع البشرة: مناسب لجميع أنواع البشرة، حتى البشرة الحساسة.\n• مكونات طبيعية: تشير العبوة إلى أن 97% من المكونات مشتقة من مصادر طبيعية.\n• مكونات حيوية فعّالة: يحتوي على البريبايوتكس التي تساعد على الحفاظ على توازن البكتيريا النافعة على البشرة وتقوية جهاز المناعة.\n\nفوائد الاستخدام\n• لا حاجة للشطف: يمكنكِ استخدامه لتنظيف وجهكِ دون الحاجة إلى شطفه بالماء بعد ذلك (مع أن العديد من أطباء الجلدية يفضلون غسل الوجه بالماء الفاتر بعد ذلك).\n• مُرطّب: ​​يحتوي على مكونات مثل البيتايين والصبار التي تُنعّم البشرة وتُخفف الحروق.\n• للعينين والشفاه: لأنه خالٍ من العطور وخضع لاختبارات سريرية، يمكن استخدامه أيضًا لإزالة مكياج العينين والشفاه.\n\nطريقة الاستخدام\n1. بللي قطعة قماش نظيفة بكمية مناسبة من الماء.\n٢. ضعيه برفق على الوجه والعينين والشفتين لإزالة الأوساخ والمكياج.\n٣. لا داعي لشدّ قطعة القماش على بشرتكِ بشدة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:43:25',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'400ml','01-58',0,0),(205,'پاکەرەوەی دەم و چاوی تایبەت بە پێستی ئاسایی لە بڕاندی بابێی ئیسپانی','Face cleanser for normal skin from Spanish brand Babe','غسول للوجه للبشرة العادية من ماركة Babe الإسبانية','پاکەرەوەی دەم و چاوی تایبەت بە پێستی ئاسایی لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاککەرەوەیەکی نەرم (Syndet): ئەم جێڵە لە جۆری \"Syndet\"ە، واتە سابوونی تێدا نییە. ئەمەش وادەکات زۆر نەرم بێت و سروشتی پێست تێکنەدا.\r\n• بۆ پێستی هەستیار: بە تایبەتی بۆ ئەو کەسانە دروستکراوە کە پێستیان هەستیارە یان بەهۆی بەکارهێنانی دەرمانی زیپکەوە پێستیان تووشی وشکبوونەوە و سوتانەوە بووە.\r\n• تەکنەلۆژیای میسێلار (Micellar): یارمەتیدەرە بۆ لادانی ماکیاژ، تەپوتۆز و چەوری زیادەی پێست بەبێ ئەوەی پێویست بە لێخشاندنی زۆر بکات.\r\nسوودەکانی:\r\n• شێدارکردنەوە: بەهۆی هەبوونی ماددەی گلیسرین (Glycerin) و بێتایین (Betaine)، پێست بە شێداری دەهێڵێتەوە و ناهێڵێت وشک ببێتەوە.\r\n• هێورکەرەوە: ماددەی Licorice (سۆس)ی تێدایە کە یارمەتی کەمکردنەوەی سووربوونەوە و هێورکردنەوەی پێست دەدات.\r\n• هاوسەنگی pH: پلەی ترشێتییەکەی (pH 5.5)ە، کە هاوسەنگە لەگەڵ پلەی سروشتی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n1. بڕێکی گونجاو بدە لە پێستت (کە کەمێک تەڕ بێت).\r\n2. بە شێوەی بازنەیی مەساجی پێ بکە تا کەفێکی کەم دروست دەکات.\r\n3. پاشان بە ئاوێکی شلەتێن بە باشی ڕوخسارت بشۆ.\r\n4. دەتوانیت بەیانیان و شەوان بەکاری بهێنیت.\r\n','Key Features:\n• Gentle cleanser (Syndet): This gel is of the \"Syndet\" type, meaning it does not contain soap. This makes it very gentle and does not disturb the nature of the skin.\n• For Sensitive Skin: Especially formulated for people with sensitive skin or dryness and burning sensation due to the use of acne medication.\n• Micellar technology: Helps remove makeup, dust and excess skin oil without excessive exfoliation.\nBenefits:\n• Moisturizing: Due to the presence of glycerin and betaine, it keeps the skin moisturized and prevents dryness.\n• Soothing: Contains licorice (sauce) to help reduce redness and soothe the skin.\n• pH balance: Its acidity is (pH 5.5), which is in balance with the skin’s natural temperature.\nHow to use:\n1. Apply an appropriate amount to your skin (which is slightly damp).\n2. Massage in circular motions until a slight lather forms.\n3. Then rinse thoroughly with lukewarm water.\n4. You can use it in the morning and at night.','الميزات الرئيسية:\n• منظف لطيف (ساينديت): هذا الجل من نوع \"ساينديت\"، أي أنه خالٍ من الصابون. وهذا ما يجعله لطيفًا جدًا ولا يُخلّ بتوازن البشرة.\n• للبشرة الحساسة: تركيبة خاصة للأشخاص ذوي البشرة الحساسة أو الذين يعانون من الجفاف والشعور بالحرقان نتيجة استخدام أدوية حب الشباب.\n• تقنية الميسيلار: تساعد على إزالة المكياج والغبار والزيوت الزائدة دون تقشير مفرط.\n\n• فوائد:\n• ترطيب: بفضل احتوائه على الجلسرين والبيتين، يحافظ على ترطيب البشرة ويمنع جفافها.\n• تهدئة: يحتوي على عرق السوس (الصلصة) للمساعدة في تقليل الاحمرار وتهدئة البشرة.\n• توازن درجة الحموضة: درجة حموضته 5.5، وهي متوازنة مع درجة حرارة البشرة الطبيعية.\n\nطريقة الاستخدام:\n1. ضعي كمية مناسبة على بشرتكِ (الرطبة قليلًا).\n2. دلكي بحركات دائرية حتى تتكون رغوة خفيفة.\n\nللاستخدام\n ٣. ثم اشطف جيداً بالماء الفاتر.\n٤. يمكنك استخدامه صباحاً ومساءً.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:44:53',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'240ml','01-57',0,0),(206,'جێلی تایبەت بە ئارامکەرەوە و شێدارکەرەوەی پێست لە بڕاندی بابێی ئیسپانی','Soothing and moisturizing gel from Spanish brand Babe','جل مهدئ ومرطب من ماركة Babe الإسبانية',' جێلی تایبەت بە ئارامکەرەوە و شێدارکەرەوەی پێست لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سەرەکی: ڕێژەیەکی بەرز لە ئەلوڤێرا (سەبڕ) و گوڵە بەیبوون (Chamomile) تێدایە.\r\n• جۆری پێست: بۆ هەموو جۆرە پێستەکان گونجاوە.\r\n• کارکردن: پێست سارد دەکاتەوە، شێداری دەکات و ئەو سووربوونەوە و هەستیارییەی کە بەهۆی وشکی یان دەرەنجامی تر دروست بووە، نایهێڵێت.\r\n• تایبەتمەندی: جێڵێکی سووکە و چەور نییە، زوو بە پێستدا دەچێت و هەستی لکاو دروست ناکات.\r\nکەی بەکاردێت؟\r\nئەم جێڵە لە چەند کاتێکی جیاوازدا زۆر بەسوودە:\r\n1. دوای بەرکەوتنی خۆر: بۆ هێورکردنەوەی ئەو پێستانەی بەهۆی خۆرەوە سوتاون یان سوور بوونەتەوە.\r\n2. دوای لادانی موو: دوای بەکارهێنانی تێغ یان هەر ڕێگەیەکی تری لادانی موو، بۆ ڕێگری لە خوران و سووربوونەوە.\r\n3. دوای حەمام: وەک شێدارکەرەوەیەک بۆ ڕێگری لە وشکبوونەوەی پێستی جەستە.\r\n4. دوای لیزەر: زۆرجار پزیشکان پێشنیاری دەکەن بۆ ئارامکردنەوەی پێست دوای جەلسەکانی لیزەر.\r\nچۆنییەتی بەکارهێنان:\r\n• بڕێکی گونجاو بدە لەو شوێنەی کە پێویستییەتی (دەموچاو یان جەستە).\r\n• بە نەرمی مەساجی پێ بکە تا بەتەواوی لەلایەن پێستەوە دەهێنرێتە ناوەوە.\r\n• دەتوانیت چەند جارێک لە ڕۆژێکدا بەکاری بهێنیتەوە بەپێی پێویست.','Key Features:\n• Main ingredients: High in aloe vera and chamomile.\n• Skin type: Suitable for all skin types.\n• Action: Cools, moisturizes and relieves redness and sensitivity caused by dryness or other consequences.\n• Features: Lightweight, non-greasy gel, absorbs quickly into the skin and does not create a sticky feeling.\nWhen is it used?\nThis gel is very useful at different times:\n1. After sun exposure: To soothe sunburned or red skin.\n2. After hair removal: After using a blade or any other method of hair removal, to prevent itching and redness.\n3. After bath: As a moisturizer to prevent dry skin.\n4. After laser: Doctors often recommend it to soothe the skin after laser sessions.\nHow to use:\n• Apply appropriate amount where needed (face or body).\n• Massage gently until completely absorbed by the skin.\n• You can reapply as many times a day as needed.','الميزات الرئيسية:\n• المكونات الرئيسية: غني بالألوفيرا والبابونج.\n• نوع البشرة: مناسب لجميع أنواع البشرة.\n• المفعول: يُلطّف البشرة، يُرطّبها، ويُخفّف الاحمرار والحساسية الناتجة عن الجفاف أو غيره.\n• المميزات: جل خفيف الوزن، غير دهني، يمتصه الجلد بسرعة ولا يترك شعورًا لزجًا.\n\nمتى يُستخدم؟\nيُعدّ هذا الجل مفيدًا جدًا في أوقات مختلفة:\n1. بعد التعرّض للشمس: لتهدئة البشرة المُصابة بحروق الشمس أو الاحمرار.\n2. بعد إزالة الشعر: بعد استخدام الشفرة أو أي طريقة أخرى لإزالة الشعر، لمنع الحكة والاحمرار.\n3. بعد الاستحمام: كمرطب لمنع جفاف البشرة.\n4. بعد الليزر: غالبًا ما ينصح به الأطباء لتهدئة البشرة بعد جلسات الليزر.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة على المنطقة المطلوبة (الوجه أو الجسم).\n• دلّكي بلطف حتى يمتصه الجلد تمامًا.\n• يُمكنكِ إعادة استخدامه عدة مرات في اليوم حسب الحاجة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:47:49',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'395ml','01-56',0,0),(207,'ئاوی میسێلار تایبەت بە پاکردنەوەی ڕۆژانەی دەم و چاو لە بڕاندی بابێی ئیسپانی','Micellar Daily Face and Eye Cleanser from Spanish brand Babe','غسول ميسيلار يومي للوجه والعينين من ماركة Babe الإسبانية','ئاوی میسێلار تایبەت بە پاکردنەوەی ڕۆژانەی دەم و چاو لە بڕاندی بابێی ئیسپانی ',15,20000,29750,4750,1,'تایبەتمەندییە گرنگەکان:\r\n• پاککەرەوەی سێ لە یەکدا: کاری پاککردنەوە، لادانی ماکیاژ، و شێدارکردنەوەی پێست پێکەوە دەکات.\r\n• بۆ کێ دەست دەدات؟ بۆ هەموو جۆرە پێستێک گونجاوە، تەنانەت پێستی زۆر هەستیار.\r\n• پێکهاتەی سروشتی: ۹۷٪ ی پێکهاتەکانی لە سەرچاوەی سروشتییەوە وەرگیراون.\r\n• بەکارهێنانی ئاسان: پێویستی بە تێپەڕاندنی ئاو نییە (واتا دوای بەکارهێنانی مەرج نییە دەموچاوت بە ئاو بشۆیت).\r\nپێکهاتە سەرەکییەکانی:\r\n• Prebiotic Active (۱٪): یارمەتی هاوسەنگکردنی بەکتریای سوودبەخشی سەر پێست دەدات و بەرگری پێست بەهێز دەکات.\r\n• Betaine (۱٪): پێست شێدار دەکات و نایەڵێت وشک ببێتەوە.\r\n• Soothing Complex (۰.۲٥٪): تێکەڵەیەکە لە بەیبوون و ئالۆڤێرا کە پێست هێمن دەکەنەوە و سووربوونەوە ناهێڵن.\r\nسوودەکانی:\r\n۱. بۆ چاو و لێو: زۆر بێ زیانە بۆ لادانی ماکیاژی چاو و لێو چونکە لەلایەن پزیشکی چاوەوە تاقیکراوەتەوە.\r\n۲. بێ بۆن: هیچ بۆنێکی دەستکردی تێدا نییە (Fragrance-free)، ئەمەش وای کردووە بۆ پێستی هەستیار بێ کێشە بێت.\r\n۳. تایبەتمەندی pH: ئاستی ترشێتییەکەی pH 6.5 ە، کە زۆر نزیکە لە فرمێسکی چاو بۆ ئەوەی چاو نەکزێنێتەوە.\r\nچۆنیەتی بەکارهێنان:\r\nپارچەیەک لۆکە (Cotton pad) بە ئاوەکە تەڕ بکە، پاشان بە نەرمی بیدە لە دەموچاو، مل، و چاوەکانت بۆ لادانی پیسی و ماکیاژ. بەیانیان و شەوان دەتوانیت بەکاری بهێنیت.\r\n','Important Features:\n• Three-in-one cleanser: combines cleansing, makeup removal, and moisturizing.\n• Who does it reach out to? Suitable for all skin types, even very sensitive skin.\n• Natural ingredients: 97% of ingredients are derived from natural sources.\n• Easy to use: No need to pass water (i.e. you don’t have to wash your face with water after use).\nKey ingredients:\n• Prebiotic Active (1%): Helps balance beneficial bacteria on the skin and strengthens the skin\'s immune system.\n• Betaine (1%): Moisturizes the skin and prevents it from drying out.\n• Soothing Complex (0.25%): A blend of violet and aloe vera that soothes the skin and prevents redness.\nBenefits:\n1. For eyes and lips: It is very harmless to remove eye and lip makeup because it has been tested by an ophthalmologist.\n2. Fragrance-free: No artificial fragrances (Fragrance-free), making it perfect for sensitive skin.\n3. pH Characteristics: Its acidity level is pH 6.5, which is too close to tears to not irritate the eye.\nHow to use:\nMoisten a cotton pad with the water, then gently apply to face, neck, and eyes to remove dirt and makeup. You can use it in the morning and at night.','الميزات الرئيسية:\n• منظف ثلاثي في ​​واحد: يجمع بين التنظيف، وإزالة المكياج، والترطيب.\n• مناسب لجميع أنواع البشرة، حتى البشرة الحساسة جدًا.\n• مكونات طبيعية: 97% من المكونات مشتقة من مصادر طبيعية.\n• سهل الاستخدام: لا حاجة لغسل الوجه بالماء بعد الاستخدام.\n\n• المكونات الرئيسية:\n• البريبايوتيك النشط (1%): يساعد على موازنة البكتيريا النافعة على البشرة ويقوي جهاز المناعة.\n• البيتايين (1%): يرطب البشرة ويمنع جفافها.\n• مركب مهدئ (0.25%): مزيج من البنفسج والصبار يهدئ البشرة ويمنع الاحمرار.\nالفوائد:\n\n1. للعينين والشفاه: آمن تمامًا لإزالة مكياج العينين والشفاه، حيث تم اختباره من قبل أطباء العيون. \n٢. خالٍ من العطور: خالٍ من العطور الاصطناعية، مما يجعله مثاليًا للبشرة الحساسة.\n٣. درجة الحموضة: درجة حموضته ٦.٥، وهي قريبة جدًا من درجة حموضة الدموع فلا تُسبب تهيجًا للعين.\n\nطريقة الاستخدام: بللي قطعة قطن بالماء، ثم امسحي بها الوجه والرقبة والعينين برفق لإزالة الأوساخ والمكياج. يُمكن استخدامه صباحًا ومساءً.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:49:16',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'250ml','01-55',0,0),(208,'جێلی تایبەت بە پاککردنەوەی ناوچەی هەستیاری منداڵان و ساوایان لە بڕاندی بابێی ئیسپانی','Special gel for cleaning sensitive areas of children and babies from the Spanish brand Babe','جل خاص لتنظيف المناطق الحساسة لدى الأطفال والرضع من ماركة Babe الإسبانية',' جێلی تایبەت بە پاککردنەوەی ناوچەی هەستیاری منداڵان و ساوایان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• بۆ کێ دەبێت؟ تایبەت بۆ منداڵان و ساوایان دروستکراوە (بۆ کچان و کوڕان).\r\n• هاوسەنگی pH: پلەی ترشێتی (pH)ی ئەم جێڵە گونجێنراوە لەگەڵ ناوچە هەستیارەکانی منداڵ بۆ ئەوەی ڕێگری بکات لە دروستبوونی هەوکردن و سووربوونەوە.\r\n• دژە بەکتریا و پارێزەر: پێکهاتەی \"Prebiotic Active\"ی تێدایە کە یارمەتی پاراستنی بەکتریا سوودبەخشەکانی پێست دەدات و ڕێگری لە گەشەی بەکتریای زیانبەخش دەکات.\r\n• ئارامکەرەوە: پێکهاتەی وەک کالێندولا (Calendula)، میمۆزا، و ئالۆوێرا (Aloe Vera)ی تێدایە کە پێستەکە ئارام دەکەنەوە و ڕێگری لە خوران دەکەن.\r\n٢. پێکهاتە گرنگەکانی (Ingredients):\r\n• Betaine (2.5%): بۆ شێدارکردنەوەی پێست.\r\n• Baby-Care Complex: تێکەڵەیەکی تایبەتە بۆ پاراستنی پێستی منداڵ.\r\n• Lactic Acid: بۆ پاراستنی هاوسەنگی سروشتی ناوچەکە.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• بڕێکی کەم لە جێڵەکە بدە لەو ناوچەیەی کە دەتەوێت پاکی بکەیتەوە (کە پێشتر بە ئاو تەڕ کراوە).\r\n• بە نەرمی بیشۆ و پاشان بە ئاوێکی زۆر لێی بکەرەوە.\r\n• تەنها بۆ بەکارهێنانی دەرەکییە (External Use).\r\n','Key Features:\n• Who will it be for? Specially designed for children and babies (for boys and girls).\n• pH balance: The acidity (pH) of this gel is adapted to the child\'s sensitive areas to prevent inflammation and redness.\n• Antibacterial and protective: Contains \"Prebiotic Active\" ingredients that help protect the skin\'s beneficial bacteria and prevent the growth of harmful bacteria.\n• Soothing: Contains ingredients such as calendula, mimosa, and aloe vera that soothe the skin and prevent irritation.\n2. Important Ingredients:\n• Betaine (2.5%): To moisturize the skin.\n• Baby-Care Complex: A special blend to protect baby’s skin.\n• Lactic Acid: To maintain the natural balance of the area.\n3. How to use:\n• Apply a small amount of the gel to the area you want to clean (which has already been moistened with water).\n• Rinse gently and then rinse with plenty of water.\n• For External Use Only.','الميزات الرئيسية:\n• لمن هذا المنتج؟ مصمم خصيصًا للأطفال والرضع (للأولاد والبنات).\n• توازن درجة الحموضة: تم تعديل حموضة هذا الجل لتناسب المناطق الحساسة لدى الطفل، مما يمنع الالتهاب والاحمرار.\n• مضاد للبكتيريا وواقي: يحتوي على مكونات \"بريبايوتيك نشطة\" تساعد على حماية البكتيريا النافعة للبشرة ومنع نمو البكتيريا الضارة.\n• ملطف: يحتوي على مكونات مثل الكاليندولا والميموزا والصبار، التي تلطف البشرة وتمنع تهيجها.\n\n٢. المكونات الهامة:\n• بيتايين (٢.٥٪): لترطيب البشرة.\n• مركب العناية بالطفل: مزيج خاص لحماية بشرة الطفل.\n• حمض اللاكتيك: للحفاظ على التوازن الطبيعي للمنطقة.\n\n٣. طريقة الاستخدام:\n• ضعي كمية صغيرة من الجل على المنطقة المراد تنظيفها (بعد ترطيبها بالماء).\n• اشطفي بلطف ثم اشطفي جيدًا بالماء.\n• للاستخدام الخارجي فقط.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:51:19',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-54',0,0),(209,'جێلی تایبەت بە پاککردنەوەی ناوچەی هەستیاری خانمان لە بڕاندی بابێی ئیسپانی','Women\'s sensitive area cleansing gel from the Spanish brand Babe','جل تنظيف المناطق الحساسة للنساء من ماركة Babe الإسبانية',' جێلی تایبەت بە پاککردنەوەی ناوچەی هەستیاری خانمان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی pH: ئاستی ترشێتی (pH) ئەم جێڵە 4.5ە، کە زۆر گونجاوە بۆ ناوچەی هەستیار و ڕێگری دەکات لە گەشەکردنی بەکتریا و کەڕووی زیانبەخش.\r\n• هێورکەرەوە: ماددەی وەک Aloe Vera (سەبڕ) و Chamomile (بەیبوون)ی تێدایە کە یارمەتی کەمکردنەوەی خوران و سووربوونەوە دەدەن.\r\n• دژە بۆن: ماددەی دژە بۆنی تێدایە بۆ ڕێگریکردن لە دروستبوونی بۆنی ناخۆش بەبێ ئەوەی ببێتە هۆی هەستیاری.\r\n• پشکنینی پزیشکی: لەلایەن پزیشکانی پسپۆڕی ئافرەتانەوە پشکنی بۆ کراوە (Gynecologically Tested).\r\nپێکهاتە گرنگەکان:\r\n• Betaine: بۆ شێدارکردنەوە و نەرمکردنی پێست.\r\n• Lactic Acid: بۆ پاراستنی هاوسەنگی سروشتی ناوچەکە.\r\n• Soy Proteins: بۆ بەهێزکردنی چینی پارێزەری پێست.\r\nچۆنیەتی بەکارهێنان:\r\n1. بڕێکی کەم لە جێڵەکە بدە لەو شوێنەی کە پێشتر بە ئاو تەڕ کراوە.\r\n2. بە هێواشی بیشۆ تا دەبێتە کەف.\r\n3. پاشان بە باشی بە ئاو ڕایبگرە و وشکی بکەرەوە.\r\n4. تێبینی: تەنها بۆ بەکارهێنانی دەرەکییە.\r\nکەنگی بەکاردێت؟\r\n• بۆ پاکوخاوێنی ڕۆژانە.\r\n• لە کاتی سوڕی مانگانەدا.\r\n• دوای وەرزشکردن یان چوونە مەلەوانگە.\r\n','Key Features:\n• pH maintenance: The pH of this gel is 4.5, which is ideal for sensitive areas and prevents the growth of harmful bacteria and worms.\n• Soothing: Contains substances such as Aloe Vera (saffron) and Chamomile (violet) that help reduce itching and redness.\n• Anti-odor: Contains anti-odor substances to prevent unpleasant odors without causing allergies.\n• Medical examination: Gynecologically tested by gynecologists.\nImportant Ingredients:\n• Betaine: To moisturize and soften the skin.\n• Lactic Acid: To maintain the natural balance of the area.\n• Soy Proteins: To strengthen the protective layer of the skin.\nHow to use:\n1. Apply a small amount of the gel to the area already moistened with water.\n2. Rinse gently until foamy.\n3. Then drain well and dry.\n4. Note: For external use only.\nwhen is it used\n• For daily hygiene.\n• During menstruation.\n• After exercising or going to the swimming pool.','الميزات الرئيسية:\n• الحفاظ على درجة الحموضة: درجة حموضة هذا الجل 4.5، وهي مثالية للمناطق الحساسة وتمنع نمو البكتيريا الضارة والديدان.\n• تهدئة البشرة: يحتوي على مواد مثل الصبار (الزعفران) والبابونج (البنفسج) التي تساعد على تخفيف الحكة والاحمرار.\n• مضاد للروائح: يحتوي على مواد مضادة للروائح لمنع الروائح الكريهة دون التسبب في الحساسية.\n• تم فحصه طبياً: تم اختباره من قبل أطباء أمراض النساء.\n\nالمكونات الهامة:\n• البيتين: لترطيب وتنعيم البشرة.\nحمض اللاكتيك: للحفاظ على التوازن الطبيعي للمنطقة.\nبروتينات الصويا: لتقوية الطبقة الواقية للبشرة.\n\nطريقة الاستخدام:\n1. ضعي كمية صغيرة من الجل على المنطقة المبللة بالماء.\n2. اشطفي بلطف حتى تتكون رغوة.\n3. جففي جيداً.\n\nملاحظة: للاستخدام الخارجي فقط.\nمتى يُستخدم؟\n• للنظافة اليومية. • أثناء الدورة الشهرية.\n• بعد ممارسة الرياضة أو الذهاب إلى المسبح.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:52:32',0.00,'percentage',NULL,1,NULL,4,NULL,NULL,'250ml','01-53',0,0),(210,'پاکەرەوەی زەیتی تایبەت بە پێستی وشک و هەستیاری منداڵان لە بڕاندی بابێی ئیسپانی','Oil cleanser for dry and sensitive children\'s skin from the Spanish brand Babe','منظف ​​زيتي لبشرة الأطفال الجافة والحساسة من ماركة Babe الإسبانية','پاکەرەوەی زەیتی تایبەت بە پێستی وشک و هەستیاری منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی زۆر وشک و حەساس: ئەم سابوونە بە تایبەتی بۆ ئەو پێستانە دروستکراوە کە تووشی خوران و سووربوونەوە دەبن.\r\n• پێکهاتەی زەیتی (Syndet): ئەمە سابوونێکی ئاسایی نییە؛ لەبری ئەوەی پێست وشک بکاتەوە، بەهۆی بوونی ئۆمیگا ۳، ٦ و ٩ تێیدا، پێست بە نەرمی دەهێڵێتەوە و چینە پارێزەرەکەی دەپارێزێت.\r\n• بێ سابوونی کیمیایی: بەوە ناسراوە کە (Soap-free) یان (Syndet)ە، واتە ئەو ماددە توندانەی تێدا نییە کە هاوسەنگی (pH)ی پێست تێک دەدەن.\r\n• تایبەتمەندی چاککەرەوە: یارمەتی نۆژەنکردنەوەی بەربەستی پارێزەری پێست دەدات و ڕێگری دەکات لە لەدەستدانی شێداری.\r\nپێکهاتە گرنگەکانی:\r\n1. زەیتی ئەڤۆکادۆ (10%): بۆ نەرمکردنەوە و خۆراکپێدانی پێست.\r\n2. کۆمپلێکسی چاککەرەوەی پێست: کە بریتین لە سیراماید و فیتۆستیرۆڵ بۆ بەهێزکردنی پێست.\r\n3. ڤیتامین F و E: وەک دژە ئۆکسان و پارێزەر کار دەکەن.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی کەم بدە لە پێستی تەڕی منداڵەکە (لە کاتی خۆشۆردن).\r\n• بە هێواشی مەساجی پێ بکە.\r\n• پاشان بە ئاوێکی زۆر ڕانی بکەرەوە (بیشۆ).\r\n• تێبینی: باشترە دوای بەکارهێنانی، پێستی منداڵەکە بە خاولییەکی نەرم و بە شێوەی (تەپتەپە) وشک بکرێتەوە، نەک بە توندی لێی بخشێنرێت.\r\n','Key Features:\n• For very dry and sensitive skin: This soap is especially formulated for skin that is prone to irritation and redness.\n• Oil texture (Syndet): This is not an ordinary soap; Instead of drying the skin, it contains omega-3, 6 and 9 fatty acids that keep the skin soft and protect its protective layer.\n• Chemical soap-free: Known as soap-free or syndet, which means it does not contain harsh substances that disrupt the skin\'s pH balance.\n• Restorative properties: Helps restore skin’s protective barrier and prevent moisture loss.\nImportant components:\n1. Avocado oil (10%): To soften and nourish the skin.\n2. Skin Repair Complex: which include ceramides and phytosterols to strengthen the skin.\n3. Vitamins F and E: Act as antioxidants and protectors.\nHow to use:\n• Apply a small amount to the child\'s wet skin (during bathing).\n• Massage gently.\n• Then rinse with plenty of water.\n• Note: It is best to dry the child\'s skin with a soft towel after use, rather than rubbing it hard.','الميزات الرئيسية:\n• للبشرة شديدة الجفاف والحساسة: صُمم هذا الصابون خصيصًا للبشرة المعرضة للتهيج والاحمرار.\n• قوام زيتي (سينديت): هذا ليس صابونًا عاديًا؛ فبدلًا من تجفيف البشرة، يحتوي على أحماض أوميغا 3 و6 و9 الدهنية التي تحافظ على نعومة البشرة وتحمي طبقتها الواقية.\n• خالٍ من الصابون الكيميائي: يُعرف أيضًا باسم \"سينديت\"، مما يعني أنه لا يحتوي على مواد قاسية تُخل بتوازن درجة حموضة البشرة.\n• خصائص ترميمية: يساعد على استعادة حاجز البشرة الواقي ومنع فقدان الرطوبة.\n\nالمكونات الهامة:\n1. زيت الأفوكادو (10%): لتنعيم البشرة وتغذيتها.\n2. مركب ترميم البشرة: يحتوي على السيراميدات والفيتوستيرولات لتقوية البشرة.\n3. فيتامينات F وE: تعمل كمضادات للأكسدة وواقية.\n\nطريقة الاستخدام:\n• ضعي كمية صغيرة على بشرة الطفل المبللة (أثناء الاستحمام).\n• دلكي بلطف.\n• ثم اشطفي جيدًا بالماء. • ملاحظة: من الأفضل تجفيف بشرة الطفل بمنشفة ناعمة بعد الاستخدام، بدلاً من فركها بقوة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:54:16',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-52',0,0),(211,'شامپۆی تایبەت بە چارەسەرکردنی کڕێژی قژی کۆرپە و منداڵان لە بڕاندی بابێی ئیسپانی','Shampoo for treating dandruff in babies and children from the Spanish brand Babe','شامبو لعلاج قشرة الرأس عند الرضع والأطفال من ماركة Babe الإسبانية','شامپۆی تایبەت بە چارەسەرکردنی کڕێژی قژی کۆرپە و منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاککردنەوە و چارەسەر: یارمەتی لێکردنەوە و نەهێشتنی ئەو توێژاڵە چەورییانە دەدات کە لەسەر سەری منداڵ دروست دەبن.\r\n• هێورکەرەوە: بەهۆی هەبوونی پێکهاتەی وەک کالێندۆلا (Calendula)، پێستی سەر هێور دەکاتەوە و سووربوونەوە ناهێڵێت.\r\n• پێکهاتەی زانستی: پرێبایۆتیک و ماددەی دژە بەکتریای تێدایە کە هاوسەنگی پێستی سەر دەپارێزن.\r\n• بێ فرمێسک: بە شێوەیەک دروست کراوە کە چاوی منداڵ نائێشێنێت و نابێتە هۆی فرمێسک ڕشتن.\r\n• بێ بۆن: هیچ بۆنێکی دەستکردی تێدا نییە بۆ ئەوەی حەساسیەت بۆ منداڵ دروست نەکات.\r\nچۆنیەتی بەکارهێنان:\r\n1. بڕێکی کەم لە شامپۆکە بدە لە سەری منداڵەکە (کە پێشتر تەڕ کراوە).\r\n2. بە هێواشی مەساجی پێ بکە.\r\n3. بۆ ماوەی چەند خولەکێک بە سەریەوە بیهێڵەرەوە.\r\n4. پاشان بە باشی بە ئاو بیشۆ و لێی بکەرەوە.\r\n5. پێشنیار کراوە کە هەفتانە ٢ بۆ ٣ جار بەکاربێت.\r\nتێبینییە گرنگەکان:\r\n• تایبەت بە منداڵ: ئەم بەرهەمە لەلایەن پزیشکانی منداڵانەوە تاقیکراوەتەوە و بۆ پێستی هەستیاری کۆرپەلە گونجاوە.\r\n','Key Features:\n• Cleansing and treatment: Helps remove fat deposits that form on the child\'s head.\n• Soothing: Due to ingredients such as calendula, it soothes the scalp and prevents redness.\n• Scientific ingredients: Contains prebiotics and antibacterial substances that maintain scalp balance.\n• Tear-free: Designed to not hurt the child\'s eyes or cause tears.\n• Fragrance-free: Contains no artificial fragrances to avoid allergies.\nHow to use:\n1. Apply a small amount of the shampoo to the scalp (which has already been wetted).\n2. Massage gently.\n3. Leave it on for a few minutes.\n4. Then rinse thoroughly with water and peel.\n5. Recommended use 2 to 3 times per week.\nImportant Notes:\n• For children: This product has been tested by pediatricians and is suitable for sensitive infant skin.','الميزات الرئيسية:\n• تنظيف وعلاج: يساعد على إزالة الدهون المتراكمة على رأس الطفل.\n• تهدئة: بفضل مكونات مثل زهرة الآذريون، يهدئ فروة الرأس ويمنع الاحمرار.\n• مكونات علمية: يحتوي على البريبايوتكس ومواد مضادة للبكتيريا تحافظ على توازن فروة الرأس.\n• لطيف على العينين: مصمم خصيصًا ليكون لطيفًا على عيون الطفل ولا يسبب الدموع.\n• خالٍ من العطور: لا يحتوي على عطور اصطناعية لتجنب الحساسية.\n\nطريقة الاستخدام:\n1. ضعي كمية صغيرة من الشامبو على فروة الرأس (بعد ترطيبها).\n2. دلكي بلطف\n3. اتركيه لبضع دقائق.\n4. اشطفيه جيدًا بالماء وقشريه.\n5. يُنصح باستخدامه من مرتين إلى ثلاث مرات أسبوعيًا.\n\nملاحظات هامة:\n• للأطفال: تم اختبار هذا المنتج من قبل أطباء الأطفال وهو مناسب لبشرة الأطفال الحساسة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:55:21',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-51',0,0),(212,'بەڵسەمی شێدارکەرەوەی تایبەت بە پێستی وشک و زۆر وشک لە بڕاندی بابێی ئیسپانی','Moisturizing balm for dry and very dry skin from Spanish brand Babe','بلسم مرطب للبشرة الجافة والجافة جداً من ماركة Babe الإسبانية','بەڵسەمی شێدارکەرەوەی تایبەت بە پێستی وشک و زۆر وشک لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. تایبەتمەندییە سەرەکییەکان\r\n• Balm to Oil: ئەم بەرهەمە لە سەرەتادا وەک مەرهەمێکی خەست (Balm) وایە، بەڵام کاتێک دەیدەیت لە پێستت و مەساژی پێ دەکەیت، دەگۆڕێت بۆ زەیتێکی سووک. ئەمە یارمەتیدەرە بۆ ئەوەی بە قووڵی بچێتە ناو پێست و بە ئاسانی بڵاوببێتەوە.\r\n• Microbiome Care: ئەم بەرهەمە یارمەتی پاراستنی هاوسەنگی بەکتریا سوودبەخشەکانی سەر پێست دەدات، کە ئەمەش بەرگری پێست بەهێز دەکات.\r\n٢. سوودەکانی\r\n• تێرکەر و شێدارکەر (Nourishes): بە قووڵی پێست شێدار دەکاتەوە و لە وشکبوونەوە دەیپارێزێت.\r\n• چاککەرەوە (Repairs): یارمەتی چاککردنەوەی ئەو پێستانە دەدات کە زیانیان پێگەیشتووە یان زۆر وشکن.\r\n• هێورکەرەوە (Soothes): خوران و سووربوونەوەی پێست کەم دەکاتەوە، بەتایبەت بۆ ئەو پێستانەی تووشی حەساسییەت بوون.\r\n٣. بۆ کێ گونجاوە؟\r\n• بۆ ئەو کەسانەی پێستیان زۆر وشکە.\r\n• بۆ ئەو کەسانەی پێستیان تووشی حەساسییەت (Sensitive Skin) یان ئەکزیما (Atopic Skin) بووە.\r\n• گونجاوە بۆ هەموو تەمەنەکان (منداڵ و گەورە).\r\n٤. چۆنیەتی بەکارهێنان\r\n• بڕێکی گونجاو لە بەرهەمەکە بدە لەو شوێنەی پێستت کە پێویستی پێیەتی.\r\n• بە هێواشی مەساژی پێ بکە تاوەکو دەگۆڕێت بۆ زەیت و پێستەکە بە تەواوی هەڵی دەمژێت.\r\n• دەتوانیت ڕۆژانە بەکاریبهێنیت.\r\n','Key Features\n• Balm to Oil: This product initially looks like a thick balm, but when you apply it to your skin and massage it, it turns into a light oil. This helps it penetrate deeper into the skin and spread more easily.\n• Microbiome Care: This product helps maintain the balance of beneficial bacteria on the skin, which strengthens the skin\'s immune system.\n2. The benefits\n• Nourishes: Deeply moisturizes skin and protects against dryness.\n• Repairs: Helps repair damaged or very dry skin.\n• Soothes: Reduces itching and redness, especially for allergic skin.\n3. Who is it suitable for?\n• For people with very dry skin.\n• For people with sensitive skin or eczema (atopic skin).\n• Suitable for all ages (children and adults).\n4. How to use\n• Apply the right amount of product where your skin needs it.\n• Gently massage until it turns into oil and is completely absorbed by the skin.\n• You can use it daily.','الميزات الرئيسية\n• يتحول من بلسم إلى زيت: يبدو هذا المنتج في البداية كبلسم كثيف، ولكن عند وضعه على البشرة وتدليكه، يتحول إلى زيت خفيف. يساعد ذلك على اختراقه بعمق في البشرة وتوزيعه بسهولة أكبر.\n• العناية بالميكروبيوم: يساعد هذا المنتج على الحفاظ على توازن البكتيريا النافعة على البشرة، مما يقوي جهاز المناعة فيها.\n\nالفوائد\n• يغذي: يرطب البشرة بعمق ويحميها من الجفاف.\n• يُرمم: يساعد على ترميم البشرة المتضررة أو شديدة الجفاف.\n• يُلطف: يقلل الحكة والاحمرار، خاصةً للبشرة الحساسة.\n\nلمن يناسب؟\n• لأصحاب البشرة شديدة الجفاف.\n• لأصحاب البشرة الحساسة أو المصابين بالإكزيما (الجلد التأتبي).\n• مناسب لجميع الأعمار (الأطفال والبالغين).\n\nطريقة الاستخدام\n• ضعي كمية مناسبة من المنتج على المناطق التي تحتاجها بشرتك.\n• دلكي بلطف حتى يتحول إلى زيت وتمتصه البشرة بالكامل.\n\nطريقة الاستخدام\n• ضعي كمية مناسبة من المنتج على المناطق التي تحتاجها بشرتك.\nدلكي بلطف حتى يتحول إلى زيت وتمتصه البشرة تمامًا. • يمكنك استخدامه يومياً.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:56:33',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'100ml','01-50',0,0),(213,'شامپۆی تایبەت بە پاککردنەوەی ڕۆژانەی قژ و پێستی سەری منداڵان لە بڕاندی بابێی ئیسپانی','Daily cleansing shampoo for children\'s hair and scalp from Spanish brand Babe','شامبو التنظيف اليومي لشعر وفروة رأس الأطفال من ماركة Babe الإسبانية','شامپۆی تایبەت بە پاککردنەوەی ڕۆژانەی قژ و پێستی سەری منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• چاو ناسووتێنێت: بە جۆرێک دروستکراوە کە لە کاتی شتنی قژدا چاوی منداڵەکە هەراسان ناکات.\r\n• نەرمی و درەوشانەوە: قژی منداڵ زۆر بە نەرمی دەهێڵێتەوە و بریقەیەکی سروشتی پێ دەبەخشێت.\r\n• بۆ پێستی هەستیار گونجاوە: پشکنینی پزیشکی (Pediatrically tested) بۆ کراوە بۆ ئەوەی دڵنیابنەوە کە لەگەڵ پێستی ناسکی منداڵان دەگونجێت.\r\nپێکهاتە گرنگەکانی ناو ئەم شامپۆیە:\r\nبەپێی ئەوەی لەسەر بوتڵەکە نووسراوە، ئەمانە لە پێکهاتە سەرەکییەکانین:\r\n1. Panthenol (1%): یارمەتی شێدارکردنەوەی قژ و پاراستنی پێستی سەر دەدات.\r\n2. Babé Care Complex: کە پێکهاتووە لە (گوڵە بەیبوون، میمۆزا، و ئالۆڤێرا) کە ئەم گیایانە یارمەتی ئارامکردنەوەی پێستی سەر دەدەن\r\nچۆنیەتی بەکارهێنان:\r\nبڕێکی کەم لە شامپۆکە بدە لە قژی تەڕی منداڵەکە، زۆر بە هێمنی مەساجی پێ بکە و پاشان بە ئاوێکی شلەتێن بە باشی قژی بشۆ.\r\n','Key Features:\n• Does not burn the eyes: It is designed not to irritate the child\'s eyes while washing the hair.\n• Softness and Shine: Keeps baby’s hair very soft and gives it a natural shine.\n• Suitable for sensitive skin: Pediatrically tested to ensure it suits children\'s delicate skin.\nImportant ingredients in this shampoo:\nAccording to the label on the bottle, these are the main ingredients:\n1. Panthenol (1%): Helps moisturize hair and protect scalp.\n2. Babé Care Complex: Contains violet, mimosa, and aloe vera, which help soothe the scalp\nHow to use:\nApply a small amount of the shampoo to baby’s wet hair, massage very gently and then rinse hair thoroughly with lukewarm water.','الميزات الرئيسية:\n• لا يسبب حرقانًا للعينين: مصمم خصيصًا ليلطف عيون الطفل أثناء غسل الشعر.\n• نعومة ولمعان: يحافظ على نعومة شعر الطفل ويمنحه لمعانًا طبيعيًا.\n• مناسب للبشرة الحساسة: تم اختباره من قبل أطباء الأطفال لضمان ملاءمته لبشرة الأطفال الرقيقة.\n\nالمكونات الرئيسية في هذا الشامبو:\nوفقًا للملصق الموجود على العبوة، هذه هي المكونات الرئيسية:\n1. بانثينول (1%): يساعد على ترطيب الشعر وحماية فروة الرأس.\n2. مركب بيبي كير: يحتوي على البنفسج والميموزا والصبار، مما يساعد على تهدئة فروة الرأس.\n\nطريقة الاستخدام:\nضعي كمية صغيرة من الشامبو على شعر الطفل المبلل، ودلكيه بلطف شديد، ثم اشطفيه جيدًا بالماء الفاتر.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 04:57:50',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-49',0,0),(214,'ستیکی دژە خۆر لە بڕاندی بابێی ئیسپانی','Sunscreen stick from Spanish brand Babe','قلم واقي من الشمس من ماركة Babe الإسبانية','ستیکی دژە خۆر لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەهێز (SPF 50): پێست دەپارێزێت لە تیشکی زیانبەخشی خۆر وەک (UVB + UVA)، هەروەها دژی تیشکی شاشە (HEV) و تیشکی ژێر سوورە (IR-A).\r\n• نابینراو (Invisible): کاتێک بەکاری دەهێنیت، هیچ ڕەنگێکی سپی لەسەر پێست جێناهێڵێت و چەور نییە.\r\n• بەرگری ئاو (Water Resistant): بۆ کاتی مەلەکردن یان ئارەقکردنەوە گونجاوە و زوو لاناچێت.\r\n• دژە پیسبوونی هەوا (Anti-pollution): چینێکی پارێزەر دروست دەکات کە ناهێڵێت تەپوتۆز و پیسی هەوا کار لە پێستت بکات.\r\n• گونجاوە بۆ هەموو شوێنێک: دەتوانیت بۆ دەموچاو و ئەو شوێنانەی جەستە کە هەستیارن (وەک دەوروبەری چاو، لوت، یان ئەو شوێنانەی خاڵ یان برینیان پێوەیە) بەکاری بهێنیت.\r\nباشییەکانی ئەم شێوازە (Stick):\r\n1. بەکارهێنانی ئاسان: پێویستی بەوە نییە دەستت لێ بدەیت، ڕاستەوخۆ دەیدەیت لە دەموچاوت.\r\n2. بۆ نوێکردنەوە: باشترین بژاردەیە بۆ ئەوەی لە جانتاکەتدا بێت و هەموو ٢ کاتژمێر جارێک دژەخۆرەکەت پێ نوێ بکەیتەوە، تەنانەت ئەگەر ماکیاژیشت پێوە بێت.\r\n3. قەبارەی گونجاو: کێشەکەی ٣٠ گرامە و زۆر سووکە بۆ هەڵگرتن.\r\nزانیاری تەندروستی:\r\n• لە لایەن پزیشکانی پێست و چاوەوە تاقیکراوەتەوە (Dermatologically & Ophthalmologically tested\r\n','Key Features:\n• Strong protection (SPF 50): Protects skin from harmful sun rays such as (UVB + UVA), as well as against screen light (HEV) and infrared (IR-A).\n• Invisible: When used, it does not leave any white spot on the skin and is not greasy.\n• Water Resistant: Suitable for swimming or sweating.\n• Anti-pollution: Creates a protective layer that prevents dust and air pollution from affecting your skin.\n• Suitable for all areas: You can use it on the face and sensitive areas of the body (such as around the eyes, nose, or areas with spots or sores).\nAdvantages of this method (Stick):\n1. Easy to use: No need to touch, apply directly to your face.\n2. To refresh: It is the best option to have in your bag and refresh your sunscreen every 2 hours, even if you have makeup on.\n3. Convenient size: It weighs 30 grams and is very light to carry.\nHealth Information:\n• Dermatologically & Ophthalmologically tested','الميزات الرئيسية:\n• حماية قوية (SPF 50): يحمي البشرة من أشعة الشمس الضارة مثل الأشعة فوق البنفسجية UVB وUVA، بالإضافة إلى ضوء الشاشة (HEV) والأشعة تحت الحمراء (IR-A).\n• غير مرئي: لا يترك أي بقع بيضاء على البشرة عند استخدامه، كما أنه غير دهني.\n• مقاوم للماء: مناسب للسباحة أو التعرق.\n• مضاد للتلوث: يُشكّل طبقة واقية تمنع الغبار وتلوث الهواء من التأثير على بشرتك.\n• مناسب لجميع المناطق: يُمكن استخدامه على الوجه والمناطق الحساسة من الجسم (مثل حول العينين والأنف، أو المناطق التي بها بقع أو جروح).\n\nمزايا هذه الطريقة (العصا):\n1. سهل الاستخدام: لا حاجة للمس، يُوضع مباشرة على الوجه.\n2. للتجديد: يُعد الخيار الأمثل لحمله في حقيبتك وتجديد واقي الشمس كل ساعتين، حتى مع وضع المكياج.\n3. حجم مناسب: يزن 30 غرامًا فقط، وهو خفيف الوزن وسهل الحمل.\n\nمعلومات صحية:\n• تم اختباره من قبل أطباء الجلدية والعيون\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:09:42',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'30g','01-48',0,0),(215,'دیۆدۆرانتی تایبەت بە پاراستنی ژێرباڵ لە بۆنی ناخۆش لە بڕاندی بابێی ئیسپانی','Underarm deodorant from bad breath from Spanish brand Babe','مزيل عرق تحت الإبط من ماركة Babe الإسبانية، يمنع رائحة الفم الكريهة.',' دیۆدۆرانتی تایبەت بە پاراستنی ژێرباڵ لە بۆنی ناخۆش لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بۆ ماوەی ٢٤ کاتژمێر کار دەکات: پارێزگاری لە وشک مانەوە و نەهێشتنی بۆنی ناخۆش دەکات بۆ ماوەیەکی درێژ.\r\n• Microbiome Friendly: پارێزگاری لە هاوسەنگی بەکتریا سوودبەخشەکانی سەر پێست دەکات، ئەمەش وادەکات پێست تەندروست بێت.\r\n• بێ کحول (0% Alcohol): هیچ کحولێکی تێدا نییە، بۆیە نابێتە هۆی سووتانەوە یان سووربوونەوەی پێست، تەنانەت دوای تاشینی مووی بنباڵیش.\r\n• بۆ هەموو خێزانەکە گونجاوە:  \"For the whole family\"، منداڵانی سەروو تەمەن ٨ ساڵ و گەورەکانیش دەتوانن بەکاری بهێنن.\r\nپێکهاتە گرنگەکان:\r\n نووسراوە:\r\n1. Anti-Odorant Complex: تێکەڵەیەکی تایبەت بۆ کۆنتڕۆڵکردنی بۆنی ناخۆش.\r\n2. Prebiotic: یارمەتی خۆراکدانی بەکتریا باشەکان دەدات بۆ پاراستنی بەرگری پێست.\r\n3. Alpha-Bisabolol: ماددەیەکی هێورکەرەوەیە و ناهێڵێت پێست تووشی هەستیاری ببێت.\r\nتێبینییەکان:\r\n• جۆری بەرهەم: ئەمە (Roll-on)ە، واتە بە شێوەی تۆپ دەخولێتەوە و شلە دەدات لە پێست.\r\n• بۆ پێستی هەستیار: زۆر گونجاوە چونکە تاقیکردنەوەی پزیشکی بۆ کراوە (Dermatologically Tested\r\n','Key Features:\n• Works for 24 hours: Protects dryness and eliminates unpleasant odors for a long time.\n• Microbiome Friendly: Maintains the balance of beneficial bacteria on the skin, which keeps the skin healthy.\n• Alcohol-free (0% Alcohol): Contains no alcohol, so it does not cause burns or redness, even after shaving the armpit hair.\n• Suitable for the whole family: \"For the whole family\", children over 8 years old and adults can use it.\nImportant Ingredients:\n Written:\n1. Anti-Odorant Complex: A special blend to control odors.\n2. Prebiotic: Helps feed good bacteria to maintain skin immunity.\n3. Alpha-Bisabolol: A soothing agent that prevents skin sensitivity.\nNotes:\n• Product Type: This is a roll-on, which means it rolls in a ball and applies liquid to the skin.\n• For sensitive skin: Very suitable because it is dermatologically tested','الميزات الرئيسية:\n• فعالية تدوم 24 ساعة: يحمي من الجفاف ويزيل الروائح الكريهة لفترة طويلة.\n• صديق للميكروبيوم: يحافظ على توازن البكتيريا النافعة على البشرة، مما يحافظ على صحتها.\n• خالٍ من الكحول (0%): لا يحتوي على الكحول، لذا فهو لا يسبب حروقًا أو احمرارًا، حتى بعد حلاقة شعر الإبط.\n• مناسب لجميع أفراد العائلة: مناسب لجميع أفراد العائلة، ويمكن استخدامه للأطفال فوق 8 سنوات والبالغين.\n\n• المكونات الرئيسية:\n• مركب مضاد للروائح: مزيج خاص للتحكم في الروائح.\n• البريبايوتيك: يساعد على تغذية البكتيريا النافعة للحفاظ على مناعة البشرة.\n• ألفا بيسابولول: عامل مهدئ يمنع حساسية البشرة.\n\n• ملاحظات:\n• نوع المنتج: رول أون، أي أنه يُلف على شكل كرة ويُوضع السائل على البشرة.\n• مناسب للبشرة الحساسة: مناسب جدًا لأنه مُختبر من قبل أطباء الجلدية.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:11:01',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-47',0,0),(216,'بەڵسەمی شێدارکەرەوەی تایبەت بە پێستی وشک و زۆر وشک  لە بڕاندی بابێی ئیسپانی','Moisturizing balm for dry and very dry skin from Spanish brand Babe','بلسم مرطب للبشرة الجافة والجافة جداً من ماركة Babe الإسبانية','بەڵسەمی شێدارکەرەوەی تایبەت بە پێستی وشک و زۆر وشک  لە بڕاندی بابێی ئیسپانی',2,20000,29750,4750,1,'. ئیشی سەرەکی چییە؟\r\nئەم بەرهەمە بەڵسمێکی شێدارکەرەوەی زۆر بەهێزە. کاتێک دەیدەیت لە پێستت، لە شێوەی کرێمێکی خەستەوە دەگۆڕێت بۆ شێوەی زەیتێکی سوک، ئەمەش وادەکات زۆر بە ئاسانی بە پێستدا بڵاوبێتەوە و بە قووڵی بچێتە ناو پێستەوە.\r\n٢. سوودە گرنگەکانی:\r\n• خۆراکبەخشین (Nourishing): بەهۆی هەبوونی زەیتە سروشتییەکان، پێستەکە بە قووڵی تێر دەکات.\r\n• هێورکەرەوە (Soothes): خوران و سووربوونەوەی پێست کە بەهۆی وشکییەوە دروست دەبێت، کەم دەکاتەوە.\r\n• پاراستنی میکرۆبایۆم: وەک لەسەر بوتڵەکە نووسراوە (Microbiome Care)، یارمەتی هاوسەنگکردنی بەکتریا سوودبەخشەکانی سەر پێست دەدات بۆ ئەوەی پێستەکە بە تەندروستی بمێنێتەوە.\r\n• نەرمکردن: پێست زۆر نەرم دەکات بەبێ ئەوەی هەستی چەورییەکی ناخۆش و لکاو جێبهێڵێت.\r\n٣. پێکهاتە سەرەکییەکانی:\r\n• زەیتی شیا و زەیتی ئینکا ئینچی: بۆ شێدارکردنەوە و چاککردنەوەی پێست.\r\n• سیراماید (Ceramides): بۆ بەهێزکردنی چینی پارێزەری پێست.\r\n• پریبایۆتیک (Prebiotic): بۆ پاراستنی بەرگری سروشتی پێست.\r\n٤. کێ دەتوانێت بەکاریبهێنێت؟\r\n• ئەوانەی پێستیان زۆر وشکە.\r\n• ئەوانەی کێشەی ئەگزیما (Atopic Dermatitis) یان خورانی پێستیان هەیە.\r\n• گونجاوە بۆ هەموو تەمەنەکان (منداڵ و گەورە).\r\nچۆنیەتی بەکارهێنان:\r\nبڕێکی گونجاو بدە لەو شوێنەی پێستت کە وشکە و بە هێواشی مەساژی پێ بکە تا بەتەواوی دەچێتە ناو پێستەکەت. باشتر وایە دوای خۆشتن بەکاربێت کاتێک پێست کەمێک شێی پێوەیە.\r\n','What is the main job?\nThis product is a very powerful moisturizing balm. When you apply it, it changes from a thick cream to a light oil, which makes it very easy to spread and penetrate deeply into the skin.\n2. Important benefits:\n• Nourishing: Due to the presence of essential oils, it deeply satisfies the skin.\n• Soothes: Relieves dry skin irritation and redness.\n• Microbiome Protection: As it says on the bottle (Microbiome Care), it helps balance the beneficial bacteria on the skin to keep the skin healthy.\n• Softening: Makes the skin very soft without leaving an unpleasant, sticky oily feeling.\n3. Key ingredients:\n• Shea butter and inka inchi oil: to moisturize and repair the skin.\n• Ceramide: To strengthen the protective layer of the skin.\n• Prebiotic: To maintain the skin\'s natural defenses.\n4. Who can use it?\n• Those with very dry skin.\n• Those with eczema (Atopic Dermatitis) or skin irritation.\n• Suitable for all ages (children and adults).\nHow to use:\nApply an appropriate amount to the dry area of ​​your skin and massage gently until it is completely absorbed. It is best used after washing when the skin is slightly moist.','ما هي وظيفته الرئيسية؟\nهذا المنتج عبارة عن بلسم مرطب فائق الفعالية. عند استخدامه، يتحول من كريم كثيف إلى زيت خفيف، مما يجعله سهل التوزيع والتغلغل بعمق في البشرة.\n\n٢. أهم فوائده:\n• مغذي: بفضل احتوائه على زيوت أساسية، يغذي البشرة بعمق.\n• ملطف: يخفف من جفاف البشرة وتهيجها واحمرارها.\n• حماية الميكروبيوم: كما هو موضح على العبوة (العناية بالميكروبيوم)، يساعد على موازنة البكتيريا النافعة على البشرة للحفاظ على صحتها.\n• منعم: يجعل البشرة ناعمة للغاية دون ترك أي شعور دهني لزج مزعج.\n\n٣. المكونات الرئيسية:\n• زبدة الشيا وزيت الإنكا إنشي: لترطيب البشرة وإصلاحها.\n• سيراميد: لتقوية الطبقة الواقية للبشرة.\n• بريبيوتيك: للحفاظ على دفاعات البشرة الطبيعية.\n\n٤. من يمكنه استخدامه؟\n• أصحاب البشرة شديدة الجفاف.\n• مناسب لمن يعانون من الإكزيما (التهاب الجلد التأتبي) أو تهيج الجلد.\n• مناسب لجميع الأعمار (الأطفال والبالغين).\n\nطريقة الاستخدام: ضعي كمية مناسبة على المنطقة الجافة من بشرتك ودلكيها بلطف حتى يتم امتصاصها بالكامل. يُفضل استخدامه بعد غسل البشرة عندما تكون رطبة قليلاً.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:13:04',0.00,'percentage',NULL,1,NULL,4,NULL,NULL,'500ml','01-46',0,0),(217,'تۆنەری تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی','Toner for oily and acne prone skin from Spanish brand Babe','تونر للبشرة الدهنية والمعرضة لحب الشباب من ماركة Babe الإسبانية','تۆنەری تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'سوودە سەرەکییەکانی:\r\n• کەمکردنەوەی چەوری: یارمەتی ڕێکخستنی دەردانی چەوری زیادەی پێست دەدات (Sebum-regulating).\r\n• پاککردنەوەی کونیلەکان: کونیلەکان بە قووڵی پاک دەکاتەوە و یارمەتی بچووککردنەوەیان دەدات.\r\n• ماتکردنی پێست: ئەو بریقە ناخۆشەی بەهۆی چەورییەوە لەسەر دەموچاو دروست دەبێت نایهێڵێت (Mattifying).\r\n• دژی بەکتریا و هەوکردن: یارمەتی وشککردنەوەی زیپکە دەدات و ڕێگری دەکات لە دووبارە دروستبوونەوەیان.\r\nپێکهاتە گرنگەکانی:\r\nبەپێی ئەوەی لەسەر پاکەتەکەی نووسراوە، ئەم پێکهاتە چالاکانەی تێدایە:\r\n1. Cytobiol Iris: تێکەڵەیەکی تایبەتە بۆ کەمکردنەوەی چەوری و هەوکردن.\r\n2. Salicylic Acid (0.20%): ترشێکی ناسراوە بۆ پاککردنەوەی ناوەوەی کونیلەکان و لابردنی خانە مردووەکان.\r\n3. Zinc PCA: کار دەکات بۆ کەمکردنەوەی چەوری و ڕێگری لە دروستبوونی بەکتریا.\r\nچۆنیەتی بەکارهێنان:\r\n• کەی؟ بەیانیان و شەوان دوای ئەوەی دەموچاوت بە غەسول دەشۆیت.\r\n• چۆن؟ بڕێکی کەم بدە لە پارچەیەک لۆکە (Cotton pad) و بەسەر دەموچاو و ملتدا بیهێنە.\r\n• تێبینی: پێویست ناکات دوای ئەم تۆنەرە دەموچاو بشۆرێتەوە. ئاگاداربە بەر چاوەکانت نەکەوێت.\r\nئایا بۆ تۆ گونجاوە؟\r\n• ئەگەر پێستت زۆر چەورە یان زیپکەی هەیە، زۆر گونجاوە.\r\n• ئەگەر پێستت وشکە یان زۆر هەستیارە، ڕەنگە ببێتە هۆی کەمێک وشکبوونەوەی زۆر، چونکە کحول (Alcohol Denat) ی تێدایە بۆ وشککردنەوەی چەورییەکان.','Key benefits:\n• Oil reduction: Helps regulate the secretion of excess oil (Sebum-regulating).\n• Pore Cleansing: Deeply cleans pores and helps shrink them.\n• Mattifying the skin: Eliminates the unpleasant shine caused by oil on the face (Mattifying).\n• Antibacterial and anti-inflammatory: Helps dry acne and prevents recurrence.\nImportant components:\nAccording to the packaging, it contains the following active ingredients:\n1. Cytobiol Iris: A special blend to reduce sebum and inflammation.\n2. Salicylic Acid (0.20%): A well-known acid for cleaning the inside of pores and removing dead cells.\n3. Zinc PCA: Works to reduce fat and prevent the formation of bacteria.\nHow to use:\n• when? Mornings and nights after you wash your face with lotion.\n• how? Apply a small amount to a cotton pad and apply to face and neck.\n• Note: You do not need to wash your face after this toner. Be careful not to get it in your eyes.\nIs it right for you?\n• Perfect if you have very oily or acne-prone skin.\n• If you have dry or very sensitive skin, it may cause a little over-drying, as it contains alcohol (Alcohol Denat) to dry out oils.','الفوائد الرئيسية:\n• تقليل الزيوت: يساعد على تنظيم إفراز الزيوت الزائدة (تنظيم الدهون).\n• تنظيف المسام: ينظف المسام بعمق ويساعد على تصغيرها.\n• إضفاء مظهر مطفي للبشرة: يزيل اللمعان غير المرغوب فيه الناتج عن الزيوت على الوجه (إضفاء مظهر مطفي).\n• مضاد للبكتيريا والالتهابات: يساعد على تجفيف حب الشباب ويمنع ظهوره مجدداً.\n\nالمكونات الهامة:\nوفقاً للعبوة، يحتوي على المكونات النشطة التالية:\n1. سايتوبيول إيريس: مزيج خاص لتقليل إفراز الدهون والالتهابات.\n2. حمض الساليسيليك (0.20%): حمض معروف بفعاليته في تنظيف المسام من الداخل وإزالة الخلايا الميتة.\n3. زنك PCA: يعمل على تقليل الدهون ومنع تكوّن البكتيريا.\n\nطريقة الاستخدام:\n• متى؟ صباحاً ومساءً بعد غسل الوجه بالغسول.\n• كيف؟ ضعي كمية صغيرة على قطعة قطن وامسحي بها الوجه والرقبة.\n\nملاحظة: لا داعي لغسل الوجه بعد استخدام هذا التونر. احرصي على عدم ملامسته للعينين.\nهل هو مناسب لكِ؟\nمثالي للبشرة الدهنية جدًا أو المعرضة لحب الشباب.\nإذا كانت بشرتكِ جافة أو حساسة جدًا، فقد يُسبب جفافًا طفيفًا، لاحتوائه على الكحول (الكحول المُحَوَّل) الذي يُزيل الزيوت.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:14:11',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'250ml','01-45',0,0),(218,'کرێمی شێدارکەرەوە و خۆراک بەخشی تایبەت بە پێستی وشک لە بڕاندی بابێی ئیسپانی','Moisturizing and nourishing cream for dry skin from Spanish brand Babe','كريم مرطب ومغذٍ للبشرة الجافة من ماركة Babe الإسبانية',' کرێمی شێدارکەرەوە و خۆراک بەخشی تایبەت بە پێستی وشک لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. کار و سوودە سەرەکییەکانی:\r\n• شێدارکەرەوە (Moisturising): بەهۆی هەبوونی ترشی هیالۆرۆنیک (Hyaluronic Acid)، شێی پێست دەپارێزێت.\r\n• خۆراکبەخش (Nourishing): پێستەکە بە نەرمی دەهێڵێتەوە و لە تێكچوون دەیپارێزێت.\r\n• پارێزگاری (Protects): ڕێگری دەکات لە چرچبوونی پێشوەختە و کاریگەرییە خراپەکانی دەوروبەر.\r\n٢. پێکهاتە گرنگەکانی:\r\nبەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە:\r\n• SPF 20: پارێزگارییەکی مامناوەند لە پێست دەکات دژی تیشکی خۆر (UV).\r\n• Shea Butter (٢%): بۆ نەرمکردن و قووڵ شێدارکردنەوەی پێست.\r\n• Jojoba Oil (٠.٥٠%): یارمەتی چاکبوونەوەی پێست و بەهێزکردنی چینی پارێزەری پێست دەدات.\r\n• Vitamin E (٠.٢٥%): وەک دژە ئۆکسان کاردەکات.\r\n• Hyaluronic Acid: بۆ پڕکردنەوەی شێی نێوان خانەکان.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• بەیانیان یان شەوان بڕێکی گونجاو بدە لە دەموچاو و ملت.\r\n• بە هێواشی مەساجی پێ بکە تا بەتەواوی لەلایەن پێستەوە هەڵدەمژرێت.\r\n٤. بۆ کێ گونجاوە؟\r\n• تایبەت بۆ پێستی وشک دروستکراوە.\r\n• بۆ ئەو پێستانەی کە کەمێک زبرن یان ڕەنگیان کز بووە (Dull skin).\r\n• ئاستی ترشێتییەکەی pH 5.5، کە هاوسەنگی سروشتی پێست دەپارێزێت.\r\n',' Main functions and benefits:\n• Moisturizing: Due to the presence of hyaluronic acid, maintains skin moisture.\n• Nourishing: Keeps skin soft and protects against damage.\n• Protects: Prevents premature wrinkles and adverse environmental effects.\n2. Important components:\nAccording to what is written on the carton:\n• SPF 20: Provides moderate protection against sunlight (UV).\n• Shea Butter (2%): To soften and deeply moisturize the skin.\n• Jojoba Oil (0.50%): Promotes skin healing and strengthens the skin’s protective layer.\n• Vitamin E (0.25%): Acts as an antioxidant.\n• Hyaluronic Acid: To replenish moisture between cells.\n3. How to use:\n• Apply appropriate amounts to face and neck in the morning or at night.\n• Massage gently until completely absorbed by the skin.\n4. Who is it suitable for?\n• Formulated for dry skin.\n• For slightly rough or dull skin.\n• Acidity level of pH 5.5, which maintains the skin’s natural balance.',' الوظائف والفوائد الرئيسية:\n• ترطيب: يحافظ على رطوبة البشرة بفضل حمض الهيالورونيك.\n• تغذية: يحافظ على نعومة البشرة ويحميها من التلف.\n• حماية: يمنع ظهور التجاعيد المبكرة والآثار البيئية الضارة.\n\n٢. المكونات الهامة:\nوفقًا لما هو مكتوب على العبوة:\n• عامل حماية من الشمس ٢٠: يوفر حماية متوسطة من أشعة الشمس (الأشعة فوق البنفسجية).\n• زبدة الشيا (٢٪): لتنعيم البشرة وترطيبها بعمق.\n• زيت الجوجوبا (٠.٥٠٪): يعزز التئام البشرة ويقوي طبقتها الواقية.\n• فيتامين هـ (٠.٢٥٪): يعمل كمضاد للأكسدة.\n• حمض الهيالورونيك: لترطيب ما بين خلايا البشرة.\n\n٣. طريقة الاستخدام:\n• ضعي كمية مناسبة على الوجه والرقبة صباحًا أو مساءً.\n• دلكي بلطف حتى تمتصه البشرة تمامًا.\n\n٤. لمن يناسب؟\n• تركيبة مخصصة للبشرة الجافة. • مناسب للبشرة الخشنة أو الباهتة قليلاً.\n• درجة حموضة 5.5، تحافظ على التوازن الطبيعي للبشرة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:15:22',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-44',0,0),(219,'پادی تەڕکراو تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی','Wet pad for oily and acne prone skin from Spanish brand Babe','فوط مبللة للبشرة الدهنية والمعرضة لحب الشباب من ماركة Babe الإسبانية','پادی تەڕکراو تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'کارەکانی ئەم بەرهەمە:\r\n• کۆنتڕۆڵکردنی چەوری: یارمەتی کەمکردنەوەی دەردانی چەوری (Sebum) دەدات.\r\n• پاککردنەوەی کونیلەکان: کونیلە گەورەبووەکان پاک دەکاتەوە و بچووکیان دەکاتەوە.\r\n• نەهێشتنی خاڵە ڕەشەکان: کاردەکات بۆ پاککردنەوەی پێست لەو خاڵە ڕەشانەی لەسەر لووت و دەموچاو دروست دەبن.\r\n• پاراستنی مایکرۆبایۆم: یارمەتی هاوسەنگی بەکتریا سوودبەخشەکانی سەر پێست دەدات بۆ ئەوەی پێستەکە کەمتر تووشی هەوکردن بێت.\r\nپێکهاتە سەرەکییەکان:\r\nئەم پادانە کۆمەڵێک ترش و ماددەی چالاکی تێدایە کە زۆر کاریگەرن:\r\n1. Salicylic Acid (%0.5): ترشێکی ناسراوە بۆ لێکردنەوەی خانە مردووەکان و پاککردنەوەی قوڵایی کونیلەکان.\r\n2. Succinic Acid (%0.5): دژە بەکتریایە و ڕێگری لە دروستبوونی زیپکە دەکات.\r\n3. Azeloglycin (%3): یارمەتی کەمکردنەوەی سووربوونەوە و ڕێکخستنی چەوری دەدات.\r\n4. Niacinamide (%2): ڤیتامین B3 کە پێست ئارام دەکاتەوە و پەڵەی زیپکە کەمدەکاتەوە.\r\n5. Prebiotic & Probiotic Complex (%3): بۆ بەهێزکردنی چینی پارێزەری پێست.\r\nچۆن بەکاردێت؟\r\n (BABÉ Advice):\r\n• پێشتر پێستت بە پاکەرەوەیەکی گونجاو (Cleanser) بشۆ و وشکی بکەرەوە.\r\n• یەکێک لە پادەکان دەربهێنە و بە جوڵەی بازنەیی بە هێواشی بەسەر دەموچاوتدا بیهێنە.\r\n• تێبینی: دوور بکەوەرەوە لە بەکارهێنانی بۆ دەوروبەری چاو، لێو، و ناوچە هەستیارەکانی تری دەموچاو.\r\nئایا بۆ تۆ گونجاوە؟\r\nئەم بەرهەمە زیاتر بۆ ئەوانە باشە کە پێستیان تێکەڵە یان چەورە. ئەگەر پێستت زۆر وشکە یان تووشی هەستیاری دەبێت، باشترە پێشتر لە شوێنێکی بچووکی پێستت تاقی بکەیتەوە، چونکە کەمێک کحوول (Alcohol Denat) ی تێدایە کە بۆ وشککردنەوەی زیپکە بەکاردێت.\r\n','Works of this product:\n• Oil control: Helps reduce sebum secretion.\n• Cleansing pores: Cleans and shrinks enlarged pores.\n• Eliminate blackheads: Works to cleanse the skin of blackheads on the nose and face.\n• Maintain the microbiome: Helps balance the beneficial bacteria on the skin to make the skin less susceptible to inflammation.\nKey Ingredients:\nThese pads contain a number of acids and active ingredients that are very effective:\n1. Salicylic Acid (0.5%): An acid known to remove dead cells and cleanse the depths of pores.\n2. Succinic Acid (0.5%): Antibacterial and prevents acne.\n3. Azeloglycin (3%): Helps reduce redness and regulate sebum.\n4. Niacinamide (2%): Vitamin B3 that soothes the skin and reduces acne scars.\n5. Prebiotic & Probiotic Complex (3%): To strengthen the protective layer of the skin.\nhow is it used\n (BABY Advice):\n• Wash and dry your skin with an appropriate cleanser beforehand.\n• Remove one of the pads and apply it slowly over your face in circular motions.\n• Note: Avoid application around the eyes, lips, and other sensitive areas of the face.\nIs it right for you?\nThis product is especially good for those with combination or oily skin. If your skin is very dry or prone to sensitivity, it is best to try it on a small area of ​​your skin beforehand, as it contains a little alcohol (Alcohol Denat) which is used to dry out acne.','فوائد هذا المنتج:\n• التحكم في إفراز الزيوت: يساعد على تقليل إفراز الدهون.\n• تنظيف المسام: ينظف المسام المتضخمة ويصغرها.\n• إزالة الرؤوس السوداء: يعمل على تنظيف البشرة من الرؤوس السوداء على الأنف والوجه.\n• الحفاظ على التوازن الميكروبي: يساعد على موازنة البكتيريا النافعة على البشرة لجعلها أقل عرضة للالتهابات.\n\nالمكونات الرئيسية:\nتحتوي هذه الفوط على عدد من الأحماض والمكونات النشطة الفعالة للغاية:\n1. حمض الساليسيليك (0.5%): حمض معروف بقدرته على إزالة الخلايا الميتة وتنظيف أعماق المسام.\n2. حمض السكسينيك (0.5%): مضاد للبكتيريا ويمنع ظهور حب الشباب.\n3. أزيلوجليسين (3%): يساعد على تقليل الاحمرار وتنظيم إفراز الدهون.\n4. نياسيناميد (2%): فيتامين ب3 الذي يهدئ البشرة ويقلل من آثار حب الشباب.\n5. مركب البريبايوتيك والبروبيوتيك (3%): لتقوية الطبقة الواقية للبشرة.\n\n\nطريقة الاستخدام\n• اغسلي بشرتكِ وجففيها جيدًا باستخدام غسول مناسب قبل الاستخدام.\n• أزيلي إحدى الضمادات وضعيها برفق على وجهكِ بحركات دائرية.\n\n• ملاحظة: تجنبي وضع المنتج حول العينين والشفتين والمناطق الحساسة الأخرى من الوجه.\n\nهل هو مناسب لكِ؟\nهذا المنتج مناسب بشكل خاص للبشرة المختلطة أو الدهنية. إذا كانت بشرتكِ جافة جدًا أو حساسة، يُفضل تجربته على منطقة صغيرة من بشرتكِ أولًا، لاحتوائه على نسبة قليلة من الكحول (الكحول المُحَوَّل) الذي يُستخدم لتجفيف حب الشباب.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:16:40',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'60pad','01-43',0,0),(220,'کرێمی شێدارکەرەوەی تایبەت بە پێستی وشکی منداڵان لە بڕاندی بابێی ئیسپانی','Moisturizing cream for children\'s dry skin from Spanish brand Babe','كريم مرطب لبشرة الأطفال الجافة من ماركة Babe الإسبانية','کرێمی شێدارکەرەوەی تایبەت بە پێستی وشکی منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. سوودە سەرەکییەکانی:\r\n• بۆ پێستی زۆر وشک: پێست بە قووڵی تەڕ (شێدار) دەکاتەوە و ناهێڵێت وشک بێتەوە.\r\n• چارەسەری خوران: بەهۆی پێکهاتەکانیەوە، خورانی پێست کە بەهۆی وشکییەوە دروست دەبێت کەمدەکاتەوە.\r\n• پاراستنی پێست: یارمەتی چاکبوونەوەی چینی پارێزەری پێست دەدات و ناهێڵێت تێکبچێت.\r\n• پێکهاتەی دەوڵەمەند: ئۆمیگا ٣ و ٦ و ٩ی تێدایە کە بۆ تەندروستی پێستی منداڵ زۆر گرنگن.\r\n٢. تایبەتمەندییەکان:\r\n• لەلایەن پزیشکانی پێست و منداڵانەوە پشکنینی بۆ کراوە.\r\n• گونجاوە بۆ بەکارهێنانی ڕۆژانە.\r\n• هیچ جۆرە ماددەیەکی زیانبەخشی تێدا نییە کە ببێتە هۆی هەستیاری زیاتر.\r\n٣. چۆن بەکاردێت؟\r\n• بڕێکی گونجاو لە کرێمەکە بدە لەو شوێنەی کە وشکە یان تووشی هەستیاری بووە.\r\n• بە هێواشی مەساجی بۆ بکە تا پێستەکە دەیمژێت.\r\n• باشترە ڕۆژانە بەکاری بهێنیت، بەتایبەت دوای گەرماوکردن کە پێست ئامادەیە بۆ مژینی شێداری.\r\n',' Key benefits:\n• For very dry skin: Deeply moisturizes (moisturizes) the skin and prevents it from drying out.\n• Itch treatment: Due to its ingredients, it reduces skin irritation caused by dryness.\n• Skin protection: Helps heal the protective layer of the skin and prevents damage.\n• Rich ingredients: Contains Omega 3, 6 and 9, which are very important for baby skin health.\n2. Features:\n• Examined by dermatologists and pediatricians.\n• Suitable for daily use.\n• Contains no harmful substances that can cause further sensitivity.\n3. how is it used\n• Apply an appropriate amount of the cream to the dry or allergic area.\n• Gently massage until the skin is absorbed.\n• It is best to use daily, especially after a bath when the skin is ready to absorb moisture.',' الفوائد الرئيسية:\n• للبشرة شديدة الجفاف: يرطب البشرة بعمق ويمنع جفافها.\n• علاج الحكة: بفضل مكوناته، يقلل من تهيج البشرة الناتج عن الجفاف.\n• حماية البشرة: يساعد على ترميم الطبقة الواقية للبشرة ويمنع تلفها.\n• مكونات غنية: يحتوي على أوميغا 3 و6 و9، وهي عناصر بالغة الأهمية لصحة بشرة الأطفال.\n\n2. المميزات:\n• تم فحصه من قبل أطباء الجلدية وأطباء الأطفال.\n• مناسب للاستخدام اليومي.\n• خالٍ من المواد الضارة التي قد تسبب المزيد من الحساسية.\n\n3. طريقة الاستخدام:\n• ضعي كمية مناسبة من الكريم على المنطقة الجافة أو المصابة بالحساسية.\n• دلكي بلطف حتى تمتصه البشرة.\n• يُفضل استخدامه يوميًا، خاصةً بعد الاستحمام عندما تكون البشرة مستعدة لامتصاص الرطوبة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:18:12',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-42',0,0),(221,'کرێمی شێدارکەرەوەی ڕۆژانەی تایبەت بە پێستی ئاسایی و تێکەڵ لە بڕاندی بابێی ئیسپانی','Daily Moisturizing Cream for normal and combination skin from Spanish brand Babe','كريم مرطب يومي للبشرة العادية والمختلطة من ماركة Babe الإسبانية','کرێمی شێدارکەرەوەی ڕۆژانەی تایبەت بە پێستی ئاسایی و تێکەڵ لە بڕاندی بابێی ئیسپانی ',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• شێدارکردن (Hydration): بۆ ماوەی ٢٤ کاتژمێر پێست بە شێداری دەهێڵێتەوە.\r\n• پاراستن (Protection): خاوەنی SPF 20ـە، واتە پێست دەپارێزێت لە تیشکی خۆر (پلەی پاراستنەکەی مامناوەندە).\r\n• پێکهاتەی سووک (Light Texture): زوو بە پێستدا دەچێت و هەستی چەوری یان بریقەی ناخۆش لەسەر دەموچاو جێناهێڵێت.\r\n• بێ کێشە بۆ کونیلەکان: لەسەر پاکەتەکە نووسراوە Non-Comedogenic، واتە کونیلەکانی پێست ناگرێت و نابێتە هۆی دروستبوونی زیپکە.\r\nپێکهاتە گرنگەکان:\r\nبەپێی لیستەکە، ئەم پێکهاتانەی تێدایە کە بۆ تەندروستی پێست باشن:\r\n• Glycerin (4%): بۆ شێدارکردنەوەی قووڵی پێست.\r\n• Panthenol (1.5%): یارمەتی چاکبوونەوە و هێورکردنەوەی پێست دەدات.\r\n• Avocado Oil: بۆ نەرمکردنی پێست.\r\n• Vitamin E: دژە ئۆکسانە و پێست لە پیربوون دەپارێزێت.\r\n• pH 6: هاوسەنگی سروشتی پێست دەپارێزێت.\r\nچۆنیەتی بەکارهێنان:\r\n• بەیانیان دوای شتنی دەموچاو، بڕێکی گونجاو بدە لە دەموچاو و ملت.\r\n• بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\nتێبینی: بەهۆی ئەوەی SPF 20ـی تێدایە، زۆر باشە بۆ بەکارهێنانی ڕۆژانە لە ناو ماڵ یان لەو کاتانەی تیشکی خۆر زۆر بەهێز نییە. ئەگەر بۆ ماوەیەکی زۆر دەچیتە بەر خۆری بەهێز، باشترە دژەخۆرێکی بەهێزتری لەگەڵ بەکاربهێنیت\r\n','Key Features:\n• Hydration: Keeps skin moisturized for 24 hours.\n• Protection: SPF 20, which means it protects the skin from sunlight (medium protection).\n• Light Texture: Absorbs quickly into the skin and does not leave an unpleasant greasy or shiny feeling on the face.\n• Pore-free: The package says Non-Comedogenic, which means it does not clog pores and cause acne.\nImportant Ingredients:\nAccording to the list, it contains the following ingredients that are good for skin health:\n• Glycerin (4%): For deep skin hydration.\n• Panthenol (1.5%): Promotes healing and soothes the skin.\n• Avocado Oil: To soften the skin.\n• Vitamin E: Antioxidant and protects skin from aging.\n• pH 6: Maintains skin’s natural balance.\nHow to use:\n• Apply an appropriate amount to your face and neck in the morning after washing your face.\n• Gently massage until fully absorbed.\nNote: Containing SPF 20, it is ideal for daily use indoors or when the sun is not very strong. If you are going to be exposed to strong sun for a long time, it is best to use a stronger sunscreen with it','الميزات الرئيسية:\n• ترطيب: يحافظ على ترطيب البشرة لمدة 24 ساعة.\n• حماية: عامل حماية من الشمس SPF 20، مما يعني أنه يحمي البشرة من أشعة الشمس (حماية متوسطة).\n• قوام خفيف: تمتصه البشرة بسرعة ولا يترك شعورًا دهنيًا أو لامعًا مزعجًا على الوجه.\n• خالٍ من المسام: العبوة مكتوب عليها \"غير كوميدوغينيك\"، مما يعني أنه لا يسد المسام ولا يسبب حب الشباب.\n\n• المكونات الهامة:\nيحتوي هذا المنتج على المكونات التالية المفيدة لصحة البشرة:\n• جلسرين (4%): لترطيب البشرة بعمق.\n• بانثينول (1.5%): يعزز التئام البشرة ويهدئها.\n• زيت الأفوكادو: لتنعيم البشرة.\n• فيتامين هـ: مضاد للأكسدة ويحمي البشرة من علامات الشيخوخة.\n• درجة حموضة 6: تحافظ على التوازن الطبيعي للبشرة.\n\n• طريقة الاستخدام:\n• ضعي كمية مناسبة على الوجه والرقبة صباحًا بعد غسل الوجه.\n• دلكيه بلطف حتى يتم امتصاصه بالكامل.\n\nملاحظة: يحتوي على عامل حماية من الشمس SPF 20، وهو مثالي للاستخدام اليومي في الأماكن المغلقة أو عندما لا تكون أشعة الشمس قوية جدًا. إذا كنت ستتعرض لأشعة الشمس القوية لفترة طويلة، فمن الأفضل استخدام واقٍ شمسي أقوى معه.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:19:35',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-41',0,0),(222,'کرێمی شێدارکەرەوەی تایبەت بە پێستی منداڵان لە بڕاندی بابێی ئیسپانی','Moisturizing cream for children\'s face from the Spanish brand Babe','كريم مرطب للوجه للأطفال من ماركة Babe الإسبانية','کرێمی شێدارکەرەوەی تایبەت بە پێستی دەم و چاوی منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'ئەم کرێمە بە شێوەیەکی سەرەکی بۆ ئەو منداڵانە دروستکراوە کە پێستیان زۆر وشکە یان تووشی ئەگزیما (Atopic Skin) بوون.\r\nلێرەدا پوختەیەک لە تایبەتمەندییەکانی دەخەینە ڕوو:\r\n١. سوودە سەرەکییەکانی:\r\n• چاککردنەوەی پێست: یارمەتی نۆژەنکردنەوەی ئەو ناوچانەی پێست دەدات کە بەهۆی وشکییەوە زیانیان بەرکەوتووە.\r\n• هێورکەرەوە: زۆر خێرا خورانی پێست و سووربوونەوەی ناهێڵێت.\r\n• پارێزگاری: بەربەستێکی سروشتی بۆ پێست دروست دەکات بۆ ئەوەی لە کاریگەرییە دەرەکییەکان بیپارێزێت.\r\n• دەوڵەمەند بە ئۆمیگا: لە پێکهاتەکەیدا  ئۆمیگا ٣، ٦ و ٩ هەیە کە بۆ قووڵ خۆراکپێدانی پێست گرنگن.\r\n٢. پێکهاتە گرنگەکانی:\r\n• SkinRepair: بۆ نۆژەنکردنەوەی خانەکانی پێست.\r\n• Shea Butter: بۆ نەرمکردنەوە و شێدارکردنەوەی قووڵ.\r\n• Avocado Oil: کە ڤیتامینی تێدایە و پێستەکە بە نەرمی دەهێڵێتەوە.\r\n• Vitamin E: وەک دژە ئۆکسان کار دەکات.\r\n٣. خاڵە ئەرێنییەکان:\r\n• بێ بۆنە (No added fragrance): ئەمەش زۆر گرنگە چونکە بۆنی دەستکرد پێستی هەستیار تێکدەدات.\r\n• لەژێر چاودێری پزیشکی منداڵان: تاقیکردنەوەی بۆ کراوە و بۆ پێستی ناسکی منداڵ گونجاوە.\r\n• pH 6.5: هاوسەنگی سروشتی پێست دەپارێزێت.\r\nچۆن بەکاردێت؟\r\nپێویستە ڕۆژانە بە یەکسانی بەسەر پێستی دەموچاو و ملدا دابەش بکرێت. دەتوانیت هەر کاتێک هەستت کرد پێستەکە پێویستی بە شێدارکردنەوەیە، بەکاری بهێنیت.\r\nتێبینی: ئاگاداربە بەر چاوی منداڵەکە نەکەوێت.\r\n','This cream is mainly designed for children who have very dry skin or suffer from eczema (Atopic Skin).\nHere’s a summary of the features:\n1. Key benefits:\n• Skin Repair: Helps repair areas of skin damaged by dryness.\n• Soothing: Prevents skin irritation and redness very quickly.\n• Protection: Creates a natural barrier for the skin to protect it from external influences.\n• Rich in Omega: It contains Omega 3, 6 and 9 which are important for deep skin nourishment.\n2. Important components:\n• SkinRepair: To repair skin cells.\n• Shea Butter: For softening and deep hydration.\n• Avocado Oil: Contains vitamins that keep skin soft.\n• Vitamin E: Acts as an antioxidant.\n3. Positive points:\n• No added fragrance: This is very important because synthetic fragrances can damage sensitive skin.\n• Under the supervision of a pediatrician: Tested and suitable for children\'s delicate skin.\n• pH 6.5: Maintains skin’s natural balance.\nhow is it used\nIt should be distributed evenly over the skin of the face and neck daily. You can use it whenever you feel the skin needs to be hydrated.\nNote: Be careful not to get into the child\'s eyes.','صُمم هذا الكريم خصيصًا للأطفال ذوي البشرة الجافة جدًا أو المصابين بالإكزيما (التهاب الجلد التأتبي).\nإليكم ملخصًا لميزاته:\n1. الفوائد الرئيسية:\n• ترميم البشرة: يساعد على ترميم المناطق المتضررة من الجفاف.\n• تهدئة البشرة: يمنع تهيجها واحمرارها بسرعة.\n• حماية البشرة: يُشكل حاجزًا طبيعيًا يحمي البشرة من العوامل الخارجية.\n• غني بالأوميغا: يحتوي على أوميغا 3 و6 و9، وهي ضرورية لتغذية البشرة بعمق.\n\n2. المكونات الأساسية:\n• ترميم البشرة: يُرمم خلايا البشرة.\n• زبدة الشيا: تُنعم البشرة وترطبها بعمق.\n• زيت الأفوكادو: يحتوي على فيتامينات تُحافظ على نعومة البشرة.\n• فيتامين هـ: يعمل كمضاد للأكسدة.\n\n3. مميزات إضافية:\n• خالٍ من العطور: هذه ميزة مهمة جدًا لأن العطور الاصطناعية قد تُلحق الضرر بالبشرة الحساسة.\n• تحت إشراف طبيب أطفال: مُختبر ومناسب لبشرة الأطفال الرقيقة.\n• درجة حموضة 6.5: تحافظ على التوازن الطبيعي للبشرة.\n\nطريقة الاستخدام: يُوزّع بالتساوي على بشرة الوجه والرقبة يوميًا. يُمكن استخدامه كلما شعرتِ بحاجة البشرة للترطيب.\n\nملاحظة: احرصي على تجنّب ملامسته لعيني الطفل.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:20:46',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-40',0,0),(223,'کرێمی تایبەت بە چارەسەرکردن و سوتانەوەی شوێنی دایبی منداڵان لە بڕاندی بابێی ئیسپانی','Baby diaper burn treatment cream from Spanish brand Babe','كريم لعلاج حروق حفاضات الأطفال من ماركة Babe الإسبانية','کرێمی تایبەت بە چارەسەرکردن و سوتانەوەی شوێنی دایبی منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'کارەکانی ئەم کرێمە:\r\n• دروستکردنی بەربەست: وەک چینێکی پارێزەر کاردەکات بۆ ڕێگری لە بەرکەوتنی پێست بەو ماددە وروژێنەرانەی لە میزو پیسایی منداڵدا هەن.\r\n• ئارامکەرەوە و چارەسەر: یارمەتی کەمکردنەوەی سووربوونەوە و هەوکردنی پێست دەدات.\r\n• شێدارکەرەوە: پێستی منداڵەکە بە نەرمی دەهێڵێتەوە و ناهێڵێت وشک ببێتەوە.\r\nپێکهاتە سەرەکییەکانی (بەپێی پاکەتەکە):\r\n• Zinc Oxide (8%): ماددەیەکی بنەڕەتییە بۆ پاراستنی پێست و ڕێگری لە شێداری زۆر.\r\n• Titanium Dioxide (2%): بۆ زیاتر بەهێزکردنی چینی پارێزەر.\r\n• Panthenol (1.5%): ناسراو بە پرۆ ڤیتامین B5، کە یارمەتی چاکبوونەوەی خێرای پێست دەدات.\r\n• Shea Butter & Calendula: بۆ نەرمکردنەوە و ئارامکردنەوەی پێستە هەستیارەکە.\r\nچۆنیەتی بەکارهێنان:\r\n• پێویستە لە کاتی هەموو دایبی گۆڕینێکدا بەکاربهێنرێت.\r\n• سەرەتا شوێنەکە بە باشی پاک بکەرەوە و وشکی بکەرەوە، پاشان چینێکی تەنک لە کرێمەکە لێ بدە.\r\nخاڵە ئەرێنییەکان:\r\n• لە لایەن پزیشکانی پێست و منداڵانەوە تاقیکراوەتەوە.\r\n• بێ بۆنە (No added fragrance): ئەمەش وادەکات ئەگەری هەستیاری (حەساسیەت) زۆر کەم بێتەوە.\r\n• pH 7: هاوسەنگە لەگەڵ پێستی منداڵ.\r\n','Functions of this cream:\n• Barrier formation: Acts as a protective layer to prevent skin contact with irritants in the child’s urine and feces.\n• Soothing and therapeutic: Helps reduce redness and inflammation of the skin.\n• Moisturizer: Keeps baby\'s skin soft and prevents dryness.\nKey ingredients (depending on the package):\n• Zinc Oxide (8%): ​​Essential for skin protection and prevention of excessive moisture.\n• Titanium Dioxide (2%): To further strengthen the protective layer.\n• Panthenol (1.5%): Known as pro-vitamin B5, which promotes rapid skin healing.\n• Shea Butter & Calendula: To soften and soothe sensitive skin.\nHow to use:\n• Should be used during every diaper change.\n• Clean and dry the area thoroughly first, then apply a thin layer of cream.\nPositive points:\n• Tested by dermatologists and pediatricians.\n• No added fragrance: This greatly reduces the risk of allergies.\n• pH 7: Balanced with baby’s skin.','فوائد هذا الكريم:\n• تكوين حاجز وقائي: يعمل كطبقة واقية لمنع ملامسة الجلد للمواد المهيجة الموجودة في بول وبراز الطفل.\n• مهدئ وعلاجي: يساعد على تقليل احمرار والتهاب الجلد.\n• مرطب: يحافظ على نعومة بشرة الطفل ويمنع جفافها.\n\nالمكونات الرئيسية (حسب العبوة):\n• أكسيد الزنك (8%): ​​ضروري لحماية البشرة ومنع الرطوبة الزائدة.\n• ثاني أكسيد التيتانيوم (2%): لتعزيز الطبقة الواقية.\n• بانثينول (1.5%): يُعرف باسم بروفيتامين B5، الذي يعزز التئام الجلد بسرعة.\n• زبدة الشيا والآذريون: لتنعيم وتهدئة البشرة الحساسة.\n\nطريقة الاستخدام:\n• يُستخدم مع كل تغيير للحفاض.\n• نظفي المنطقة وجففيها جيدًا، ثم ضعي طبقة رقيقة من الكريم.\n\nالمميزات:\n• تم اختباره من قبل أطباء الجلدية وأطباء الأطفال.\n• خالٍ من العطور المضافة: يقلل هذا بشكل كبير من خطر الحساسية.\n• درجة حموضة 7: متوازنة مع بشرة الطفل.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:22:12',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'100ml','01-39',0,0),(224,'لۆشنی دژە خۆری تایبەت بە منداڵان و ساوایان لە بڕاندی بابێی ئیسپانی','Sunscreen lotion for children and babies from the Spanish brand Babe','لوشن واقي من الشمس للأطفال والرضع من ماركة Babe الإسبانية','لۆشنی دژە خۆری تایبەت بە منداڵان و ساوایان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەهێز: پلەی پاراستنی (SPF 50+) هەیە کە دژی تیشکە زیانبەخشەکانی (UVA) و (UVB) کار دەکات.\r\n• تایبەت بە منداڵان: لەلایەن پزیشکانی منداڵان و پێستەوە تاقی کراوەتەوە (Pediatrically Tested).\r\n• بێ کحول: هیچ جۆرە کحولێکی تێدا نییە، ئەمەش وادەکات پێست وشک نەکاتەوە و نەبێتە هۆی سووتانەوە.\r\n• بەرگری دژی ئاو: زۆر بەرگەی ئاو دەگرێت (Very Water Resistant)، کە ئەمە زۆر گرنگە کاتێک منداڵەکە یاری دەکات یان ئارەق دەکاتەوە.\r\n• بەکارهێنان: دەتوانرێت بۆ دەموچاو و جەستە بەکاربهێنرێت.\r\nپێکهاتە گرنگەکان:\r\nئەم دژەخۆرە کۆمەڵێک پێکهاتەی هێورکەرەوەی تێدایە (Soothing Complex) وەک:\r\n• ئەلۆڤێرا و چامۆمایل: بۆ هێورکردنەوەی پێست و ڕێگریکردن لە سووربوونەوە.\r\n• ڤیتامین E: وەک دژە ئۆکسان کار دەکات بۆ پاراستنی خانەکانی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n١. ٢٠ خولەک پێش چوونە بەردەم خۆر بڕێکی پێویست لە لۆشەنەکە بدە لە پێستی منداڵەکە.\r\n٢. پێویستە بە شێوەیەکی یەکسان بە هەموو شوێنەکاندا بڵاوی بکەیتەوە.\r\n٣. ئەگەر منداڵەکە ماوەیەکی زۆر لەبەر خۆر بوو یان مەلەی کرد، پێویستە هەموو ٢ کاتژمێر جارێک لۆشەنەکەی بۆ نوێ بکەیتەوە.\r\n','Key Features:\n• Strong protection: SPF 50+ that works against harmful rays (UVA) and (UVB).\n• For children: Pediatrically Tested by pediatricians and dermatologists.\n• Alcohol-free: Contains no alcohol, which prevents skin from drying out and causing burns.\n• Water resistance: Very Water Resistant, which is very important when the child is playing or sweating.\n• Application: Can be used on face and body.\nImportant Ingredients:\nThis sunscreen contains a number of soothing complexes such as:\n• Aloe vera and chamomile: to soothe the skin and prevent redness.\n• Vitamin E: Acts as an antioxidant to protect skin cells.\nHow to use:\n1. Apply the right amount of lotion to the child\'s skin 20 minutes before going out in the sun.\n2. You need to spread it all over evenly.\n3. If the child has been in the sun for a long time or has been swimming, you should renew the lotion every 2 hours.','الميزات الرئيسية:\n• حماية قوية: عامل حماية من الشمس SPF 50+ يحمي من الأشعة الضارة (UVA) و(UVB).\n• مناسب للأطفال: تم اختباره من قبل أطباء الأطفال وأطباء الجلدية.\n• خالٍ من الكحول: لا يحتوي على الكحول، مما يمنع جفاف البشرة وحروق الشمس.\n• مقاومة للماء: مقاوم للماء بدرجة عالية، وهو أمر بالغ الأهمية أثناء لعب الطفل أو تعرقه.\n• طريقة الاستخدام: يمكن استخدامه على الوجه والجسم.\n\n• المكونات الرئيسية:\n• يحتوي هذا الواقي الشمسي على عدد من المركبات المهدئة، مثل:\n• الصبار والبابونج: لتهدئة البشرة ومنع الاحمرار.\n• فيتامين هـ: يعمل كمضاد للأكسدة لحماية خلايا الجلد.\n\n• طريقة الاستخدام:\n1. ضعي كمية مناسبة من الكريم على بشرة الطفل قبل 20 دقيقة من التعرض للشمس.\n2. وزعيه بالتساوي على كامل البشرة.\nاستخدميه لمدة 20 دقيقة قبل التعرض للشمس.\n 3. إذا كان الطفل قد تعرض لأشعة الشمس لفترة طويلة أو كان يسبح، فيجب عليك تجديد المستحضر كل ساعتين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:23:38',0.00,'percentage',NULL,1,NULL,4,NULL,NULL,'100ml','01-38',0,0),(225,'شێدارکەرەوەی تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی','Moisturizer for oily and acne prone skin from Spanish brand Babe','مرطب للبشرة الدهنية والمعرضة لحب الشباب من ماركة Babe الإسبانية','شێدارکەرەوەی تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. ئامانجی سەرەکی بەرهەمەکە\r\n• کەمکردنەوەی چەوری (Mattifying): ڕێگری دەکات لە درەوشانەوەی پێست بەهۆی چەوری زیادەوە و شێوەیەکی سروشتی و وشک (Matte) بە پێست دەبەخشێت.\r\n• ڕێکخستنی دەردانی چەوری: یارمەتی هاوسەنگکردنەوەی بەرهەمهێنانی چەوری پێست دەدات.\r\n• چارەسەری زیپکە: بەهۆی پێکهاتە ترشەکانی ناویا، یارمەتی پاککردنەوەی کونیلەکان و کەمکردنەوەی دروستبوونی زیپکە دەدات.\r\n٢. پێکهاتە سەرەکییەکان (Ingredients)\r\nبەپێی زانیارییەکانی سەر کارتۆنەکە، ئەم ماددانەی تێدایە:\r\n• Niacinamide (4%): دژە هەوکردنە، سووربوونەوە کەم دەکاتەوە و بەربەستی پارێزەری پێست بەهێز دەکات.\r\n• Salicylic Acid: کونیلەکان پاک دەکاتەوە و ڕێگری لە دروستبوونی زیپکەی سەرڕەش و سەر سپی دەکات.\r\n• Succinic Acid: دژە بەکتریایە و یارمەتی نوێبوونەوەی خانەکانی پێست دەدات.\r\n• Azeloglycin: یارمەتی کەمکردنەوەی پەڵەی جێگەی زیپکە و ڕێکخستنی چەوری دەدات.\r\n• Prebiotic & Probiotic: بۆ پاراستنی هاوسەنگی بەکتریای سوودبەخشی پێست (Microbiome Care).\r\n٣. چۆنیەتی بەکارهێنان\r\n• بڕێکی گونجاو بدە لە پێستی دەموچاو و مل.\r\n• بە هێواشی مەساژی بۆ بکە تا بەتەواوی دەمژرێت.\r\n• باشترە ڕۆژی دوو جار (بەیانیان و شەوان) بەکاربێت دوای شتنی دەموچاو بە غسولێکی گونجاو.\r\n٤. خاڵە ئەرێنییەکان\r\n• Non-Comedogenic: کونیلەکانی پێست ناگرێت.\r\n• Dermatologically Tested: لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە.\r\n• pH 5: هاوسەنگە لەگەڵ سروشتی پێست و نایسوتێنێت.\r\n','The primary purpose of the product\n• Mattifying: Prevents shine due to excess oil and gives the skin a natural, dry matte appearance.\n• Regulates sebum secretion: Helps rebalance skin sebum production.\n• Treatment of acne: Due to its acidic ingredients, it helps cleanse pores and reduce the formation of acne.\n2. Main Ingredients\nAccording to the information on the carton, it contains the following ingredients:\n• Niacinamide (4%): Anti-inflammatory, reduces redness and strengthens skin’s protective barrier.\n• Salicylic Acid: Cleans pores and prevents the formation of blackheads and whiteheads.\n• Succinic Acid: Antibacterial and promotes skin cell renewal.\n• Azeloglycin: Helps reduce acne bed scarring and regulate sebum.\n• Prebiotic & Probiotic: To maintain the balance of beneficial skin bacteria (Microbiome Care).\n3. How to use\n• Apply an appropriate amount to the skin of the face and neck.\n• Massage gently until fully absorbed.\n• It is best to use twice a day (morning and night) after washing the face with an appropriate lotion.\n4. The positive points\n• Non-Comedogenic: Does not block pores.\n• Dermatologically Tested: Tested by dermatologists.\n• pH 5: Balances with the skin’s nature and doesn’t burn.',' الغرض الأساسي من المنتج\n• إضفاء مظهر مطفي: يمنع اللمعان الناتج عن الزيوت الزائدة، ويمنح البشرة مظهرًا طبيعيًا جافًا غير لامع.\n• تنظيم إفراز الدهون: يساعد على إعادة توازن إنتاج دهون البشرة.\n• علاج حب الشباب: بفضل مكوناته الحمضية، يساعد على تنظيف المسام والحد من ظهور حب الشباب.\n\n٢. المكونات الرئيسية\nوفقًا للمعلومات الواردة على العبوة، يحتوي المنتج على المكونات التالية:\n• نياسيناميد (٤٪): مضاد للالتهابات، يقلل الاحمرار، ويقوي حاجز البشرة الواقي.\n• حمض الساليسيليك: ينظف المسام ويمنع ظهور الرؤوس السوداء والبيضاء.\n• حمض السكسينيك: مضاد للبكتيريا، ويعزز تجديد خلايا البشرة.\n• أزيلوجليسين: يساعد على تقليل ندبات حب الشباب وتنظيم إفراز الدهون.\n• بريبيوتيك وبروبيوتيك: للحفاظ على توازن البكتيريا النافعة للبشرة (العناية بالميكروبيوم).\n\n٣. طريقة الاستخدام\n• ضعي كمية مناسبة على بشرة الوجه والرقبة.\n• دلكي بلطف حتى يتم امتصاصه بالكامل.\n• يُفضل استخدامه مرتين يوميًا (صباحًا ومساءً) بعد غسل الوجه بلوشن مناسب.\n\n٤. المزايا\n• غير كوميدوغينيك: لا يسد المسام.\n• مُختَبَر من قِبَل أطباء الجلدية.\n• درجة حموضة ٥: متوازنة مع طبيعة البشرة ولا تُسبب تهيجًا.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:25:04',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-37',0,0),(226,'لۆشنی تایبەت بە چارەسەرکردنی کڕێژی سەری کۆرپە و منداڵ لە بڕاندی بابێی ئیسپانی','Lotion for the treatment of dandruff in babies and children from the Spanish brand Babe','لوشن لعلاج قشرة الرأس عند الرضع والأطفال من ماركة Babe الإسبانية','لۆشنی تایبەت بە چارەسەرکردنی کڕێژی سەری کۆرپە و منداڵ لە بڕاندی بابێی ئیسپانی',2,20000,29750,4750,1,'• بۆ نەهێشتنی ئەو چینە چەوری و کڕێژە زەردەی لەسەر سەری زۆربەی کۆرپەکان دروست دەبێت (Cradle Cap).\r\n• یارمەتی کەمکردنەوەی سووربوونەوە و خوران دەدات.\r\n• پێستی سەر نەرم دەکاتەوە و پاکی دەکاتەوە.\r\n٢. پێکهاتە سەرەکییەکانی:\r\nبەپێی نووسراوی سەر کارتۆنەکە، ئەم ماددانەی تێدایە:\r\n• Prebiotics: بۆ پاراستنی هاوسەنگی سروشتی پێست.\r\n• Calendula (گوڵە بەیبوون): بۆ هێورکردنەوەی پێست و کەمکردنەوەی هەوکردن.\r\n• Panthenol (Pro-Vitamin B5): بۆ شێدارکردن و نوێکردنەوەی خانەکانی پێست.\r\n٣. چۆنیەتی بەکارهێنان (وەک لەسەر پاکەتەکە ڕوونکراوەتەوە):\r\n1. بڕێکی گونجاو لە \"ئیمەلشنەکە\" بدە لەو شوێنەی کە کڕێژەکەی لێیە (سەر یان دەموچاو).\r\n2. بە هێواشی مەساجی پێ بکە.\r\n3. بۆ ماوەی ١٥ خولەک پێوەی بهێڵەرەوە.\r\n4. پاشان بە شامپۆی تایبەت بە کڕێژی سەری منداڵ (وەک شامپۆی هەمان براند) بیشۆ.\r\n5. باشترە هەفتەی ٢ بۆ ٣ جار بەکاربهێنرێت.\r\n٤. تایبەتمەندییەکانی:\r\n• pH 5.0: کە گونجاوە بۆ پێستی ناسکی منداڵ.\r\n• بەبێ بۆنە و تاقیکردنەوەی پزیشکی بۆ کراوە.\r\nتێبینی: ئاگاداربە بەر چاوی منداڵەکە نەکەوێت. ئەگەر کڕێژەکە زۆر بوو یان نیشانەی تری وەک برین و خوێنی لەگەڵ بوو، باشترە پێش بەکارهێنان ڕاوێژ بە پزیشکی منداڵان بکەیت.\r\n','• To remove the layer of fat and yellow dandruff that forms on the head of most babies (Cradle Cap).\n• Helps reduce redness and itching.\n• Softens and cleanses the scalp.\n2. Key ingredients:\nAccording to the label, it contains the following ingredients:\n• Prebiotics: To maintain the skin’s natural balance.\n• Calendula (violet flower): to soothe the skin and reduce inflammation.\n• Panthenol (Pro-Vitamin B5): To moisturize and renew skin cells.\n3. How to use (as explained on the package):\n1. Apply an appropriate amount of the “emulsion” to the area where the dandruff is located (head or face).\n2. Massage gently.\n3. Leave on for 15 minutes.\n4. Then wash with a baby\'s dandruff shampoo (such as the same brand).\n5. It is best to use 2 to 3 times a week.\n4. Features:\n• pH 5.0: ideal for baby’s delicate skin.\n• Has undergone medical examination without occasion.\nNote: Be careful not to get into the child\'s eyes. If the rash is severe or accompanied by other symptoms such as sores and bleeding, it is best to consult a pediatrician before use.','• لإزالة طبقة الدهون والقشرة الصفراء التي تتكون على رأس معظم الأطفال (قشرة المهد).\n• يساعد على تقليل الاحمرار والحكة.\n• ينعم فروة الرأس وينظفها.\n\n٢. المكونات الرئيسية:\nوفقًا للملصق، يحتوي على المكونات التالية:\n• البريبايوتكس: للحفاظ على التوازن الطبيعي للبشرة.\n• زهرة الكاليندولا (زهرة البنفسج): لتهدئة البشرة وتقليل الالتهاب.\n• البانثينول (بروفيتامين ب٥): لترطيب وتجديد خلايا البشرة.\n\n٣. طريقة الاستخدام (كما هو موضح على العبوة):\n١. ضعي كمية مناسبة من \"المستحلب\" على المنطقة المصابة بالقشرة (الرأس أو الوجه).\n٢. دلكي بلطف.\n٣. اتركيه لمدة ١٥ دقيقة.\n٤. ثم اغسليه بشامبو مخصص للأطفال مضاد للقشرة (مثل نفس العلامة التجارية).\n٥. يُفضل استخدامه من مرتين إلى ثلاث مرات أسبوعيًا.\n\n٤. المميزات:\n• درجة حموضة ٥.٠: مثالية لبشرة الطفل الحساسة.\n• خضع لفحص طبي دون أي مشاكل.\n\nملاحظة: يُرجى الحرص على عدم ملامسة المنتج لعيني الطفل. في حال كان الطفح الجلدي شديدًا أو مصحوبًا بأعراض أخرى كالتقرحات والنزيف، يُنصح باستشارة طبيب أطفال قبل الاستخدام.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:26:22',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-36',0,0),(227,'کرێمی تایبەت بە چارەسەرکردنی شوێنی زیپکە لە بڕاندی بابێی ئیسپانی','Acne cream from Spanish brand Babe','كريم حب الشباب من ماركة Babe الإسبانية','کرێمی تایبەت بە چارەسەرکردنی شوێنی زیپکە لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. ئامانجی سەرەکی بەرهەمەکە\r\nکاتێک چارەسەری زیپکە دەکەیت، زۆرجار پێستت تووشی وشکبوونەوەی زۆر، سووربوونەوە و هەستیاری دەبێت. ئەم کرێمە ئیشی ئەوەیە کە:\r\n• پێستەکە بژێنێتەوە: ئەو شێدارییەی بەهۆی دەرمانەکانەوە لەدەستچووە، بۆی دەگەڕێنێتەوە.\r\n• چاککردنەوەی بەربەستی پێست: یارمەتی نۆژەنکردنەوەی چینی پارێزەری پێست دەدات (Skin Barrier).\r\n• نەرمکردنەوە: کزانەوە و سووربوونەوەی پێست کەمدەکاتەوە.\r\n٢. پێکهاتە سەرەکییەکان (وەک لەسەر پاکەتەکە نووسراوە)\r\n• Niacinamide (4%): دژە هەوکردنە و یارمەتی ڕێکخستنی چەوری و کەمکردنەوەی پەڵەی سووری زیپکە دەدات.\r\n• Murumuru Butter (3%): پێستەکە بە قووڵی شێدار دەکات بێ ئەوەی کونیلەکان بگرێت.\r\n• Squalane (2%): ماددەیەکی سروشتییە کە پێست نەرم دەکات و نایەڵێت ئاوی پێستەکە هەڵم ببێت.\r\n• Bisabolol (0.5%): بۆ هێورکردنەوەی پێستی هەستیار و کەمکردنەوەی کزانەوە.\r\n• Vitamin E: وەک دژە ئۆکسان کاردەکات بۆ پاراستنی خانەکانی پێست.\r\n٣. خاڵە گرنگەکان\r\n• Non-comedogenic: واتە نابێتە هۆی دروستبوونی زیپکەی نوێ و کونیلەکان ناگرێت.\r\n• pH 6: هاوسەنگی سروشتی پێست دەپارێزێت.\r\n• بۆ کێ گونجاوە؟ تەنها بۆ پێستی چەور یان تێکەڵاو کە لەژێر چارەسەری زیپکەدایە و پێستەکەی زۆر وشک بووەتەوە.\r\nچۆن بەکاری بهێنیت؟\r\nبڕێکی گونجاو بدە لە دەموچاو و ملت و بە هێواشی مەساجی بۆ بکە تا هەمووی دەمژرێت. دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.','The primary purpose of the product\nWhen you treat acne, your skin often experiences extreme dryness, redness, and sensitivity. This cream works by:\n• Revitalize skin: Restores moisture lost due to medications.\n• Repair the skin barrier: Helps repair the skin barrier.\n• Softening: Reduces wrinkles and redness.\n2. Key ingredients (as stated on package)\n• Niacinamide (4%): Anti-inflammatory and helps regulate sebum and reduce red acne spots.\n• Murumuru Butter (3%): Deeply moisturizes skin without clogging pores.\n• Squalane (2%): A natural substance that softens the skin and prevents water from evaporating.\n• Bisabolol (0.5%): To soothe sensitive skin and reduce wrinkles.\n• Vitamin E: Acts as an antioxidant to protect skin cells.\n3. Important points\n• Non-comedogenic: means it does not cause new acne and does not clog pores.\n• pH 6: Maintains skin’s natural balance.\n• Who is it suitable for? Only for oily or combination skin that is undergoing acne treatment and has very dry skin.\nhow do you use it\nApply an appropriate amount to your face and neck and massage gently until it is all absorbed. You can use it twice a day (morning and night).','الهدف الأساسي للمنتج\nعند علاج حب الشباب، غالبًا ما تعاني البشرة من جفاف شديد واحمرار وحساسية. يعمل هذا الكريم من خلال:\n• تنشيط البشرة: استعادة الرطوبة المفقودة نتيجة استخدام الأدوية.\n• إصلاح حاجز البشرة: يساعد على إصلاح حاجز البشرة.\n• تنعيم البشرة: يقلل التجاعيد والاحمرار.\n\n٢. المكونات الرئيسية (كما هو موضح على العبوة)\n• نياسيناميد (٤٪): مضاد للالتهابات، يساعد على تنظيم إفراز الدهون وتقليل بقع حب الشباب الحمراء.\n• زبدة مورومورو (٣٪): ترطب البشرة بعمق دون سد المسام.\n• سكوالين (٢٪): مادة طبيعية تنعم البشرة وتمنع تبخر الماء.\n• بيسابولول (٠.٥٪): لتهدئة البشرة الحساسة وتقليل التجاعيد.\n• فيتامين هـ: يعمل كمضاد للأكسدة لحماية خلايا البشرة.\n\n٣. نقاط مهمة\n• غير كوميدوغينيك: أي أنه لا يسبب ظهور حب شباب جديد ولا يسد المسام.\n• درجة حموضة 6: تحافظ على التوازن الطبيعي للبشرة.\nلمن يناسب؟ يناسب البشرة الدهنية أو المختلطة التي تخضع لعلاج حب الشباب، والبشرة شديدة الجفاف.\n\nطريقة الاستخدام: ضعي كمية مناسبة على الوجه والرقبة، ودلكي بلطف حتى يتم امتصاصه بالكامل. يمكنكِ استخدامه مرتين يوميًا (صباحًا ومساءً).\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:27:49',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-35',0,0),(228,'فلود(شلە)ی تایبەت بە پێستی چەور و شوێنی زیپکە لە بڕاندی بابێی ئیسپانی','Fluid for oily skin and acne from the Spanish brand Babe','سائل للبشرة الدهنية وحب الشباب من ماركة Babe الإسبانية',' فلود(شلە)ی تایبەت بە پێستی چەور و شوێنی زیپکە لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پێکهاتەی سەرەکی: ڕێژەی 7% ئەسیدی گلایکۆلیک (Glycolic Acid) تێدایە کە کاردەکات بۆ نوێکردنەوەی خانەکانی پێست.\r\n• لابردنی خانە مردووەکان: یارمەتی پاککردنەوەی کونیلەکان دەدات و ڕێگری دەکات لە دروستبوونی زیپکەی نوێ.\r\n• کەمکردنەوەی شوێنەوار: کاریگەری هەیە لەسەر کاڵکردنەوەی پەڵە و شوێنەواری کۆنی زیپکە و ڕەقبوونی پێست.\r\n• کۆنترۆڵکردنی چەوری: ئاستی دەردانی چەوری پێست ڕێکدەخاتەوە و پێستەکە مات دەکات (بریقەی نامێنێت).\r\nچۆن بەکاردێت؟ (زۆر گرنگە):\r\n1. کاتی بەکارهێنان: تەنها لە شەواندا بەکاری بهێنە لەسەر پێستێکی پاک و وشک.\r\n2. خشتەی بەکارهێنان: بۆ ماوەی 3 هەفتە بەکاری بهێنە (شەوێک نا شەوێک)، پاشان لە هەفتەی چوارەمدا پشووی پێ بدە و بەکاری مەهێنە.\r\n3. پاراستن: بە هیچ شێوەیەک نزیکی چاو و لێو و برین مەخەرەوە.\r\n4. دژەخۆر: چونکە ئەسیدی تێدایە، پێست هەستیار دەکات بە خۆر؛ بۆیە زۆر گرنگە بەیانیان دژەخۆر بەکاربهێنیت.\r\nتێبینی:\r\n• ئاساییە ئەگەر لە سەرەتای بەکارهێنانی هەست بە کەمێک کزانەوە یان سووربوونەوە بکەیت، بەڵام ئەگەر زۆر بوو دەبێت ڕاوێژ بە پزیشک یان دەرمانساز بکەیت.\r\n• نابێت ڕاستەوخۆ دوای نەشتەرگەری یان چارەسەری پزیشکیی توندی پێست بەکاری بهێنیت.\r\n','Key Features:\n• Main ingredients: Contains 7% glycolic acid that works to renew skin cells.\n• Remove dead cells: Helps clear pores and prevent new acne from forming.\n• Scar reduction: Effective in fading scars, old acne scars and skin hardening.\n• Sebum Control: Regulates skin sebum secretion levels and dulls skin (loss of shine).\nhow is it used (very important):\n1. When to use: Use only at night on clean, dry skin.\n2. Schedule: Use for 3 weeks (overnight, not overnight), then rest and do not use in the fourth week.\n3. Protection: Do not put near eyes, lips or wounds.\n4. Sunscreen: Because it contains acid, it makes the skin sensitive to the sun; Therefore, it is very important to apply sunscreen in the morning.\nnotice:\n• It is normal to experience slight cramping or redness at the beginning of use, but if it is severe, consult a doctor or pharmacist.\n• Do not use immediately after surgery or acute medical treatment of the skin.','الميزات الرئيسية:\n• المكونات الرئيسية: يحتوي على 7% من حمض الجليكوليك الذي يعمل على تجديد خلايا البشرة.\n• إزالة الخلايا الميتة: يساعد على تنظيف المسام ومنع ظهور حب الشباب الجديد.\n• تقليل الندبات: فعال في إزالة الندبات، وندبات حب الشباب القديمة، وتصلب الجلد.\n• التحكم في إفراز الدهون: ينظم مستويات إفراز الدهون في البشرة ويمنحها النضارة.\n\nطريقة الاستخدام (هام جدًا):\n1. وقت الاستخدام: يُستخدم ليلًا فقط على بشرة نظيفة وجافة.\n2. جدول الاستخدام: يُستخدم لمدة 3 أسابيع (ليلاً، وليس ليلاً)، ثم يُستغنى عنه في الأسبوع الرابع.\n3. الحماية: تجنب ملامسته للعينين أو الشفتين أو الجروح.\n4. واقي الشمس: نظرًا لاحتوائه على حمض، فإنه يجعل البشرة حساسة لأشعة الشمس؛ لذلك، من المهم جدًا وضع واقي الشمس صباحًا.\n\nملاحظة:\n• من الطبيعي الشعور بتقلصات طفيفة أو احمرار في بداية الاستخدام، ولكن في حال كان الاحمرار شديدًا، يُرجى استشارة الطبيب أو الصيدلي.\n• لا تستخدم مباشرة بعد الجراحة أو العلاج الطبي الحاد للجلد.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:29:10',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'30ml','01-34',0,0),(229,'دژە خۆری تایبەت بە پێستی هەستیار و ناسکی منداڵان لە بڕاندی بابێی ئیسپانی','Sunscreen for children\'s sensitive skin from Spanish brand Babe','واقي شمس لبشرة الأطفال الحساسة من ماركة Babe الإسبانية','دژە خۆری تایبەت بە پێستی هەستیار و ناسکی منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەرز (SPF 50): پاراستنێکی زۆر باش دژی تیشکی (UVA و UVB) و تیشکی شاشەکان (HEV) و تیشکی ژێر سوور (IR-A) دابین دەکات.\r\n• فیلتەری مەعدەنی (100% Mineral Filters): ئەمە خاڵێکی زۆر گرنگە؛ چونکە فیلتەری کیمیایی تێدا نییە، بۆیە ئەگەری هەستیاری (Allergy) زۆر کەم دەکاتەوە و بۆ ئەو منداڵانەی پێستیان زۆر ناسکە یان ئەکزیمایان (Atopic Skin) هەیە، گونجاوترینە.\r\n• پێکهاتەی سووک (Super Fluid): شلەیە و زۆر بە ئاسانی بە پێستدا بڵاو دەبێتەوە و چەوری بەجێ ناهێڵێت.\r\n• ناسووتێتەوە: یەکێک لە باشترین سیفەتەکانی ئەوەیە کە چاو ناسووتێنێتەوە ئەگەر بەر چاوی منداڵەکە بکەوێت.\r\n• بێ بۆن و بەرگری ئاو: هیچ بۆنێکی پێوە نییە کە ببێتە هۆی هەستیاری، هەروەها لە کاتی ئارەق کردنەوە یان مەلەکردن زوو لاناچێت.\r\nپێکهاتە گرنگەکان:\r\nبەپێی زانیارییەکانی سەر پاکەتەکە، ئەمانەی تێدایە:\r\n• Prebiotics: بۆ پاراستنی بەکتریای سوودبەخشی سەر پێست و بەهێزکردنی بەرگری پێست.\r\n• Panthenol: بۆ ئارامکردنەوە و شێدارکردنەوەی پێست.\r\n• Zinc Oxide & Titanium Dioxide: وەک قەڵغانێک کاردەکەن بۆ گەڕاندنەوەی تیشکی خۆر.\r\nچۆنیەتی بەکارهێنان:\r\n1. ڕاوەشاندن: پێش بەکارهێنان پێویستە بە باشی ڕایبوەشێنیت (وەک لەسەر پاکەتەکە بە هێمای Shake نیشان دراوە).\r\n2. کات: ٢٠ خولەک پێش ئەوەی منداڵەکە بڕواتە بەر خۆر، بڕێکی گونجاوی لێ بدە.\r\n3. دووبارەکردنەوە: هەر ٢ کاتژمێر جارێک یان دوای مەلەکردن و وشککردنەوەی پێست بە خاولی، دووبارە لێی بدەرەوە.\r\n','Key Features:\n• High Protection (SPF 50): Provides excellent protection against radiation (UVA and UVB), screen radiation (HEV) and infrared radiation (IR-A).\n• Mineral Filters (100% Mineral Filters): This is a very important point; Because it does not contain chemical filters, it greatly reduces the risk of allergies and is suitable for children with very sensitive skin or atopic skin.\n• Super Fluid: It is liquid and spreads very easily through the skin and does not leave oil.\n• Does not burn: One of its best features is that it does not burn the eyes if they come into contact with the child\'s eyes.\n• Odorless and water resistant: No odor that can cause allergies, and does not disappear quickly when sweating or swimming.\nImportant Ingredients:\nAccording to the packaging, it contains:\n• Prebiotics: To protect beneficial bacteria on the skin and strengthen the skin\'s immune system.\n• Panthenol: To soothe and moisturize the skin.\n• Zinc Oxide & Titanium Dioxide: Act as a shield to reflect sunlight.\nHow to use:\n1. Shake: Shake well before use (as indicated on the packaging by the Shake symbol).\n2. Time: Apply an appropriate amount 20 minutes before sun exposure.\n3. Repeat: Reapply every 2 hours or after swimming and towel drying.','الميزات الرئيسية:\n• حماية عالية (SPF 50): يوفر حماية ممتازة ضد الأشعة فوق البنفسجية (UVA وUVB)، وأشعة الشمس (HEV)، والأشعة تحت الحمراء (IR-A).\n• فلاتر معدنية (فلاتر معدنية 100%): هذه ميزة بالغة الأهمية؛ فخلوه من الفلاتر الكيميائية يقلل بشكل كبير من خطر الحساسية، وهو مناسب للأطفال ذوي البشرة الحساسة جدًا أو المصابين بالتهاب الجلد التأتبي.\n• قوام سائل: يتميز بقوامه السائل وسهولة انتشاره على البشرة دون ترك أي أثر دهني.\n• لا يسبب حرقانًا: من أهم مميزاته أنه لا يسبب حرقانًا في العينين عند ملامسته لعيون الطفل.\n• عديم الرائحة ومقاوم للماء: لا توجد به رائحة قد تسبب الحساسية، ولا يزول بسرعة عند التعرق أو السباحة.\n\n• المكونات الرئيسية:\nوفقًا للعبوة، يحتوي على:\n• البريبايوتكس: لحماية البكتيريا النافعة على البشرة وتقوية جهاز المناعة.\n• البانثينول: لتهدئة البشرة وترطيبها.\n• أكسيد الزنك وثاني أكسيد التيتانيوم: يعملان كحاجز عاكس لأشعة الشمس.\n\nطريقة الاستخدام:\n1. رج العبوة جيداً قبل الاستخدام (كما هو موضح على العبوة برمز الرج).\n2. الوقت: ضع كمية مناسبة قبل التعرض للشمس بـ 20 دقيقة.\n3. التكرار: أعد وضع المنتج كل ساعتين أو بعد السباحة والتجفيف بالمنشفة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:30:51',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-33',0,0),(230,'دژە خۆری تایبەت بە کێشەی پەڵە و ناڕێکی ڕەنگی پێست لە بڕاندی بابێی ئیسپانی','Sunscreen for spots and skin irregularities from the Spanish brand Babe','واقي شمسي للبقع وعيوب البشرة من ماركة Babe الإسبانية','دژە خۆری تایبەت بە کێشەی پەڵە و ناڕێکی ڕەنگی پێست لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پاراستنێکی تەواو (SPF 50)\r\nئەم دژەخۆرە تەنها دژی تیشکی خۆر نییە، بەڵکو پێست دەپارێزێت لە:\r\n• UVB + UVA: پاراستنی بەهێز دژی سووتان و پیربوونی پێست.\r\n• HEV (تیشکی شین): پاراستن لەو تیشکەی لە شاشەی مۆبایل و کۆمپیوتەرەوە دەردەچێت.\r\n• IR-A (تیشکی ژێر سوور): پاراستن لە زیانەکانی گەرمی.\r\n٢. پێکهاتە سەرەکییەکان بۆ چارەسەری پەڵە\r\nئەم بەرهەمە زیاترە لە دژەخۆرێک، چونکە ئەم ماددانەی تێدایە:\r\n• ترشی ترانێکسامیک (Tranexamic Acid): یارمەتیدەرێکی بەهێزە بۆ کەمکردنەوەی پەڵەی ڕەق و ڕێگریگرتن لە دروستبوونی پەڵەی نوێ.\r\n• ڤیتامین C (Stable Vitamin C): ڕەنگی پێست ڕوون دەکاتەوە و گەشاوەیی پێ دەبەخشێت، هەروەها دژە ئۆکسانێکی بەهێزە.\r\n٣. تایبەتمەندییە گشتییەکانی تر\r\n• تێکستەری سووپەر فلۆید (Super Fluid): شلەیەکی زۆر سووکە، بە خێرایی هەڵدەمژرێت و هەست بە چەوری ناکەیت لەسەر پێست.\r\n• دژە پیسبوونی هەوا (Anti-Pollution): پێست لە تۆز و غوباری ناو شار دەپارێزێت.\r\n• چاو ناسووتێنێت: بە جۆرێک دروستکراوە کە لە کاتی ئارەقکردنەوەدا چاوەکانت بێزار نەکات.\r\n• بۆ هەموو جۆرە پێستێک گونجاوە: تەنانەت پێستی هەستیاریش.\r\nچۆنیەتی بەکارهێنان:\r\n١. پێش بەکارهێنان باش ڕایوەشێنە.\r\n٢. بڕێکی گونجاو بدە لە دەموچاو و ملت ٢٠ خولەک پێش ئەوەی بچیتە بەر خۆر.\r\n٣. ئەگەر بۆ ماوەیەکی زۆر لەبەر خۆر بوویت، هەموو ٢ کاتژمێر جارێک نوێی بکەرەوە.\r\n','Full protection (SPF 50)\nThis sunscreen not only protects against the sun, but also protects the skin from:\n• UVB + UVA: Strong protection against skin burns and aging.\n• HEV (blue light): Protection from radiation emitted by mobile phone and computer screens.\n• IR-A (infrared radiation): protection against thermal damage.\n2. Essential Ingredients for Scar Treatment\nThis product is more than a sunscreen, as it contains:\n• Tranexamic Acid: A powerful helper to reduce hard spots and prevent new ones from forming.\n• Stable Vitamin C: Brightens and brightens skin, and is a powerful antioxidant.\n3. Other general features\n• Super Fluid Texture: Very light liquid, absorbs quickly and does not feel greasy on the skin.\n• Anti-Pollution: Protects skin from city dust.\n• Non-Eye Burn: Designed to not irritate your eyes while sweating.\n• Suitable for all skin types: even sensitive skin.\nHow to use:\n1. Shake well before use.\n2. Apply an appropriate amount to your face and neck 20 minutes before going out in the sun.\n3. If you have been in the sun for a long time, refresh every 2 hours.',' حماية كاملة (SPF 50)\nلا يقتصر هذا الواقي الشمسي على الحماية من أشعة الشمس فحسب، بل يحمي البشرة أيضًا من:\n• الأشعة فوق البنفسجية UVB وUVA: حماية قوية من حروق الشمس وعلامات الشيخوخة.\n• الضوء الأزرق (HEV): حماية من الإشعاع المنبعث من شاشات الهواتف المحمولة وأجهزة الكمبيوتر.\n• الأشعة تحت الحمراء (IR-A): حماية من التلف الحراري.\n\n٢. مكونات أساسية لعلاج الندبات\nهذا المنتج أكثر من مجرد واقٍ شمسي، فهو يحتوي على:\n• حمض الترانيكساميك: مُساعد فعّال في تقليل البقع الصلبة ومنع ظهور بقع جديدة.\n• فيتامين سي ثابت: يُفتّح البشرة ويُضفي عليها نضارةً، وهو مضاد أكسدة قوي.\n\n٣. خصائص عامة أخرى\n• قوام سائل فائق النعومة: سائل خفيف جدًا، يمتصه الجلد بسرعة ولا يترك ملمسًا دهنيًا.\n• مضاد للتلوث: يحمي البشرة من غبار المدينة.\n• لا يُسبب تهيجًا للعينين: مُصمم خصيصًا لعدم التسبب في تهيج العينين أثناء التعرق.\n• مناسب لجميع أنواع البشرة: حتى البشرة الحساسة. طريقة الاستخدام:\n١. رج العبوة جيداً قبل الاستخدام.\n٢. ضع كمية مناسبة على وجهك ورقبتك قبل ٢٠ دقيقة من التعرض لأشعة الشمس.\n٣. إذا كنت قد تعرضت لأشعة الشمس لفترة طويلة، جدد وضع المنتج كل ساعتين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:32:09',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-32',0,0),(231,'دژە خۆری ڕەنگدار تایبەت بە پێستی وشک لە بڕاندی بابێی ئیسپانی','Colored sunscreen for dry skin from Spanish brand Babe','واقي شمس ملون للبشرة الجافة من ماركة Babe الإسبانية','دژە خۆری ڕەنگدار تایبەت بە پێستی وشک لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەهێز (SPF 50): پێست دەپارێزێت لە تیشکی UVA و UVB، هەروەها پارێزگاری دەکات لە تیشکی شاشەکان (HEV) و تیشکی ژێر سوور (IR-A).\r\n• ڕەنگدار (Color): ئەم جۆرەیان ڕەنگی تێدایە، وەک \"تەکنیک\" یان \"ئەساسێکی سووک\" کاردەکات؛ ڕەنگی پێست یەکدەخات و پەڵە و ناتەواوییەکان دادەپۆشێت بەبێ ئەوەی هەست بە قورسی بکەیت.\r\n• هایالۆرۆنیک ئەسید: ڕێژەیەک لەم ماددەیەی تێدایە کە یارمەتی شێدارکردنەوەی پێست دەدات و نایەڵێت وشک ببێتەوە.\r\n• دژە پیسبوونی ژینگە: پێست دەپارێزێت لە تەپوتۆز و کاریگەرییە خراپەکانی دەوروبەر.\r\n٢. بۆ کێ گونجاوە؟\r\n• بۆ هەموو جۆرە پێستەکان گونجاوە، تەنانەت پێستی هەستیاریش.\r\n• زۆر باشە بۆ ئەو کەسانەی حەز بە بەکارهێنانی ئەساسی قورس ناکەن و دەیانەوێت ڕەنگی پێستیان سروشتی و جوان دەربکەوێت.\r\n٣. خاڵە ئەرێنییەکان:\r\n• زۆر سووکە (Super Fluid): بە خێرایی بە پێستدا دەچێت و چەوری جێناهێڵێت.\r\n• چاو ناسووتێنێت: وەک لەسەر کارتۆنەکە نووسراوە (Does not sting eyes).\r\n• دژە ئاوە: بەرگری هەیە بەرامبەر ئارەق کردن و ئاو.\r\n٤. چۆنیەتی بەکارهێنان:\r\n• پێش بەکارهێنان پێویستە بەلەرزێنرێت (ڕاوەشێنرێت).\r\n• ٢٠ خولەک پێش چوونە بەردەم خۆر بەکاری بهێنە.\r\n• ئەگەر بۆ ماوەیەکی زۆر لەبەر خۆر بوویت، باشترە هەر ٢ کاتژمێر جارێک نوێی بکەیتەوە.\r\n','Key Features:\n• Strong protection (SPF 50): Protects skin from UVA and UVB rays, as well as protection from screens (HEV) and infrared (IR-A).\n• Color: This type contains pigment, acting as a \"technique\" or \"light foundation\"; It unifies skin tone and covers blemishes and imperfections without feeling heavy.\n• Hyaluronic acid: Contains an amount of this substance that helps moisturize the skin and prevents it from drying out.\n• Anti-pollution: Protects skin from dust and adverse environmental effects.\n2. Who is it suitable for?\n• Suitable for all skin types, even sensitive skin.\n• Great for people who do not like to use heavy foundation and want their skin color to look natural and beautiful.\n3. Positive points:\n• Super Fluid: Absorbs quickly into the skin and does not leave grease.\n• Does not sting eyes: As stated on the carton (Does not sting eyes).\n• Waterproof: Resistant to sweat and water.\n4. How to use:\n• Shake (shake) before use.\n• Apply 20 minutes before going out in the sun.\n• If you have been in the sun for a long time, it is best to renew every 2 hours.','الميزات الرئيسية:\n• حماية قوية (SPF 50): يحمي البشرة من أشعة UVA وUVB، بالإضافة إلى الحماية من أشعة الشمس (HEV) والأشعة تحت الحمراء (IR-A).\n• اللون: يحتوي هذا النوع على صبغة تعمل كـ\"كريم أساس خفيف\"؛ فهو يوحد لون البشرة ويخفي الشوائب والعيوب دون أن يثقلها.\n• حمض الهيالورونيك: يحتوي على كمية من هذه المادة التي تساعد على ترطيب البشرة ومنع جفافها.\n• مضاد للتلوث: يحمي البشرة من الغبار والآثار البيئية الضارة.\n\nلمن يناسب؟\n• مناسب لجميع أنواع البشرة، حتى الحساسة منها.\n• مثالي لمن لا يفضلون استخدام كريم أساس ثقيل ويرغبون في الحصول على لون بشرة طبيعي وجميل.\n\nالمزايا:\n• انسيابي للغاية: يمتصه الجلد بسرعة ولا يترك أي أثر دهني.\n• لا يسبب تهيجًا للعينين: كما هو موضح على العبوة (لا يسبب تهيجًا للعينين).\n• مقاوم للماء: مقاوم للعرق والماء.\n\n٤. طريقة الاستخدام:\n• رج العبوة جيداً قبل الاستخدام.\n• ضعه قبل ٢٠ دقيقة من التعرض لأشعة الشمس.\n• إذا كنت قد تعرضت لأشعة الشمس لفترة طويلة، يُفضل إعادة وضعه كل ساعتين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:33:47',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-31',0,0),(232,'سیڕۆمی شێدارکەرەوەی پێست لە بڕاندی بابێی ئیسپانی','Moisturizing serum from Spanish brand Babe','سيروم مرطب من ماركة Babe الإسبانية','سیڕۆمی شێدارکەرەوەی پێست لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'پێکهاتە سەرەکییەکانی:\r\n• Hyaluronic Acid (ترشی هیالۆرۆنیک): بە سێ کێشی جیاوازی گەردیلەیی تێدایە (بەرز، مامناوەند، نزم)، ئەمەش وادەکات شێدارییەکە بگاتە قووڵایی پێست و نەک تەنها لەسەر ڕووکەش بمێنێتەوە.\r\n• Panthenol (پانتینۆڵ): یارمەتی چاککردنەوە و هێورکردنەوەی پێست دەدات.\r\n• Prebiotics (پریبایۆتیک): بۆ پاراستنی هاوسەنگی بەکتریا سوودبەخشەکانی پێست و بەهێزکردنی بەربەستی پارێزەری پێست.\r\nسوودەکانی ئەم سێرمە:\r\n1. شێدارکردنێکی قووڵ: شێدارییەکی زۆر بە پێست دەبەخشێت کە بۆ ماوەیەکی درێژ دەمێنێتەوە.\r\n2. پڕکردنەوە (Plumping Effect): یارمەتی پڕکردنەوەی هێڵە وردەکانی دەموچاو و چرچییەکان دەدات بەهۆی پڕبوونی پێست لە شێداری.\r\n3. نەرمکردن: پێست زۆر نەرم و ساف دەکات.\r\n4. گونجاو بۆ هەمووان: ئەم سێرمە بۆ هەموو جۆرە پێستێک گونجاوە، تەنانەت بۆ پێستی هەستیاریش چونکە لەژێر چاودێری پزیشکی پێست و چاو تاقیکراوەتەوە.\r\nشێوازی بەکارهێنان:\r\n• ڕۆژانە دوو جار (بەیانیان و شەوان).\r\n• ٣ بۆ ٤ دڵۆپ بدە لە پێستی خاوێن و وشک (دەموچاو، مل، و سنگ).\r\n• بە هێواشی مەساجی پێ بکە تا بەتەواوی هەڵدەمژرێت.\r\n• دوای ئەم سێرمە، دەتوانیت کرێمی شێدارکەرەوەی ئاسایی خۆت بەکاربهێنیت.\r\n','Key ingredients:\n• Hyaluronic Acid: Contained in three different molecular weights (high, medium, low), this allows moisture to reach deep into the skin and not just stay on the surface.\n• Panthenol: Helps repair and soothe the skin.\n• Prebiotics: To maintain the balance of beneficial skin bacteria and strengthen the skin\'s protective barrier.\nBenefits of this serum:\n1. Deep moisturizing: Provides long-lasting moisture.\n2. Plumping Effect: Helps fill in fine facial lines and wrinkles as the skin is replenished with moisture.\n3. Softening: Makes the skin very soft and clean.\n4. Suitable for everyone: This serum is suitable for all skin types, even sensitive skin because it has been tested under the supervision of a dermatologist and eye doctor.\nHow to use:\n• Twice daily (morning and night).\n• Apply 3 to 4 drops to clean, dry skin (face, neck, and chest).\n• Massage gently until completely absorbed.\n• After this serum, you can use your regular moisturizer.','المكونات الرئيسية:\n• حمض الهيالورونيك: متوفر بثلاثة أوزان جزيئية مختلفة (عالية، متوسطة، منخفضة)، مما يسمح للرطوبة بالتغلغل في أعماق البشرة بدلاً من البقاء على سطحها فقط.\n• بانثينول: يساعد على ترميم البشرة وتهدئتها.\n• البريبايوتكس: للحفاظ على توازن البكتيريا النافعة في البشرة وتقوية حاجزها الواقي.\n\nفوائد هذا السيروم:\n1. ترطيب عميق: يوفر ترطيبًا يدوم طويلاً.\n2. تأثير ملء البشرة: يساعد على ملء الخطوط الدقيقة والتجاعيد في الوجه من خلال تجديد رطوبة البشرة.\n3. تنعيم البشرة: يجعل البشرة ناعمة ونظيفة للغاية.\n4. مناسب للجميع: هذا السيروم مناسب لجميع أنواع البشرة، حتى الحساسة منها، لأنه تم اختباره تحت إشراف أطباء الجلدية والعيون.\n\nطريقة الاستخدام:\n• مرتين يوميًا (صباحًا ومساءً).\n• ضعي 3 إلى 4 قطرات على بشرة نظيفة وجافة (الوجه، الرقبة، والصدر).\n• دلكي بلطف حتى يتم امتصاصه بالكامل.\n\nاستخدميه مرتين يوميًا (صباحًا ومساءً).\n• ضعي 3 إلى 4 قطرات على بشرة نظيفة وجافة (الوجه، الرقبة، والصدر).\nدلكي بلطف حتى يتم امتصاصه بالكامل. • بعد استخدام هذا السيروم، يمكنك استخدام مرطبك المعتاد.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:35:00',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'30ml','01-30',0,0),(233,'دژە خۆری تایبەت بە پێستی چەور و تێکەڵ لە بڕاندی بابێی ئیسپانی','Sunscreen for oily and combination skin from Spanish brand Babe','واقي شمس للبشرة الدهنية والمختلطة من ماركة Babe الإسبانية','دژە خۆری تایبەت بە پێستی چەور و تێکەڵ لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەهێز (SPF 50): پێست دەپارێزێت لە تیشکی (UVB + UVA) و هەروەها تیشکی شینی شاشەکان (HEV) و تیشکی ژێر سوور (IR-A).\r\n• ماتکەرەوە (Mattifying): برەقینەوەی پێست ناهێڵێت و شێوەیەکی سروشتی و وشک بە پێست دەبەخشێت (بەسوودە بۆ ئەوانەی زوو پێستیان دەدرەوشێتەوە بەهۆی چەورییەوە).\r\n• نایاسیناماید (Niacinamide 4%): ئەم ماددەیەی تێدایە کە یارمەتی ڕێکخستنی دەردانی چەوری پێست دەدات و پەڵە و سووربوونەوەی پێست کەمدەکاتەوە.\r\n• کارنۆسین (Carnosine 0.20%): ماددەیەکی دژە ئۆکسانە کە پێست دەپارێزێت لە پیربوون و پیسبوونی ژینگە.\r\nسوودەکانی:\r\n• شێوەی فلۆید (Fluid): زۆر سووکە و وەک ئاو وایە، زوو هەڵدەمژرێت و هەست بە قورسی ناکەیت لەسەر دەموچاو.\r\n• بێ چەوری (Oil-Free): نابێتە هۆی دروستبوونی زیپکە (Non-comedogenic).\r\n• چاو ناسووتێنێت: بەجۆرێک دروستکراوە کە ئەگەر بچێتە نزیک چاویش، ئازاری نییە.\r\n• دژە ئاوە: بەرگرییەکی باشی هەیە بەرامبەر ئارەقکردنەوە و ئاو.\r\nچۆنیەتی بەکارهێنان:\r\n• پێش بەکارهێنان باش ڕایوەشێنە.\r\n• ٢٠ خولەک پێش چوونە بەر خۆر، بڕێکی گونجاو بدە لە دەموچاو و ملت.\r\n• ئەگەر بۆ ماوەیەکی زۆر لەبەر خۆر بوویت، پێویستە هەموو ٢ کاتژمێر جارێک نوێی بکەیتەوە.\r\nتێبینی: ئەم دژەخۆرە زۆر گونجاوە بۆ بەکارهێنانی ڕۆژانە، بەتایبەت ئەگەر کێشەی چەوری زۆری پێستت هەیە.\r\n','Key Features:\n• Strong protection (SPF 50): Protects skin from UVB + UVA as well as screen blue light (HEV) and infrared light (IR-A).\n• Mattifying: Prevents shine and gives the skin a natural, dry appearance (useful for those whose skin shines quickly due to oil).\n• Niacinamide (Niacinamide 4%): Contains this substance that helps regulate the secretion of skin oil and reduces spots and redness.\n• Carnosine (Carnosine 0.20%): An antioxidant that protects the skin from aging and environmental pollution.\nBenefits:\n• Fluid: Very light and watery, absorbs quickly and does not feel heavy on the face.\n• Oil-Free: Non-comedogenic.\n• Does not burn the eyes: It is designed to be painless even if it comes near the eyes.\n• Waterproof: Good resistance to sweat and water.\nHow to use:\n• Shake well before use.\n• Apply an appropriate amount to your face and neck 20 minutes before going out in the sun.\n• If you have been in the sun for a long time, you should renew it every 2 hours.\nNote: This sunscreen is very suitable for daily use, especially if you have a lot of oily skin.','الميزات الرئيسية:\n• حماية قوية (SPF 50): يحمي البشرة من الأشعة فوق البنفسجية UVB وUVA، بالإضافة إلى الضوء الأزرق المنبعث من الشاشات (HEV) والأشعة تحت الحمراء (IR-A).\n• مطفي: يمنع اللمعان ويمنح البشرة مظهرًا جافًا طبيعيًا (مفيد لمن يعانون من لمعان البشرة السريع بسبب الزيوت).\n• نياسيناميد (4%): يحتوي على هذه المادة التي تساعد على تنظيم إفراز الزيوت في البشرة، وتقلل من البقع والاحمرار.\n• كارنوزين (0.20%): مضاد للأكسدة يحمي البشرة من علامات الشيخوخة والتلوث البيئي.\n• سائل: خفيف جدًا ومائي، يمتص بسرعة ولا يترك شعورًا بالثقل على الوجه.\n• خالٍ من الزيوت: لا يسد المسام.\n• لا يسبب حرقانًا للعينين: مصمم ليكون غير مؤلم حتى عند ملامسته للعينين.\n• مقاوم للماء: مقاومة جيدة للعرق والماء.\n\nطريقة الاستخدام:\n• رج العبوة جيدًا قبل الاستخدام.\n• ضعي كمية مناسبة على وجهكِ ورقبتكِ قبل 20 دقيقة من التعرض لأشعة الشمس.\n• إذا كنتِ قد تعرضتِ للشمس لفترة طويلة، يُنصح بتجديده كل ساعتين.\n\nملاحظة: هذا الواقي الشمسي مناسب جدًا للاستخدام اليومي، خاصةً إذا كانت بشرتكِ دهنية.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:36:43',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-29',0,0),(234,'دژە خۆری تایبەت بە پێستی ناسک و هەستیار لە بڕاندی بابێی ئیسپانی','Sunscreen for delicate and sensitive skin from Spanish brand Babe','واقي شمس للبشرة الحساسة والرقيقة من ماركة Babe الإسبانية','دژە خۆری تایبەت بە پێستی ناسک و هەستیار لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی تەواو (SPF 50): نەک تەنها لە تیشکی UVB و UVA دەتپارێزێت، بەڵکو دژی تیشکی شاشەکان (تیشکی شین - HEV) و تیشکی ژێرسوور (IR-A) کار دەکات.\r\n• ١٠٠٪ فلتەری کانزایی (Mineral): بە پێچەوانەی دژەخۆرە کیمیاییەکان، ئەمە فلتەری کانزایی (وەک Zinc Oxide و Titanium Dioxide) بەکاردەهێنێت کە لەسەر ڕووی پێست دەمێننەوە و تیشکەکە دەدەنەوە، ئەمەش وادەکات زۆر گونجاو بێت بۆ پێستی ناسک و هەستیار.\r\n• پێکهاتەی سووک (Super Fluid): سەرەڕای ئەوەی کانزاییە، بەڵام شلەیەکی زۆر سووکی هەیە و بە خێرایی هەڵدەمژرێت، پێست چەور ناکات و سپیاتی (White cast) بەجێناهێڵێت.\r\nپێکهاتە گرنگەکانی ناوی:\r\n• 1% Microbiome Photoprotector: یارمەتی پاراستنی بەکتریا سوودبەخشەکانی سەر پێست دەدات و بەرگری پێست بەهێز دەکات.\r\n• 1% Panthenol: پێست هێمن دەکاتەوە و کار بۆ شێدارکردنەوە و چاککردنەوەی خانەکان دەکات.\r\n• 0.2% Carnosine: وەک دژە ئۆکسانێکی بەهێز کاردەکات بۆ پاراستنی پێست لە پیربوون و پیسبوونی ژینگە.\r\nخاڵە ئەرێنییەکانی تر:\r\n• بێ بۆنە (Fragrance Free): بۆ ئەوەی هیچ حەساسیەتێک دروست نەکات.\r\n• دژە ئاوە: بەرگەی ئارەق کردنەوە و ئاو دەگرێت.\r\n• چاو ناسووتێنێت: تاقیکردنەوەی بۆ کراوە کە بۆ دەوروبەری چاویش بێ زیانە.\r\nچۆنیەتی بەکارهێنان:\r\n١. پێش بەکارهێنان بە باشی ڕایوەشێنە (چونکە پێکهاتەکەی زۆر شلەیە).\r\n٢. ٢٠ خولەک پێش چوونە بەر خۆر بە یەکسانی بیدە لە دەموچاو و ملت.\r\n٣. ئەگەر زۆر لەبەر خۆر بوویت، هەموو ٢ کاتژمێر جارێک نوێی بکەرەوە.\r\n','Key Features:\n• Full Protection (SPF 50): Protects not only against UVB and UVA rays, but also works against radiation from screens (blue light - HEV) and infrared radiation (IR-A).\n• 100% Mineral Filter: Unlike chemical sunscreens, this uses mineral filters (such as Zinc Oxide and Titanium Dioxide) that stay on the skin\'s surface and reflect the rays, making it ideal for delicate and sensitive skin.\n• Super Fluid: Despite being mineral, it has a very light liquid that is absorbed quickly, does not oil the skin and does not leave a white cast.\nImportant components of the name:\n• 1% Microbiome Photoprotector: Helps protect beneficial bacteria on the skin and strengthens the skin\'s immune system.\n• 1% Panthenol: Soothes the skin and works to moisturize and repair cells.\n• 0.2% Carnosine: Acts as a powerful antioxidant to protect skin from aging and environmental pollution.\nOther positive points:\n• Fragrance Free: To avoid any allergies.\n• Waterproof: Sweat and water resistant.\n• Does not burn the eyes: Tested to be harmless to the eye area.\nHow to use:\n1. Shake well before use (because the texture is very liquid).\n2. Apply evenly to face and neck 20 minutes before sun exposure.\n3. If you are in the sun a lot, refresh every 2 hours.','الميزات الرئيسية:\n• حماية كاملة (SPF 50): لا يحمي فقط من أشعة UVB وUVA، بل يحمي أيضًا من الإشعاع المنبعث من الشاشات (الضوء الأزرق - HEV) والأشعة تحت الحمراء (IR-A).\n• فلتر معدني 100%: على عكس واقيات الشمس الكيميائية، يستخدم هذا المنتج فلاتر معدنية (مثل أكسيد الزنك وثاني أكسيد التيتانيوم) تبقى على سطح الجلد وتعكس الأشعة، مما يجعله مثاليًا للبشرة الحساسة.\n• قوام سائل فائق: على الرغم من كونه معدنيًا، إلا أنه سائل خفيف جدًا يمتصه الجلد بسرعة، ولا يترك طبقة دهنية أو بيضاء.\n\n• مكونات هامة:\n• 1% واقي ضوئي للميكروبيوم: يساعد على حماية البكتيريا النافعة على الجلد ويقوي جهاز المناعة.\n• 1% بانثينول: يلطف البشرة ويرطبها ويصلح خلاياها.\n• 0.2% كارنوزين: يعمل كمضاد أكسدة قوي لحماية البشرة من الشيخوخة والتلوث البيئي.\n\nمزايا أخرى:\n• خالٍ من العطور: لتجنب أي حساسية.\n• مقاوم للماء: مقاوم للعرق والماء.\n• لا يسبب تهيجًا للعينين: تم اختباره وثبت أنه آمن على منطقة العين.\n\nطريقة الاستخدام:\n1. رج العبوة جيدًا قبل الاستخدام (لأن قوامه سائل جدًا).\n2. ضعيه بالتساوي على الوجه والرقبة قبل التعرض للشمس بـ 20 دقيقة.\n3. إذا كنتِ تتعرضين للشمس لفترات طويلة، كرري وضعه كل ساعتين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:38:03',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-28',0,0),(235,'دژە خۆری ڕەنگدار تایبەت بە پێستی چەور و تێکەڵ لە بڕاندی بابێی ئیسپانی','Pigmented sunscreen for oily and combination skin from Spanish brand Babe','واقي شمس ملون للبشرة الدهنية والمختلطة من ماركة BABE الإسبانية','دژە خۆری ڕەنگدار تایبەت بە پێستی چەور و تێکەڵ لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەهێز (SPF 50): پێست دەپارێزێت لە تیشکی UVA و UVB، هەروەها دژە تیشکی شاشە (HEV) و تیشکی ژێر سوورە (IR-A).\r\n• ڕەنگدارە (Color): ئەم جۆرەیان ڕەنگی تێدایە، وەک \"بی بی کرێم\" کاردەکات؛ ڕەنگی پێست یەکدەخات و پەڵە و کەم‌وکوڕییە سووکەکانی پێست دادەپۆشێت، پێویستت بە بەکارهێنانی ئەساس (Foundation) نابێت.\r\n• ماتکەرەوە (Mattifying): چەوری پێست کۆنترۆڵ دەکات و نایەڵێت پێست ببریسکێتەوە، ئەمەش زۆر گونجاوە بۆ ئەو کەسانەی پێستیان زوو چەور دەبێت.\r\n• نایاسیناماید (Niacinamide 4%): ڕێژەیەکی باشی نایاسینامایدی تێدایە کە یارمەتی کۆنترۆڵکردنی چەوری دەدات، سووربوونەوە کەم دەکاتەوە و بەربەستی پارێزەری پێست بەهێز دەکات.\r\n• کارنۆسین (Carnosine 0.2%): دژە ئۆکسانێکی بەهێزە کە پێست لە پیسبوونی ژینگە و پیربوونی پێشوەختە دەپارێزێت.\r\nسوودەکانی:\r\n• نازەردێت (Oil-Free): ڕێگری دەکات لە دروستبوونی زیپکە و گیرانی کونیەلەکانی پێست.\r\n• چاو ناسووتێنێت: تەکنەلۆژیای تێدایە کە لە کاتی ئارەقکردنەوەدا چاوەکانت بێزار ناکات.\r\n• بەرگری ئاو: لە کاتی ئارەقکردنەوە یان تەڕبووندا بە ئاسانی لاناچێت.\r\n• شێوەیەکی سروشتی: تێکستەرەکەی زۆر سووکە (Fluid) و بە خێرایی هەڵدەمژرێت بێ ئەوەی هەست بە قورسی بکەیت لەسەر دەموچاوت.\r\nچۆن بەکاری بهێنیت؟\r\nبڕێکی گونجاو لە دژەخۆرەکە بدە لە دەموچاو و ملت ٢٠ خولەک پێش ئەوەی بچیتە بەر هەتاو. پێویستە هەموو ٢ کاتژمێر جارێک نوێی بکەیتەوە ئەگەر لەبەر هەتاو بوویت.\r\n','Key Features:\n• Strong protection (SPF 50): Protects skin from UVA and UVB rays, and is anti-screen (HEV) and infrared (IR-A).\n• Color: This type contains color, acts as a BB cream; Unifies skin tone and covers light spots and imperfections, you don\'t need to use foundation.\n• Mattifying: Controls skin oil and prevents shine, which is very suitable for people with oily skin.\n• Niacinamide (Niacinamide 4%): Contains a good amount of niacinamide that helps control oiliness, reduces redness and strengthens the skin’s protective barrier.\n• Carnosine (Carnosine 0.2%): A powerful antioxidant that protects the skin from environmental pollution and premature aging.\nBenefits:\n• Oil-Free: Prevents acne and clogged pores.\n• Doesn’t burn eyes: Contains technology that won’t irritate your eyes while sweating.\n• Water resistance: Does not remove easily when sweating or getting wet.\n• Natural texture: The texture is very light (Fluid) and absorbs quickly without feeling heavy on your face.\nhow do you use it\nApply an appropriate amount of sunscreen to your face and neck 20 minutes before going out in the sun. You should renew every 2 hours if you are in the sun.','الميزات الرئيسية:\n• حماية قوية (SPF 50): يحمي البشرة من أشعة UVA وUVB، كما أنه مضاد للضوء الأزرق (HEV) والأشعة تحت الحمراء (IR-A).\n• لون: يحتوي هذا النوع على لون، ويعمل ككريم BB؛ يوحد لون البشرة ويخفي البقع الفاتحة والعيوب، فلا حاجة لاستخدام كريم أساس.\n• مطفي: يتحكم في إفراز الزيوت ويمنع اللمعان، وهو مناسب جدًا للبشرة الدهنية.\n• نياسيناميد (4%): يحتوي على نسبة جيدة من النياسيناميد الذي يساعد على التحكم في إفراز الزيوت، ويقلل الاحمرار، ويقوي حاجز البشرة الواقي.\n• كارنوزين (0.2%): مضاد أكسدة قوي يحمي البشرة من التلوث البيئي والشيخوخة المبكرة.\n\n• فوائد:\n• خالٍ من الزيوت: يمنع ظهور حب الشباب وانسداد المسام.\n• لا يسبب حرقان العينين: يحتوي على تقنية لا تسبب تهيج العينين حتى مع التعرق.\n• مقاومة للماء: لا يزول بسهولة عند التعرق أو البلل.\n• قوام طبيعي: قوامه خفيف جدًا (سائل) ويمتص بسرعة دون أن يترك شعورًا بالثقل على البشرة.\n\nطريقة الاستخدام: ضعي كمية مناسبة من واقي الشمس على وجهك ورقبتك قبل 20 دقيقة من التعرض لأشعة الشمس. يُنصح بتجديده كل ساعتين أثناء التعرض للشمس.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:39:26',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-27',0,0),(236,'دژە خۆری تایبەت بە پێستی وشک لە بڕاندی بابێی ئیسپانی','Sunscreen for dry skin from Spanish brand Babe','واقي شمس للبشرة الجافة من ماركة Babe الإسبانية','دژە خۆری تایبەت بە پێستی وشک لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەهێز (SPF 50): نەک تەنها دژی تیشکی UVB (کە دەبێتە هۆی سووتان)، بەڵکو دژی تیشکی UVA و HEV (تیشکی شینی شاشەکان) و IR-A (تیشکی ژێر سوور) دەتپارێزێت.\r\n• سووکی و نەرمی: ناوی \"Super Fluid\"ـە چونکە زۆر شل و سووکە، بە خێرایی بە پێستدا دەچێت و هەست بە قورسی یان چەوری ناکەیت.\r\n• ترشی هیالۆرۆنیک (Hyaluronic Acid): تێدایە کە یارمەتی شێدارکردنەوەی پێست دەدات و ناهێڵێت پێست وشک ببێتەوە.\r\n• دژە پیسبوونی هەوا (Anti-pollution): پێست لە تۆز و غوبار و پیسی ژینگە دەپارێزێت.\r\nسوودەکانی:\r\n1. بۆ هەموو جۆرە پێستێک گونجاوە: تەنانەت بۆ پێستی هەستیاریش زۆر باشە.\r\n2. چاو ناسووتێنێت: یەکێک لە کێشەکانی دژەخۆر ئەوەیە بچێتە ناو چاو دەیصووتێنێت، بەڵام ئەمەیان تایبەتمەندی \"Does not sting eyes\" ی هەیە.\r\n3. شوێنەواری سپی جێنەهێڵێت: لەبەر ئەوەی زۆر سووکە، پێست سپی ناکات و وەک ماسک دەرناکەوێت.\r\n4. بەرگری ئاوی هەیە: تا ڕادەیەک بەرگەی ئەرەقە و ئاو دەگرێت.\r\nچۆن بەکاردێت؟\r\n• بڕێکی گونجاو (بە ئەندازەی دوو پەنجە) بدە لە دەموچاو و ملت ٢٠ خولەک پێش ئەوەی بچیتە بەر خۆر.\r\n• ئەگەر بۆ ماوەیەکی درێژ لەبەر خۆر بوویت، پێویستە هەموو ٢ کاتژمێر جارێک نوێی بکەیتەوە.\r\nتێبینییەکی گرنگ:\r\nئەم دژەخۆرە بەهۆی هەبوونی Hyaluronic Acid، جگە لە پاراستن، وەک شێدارکەرەوەیەکی (Moisturizer) سووکیش کار دەکات، بۆیە بۆ ئەو کەسانەی پێستیان چەورە یان تێکەڵەیە زۆر نایابە.\r\n','Key Features:\n• Strong protection (SPF 50): Protects not only against UVB rays (which can cause burns), but also against UVA, HEV (blue rays from screens) and IR-A (infrared rays).\n• Lightness and softness: It is called \"Super Fluid\" because it is very fluid and light, it absorbs quickly into the skin and does not feel heavy or greasy.\n• Contains Hyaluronic Acid, which helps moisturize the skin and prevents it from drying out.\n• Anti-pollution: Protects skin from dust and environmental pollution.\nBenefits:\n1. Suitable for all skin types: Great even for sensitive skin.\n2. Does not sting the eyes: One of the problems with sunscreen is that it does not sting the eyes, but this one has the feature \"Does not sting eyes\"\n3. Does not leave white traces: Because it is very light, it does not whiten the skin and does not look like a mask.\n4. Water resistance: Somewhat resistant to sweat and water.\nhow is it used\n• Apply an appropriate amount (two finger sizes) to face and neck 20 minutes before going out in the sun.\n• If you have been in the sun for a long time, you should renew it every 2 hours.\nImportant note:\nDue to the presence of Hyaluronic Acid, in addition to protection, this sunscreen also acts as a mild moisturizer, so it is great for people with oily or combination skin.','الميزات الرئيسية:\n• حماية قوية (SPF 50): يحمي ليس فقط من أشعة UVB (التي قد تسبب حروق الشمس)، بل أيضًا من أشعة UVA، والأشعة الزرقاء (HEV) المنبعثة من الشاشات، والأشعة تحت الحمراء (IR-A).\n• خفة ونعومة: يُطلق عليه اسم \"سوبر سيلويد\" نظرًا لتركيبته السائلة والخفيفة للغاية، حيث تمتصه البشرة بسرعة ولا يترك شعورًا بالثقل أو الدهنية.\n• يحتوي على حمض الهيالورونيك، الذي يساعد على ترطيب البشرة ويمنع جفافها.\n• مضاد للتلوث: يحمي البشرة من الغبار والتلوث البيئي.\n\nالفوائد:\n1. مناسب لجميع أنواع البشرة: مثالي حتى للبشرة الحساسة.\n2. لا يسبب تهيجًا للعينين: من عيوب واقيات الشمس الأخرى أنها لا تسبب تهيجًا للعينين، ولكن هذا المنتج يتميز بخاصية \"لا يسبب تهيجًا للعينين\".\n3. لا يترك أثرًا أبيض: نظرًا لخفته، لا يترك أثرًا أبيض على البشرة ولا يبدو كقناع.\n4. مقاوم للماء: مقاوم للماء والعرق إلى حد ما.\n\nطريقة الاستخدام\n• ضعي كمية مناسبة (بحجم إصبعين) على الوجه والرقبة قبل 20 دقيقة من التعرض لأشعة الشمس.\n• إذا كنتِ قد تعرضتِ للشمس لفترة طويلة، يُنصح بتجديده كل ساعتين.\n\nملاحظة هامة:\nبفضل احتوائه على حمض الهيالورونيك، يعمل هذا الواقي الشمسي، بالإضافة إلى الحماية، كمرطب لطيف، مما يجعله مثالياً لأصحاب البشرة الدهنية أو المختلطة.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:41:00',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-26',0,0),(237,'دژە خۆری تایبەت بە منداڵان لە بڕاندی بابێی ئیسپانی','Children\'s sunscreen from Spanish brand Babe','واقي شمس للأطفال من ماركة Babe الإسبانية','دژە خۆری تایبەت بە منداڵان لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەهێز (SPF 50): ئاستێکی زۆر بەرزی پاراستن دابین دەکات دژی تیشکە زیانبەخشەکانی وەک UVA و UVB. هەروەها پارێزگاری دەکات لە تیشکی شاشەکان (HEV) و تیشکی ژێر سوور (IR-A).\r\n• پێکهاتەی سووک (Super Fluid): شلەیەکی زۆر سووکە، بە خێرایی بە پێستدا بڵاو دەبێتەوە و دەمژرێت بێ ئەوەی هەست بە چەوری بکەیت یان شوێنی سپی بەجێ بهێڵێت.\r\n• تایبەتمەندیی Pediatric: ئەمە واتە بەرهەمەکە لەژێر چاودێری پزیشکی منداڵان و پزیشکی چاو تاقیکراوەتەوە و بۆ پێستی زۆر ناسکیش گونجاوە.\r\n• ناسووتێتەوە: یەکێک لە باشترین خاسیەتەکانی ئەوەیە کە چاو نا سووتێنێتەوە (Tear-free).\r\nپێکهاتە گرنگەکان:\r\n• Panthenol (پانتینۆڵ): یارمەتی ئارامکردنەوە و شێدارکردنەوەی پێست دەدات و خانەکان نوێ دەکاتەوە.\r\n• Prebiotic (پریبایۆتیک): بەرگری سروشتی پێست بەهێز دەکات و هاوسەنگی بەکتریای سوودبەخشی سەر پێست دەپارێزێت.\r\nچۆنیەتی بەکارهێنان:\r\n1. پێش بەکارهێنان باش ڕایوەشێنە.\r\n2. بڕێکی گونجاو بدە لە دەموچاو و ملی منداڵەکە ٢٠ خولەک پێش چوونە بەر خۆر.\r\n3. ئەگەر منداڵەکە لەبەر خۆر مایەوە یان مەلەی کرد، هەموو ٢ کاتژمێر جارێک دووبارە لێی بدەرەوە.\r\n','Key Features:\n• Strong Protection (SPF 50): Provides a very high level of protection against harmful rays such as UVA and UVB. It also protects against screen light (HEV) and infrared (IR-A) light.\n• Super Fluid: A very light liquid, it spreads quickly through the skin and is absorbed without feeling greasy or leaving white spots.\n• Pediatric features: This means that the product has been tested under the supervision of a pediatrician and ophthalmologist and is suitable for very sensitive skin.\n• Does not burn: One of its best features is that it is tear-free.\nImportant Ingredients:\n• Panthenol: Helps soothe, moisturize and renew cells.\n• Prebiotic: Strengthens the skin\'s natural defenses and maintains the balance of beneficial bacteria on the skin.\nHow to use:\n1. Shake well before use.\n2. Apply an appropriate amount to the child\'s face and neck 20 minutes before sun exposure.\n3. If baby stays in the sun or swims, reapply every 2 hours.','الميزات الرئيسية:\n• حماية فائقة (SPF 50): يوفر حماية عالية جدًا من الأشعة الضارة مثل الأشعة فوق البنفسجية UVA وUVB. كما يحمي من ضوء الشاشة (HEV) والأشعة تحت الحمراء (IR-A).\n• قوام سائل فائق: سائل خفيف جدًا، ينتشر بسرعة على البشرة ويتم امتصاصه دون ترك أي ملمس دهني أو بقع بيضاء.\n• مناسب للأطفال: تم اختبار هذا المنتج تحت إشراف طبيب أطفال وطبيب عيون، وهو مناسب للبشرة الحساسة جدًا.\n• لا يسبب حروقًا: من أفضل مميزاته أنه لا يسبب الدموع.\n\n• مكونات هامة:\n• بانثينول: يساعد على تهدئة البشرة وترطيبها وتجديد خلاياها.\n• بريبيوتيك: يقوي دفاعات البشرة الطبيعية ويحافظ على توازن البكتيريا النافعة فيها.\n\nطريقة الاستخدام:\n1. رج العبوة جيدًا قبل الاستخدام.\n2. ضعي كمية مناسبة على وجه الطفل ورقبته قبل 20 دقيقة من التعرض لأشعة الشمس.\nضعي كمية مناسبة على وجه الطفل ورقبته قبل 20 دقيقة من التعرض لأشعة الشمس.\n 3. إذا بقي الطفل في الشمس أو سبح، فأعد وضع الكريم كل ساعتين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:42:40',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-25',0,0),(238,'تەقشیری جێلی پاکەرەوەی پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی','Babey Cleansing Gel Exfoliator for Oily and Acne Skin','جل التنظيف المقشر من بيبي للبشرة الدهنية والمعرضة لحب الشباب','تەقشیری جێلی پاکەرەوەی پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. کار و سوودەکانی:\r\n• پاککردنەوەی قووڵ: یارمەتی کردنەوەی کونیلەکانی پێست دەدات و چەوری زیادە لادەبات.\r\n• نوێکردنەوەی پێست: بەهۆی هەبوونی دەنکۆڵەی زۆر ورد، خانە مردووەکانی پێست لادەبات و پێستەکە گەشاوەتر دەکات.\r\n• کۆنتڕۆڵکردنی بەکتریا: پێکهاتەکانی ڕێگری دەکەن لە گەشەی ئەو بەکتریایانەی دەبنە هۆی دروستبوونی زیپکە.\r\n• کەمکردنەوەی بریقە: یارمەتی ماتکردنی (Matte) پێست دەدات و ناهێڵێت زۆر بچەورێتەوە.\r\n٢. پێکهاتە سەرەکییەکانی:\r\n• Salicylic Acid (BHA): پێکهاتەیەکی سەرەکییە بۆ پاککردنەوەی ناوەوەی کونیلەکان و چارەسەری زیپکە.\r\n• Succinic Acid: دژە بەکتریایە و یارمەتی کەمکردنەوەی هەوکردن دەدات.\r\n• Prebiotics: بۆ پاراستنی هاوسەنگی سروشتی پێست و بەهێزکردنی بەرگری پێست.\r\n• Zinc PCA: کۆنتڕۆڵی ڕێژەی چەوری (Sebum) پێست دەکات.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• هەفتەی ١ بۆ ٢ جار بەکاردێت (نەک هەموو ڕۆژێک، چونکە تەقشیرکەرە).\r\n• بیدە لە پێستی تەڕ، بە شێوەی بازنەیی مەساژی پێ بکە (دوور بکەوەرەوە لە دەوری چاو).\r\n• دواتر بە ئاوێکی شلەتێن بە باشی دەموچاوت بشۆ.\r\nتێبینی گرنگ:\r\nئەگەر پێستت زۆر هەستیارە، سەرەتا لە ناوچەیەکی بچووکی دەموچاوت تاقی بکەرەوە. هەروەها چونکە ئەم بەرهەمە ماددەی تەقشیرکەری تێدایە، زۆر گرنگە لە کاتی ڕۆژدا دژەخۆر بەکاربهێنیت.\r\n','Functions and Benefits:\n• Deep Cleansing: Helps open pores and removes excess oil.\n• Skin renewal: Due to its very fine grains, it removes dead skin cells and makes the skin brighter.\n• Bacterial control: Ingredients prevent the growth of bacteria that cause acne.\n• Reduce shine: Helps matte skin and prevents excessive wrinkles.\n2. Key ingredients:\n• Salicylic Acid (BHA): A key ingredient for clearing the inside of pores and treating acne.\n• Succinic Acid: Antibacterial and helps reduce inflammation.\n• Prebiotics: To maintain the skin\'s natural balance and strengthen the skin\'s immune system.\n• Zinc PCA: Controls the amount of sebum in the skin.\n3. How to use:\n• Used 1 to 2 times a week (not every day, as it is exfoliating).\n• Apply to damp skin, massaging in circular motions (avoid eye area).\n• Then wash your face thoroughly with lukewarm water.\nImportant Notes:\nIf you have very sensitive skin, try it on a small area of ​​your face first. Also, because this product contains exfoliators, it is very important to use sunscreen during the day.','الوظائف والفوائد:\n• تنظيف عميق: يساعد على فتح المسام وإزالة الزيوت الزائدة.\n• تجديد البشرة: بفضل حبيباته الدقيقة جدًا، يزيل خلايا الجلد الميتة ويجعل البشرة أكثر إشراقًا.\n• مكافحة البكتيريا: تمنع مكوناته نمو البكتيريا المسببة لحب الشباب.\n• تقليل اللمعان: يساعد على الحصول على بشرة غير لامعة ويمنع ظهور التجاعيد.\n\n٢. المكونات الرئيسية:\n• حمض الساليسيليك (BHA): مكون رئيسي لتنظيف المسام من الداخل وعلاج حب الشباب.\n• حمض السكسينيك: مضاد للبكتيريا ويساعد على تقليل الالتهاب.\n• البريبايوتكس: للحفاظ على التوازن الطبيعي للبشرة وتقوية جهاز المناعة.\n• زنك PCA: يتحكم في كمية الدهون في البشرة.\n\n٣. طريقة الاستخدام:\n• يُستخدم من مرة إلى مرتين أسبوعيًا (ليس يوميًا، لأنه مقشر).\n• يُوضع على بشرة رطبة مع التدليك بحركات دائرية (تجنب منطقة العينين).\n• ثم اغسلي وجهكِ جيداً بالماء الفاتر.\n\nملاحظة هامة: إذا كانت بشرتكِ حساسة للغاية، جربي المنتج على منطقة صغيرة من وجهكِ أولاً. أيضاً، نظراً لاحتواء هذا المنتج على مواد مقشرة، من الضروري جداً استخدام واقي الشمس خلال النهار.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:43:52',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-24',0,0),(239,'جێلی پاکەرەوەی تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی','Cleansing gel for oily and acne prone skin from the Spanish brand Babe','جل منظف للبشرة الدهنية والمعرضة لحب الشباب من ماركة Babe الإسبانية','جێلی پاکەرەوەی تایبەت بە پێستی چەور و زیپکەدار لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'کارەکانی ئەم جێڵە:\r\n• پاککردنەوەی قووڵ: یارمەتی لادانی چەوری زیادە و پیسی پێست دەدات بەبێ ئەوەی پێستەکە زۆر وشک بکاتەوە.\r\n• کۆنتڕۆڵکردنی چەوری: یارمەتی کەمکردنەوەی درەوشانەوەی پێست (Matte effect) دەدات.\r\n• ڕێگری لە زیپکە: بەهۆی پێکهاتە دژە بەکتریاکانی، ڕێگری دەکات لە دروستبوونی زیپکەی نوێ و پاککردنەوەی کونیلەکان.\r\n• پاراستنی میکرۆبیۆم: وەک لەسەری نووسراوە \"Microbiome Care\"، ئەمەش واتە هاوسەنگی بەکتریا سوودبەخشەکانی سەر پێست دەپارێزێت.\r\nپێکهاتە سەرەکییەکانی:\r\n• Salicylic Acid (سالیboundary ئەسید): کونیلەکان پاک دەکاتەوە و ڕێگری دەکات لە گیرانیان.\r\n• Succinic Acid: دژە بەکتریایە و یارمەتی کەمکردنەوەی سووربوونەوە و هەوکردن دەدات.\r\n• Azeloglycin: یارمەتی سپیکردنەوەی پەڵەی زیپکە و ڕێکخستنی چەوری دەدات.\r\n• Prebiotics: بۆ بەهێزکردنی بەربەستی سروشتی پێست.\r\n• Zinc PCA: کاریگەرە بۆ کەمکردنەوەی چەوری و چاکبوونەوەی برینی زیپکە.\r\nچۆنیەتی بەکارهێنان:\r\n1. بەیانیان و شەوان بەکاردێت.\r\n2. بڕێکی کەم بدە لە دەموچاوی تەڕ.\r\n3. بە شێوەی بازنەیی مەساجی پێ بکە (دوور بکەوەرەوە لە چاو).\r\n4. بە ئاوێکی شلەتێن بە باشی دەموچاوت بشۆ و پاشان بە خاولییەکی نەرم وشکی بکەرەوە.\r\nتێبینییەکی گرنگ:\r\nئەم بەرهەمە زۆر باشە بۆ پێستی چەور، بەڵام ئەگەر پێستت زۆر هەستیارە یان وشکە، ڕەنگە کەمێک هەست بە وشکی بکەیت، بۆیە هەمیشە دوای شۆردن کریمێکی شێدارکەرەوەی (Moisturizer) بێ چەوری بەکاربهێنە.\r\n','Functions of this gel:\n• Deep Cleansing: Helps remove excess oil and skin impurities without over drying the skin.\n• Oil control: Helps reduce matte effect.\n• Prevent acne: Due to its antibacterial properties, it prevents the formation of new acne and clears pores.\n• Microbiome Care: As it says “Microbiome Care”, this means it maintains the balance of beneficial bacteria on the skin.\nKey ingredients:\n• Salicylic Acid (salicylic acid): Cleans pores and prevents clogging.\n• Succinic Acid: Antibacterial and helps reduce redness and inflammation.\n• Azeloglycin: Helps whiten acne spots and regulate sebum.\n• Prebiotics: To strengthen the skin’s natural barrier.\n• Zinc PCA: Effective for sebum reduction and acne ulcer healing.\nHow to use:\n1. Used in the morning and at night.\n2. Apply a small amount to wet face.\n3. Massage in circular motions (away from eyes).\n4. Rinse your face thoroughly with lukewarm water and then dry with a soft towel.\nImportant note:\nThis product is great for oily skin, but if you have very sensitive or dry skin, you may feel a little dry, so always use an oil-free moisturizer after washing.','فوائد هذا الجل:\n• تنظيف عميق: يساعد على إزالة الزيوت الزائدة وشوائب البشرة دون تجفيفها.\n• التحكم في إفراز الزيوت: يساعد على تقليل مظهر البشرة الباهت.\n• الوقاية من حب الشباب: بفضل خصائصه المضادة للبكتيريا، يمنع ظهور حب الشباب الجديد وينظف المسام.\n• العناية بالميكروبيوم: كما يوحي اسمه، فهو يحافظ على توازن البكتيريا النافعة على البشرة.\n\nالمكونات الرئيسية:\n• حمض الساليسيليك: ينظف المسام ويمنع انسدادها.\n• حمض السكسينيك: مضاد للبكتيريا ويساعد على تقليل الاحمرار والالتهاب.\n• أزيلوجليسين: يساعد على تفتيح بقع حب الشباب وتنظيم إفراز الدهون.\n• البريبايوتكس: لتقوية حاجز البشرة الطبيعي.\n• زنك PCA: فعال في تقليل إفراز الدهون وعلاج قرح حب الشباب.\n\nطريقة الاستخدام:\n1. يُستخدم صباحًا ومساءً.\n2. ضعي كمية صغيرة على بشرة مبللة.\n3. دلكي بحركات دائرية (بعيدًا عن العينين). ٤. اشطفي وجهكِ جيداً بالماء الفاتر ثم جففيه بمنشفة ناعمة.\n\nملاحظة هامة: هذا المنتج رائع للبشرة الدهنية، ولكن إذا كانت بشرتكِ حساسة جداً أو جافة، فقد تشعرين ببعض الجفاف، لذا استخدمي دائماً مرطباً خالياً من الزيوت بعد غسل وجهكِ.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:45:06',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-23',0,0),(240,'لۆشنی دژە خۆری جەستە و دەم و چاو لە بڕاندی بابێی ئیسپانی','Body and face sunscreen lotion from Spanish brand Babe','لوشن واقي من الشمس للجسم والوجه من ماركة Babe الإسبانية','لۆشنی دژە خۆری جەستە و دەم و چاو لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستنی بەهێز (SPF 50+): نیشانەی ئەوەیە کە پاراستنێکی زۆر بەهێز دابین دەکات دژی تیشکە زیانبەخشەکانی خۆر (UVB و UVA).\r\n• بۆ هەموو جۆرە پێستێک: گونجاوە بۆ هەموو جۆرە پێستێک، تەنانەت ئەو پێستانەی کە زۆر هەستیارن.\r\n• پێکهاتەی هێورکەرەوە: وەک لەسەری نووسراوە \"Soothing Active Ingredients\"، پێکهاتەی تێدایە (وەک کارۆسین، ئالۆڤێرا، و بەیبوون) کە پێست هێور دەکەنەوە و ناهێڵن بەهۆی گەرماوە سوور ببێتەوە.\r\n• دژە ئاو (Water Resistant): بەرگەی ئارەقکردنەوە و ئاو دەگرێت، بۆیە بۆ مەلەکردن و وەرزشکردن زۆر گونجاوە.\r\nسوودەکانی:\r\n• ڕێگری لە پیربوونی پێست: پاراستنی پێست لە چرچبوونی پێشوەختە کە بەهۆی تیشکی خۆرەوە دروست دەبێت.\r\n• زوو هەڵمژین: شێوەی وەک لۆشنێکی سووکە و بە خێرایی بە پێستەوە نامێنێت و هەستی چەورییەکی ناخۆش دروست ناکات.\r\n• بەرهەمێکی پزیشکییە: لەلایەن پزیشکانی پێستەوە تاقی کراوەتەوە (Dermatologically Tested).\r\nچۆنێتی بەکارهێنان:\r\n1. نزیکەی ٢٠ خولەک پێش ئەوەی بچیتە بەر خۆر، بڕێکی گونجاو لە لۆشنەکە بدە لەو شوێنانەی جەستەت کە بەر خۆر دەکەون.\r\n2. ئەگەر بۆ ماوەیەکی زۆر لەبەر خۆر بوویت، یان ئەگەر مەلەت کرد و خۆت وشک کردەوە، پێویستە هەر ٢ کاتژمێر جارێک دووبارەی بکەیتەوە.\r\n','Key Features:\n• Strong Protection (SPF 50+): Marks that it provides very strong protection against harmful sun rays (UVB and UVA).\n• For all skin types: Suitable for all skin types, even the most sensitive.\n• Soothing Ingredients: As labeled \"Soothing Active Ingredients,\" it contains ingredients (such as carrots, aloe vera, and violet) that soothe skin and prevent heat-induced redness.\n• Water Resistant: Sweat and water resistant, so it is perfect for swimming and exercise.\nBenefits:\n• Prevent skin aging: Protect skin from premature wrinkles caused by sunlight.\n• Quick absorption: It looks like a light lotion and disappears quickly on the skin without creating an unpleasant greasy feeling.\n• A medical product: Dermatologically Tested.\nHow to use:\n1. About 20 minutes before going out in the sun, apply an appropriate amount of the lotion to the areas of your body that are exposed to the sun.\n2. If you have been in the sun for a long time, or if you swim and dry yourself, you should repeat every 2 hours.','الميزات الرئيسية:\n• حماية فائقة (SPF 50+): يوفر حماية قوية جدًا من أشعة الشمس الضارة (UVB وUVA).\n• مناسب لجميع أنواع البشرة: مناسب لجميع أنواع البشرة، حتى الأكثر حساسية.\n• مكونات ملطفة: يحتوي على مكونات ملطفة (مثل الجزر، والصبار، والبنفسج) التي تلطف البشرة وتمنع الاحمرار الناتج عن الحرارة.\n• مقاوم للماء: مقاوم للعرق والماء، مما يجعله مثاليًا للسباحة والرياضة.\n\n• فوائد:\n• الوقاية من شيخوخة البشرة: يحمي البشرة من التجاعيد المبكرة الناتجة عن أشعة الشمس.\n• امتصاص سريع: قوامه خفيف ويمتصه الجلد بسرعة دون ترك أي شعور دهني مزعج.\n• منتج طبي: تم اختباره من قبل أطباء الجلدية.\n\nطريقة الاستخدام:\n1. قبل الخروج في الشمس بحوالي 20 دقيقة، ضعي كمية مناسبة من الكريم على المناطق المعرضة للشمس من جسمك.\n\nمنتج طبي: تم اختباره من قبل أطباء الجلدية. 2. إذا كنت قد تعرضت لأشعة الشمس لفترة طويلة، أو إذا كنت تسبح وتجفف نفسك، فيجب عليك تكرار ذلك كل ساعتين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:46:31',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-22',0,0),(241,'کرێمی تایبەت بە پێستی دەست لە بڕاندی بابێی ئیسپانی','Hand cream from Spanish brand Babe','كريم لليدين من ماركة Babe الإسبانية','کرێمی تایبەت بە پێستی دەست لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. تایبەتمەندییە سەرەکییەکان:\r\n• بۆ پێستی زۆر وشک: گونجاوە بۆ ئەو دەستانەی بەهۆی سەرما، ماددەی پاککەرەوە، یان وشکی زۆرەوە زبر بوون یان قڵیشاون.\r\n• نەرمکەرەوە و هێورکەرەوە: یارمەتی کەمکردنەوەی هەوکردن و سووربوونەوەی دەست دەدات و هەستی ئاسوودەیی بە پێست دەبەخشێت.\r\n• خێرا هەڵدەمژرێت: یەکێک لە باشییەکانی ئەم براندە ئەوەیە کە کرێمەکە چەورییەکی بێزارکەر لەسەر دەست جێناهێڵێت.\r\n٢. پێکهاتە گرنگەکان:\r\n• کۆمەڵەی چاککەرەوە (Repairing Complex): کە پێکهاتووە لە (Bio Ceramide, Bisabolol, Phytosterols) بۆ دووبارە بنیاتنانەوەی چینی پارێزەری پێست.\r\n• کەرەی شیا (Shea Butter): بۆ شێدارکردنەوەی قووڵ و نەرمکردنی پێست.\r\n• گلیسرین (Glycerin): یارمەتی هێشتنەوەی شێ دەدات لەناو پێستدا.\r\n٣. زانیارییە گرنگەکان:\r\n• pH 5.5: هاوسەنگی ترشێتی پێست دەپارێزێت و تێکی نادات.\r\n• بەرهەمی ئیسپانیایە: یەکێکە لە براندە ناسراوەکانی دەرمانخانە (Dermocosmetic).\r\n٤. چۆن بەکاردێت؟\r\nبڕێکی گونجاو لە کرێمەکە بدە لە دەستەکانت و بە نەرمی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت. دەتوانیت ڕۆژانە چەند جارێک بەکاریبهێنیت، بە تایبەت دوای دەست شوشتن.\r\n',' Key Features:\n• For very dry skin: Suitable for hands that are rough or peeling from cold, detergent, or excessive dryness.\n• Softening and soothing: Helps reduce inflammation and redness of the hands and gives the skin a comfortable feeling.\n• Quickly absorbed: One of the advantages of this brand is that the cream does not leave an annoying grease on the hands.\n2. Important Ingredients:\n• Repairing Complex: Consisting of Bio Ceramide, Bisabolol, Phytosterols to rebuild the skin\'s protective layer.\n• Shea Butter: To deeply moisturize and soften the skin.\n• Glycerin: Helps retain moisture in the skin.\n3. Important information:\n• pH 5.5: Maintains the acidity balance of the skin and does not disrupt it.\n• Spanish product: One of the well-known brands of pharmacies (Dermocosmetic).\n4. how is it used\nApply an appropriate amount of the cream to your hands and massage gently until it is fully absorbed. You can use it several times a day, especially after washing your hands.','.الميزات الرئيسية:\n• للبشرة شديدة الجفاف: مناسب لليدين الخشنتين أو المتقشرتين نتيجة البرد أو المنظفات أو الجفاف المفرط.\n• مُنعم ومهدئ: يساعد على تقليل التهاب واحمرار اليدين ويمنح البشرة شعورًا بالراحة.\n• سريع الامتصاص: من مميزات هذا المنتج أنه لا يترك أي أثر دهني مزعج على اليدين.\n\n٢. المكونات الهامة:\n• مركب ترميمي: يتكون من بيو سيراميد، بيسابولول، فيتوستيرولات لإعادة بناء الطبقة الواقية للبشرة.\n• زبدة الشيا: لترطيب وتنعيم البشرة بعمق.\n• الجلسرين: يساعد على الاحتفاظ برطوبة البشرة.\n\n٣. معلومات هامة:\n• درجة حموضة ٥.٥: يحافظ على توازن حموضة البشرة ولا يُخلّ به.\n• منتج إسباني: من أشهر العلامات التجارية في الصيدليات (مستحضرات التجميل الطبية).\n\n٤. طريقة الاستخدام\nضعي كمية مناسبة من الكريم على يديكِ ودلكيها بلطف حتى يمتصها الجلد تماماً. يمكنكِ استخدامه عدة مرات في اليوم، خاصةً بعد غسل اليدين.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:47:36',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-21',0,0),(242,'کرێمی شێدارکەرەوەی تایبەت بە پێستی زۆر وشک و ئەکزیما لە بڕاندی بابێی ئیسپانی','Moisturizing cream for very dry and eczema skin from the Spanish brand Babe','كريم مرطب للبشرة شديدة الجفاف والمصابة بالإكزيما من ماركة Babe الإسبانية','کرێمی شێدارکەرەوەی تایبەت بە پێستی زۆر وشک و ئەکزیما لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. سوودە سەرەکییەکانی:\r\n• هێورکەرەوەی خوروو: یارمەتی کەمکردنەوەی ئەو خوروو و ناڕەحەتییە دەدات کە بەهۆی وشکی زۆری پێستەوە دروست دەبێت.\r\n• دووبارە بونیاتنانەوەی پێست: یارمەتی نوێکردنەوە و چاککردنەوەی ئەو شوێنانەی پێست دەدات کە زیانیان بەرکەوتووە.\r\n• نەرمکەرەوە: بەهۆی پێکهاتە دەوڵەمەندەکانی، پێست زۆر نەرم دەکات و لە توێژاڵ و زبری دەیپارێزێت.\r\n• ئۆمیگا ٣، ٦ و ٩: لە پێکهاتەکەیدا ئەم ترشە چەورییە گرنگانەی تێدایە کە بۆ تەندروستی و بەهێزیی بەربەستی پارێزەری پێست پێویستن.\r\n٢. پێکهاتە گرنگەکانی:\r\nبەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە، ڕێژەی پێکهاتە کاریگەرەکانی ئەمانەن:\r\n• کەرەی شەیا (Shea Butter) ٤٪: بۆ شێدارکردنەوەی قووڵ.\r\n• گلیسرین ٣٪: بۆ هێشتنەوەی شێ لەناو پێستدا.\r\n• ڕۆنی ئینکا ئینچی (Inca Inchi Oil) ١٪: کە سەرچاوەی ئۆمیگاکانە.\r\n• فاکتەری شێداری سروشتی ١٪: بۆ ڕاگرتنی هاوسەنگی ئاوی پێست.\r\n• ڤیتامین F: بۆ چاککردنەوەی خانەکان.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• بۆ کێ دەبێت؟ بۆ منداڵ، گەورە، و هەر کەسێک کە پێستی زۆر وشکە یان حەساسیەت و ئەکزیمای هەیە.\r\n• چۆن بەکاردێت؟ بڕێکی گونجاو بدە لەو شوێنانەی کە وشکن یان خورویان هەیە، بە شێوەیەکی بازنەیی و لەسەرخۆ مەساجی پێ بکە تا پێستەکە دەیمژێت. دەتوانیت ڕۆژانە بەکاری بهێنیت.\r\nتێبینییەکی گرنگ:\r\nئەم کرێمە Dermatologically Tested کراوە، واتە لەلایەن پزیشکانی پێستەوە تاقی کراوەتەوە و بۆ پێستی هەستیار گونجاوە. هەروەها pH ٥.٥ ە کە هاوسەنگی سروشتی پێست تێک نادات.\r\n','Key benefits:\n• Itch soothing: Helps reduce itching and discomfort caused by excessive dryness of the skin.\n• Skin regeneration: Helps renew and repair damaged skin areas.\n• Softener: Due to its rich ingredients, it makes the skin very soft and protects it from peeling and roughness.\n• Omega 3, 6 and 9: Contains these essential fatty acids that are essential for the health and strength of the skin\'s protective barrier.\n2. Important components:\nAccording to the label, the effective ingredient ratios are:\n• Shea Butter 4%: For deep moisturizing.\n• Glycerin 3%: To keep moisture in the skin.\n• Inca Inchi Oil 1%: A source of omegas.\n• 1% natural moisture factor: to maintain the skin’s water balance.\n• Vitamin F: For cell repair.\n3. How to use:\n• Who will it be for? For children, adults, and anyone with very dry skin or allergies and eczema.\n• How is it used? Apply an appropriate amount to dry or itchy areas, massaging in a circular motion spontaneously until the skin absorbs. You can use it daily.\nImportant note:\nThis cream is Dermatologically Tested, which means it has been tested by dermatologists and is suitable for sensitive skin. It’s also a pH of 5.5 which doesn’t upset the skin’s natural balance.','الفوائد الرئيسية:\n• تهدئة الحكة: يساعد على تخفيف الحكة والانزعاج الناتج عن جفاف الجلد المفرط.\n• تجديد البشرة: يساعد على تجديد وإصلاح المناطق المتضررة من الجلد.\n• مُنعم: بفضل مكوناته الغنية، يجعل البشرة ناعمة للغاية ويحميها من التقشر والخشونة.\n• أوميغا 3 و6 و9: يحتوي على هذه الأحماض الدهنية الأساسية الضرورية لصحة وقوة حاجز البشرة الواقي.\n\n2. المكونات الهامة:\nوفقًا للملصق، فإن نسب المكونات الفعالة هي:\n• زبدة الشيا 4%: لترطيب عميق.\n• الجلسرين 3%: للحفاظ على رطوبة البشرة.\n• زيت إنكا إنشي 1%: مصدر للأوميغا.\n• عامل ترطيب طبيعي 1%: للحفاظ على توازن الماء في البشرة.\n• فيتامين F: لإصلاح الخلايا.\n\n3. طريقة الاستخدام:\n• لمن هذا المنتج؟ مناسب للأطفال والبالغين، ولكل من يعاني من جفاف شديد في الجلد أو الحساسية أو الإكزيما.\nطريقة الاستخدام: ضعي كمية مناسبة على المناطق الجافة أو المصابة بالحكة، ودلكيها بحركات دائرية حتى تمتصها البشرة. يمكن استخدامه يوميًا.\n\nملاحظة هامة: هذا الكريم مُختَبَر من قِبَل أطباء الجلدية، أي أنه مُختَبَر من قِبَل أطباء الجلدية ومناسب للبشرة الحساسة. كما أن درجة حموضته 5.5، مما يحافظ على توازن البشرة الطبيعي.\n',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:49:11',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-20',0,0),(243,'شامپۆی تایبەت بە چارەسەرکردن و کەمکردنەوەی قژ هەڵوەرین لە بڕاندی بابێی ئیسپانی',NULL,NULL,NULL,15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• ڕێگریکردن لە هەڵوەرین: یارمەتی کەمکردنەوە و ڕێگریکردن لە هەڵوەرینی قژ دەدات.\r\n• بەهێزکەر: قژی لاواز و تەنک بەهێز دەکات و وزەی پێ دەبەخشێتەوە.\r\n• پێکهاتەی سروشتی: کۆمەڵێک پێکهاتەی وەک (Ginkgo Biloba) و (Cinchona Extract) و (Biotin)ی تێدایە کە سووڕی خوێن لە پێستی سەردا چالاک دەکەن.\r\n• هاوسەنگی pH: پلەی ترشێتییەکەی pH 5.5 کە گونجاوە بۆ پاراستنی تەندروستی پێستی سەر.\r\nچۆنیەتی بەکارهێنان:\r\n1. بڕێکی گونجاو بدە لە پێستی سەری تەڕ.\r\n2. بە هێواشی مەساجی پێ بکە.\r\n3. با بۆ ماوەی چەند خولەکێک بە قژتەوە بمێنێتەوە تا پێکهاتەکان کار بکەن.\r\n4. پاشان بە باشی بە ئاو بیشۆ.\r\n5. پێشنیار کراوە هەفتەی ٢ بۆ ٣ جار بەکاربێت (دەتوانیت لە نێوان ڕۆژەکاندا شامپۆیەکی زۆر نەرم بەکاربهێنیت).\r\n','Babe anti-hair loss shampoo designed to help reduce hair shedding and strengthen thin or weak hair. Contains plant-based actives such as Ginkgo Biloba, Cinchona extract, and Biotin to help stimulate scalp circulation and support healthier hair growth. Maintains pH 5.5 to protect scalp health and balance. How to use: apply an appropriate amount to wet scalp and hair, massage gently, leave for a few minutes to allow actives to work, then rinse thoroughly. Recommended 2–3 times per week; on other days you can use a very mild daily shampoo.','شامبو Babe لمكافحة تساقط الشعر يساعد على تقليل التساقط وتقوية الشعر الضعيف أو الخفيف. يحتوي على مكونات فعالة مثل الجنكو بيلوبا وخلاصة السينشونا والبيوتين للمساعدة على تنشيط الدورة الدموية في فروة الرأس ودعم نمو شعر أكثر صحة. يحافظ على pH 5.5 لحماية توازن الفروة. طريقة الاستخدام: توضع كمية مناسبة على فروة الرأس والشعر المبلل، تُدلّك بلطف وتُترك لبضع دقائق حتى تعمل المكونات ثم تُشطف جيداً. يُنصح باستخدامه 2–3 مرات أسبوعياً، ويمكن في الأيام الأخرى استخدام شامبو يومي لطيف جداً.',NULL,NULL,NULL,NULL,NULL,'2026-01-11 05:50:49',0.00,'percentage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0),(244,'شامپۆی دژە کڕێش و پێستی سەری چەور لە بڕاندی بابێی ئیسپانی','Anti-wrinkle and oily scalp shampoo from Spanish brand Babe','شامبو مضاد للتجاعيد وفروة الرأس الدهنية من ماركة Babe الإسبانية','شامپۆی دژە کڕێش و پێستی سەری چەور لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. سوودە سەرەکییەکانی:\r\n• نەهێشتنی کڕێش: یارمەتی کەمکردنەوە و نەهێشتنی کڕێشی چەور دەدات.\r\n• ڕێکخستنی چەوری: کۆنترۆڵی ڕێژەی دەردانی چەوری (Sebum) دەکات لە پێستی سەردا.\r\n• هێورکەرەوە: خورانی پێستی سەر کەم دەکاتەوە و هەستی ئارامی دەبەخشێت.\r\n• پاراستنی هاوسەنگی: یارمەتی گەڕاندنەوەی هاوسەنگی سروشتی پێستی سەر دەدات بەهۆی ئەوەی ڕێژەی ترشێتییەکەی (pH) گونجاوە (pH 5).\r\n٢. پێکهاتە گرنگەکانی:\r\nبەپێی زانیارییەکانی سەر کارتۆنەکە، ئەم پێکهاتانەی تێدایە:\r\n• سالی سیلیک ئەسید (Salicylic Acid): یارمەتی لێکردنەوەی قەپاڵ و کڕێشە چەورەکان دەدات.\r\n• پیرۆکتۆن ئۆلامین (Piroctone Olamine): دژە کەڕووە و هۆکاری سەرەکی دروستبوونی کڕێش لەناو دەبات.\r\n• بایۆتین و سیتاپۆڵ: بۆ بەهێزکردن و تەندروست ڕاگرتنی مووەکانی قژ.\r\n٣. چۆنیەتی بەکارهێنان:\r\n١. قژت بە باشی تەڕ بکە.\r\n٢. بڕێکی گونجاو لە شامپۆکە بدە لە پێستی سەرت و بە پەنجەکانت بە هێواشی مەساجی پێ بکە.\r\n٣. گرنگە: وازی لێ بهێنە بۆ ماوەی ٢ بۆ ٣ خولەک بە پێستی سەرەوە بمێنێتەوە تا پێکهاتەکانی کار بکەن.\r\n٤. دواتر بە ئاوێکی زۆر بیشۆ.\r\n٥. دەتوانیت لە هەفتەیەکدا ٢ بۆ ٣ جار بەکاری بهێنیت.\r\nتێبینی:\r\n• ئەگەر لە کاتی بەکارهێناندا چوو بە چاوتدا، خێرا بە ئاو بیشۆ.\r\n• ئەم شامپۆیە زیاتر بۆ چارەسەرە، بۆیە ئەگەر قژت زۆر وشک بووەوە، دەتوانیت لەگەڵ شامپۆیەکی ڕۆژانەی زۆر نەرم (Extra Mild) بە نۆبە بەکاری بهێنیت.\r\n','Key benefits:\n• Eliminate wrinkles: Helps reduce and eliminate oily wrinkles.\n• Sebum regulation: Controls the amount of sebum secreted in the scalp.\n• Soothing: Reduces scalp irritation and provides a sense of peace.\n• Maintain balance: Helps restore the natural balance of the scalp by having a balanced pH (pH 5).\n2. Important components:\nAccording to the information on the carton, it contains the following ingredients:\n• Salicylic Acid: Helps remove fatty wrinkles.\n• Piroctone Olamine: Antifungal and eliminates the main cause of wrinkles.\n• Biotin and Citapol: To strengthen and keep hair healthy.\n3. How to use:\n1. Wet your hair thoroughly.\n2. Apply an appropriate amount of shampoo to your scalp and massage gently with your fingers.\n3. Important: Leave it on the scalp for 2 to 3 minutes for the ingredients to work.\n4. Then rinse with plenty of water.\n5. You can use it 2 to 3 times a week.\nnotice:\n• If it gets in your eyes during use, rinse immediately with water.\n• This shampoo is more therapeutic, so if your hair is very dry, you can use it alternately with a very mild (Extra Mild) daily shampoo.','الفوائد الرئيسية:\n• إزالة التجاعيد: يساعد على تقليل التجاعيد الدهنية وإزالتها.\n• تنظيم إفراز الدهون: يتحكم في كمية الدهون التي تفرزها فروة الرأس.\n• تهدئة فروة الرأس: يقلل من تهيجها ويمنح شعورًا بالراحة.\n• الحفاظ على التوازن: يساعد على استعادة التوازن الطبيعي لفروة الرأس من خلال الحفاظ على درجة حموضة متوازنة (pH 5).\n\n٢. المكونات الهامة:\nوفقًا للمعلومات الموجودة على العبوة، يحتوي على المكونات التالية:\n• حمض الساليسيليك: يساعد على إزالة التجاعيد الدهنية.\n• بيروكتون أولامين: مضاد للفطريات ويقضي على السبب الرئيسي للتجاعيد.\n• البيوتين والسيتابول: لتقوية الشعر والحفاظ على صحته.\n\n٣. طريقة الاستخدام:\n١. بللي شعرك جيدًا.\n٢. ضعي كمية مناسبة من الشامبو على فروة رأسك ودلكيها بلطف بأطراف أصابعك.\n٣. هام: اتركيه على فروة الرأس لمدة ٢ إلى ٣ دقائق حتى تعمل المكونات.\n٤. ثم اشطفي شعركِ بكمية وفيرة من الماء.\n٥. يمكنكِ استخدامه من مرتين إلى ثلاث مرات أسبوعيًا.\n\nملاحظة:\n• في حال ملامسته للعينين أثناء الاستخدام، اشطفيهما بالماء فورًا.\n• هذا الشامبو ذو خصائص علاجية، لذا إذا كان شعركِ جافًا جدًا، يمكنكِ استخدامه بالتناوب مع شامبو يومي لطيف جدًا (لطيف للغاية).','. سوودە سەرەکییەکانی:\n• نەهێشتنی کڕێش: یارمەتی کەمکردنەوە و نەهێشتنی کڕێشی چەور دەدات.\n• ڕێکخستنی چەوری: کۆنترۆڵی ڕێژەی دەردانی چەوری (Sebum) دەکات لە پێستی سەردا.\n• هێورکەرەوە: خورانی پێستی سەر کەم دەکاتەوە و هەستی ئارامی دەبەخشێت.\n• پاراستنی هاوسەنگی: یارمەتی گەڕاندنەوەی هاوسەنگی سروشتی پێستی سەر دەدات بەهۆی ئەوەی ڕێژەی ترشێتییەکەی (pH) گونجاوە (pH 5).\n٢. پێکهاتە گرنگەکانی:\nبەپێی زانیارییەکانی سەر کارتۆنەکە، ئەم پێکهاتانەی تێدایە:\n• سالی سیلیک ئەسید (Salicylic Acid): یارمەتی لێکردنەوەی قەپاڵ و کڕێشە چەورەکان دەدات.\n• پیرۆکتۆن ئۆلامین (Piroctone Olamine): دژە کەڕووە و هۆکاری سەرەکی دروستبوونی کڕێش لەناو دەبات.\n• بایۆتین و سیتاپۆڵ: بۆ بەهێزکردن و تەندروست ڕاگرتنی مووەکانی قژ.\n٣. چۆنیەتی بەکارهێنان:\n١. قژت بە باشی تەڕ بکە.\n٢. بڕێکی گونجاو لە شامپۆکە بدە لە پێستی سەرت و بە پەنجەکانت بە هێواشی مەساجی پێ بکە.\n٣. گرنگە: وازی لێ بهێنە بۆ ماوەی ٢ بۆ ٣ خولەک بە پێستی سەرەوە بمێنێتەوە تا پێکهاتەکانی کار بکەن.\n٤. دواتر بە ئاوێکی زۆر بیشۆ.\n٥. دەتوانیت لە هەفتەیەکدا ٢ بۆ ٣ جار بەکاری بهێنیت.\nتێبینی:\n• ئەگەر لە کاتی بەکارهێناندا چوو بە چاوتدا، خێرا بە ئاو بیشۆ.\n• ئەم شامپۆیە زیاتر بۆ چارەسەرە، بۆیە ئەگەر قژت زۆر وشک بووەوە، دەتوانیت لەگەڵ شامپۆیەکی ڕۆژانەی زۆر نەرم (Extra Mild) بە نۆبە بەکاری بهێنیت.\n',NULL,NULL,NULL,NULL,'2026-01-11 05:52:08',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'250ml','01-19',0,0),(245,'لۆشنی دژە هەڵوەرینی قژ لە بڕاندی بابێی ئیسپانی','Anti-hair loss lotion from Spanish brand Babe','لوشن مضاد لتساقط الشعر من ماركة Babe الإسبانية','لۆشنی دژە هەڵوەرینی قژ لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• بەهێزکردنی ڕەگی قژ: یارمەتی چالاککردنەوەی پیازە یان فۆلیکڵەکانی قژ دەدات بۆ ئەوەی قژەکە بەهێزتر شین ببێتەوە.\r\n• کۆنتڕۆڵکردنی چەوری: ڕێژەی چەوری زیادەی پێستی سەر ڕێکدەخات، چونکە زۆری چەوری یەکێکە لە هۆکارەکانی هەڵوەرین.\r\n• سوڕی خوێن: یارمەتی باشترکردنی سوڕی خوێن دەدات لە پێستی سەردا، ئەمەش وادەکات خۆراک و ئۆکسجینی زیاتر بگات بە قژەکە.\r\n• پێکهاتەی دەوڵەمەند: پێکهاتەی وەک (Cytobiol Bardane، Ginkgo Biloba، و Vital Hair)ی تێدایە کە بۆ تەندروستی قژ گرنگن.\r\nڕێگەی بەکارهێنان:\r\nبەپێی ڕێنمایییەکانی سەر کارتۆنەکە، بەم شێوەیە بەکاری بهێنە:\r\n1. کون کردنی سەری دەبەکه: سەرەتا پێویستە سەری دەبەکە بە توندی بەرەو خوارەوە دابگریت تاوەکو کانوولەکە (لولەکە) کون دەبێت و ئامادە دەبێت بۆ بەکارهێنان.\r\n2. بەکارهێنان: ڕۆژی دوو جار (بەیانیان و شەوان) بڕێکی گونجاو لە لۆشنەکە بدە لە پێستی سەرت.\r\n3. شێلان (مەساج): بە نوکی پەنجەکانت بە شێوەی بازنەیی مەساج بۆ پێستی سەرت بکە تاوەکو لۆشنەکە بە باشی هەڵدەمژرێت.\r\n4. تێبینی گرنگ: پێویست ناکات دوای بەکارهێنانی قژت بشۆیت (واتە بێ غوسڵە).\r\n5. ماوەی بەکارهێنان: بۆ ئەوەی باشترین ئەنجامت دەستبکەوێت، پێشنیار کراوە لانی کەم بۆ ماوەی ٣ مانگ بەردەوام بیت لەسەری.\r\nتێبینییەکان:\r\n• دەتوانرێت لەسەر قژی وشک یان تەڕ بەکاربهێنرێت.\r\n• ئەم بەرهەمە تێست کراوە لەلایەن پزیشکانی پێستەوە (Dermatologically Tested).\r\n','Key Features:\n• Strengthens the hair roots: Helps reactivate the onions or hair follicles to make the hair blue more strongly.\n• Oil control: Regulates the amount of excess oil on the scalp, as too much oil is one of the causes of hair loss.\n• Blood circulation: Helps improve blood circulation in the scalp, which allows more nutrients and oxygen to reach the hair.\n• Rich ingredients: Contains ingredients such as Cytobiol Bardane, Ginkgo Biloba, and Vital Hair that are important for hair health.\nHow to use:\nAccording to the instructions on the carton, use it as follows:\n1. Punch the top of the can: First, press the top of the can firmly downward until the cannula is punctured and ready for use.\n2. Usage: Apply an appropriate amount of the lotion to your scalp twice a day (morning and night).\n3. Rub (massage): Massage your scalp in circular motions with your fingertips until the lotion is well absorbed.\n4. Important Note: You do not need to wash your hair after use (i.e. no ghusl).\n5. Duration: For best results, it is recommended to continue for at least 3 months.\nNotes:\n• Can be used on dry or wet hair.\n• This product is Dermatologically Tested.','الميزات الرئيسية:\n• يقوي جذور الشعر: يساعد على تنشيط بصيلات الشعر لتعزيز لون الشعر.\n• التحكم في إفراز الزيوت: ينظم كمية الزيوت الزائدة في فروة الرأس، حيث أن زيادة إفراز الزيوت أحد أسباب تساقط الشعر.\n• تحسين الدورة الدموية: يساعد على تحسين الدورة الدموية في فروة الرأس، مما يسمح بوصول المزيد من العناصر الغذائية والأكسجين إلى الشعر.\n• مكونات غنية: يحتوي على مكونات مثل سايتوبيول باردان، وجينكو بيلوبا، وزيت فيتال هير، وهي مكونات مهمة لصحة الشعر.\n\nطريقة الاستخدام:\nاتبع التعليمات الموجودة على العبوة، واستخدمه كما يلي:\n1. اثقب غطاء العبوة: اضغط على غطاء العبوة بقوة للأسفل حتى يتم ثقب الأنبوب ويصبح جاهزًا للاستخدام.\n2. الاستخدام: ضع كمية مناسبة من اللوشن على فروة رأسك مرتين يوميًا (صباحًا ومساءً).\n3. التدليك: دلك فروة رأسك بحركات دائرية بأطراف أصابعك حتى يتم امتصاص اللوشن جيدًا.\n٤. ملاحظة هامة: لا داعي لغسل الشعر بعد الاستخدام (أي لا حاجة للاغتسال).\n٥. مدة الاستخدام: للحصول على أفضل النتائج، يُنصح بالاستمرار في الاستخدام لمدة ٣ أشهر على الأقل.\n\nملاحظات:\n• يُمكن استخدامه على الشعر الجاف أو المبلل.\n• هذا المنتج مُختَبَر من قِبَل أطباء الجلدية.\n','تایبەتمەندییە سەرەکییەکان:\n• بەهێزکردنی ڕەگی قژ: یارمەتی چالاککردنەوەی پیازە یان فۆلیکڵەکانی قژ دەدات بۆ ئەوەی قژەکە بەهێزتر شین ببێتەوە.\n• کۆنتڕۆڵکردنی چەوری: ڕێژەی چەوری زیادەی پێستی سەر ڕێکدەخات، چونکە زۆری چەوری یەکێکە لە هۆکارەکانی هەڵوەرین.\n• سوڕی خوێن: یارمەتی باشترکردنی سوڕی خوێن دەدات لە پێستی سەردا، ئەمەش وادەکات خۆراک و ئۆکسجینی زیاتر بگات بە قژەکە.\n• پێکهاتەی دەوڵەمەند: پێکهاتەی وەک (Cytobiol Bardane، Ginkgo Biloba، و Vital Hair)ی تێدایە کە بۆ تەندروستی قژ گرنگن.\nڕێگەی بەکارهێنان:\nبەپێی ڕێنمایییەکانی سەر کارتۆنەکە، بەم شێوەیە بەکاری بهێنە:\n1. کون کردنی سەری دەبەکه: سەرەتا پێویستە سەری دەبەکە بە توندی بەرەو خوارەوە دابگریت تاوەکو کانوولەکە (لولەکە) کون دەبێت و ئامادە دەبێت بۆ بەکارهێنان.\n2. بەکارهێنان: ڕۆژی دوو جار (بەیانیان و شەوان) بڕێکی گونجاو لە لۆشنەکە بدە لە پێستی سەرت.\n3. شێلان (مەساج): بە نوکی پەنجەکانت بە شێوەی بازنەیی مەساج بۆ پێستی سەرت بکە تاوەکو لۆشنەکە بە باشی هەڵدەمژرێت.\n4. تێبینی گرنگ: پێویست ناکات دوای بەکارهێنانی قژت بشۆیت (واتە بێ غوسڵە).\n5. ماوەی بەکارهێنان: بۆ ئەوەی باشترین ئەنجامت دەستبکەوێت، پێشنیار کراوە لانی کەم بۆ ماوەی ٣ مانگ بەردەوام بیت لەسەری.\nتێبینییەکان:\n• دەتوانرێت لەسەر قژی وشک یان تەڕ بەکاربهێنرێت.\n• ئەم بەرهەمە تێست کراوە لەلایەن پزیشکانی پێستەوە (Dermatologically Tested).',NULL,NULL,NULL,NULL,'2026-01-11 05:53:36',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'100ml','01-18',0,0),(246,'فلود(شلە)ی تایبەت بە چارەسەرکردنی پەڵە و یەکخستنی ڕەنگی پێست لە بڕاندی بابێی ئیسپانی','Fluid for spot treatment and skin tone unification from the Spanish brand Babe','سائل لعلاج البقع وتوحيد لون البشرة من ماركة Babe الإسبانية','فلود(شلە)ی تایبەت بە چارەسەرکردنی پەڵە و یەکخستنی ڕەنگی پێست لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,' ١. ئیشی سەرەکی چییە؟\r\n• لابردنی پەڵە: کار دەکات بۆ کاڵکردنەوەی ئەو پەڵە تۆخانەی بەهۆی خۆر، تەمەن، یان شوێنەواری زیپکەوە دروست بوون.\r\n• یەکخستنی ڕەنگ: ڕەنگی پێست گەشاوە و یەکدەست دەکات.\r\n• نوێکردنەوە: یارمەتی تازەبوونەوەی خانەکانی پێست دەدات (Renewal).\r\n٢. پێکهاتە سەرەکییەکانی:\r\nئەم فلۆیدە (شلەیە) کۆمەڵێک ماددەی چالاکی بەهێزی تێدایە کە لەسەر پاکەتەکە نوسراون:\r\n• Azeloglicina (3%): یارمەتی کەمکردنەوەی پەڵە و سووربوونەوە دەدات.\r\n• Hexylresorcinol (1%): ماددەیەکی بەهێزە بۆ سپیکردنەوە و ڕێگری لە دروستبوونی پەڵەی نوێ.\r\n• Niacinamide (2%): ڤیتامین B3 کە پێست ئارام دەکاتەوە و کونیلەکان بچووک دەکاتەوە و گەشاوەیی دەداتێ.\r\n• Stable Vitamin C (0.5%): دژە ئۆکسانێکی بەهێزە بۆ ڕووناککردنەوەی پێست.\r\n• Lactic Acid (3%): ترشێکی سووکە کە خانە مردووەکان لادەبات (تەقشیرێکی زۆر هێواش).\r\n٣. چۆنیەتی بەکارهێنان:\r\n• دەتوانیت بەیانیان و شەوان بەکاری بهێنیت.\r\n• بڕێکی گونجاو بدە لە پێستی دەموچاو، مل و سنگ (بەتایبەت ئەو شوێنانەی پەڵەیان پێوەیە).\r\n• تێبینی زۆر گرنگ: بەهۆی ئەوەی ماددەی دژە پەڵەی تێدایە، پێویستە بەیانیان حەتمەن دژەخۆر بەکاربهێنیت بۆ ئەوەی ئەنجامێکی باشت دەستبکەوێت و پێستت تووشی هەستیاری نەبێت.\r\n٤. جۆری پێست:\r\nئەم بەرهەمە بۆ هەموو جۆرە پێستەکان گونجاوە و بە شێوەیەک دروستکراوە کە زوو هەڵدەمژرێت و چەوری جێنەهێڵێت.\r\n','1. What is the main job?\n• Spot Remover: Works to fade dark spots caused by the sun, age, or acne scars.\n• Color unification: Brightens and uniforms skin tone.\n• Renewal: Helps skin cells renew.\n2. Key ingredients:\nThis fluid contains a number of powerful active ingredients that are written on the package:\n• Azeloglycina (3%): Helps reduce spots and redness.\n• Hexylresorcinol (1%): A powerful bleaching agent that prevents the formation of new spots.\n• Niacinamide (2%): Vitamin B3 that soothes the skin, shrinks pores and adds radiance.\n• Stable Vitamin C (0.5%): Powerful antioxidant for skin lightening.\n• Lactic Acid (3%): A mild acid that removes dead cells (very slow exfoliation).\n3. How to use:\n• You can use it in the morning and at night.\n• Apply an appropriate amount to the skin of the face, neck and chest (especially the scarred areas).\n• Very important note: Because it contains anti-spot substances, you should be sure to use sunscreen in the morning to get good results and avoid skin sensitivity.\n4. Skin Type:\nSuitable for all skin types, this product is formulated to absorb quickly and leave no oil.','١. ما هي الوظيفة الرئيسية؟\n• مزيل البقع: يعمل على تفتيح البقع الداكنة الناتجة عن الشمس أو التقدم في السن أو ندبات حب الشباب.\n• توحيد لون البشرة: يُفتّح لون البشرة ويُوحّده.\n• تجديد البشرة: يُساعد على تجديد خلايا البشرة.\n\n٢. المكونات الرئيسية:\nيحتوي هذا السائل على عدد من المكونات النشطة الفعّالة المذكورة على العبوة:\n• أزيلوجليسين (٣٪): يُساعد على تقليل البقع والاحمرار.\n• هيكسيل ريزورسينول (١٪): عامل تبييض قوي يمنع ظهور بقع جديدة.\n• نياسيناميد (٢٪): فيتامين ب٣ يُهدئ البشرة، ويُصغّر المسام، ويُضفي عليها نضارةً وإشراقًا.\n• فيتامين ج ثابت (٠.٥٪): مضاد أكسدة قوي لتفتيح البشرة.\n• حمض اللاكتيك (٣٪): حمض لطيف يُزيل الخلايا الميتة (تقشير بطيء جدًا).\n\n٣. طريقة الاستخدام:\n• يُمكن استخدامه صباحًا ومساءً.\n• ضعي كمية مناسبة على بشرة الوجه والرقبة والصدر (خاصةً المناطق التي بها ندوب).\n• ملاحظة هامة جدًا: نظرًا لاحتوائه على مواد مضادة للبقع، يُنصح باستخدام واقي الشمس صباحًا للحصول على أفضل النتائج وتجنب حساسية البشرة.\n\n4. نوع البشرة:\nهذا المنتج مناسب لجميع أنواع البشرة، وهو مصمم لامتصاص سريع ولا يترك أي أثر دهني.',' ١. ئیشی سەرەکی چییە؟\n• لابردنی پەڵە: کار دەکات بۆ کاڵکردنەوەی ئەو پەڵە تۆخانەی بەهۆی خۆر، تەمەن، یان شوێنەواری زیپکەوە دروست بوون.\n• یەکخستنی ڕەنگ: ڕەنگی پێست گەشاوە و یەکدەست دەکات.\n• نوێکردنەوە: یارمەتی تازەبوونەوەی خانەکانی پێست دەدات (Renewal).\n٢. پێکهاتە سەرەکییەکانی:\nئەم فلۆیدە (شلەیە) کۆمەڵێک ماددەی چالاکی بەهێزی تێدایە کە لەسەر پاکەتەکە نوسراون:\n• Azeloglicina (3%): یارمەتی کەمکردنەوەی پەڵە و سووربوونەوە دەدات.\n• Hexylresorcinol (1%): ماددەیەکی بەهێزە بۆ سپیکردنەوە و ڕێگری لە دروستبوونی پەڵەی نوێ.\n• Niacinamide (2%): ڤیتامین B3 کە پێست ئارام دەکاتەوە و کونیلەکان بچووک دەکاتەوە و گەشاوەیی دەداتێ.\n• Stable Vitamin C (0.5%): دژە ئۆکسانێکی بەهێزە بۆ ڕووناککردنەوەی پێست.\n• Lactic Acid (3%): ترشێکی سووکە کە خانە مردووەکان لادەبات (تەقشیرێکی زۆر هێواش).\n٣. چۆنیەتی بەکارهێنان:\n• دەتوانیت بەیانیان و شەوان بەکاری بهێنیت.\n• بڕێکی گونجاو بدە لە پێستی دەموچاو، مل و سنگ (بەتایبەت ئەو شوێنانەی پەڵەیان پێوەیە).\n• تێبینی زۆر گرنگ: بەهۆی ئەوەی ماددەی دژە پەڵەی تێدایە، پێویستە بەیانیان حەتمەن دژەخۆر بەکاربهێنیت بۆ ئەوەی ئەنجامێکی باشت دەستبکەوێت و پێستت تووشی هەستیاری نەبێت.\n٤. جۆری پێست:\nئەم بەرهەمە بۆ هەموو جۆرە پێستەکان گونجاوە و بە شێوەیەک دروستکراوە کە زوو هەڵدەمژرێت و چەوری جێنەهێڵێت.\n',NULL,NULL,NULL,NULL,'2026-01-11 05:55:52',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'40ml','01-17',0,0),(247,'لۆشنی تایبەت بە ڕووناککردنەوە و یەکخستنی ڕەنگی پێست لە بڕاندی بابێی ئیسپانی','Brightening and skin tone unifying lotion from Spanish brand Babe','لوشن لتفتيح وتوحيد لون البشرة من ماركة Babe الإسبانية','لۆشنی تایبەت بە ڕووناککردنەوە و یەکخستنی ڕەنگی پێست لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'پێکهاتە سەرەکییەکان:\r\nئەم بەرهەمە تێکەڵەیەکی بەهێزی تێدایە کە کاریگەرییان لەسەر تازەکردنەوەی پێست هەیە:\r\n• Gluconolactone (PHA) 5%: ترشێکی نەرمە کە پێستەکە پاک دەکاتەوە و خانە مردووەکان لادەبات بەبێ ئەوەی پێستەکە زۆر هەستیار بکات.\r\n• Niacinamide 3%: (ڤیتامین B3) یارمەتی کەمکردنەوەی سووربوونەوە و یەکخستنی ڕەنگی پێست دەدات.\r\n• Stable Vitamin C 2%: دژە ئۆکسانێکی بەهێزە، پێست گەشاوە دەکات و پەڵە کاڵ دەکاتەوە.\r\n• Panthenol 2%: پێستەکە بە نەرمی دەهێڵێتەوە و ناهێڵێت وشک ببێتەوە.\r\n• Hyaluronic Acid 0.1%: بۆ شێدارکردنەوەی پێست.\r\nسوودەکانی ئەم لۆشنە:\r\n1. ڕووناککردنەوە (Glow): یارمەتی درەوشانەوەی سروشتی پێست دەدات و بێڕەنگی لادەبات.\r\n2. یەکخستنی ڕەنگ: پەڵەی ڕەش و ناتەواوی ڕەنگی پێست کەمدەکاتەوە.\r\n3. تازەکردنەوە: بەهۆی هەبوونی PHA، پێست بە نەرمی نوێ دەکاتەوە و سافی دەکات.\r\n4. گونجاندن: لەسەر پاکەتەکە نووسراوە کە پشکنینی پزیشکی بۆ کراوە و لەگەڵ هەموو جۆرە پێستێک دەگونجێت.\r\nچۆنیەتی بەکارهێنان:\r\n• کات: دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.\r\n• شێواز: بڕێکی کەم بدە لە پەنجەکانت یان پارچە لۆکەیەک و بیدە لە پێستی پاکی ڕووخسار، مل و سەر سنگ.\r\n• تێبینی گرنگ: بەیانیان دوای بەکارهێنانی ئەم لۆشنە، پێویستە دژەخۆر (Sunscreen) بەکاربهێنیت بۆ ئەوەی پێستت لە تیشکی خۆر بپارێزیت.\r\n','Key Ingredients:\nThis product contains a powerful ingredient that has a skin refreshing effect:\n• Gluconolactone (PHA) 5%: Gentle acid that exfoliates and removes dead skin cells without over-sensitive skin.\n• Niacinamide 3%: (Vitamin B3) Helps reduce redness and even skin tone.\n• Stable Vitamin C 2%: Powerful antioxidant, brightens skin and fades spots.\n• Panthenol 2%: Keeps skin soft and prevents dryness.\n• Hyaluronic Acid 0.1%: To moisturize the skin.\nBenefits of this lotion:\n1. Glow: Helps skin\'s natural glow and removes discoloration.\n2. Color unification: Reduces dark spots and skin tone imperfections.\n3. Refreshing: Due to its PHA content, it gently renews and cleanses the skin.\n4. Compatibility: The packaging says that it has been medically tested and is suitable for all skin types.\nHow to use:\n• Time: You can use it twice a day (morning and night).\n• Method: Apply a small amount to your fingers or a piece of cloth and apply to clean skin of face, neck and chest.\n• Important Note: In the morning after using this lotion, you should use sunscreen to protect your skin from the sun.','المكونات الرئيسية:\nيحتوي هذا المنتج على مكونات فعّالة تُنعش البشرة:\n• غلوكونولاكتون (PHA) 5%: حمض لطيف يُقشّر البشرة ويزيل خلايا الجلد الميتة دون التسبب في تهيجها.\n• نياسيناميد 3% (فيتامين B3): يُساعد على تقليل الاحمرار وتوحيد لون البشرة.\n• فيتامين C ثابت 2%: مضاد أكسدة قوي، يُفتّح البشرة ويُخفّف البقع.\n• بانثينول 2%: يُحافظ على نعومة البشرة ويمنع جفافها.\n• حمض الهيالورونيك 0.1%: لترطيب البشرة.\n\nفوائد هذا المستحضر:\n1. إشراقة: يُساعد على استعادة إشراقة البشرة الطبيعية ويُزيل التصبغات\n2. توحيد اللون: يُقلّل من البقع الداكنة وعيوب لون البشرة\n3. انتعاش: بفضل احتوائه على PHA، يُجدّد البشرة ويُنظّفها بلطف.\n٤. التوافق: تشير العبوة إلى أن المنتج قد خضع لاختبارات طبية وهو مناسب لجميع أنواع البشرة.\n\nطريقة الاستخدام:\n• الوقت: يمكن استخدامه مرتين يوميًا (صباحًا ومساءً).\n• الطريقة: ضعي كمية صغيرة على أطراف أصابعك أو قطعة قماش، ثم وزعيها على بشرة نظيفة للوجه والرقبة والصدر.\n• ملاحظة هامة: في الصباح بعد استخدام هذا المستحضر، يُنصح باستخدام واقي الشمس لحماية بشرتك من أشعة الشمس.','پێکهاتە سەرەکییەکان:\nئەم بەرهەمە تێکەڵەیەکی بەهێزی تێدایە کە کاریگەرییان لەسەر تازەکردنەوەی پێست هەیە:\n• Gluconolactone (PHA) 5%: ترشێکی نەرمە کە پێستەکە پاک دەکاتەوە و خانە مردووەکان لادەبات بەبێ ئەوەی پێستەکە زۆر هەستیار بکات.\n• Niacinamide 3%: (ڤیتامین B3) یارمەتی کەمکردنەوەی سووربوونەوە و یەکخستنی ڕەنگی پێست دەدات.\n• Stable Vitamin C 2%: دژە ئۆکسانێکی بەهێزە، پێست گەشاوە دەکات و پەڵە کاڵ دەکاتەوە.\n• Panthenol 2%: پێستەکە بە نەرمی دەهێڵێتەوە و ناهێڵێت وشک ببێتەوە.\n• Hyaluronic Acid 0.1%: بۆ شێدارکردنەوەی پێست.\nسوودەکانی ئەم لۆشنە:\n1. ڕووناککردنەوە (Glow): یارمەتی درەوشانەوەی سروشتی پێست دەدات و بێڕەنگی لادەبات.\n2. یەکخستنی ڕەنگ: پەڵەی ڕەش و ناتەواوی ڕەنگی پێست کەمدەکاتەوە.\n3. تازەکردنەوە: بەهۆی هەبوونی PHA، پێست بە نەرمی نوێ دەکاتەوە و سافی دەکات.\n4. گونجاندن: لەسەر پاکەتەکە نووسراوە کە پشکنینی پزیشکی بۆ کراوە و لەگەڵ هەموو جۆرە پێستێک دەگونجێت.\nچۆنیەتی بەکارهێنان:\n• کات: دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.\n• شێواز: بڕێکی کەم بدە لە پەنجەکانت یان پارچە لۆکەیەک و بیدە لە پێستی پاکی ڕووخسار، مل و سەر سنگ.\n• تێبینی گرنگ: بەیانیان دوای بەکارهێنانی ئەم لۆشنە، پێویستە دژەخۆر (Sunscreen) بەکاربهێنیت بۆ ئەوەی پێستت لە تیشکی خۆر بپارێزیت.',NULL,NULL,NULL,NULL,'2026-01-11 05:58:05',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'150ml','01-16',0,0),(248,'سیڕۆمی چڕ و بەهێز تایبەت بە چارەسەرکردنی کێشەکانی ڕەنگی پێست و پەڵە لە بڕاندی بابێی ئیسپانی','Intensive and powerful serum for the treatment of skin color problems and spots from the Spanish brand Babe','سيروم مكثف وفعال لعلاج مشاكل لون البشرة والبقع من ماركة Babe الإسبانية','سیڕۆمی چڕ و بەهێز تایبەت بە چارەسەرکردنی کێشەکانی ڕەنگی پێست و پەڵە لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. کارە سەرەکییەکانی ئەم سێرمە:\r\n• لابردنی پەڵە: کاردەکات بۆ کاڵکردنەوە و نەهێشتنی پەڵە تۆخەکان (Hyperpigmentation).\r\n• یەکخستنی ڕەنگی پێست: یارمەتیدەرە بۆ ئەوەی ڕەنگی هەموو دەموچاو وەک یەک لێ بێتەوە.\r\n• نوێکردنەوەی پێست: بەهۆی هەبوونی ماددەی (Retinal)، خانە مردووەکانی پێست لادەبات و پێستەکە گەنج و گەشاوە دەکاتەوە.\r\n٢. پێکهاتە سەرەکییەکان:\r\nئەم سێرمە پێکهاتەی زۆر بەهێزی تێدایە کە پێکەوە کاردەکەن:\r\n• Tranexamic Acid: بۆ ڕێگریکردن لە دروستبوونی پەڵەی نوێ.\r\n• Niacinamide: بۆ هێورکردنەوەی پێست و کەمکردنەوەی سووربوونەوە.\r\n• Arbutin: بۆ سپیکردنەوە و درەوشانەوەی پێست.\r\n• Retinal: کە جۆرێکی بەهێزی ڤیتامین A یە، بۆ نوێکردنەوەی خانەکان و دژە پیربوون.\r\n٣. شێوازی بەکارهێنان (زۆر گرنگە):\r\n• تەنها شەوان بەکاردێت:  (NIGHT)، چونکە پێکهاتەی ڕێتیناڵی تێدایە و نابێت بەر تیشکی خۆر بکەوێت.\r\n• بڕی پێویست: چەند دڵۆپێکی کەم بدە لەو شوێنانەی پەڵەیان پێوەیە، یان تەواوی دەموچاو و مل (دوور لە چاوەکانت).\r\n• دژەخۆر: زۆر پێویستە بەیانیان دژەخۆر (SPF 50) بەکاربهێنیت، چونکە ئەم سێرمە پێست هەستیار دەکات بە تیشکی خۆر.\r\n٤. تێبینییەکان:\r\n• ئەم بەرهەمە بۆ هەموو جۆرە پێستێک گونجاوە، بەڵام ئەگەر پێستت زۆر هەستیارە، سەرەتا بە بڕێکی کەم و دوو شەو جارێک دەست پێ بکە تا پێستت ڕادێت.\r\n• نابێت لە کاتی دووگیانی (حامیلە) و شیرپێداندا بەکاربهێنرێت بەبێ پرسی دکتۆر، بەهۆی هەبوونی ڕێتیناڵ.\r\n','The main functions of this serum:\n• Spot remover: Works to fade and eliminate dark spots (Hyperpigmentation).\n• Skin tone unification: Helps to make the whole face look the same.\n• Skin renewal: Due to the presence of retinal, removes dead skin cells and makes the skin young and bright.\n2. Key Ingredients:\nThis serum contains very powerful ingredients that work together:\n• Tranexamic Acid: To prevent new scarring.\n• Niacinamide: To soothe the skin and reduce redness.\n• Arbutin: For whitening and brightening the skin.\n• Retinal: A powerful form of vitamin A, for cell renewal and anti-aging.\n3. How to use (very important):\n• Only used at night: (NIGHT), because it contains retinal ingredients and should not be exposed to sunlight.\n• Dosage: Apply a few drops to the affected areas, or the entire face and neck (away from your eyes).\n• Sunscreen: It is very important to use sunscreen (SPF 50) in the morning, as this serum makes the skin sensitive to sunlight.\n4. Notes:\n• This product is suitable for all skin types, but if you have very sensitive skin, start with a small amount once every two nights until your skin gets used to it.\n• Should not be used during pregnancy and breastfeeding without consulting a doctor, due to the presence of retina.','الوظائف الرئيسية لهذا السيروم:\n• مزيل للبقع: يعمل على تفتيح وإزالة البقع الداكنة (فرط التصبغ).\n• توحيد لون البشرة: يساعد على جعل الوجه بأكمله يبدو متجانسًا.\n• تجديد البشرة: بفضل احتوائه على الريتينول، يزيل خلايا الجلد الميتة ويجعل البشرة شابة ونضرة.\n\n٢. المكونات الرئيسية:\nيحتوي هذا السيروم على مكونات فعّالة للغاية تعمل معًا:\n• حمض الترانيكساميك: لمنع ظهور ندبات جديدة.\n• النياسيناميد: لتهدئة البشرة وتقليل الاحمرار.\n• الأربوتين: لتفتيح وتوحيد لون البشرة.\n• الريتينول: شكل فعّال من فيتامين أ، لتجديد الخلايا ومكافحة علامات الشيخوخة.\n\n٣. طريقة الاستخدام (هام جدًا):\n• يُستخدم ليلًا فقط: (ليلاً)، لاحتوائه على مكونات الريتينول، ويجب تجنب تعريضه لأشعة الشمس.\n• الجرعة: ضعي بضع قطرات على المناطق المصابة، أو على كامل الوجه والرقبة (مع تجنب منطقة العينين).\n• واقي الشمس: من المهم جدًا استخدام واقي الشمس (SPF ٥٠) صباحًا، لأن هذا السيروم يجعل البشرة حساسة لأشعة الشمس.\n\n٤. ملاحظات:\n• هذا المنتج مناسب لجميع أنواع البشرة، ولكن إذا كانت بشرتكِ حساسة جدًا، ابدئي بكمية صغيرة مرة كل ليلتين حتى تعتاد بشرتكِ عليه.\n• لا يُنصح باستخدامه أثناء الحمل والرضاعة دون استشارة الطبيب، لاحتوائه على مادة الريتينول.\n','. کارە سەرەکییەکانی ئەم سێرۆمە:\n• لابردنی پەڵە: کاردەکات بۆ کاڵکردنەوە و نەهێشتنی پەڵە تۆخەکان (Hyperpigmentation).\n• یەکخستنی ڕەنگی پێست: یارمەتیدەرە بۆ ئەوەی ڕەنگی هەموو دەموچاو وەک یەک لێ بێتەوە.\n• نوێکردنەوەی پێست: بەهۆی هەبوونی ماددەی (Retinal)، خانە مردووەکانی پێست لادەبات و پێستەکە گەنج و گەشاوە دەکاتەوە.\n٢. پێکهاتە سەرەکییەکان:\nئەم سێرمە پێکهاتەی زۆر بەهێزی تێدایە کە پێکەوە کاردەکەن:\n• Tranexamic Acid: بۆ ڕێگریکردن لە دروستبوونی پەڵەی نوێ.\n• Niacinamide: بۆ هێورکردنەوەی پێست و کەمکردنەوەی سووربوونەوە.\n• Arbutin: بۆ سپیکردنەوە و درەوشانەوەی پێست.\n• Retinal: کە جۆرێکی بەهێزی ڤیتامین A یە، بۆ نوێکردنەوەی خانەکان و دژە پیربوون.\n٣. شێوازی بەکارهێنان (زۆر گرنگە):\n• تەنها شەوان بەکاردێت:  (NIGHT)، چونکە پێکهاتەی ڕێتیناڵی تێدایە و نابێت بەر تیشکی خۆر بکەوێت.\n• بڕی پێویست: چەند دڵۆپێکی کەم بدە لەو شوێنانەی پەڵەیان پێوەیە، یان تەواوی دەموچاو و مل (دوور لە چاوەکانت).\n• دژەخۆر: زۆر پێویستە بەیانیان دژەخۆر (SPF 50) بەکاربهێنیت، چونکە ئەم سێرمە پێست هەستیار دەکات بە تیشکی خۆر.\n٤. تێبینییەکان:\n• ئەم بەرهەمە بۆ هەموو جۆرە پێستێک گونجاوە، بەڵام ئەگەر پێستت زۆر هەستیارە، سەرەتا بە بڕێکی کەم و دوو شەو جارێک دەست پێ بکە تا پێستت ڕادێت.\n• نابێت لە کاتی دووگیانی (حامیلە) و شیرپێداندا بەکاربهێنرێت بەبێ پرسی دکتۆر، بەهۆی هەبوونی ڕێتیناڵ.\n',NULL,NULL,NULL,NULL,'2026-01-11 06:00:34',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'30ml','01-15',0,0),(249,'کرێمی تایبەت بە پێستی پێگەیشتوو (سەروو ٤٠ ساڵ) لە بڕاندی بابێی ئیسپانی','Cream for mature skin (over 40 years) from the Spanish brand Babe','كريم للبشرة الناضجة (أكثر من 40 عامًا) من ماركة Babe الإسبانية','کرێمی تایبەت بە پێستی پێگەیشتوو (سەروو ٤٠ ساڵ) لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'کارە سەرەکییەکانی ئەم کرێمە:\r\n• دژە چرچولۆچی: یارمەتی کەمکردنەوەی نیشانەکانی پیری و چرچی پێست دەدات.\r\n• توندکردنەوە (Firming): پێستەکە توند دەکاتەوە و ڕێگری لە شۆڕبوونەوەی دەکات.\r\n• تێرکەر و شێدارکەر (Nourishing): بەهۆی هەبوونی ڕۆنی سروشتی، پێست بە قووڵی نەرم دەکات و بۆ ئەو کەسانە زۆر باشە کە پێستیان وشک بووەتەوە.\r\n• یەکخستنی ڕەنگی پێست: کار دەکات بۆ کاڵکردنەوەی پەڵە و یەکخستنی ڕەنگی دەموچاو.\r\nپێکهاتە گرنگەکانی:\r\nبەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە، ئەمانە گرنگترین پێکهاتەکانین:\r\n• Centella Asiatica (3%): بۆ چاککردنەوەی خانەکانی پێست و هێورکردنەوەی زۆر بەسوودە.\r\n• Biolin Prebiotic (2%): پارێزگاری لە بەکتریا سوودبەخشەکانی سەر پێست دەکات و بەرگری پێست بەهێز دەکات.\r\n• Vitamin C & Vitamin E: وەک دژە ئۆکسان کار دەکەن بۆ گەشانەوەی پێست و پاراستنی لە کاریگەرییە دەرەکییەکان.\r\n• Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵ و پڕکردنەوەی هێڵە وردەکانی دەموچاو.\r\n• Lactic Acid & Pyruvic Acid: یارمەتی تازەکردنەوەی خانەکانی پێست دەدەن.\r\n• Collagen & Elastin: بۆ پاراستنی نەرموونیانی و توندی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n1. پێستت بە باشی پاک بکەرەوە.\r\n2. بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاو و مل.\r\n3. بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\n4. دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.\r\nتێبینی:\r\nئەم کرێمە بە تایبەت بۆ Mature Skin (پێستی گەورە و پێگەیشتوو) دروستکراوە. ئەگەر پێستت زۆر چەورە، ڕەنگە کەمێک بۆت قورس بێت، بەڵام بۆ پێستی وشک، نۆرماڵ و تێکەڵاو زۆر گونجاوە.\r\n','The main functions of this cream:\n• Anti-wrinkle: Helps reduce signs of aging and wrinkles.\n• Firming: Tightens the skin and prevents sagging.\n• Nourishing: Due to its natural oils, it deeply softens the skin and is great for people with dry skin.\n• Skin tone unifying: Works to fade spots and unify facial tone.\nImportant components:\nAccording to the carton, these are the most important ingredients:\n• Centella Asiatica (3%): Very useful for repairing skin cells and soothing.\n• Biolin Prebiotic (2%): Protects beneficial bacteria on the skin and strengthens skin immunity.\n• Vitamin C & Vitamin E: Act as antioxidants to brighten the skin and protect it from external influences.\n• Hyaluronic Acid: To deeply hydrate and fill in fine facial lines.\n• Lactic Acid & Pyruvic Acid: Help refresh skin cells.\n• Collagen & Elastin: To maintain skin softness and firmness.\nHow to use:\n1. Clean your skin thoroughly.\n2. Apply an appropriate amount of the cream to the face and neck.\n3. Gently massage until fully absorbed.\n4. You can use it twice a day (morning and night).\nnotice:\nThis cream is especially formulated for Mature Skin. If you have very oily skin, it may be a little difficult for you, but it is perfect for dry, normal and combination skin.','الوظائف الرئيسية لهذا الكريم:\n• مضاد للتجاعيد: يساعد على تقليل علامات الشيخوخة والتجاعيد.\n• شد البشرة: يشد البشرة ويمنع ترهلها.\n• تغذية البشرة: بفضل زيوته الطبيعية، ينعم البشرة بعمق وهو مثالي للبشرة الجافة.\n• توحيد لون البشرة: يعمل على تفتيح البقع وتوحيد لون الوجه.\n\nالمكونات الهامة:\nوفقًا للعبوة، هذه هي أهم المكونات:\n• نبات سرة الأرض (3%): مفيد جدًا في إصلاح خلايا البشرة وتهدئتها.\n• بريبيوتيك بيولين (2%): يحمي البكتيريا النافعة على البشرة ويقوي مناعتها.\n• فيتامين ج وفيتامين هـ: يعملان كمضادات للأكسدة لتفتيح البشرة وحمايتها من العوامل الخارجية.\n• حمض الهيالورونيك: لترطيب البشرة بعمق وملء الخطوط الدقيقة.\n• حمض اللاكتيك وحمض البيروفيك: يساعدان على تجديد خلايا البشرة.\n• الكولاجين والإيلاستين: للحفاظ على نعومة البشرة ومرونتها.\n\n\nطريقة الاستخدام:\n١. نظفي بشرتكِ جيداً.\n٢. ضعي كمية مناسبة من الكريم على الوجه والرقبة.\n٣. دلكي بلطف حتى يتم امتصاصه بالكامل.\n٤. يمكنكِ استخدامه مرتين يومياً (صباحاً ومساءً).\n\nملاحظة:\nهذا الكريم مُصمم خصيصاً للبشرة الناضجة. إذا كانت بشرتكِ دهنية جداً، فقد يكون استخدامه صعباً بعض الشيء، ولكنه مثالي للبشرة الجافة والعادية والمختلطة.\n','کارە سەرەکییەکانی ئەم کرێمە:\n• دژە چرچولۆچی: یارمەتی کەمکردنەوەی نیشانەکانی پیری و چرچی پێست دەدات.\n• توندکردنەوە (Firming): پێستەکە توند دەکاتەوە و ڕێگری لە شۆڕبوونەوەی دەکات.\n• تێرکەر و شێدارکەر (Nourishing): بەهۆی هەبوونی ڕۆنی سروشتی، پێست بە قووڵی نەرم دەکات و بۆ ئەو کەسانە زۆر باشە کە پێستیان وشک بووەتەوە.\n• یەکخستنی ڕەنگی پێست: کار دەکات بۆ کاڵکردنەوەی پەڵە و یەکخستنی ڕەنگی دەموچاو.\nپێکهاتە گرنگەکانی:\nبەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە، ئەمانە گرنگترین پێکهاتەکانین:\n• Centella Asiatica (3%): بۆ چاککردنەوەی خانەکانی پێست و هێورکردنەوەی زۆر بەسوودە.\n• Biolin Prebiotic (2%): پارێزگاری لە بەکتریا سوودبەخشەکانی سەر پێست دەکات و بەرگری پێست بەهێز دەکات.\n• Vitamin C & Vitamin E: وەک دژە ئۆکسان کار دەکەن بۆ گەشانەوەی پێست و پاراستنی لە کاریگەرییە دەرەکییەکان.\n• Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵ و پڕکردنەوەی هێڵە وردەکانی دەموچاو.\n• Lactic Acid & Pyruvic Acid: یارمەتی تازەکردنەوەی خانەکانی پێست دەدەن.\n• Collagen & Elastin: بۆ پاراستنی نەرموونیانی و توندی پێست.\nچۆنیەتی بەکارهێنان:\n1. پێستت بە باشی پاک بکەرەوە.\n2. بڕێکی گونجاو لە کرێمەکە بدە لە دەموچاو و مل.\n3. بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\n4. دەتوانیت ڕۆژانە دوو جار (بەیانیان و شەوان) بەکاری بهێنیت.\nتێبینی:\nئەم کرێمە بە تایبەت بۆ Mature Skin (پێستی گەورە و پێگەیشتوو) دروستکراوە. ئەگەر پێستت زۆر چەورە، ڕەنگە کەمێک بۆت قورس بێت، بەڵام بۆ پێستی وشک، نۆرماڵ و تێکەڵاو زۆر گونجاوە.\n',NULL,NULL,NULL,NULL,'2026-01-11 08:30:58',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-14',0,0),(250,'کرێمی تایبەت بە گەنجکردنەوە و پاراستنی پێستی رۆژانە لە بڕاندی بابێی ئیسپانی','Daily skin rejuvenation and protection cream from Spanish brand Babe','كريم يومي لتجديد وحماية البشرة من ماركة BABE الإسبانية','کرێمی تایبەت بە گەنجکردنەوە و پاراستنی پێستی رۆژانە لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پاراستن لە تیشکی خۆر و ژینگە\r\n• SPF 30: پێست دەپارێزێت لە تیشکی زیانبەخشی خۆر (UVA/UVB).\r\n• پاراستن لە تیشکی شین و ژێر سوور: پێست دەپارێزێت لەو تیشکانەی کە لە شاشەی مۆبایل و کۆمپیوتەرەوە دەردەچن (HEV) و تیشکی گەرمی (IR).\r\n• دژە پیسبوونی ژینگە (Anti-Pollution): وەکو قەڵغانێک کاردەکات بۆ ڕێگری لە چوونە ناوەوەی تەپوتۆڵ و ماددە زیانبەخشەکان بۆ ناو کونیلەکانی پێست.\r\n٢. پێکهاتە سەرەکییەکان و سوودەکانیان\r\nئەم کرێمە کۆمەڵێک ماددەی چالاکی تێدایە کە کاریگەرییان بەهێزە:\r\n• Centella Asiatica (3%): یارمەتی چاکبوونەوەی پێست دەدات و هێمنی دەکاتەوە.\r\n• DMAE (2.5%): ماددەیەکی زۆر بەهێزە بۆ توندکردنەوەی پێست و ڕێگری لە شۆڕبوونەوە.\r\n• Prebiotics (2%): پارێزگاری لە هاوسەنگی بەکتریا سوودبەخشەکانی پێست دەکات، کە ئەمە دەبێتە هۆی بەهێزبوونی بەرگری پێست.\r\n• Vitamin C & E: وەکو دژە ئۆکسان کاردەکەن بۆ ڕووناککردنەوەی پێست و پاراستنی لە پیربوون.\r\n• Hyaluronic Acid: شێدارییەکی زۆر بە پێست دەبەخشێت و ڕێگری لە وشکبوونەوە دەکات.\r\n٣. کاریگەرییە گشتییەکان\r\n• توندکردنەوە (Lifting Effect): یارمەتی کەمکردنەوەی چرچوڵۆچی و هێڵە وردەکانی دەموچاو دەدات.\r\n• شێدارکردنی ٢٤ کاتژمێری: پێست بە نەرمی و گەشاوەیی دەهێڵێتەوە.\r\n• یەکخستنی ڕەنگی پێست: یارمەتی کەمکردنەوەی پەڵە و یەکخستنی ڕەنگی دەموچاو دەدات.\r\nچۆنیەتی بەکارهێنان:\r\n• بەیانیان بڕێکی گونجاو بدە لە دەموچاو و مل.\r\n• بە هێواشی مەساجی پێ بکە تا بەتەواوی هەڵدەمژرێت.\r\n• چونکە SPF 30ی تێدایە، باشترین کات بۆ بەکارهێنانی پێش چوونە دەرەوەیە لە ماڵ.\r\nتێبینی: ئەم بەرهەمە pHەکەی 5.5ە، کە زۆر گونجاوە بۆ سروشتی پێست و لەلایەن پزیشکانی چاو و پێستەوە تاقیکراوەتەوە.\r\n',' Protection from sunlight and the environment\n• SPF 30: Protects skin from harmful sun rays (UVA/UVB).\n• Blue and Infrared Radiation Protection: Protects skin from radiation emitted by mobile phone and computer screens (HEV) and heat radiation (IR).\n• Anti-Pollution: Acts as a shield to prevent dust and harmful substances from entering the pores of the skin.\n2. Key ingredients and benefits\nThis cream contains a number of active ingredients that have a strong effect:\n• Centella Asiatica (3%): Promotes skin healing and soothes.\n• DMAE (2.5%): A very powerful skin tightener and preventer of sagging.\n• Prebiotics (2%): Maintains the balance of beneficial skin bacteria, which strengthens the skin\'s immune system.\n• Vitamin C & E: Act as antioxidants to brighten skin and protect against aging.\n• Hyaluronic Acid: Provides skin with plenty of moisture and prevents dryness.\n3. General effects\n• Tightening (Lifting Effect): Helps reduce wrinkles and fine lines.\n• 24-hour moisturizing: Keeps skin soft and radiant.\n• Skin tone unification: Helps reduce blemishes and unify facial tone.\nHow to use:\n• Apply an appropriate amount to the face and neck in the morning.\n• Massage gently until completely absorbed.\n• Because it contains SPF 30, it is best used before leaving home.\nNote: This product has a pH of 5.5, which is perfect for the skin\'s nature and has been tested by ophthalmologists and dermatologists.',' حماية من أشعة الشمس والبيئة\n• عامل حماية من الشمس 30: يحمي البشرة من أشعة الشمس الضارة (UVA/UVB).\n• حماية من الأشعة الزرقاء والأشعة تحت الحمراء: يحمي البشرة من الإشعاع المنبعث من شاشات الهواتف المحمولة وأجهزة الكمبيوتر (HEV) والإشعاع الحراري (IR).\n• مضاد للتلوث: يعمل كحاجز لمنع دخول الغبار والمواد الضارة إلى مسام البشرة.\n\n2. المكونات الرئيسية وفوائدها\nيحتوي هذا الكريم على عدد من المكونات النشطة ذات التأثير القوي:\n• مستخلص نبات سرة الأرض (3%): يعزز التئام البشرة ويلطفها.\n• ثنائي ميثيل أمينو إيثانول (2.5%): عامل قوي جدًا لشد البشرة ومنع ترهلها.\n• البريبايوتكس (2%): يحافظ على توازن البكتيريا النافعة في البشرة، مما يقوي جهاز المناعة.\n• فيتامين ج وفيتامين هـ: يعملان كمضادات للأكسدة لتفتيح البشرة وحمايتها من علامات الشيخوخة.\n• حمض الهيالورونيك: يرطب البشرة بعمق ويمنع جفافها.\n\n٣. التأثيرات العامة\n• شد البشرة (تأثير رفع): يساعد على تقليل التجاعيد والخطوط الدقيقة.\n• ترطيب يدوم ٢٤ ساعة: يحافظ على نعومة البشرة وإشراقها.\n• توحيد لون البشرة: يساعد على تقليل الشوائب وتوحيد لون الوجه.\n\nطريقة الاستخدام:\n• ضعي كمية مناسبة على الوجه والرقبة صباحًا.\n• دلكي بلطف حتى يتم امتصاصه بالكامل.\n• نظرًا لاحتوائه على عامل حماية من الشمس SPF ٣٠، يُفضل استخدامه قبل الخروج من المنزل.\n\nملاحظة: يتميز هذا المنتج بدرجة حموضة ٥.٥، وهي مثالية لطبيعة البشرة، وقد تم اختباره من قبل أطباء العيون وأطباء الجلدية.\n','. پاراستن لە تیشکی خۆر و ژینگە\n• SPF 30: پێست دەپارێزێت لە تیشکی زیانبەخشی خۆر (UVA/UVB).\n• پاراستن لە تیشکی شین و ژێر سوور: پێست دەپارێزێت لەو تیشکانەی کە لە شاشەی مۆبایل و کۆمپیوتەرەوە دەردەچن (HEV) و تیشکی گەرمی (IR).\n• دژە پیسبوونی ژینگە (Anti-Pollution): وەکو قەڵغانێک کاردەکات بۆ ڕێگری لە چوونە ناوەوەی تەپوتۆڵ و ماددە زیانبەخشەکان بۆ ناو کونیلەکانی پێست.\n٢. پێکهاتە سەرەکییەکان و سوودەکانیان\nئەم کرێمە کۆمەڵێک ماددەی چالاکی تێدایە کە کاریگەرییان بەهێزە:\n• Centella Asiatica (3%): یارمەتی چاکبوونەوەی پێست دەدات و هێمنی دەکاتەوە.\n• DMAE (2.5%): ماددەیەکی زۆر بەهێزە بۆ توندکردنەوەی پێست و ڕێگری لە شۆڕبوونەوە.\n• Prebiotics (2%): پارێزگاری لە هاوسەنگی بەکتریا سوودبەخشەکانی پێست دەکات، کە ئەمە دەبێتە هۆی بەهێزبوونی بەرگری پێست.\n• Vitamin C & E: وەکو دژە ئۆکسان کاردەکەن بۆ ڕووناککردنەوەی پێست و پاراستنی لە پیربوون.\n• Hyaluronic Acid: شێدارییەکی زۆر بە پێست دەبەخشێت و ڕێگری لە وشکبوونەوە دەکات.\n٣. کاریگەرییە گشتییەکان\n• توندکردنەوە (Lifting Effect): یارمەتی کەمکردنەوەی چرچوڵۆچی و هێڵە وردەکانی دەموچاو دەدات.\n• شێدارکردنی ٢٤ کاتژمێری: پێست بە نەرمی و گەشاوەیی دەهێڵێتەوە.\n• یەکخستنی ڕەنگی پێست: یارمەتی کەمکردنەوەی پەڵە و یەکخستنی ڕەنگی دەموچاو دەدات.\nچۆنیەتی بەکارهێنان:\n• بەیانیان بڕێکی گونجاو بدە لە دەموچاو و مل.\n• بە هێواشی مەساجی پێ بکە تا بەتەواوی هەڵدەمژرێت.\n• چونکە SPF 30ی تێدایە، باشترین کات بۆ بەکارهێنانی پێش چوونە دەرەوەیە لە ماڵ.\nتێبینی: ئەم بەرهەمە pHەکەی 5.5ە، کە زۆر گونجاوە بۆ سروشتی پێست و لەلایەن پزیشکانی چاو و پێستەوە تاقیکراوەتەوە.',NULL,NULL,NULL,NULL,'2026-01-11 08:33:01',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-13',0,0),(251,'کرێمی تایبەت بە نوێکردنەوە و چاکردنەوەی پێست لە شەودا لە بڕاندی بابێی ئیسپانی','Skin renewal and repair cream at night from the Spanish brand Babe','كريم ليلي لتجديد البشرة وإصلاحها من ماركة Babe الإسبانية','کرێمی تایبەت بە نوێکردنەوە و چاکردنەوەی پێست لە شەودا لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پێکهاتە سەرەکییەکان و سوودەکانیان:\r\nئەم کرێمە کۆمەڵێک ماددەی زۆر کاریگەری تێدایە کە یارمەتی گەنجکردنەوەی پێست دەدەن:\r\n• باکوچیۆل (Bakuchiol 0.50%): جێگرەوەیەکی سروشتی ڕێتینۆڵە، یارمەتی کەمکردنەوەی چرچی دەدات بەبێ ئەوەی پێست بڕوشێنێت.\r\n• ڕێتینۆڵی داپۆشراو (Encapsulated Retinol 0.50%): یەکێکە لە بەهێزترین ماددەکان بۆ نوێکردنەوەی خانەکانی پێست و هاندانی بەرهەمهێنانی کۆلاجین.\r\n• ڤیتامین C و E: دژە ئۆکسانن، ڕەنگی پێست یەکدەخەن و گەشانەوەی پێ دەبەخشن.\r\n• ترشی هیالۆرۆنیک (Hyaluronic Acid): بۆ شێدارکردنەوەی قووڵی پێست.\r\n• کالێندۆلا و سێنتێلا (Calendula & Centella): بۆ هێورکردنەوەی پێست و چاککردنەوەی شانە تێکچووەکان.\r\n٢. کارکردنی ئەم کرێمە:\r\n• نوێکردنەوە (Renovating): لە کاتی شەودا خانە مردووەکان لادەبات و خانەی نوێ دروست دەکات.\r\n• دژە چرچی: یارمەتی کەمکردنەوەی هێڵە وردەکان و چرچییە قووڵەکان دەدات.\r\n• یەکخستنی ڕەنگ: پەڵە و ناڕێکی ڕەنگی پێست کەم دەکاتەوە.\r\n• بەهێزکردنی لاستیکی پێست: وا دەکات پێست توندتر و گەنجتر دەربکەوێت.\r\n٣. چۆنیەتی بەکارهێنان :\r\n• تەنها شەوان بەکاردێت.\r\n• بڕێکی گونجاو بدە لە دەموچاو و مل.\r\n• بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\nتێبینییەکی گرنگ:\r\nبەهۆی هەبوونی ڕێتینۆڵ تێیدا، ئەگەر یەکەمجارتە بەکاری بهێنیت، باشترە هەفتەی ٢ بۆ ٣ شەو دەست پێ بکەیت تا پێستت ڕادێت. هەروەها زۆر گرنگە بەیانیان دژە خۆر بەکاربهێنیت، چونکە ڕێتینۆڵ پێست بەرامبەر تیشکی خۆر هەستیار دەکات.\r\n','. . . . Key ingredients and benefits:\nThis cream contains some very effective ingredients that help rejuvenate the skin:\n• Bakuchiol (Bakuchiol 0.50%): A natural retinol replacement, it helps reduce wrinkles without stripping the skin.\n• Encapsulated Retinol (0.50%): One of the most powerful agents to renew skin cells and stimulate collagen production.\n• Vitamins C and E: Antioxidants, unify and brighten skin.\n• Hyaluronic Acid: To deeply moisturize the skin.\n• Calendula & Centella: To soothe skin and repair damaged tissue.\n2. How this cream works:\n• Renovating: During the night, it removes dead cells and makes new ones.\n• Anti-wrinkle: Helps reduce fine lines and deep wrinkles.\n• Color unification: Reduces spots and irregularities.\n• Strengthens skin elasticity: Makes skin look tighter and younger.\n3. How to use :\n• Used only at night.\n• Apply appropriate amounts to face and neck.\n• Gently massage until fully absorbed.\nImportant note:\nBecause of the retinol in it, if it’s your first time using it, it’s best to start 2 to 3 nights a week until your skin gets used to it. It is also very important to use sunscreen in the morning, as retinol sensitizes the skin to sunlight.','المكونات الرئيسية وفوائدها:\nيحتوي هذا الكريم على مكونات فعّالة للغاية تُساعد على تجديد البشرة:\n• باكوشيول (0.50%): بديل طبيعي للريتينول، يُساعد على تقليل التجاعيد دون تجريد البشرة من زيوتها الطبيعية.\n• ريتينول مُغلّف (0.50%): من أقوى العوامل لتجديد خلايا البشرة وتحفيز إنتاج الكولاجين.\n• فيتامينات C وE: مضادات أكسدة، تُوحّد لون البشرة وتُضفي عليها إشراقة.\n• حمض الهيالورونيك: لترطيب البشرة بعمق.\n• آذريون وسنتيلا: لتهدئة البشرة وإصلاح الأنسجة التالفة.\n\nكيفية عمل هذا الكريم:\n• التجديد: يُزيل الخلايا الميتة ويُجددها أثناء الليل.\n• مُضاد للتجاعيد: يُساعد على تقليل الخطوط الدقيقة والتجاعيد العميقة.\n• توحيد لون البشرة: يُقلل من البقع والعيوب.\n• يُعزز مرونة البشرة: يجعل البشرة تبدو أكثر تماسكًا وشبابًا.\n\nطريقة الاستخدام:\n• يُستخدم ليلًا فقط.\n• ضعي كمية مناسبة على الوجه والرقبة.\n• دلكي بلطف حتى يتم امتصاصه بالكامل.\n\nملاحظة هامة:\nنظرًا لاحتوائه على الريتينول، يُنصح باستخدامه مرتين أو ثلاث مرات أسبوعيًا في حال استخدامه لأول مرة، حتى تعتاد بشرتك عليه. كما يُنصح بشدة باستخدام واقي الشمس صباحًا، لأن الريتينول يزيد من حساسية البشرة لأشعة الشمس.\n','. پێکهاتە سەرەکییەکان و سوودەکانیان:\nئەم کرێمە کۆمەڵێک ماددەی زۆر کاریگەری تێدایە کە یارمەتی گەنجکردنەوەی پێست دەدەن:\n• باکوچیۆل (Bakuchiol 0.50%): جێگرەوەیەکی سروشتی ڕێتینۆڵە، یارمەتی کەمکردنەوەی چرچی دەدات بەبێ ئەوەی پێست بڕوشێنێت.\n• ڕێتینۆڵی داپۆشراو (Encapsulated Retinol 0.50%): یەکێکە لە بەهێزترین ماددەکان بۆ نوێکردنەوەی خانەکانی پێست و هاندانی بەرهەمهێنانی کۆلاجین.\n• ڤیتامین C و E: دژە ئۆکسانن، ڕەنگی پێست یەکدەخەن و گەشانەوەی پێ دەبەخشن.\n• ترشی هیالۆرۆنیک (Hyaluronic Acid): بۆ شێدارکردنەوەی قووڵی پێست.\n• کالێندۆلا و سێنتێلا (Calendula & Centella): بۆ هێورکردنەوەی پێست و چاککردنەوەی شانە تێکچووەکان.\n٢. کارکردنی ئەم کرێمە:\n• نوێکردنەوە (Renovating): لە کاتی شەودا خانە مردووەکان لادەبات و خانەی نوێ دروست دەکات.\n• دژە چرچی: یارمەتی کەمکردنەوەی هێڵە وردەکان و چرچییە قووڵەکان دەدات.\n• یەکخستنی ڕەنگ: پەڵە و ناڕێکی ڕەنگی پێست کەم دەکاتەوە.\n• بەهێزکردنی لاستیکی پێست: وا دەکات پێست توندتر و گەنجتر دەربکەوێت.\n٣. چۆنیەتی بەکارهێنان :\n• تەنها شەوان بەکاردێت.\n• بڕێکی گونجاو بدە لە دەموچاو و مل.\n• بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\nتێبینییەکی گرنگ:\nبەهۆی هەبوونی ڕێتینۆڵ تێیدا، ئەگەر یەکەمجارتە بەکاری بهێنیت، باشترە هەفتەی ٢ بۆ ٣ شەو دەست پێ بکەیت تا پێستت ڕادێت. هەروەها زۆر گرنگە بەیانیان دژە خۆر بەکاربهێنیت، چونکە ڕێتینۆڵ پێست بەرامبەر تیشکی خۆر هەستیار دەکات.\n',NULL,NULL,NULL,NULL,'2026-01-11 08:34:18',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'50ml','01-12',0,0),(252,'سیڕۆمی تایبەت بە نوێکردنەوەی پێست لە شەودا لە بڕاندی بابێی ئیسپانی','Night skin renewal serum from Spanish brand Babe','سيروم ليلي لتجديد البشرة من ماركة Babe الإسبانية','سیڕۆمی تایبەت بە نوێکردنەوەی پێست لە شەودا لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'کارەکانی ئەم بەرهەمە:\r\n• نوێکردنەوەی پێست: یارمەتی لادانی خانە مردووەکانی پێست دەدات و ڕەنگی دەموچاو گەش دەکاتەوە.\r\n• دژە چرچولۆچی: بەهۆی هەبوونی \"پڕۆ-ڕێتینۆڵ\"، یارمەتی کەمکردنەوەی هێڵە وردەکان و چرچی دەدات.\r\n• پاککردنەوەی پەڵە: کاردەکات بۆ کاڵکردنەوەی پەڵەی تەمەن یان ئەو پەڵانەی بەهۆی خۆرەوە دروست بوون.\r\n• کونکردنەوەی کونیلەکان: یارمەتی سافکردنی دەموچاو و بچووککردنەوەی کونیلە کراوەکان دەدات.\r\nپێکهاتە سەرەکییەکان (بەپێی پاکەتەکە):\r\nئەم سیرەمە پێکهاتەیەکی بەهێزی هەیە کە تێکەڵەیەکە لە ترشەکان و ڤیتامینەکان:\r\n1. Encapsulated Pro-Retinol (6.6%): جۆرێکی پەرەپێدراوی ڤیتامین A یە کە بە هێواشی دەچێتە ناو پێستەوە بۆ ئەوەی کەمترین هەستیاری دروست بکات و چرچی نەهێڵێت.\r\n2. Lactic Acid (5.6%) & Mandelic Acid (5%): ترشی (AHA)ن کە پێستەکە \"تەقشیر\" دەکەن و دەیشۆنەوە بۆ ئەوەی ساف و گەش بێت.\r\n3. Pyruvic Acid (1%): یارمەتی قووڵایی نوێبوونەوەی پێست دەدات.\r\n4. Bakuchiol (0.5%): جێگرەوەیەکی سروشتی ڕێتینۆڵە و کارەکانی بەهێزتر دەکات بەبێ سووربوونەوە.\r\n5. Vitamin C (0.5%): بۆ ڕوونکردنەوەی پێست و وەک دژە ئۆکسان.\r\n6. Hyaluronic Acid (0.1%): بۆ شێدارکردنەوەی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n• تەنها لە شەواندا: نابێت بە ڕۆژ بەکاربێت چونکە پێست بەرامبەر خۆر هەستیار دەکات.\r\n• بڕی بەکارهێنان: ٣ بۆ ٤ دڵۆپ بدە لە دەموچاو و مل و سنگ (لەسەر پێستی پاک و وشک).\r\n• پلەبەندی: لە سەرەتادا هەفتەی ٢ جار بەکاری بهێنە، پاشان ئەگەر پێستت ڕاهات دەتوانیت شەوانە بەکاری بهێنیت.\r\n• دژەخۆر: پێویستە بەیانیان حەتمەن دژەخۆر بەکاربهێنیت.\r\nئاگاداری:\r\n• مەیخە سەر برین یان پێستێک کە سووتاوی و هەستیاری پێوە بێت.\r\n• دوور بکەوەرەوە لە بەرکەوتنی بە چاو.\r\n• ئەگەر دووگیانیت یان شیر دەدەیت، باشترە پێش بەکارهێنانی ڕاوێژ بە پزیشک بکەیت (بەهۆی هەبوونی ڤیتامین A).\r\n','Works of this product:\n• Skin renewal: Helps remove dead skin cells and brightens the complexion.\n• Anti-wrinkle: Due to its pro-retinol content, it helps reduce fine lines and wrinkles.\n• Spot Cleansing: Works to fade age spots or spots caused by the sun.\n• Pore piercing: Helps cleanse the face and shrink open pores.\nKey ingredients (depending on the package):\nThis serum has a strong combination of acids and vitamins:\n1. Encapsulated Pro-Retinol (6.6%): An enhanced form of Vitamin A that penetrates slowly into the skin to minimize sensitivity and eliminate wrinkles.\n2. Lactic Acid (5.6%) & Mandelic Acid (5%): Acids (AHAs) that “exfoliate” and exfoliate the skin to make it clear and bright.\n3. Pyruvic Acid (1%): Promotes deep skin renewal.\n4. Bakuchiol (0.5%): A natural retinol replacer and strengthens its actions without redness.\n5. Vitamin C (0.5%): For skin lightening and as an antioxidant.\n6. Hyaluronic Acid (0.1%): To moisturize the skin.\nHow to use:\n• Only at night: Do not use during the day as it sensitizes the skin to the sun.\n• Dosage: Apply 3 to 4 drops to face, neck and chest (on clean, dry skin).\n• Graduation: Initially use 2 times a week, then if your skin gets used to it, you can use it at night.\n• Sunscreen: Be sure to use sunscreen in the morning.\nalert:\n• Do not apply to wounds or skin with burns or sensitivity.\n• Avoid eye contact.\n• If you are pregnant or breastfeeding, it is best to consult a doctor before use (due to its vitamin A content).','فوائد هذا المنتج:\n• تجديد البشرة: يساعد على إزالة خلايا الجلد الميتة وتفتيح لون البشرة.\n• مضاد للتجاعيد: بفضل محتواه من البرو-ريتينول، يساعد على تقليل الخطوط الدقيقة والتجاعيد.\n• تنظيف البقع: يعمل على تفتيح بقع الشيخوخة أو البقع الناتجة عن الشمس.\n• تضييق المسام: يساعد على تنظيف الوجه وتضييق المسام المفتوحة.\n\nالمكونات الرئيسية (حسب العبوة):\nيحتوي هذا السيروم على مزيج قوي من الأحماض والفيتامينات:\n1. برو-ريتينول مغلف (6.6%): شكل مُحسّن من فيتامين أ يتغلغل ببطء في البشرة لتقليل الحساسية والقضاء على التجاعيد.\n2. حمض اللاكتيك (5.6%) وحمض الماندليك (5%): أحماض (أحماض ألفا هيدروكسي) تُقشّر البشرة وتجعلها صافية ومشرقة.\n3. حمض البيروفيك (1%): يُعزز تجديد البشرة من الأعماق.\n٤. باكوشيول (٠.٥٪): بديل طبيعي للريتينول، يعزز فعاليته دون التسبب باحمرار.\n٥. فيتامين سي (٠.٥٪): لتفتيح البشرة وكمضاد للأكسدة.\n٦. حمض الهيالورونيك (٠.١٪): لترطيب البشرة.\n\nطريقة الاستخدام:\n• ليلاً فقط: لا يُستخدم نهاراً لأنه يزيد حساسية البشرة لأشعة الشمس.\n• الجرعة: ضعي ٣ إلى ٤ قطرات على الوجه والرقبة والصدر (على بشرة نظيفة وجافة).\n• الاستخدام التدريجي: استخدميه مبدئياً مرتين أسبوعياً، ثم إذا اعتادت بشرتك عليه، يمكنكِ استخدامه ليلاً.\n• واقي الشمس: احرصي على استخدام واقي الشمس صباحاً.\n\nتنبيه:\n• لا يُوضع على الجروح أو البشرة المصابة بحروق أو حساسية.\n• تجنبي ملامسة العينين.\n• إذا كنتِ حاملاً أو مرضعة، يُفضل استشارة الطبيب قبل الاستخدام (لاحتوائه على فيتامين أ).\n','کارەکانی ئەم بەرهەمە:\n• نوێکردنەوەی پێست: یارمەتی لادانی خانە مردووەکانی پێست دەدات و ڕەنگی دەموچاو گەش دەکاتەوە.\n• دژە چرچولۆچی: بەهۆی هەبوونی \"پڕۆ-ڕێتینۆڵ\"، یارمەتی کەمکردنەوەی هێڵە وردەکان و چرچی دەدات.\n• پاککردنەوەی پەڵە: کاردەکات بۆ کاڵکردنەوەی پەڵەی تەمەن یان ئەو پەڵانەی بەهۆی خۆرەوە دروست بوون.\n• کونکردنەوەی کونیلەکان: یارمەتی سافکردنی دەموچاو و بچووککردنەوەی کونیلە کراوەکان دەدات.\nپێکهاتە سەرەکییەکان (بەپێی پاکەتەکە):\nئەم سیرەمە پێکهاتەیەکی بەهێزی هەیە کە تێکەڵەیەکە لە ترشەکان و ڤیتامینەکان:\n1. Encapsulated Pro-Retinol (6.6%): جۆرێکی پەرەپێدراوی ڤیتامین A یە کە بە هێواشی دەچێتە ناو پێستەوە بۆ ئەوەی کەمترین هەستیاری دروست بکات و چرچی نەهێڵێت.\n2. Lactic Acid (5.6%) & Mandelic Acid (5%): ترشی (AHA)ن کە پێستەکە \"تەقشیر\" دەکەن و دەیشۆنەوە بۆ ئەوەی ساف و گەش بێت.\n3. Pyruvic Acid (1%): یارمەتی قووڵایی نوێبوونەوەی پێست دەدات.\n4. Bakuchiol (0.5%): جێگرەوەیەکی سروشتی ڕێتینۆڵە و کارەکانی بەهێزتر دەکات بەبێ سووربوونەوە.\n5. Vitamin C (0.5%): بۆ ڕوونکردنەوەی پێست و وەک دژە ئۆکسان.\n6. Hyaluronic Acid (0.1%): بۆ شێدارکردنەوەی پێست.\nچۆنیەتی بەکارهێنان:\n• تەنها لە شەواندا: نابێت بە ڕۆژ بەکاربێت چونکە پێست بەرامبەر خۆر هەستیار دەکات.\n• بڕی بەکارهێنان: ٣ بۆ ٤ دڵۆپ بدە لە دەموچاو و مل و سنگ (لەسەر پێستی پاک و وشک).\n• پلەبەندی: لە سەرەتادا هەفتەی ٢ جار بەکاری بهێنە، پاشان ئەگەر پێستت ڕاهات دەتوانیت شەوانە بەکاری بهێنیت.\n• دژەخۆر: پێویستە بەیانیان حەتمەن دژەخۆر بەکاربهێنیت.\nئاگاداری:\n• مەیخە سەر برین یان پێستێک کە سووتاوی و هەستیاری پێوە بێت.\n• دوور بکەوەرەوە لە بەرکەوتنی بە چاو.\n• ئەگەر دووگیانیت یان شیر دەدەیت، باشترە پێش بەکارهێنانی ڕاوێژ بە پزیشک بکەیت (بەهۆی هەبوونی ڤیتامین A).',NULL,NULL,NULL,NULL,'2026-01-11 08:35:39',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'30ml','01-11',0,0);
INSERT INTO `products` VALUES (253,'سڕۆمی ڤایتامین سی لە بڕاندی بابێی ئیسپانی','Vitamin C serum from Spanish brand Babe','سيروم فيتامين سي من العلامة التجارية الإسبانية Babe','سڕۆمی ڤایتامین سی لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پێکهاتە سەرەکییەکانی:\r\n• ڤیتامین C (ڕێژەی ١٥٪): ڕێژەیەکی بەرز و کاریگەرە بۆ سپیکردنەوەی پێست، نەهێشتنی پەڵە و هاندانی دروستبوونی کۆلاجین.\r\n• ئەسیدی فێرلیک (Ferulic Acid): دژە ئۆکسانێکی بەهێزە، کار دەکات بۆ پاراستنی پێست لە زیانەکانی تیشکی خۆر و پیسبوونی ژینگە.\r\n• کارنۆسین (Carnosine): یارمەتی پاراستنی خانەکانی پێست دەدات لە پیربوونی پێشوەختە و کاریگەرییە خراپەکانی \"ڕووناکی شین\" (Blue Light) کە لە مۆبایل و کۆمپیوتەرەوە دەردەچێت.\r\n• Prebiotic: یارمەتی هاوسەنگکردنی بەکتریای سوودبەخشی سەر پێست دەدات و بەرگری پێست بەهێز دەکات.\r\n• هەیالۆرۆنیک ئەسید: بۆ شێدارکردنەوەی قووڵی پێست.\r\n٢. سوودە سەرەکییەکانی:\r\n• ڕووناککردنەوە (Brightening): ڕەنگی پێست یەکدەخات و بریقەیەکی تەندروستی پێ دەبەخشێت.\r\n• دژە پیربوون: یارمەتی کەمکردنەوەی هێڵە وردەکانی دەموچاو دەدات.\r\n• پاراستن: بەرگری پێست بەهێز دەکات دژی دووکەڵ، پیسی و تیشکی زیانبەخش.\r\n• pH 4.5: ئەم نمرەی ترشێتییە زۆر گونجاوە بۆ ئەوەی ڤیتامین C بە باشترین شێوە کار بکات بەبێ ئەوەی پێست تووشی هەستیاری زۆر بکات.\r\n٣. چۆن بەکاری بهێنیت؟ \r\n1. سەرەتا دەموچاوت بە باشی پاک بکەرەوە و وشکی بکەرەوە.\r\n2. ٣ بۆ ٤ دڵۆپ لە سیرەمەکە بدە لە دەموچاو، مل و بەشی سەرەوەی سنگ.\r\n3. بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\n4. باشتر وایە بەیانیان بەکاری بهێنیت (لەبەر ئەوەی دژە ئۆکسانە)، بەڵام دەبێت دژە خۆر لەدوای ئەم سیرەمە بەکاربهێنیت بۆ ئەوەی ئەنجامێکی باشت دەستبکەوێت و پێستت نەسوتێت.\r\n⚠️ تێبینی گرنگ:\r\n• ئەم سیرەمە ڕێژەی ڤیتامین C تێیدا بەرزە (١٥٪)، ئەگەر پێستت زۆر هەستیارە، سەرەتا لە شوێنێکی بچووک تاقی بکەرەوە.\r\n• دوای کردنەوەی، لە شوێنێکی تاریک و فێنک دایبنێ چونکە ڤیتامین C بە ڕووناکی و گەرما تێکدەچێت.\r\n','Key ingredients:\n• Vitamin C (15%): High and effective for skin whitening, spot removal and stimulating collagen formation.\n• Ferulic Acid: A powerful antioxidant, it works to protect the skin from sun damage and environmental pollution.\n• Carnosine: Helps protect skin cells from premature aging and the harmful effects of \"blue light\" emitted by mobile phones and computers.\n• Prebiotic: Helps balance beneficial bacteria on the skin and strengthens the skin\'s immune system.\n• Hyaluronic Acid: For deep skin moisturizing.\n2. Key benefits:\n• Brightening: Unifies skin tone and gives it a healthy glow.\n• Anti-aging: Helps reduce fine lines.\n• Protection: Strengthens skin\'s resistance against smoke, dirt and harmful rays.\n• pH 4.5: This acidity score is ideal for vitamin C to work optimally without causing skin hypersensitivity.\n3. how do you use it \n1. First, cleanse and dry your face thoroughly.\n2. Apply 3 to 4 drops of the serum to face, neck and upper chest.\n3. Gently massage until fully absorbed.\n4. It is best to use it in the morning (because it is an antioxidant), but you must use sunscreen after this serum to get the best results and not burn your skin.\n⚠️ Important Note:\n• This serum is high in vitamin C (15%). If your skin is very sensitive, try it on a small area first.\n• After opening, store in a dark, cool place as vitamin C is degraded by light and heat.',' المكونات الرئيسية:\n• فيتامين سي (15%): عالي وفعال لتفتيح البشرة، وإزالة البقع، وتحفيز إنتاج الكولاجين.\n• حمض الفيروليك: مضاد أكسدة قوي، يعمل على حماية البشرة من أضرار أشعة الشمس والتلوث البيئي.\n• كارنوزين: يساعد على حماية خلايا البشرة من الشيخوخة المبكرة والآثار الضارة للضوء الأزرق المنبعث من الهواتف المحمولة وأجهزة الكمبيوتر.\n• بريبيوتيك: يساعد على موازنة البكتيريا النافعة على البشرة ويقوي جهاز المناعة فيها.\n• حمض الهيالورونيك: لترطيب البشرة بعمق.\n\n2. الفوائد الرئيسية:\n• تفتيح البشرة: يوحد لون البشرة ويمنحها إشراقة صحية.\n• مكافحة الشيخوخة: يساعد على تقليل الخطوط الدقيقة.\n• حماية البشرة: يعزز مقاومة البشرة للدخان والأوساخ والأشعة الضارة.\n• درجة حموضة 4.5: هذه الدرجة مثالية لعمل فيتامين سي على النحو الأمثل دون التسبب في فرط حساسية البشرة.\n\n3. طريقة الاستخدام:\n1. نظفي وجهكِ وجففيه جيدًا. ٢. ضعي ٣ إلى ٤ قطرات من السيروم على الوجه والرقبة وأعلى الصدر.\n٣. دلكي بلطف حتى يتم امتصاصه بالكامل.\n٤. يُفضل استخدامه صباحًا (لأنه مضاد للأكسدة)، ولكن يجب استخدام واقي الشمس بعده للحصول على أفضل النتائج وتجنب حروق الشمس.\n\n⚠️ ملاحظة هامة:\n• يحتوي هذا السيروم على نسبة عالية من فيتامين سي (١٥٪). إذا كانت بشرتك حساسة للغاية، جربيه على منطقة صغيرة أولًا.\n• بعد الفتح، يُحفظ في مكان بارد ومظلم لأن فيتامين سي يتأثر بالضوء والحرارة.\n','. پێکهاتە سەرەکییەکانی:\n• ڤیتامین C (ڕێژەی ١٥٪): ڕێژەیەکی بەرز و کاریگەرە بۆ سپیکردنەوەی پێست، نەهێشتنی پەڵە و هاندانی دروستبوونی کۆلاجین.\n• ئەسیدی فێرلیک (Ferulic Acid): دژە ئۆکسانێکی بەهێزە، کار دەکات بۆ پاراستنی پێست لە زیانەکانی تیشکی خۆر و پیسبوونی ژینگە.\n• کارنۆسین (Carnosine): یارمەتی پاراستنی خانەکانی پێست دەدات لە پیربوونی پێشوەختە و کاریگەرییە خراپەکانی \"ڕووناکی شین\" (Blue Light) کە لە مۆبایل و کۆمپیوتەرەوە دەردەچێت.\n• Prebiotic: یارمەتی هاوسەنگکردنی بەکتریای سوودبەخشی سەر پێست دەدات و بەرگری پێست بەهێز دەکات.\n• هەیالۆرۆنیک ئەسید: بۆ شێدارکردنەوەی قووڵی پێست.\n٢. سوودە سەرەکییەکانی:\n• ڕووناککردنەوە (Brightening): ڕەنگی پێست یەکدەخات و بریقەیەکی تەندروستی پێ دەبەخشێت.\n• دژە پیربوون: یارمەتی کەمکردنەوەی هێڵە وردەکانی دەموچاو دەدات.\n• پاراستن: بەرگری پێست بەهێز دەکات دژی دووکەڵ، پیسی و تیشکی زیانبەخش.\n• pH 4.5: ئەم نمرەی ترشێتییە زۆر گونجاوە بۆ ئەوەی ڤیتامین C بە باشترین شێوە کار بکات بەبێ ئەوەی پێست تووشی هەستیاری زۆر بکات.\n٣. چۆن بەکاری بهێنیت؟ \n1. سەرەتا دەموچاوت بە باشی پاک بکەرەوە و وشکی بکەرەوە.\n2. ٣ بۆ ٤ دڵۆپ لە سیرەمەکە بدە لە دەموچاو، مل و بەشی سەرەوەی سنگ.\n3. بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\n4. باشتر وایە بەیانیان بەکاری بهێنیت (لەبەر ئەوەی دژە ئۆکسانە)، بەڵام دەبێت دژە خۆر لەدوای ئەم سیرەمە بەکاربهێنیت بۆ ئەوەی ئەنجامێکی باشت دەستبکەوێت و پێستت نەسوتێت.\n⚠️ تێبینی گرنگ:\n• ئەم سیرەمە ڕێژەی ڤیتامین C تێیدا بەرزە (١٥٪)، ئەگەر پێستت زۆر هەستیارە، سەرەتا لە شوێنێکی بچووک تاقی بکەرەوە.\n• دوای کردنەوەی، لە شوێنێکی تاریک و فێنک دایبنێ چونکە ڤیتامین C بە ڕووناکی و گەرما تێکدەچێت.',NULL,NULL,NULL,NULL,'2026-01-11 08:36:54',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'30ml','01-10',0,0),(254,'کرێمی تایبەت بە چارەسەرکردنی کێشەکانی دەوروبەری چاو لە بڕاندی بابێی ئیسپانی','Cream for treating problems around the eyes from the Spanish brand Babe','كريم لعلاج مشاكل منطقة العين من ماركة Babe الإسبانية','کرێمی تایبەت بە چارەسەرکردنی کێشەکانی دەوروبەری چاو لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'سوودە سەرەکییەکانی:\r\n• نەهێشتنی ڕەشی دەوری چاو: کاردەکات بۆ کاڵکردنەوە و نەهێشتنی ئەو ڕەشی و پەڵانەی لە ژێر چاودا دروست دەبن.\r\n• یەکخستنی ڕەنگی پێست: یارمەتی یەکسانکردنەوەی ڕەنگی ناوچەی دەوری چاو دەدات لەگەڵ باقی ڕوخسار.\r\n• کەمکردنەوەی پف و ماندوویەتی: یارمەتی کەمکردنەوەی هەوکردن و پفکردنی ژێر چاو دەدات.\r\n• بەکارهێنانی شەو و ڕۆژ: دەتوانیت هەم بەیانیان و هەم شەوان پێش خەوتن بەکاری بهێنیت.\r\nپێکهاتە گرنگەکانی (وەک لەسەر کارتۆنەکە نووسراوە):\r\n1. Liposome Vitamin K1 Oxide: زۆر کاریگەرە بۆ کەمکردنەوەی ڕەشی ژێر چاو کە بەهۆی کێشەی بۆرییە خوێنەکانەوە دروست بووە.\r\n2. Tranexamic Acid Complex: یارمەتی کەمکردنەوەی پەڵە و ڕەشی پێست دەدات و ڕێگری لە دروستبوونی پەڵەی نوێ دەکات.\r\n3. HPR (Retinoid): جۆرێکی پێشکەوتووی رێتینۆڵە کە یارمەتی نوێکردنەوەی خانەکان و کەمکردنەوەی چرچی دەدات بەبێ ئەوەی پێستەکە زۆر هەستیار بکات.\r\n4. Caffeine (1%): بۆ کەمکردنەوەی پفکردنی ژێر چاو و چالاککردنی سوڕی خوێن لەو ناوچەیەدا.\r\n5. Niacinamide (3%): بۆ شێدارکردنەوە و سپیکردنەوەی پێست.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی کەم لە کرێمەکە بدە لە ژێر چاو و دەوروبەری.\r\n• بە سەری پەنجەکانت بە هێواشی (وەک تەپتەپە) بڵاوی بکەرەوە تاوەکو پێستەکە هەڵی دەمژێت.\r\n• ئاگاداربە نەچێتە ناو چاوەکانتەوە.\r\nتێبینی: بەهۆی هەبوونی ماددەی (HPR/Retinoid) تێیدا، ئەگەر پێستت زۆر هەستیارە یان دووگیانیت، باشترە پێشتر ڕاوێژ بە پزیشک بکەیت.\r\n','Key benefits:\n• Eliminate dark circles around the eyes: Works to fade and eliminate dark circles and spots under the eyes.\n• Skin tone unification: Helps even out the color of the area around the eyes with the rest of the face.\n• Reduce puffiness and fatigue: Helps reduce inflammation and puffiness under the eyes.\n• Day and night use: You can use it both in the morning and at night before going to bed.\nImportant ingredients (as listed on the carton):\n1. Liposome Vitamin K1 Oxide: Very effective for reducing dark circles under the eyes caused by blood vessel problems.\n2. Tranexamic Acid Complex: Helps reduce spots and dark circles and prevents the formation of new scars.\n3. HPR (Retinoid): An advanced form of retinol that helps renew cells and reduce wrinkles without making the skin too sensitive.\n4. Caffeine (1%): To reduce puffiness under the eyes and activate blood circulation in the area.\n5. Niacinamide (3%): To moisturize and whiten the skin.\nHow to use:\n• Apply a small amount of the cream under and around the eyes.\n• Spread gently (like a patch) with your fingertips until absorbed by the skin.\n• Be careful not to get it in your eyes.\nNote: Due to the presence of HPR/Retinoid, it is best to consult a doctor if your skin is very sensitive or you are pregnant.','الفوائد الرئيسية:\n• إزالة الهالات السوداء حول العينين: يعمل على تفتيح وإزالة الهالات السوداء والبقع تحت العينين.\n• توحيد لون البشرة: يساعد على توحيد لون منطقة ما حول العينين مع باقي الوجه.\n• تقليل الانتفاخ والإرهاق: يساعد على تقليل الالتهاب والانتفاخ تحت العينين.\n• للاستخدام صباحًا ومساءً: يمكن استخدامه صباحًا ومساءً قبل النوم.\n\nالمكونات الهامة (كما هو موضح على العبوة):\n1. أكسيد فيتامين K1 الليبوزومي: فعال جدًا في تقليل الهالات السوداء تحت العينين الناتجة عن مشاكل الأوعية الدموية.\n2. مركب حمض الترانيكساميك: يساعد على تقليل البقع والهالات السوداء ويمنع ظهور ندبات جديدة.\n3. HPR (ريتينويد): شكل متطور من الريتينول يساعد على تجديد الخلايا وتقليل التجاعيد دون التسبب في حساسية مفرطة للبشرة.\n4. الكافيين (1%): لتقليل الانتفاخ تحت العينين وتنشيط الدورة الدموية في هذه المنطقة.\n٥. نياسيناميد (٣٪): لترطيب وتفتيح البشرة.\n\nطريقة الاستخدام:\n• ضعي كمية صغيرة من الكريم تحت وحول العينين.\n• وزّعيه بلطف (مثل رقعة صغيرة) بأطراف أصابعك حتى تمتصه البشرة.\n• احرصي على عدم ملامسته للعينين.\n\nملاحظة: نظرًا لاحتواء الكريم على مادة HPR/الريتينويد، يُنصح باستشارة الطبيب إذا كانت بشرتك حساسة للغاية أو كنتِ حاملاً.\n','سوودە سەرەکییەکانی:\n• نەهێشتنی ڕەشی دەوری چاو: کاردەکات بۆ کاڵکردنەوە و نەهێشتنی ئەو ڕەشی و پەڵانەی لە ژێر چاودا دروست دەبن.\n• یەکخستنی ڕەنگی پێست: یارمەتی یەکسانکردنەوەی ڕەنگی ناوچەی دەوری چاو دەدات لەگەڵ باقی ڕوخسار.\n• کەمکردنەوەی پف و ماندوویەتی: یارمەتی کەمکردنەوەی هەوکردن و پفکردنی ژێر چاو دەدات.\n• بەکارهێنانی شەو و ڕۆژ: دەتوانیت هەم بەیانیان و هەم شەوان پێش خەوتن بەکاری بهێنیت.\nپێکهاتە گرنگەکانی (وەک لەسەر کارتۆنەکە نووسراوە):\n1. Liposome Vitamin K1 Oxide: زۆر کاریگەرە بۆ کەمکردنەوەی ڕەشی ژێر چاو کە بەهۆی کێشەی بۆرییە خوێنەکانەوە دروست بووە.\n2. Tranexamic Acid Complex: یارمەتی کەمکردنەوەی پەڵە و ڕەشی پێست دەدات و ڕێگری لە دروستبوونی پەڵەی نوێ دەکات.\n3. HPR (Retinoid): جۆرێکی پێشکەوتووی رێتینۆڵە کە یارمەتی نوێکردنەوەی خانەکان و کەمکردنەوەی چرچی دەدات بەبێ ئەوەی پێستەکە زۆر هەستیار بکات.\n4. Caffeine (1%): بۆ کەمکردنەوەی پفکردنی ژێر چاو و چالاککردنی سوڕی خوێن لەو ناوچەیەدا.\n5. Niacinamide (3%): بۆ شێدارکردنەوە و سپیکردنەوەی پێست.\nچۆنیەتی بەکارهێنان:\n• بڕێکی کەم لە کرێمەکە بدە لە ژێر چاو و دەوروبەری.\n• بە سەری پەنجەکانت بە هێواشی (وەک تەپتەپە) بڵاوی بکەرەوە تاوەکو پێستەکە هەڵی دەمژێت.\n• ئاگاداربە نەچێتە ناو چاوەکانتەوە.\nتێبینی: بەهۆی هەبوونی ماددەی (HPR/Retinoid) تێیدا، ئەگەر پێستت زۆر هەستیارە یان دووگیانیت، باشترە پێشتر ڕاوێژ بە پزیشک بکەیت.',NULL,NULL,NULL,NULL,'2026-01-11 08:38:18',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'15ml','01-9',0,0),(256,'کرێمی تایبەت بە چاککردن و پاراستنی پێستی دەوروبەری چاو و لێو لە بڕاندی بابێی ئیسپانی','Cream for repairing and protecting the skin around the eyes and lips from the Spanish brand Babe','كريم لإصلاح وحماية البشرة حول العينين والشفاه من ماركة Babe الإسبانية','کرێمی تایبەت بە چاککردن و پاراستنی پێستی دەوروبەری چاو و لێو لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'کارەکانی ئەم بەرهەمە:\r\n• دژە چرچولۆچی: یارمەتی کەمکردنەوەی هێڵە وردەکان و چرچی دەوروبەری چاو و لێو دەدات.\r\n• کەمکردنەوەی هەڵئاوسان و ڕەشی: کاریگەری هەیە لەسەر کەمکردنەوەی پفکردنی ژێر چاو و ئەو ڕەشییەی کە لەو ناوچەیە دروست دەبێت.\r\n• توندکردنەوە: وەک \"تێنسۆر\" (Tensor) کار دەکات، واتە پێستەکە کەمێک توند دەکاتەوە و نەرمی و لاستیکییەکەی بۆ دەگەڕێنێتەوە.\r\nپێکهاتە سەرەکییەکانی:\r\nئەم کرێمە پێکهاتەی زۆر بەهێزی تێدایە کە بەیەکەوە کار دەکەن:\r\n1. Bakuchiol & Retinol: ئەمانە باشترین پێکهاتەن بۆ نوێکردنەوەی خانەکانی پێست و بەرەنگاربوونەوەی نیشانەکانی پیری.\r\n2. Caffeine (کافایین): بۆ کەمکردنەوەی پف و ڕەشی ژێر چاو.\r\n3. Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵی پێست.\r\n4. Prebiotic & Peptides: بۆ بەهێزکردنی بەربەستی پارێزەری پێست و هاندانی دروستبوونی کۆلاجین.\r\nچۆنیەتی بەکارهێنان:\r\n• بڕێکی کەم لە کرێمەکە بدە لە دەوروبەری چاوەکان (بەشی سەرەوەی ئێسکی ڕوومەت) و دەوروبەری لێوەکان.\r\n• بە نوکە پەنجە و بە شێوەی لێدانی زۆر سوک (Tapping) بڵاوی بکەرەوە تا هەڵدەمژرێت.\r\n• ئاگاداربە نەچێتە ناو خودی چاوەکەتەوە.\r\nتێبینییە گرنگەکان:\r\n• pH 7: پلەی ترشێتییەکەی گونجاوە بۆ ئەوەی چاو نەکورێنێتەوە.\r\n• ئەم بەرهەمە لەلایەن پزیشکانی چاو و پێستەوە تاقی کراوەتەوە.\r\n','Works of this product:\n• Anti-wrinkle: Helps reduce fine lines and wrinkles around the eyes and lips.\n• Reduce puffiness and dark circles: It reduces puffiness under the eyes and dark circles that form in the area.\n• Tightening: Acts as a tensor, which means it tightens the skin slightly and restores its softness and elasticity.\nKey ingredients:\nThis cream contains very powerful ingredients that work together:\n1. Bakuchiol & Retinol: These are the best ingredients to renew skin cells and fight signs of aging.\n2. Caffeine: To reduce puffiness and dark circles under the eyes.\n3. Hyaluronic Acid: To deeply moisturize the skin.\n4. Prebiotic & Peptides: To strengthen the skin’s protective barrier and stimulate collagen formation.\nHow to use:\n• Apply a small amount of the cream around the eyes (top part of the cheekbones) and around the lips.\n• Spread with fingertips and very light tapping until absorbed.\n• Be careful not to get into your eye itself.\nImportant Notes:\n• pH 7: Suitable acidity to prevent eye irritation.\n• This product has been tested by ophthalmologists and dermatologists.','فوائد هذا المنتج:\n• مضاد للتجاعيد: يساعد على تقليل الخطوط الدقيقة والتجاعيد حول العينين والشفتين.\n• يقلل الانتفاخ والهالات السوداء: يقلل الانتفاخ تحت العينين والهالات السوداء التي تظهر في هذه المنطقة.\n• شد البشرة: يعمل كمشد، مما يعني أنه يشد البشرة قليلاً ويعيد إليها نعومتها ومرونتها.\n\nالمكونات الرئيسية:\nيحتوي هذا الكريم على مكونات فعّالة للغاية تعمل معًا:\n1. باكوشيول وريتينول: أفضل المكونات لتجديد خلايا البشرة ومكافحة علامات الشيخوخة.\n2. الكافيين: لتقليل الانتفاخ والهالات السوداء تحت العينين.\n3. حمض الهيالورونيك: لترطيب البشرة بعمق.\n4. البريبايوتيك والببتيدات: لتقوية حاجز البشرة الواقي وتحفيز إنتاج الكولاجين.\n\nطريقة الاستخدام:\n• ضعي كمية صغيرة من الكريم حول العينين (أعلى عظام الخدين) وحول الشفتين.\n• وزّعي الكريم بأطراف الأصابع مع التربيت الخفيف حتى يتم امتصاصه.\nاستخدمي أطراف الأصابع لتوزيع الكريم بلطف حتى يتم امتصاصه. • احرص على عدم دخوله في عينك.\n\nملاحظات هامة:\n• درجة الحموضة 7: حموضة مناسبة لمنع تهيج العين.\n• تم اختبار هذا المنتج من قبل أطباء العيون وأطباء الجلدية.\n','کارەکانی ئەم بەرهەمە:\n• دژە چرچولۆچی: یارمەتی کەمکردنەوەی هێڵە وردەکان و چرچی دەوروبەری چاو و لێو دەدات.\n• کەمکردنەوەی هەڵئاوسان و ڕەشی: کاریگەری هەیە لەسەر کەمکردنەوەی پفکردنی ژێر چاو و ئەو ڕەشییەی کە لەو ناوچەیە دروست دەبێت.\n• توندکردنەوە: وەک \"تێنسۆر\" (Tensor) کار دەکات، واتە پێستەکە کەمێک توند دەکاتەوە و نەرمی و لاستیکییەکەی بۆ دەگەڕێنێتەوە.\nپێکهاتە سەرەکییەکانی:\nئەم کرێمە پێکهاتەی زۆر بەهێزی تێدایە کە بەیەکەوە کار دەکەن:\n1. Bakuchiol & Retinol: ئەمانە باشترین پێکهاتەن بۆ نوێکردنەوەی خانەکانی پێست و بەرەنگاربوونەوەی نیشانەکانی پیری.\n2. Caffeine (کافایین): بۆ کەمکردنەوەی پف و ڕەشی ژێر چاو.\n3. Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵی پێست.\n4. Prebiotic & Peptides: بۆ بەهێزکردنی بەربەستی پارێزەری پێست و هاندانی دروستبوونی کۆلاجین.\nچۆنیەتی بەکارهێنان:\n• بڕێکی کەم لە کرێمەکە بدە لە دەوروبەری چاوەکان (بەشی سەرەوەی ئێسکی ڕوومەت) و دەوروبەری لێوەکان.\n• بە نوکە پەنجە و بە شێوەی لێدانی زۆر سوک (Tapping) بڵاوی بکەرەوە تا هەڵدەمژرێت.\n• ئاگاداربە نەچێتە ناو خودی چاوەکەتەوە.\nتێبینییە گرنگەکان:\n• pH 7: پلەی ترشێتییەکەی گونجاوە بۆ ئەوەی چاو نەکورێنێتەوە.\n• ئەم بەرهەمە لەلایەن پزیشکانی چاو و پێستەوە تاقی کراوەتەوە.\n',NULL,NULL,NULL,NULL,'2026-01-11 08:39:43',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'15ml','01-8',0,0),(257,'سیڕۆمی چڕ و بەهێز تایبەت بە نوێکردنەوە و ڕوبەڕوبوونەوەی نیشانەکانی پیری پێست لە بڕاندی بابێی ئیسپانی','Intensive and powerful serum to renew and combat the signs of skin aging from the Spanish brand Babe','سيروم مكثف وفعال لتجديد البشرة ومكافحة علامات الشيخوخة من ماركة Babe الإسبانية','سیڕۆمی چڕ و بەهێز تایبەت بە نوێکردنەوە و ڕوبەڕوبوونەوەی نیشانەکانی پیری پێست لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پێکهاتە سەرەکییەکان و سوودەکانیان:\r\nئەم سیرومە تێکەڵەیەکی دەوڵەمەندە لە ماددەی چالاک کە بە ڕێژەی دیاریکراو دانراون:\r\n• Bakuchiol (باکوچیۆل): جێگرەوەیەکی سروشتییە بۆ \"ڕێتینۆڵ\"، یارمەتی کەمکردنەوەی چرچ و لۆچی دەدات بەبێ ئەوەی پێست تووشی هەستیاری بکات.\r\n• Collagen Biostimulator (هاندەری کۆلاجین): یارمەتی توندکردنەوەی پێست و زیادکردنی لاستیکی (Elasticity) پێست دەدات.\r\n• Hyaluronic Acid (هایالۆرۆنیک ئەسید): بۆ شێدارکردنەوەی قوڵی پێست و پڕکردنەوەی هێڵە وردەکان.\r\n• Vitamin C & E: وەک دژە ئۆکسان کار دەکەن بۆ گەشانەوەی پێست و پاراستنی لە کاریگەرییە خراپەکانی دەرەوە.\r\n• Prebiotics (پریبایۆتیک): بۆ پاراستنی هاوسەنگی بەکتریای سوودبەخشی سەر پێست و بەهێزکردنی بەرگری پێست.\r\n٢. ئیشی سەرەکی ئەم بەرهەمە چییە؟\r\n• گەنجکردنەوە: یارمەتی کەمکردنەوەی چرچ و لۆچی و هێڵە وردەکانی دەموچاو دەدات.\r\n• گەشانەوە: ڕەنگی پێست یەکدەخات و بریقە و گەشاوەیی بۆ دەگەڕێنێتەوە.\r\n• توندکردنەوە: ڕێگری دەکات لە شۆڕبوونەوەی پێست و بە توندی دەیهێڵێتەوە.\r\n• وزەبەخشین: پێستە ماندووەکان چاک دەکاتەوە و دیمەنێکی تەندروستتریان پێ دەبەخشێت.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• کات: دەتوانیت بەیانیان و شەوان بەکاری بهێنیت.\r\n• شێواز: دوای ئەوەی دەموچاوت بە باشی پاک دەکەیتەوە، چەند دڵۆپێکی کەم لە سیرومەکە بدە لە دەموچاو و ملت. بە هێواشی بە شێوەی بازنەیی مەساژی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\n• تێبینی: دەتوانیت دوای ئەم سیرومە، کرێمی شێدارکەرەوەی ڕۆژ یان شەو بەکاربهێنیت بۆ ئەوەی ئەنجامێکی باشتری هەبێت.\r\n٤. بۆ کێ گونجاوە؟\r\nئەم بەرهەمە بۆ هەموو جۆرە پێستەکان گونجاوە، بەتایبەت بۆ ئەو کەسانەی تەمەنیان لە سەروو ٣٠ ساڵییەوەیە و دەیانەوێت ڕێگری لە پیربوونی پێستیان بگرن یان چارەسەری چرچ و لۆچی بکەن.\r\n','Key ingredients and benefits:\nThis serum is a rich blend of active ingredients in the right proportions:\n• Bakuchiol (Bakuchiol): A natural substitute for “retinol”, helps reduce wrinkles without causing skin sensitivity.\n• Collagen Biostimulator: Helps tighten the skin and increase its elasticity.\n• Hyaluronic Acid: To deeply moisturize the skin and fill in fine lines.\n• Vitamin C & E: Act as antioxidants to brighten the skin and protect it from harmful external influences.\n• Prebiotics: To maintain the balance of beneficial bacteria on the skin and strengthen the skin\'s immune system.\n2. What is the main function of this product?\n• Rejuvenation: Helps reduce facial wrinkles and fine lines.\n• Brightening: Unifies skin tone and restores radiance.\n• Tightening: Prevents skin sagging and keeps it firm.\n• Energizing: Repairs tired skin and gives it a healthier look.\n3. How to use:\n• Time: You can use it in the morning and at night.\n• Method: After thoroughly cleansing your face, apply few drops of the serum on your face and neck. Gently massage in circular motions until fully absorbed.\n• Note: You can use a day or night moisturizer after this serum for better results.\n4. Who is it suitable for?\nThis product is suitable for all skin types, especially for people over the age of 30 who want to prevent skin aging or treat wrinkles.','المكونات الرئيسية وفوائدها:\nهذا السيروم مزيج غني من المكونات النشطة بنسب دقيقة:\n• باكوشيول: بديل طبيعي للريتينول، يساعد على تقليل التجاعيد دون التسبب بحساسية البشرة.\n• محفز الكولاجين الحيوي: يساعد على شد البشرة وزيادة مرونتها.\n• حمض الهيالورونيك: يرطب البشرة بعمق ويملأ الخطوط الدقيقة.\n• فيتامين ج وفيتامين هـ: يعملان كمضادات للأكسدة لتفتيح البشرة وحمايتها من العوامل الخارجية الضارة.\n• البريبايوتكس: تحافظ على توازن البكتيريا النافعة على البشرة وتقوي جهاز المناعة فيها.\n\n٢. ما هي الوظيفة الرئيسية لهذا المنتج؟\n• تجديد البشرة: يساعد على تقليل تجاعيد الوجه والخطوط الدقيقة.\n• تفتيح البشرة: يوحد لون البشرة ويعيد إليها نضارتها.\n• شد البشرة: يمنع ترهلها ويحافظ على تماسكها.\n• تنشيط البشرة: يُصلح البشرة المتعبة ويمنحها مظهرًا صحيًا.\n\n٣. طريقة الاستخدام:\n• الوقت: يُمكن استخدامه صباحًا ومساءً.\n• الطريقة: بعد تنظيف الوجه جيدًا، ضعي بضع قطرات من السيروم على الوجه والرقبة. دلكي بلطف بحركات دائرية حتى يتم امتصاصه بالكامل.\n• ملاحظة: يُمكنكِ استخدام مرطب نهاري أو ليلي بعد هذا السيروم للحصول على نتائج أفضل.\n\n٤. لمن يُناسب؟\nهذا المنتج مُناسب لجميع أنواع البشرة، وخاصةً لمن تزيد أعمارهم عن ٣٠ عامًا والذين يرغبون في الوقاية من علامات تقدم سن البشرة أو علاج التجاعيد.\n','. پێکهاتە سەرەکییەکان و سوودەکانیان:\nئەم سیرومە تێکەڵەیەکی دەوڵەمەندە لە ماددەی چالاک کە بە ڕێژەی دیاریکراو دانراون:\n• Bakuchiol (باکوچیۆل): جێگرەوەیەکی سروشتییە بۆ \"ڕێتینۆڵ\"، یارمەتی کەمکردنەوەی چرچ و لۆچی دەدات بەبێ ئەوەی پێست تووشی هەستیاری بکات.\n• Collagen Biostimulator (هاندەری کۆلاجین): یارمەتی توندکردنەوەی پێست و زیادکردنی لاستیکی (Elasticity) پێست دەدات.\n• Hyaluronic Acid (هایالۆرۆنیک ئەسید): بۆ شێدارکردنەوەی قوڵی پێست و پڕکردنەوەی هێڵە وردەکان.\n• Vitamin C & E: وەک دژە ئۆکسان کار دەکەن بۆ گەشانەوەی پێست و پاراستنی لە کاریگەرییە خراپەکانی دەرەوە.\n• Prebiotics (پریبایۆتیک): بۆ پاراستنی هاوسەنگی بەکتریای سوودبەخشی سەر پێست و بەهێزکردنی بەرگری پێست.\n٢. ئیشی سەرەکی ئەم بەرهەمە چییە؟\n• گەنجکردنەوە: یارمەتی کەمکردنەوەی چرچ و لۆچی و هێڵە وردەکانی دەموچاو دەدات.\n• گەشانەوە: ڕەنگی پێست یەکدەخات و بریقە و گەشاوەیی بۆ دەگەڕێنێتەوە.\n• توندکردنەوە: ڕێگری دەکات لە شۆڕبوونەوەی پێست و بە توندی دەیهێڵێتەوە.\n• وزەبەخشین: پێستە ماندووەکان چاک دەکاتەوە و دیمەنێکی تەندروستتریان پێ دەبەخشێت.\n٣. چۆنیەتی بەکارهێنان:\n• کات: دەتوانیت بەیانیان و شەوان بەکاری بهێنیت.\n• شێواز: دوای ئەوەی دەموچاوت بە باشی پاک دەکەیتەوە، چەند دڵۆپێکی کەم لە سیرومەکە بدە لە دەموچاو و ملت. بە هێواشی بە شێوەی بازنەیی مەساژی پێ بکە تا بە تەواوی هەڵدەمژرێت.\n• تێبینی: دەتوانیت دوای ئەم سیرومە، کرێمی شێدارکەرەوەی ڕۆژ یان شەو بەکاربهێنیت بۆ ئەوەی ئەنجامێکی باشتری هەبێت.\n٤. بۆ کێ گونجاوە؟\nئەم بەرهەمە بۆ هەموو جۆرە پێستەکان گونجاوە، بەتایبەت بۆ ئەو کەسانەی تەمەنیان لە سەروو ٣٠ ساڵییەوەیە و دەیانەوێت ڕێگری لە پیربوونی پێستیان بگرن یان چارەسەری چرچ و لۆچی بکەن.',NULL,NULL,NULL,NULL,'2026-01-11 08:40:59',10000.00,'fixed',NULL,15,NULL,4,NULL,NULL,'50ml','01-7',0,0),(258,'کرێمی چاکەرەوەی تایبەت بە پێی وشک و قڵیشاو لە بڕاندی بابێی ئیسپانی','Special repair cream for dry and flaky feet from the Spanish brand Babe','كريم ترميم خاص للقدمين الجافتين والمتقشرتين من ماركة Babe الإسبانية','کرێمی چاکەرەوەی تایبەت بە پێی وشک و قڵیشاو لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پێکهاتە سەرەکییەکانی:\r\n• یوریا (10% Urea): ئەمە پێکهاتەی سەرەکییە کە شێدارییەکی قووڵ بە پێست دەبەخشێت و یارمەتی لادانی خانە مردووەکان و نەرمکردنەوەی بەشە ڕەقەکان (وەک پاشینەی پێ) دەدات.\r\n• گلیسرین (3%): بۆ پاراستنی شێداری پێست.\r\n• کەرەی شیا (Shea Butter - 2%): بۆ نەرمکردنەوە و خۆراکپێدانی پێست.\r\n• ترشی لاکتیک (Lactic Acid): بۆ نوێکردنەوەی خانەکانی پێست.\r\n• ڤیتامین E: وەک دژە ئۆکسان و پارێزەر کار دەکات.\r\n٢. سوودەکانی:\r\n• چارەسەری قڵیشان: بە شێوەیەکی کاریگەر ئەو قڵیشانەی لەسەر پاشینەی پێ دروست دەبن چاک دەکاتەوە.\r\n• نەرمکردنەوە: ئەو بەشە ڕەق و زبرانەی پێست (کالۆس) کە بەهۆی وشکییەوە دروست بوون، نەرم دەکات.\r\n• کەمکردنەوەی توندبوون: ئەو هەستی توندبوون و ناڕەحەتییەی بەهۆی وشکییەوە دروست دەبێت نایهێڵێت.\r\n• پاراستن: ڕێگری دەکات لە دووبارە وشکبوونەوەی پێست.\r\n٣. شێوازی بەکارهێنان:\r\n• بڕێکی گونجاو لە کرێمەکە بدە لە پێیەکانت (بە تایبەت پاشینەی پێ).\r\n• بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\n• تێبینی گرنگ:  نابێت ئەم کرێمە بدرێت لەو برینانەی کە کراوەن یان خوێنیان لێ دێت.\r\n','Key ingredients:\n• Urea (10% Urea): This is the main ingredient that gives the skin deep moisture and helps remove dead cells and soften hard parts (such as the soles of the feet).\n• Glycerin (3%): To maintain skin moisture.\n• Shea Butter (2%): To soften and nourish the skin.\n• Lactic Acid: To renew skin cells.\n• Vitamin E: Acts as an antioxidant and protector.\n2. Benefits:\n• Exfoliation treatment: Effectively repairs exfoliation on the soles of the feet.\n• Softening: Softens the hard, rough patches of skin (callus) caused by dryness.\n• Reduce tightness: It eliminates the feeling of tightness and discomfort caused by dryness.\n• Protection: Prevents re-drying of the skin.\n3. How to use:\n• Apply an appropriate amount of cream to your feet (especially the heels).\n• Gently massage until fully absorbed.\n• Important Note: This cream should not be applied to open or bleeding wounds.','المكونات الرئيسية:\n• اليوريا (10%): المكون الرئيسي الذي يمنح البشرة ترطيبًا عميقًا ويساعد على إزالة الخلايا الميتة وتنعيم المناطق الخشنة (مثل باطن القدمين).\n• الجلسرين (3%): للحفاظ على ترطيب البشرة.\n• زبدة الشيا (2%): لتنعيم وتغذية البشرة.\n• حمض اللاكتيك: لتجديد خلايا البشرة.\n• فيتامين هـ: يعمل كمضاد للأكسدة وواقي.\n\n2. الفوائد:\n• علاج التقشير: يُصلح بفعالية آثار التقشير على باطن القدمين.\n• التنعيم: يُنعم بقع الجلد الخشنة والمتصلبة (الكالو) الناتجة عن الجفاف.\n• تخفيف الشعور بالشد: يُزيل الشعور بالشد وعدم الراحة الناتج عن الجفاف.\n• الحماية: يمنع جفاف البشرة مرة أخرى.\n\n3. طريقة الاستخدام:\n• ضعي كمية مناسبة من الكريم على قدميكِ (خاصة الكعبين).\n• دلكي بلطف حتى يتم امتصاصه بالكامل. • ملاحظة هامة: لا ينبغي وضع هذا الكريم على الجروح المفتوحة أو النازفة.','. پێکهاتە سەرەکییەکانی:\n• یوریا (10% Urea): ئەمە پێکهاتەی سەرەکییە کە شێدارییەکی قووڵ بە پێست دەبەخشێت و یارمەتی لادانی خانە مردووەکان و نەرمکردنەوەی بەشە ڕەقەکان (وەک پاشینەی پێ) دەدات.\n• گلیسرین (3%): بۆ پاراستنی شێداری پێست.\n• کەرەی شیا (Shea Butter - 2%): بۆ نەرمکردنەوە و خۆراکپێدانی پێست.\n• ترشی لاکتیک (Lactic Acid): بۆ نوێکردنەوەی خانەکانی پێست.\n• ڤیتامین E: وەک دژە ئۆکسان و پارێزەر کار دەکات.\n٢. سوودەکانی:\n• چارەسەری قڵیشان: بە شێوەیەکی کاریگەر ئەو قڵیشانەی لەسەر پاشینەی پێ دروست دەبن چاک دەکاتەوە.\n• نەرمکردنەوە: ئەو بەشە ڕەق و زبرانەی پێست (کالۆس) کە بەهۆی وشکییەوە دروست بوون، نەرم دەکات.\n• کەمکردنەوەی توندبوون: ئەو هەستی توندبوون و ناڕەحەتییەی بەهۆی وشکییەوە دروست دەبێت نایهێڵێت.\n• پاراستن: ڕێگری دەکات لە دووبارە وشکبوونەوەی پێست.\n٣. شێوازی بەکارهێنان:\n• بڕێکی گونجاو لە کرێمەکە بدە لە پێیەکانت (بە تایبەت پاشینەی پێ).\n• بە هێواشی مەساجی پێ بکە تا بە تەواوی هەڵدەمژرێت.\n• تێبینی گرنگ:  نابێت ئەم کرێمە بدرێت لەو برینانەی کە کراوەن یان خوێنیان لێ دێت.\n',NULL,NULL,NULL,NULL,'2026-01-11 08:42:19',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'100ml','01-6',0,0),(259,'کرێمی تایبەت بە چارەسەرکردن و رێگریکردن لە دروستبوونی هێڵەکانی جەستە لە بڕاندی بابێی ئیسپانی','Special cream to treat and prevent the formation of body lines from the Spanish brand Babe','كريم خاص لعلاج ومنع ظهور تجاعيد الجسم من ماركة Babe الإسبانية','کرێمی تایبەت بە چارەسەرکردن و رێگریکردن لە دروستبوونی هێڵەکانی جەستە لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. بەکارهێنانی سەرەکی\r\nئەم کرێمە یارمەتی کەمکردنەوەی نیشانەکانی کێشانی پێست دەدات و ڕێگری دەکات لە دروستبوونی هێڵی نوێ. گونجاوە بۆ ئەو کەسانەی کە:\r\n• بەهۆی دووگیانییەوە کێشیان گۆڕاوە.\r\n• بەهۆی وەرزش یان گۆڕانی کتوپڕی کێشەوە هێڵ لەسەر جەستەیان دروست بووە.\r\n• لە کاتی هەرزەکاریدا بەهۆی گەشەی خێراوە پێستیان درزی بردووە.\r\n٢. پێکهاتە سەرەکییەکانی\r\nبەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە، ئەم پێکهاتە گرنگانەی تێدایە:\r\n• Centella Asiatica (3%): یارمەتی چاکبوونەوەی خانەکانی پێست و بەرهەمهێنانی کۆلاجین دەدات.\r\n• Rosa Moschata Oil (2%): ڕۆنی گوڵە کێویلە کە دەوڵەمەندە بە ڤیتامین و ترشە چەورییەکان بۆ شێدارکردنەوە و نەرمکردنی پێست.\r\n• Glycerin (3%): بۆ پاراستنی شێداری پێست.\r\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست دەپارێزێت.\r\n٣. تایبەتمەندییەکان\r\n• نەرمی و جیڕی: یارمەتی بەهێزکردنی جیڕی (Elasticity) پێست دەدات بۆ ئەوەی لە کاتی کێشاندا نەدڕێت.\r\n• تێستکراوە: لە لایەن پزیشکانی پێستەوە پشکێنراوە (Dermatologically Tested).\r\n• pH 5.5: هاوسەنگی سروشتی پێست دەپارێزێت.\r\n٤. چۆنیەتی بەکارهێنان\r\n• بڕێکی گونجاو لە کرێمەکە بدە لەو شوێنانەی کە مەبەستتە (وەک: سک، ڕان، قۆڵ، و سنگ).\r\n• بە شێوەی بازنەیی و بە هێمنی مەساژی پێ بکە تا بە تەواوی هەڵدەمژرێت.\r\n• باشترە بۆ ماوەی لانی کەم ٣ مانگ بەردەوام بیت بۆ بینینی باشترین ئەنجام.\r\nتێبینی: ئەگەر دووگیانیت یان شیردەریت، ئەم بەرهەمە بە گشتی گونجاوە.\r\n','Major uses\nThis cream helps reduce stretch marks and prevents new lines from forming. Suitable for people who:\n• Weight changes due to pregnancy.\n• They have lines on their body due to exercise or sudden weight changes.\n• Cracked skin during adolescence due to rapid growth.\n2. Its main components\nAccording to the label, it contains the following important ingredients:\n• Centella Asiatica (3%): Promotes skin cell healing and collagen production.\n• Rosa Moschata Oil (2%): Wild rose oil rich in vitamins and fatty acids to moisturize and soften the skin.\n• Glycerin (3%): To maintain skin moisture.\n• Vitamin E: Acts as an antioxidant and protects the skin.\n3. characteristics\n• Elasticity: Helps strengthen the elasticity of the skin to prevent tearing during stretching.\n• Tested: Dermatologically Tested.\n• pH 5.5: Maintains skin’s natural balance.\n4. How to use\n• Apply an appropriate amount of cream to the intended areas (eg: abdomen, thighs, arms, and chest).\n• Massage gently in circular motions until fully absorbed.\n• It is best to continue for at least 3 months to see the best results.\nNote: If you are pregnant or breastfeeding, this product is generally suitable.',' الاستخدامات الرئيسية\nيساعد هذا الكريم على تقليل علامات التمدد ويمنع ظهور خطوط جديدة. مناسب للأشخاص الذين:\n• تغيرات الوزن بسبب الحمل.\n• ظهور خطوط على الجسم نتيجة ممارسة الرياضة أو تغيرات الوزن المفاجئة.\n• تشقق الجلد خلال فترة المراهقة نتيجة النمو السريع.\n\n2. مكوناته الرئيسية\nوفقًا للملصق، يحتوي على المكونات الهامة التالية:\n• نبات سرة الأرض (3%): يعزز التئام خلايا الجلد وإنتاج الكولاجين.\n• زيت ثمر الورد البري (2%): زيت الورد البري غني بالفيتامينات والأحماض الدهنية لترطيب وتنعيم البشرة.\n• الجلسرين (3%): للحفاظ على رطوبة البشرة.\n• فيتامين هـ: يعمل كمضاد للأكسدة ويحمي البشرة.\n\n3. الخصائص\n• المرونة: يساعد على تقوية مرونة الجلد لمنع التمزق أثناء التمدد.\n• تم اختباره: تم اختباره من قبل أطباء الجلدية.\n• درجة حموضة 5.5: تحافظ على التوازن الطبيعي للبشرة.\n\n\n٤. طريقة الاستخدام\n• ضعي كمية مناسبة من الكريم على المناطق المستهدفة (مثل: البطن، الفخذين، الذراعين، والصدر).\n• دلكي بلطف بحركات دائرية حتى يتم امتصاصه بالكامل.\n• يُفضل الاستمرار في الاستخدام لمدة ٣ أشهر على الأقل للحصول على أفضل النتائج.\n\nملاحظة: هذا المنتج مناسب بشكل عام للحوامل والمرضعات.\n','. بەکارهێنانی سەرەکی\nئەم کرێمە یارمەتی کەمکردنەوەی نیشانەکانی کێشانی پێست دەدات و ڕێگری دەکات لە دروستبوونی هێڵی نوێ. گونجاوە بۆ ئەو کەسانەی کە:\n• بەهۆی دووگیانییەوە کێشیان گۆڕاوە.\n• بەهۆی وەرزش یان گۆڕانی کتوپڕی کێشەوە هێڵ لەسەر جەستەیان دروست بووە.\n• لە کاتی هەرزەکاریدا بەهۆی گەشەی خێراوە پێستیان درزی بردووە.\n٢. پێکهاتە سەرەکییەکانی\nبەپێی ئەوەی لەسەر کارتۆنەکە نووسراوە، ئەم پێکهاتە گرنگانەی تێدایە:\n• Centella Asiatica (3%): یارمەتی چاکبوونەوەی خانەکانی پێست و بەرهەمهێنانی کۆلاجین دەدات.\n• Rosa Moschata Oil (2%): ڕۆنی گوڵە کێویلە کە دەوڵەمەندە بە ڤیتامین و ترشە چەورییەکان بۆ شێدارکردنەوە و نەرمکردنی پێست.\n• Glycerin (3%): بۆ پاراستنی شێداری پێست.\n• ڤیتامین E: وەک دژە ئۆکسان کاردەکات و پێست دەپارێزێت.\n٣. تایبەتمەندییەکان\n• نەرمی و جیڕی: یارمەتی بەهێزکردنی جیڕی (Elasticity) پێست دەدات بۆ ئەوەی لە کاتی کێشاندا نەدڕێت.\n• تێستکراوە: لە لایەن پزیشکانی پێستەوە پشکێنراوە (Dermatologically Tested).\n• pH 5.5: هاوسەنگی سروشتی پێست دەپارێزێت.\n٤. چۆنیەتی بەکارهێنان\n• بڕێکی گونجاو لە کرێمەکە بدە لەو شوێنانەی کە مەبەستتە (وەک: سک، ڕان، قۆڵ، و سنگ).\n• بە شێوەی بازنەیی و بە هێمنی مەساژی پێ بکە تا بە تەواوی هەڵدەمژرێت.\n• باشترە بۆ ماوەی لانی کەم ٣ مانگ بەردەوام بیت بۆ بینینی باشترین ئەنجام.\nتێبینی: ئەگەر دووگیانیت یان شیردەریت، ئەم بەرهەمە بە گشتی گونجاوە.\n',NULL,NULL,NULL,NULL,'2026-01-11 08:45:43',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'200ml','01-5',0,0),(260,'کرێمی تایبەت بە وشکبوونەوەی توندی لێو لە بڕاندی بابێی ئیسپانی','Severe Dry Lip Cream from Spanish brand Babe','كريم مرطب للشفاه شديدة الجفاف من ماركة BABE الإسبانية','کرێمی تایبەت بە وشکبوونەوەی توندی لێو لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. سوودە سەرەکییەکانی:\r\n• چاککەرەوە (Repairing): یارمەتی چاکبوونەوەی لێوی قڵیشاو و بریندار دەدات.\r\n• تێرکەر (Nourishing): پێستی لێو بە قووڵی خۆراک پێ دەدات.\r\n• نەرمکەرەوە (Softening): لێوەکان زۆر نەرم دەکات و هەستی زبری لادەبات.\r\n• پارێزگاری: چینێکی پارێزەر لەسەر لێو دروست دەکات دژی سەرما، با، و گۆڕانکارییەکانی کەشوهەوا.\r\n٢. پێکهاتە گرنگەکانی:\r\nبەپێی ئەوەی لەسەر پشتەوەی بەرهەمەکە نووسراوە، ئەمانەی تێدایە:\r\n• Shea Butter (کەرەی شیا): بۆ شێدارییەکی زۆر و نەرمکردنەوە.\r\n• Rosehip Oil (ڕۆنی گوڵەباخ): یارمەتی نوێبوونەوەی خانەکانی پێست دەدات.\r\n• Vitamin E: دژە ئۆکسانە و دژی پیربوون و وشکبوونەوەی پێستە.\r\n• Bisabolol: بۆ هێورکردنەوەی سووربوونەوە و هەوکردنی لێو.\r\n٣. چۆنیەتی بەکارهێنان:\r\n• دەتوانیت ڕۆژانە چەند جارێک بەکاری بهێنیت (هەر کاتێک هەستت بە وشکبوونەوە کرد).\r\n• جگە لە لێو، دەکرێت بۆ دەوروبەری لوتیش بەکاربێت ئەگەر بەهۆی هەڵامەت یان وشکییەوە تووشی قڵیشان بووبێت.\r\n','Key benefits:\n• Repairing: Helps heal scratched and injured lips.\n• Nourishing: Deeply nourishes lip skin.\n• Softening: Makes the lips very soft and removes the feeling of roughness.\n• Protection: Creates a protective layer on the lips against cold, wind, and weather changes.\n2. Important components:\nAccording to the back of the product, it contains:\n• Shea Butter: For great moisture and softening.\n• Rosehip Oil: Helps renew skin cells.\n• Vitamin E: Antioxidant and anti-aging and dry skin.\n• Bisabolol: To relieve redness and inflammation of the lips.\n3. How to use:\n• You can use it several times a day (whenever you feel dry).\n• In addition to the lips, it can also be used around the nose if it is itchy due to colds or dryness.',' الفوائد الرئيسية:\n• ترميم: يساعد على التئام الخدوش والجروح في الشفاه.\n• تغذية: يغذي بشرة الشفاه بعمق.\n• تنعيم: يجعل الشفاه ناعمة للغاية ويزيل الشعور بالخشونة.\n• حماية: يشكل طبقة واقية على الشفاه ضد البرد والرياح وتغيرات الطقس.\n\n٢. المكونات الهامة:\nوفقًا لما هو مدون على ظهر المنتج، يحتوي على:\n• زبدة الشيا: لترطيب وتنعيم فائقين.\n• زيت ثمر الورد: يساعد على تجديد خلايا الجلد.\n• فيتامين هـ: مضاد للأكسدة ومضاد للشيخوخة وجفاف البشرة.\n• بيسابولول: لتخفيف احمرار والتهاب الشفاه.\n\n٣. طريقة الاستخدام:\n• يمكن استخدامه عدة مرات في اليوم (كلما شعرتِ بالجفاف).\n• بالإضافة إلى الشفاه، يمكن استخدامه أيضًا حول الأنف في حالة الحكة الناتجة عن نزلات البرد أو الجفاف.\n','',NULL,NULL,NULL,NULL,'2026-01-11 08:46:50',0.00,'percentage',NULL,15,NULL,4,NULL,NULL,'15ml','01-4',0,0),(261,'سوراو و شێدارکەرەوەی لێو لە بڕاندی بابێی ئیسپانی','Lipstick and moisturizer from Spanish brand Babe','أحمر شفاه ومرطب من ماركة Babe الإسبانية','سوراو و شێدارکەرەوەی لێو لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'تایبەتمەندییە سەرەکییەکان:\r\n• پاراستن لە خۆر (SPF 50): ئەمە خاڵی بەهێزی بەرهەمەکەیە. نەک تەنها ڕەنگ دەبەخشێت، بەڵکو پاراستنێکی زۆر باش لە تیشکی خۆر (UVA/UVB) بۆ لێو و پێست دابین دەکات.\r\n• پێکهاتە دەوڵەمەندەکان:\r\n• Hyaluronic Acid: بۆ شێدارکردنەوەی قووڵ و ڕێگریکردن لە وشکبوونەوەی لێو.\r\n• Peptides: یارمەتی پڕکردنەوە و نەرمکردنی پێست دەدەن (Plumping Effect).\r\n• ڕەنگێکی سروشتی: ڕەنگێکی سووکی هەیە کە شێوەیەکی سروشتی و تەندروست بە ڕوخسار دەبەخشێت.\r\n• پاراستن لە تیشکی شین و ژێر سوور: وەک لەسەر تیوبەکە نووسراوە (HEV + IR-A)، دژە ئۆکسانە و پێست لە کاریگەرییە خراپەکانی تیشکی شاشە و گەرمی دەپارێزێت.\r\nسوودەکانی:\r\n• دوو کارە لە یەکێکدا: دەتوانیت بۆ لێو و ڕوومەت بەکاریبهێنیت، ئەمەش کات و پارەت بۆ دەگەڕێنێتەوە.\r\n• دژە ئاو و ئارەقەیە: بۆ ماوەیەکی باش دەمێنێتەوە.\r\n• بۆ پێستی هەستیار گونجاوە: لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە.\r\nچۆن بەکاردێت؟\r\nبڕێکی کەم بدە لە لێوەکانت یان سێوی ڕوومەتت و بە سەری پەنجەکانت بە شێوەیەکی بازنەیی بڵاوی بکەرەوە تا ڕەنگەکە بە جوانی لەگەڵ پێستت تێکەڵ دەبێت.\r\n','Key Features:\n• Sun protection (SPF 50): This is the strength of the product. Not only does it provide color, but it also provides great sun protection (UVA/UVB) for lips and skin.\n• Rich ingredients:\n• Hyaluronic Acid: To deeply hydrate and prevent dry lips.\n• Peptides: Help plump and soften the skin (Plumping Effect).\n• Natural complexion: It has a light texture that gives a natural and healthy look.\n• Blue and Infrared Protection: As stated on the tube (HEV + IR-A), it is an antioxidant and protects the skin from the harmful effects of screen light and heat.\nBenefits:\n• Two jobs in one: You can use it for lips and cheeks, saving you time and money.\n• Waterproof and sweatproof: Lasts for a long time.\n• Suitable for sensitive skin: Tested by dermatologists.\nhow is it used\nApply a small amount to your lips or apples of your cheeks and spread with your fingertips in a circular motion until the color blends nicely with your skin.','الميزات الرئيسية:\n• حماية من الشمس (SPF 50): هذه هي قوة المنتج. فهو لا يمنح لونًا فحسب، بل يوفر أيضًا حماية فائقة من أشعة الشمس (UVA/UVB) للشفاه والبشرة.\n\n• مكونات غنية:\n• حمض الهيالورونيك: لترطيب الشفاه بعمق ومنع جفافها.\n• الببتيدات: تساعد على نفخ وتنعيم البشرة (تأثير النفخ).\n• بشرة طبيعية: يتميز بقوام خفيف يمنح مظهرًا طبيعيًا وصحيًا.\n• حماية من الضوء الأزرق والأشعة تحت الحمراء: كما هو موضح على العبوة (HEV + IR-A)، فهو مضاد للأكسدة ويحمي البشرة من الآثار الضارة لضوء الشاشة والحرارة.\n• فوائد متعددة: يمكن استخدامه للشفاه والخدود، مما يوفر الوقت والمال.\n• مقاوم للماء والعرق: يدوم طويلًا.\n• مناسب للبشرة الحساسة: تم اختباره من قبل أطباء الجلدية.\n\nكيفية الاستخدام\nضعي كمية صغيرة على شفتيكِ أو تفاحتي خديكِ ووزعيها بأطراف أصابعكِ بحركات دائرية حتى يمتزج اللون جيداً مع بشرتكِ.\n','',NULL,NULL,NULL,NULL,'2026-01-11 08:47:51',50.00,'percentage',NULL,15,NULL,4,NULL,NULL,'15ml','01-3',0,0),(262,'پارێزەر و چاکەرەوەی لێو لە بڕاندی بابێی ئیسپانی','Lip protector and repair from the Spanish brand Babe','مرطب ومُرمِّم للشفاه من العلامة التجارية الإسبانية Babe','پارێزەر و چاکەرەوەی لێو لە بڕاندی بابێی ئیسپانی',15,20000,29750,4750,1,'. پاراستن لە خۆر (SPF 50)\r\nئەمە خاڵە بەهێزەکەیەتی؛ ڕێگری دەکات لە سووتان و ڕەشبوونی لێوەکان بەهۆی تیشکی خۆرەوە. نەک تەنها دژی تیشکی (UVA/UVB)، بەڵکو وەک لەسەر تیوپەکە نووسراوە پارێزگاری لە لێو دەکات بەرامبەر بە (HEV) کە تیشکی شاشەکانە (Blue Light).\r\n٢. پێکهاتە و سوودەکانی\r\n• Hyaluronic Acid: یارمەتی شێدارکردنەوەی قووڵی لێو دەدات و ڕێگری دەکات لە وشکبوونەوە.\r\n• Plumping Effect: کاریگەرییەکی کاتی \"پڕکردنەوە\" یان قەبارەدان بە لێو دەبەخشێت بەهۆی شێدارکردنەوەی زۆرەوە.\r\n• Repairs & Protects: یارمەتی چاکبوونەوەی ئەو لێوانە دەدات کە قڵیشاون یان زۆر وشکن.\r\n٣. کەی و چۆن بەکاردێت؟\r\n• دەتوانیت ڕۆژانە بەکاریبهێنیت، بەتایبەت پێش ئەوەی بچیتە بەر خۆر.\r\n• گونجاوە بۆ هەموو جۆرە پێستێک، تەنانەت پێستی هەستیاریش چونکە لەلایەن پزیشکانی پێستەوە تاقیکراوەتەوە.\r\n','Sun Protection (SPF 50)\nThis is his strength; Prevents sunburn and darkening of the lips. Not only against UVA/UVB rays, but also as written on the tube it protects the lips against HEV rays (Blue Light).\n2. Ingredients and benefits\n• Hyaluronic Acid: Helps deeply moisturize lips and prevent dryness.\n• Plumping Effect: Gives lips a temporary “filling” or volume effect due to extreme hydration.\n• Repairs & Protects: Helps heal exfoliated or very dry lips.\n3. When and how is it used?\n• You can use it daily, especially before going out in the sun.\n• Suitable for all skin types, even sensitive skin because it has been tested by dermatologists.','.واقي من الشمس (SPF 50)\nهذه هي قوته؛ فهو يمنع حروق الشمس واسمرار الشفاه. لا يحمي فقط من أشعة UVA/UVB، بل يحمي الشفاه أيضًا، كما هو موضح على العبوة، من أشعة HEV (الضوء الأزرق).\n\n2. المكونات والفوائد\n• حمض الهيالورونيك: يساعد على ترطيب الشفاه بعمق ومنع جفافها.\n• تأثير نفخ الشفاه: يمنح الشفاه امتلاءً مؤقتًا بفضل الترطيب العميق.\n• يُرمم ويحمي: يساعد على شفاء الشفاه المتقشرة أو شديدة الجفاف.\n\n3. متى وكيف يُستخدم؟\n• يُمكن استخدامه يوميًا، خاصةً قبل التعرض لأشعة الشمس.\n• مناسب لجميع أنواع البشرة، حتى الحساسة منها، لأنه مُختبر من قبل أطباء الجلدية.','',NULL,NULL,NULL,NULL,'2026-01-11 08:48:58',19000.00,'fixed',NULL,15,NULL,4,NULL,NULL,'15ml','01-2',0,0);
